window.HADITH_CACHE["ahmad_5"] = {"2501":{"ar":"حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ آدَمَ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ أَبِي إِسْحَاقَ عَنْ يَزِيدَ بْنِ أَبِي مَرْيَمَ عَنِ الْأَشْعَرِيِّ قَالَلَقَدْ ذَكَّرَنَا ابْنُ أَبِي طَالِبٍ وَنَحْنُ بِالْبَصْرَةِ صَلَاةً كُنَّا نُصَلِّيهَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ إِذَا سَجَدَ وَإِذَا قَامَ فَلَا أَدْرِي أَنَسِينَاهَا أَمْ تَرَكْنَاهَا عَمْدًاحَدَّثَنَا يُونُسُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ يُونُسَ وَثَابِتٍ وَحُمَيْدٍ وَحَبِيبٍ عَنِ الْحَسَنِ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ فَذَكَرَ نَحْوًا مِنْ حَدِيثِ عَبْدِ الصَّمَدِ عَنْ حَمَّادٍ عَنْ عَلِيِّ بْنِ زَيْدٍ إِلَّا أَنَّهُ قَالَ قَالَ أَبُو مُوسَى وَالَّذِي نَفْسِي بِيَدِهِ لَا أَجِدُ لِي وَلَكُمْ إِنْ أَدْرَكْتُهُنَّ إِلَّا أَنْ نَخْرُجَ مِنْهَا كَمَا دَخَلْنَاهَا لَمْ نُصِبْ فِيهَا دَمًا وَلَا مَالًا","id":"Telah menceritakan kepada kami [Yahya bin Adam] yakni Ibnu Adam, Telah menceritakan kepada kami [Ammar bin Ruzaiq] dari [Abu Ishaq] dari [Yazid bin Abu Maryam] dari [Al Asy'ari] ia berkata; \" [Ibnu Abu Thalib] mengingatkan kami di Bashrah tentang shalat yang pernah kami tunaikan bersama Rasulullah shallallahu 'alaihi wasallam. beliau selalu bertakbir ketika hendak sujud, dan berdiri. Saya tidak tahu, apakah waktu itu kami lupa, ataukah sengaja meninggalkannya.\" Telah menceritakan kepada kami [Yunus] Telah menceritakan kepada kami [Hammad] yakni Ibnu Salamah, dari [Yunus] dan [Tsabit] dan [Humaid] dan [Habib] dari [Al Hasan] dari [Hiththan bin Abdullah Ar Raqasyi] dari [Abu Musa Al Asy'ari] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya menjelang datangnya hari kiamat.\" Ia pun menyebutkan hadits semisal haditsnya Abdush Shamad dari Hammad dari Ali bin Zaid, hanya saja ia mengatakan; Abu Musa berkata, \"Demi Dzat yang jiwaku berada di tangan-Nya, saya tidak mendapatkan lagi sesuatu bagiku dan bagi kalian setelah mendapatkan hari-hari fitnah itu, kecuali kita harus keluar darinya sebagaimana kita telah memasukinya. Kita tidak menumpahkan darah dan tidak pula menjarah harta.\""},"2502":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ لَيْثٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَرَرْتُمْ بِالسِّهَامِ فِي أَسْوَاقِ الْمُسْلِمِينَ أَوْ فِي مَسَاجِدِهِمْ فَأَمْسِكُوا بِالْأَنْصَالِ لَا تَجْرَحُوا بِهَا أَحَدًا","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Sufyan] dari [Laits] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kalian lewat di pasar-pasar kaum muslimin atau di dalam masjid-masjid mereka dengan membawa tombak, maka jagalah mata tombaknya, jangan sampai kalian melukai seorang pun.\""},"2503":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَنْبَأَنَا مَعْمَرٌ عَنْ مَطَرٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ الْأَسْلَمِيِّ قَالَشَكَّ عُبَيْدُ اللَّهِ بْنُ زِيَادٍ فِي الْحَوْضِ فَأَرْسَلَ إِلَى أَبِي بَرْزَةَ الْأَسْلَمِيِّ فَأَتَاهُ فَقَالَ لَهُ جُلَسَاءُ عُبَيْدِ اللَّهِ إِنَّمَا أَرْسَلَ إِلَيْكَ الْأَمِيرُ لِيَسْأَلَكَ عَنْ الْحَوْضِ هَلْ سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ شَيْئًا قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُهُ فَمَنْ كَذَّبَ بِهِ فَلَا سَقَاهُ اللَّهُ مِنْهُ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah memberitakan pada kami [Ma'mar] dari [Mathar] dari [Abdullah bin Buraidah Al Aslamy] berkata; Ubaidullah bin Ziyad masih ragu-ragu tentang Al Haudh (telaga di surga) maka dia pun mengutus seseorang ke Abu Barzah Al Aslamy yang menyampaikan pesan agar menemui Ubaidillah bin Ziyad. Lalu utusan tersebut mendatanginya, sesampainya di sana, para sahabat Ubaidullah bertanya kepada [Abu Barzah al-aslamy]; \"Sang amir (pemimpin) kita mengutus utusan kepadamu, dalam rangka menanyakan kepadamu tentang Al Haudh (telaga di surga), apakah engkau pernah mendengar dari Rasulullah shallallahu 'alaihi wasallam tentang hal itu?.\" Dia menjawab; \"Ya, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam menyebutkannya bahwa barangsiapa yang mendustakannya(Al Haudh) maka Allah tidak akan memberi minum darinya.\""},"2504":{"ar":"حَدَّثَنَا مُعْتَمِرٌ قَالَ أَنْبَأَنِي أَبِي عَنْ أَبِي الْمِنْهَالِ عَنْ أَبِي بَرْزَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الْغَدَاةِ بِالْمِائَةِ إِلَى السِّتِّينَ وَالسِّتِّينَ إِلَى الْمِائَةِ","id":"Telah menceritakan kepada kami [Mu'tamar] ia berkata; telah mengkabarkan kepada kami [ayahku] dari [Abul Minhal] dari [Abu Barzah] bahwa sesungguhnya Rasulullah shallallahu 'alaihi wasallam membaca di shalat zhuhur seratus sampai enam puluh ayat dan enam puluh hingga seratus ayat."},"2505":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي بَرْزَةَ قَالَكَانَتْ رَاحِلَةٌ أَوْ نَاقَةٌ أَوْ بَعِيرٌ عَلَيْهَا بَعْضُ مَتَاعِ الْقَوْمِ وَعَلَيْهَا جَارِيَةٌ فَأَخَذُوا بَيْنَ جَبَلَيْنِ فَتَضَايَقَ بِهِمْ الطَّرِيقُ فَأَبْصَرَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ حَلْ حَلْ اللَّهُمَّ الْعَنْهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَاحِبُ هَذِهِ ا��ْجَارِيَةِ لَا تَصْحَبُنَا رَاحِلَةٌ أَوْ نَاقَةٌ أَوْ بَعِيرٌ عَلَيْهَا مِنْ لَعْنَةِ اللَّهِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Sulaiman] dari [Abu Utsman] dari [Abu Barzah] berkata bahwasanya ada seekor unta atau unta yang biasa digunakan buat perjalanan, di atasnya terdapat perbekalan empunya juga ada seorang budak wanita, ketika mereka sampai diantara dua gunung maka jalan terasa sulit dan sempit bagi mereka, lantas dia (budak wanita tersebut) melihat Rasulullah shallallahu 'alaihi wasallam, lalu dia berkata; \"Hus..hus...ya Allah laknatlah unta itu!.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Siapakah yang mempunyai budak wanita ini?, janganlah mengikuti kami unta atau kendaraan yang telah dilaknat.\""},"2506":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَوَكِيعٌ قَالَا ثَنَا أَبَانُ بْنُ صَمْعَةَ عَنْ أَبِي الْوَازِعِ عَنْ أَبِي بَرْزَةَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَلِّمْنِي شَيْئًا أَنْتَفِعُ بِهِ قَالَ اعْزِلْ الْأَذَى عَنْ طَرِيقِ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dan [Waki'], keduanya berkata; telah menceritakan kepada kami [Aban bin Sham'ah] dari [Abi Wazi'] dari [Abu Barzah] berkata; Aku bertanya; \"Wahai Rasulullah, ajarkanlah padaku sesuatu yang dapat bermanfaat bagiku!.\" Beliau menjawab: \"Singkirkanlah sesuatu yang membahayakan dari jalan orang Islam.\""},"2507":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ أَنْبَأَنَا حَجَّاجٌ عَنْ أَبِي هَاشِمٍ الْوَاسِطِيِّ عَنْ رُفَيْعٍ أَبِي الْعَالِيَةِ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِآخِرَةٍ إِذَا طَالَ الْمَجْلِسُ فَقَامَ قَالَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا أَنْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ فَقَالَ لَهُ بَعْضُنَا إِنَّ هَذَا قَوْلٌ مَا كُنَّا نَسْمَعُهُ مِنْكَ فِيمَا خَلَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا كَفَّارَةُ مَا يَكُونُ فِي الْمَجْلِسِ","id":"Telah menceritakan kepada kami [Abdullah bin Numair]; telah mengkabarkan kepada kami [Hajjaj] dari [Abu Hasyim al Wasithi] dari [Rufa'I Abul 'Aliyah] dari [Abu Barzah Al Aslamy] berkata; bahwasanya Nabi shallallahu 'alaihi wasallam diakhir majlis berdo'a \"Subhanaka Allahumma wabihamdika asyhadu alla ilaaha illa anta astaghfiruka waatubu ilaika\" (mahasuci Engkau ya Allah dan segala puji bagi-Mu, aku bersaksi bahwa tidak ada tuhan yang berhak untuk disembah kecuali Engkau, aku memohon ampun kepada-Mu dan bertaubat kepada-Mu).\" Sebagian kami berkata; \"Sungguh ini adalah perkataan yang belum pernah kami dengar dari anda setiap kali selesai majlis.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini adalah sebuah penghapus dosa terhadap dosa yang terjadi di dalam majlis.\""},"2508":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْأَزْرَقِ بْنِ قَيْسٍ قَالَكَانَ أَبُو بَرْزَةَ بِالْأَهْوَازِ عَلَى جَرْفِ نَهْرٍ وَقَدْ جَعَلَ اللِّجَامَ فِي يَدِهِ وَجَعَلَ يُصَلِّي فَجَعَلَتْ الدَّابَّةُ تَنْكُصُ وَجَعَلَ يَتَأَخَّرُ مَعَهَا فَجَعَلَ رَجُلٌ مِنْ الْخَوَارِجِ يَقُولُ اللَّهُمَّ اخْزِ هَذَا الشَّيْخَ كَيْفَ يُصَلِّي فَلَمَّا صَلَّى قَالَ قَدْ سَمِعْتُ مَقَالَتَكُمْ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتًّا أَوْ سَبْعًا أَوْ ثَمَانِيًا فَشَهِدْتُ أَمْرَهُ وَتَيْسِيرَهُ فَكَانَ رُجُوعِي مَعَ دَابَّتِي أَهْوَنَ عَلَيَّ مِنْ تَرْكِهَا فَتَنْزِعُ إِلَى مَأْلَفِهَا فَيَشُقُّ عَلَيَّ وَصَلَّى أَبُو بَرْزَةَ الْعَصْرَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Al Azraq bin Qais] berkata; bahwasanya [Abu Barzah] ketika di daerah Ahwaz di tepian sungai, sedang tali kekang binatang tunggangannya berada di tangannya, sambil ia melaksanakan shalat. Lantas binatang kendaraannya tersebut berjalan mundur sehingga ia ikut mundur bersamanya. Lalu seorang dari Khawarij mendo'akannya; \"Ya Allah, hinakanlah orang tua ini, bagaimana dia melaksanakan shalatnya ini. Ketika ia selesai melaksanakan shalat, ia berkata; \"Aku telah mendengar perkataan kalian, aku telah berperang bersama Rasulullah shallallahu 'alaihi wasallam enam, tujuh atau delapan kali, dan aku menyaksikan urusannya dan Kemudahannya, mundurnya aku dan kendaraanku lebih mudah bagiku dari pada aku meninggalkan untaku sehingga perlu dijinakkan kembali dan itu sangat sangat menyulitkanku.\" (Waktu itu) Abu Barzah melaksanakan shalat 'ashar dua rakaat."},"2509":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَ أَبُو الْأَشْهَبِ لَا أَعْلَمُهُ إِلَّا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَإِنَّ مِمَّا أَخْشَى عَلَيْكُمْ شَهَوَاتِ الْغَيِّ فِي بُطُونِكُمْ وَفُرُوجِكُمْ وَمُضِلَّاتِ الْفِتَنِ","id":"Telah menceritakan kepada kami [Yunus] telah menceritakan kepada kami [Abul Asyhab] dari [Ali bin Al Hakam] dari [Abu Barzah Al Aslamy]. Abul Asyhab berkata; \"Aku tidak mengetahuinya kecuali dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya yang paling aku takutkan dari kalian adalah syahwat menyimpang yang terdapat dalam perut, dan kemaluan kalian, dan juga fitnah-fitnah yang menyesatkan.\""},"2510":{"ar":"حَدَّثَنَاه يَزِيدُ قَالَ أَخْبَرَنَا أَبُو الْأَشْهَبِ عَنْ أَبِي الْحَكَمِ الْبُنَانِيِّ عَنْ أَبِي بَرْزَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِمَّا أَخْشَى عَلَيْكُمْ شَهَوَاتِ الْغَيِّ فِي بُطُونِكُمْ وَفُرُوجِكُمْ وَمُضِلَّاتِ الْهَوَى","id":"Telah menceritakan sebuah hadits pada kami [Yazid] telah mengkabarkan kepada kami [Abul Asyhab] dari [Abul Hakam Al Bunany] dari [Abu Barzah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sungguh yang sangat aku takutkan dari kalian adalah syahwat keji dari perut, dan kemaluan kalian, serta hawa nafsu yang menyesatkan.\""},"2511":{"ar":"حَدَّثَنَا حَجَّاجٌ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي حَمْزَةَ جَارِهِمْ قَالَ سَمِعْتُ حُمَيْدَ بْنَ هِلَالٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ مُطَرِّفٍ عَنْ أَبِي بَرْزَةَ قَالَكَانَ أَبْغَضَ النَّاسِ أَوْ أَبْغَضَ الْأَحْيَاءِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَقِيفُ وَبَنُو حَنِيفَةَ","id":"Telah menceritakan kepada kami [Hajjaj] telah mengkabarkan kepada kami [Syu'bah] dari [Abu Hamzah Jarihim] berkata; aku mendengar [Humaid bin Hilal] menceritakan dari [Abdullah bin Mutharrif] dari [Abu Barzah] berkata; \"Manusia atau kabilah yang paling dibenci Rasulullah shallallahu 'alaihi wasallam adalah bani Tsaqif dan bani Hanifah.\""},"2512":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ شَاذَانُ أَخْبَرَنَا أَبُو بَكْرٍ يَعْنِي ابْنَ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ سَعِيدِ بْنِ عَبْدِ اللَّهِ بْنِ جُرَيْجٍ عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ مَنْ آمَنَ بِلِسَانِهِ وَلَمْ يَدْخُلْ الْإِيمَانُ قَلْبَهُ لَا تَغْتَابُوا الْمُسْلِمِينَ وَلَا تَتَّبِعُوا عَوْرَاتِهِمْ فَإِنَّهُ مَنْ يَتَّبِعْ عَوْرَاتِهِمْ يَتَّبِعْ اللَّهُ عَوْرَتَهُ وَمَنْ يَتَّبِعْ اللَّهُ عَوْرَتَهُ يَفْضَحْهُ فِي بَيْتِهِ","id":"Telah menceritakan kepada kami [Aswad bin Amir bin Syadzan]; telah mengkabarkan kepada kami [Abu Bakar] yaitu Ibnu 'Ayyasy dari [Al A'masy] dari [Sa'id bin Abdillah bin Juraij] dari [Abu Barzah Al Aslamy] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai orang yang imannya masih sebatas lisannya dan belum masuk ke hati, janganlah kalian menggunjing orang-orang muslim, janganlah kalian mencari-cari aurat ('aib) mereka. Karena barang siapa yang selalu mencari-cari kesalahan mereka, maka Allah akan membongkar kesalahannya, serta barang siapa yang diungkap auratnya oleh Allah, maka Dia akan memperlihatkannya (aibnya) di rumahnya.\""},"2513":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ ابْنِ أَخِي مُطَرِّفِ بْنِ الشِّخِّيرِ قَالَ سَمِعْتُ مُطَرِّفًا يُحَدِّثُ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ هَلْ صُمْتَ مِنْ سُرَرِ هَذَا الشَّهْرِ شَيْئًا يَعْنِي شَعْبَانَ فَقَالَ لَا قَالَ فَقَالَ لَهُ إِذَا أَفْطَرْتَ رَمَضَانَ فَصُمْ يَوْمًا أَوْ يَوْمَيْنِ شَكَّ الَّذِي شَكَّ فِيهِ قَالَ وَأَظُنُّهُ قَالَ يَوْمَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far]; telah menceritakan kepada kami [Syu'bah] dari [Ibnu Akhi Mutharrif bin Syikhir] dari [Mutharrif bin Syikhkhir] berkata; \"Aku mendengar sebuah hadits dari [Imran bin Hushain] radliallahu 'anhu bahwasanya Nabi shallallahu 'alaihi wasallam bersabda kepada seseorang: \"Apakah kamu berpuasa pada pertengahan bulan ini yaitu Sya'ban?.\" Dia menjawab; \"Tidak!.\" Beliau bersabda kepadanya lagi: \"Apabila kamu telah selesai puasa pada bulan ramadhan, maka berpuasalah sehari atau dua hari. -dia ragu kepastiannya--, sementara aku mengiranya dua hari.\""},"2514":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ غَيْلَانَ بْنِ جَرِيرٍ وَعَبْدُ الْوَهَّابِ عَنِ صَاحِبٍ لَهُ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ مُطَرِّفِ بْنِ الشِّخِّيرِ أَنَّهُ قَالَكُنْتُ مَعَ عِمْرَانَ بْنِ حُصَيْنٍ بِالْكُوفَةِ فَصَلَّى بِنَا عَلِيُّ بْنُ أَبِي طَالِبٍ فَجَعَلَ يُكَبِّرُ كُلَّمَا سَجَدَ وَكُلَّمَا رَفَعَ رَأْسَهُ فَلَمَّا فَرَغَ قَالَ عِمْرَانُ صَلَّى بِنَا هَذَا مِثْلَ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Sa'id bin Ghailan bin Jabir] dan [Abdul Wahhab] dari [sahabatnya] dari [Ghailan bin Jarir] dari [Mutharrif bin Asy Syikhir] berkata; \"Aku bersama Imran bin Hushain radliallahu 'anhu di Kufah, lalu Ali bin Abu Thalib radliallahu 'anhu shalat mengimami kami, dia bertakbir setiap bersujud dan bangun dari sujud. Setelah selesai, [Imran bin Hushain] radliallahu 'anhu berkata; \"Dia shalat mengimami kami ini sebagaimana shalat Rasulullah shallallahu 'alaihi wasallam.\""},"2515":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَابْنُ نُمَيْرٍ قَالَا ثَنَا سَعِيدٌ وَيَزِيدُ أَخْبَرَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَ��ْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا عَضَّ رَجُلًا عَلَى ذِرَاعِهِ قَالَ ابْنُ نُمَيْرٍ فَنَزَعَ يَدَهُ مِنْهُ فَسَقَطَتْ ثَنِيَّتَاهُ فَجَذَبَهَا فَانْتَزَعَتْ ثَنِيَّتَهُ فَرُفِعَ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبْطَلَهَا وَقَالَ أَرَدْتَ أَنْ تَقْضَمَ لَحْمَ أَخِيكَ كَمَا يَقْضَمُ الْفَحْلُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Ibnu Numair] keduanya berkata; telah menceritakan kepada kami [Sa'id] dan [Yazid] telah mengkabarkan kepada kami [Sa'id] dari [Qatadah] dari [Zurarah bin `Aufa] dari ['Imron bin Hushain] bahwa ada seseorang yang telah menggigit lengan orang lain. Ibnu Numair berkata; Lantas ia menarik tangannya sehingga rontok dua gigi serinya. Namun di kemudian hari berkata dengan redaksi \"Menariknya hingga giginya (bukan dua gigi) tersebut terlepas. Kemudian hal itu dilaporkan kehadapan Rasulullah dan beliau pun membatalkannya (maksudnya tidak ada diyat) dan beliau bersabda: \"Kalian menginginkan merobek daging saudara kalian sebagaimana kuda merobeknya?.\""},"2516":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِأَنَّ هَيَّاجَ بْنَ عِمْرَانَ أَتَى عِمْرَانَ بْنَ حُصَيْنٍ فَقَالَ إِنَّ أَبِي قَدْ نَذَرَ لَئِنْ قَدَرَ عَلَى غُلَامِهِ لَيَقْطَعَنَّ مِنْهُ طَابِقًا أَوْ لَيَقْطَعَنَّ يَدَهُ فَقَالَ قُلْ لِأَبِيكَ يُكَفِّرْ عَنْ يَمِينِهِ وَلَا يَقْطَعْ مِنْهُ طَابِقًا فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَحُثُّ فِي خُطْبَتِهِ عَلَى الصَّدَقَةِ وَيَنْهَى عَنْ الْمُثْلَةِثُمَّ أَتَى سَمُرَةَ بْنَ جُنْدُبٍ فَقَالَ لَهُ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] bahwa Hayyaj bin 'Imran datang menemui ['Imran bin Hushain] dan bertanya; \"Sesungguhnya ayahku telah bernazar, apabila dia mendapatkan budaknya, maka dia akan memotong tangannya?.\" 'Imran berkata; \"Katakanlah kepada ayahmu, hendaknya dia membayar kafarat dari sumpahnya dan janganlah dia memotong tangan budaknya karena dalam khutbahnya, Rasulullah shallallahu 'alaihi wasallam selalu memotivasi untuk bersedekah dan melarang melakukan mutilasi.\" Setelah itu, dia mendatangi [Samurah bin Jundub], ternyata Samurah juga mengatakan hal yang sama.\""},"2517":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِأَنَّ رَجُلًا مِنْ الْأَنْصَارِ أَعْتَقَ رُءُوسًا سِتَّةً عِنْدَ مَوْتِهِ وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُمْ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَغْلَظَ لَهُ فَدَعَا بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْرَعَ بَيْنَهُمْ فَأَعْتَقَ اثْنَيْنِ وَرَدَّ أَرْبَعَةً فِي الرِّقِّ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari ['Imran bin Hushain] bahwa ada seorang dari Anshar membebaskan enam budaknya ketika hendak meninggal dunia, namun ia tidak memiliki harta selain budak tersebut. Ketika hal itu dilaporkan pada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah menyalahkannya dan memanggil seluruh budak itu, kemudian budak-budak tersebut diundi hingga dua orang budak menjadi merdeka sedang empat lainnya tetap menjadi budak.\""},"2518":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا الْحَسَنُ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ ابْنِي مَاتَ فَمَا لِي مِنْ مِيرَاثِهِ قَالَ لَكَ السُّدُسُ قَالَ فَلَمَّا أَدْبَرَ دَعَاهُ قَالَ لَكَ آخَرُ فَلَمَّا أَدْبَرَ دَعَاهُ قَالَ إِنَّ السُّدُسَ الْآخَرَ طُعْمَةٌ","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari ['Imran bin Hushain] bahwa seseorang datang menemui Rasulullah shallallahu 'alaihi wasallam sambil berkata; \"Anakku telah meninggal, lantas berapa bagiankah yang aku dapatkan dari harta peninggalannya?.\" Beliau menjawab: \"Kamu mendapatkan seperenam.\" Ketika dia beranjak pulang, beliau memanggilnya lagi lalu bersabda: \"Bagimu ada yang lain (sisa).\" Ketika dia beranjak pulang, beliau memanggilnya lagi lalu bersabda: \"Sesungguhnya seperenam yang lain merupakan harta pemberian.\""},"2519":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ أَوْ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّهُ قَالَأَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَانَا عَنْ لُبْسِ الْحَرِيرِ وَعَنْ الشُّرْبِ فِي الْحَنَاتِمِ","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Aban bin Yazid], telah menceritakan kepada kami [Qatadah] dari [Abu Nadlrah] dari [Abu Sa'id] atau dari ['Imran bin Hushain] bahwa ia berkata; \"Aku bersaksi atas nama Rasulullah shallallahu 'alaihi wasallam bahwa beliau melarang kita memakai pakaian sutera dan meminum dari hanatim.\" "},"2520":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا قَتَادَةُ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَزَالُ طَائِفَةٌ مِنْ أُمَّتِي عَلَى الْحَقِّ ظَاهِرِينَ عَلَى مَنْ نَاوَأَهُمْ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ تَبَارَكَ وَتَعَالَى وَيَنْزِلَ عِيسَى ابْنُ مَرْيَمَ عَلَيْهِ السَّلَام","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Qatadah] dari [Mutharrif] dari ['Imran bin Hushain] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekelompok dari umatku akan senantiasa berada diatas kebenaran dan selalu menang terhadap orang yang memusuhi mereka, hingga datang urusan Allah tabaraka wata'ala dan turunnya Isa bin Maryam 'alaihissalam.\""},"2521":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَوْفٌ عَنْ أَبِي رَجَاءٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطَّلَعْتُ فِي النَّارِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ وَاطَّلَعْتُ فِي الْجَنَّةِ فَرَأَيْتُ أَكْثَرَ أَهْلِهَا الْفُقَرَاءَحَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا سَلْمُ بْنُ زَرِيرٍ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اطَّلَعْتُ فَذَكَرَ مِثْلَهُ حَدَّثَنَا الْخَفَّافُ أَخْبَرَنَا سَعِيدٌ عَنْ أَبِي رَجَاءٍ عَنِ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami ['Auf] dari [Abu Raja'] dari ['Imran bin Hushain] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku melongok keneraka, maka aku melihat kebanyakan penghuninya adalah wanita. Dan aku melongok kesurga, maka aku melihat kebanyakan penghuninya adalah orang-orang fakir.\" Telah berkata kepada kami [Abdusshamad] telah berkata kepada kami [Salam bin Zarir] telah berkata kepada kami [Abu Raja`] dari ['Imran bin Hushain] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku melongok…-seperti hadits diatas-. Telah menceritakan kepada kami [Al Khaffaf] telah mengabarkan kepada kami [Sa'id] dari [Abu Raja'] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"2522":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي قَزَعَةَ عَنِ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا جَلَبَ وَلَا جَنَبَ وَلَا شِغَارَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Abu Qaza'ah] dari [Al Hasan] dari ['Imran bin Hushain] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada jalb, tidak ada janab dan tidak ada nikah syighar.\" "},"2523":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ حَدَّثَنِي شِبْلُ بْنُ عَبَّادٍ وَابْنُ أَبِي بُكَيْرٍ يَعْنِي يَحْيَى بْنَ أَبِي بُكَيْرٍ حَدَّثَنَا شِبْلُ بْنُ عَبَّادٍ الْمَعْنَى قَالَ سَمِعْتُ أَبَا قَزَعَةَ يُحَدِّثُ عَمْرَو بْنَ دِيْنَارٍ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ الْبَهْزِيِّ عَنْ أَبِيهِ أَنَّهُقَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي حَلَفْتُ هَكَذَا وَنَشَرَ أَصَابِعَ يَدَيْهِ حَتَّى تُخْبِرَنِي مَا الَّذِي بَعَثَكَ اللَّهُ تَبَارَكَ وَتَعَالَى بِهِ قَالَ بَعَثَنِي اللَّهُ تَبَارَكَ وَتَعَالَى بِالْإِسْلَامِ قَالَ وَمَا الْإِسْلَامُ قَالَ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَتُقِيمُ الصَّلَاةَ وَتُؤْتِي الزَّكَاةَ أَخَوَانِ نَصِيرَانِ لَا يَقْبَلُ اللَّهُ عَزَّ وَجَلَّ مِنْ أَحَدٍ تَوْبَةً أَشْرَكَ بَعْدَ إِسْلَامِهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ مَا حَقُّ زَوْجِ أَحَدِنَا عَلَيْهِ قَالَ تُطْعِمُهَا إِذَا أَكَلْتَ وَتَكْسُوهَا إِذَا اكْتَسَيْتَ وَلَا تَضْرِبْ الْوَجْهَ وَلَا تُقَبِّحْ وَلَا تَهْجُرْ إِلَّا فِي الْبَيْتِ ثُمَّ قَالَ هَاهُنَا تُحْشَرُونَ هَاهُنَا تُحْشَرُونَ هَاهُنَا تُحْشَرُونَ ثَلَاثًا رُكْبَانًا وَمُشَاةً وَعَلَى وُجُوهِكُمْ تُوفُونَ يَوْمَ الْقِيَامَةِ سَبْعِينَ أُمَّةً أَنْتُمْ آخِرُ الْأُمَمِ وَأَكْرَمُهَا عَلَى اللَّهِ تَبَارَكَ وَتَعَالَى تَأْتُونَ يَوْمَ الْقِيَامَةِ وَعَلَى أَفْوَاهِكُمْ الْفِدَامُ أَوَّلُ مَا يُعْرِبُ عَنْ أَحَدِكُمْ فَخِذُهُ قَالَ ابْنُ أَبِي بُكَيْرٍ فَأَشَارَ بِيَدِهِ إِلَى الشَّامِ فَقَالَ إِلَى هَاهُنَا تُحْشَرُونَ","id":"Telah menceritakan kepada kami [Abdullah bin Harits], telah menceritakan padaku [Syibl bin 'Abbad] dan [Ibnu Abu Bukair yaitu Yahya bin Abu Bukair], telah menceritakan kepada kami [Syibl bin 'Abbad] secara makna, ia berkata; Aku mendengar [Abu Qaza'ah] menceritakan kepada 'Amru bin Dinar dari [Hakim bin Mu'awiyah Al Bahzi] dari [Ayahnya] bahwa ia berkata pada Nabi Shalallahu 'alaihi wasallam; \"Sungguh aku telah bersumpah seperti ini, -sambil merekahkan jarinya- hingga engkau mengabariku untuk apa Allah Tabaraka wa Ta'ala mengutusmu?.\" Beliau bersabda: \"Allah Tabaraka Wata'ala mengutusku dengan Islam.\" Mu'awiyah bertanya; \"Apakah Islam itu?.\" Beliau menjawab: \"Syahadat Laa Ilaaha Illallah wa Anna Muhammadan 'Abduhu Wa Rasuluhu (bersaksi bahwa tiada Ilah kecuali Allah dan Muhammad adalah hamba dan utusan-Nya), kamu mendirikan shalat, menunaikan zakat, ia merupakan dua hal yang selalu bersambung, dan Allah Azza Wa Jalla tidak akan menerima taubat seorang hamba yang menyekutukan-Nya setelah ia masuk Islam.\" Mu'awiyah berkata; Aku bertanya pada Rasulullah shallallahu 'alaihi wasallam; \"Wahai Rasulullah, apa hak seorang istri terhadap suami?.\" Beliau bersabda: \"Memberinya makan bila kamu makan, memberinya pakaian bila kamu berpakaian, jangan kamu pukul wajahnya, jangan kamu jelekkan dan jangan kamu menghajr (memisahkan diri dari kamar tidur) kecuali di satu rumah.\" Kemudian beliau melanjutkan: \"Di sinilah kalian akan dikumpulkan, di sinilah kalian akan dikumpulkan dan di sinilah kalian akan di kumpulkan -sebanyak tiga kali-, dalam keadaan berkendaraan dan tak berjalan kaki dan kalian akan dikumpulkan di hari kiamat selepas kematian kalian di antara tujuh puluh umat, sedangkan kalian adalah umat yang paling terakhir dari mereka, sementara kalian adalah ummat yang dimuliakan disisi Allah Tabaraka Wata'ala. Kalian datang di hari kiamat dalam keadaan mulut kalian terkunci, dan yang pertama kali berbicara adalah kaki-kaki kalian (paha).\" Ibnu Abu Bukair berkata; Lalu beliau menunjukkan dengan isyarat tangannya ke arah Syam sambil bersabda: \"Kesanalah kalian akan dikumpulkan.\""},"2524":{"ar":"حَدَّثَنَا مُهَنَّأُ بْنُ عَبْدِ الْحَمِيدِ أَبُو شِبْلٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي قَزَعَةَ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ رَجُلًا كَانَ فِيمَنْ كَانَ قَبْلَكُمْ رَغَسَهُ اللَّهُ تَبَارَكَ وَتَعَالَى مَالًا وَوَلَدًا حَتَّى ذَهَبَ عَصْرٌ وَجَاءَ عَصْرٌ فَلَمَّا حَضَرَتْهُ الْوَفَاةُ قَالَ أَيْ بَنِيَّ أَيَّ أَبٍ كُنْتُ لَكُمْ قَالُوا خَيْرَ أَبٍ قَالَ فَهَلْ أَنْتُمْ مُطِيعِيَّ قَالُوا نَعَمْ قَالَ انْظُرُوا إِذَا مُتُّ أَنْ تُحَرِّقُونِي حَتَّى تَدَعُونِي فَحْمًا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَعَلُوا ذَلِكَ ثُمَّ اهْرُسُونِي بِالْمِهْرَاسِ يُومِئُ بِيَدِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَعَلُوا وَاللَّهِ ذَلِكَ ثُمَّ اذْرُونِي فِي الْبَحْرِ فِي يَوْمِ رِيحٍ لَعَلِّي أَضِلُّ اللَّهَ تَبَارَكَ وَتَعَالَى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَعَلُوا وَاللَّهِ ذَلِكَ فَإِذَا هُوَ فِي قَبْضَةِ اللَّهِ تَبَارَكَ وَتَعَالَى فَقَالَ يَا ابْنَ آدَمَ مَا حَمَلَكَ عَلَى مَا صَنَعْتَ قَالَ أَيْ رَبِّ مَخَافَتُكَ قَالَ فَتَلَافَاهُ اللَّهُ تَبَارَكَ وَتَعَالَى بِهَا","id":"Telah menceritakan kepada kami [Muhanna` bin Abdul Hamid Abu Syibl], telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Qaza'ah] dari [Hakim bin Mu'awiyah] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang lelaki dari kaum sebelum kalian ada yang Allah berikan kepadanya harta dan anak yang banyak hingga generasi silih berganti. Ketika hendak meninggal, laki-laki berkata; 'Wahai anak-anakku, menurut kalian, aku ini ayah macam apa?.' Mereka berkata; 'Ayah adalah orang yang terbaik!.' Dia berkata lagi; 'Apakah kalian akan mentaatiku?.' Mereka berkata; 'Ya!.' Dia bertanya lagi; 'Nanti kalau aku telah meninggal, bakarlah aku dan biarkanlah aku hingga menjadi arang.' -Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka anak-anaknya pun melakukan wasiat ayahnya.\"- (kata laki-laki itu selanjutnya) Kemudian tumbuklah arangku dengan alat penumbuk.' -seraya memberi isyarat dengan tangannya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lalu merekapun melakukannya.\"- 'Kemudian buanglah aku ke tengah lautan di hari-hari yang anginnya kencang agar Allah Tabaraka Wa Ta'ala tidak dapat menemukanku.' Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah, merekapun melakukan perintah itu. Ternyata laki-laki itu sudah berada dalam genggaman Allah Tabaraka Wata'ala. Maka Allah berkata kepadanya: 'Wahai anak Adam, apakah yang membuatmu melakukan demikian (menyuruh membakar diri)?.' Dia menjawab; 'Ya Rabb-ku, karena takut kepada-Mu!.' Maka Allah Tabaraka Wa Ta'ala mengampuninya.\""},"2525":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي قَزَعَةَ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَأَلَهُ رَجُلٌ مَا حَقُّ الْمَرْأَةِ عَلَى الزَّوْجِ قَالَ تُطْعِمُهَا إِذَا طَعِمْتَ وَتَكْسُوهَا إِذَا اكْتَسَيْتَ وَلَا تَضْرِبْ الْوَجْهَ وَلَا تُقَبِّحْ وَلَا تَهْجُرْ إِلَّا فِي الْبَيْتِ","id":"Telah menceritakan kepada kami [Yazid], telah mengabarkan pada kami [Syu'bah], dari [Abu Qaza'ah] dari [Hakim bin Mu'awiyah] dari [Ayahnya] dari Nabi Shalallahu 'alaihi wasallam, Seseorang bertanya kepada beliau; \"Apa hak seorang istri dari suaminya?.\" beliau menjawab: \"Kamu memberinya makan sebagaimana kamu makan, memberinya pakaian sebagaimana kamu berpakaian, tidak memukul wajahnya, tidak menjelek-jelekkannya dan tidak menghajrnya (memisahkan dari tempat tidur) kecuali di dalam rumah.\""},"2526":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا أَبُو قَزَعَةَ سُوَيْدُ بْنُ حُجَيْرٍ الْبَاهِلِيُّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِأَنَّ أَخَاهُ مَالِكًا قَالَ يَا مُعَاوِيَةُ إِنَّ مُحَمَّدًا أَخَذَ جِيرَانِي فَانْطَلِقْ إِلَيْهِ فَإِنَّهُ قَدْ عَرَفَكَ وَكَلَّمَكَ قَالَ فَانْطَلَقْتُ مَعَهُ فَقَالَ دَعْ لِي جِيرَانِي فَإِنَّهُمْ قَدْ كَانُوا أَسْلَمُوا فَأَعْرَضَ عَنْهُ فَقَامَ مُتَمَعِّطًا فَقَالَ أَمْ وَاللَّهِ لَئِنْ فَعَلْتَ إِنَّ النَّاسَ لَيَزْعُمُونَ أَنَّكَ تَأْمُرُ بِالْأَمْرِ وَتَخْلُفُ إِلَى غَيْرِهِ وَجَعَلْتُ أَجُرُّهُ وَهُوَ يَتَكَلَّمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَقُولُ فَقَالُوا إِنَّكَ وَاللَّهِ لَئِنْ فَعَلْتَ ذَلِكَ إِنَّ النَّاسَ لَيَزْعُمُونَ أَنَّكَ لَتَأْمُرُ بِالْأَمْرِ وَتُخَالِفُ إِلَى غَيْرِهِ قَالَ فَقَالَ أَوَ قَدْ قَالُوهَا أَوْ قَائِلُهُمْ فَلَئِنْ فَعَلْتُ ذَاكَ وَمَا ذَاكَ إِلَّا عَلَيَّ وَمَا عَلَيْهِمْ مِنْ ذَلِكَ مِنْ شَيْءٍ أَرْسِلُوا لَهُ جِيرَانَهُ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan pada kami [Abu Qaza'ah Suwaid bin Hujair Al Bahili] dari [Hakim bin Mu'awiyah] dari [Ayahnya] bahwa saudaranya Malik berkata kepadanya; \"Wahai Muawiyah, sesungguhnya Muhammad telah menawan tetanggaku maka marilah kita pergi karena dia mengenalmu dan telah berbicara kepadamu, \" Mu'awiyah berkata; \"Lalu aku pergi bersamanya, (sesampainya di hadapan Rasulullah Shallalahu 'alaihi wasallam) Malik berkata; \"Biarkanlah tetanggaku bersamaku karena dia telah masuk Islam sebelumnya!.\" Akan tetapi beliau menolaknya, maka Malik berdiri seraya menghunuskan pedang, sambil berkata; \"Demi Allah, sungguh jika kamu tetap melakukan itu, orang-orang pasti akan menganggap bahwa kamu memerintahkan yang ma'ruf tetapi kamu sendiri menyelisihinya.\" Maka aku menariknya, namun dia tetap berbicara. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang kamu katakan?.\" Mereka menjawab; \"Demi Allah, sungguh jika kamu tetap melakukan itu, orang-orang pasti akan menganggap bahwa kamu memerintahkan yang ma'ruf tetapi kamu sendiri menyelisihinya.\" Beliau pun bersabda: \"Apakah mereka telah mengatakan itu kalau aku melakukannya? Dan itu bukan kewajibanku dan mereka juga tidak dipaksa sedikitpun, kerimlah tetangganya kepadanya (maksudnya melepaskan)!.\""},"2527":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنِ الْجُرَيْرِيِّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَأَنْتُمْ تُوفُونَ سَبْعِينَ أُمَّةً أَنْتُمْ خَيْرُهَا وَأَكْرَمُهَا عَلَى اللَّهِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah] dari [Al Jurari] dari [Hakim bin Mu'awiyah] dari [Ayahnya] bahwa Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Sungguh kalian sebanding dengan tujuh puluh umat, sedang kalian adalah yang terbaik dan mulia diantara mereka di hadapan Allah Tabaraka Wa Ta'ala.\""},"2528":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ أَبَاهُ أَوْ عَمَّهَ قَامَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ جِيرَانِي بِمَ أُخِذُوا فَأَعْرَضَ عَنْهُ ثُمَّ قَالَ أَخْبِرْنِي بِمَ أُخِذُوا فَأَعْرَضَ عَنْهُ فَقَالَ لَئِنْ قُلْتُ ذَاكَ إِنَّهُمْ لَيَزْعُمُونَ أَنَّكَ تَنْهَى عَنْ الْغَيِّ وَتَسْتَخْلِي بِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَالَ فَقَامَ أَخُوهُ أَوْ ابْنُ أَخِيهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهُ قَالَ فَقَالَ لَقَدْ قُلْتُمُوهَا أَوْ قَائِلُكُمْ وَلَئِنْ كُنْتُ أَفْعَلُ ذَلِكَ إِنَّهُ لَعَلَيَّ وَمَا هُوَ عَلَيْكُمْ خَلُّوا لَهُ عَنْ جِيرَانِهِ","id":"Telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Bahz bin Hakim] dari [Ayahnya] dari [kakeknya], bahwa ayah atau kakeknya pernah menemui Nabi shallallahu 'alaihi wasallam, lantas ayah atau kakeknya berujar; \"Dengan alasan apa tetanggaku ditangkap (ditahan)? Beliau kemudian berpaling darinya. Kemudian ayah atau kakeknya berujar lagi; \"Beritahukanlah kepadaku, karena alasan apa mereka ditahan?\" Beliau masih tetap berpaling. Maka ayah atau kakeknya berujar; \"Kalau aku katakan sesuatu, maka orang-orang akan beranggapan bahwa anda melarang kejahatan (penyimpangan), namun anda sendiri melakukannya.\" Lantas Nabi shallallahu 'alaihi wasallam mengucapkan sebagaimana yang beliau ucapkan. Lantas saudara atau keponakan dari ayah atau kakeknya melaporkan; \"Hai Rasulullah, ia telah berkata demikian-demikian.\" Beliau bersabda: \"Kalian atau salah seorang dari kalian telah mengomel sedemikian rupa, kalaulah aku lakukan yang demikian, itu tanggung jawabku bukan tanggung jawab kalian, dan sekarang tolong suruh ia melepaskan tetangganya.\""},"2529":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ عَنْ حَمَّادٍ حَدَّثَنَا أَبُو قَزَعَةَ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى لَا يَقْبَلُ تَوْبَةَ عَبْدٍ كَفَرَ بَعْدَ إِسْلَامِهِ","id":"Telah menceritakan kepada kami [Abu Kamil] dari [Hammad], telah menceritakan kepada kami [Abu Qaza'ah] dari [Hakim bin Mu'awiyah] dari [Ayahnya] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Tabaraka Wa Ta'ala tidak menerima taubat seseorang yang kafir (murtad) setelah keIslamannya.\""},"2530":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَأَلَهُ مَوْلَاهُ فَضْلَ مَالِهِ فَلَمْ يُعْطِهِ جُعِلَ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Ma'mar] dari [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] bahwa ia mendengar Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Barangsiapa yang budaknya meminta sedikit kelebihan hartanya, namun ia menolak, maka akan didatangkan untuknya di hari kiamat seekor ular raksasa.\""},"2531":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَيْلٌ لِلَّذِي يُحَدِّثُ الْقَوْمَ ثُمَّ يَكْذِبُ لِيُضْحِكَهُمْ وَيْلٌ لَهُ وَوَيْلٌ لَهُ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Ma'mar] dari [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celakalah orang yang berbicara kemudian berbohong agar orang lain mentertawakannya, celakalah dia, celakalah dia.\""},"2532":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا أَبُو قَزَعَةَ الْبَاهِلِيُّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مَا أَتَيْتُكَ حَتَّى حَلَفْتُ عَدَدَ أَصَابِعِي هَذِهِ أَنْ لَا آتِيَكَ أَرَانَا عَفَّانُ وَطَبَّقَ كَفَّيْهِ فَبِالَّذِي بَعَثَكَ بِالْحَقِّ مَا الَّذِي بَعَثَكَ بِهِ قَالَ الْإِسْلَامُ قَالَ وَمَا الْإِسْلَامُ قَالَ أَنْ يُسْلِمَ قَلْبُكَ لِلَّهِ تَعَالَى وَأَنْ تُوَجِّهَ وَجْهَكَ إِلَى اللَّهِ تَعَالَى وَتُصَلِّيَ الصَّلَاةَ الْمَكْتُوبَةَ وَتُؤَدِّيَ الزَّكَاةَ الْمَفْرُوضَةَ أَخَوَانِ نَصِيرَانِ لَا يَقْبَلُ اللَّهُ عَزَّ وَجَلَّ مِنْ أَحَدٍ تَوْبَةً أَشْرَكَ بَعْدَ إِسْلَامِهِ قُلْتُ مَا حَقُّ زَوْجَةِ أَحَدِنَا عَلَيْهِ قَالَ تُطْعِمُهَا إِذَا طَعِمْتَ وَتَكْسُوهَا إِذَا اكْتَسَيْتَ وَلَا تَضْرِبْ الْوَجْهَ وَلَا تُقَبِّحْ وَلَا تَهْجُرْ إِلَّا فِي الْبَيْتِ قَالَ تُحْشَرُونَ هَاهُنَا وَأَوْمَأَ بِيَدِهِ إِلَى نَحْوِ الشَّامِ مُشَاةً وَرُكْبَانًا وَعَلَى وُجُوهِكُمْ تُعْرَضُونَ عَلَى اللَّهِ تَعَالَى وَعَلَى أَفْوَاهِكُمْ الْفِدَامُ وَأَوَّلُ مَا يُعْرِبُ عَنْ أَحَدِكُمْ فَخِذُهُ وَقَالَ مَا مِنْ مَوْلًى يَأْتِي مَوْلًى لَهُ فَيَسْأَلُهُ مِنْ فَضْلٍ عِنْدَهُ فَيَمْنَعُهُ إِلَّا جَعَلَهُ اللَّهُ تَعَالَى عَلَيْهِ شُجَاعًا يَنْهَسُهُ قَبْلَ الْقَضَاءِ قَالَ عَفَّانُ يَعْنِي بِالْمَوْلَى ابْنَ عَمِّهِ قَالَ وَقَالَ إِنَّ رَجُلًا مِمَّنْ كَانَ قَبْلَكُمْ رَغَسَهُ اللَّهُ تَعَالَى مَالًا وَوَلَدًا حَتَّى ذَهَبَ عَصْرٌ وَجَاءَ آخَرُ فَلَمَّا احْتُضِرَ قَالَ لِوَلَدِهِ أَيَّ أَبٍ كُنْتُ لَكُمْ قَالُوا خَيْرَ أَبٍ فَقَالَ هَلْ أَنْتُمْ مُطِيعِيَّ وَإِلَّا أَخَذْتُ مَالِي مِنْكُمْ انْظُرُوا إِذَا أَنَا مُتُّ أَنْ تُحَرِّقُونِي حَتَّى تَدَعُونِي حُمَمًا ثُمَّ اهْرُسُونِي بِالْمِهْرَاسِ وَأَدَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ حِذَاءَ رُكْبَتَيْهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَعَلُوا وَاللَّهِ وَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ هَكَذَا ثُمَّ اذْرُونِي فِي يَوْمٍ رَاحٍ لَعَلِّي أَضِلُّ اللَّهَ تَعَالَى كَذَا قَالَ عَفَّانُ قَالَ أَبِي وَقَالَ مُهَنَّا أَبُو شِبْلٍ عَنْ حَمَّادٍ أَضِلُّ اللَّهَ فَفَعَلُوا وَاللَّهِ ذَاكَ فَإِذَا هُوَ قَائِمٌ فِي قَبْضَةِ اللَّهِ تَعَالَى فَقَالَ يَا ابْنَ آدَمَ مَا حَمَلَكَ عَلَى مَا فَعَلْتَهُ قَالَ مِنْ مَخَافَتِكَ قَالَ فَتَلَافَاهُ اللَّهُ تَعَالَى بِهَا","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan pada kami [Abu Qar'ah Al Bahili] dari [Hakim bin Mu'awiyah] dari [Ayahnya] ia berkata; Aku datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu aku berkata; \"Tidaklah aku datang kepadamu kecuali aku telah bersumpah dengan beberapa jariku ini bahwa aku tidak akan datang kepadamu -'Affan memperlihatkan dan menengadahkan telapaknya- Demi dzat yang mengutusmu dengan kebenaran, dengan apakah kamu di utus?.\" Beliau menjawab: \"Dengan Islam.\" Mu'awiyah bertanya; \"Apakah Islam itu?.\" Beliau menjawab: \"Hendaknya engkau serahkan jiwamu sepenuhnya hanya pada Allah Ta'ala dan engkau menghadapkan wajahmu hanya kepada Allah saja, engkau mengerjakan shalat, menunaikan zakat, itulah dua hal yang tidak bisa dipisahkan dan Allah Azza Wa Jalla tidak akan menerima taubat seorang hamba yang menyekutukan-Nya setelah ia masuk Islam.\" Aku bertanya; \"Lalu apa hak istri terhadap kita (suami)?.\" Beliau menjawab: \"Engkau memberinya makan apabila engkau makan, memberinya pakaian apabila engkau berpakaian, jangan memukul wajah, jangan menjelekkannya dan jangan memisahkan tempat tidur kecuali dalam satu rumah.\" Beliau melanjutkan: \"Kalian akan dikumpulkan di sana, (seraya menunjukkan tangannya ke arah Syam) dalam keadaan berjalan kaki dan berkendaraan, wajah kalian akan ditampakkan semua dihadapan Allah, mulut-mulut kalian akan dikunci dan yang pertama kali akan berkomentar adalah paha (kaki-kaki) kalian.\" Beliau melanjutkan lagi: \"Dan siapa saja dari seorang budak yang meminta kelebihan dari harta tuannya, namun tuannya tidak memberinya, melainkan Allah Ta'ala akan menjadikan untuknya seekor ular besar bernama Syuja', dan Ular itu akan menghancurkannya sebelum diputuskannya perkara.\" ['Affan] seorang budak milik anak pamannya berkata; \"Sesungguhnya sebelum kalian ada seseorang yang Allah Ta'ala karuniai harta dan anak-anak, hingga zaman berganti dengan generasi setelahnya. Sewaktu ayahnya hendak meninggal, ia berkata kepada anaknya; \"Buat kalian, ayah macam apakah aku ini? Mereka berkata; 'Ayah adalah orang yang terbaik!.' Dia berkata lagi; 'Apakah kalian akan mentaatiku?, kalau tidak, maka aku akan mengambil semua hartaku dari kalian!.' 'Lihatlah oleh kalian, jika nanti aku telah meninggal dunia, maka bakarlah aku hingga diriku menjadi arang.' Kemudian tumbuklah (arangku) hingga halus dengan alat penumbuk -Rasulullah shallallahu 'alaihi wasallam sambil mendemontrasikan dengan memutar-mutar dengan kedua tangannya sejajar kedua lututnya- Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Kemudian mereka melakukan wasiat ayahnya.\" Demi Allah Nabiyullah shallallahu 'alaihi wasallam mempraktekkan dengan tangannya seperti ini, - 'Kemudian tebarkanlah (abuku) pada hari yang anginya kencang, supaya Allah Ta'ala tidak dapat menemukanku.' -demikianlah yang di katakan 'Affan, Ayahku berkata; dan Muhanna Abu Syibl mengatakan dari Hammad dengan redaksi -supaya diriku tidak dapat di temukan Allah- lalu anak-anaknya melaksanakan perintah ayahnya, demi Allah, ternyata dirinya telah berdiri tegak dalam genggaman Allah Ta'ala. Maka Allah bertanya kepadanya: 'Wahai anak Adam, apa yang membuatmu melakukan hal ini (membakar diri)?.' Lak-laki itu menjawab; 'Ya Rabb-ku, karena aku takut kepada-Mu!.' Maka Allah Ta'ala pun mengampuni perbuatannya.\""},"2533":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا الْجُرَيْرِيُّ أَبُو مَسْعُودٍ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَجِيئُونَ يَوْمَ الْقِيَامَةِ عَلَى أَفْوَاهِكُمْ الْفِدَامُ وَإِنَّ أَوَّلَ مَا يَتَكَلَّمُ مِنْ الْآدَمِيِّ فَخِذُهُ وَكَفُّهُ","id":"Telah menceritakan kepada kami [Yazid], telah mengabarkan pada kami [Al Jurairi Abu Mas'ud] dari [Hakim bin Mu'awiyah] dari [Ayahnya] dari Nabi Shalallahu 'alaihi wasallam, beliau bersabda: \"Kalian akan datang pada hari kiamat dalam keadaan mulut terkunci, sedangkan yang pertama kali berbicara dari anak cucu Adam adalah paha dan telapak tangannya (yaitu kaki dan tangannya).\""},"2534":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنَا أَبُو قَزَعَةَ عَنْ رَجُلٍ مِنْ بَنِي قُشَيْرٍ عَنْ أَبِيهِ أَنَّهُسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَقُّ امْرَأَتِي عَلَيَّ قَالَ تُطْعِمُهَا إِذَا طَعِمْتَ وَتَكْسُوهَا إِذَا اكْتَسَيْتَ وَلَا تَضْرِبْ الْوَجْهَ وَلَا تَهْجُرْ إِلَّا فِي الْبَيْتِ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Ibnu Juraij], telah mengabarkan kepada kami [Abu Qaza'ah] dari [seorang laki-laki] dari bani Qusyair dari [Ayahnya] bahwa ia bertanya kepada Nabi Shalallahu 'alaihi wasallam; \"Apakah hak seorang istri terhadapku?.\" Beliau menjawab: \"Kamu memberinya makan sebagaimana kamu makan, memberinya pakaian sebagaimana kamu berpakaian, tidak memukul wajahnya, tidak menjelekkannya dan tidak menghajrnya (memisahkan dari tempat tidur) kecuali di dalam rumah.\""},"2535":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا بَهْزٌ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا إِنَّكُمْ تُوفُونَ سَبْعِينَ أُمَّةً أَنْتُمْ خَيْرُهَا وَأَكْرَمُهَا عَلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Yazid], telah menceritakan kepada kami [Bahz] dari [Ayahnya] dari [Kakeknya] ia berkata; Aku mendengar Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Sungguh (jumlah) kalian sebanding dengan tujuh puluh umat, sedangkan kalian adalah ummat yang terbaik dan mulia diantara mereka di hadapan Allah Azza Wa Jalla.\""},"2536":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا نَبِيَّ اللَّهِ نِسَاؤُنَا مَا نَأْتِي مِنْهَا وَمَا نَذَرُ قَالَ حَرْثُكَ ائْتِ حَرْثَكَ أَنَّى شِئْتَ غَيْرَ أَنْ لَا تَضْرِبَ الْوَجْهَ وَلَا تُقَبِّحْ وَلَا تَهْجُرْ إِلَّا فِي الْبَيْتِ وَأَطْعِمْ إِذَا طَعِمْتَ وَاكْسُ إِذَا اكْتَسَيْتَ كَيْفَ وَقَدْ أَفْضَى بَعْضُكُمْ إِلَى بَعْضٍ إِلَّا بِمَا حَلَّ عَلَيْهَا","id":"Telah menceritakan kepada kami [Yazid], telah mengabarkan pada kami [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] ia berkata; \"Aku bertanya pada Rasulullah Shallalahu 'alaihi wasallam; \"Wahai Nabiyullah, terhadap siteri-isteri kami, apa yang harus kami lakukan dan apa yang harus kami tinggalkan?.\" Beliau menjawab: \"Isteri-siterimu adalah ladang bagimu, datangilah ladang kalian dari mana saja kalian suka, jangan memukul wajahnya, jangan menjelekkannya dan jangan menghajrnya (memisahkan dari tempat tidur) kecuali dalam satu rumah, kamu memberinya makan sebagaimana kamu makan, memberinya pakaian sebagaimana kamu berpakaian, bagaimana lagi, kalian juga telah bersebadan antara satu sama lain, selain sesuatu yang telah di halalkan baginya.\""},"2537":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا بَهْزٌ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيْنَ تَأْمُرُنِي قَالَ هَاهُنَا وَنَحَا بِيَدِهِ نَحْوَ الشَّامِ قَالَ إِنَّكُمْ مَحْشُورُونَ رِجَالًا وَرُكْبَانًا وَتُجَرُّونَ عَلَى وُجُوهِكُمْ","id":"Telah menceritakan kepada kami [Yazid], telah mengabarkan pada kami [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] ia berkata; Aku bertanya pada Rasulullah Shallalahu 'alaihi wasallam; \"Wahai Rasulullah, kemana engkau akan menyuruhku?.\" Beliau bersabda: \"Ke sini -seraya menunjukkan dengan tangan beliau ke arah Syam- Beliau melanjutkan: \"Sungguh kalian akan dikumpulkan dalam keadaan berjalan kaki dan berkendaraan dan wajah-wajah kalian juga akan dihela (secara berurutan atau satu persatu).\""},"2538":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَوْرَاتُنَا مَا نَأْتِي مِنْهَا وَمَا نَذَرُ قَالَ احْفَظْ عَوْرَتَكَ إِلَّا مِنْ زَوْجَتِكَ أَوْ مَا مَلَكَتْ يَمِينُكَ قُلْتُ أَرَأَيْتَ إِنْ كَانَ الْقَوْمُ بَعْضُهُمْ فِي بَعْضٍ قَالَ إِنْ اسْتَطَعْتَ أَنْ لَا يَرَاهَا أَحَدٌ فَلَا يَرَاهَا قُلْتُ أَرَأَيْتَ إِنْ كَانَ أَحَدُنَا خَالِيًا قَالَ فَاللَّهُ تَبَارَكَ وَتَعَالَى أَحَقُّ أَنْ يُسْتَحْيَا مِنْ النَّاسِ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim], telah menceritakan kepada kami [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] dia berkata; Aku bertanya: \"Wahai Rasulullah, dimanakah kami harus menutup aurat kami dan dimana kami boleh menanggalkannya (tidak terjaga)?.\" Beliau bersabda: \"Jagalah auratmu kecuali dihadapan istrimu atau budak wanitamu.\" Aku berkata lagi; \"Kalau di hadapan sejenis?.\" Beliau menjawab: \"Jika kamu mampu, maka jangan sampai ada orang yang melihatnya!.\" Aku berkata lagi; \"Bagaimana pendapat anda bila kami dalam keaadaan sendiri? Beliau pun menjawab: \"Di hadapan Allah Tabaraka Wa Ta'ala hendaknya kamu lebih berhak untuk malu daripada di hadapan manusia!.\""},"2539":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ أَخَاهُ أَوْ عَمَّهُ قَامَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ جِيرَانِي بِمَا أُخِذُوا فَأَعْرَضَ عَنْهُ قَالَ جِيرَانِي بِمَا أُخِذُوا فَأَعْرَضَ عَنْهُ ثُمَّ قَالَ جِيرَانِي بِمَا أُخِذُوا فَأَعْرَضَ عَنْهُ قَالَ لَئِنْ قُلْتُ ذَاكَ لَقَدْ زَعَمَ النَّاسُ أَنَّ مُحَمَّدًا يَنْهَى عَنْ الْغَيِّ وَيَسْتَخْلِي بِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَالَ فَقَامَ أَخُوهُ أَوْ ابْنُ أَخِيهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهُ إِنَّهُ فَقَالَ أَمَا لَقَدْ قُلْتُمُوهَا أَوْ قَالَ قَائِلُكُمْ وَلَئِنْ كُنْتُ أَفْعَلُ ذَلِكَ إِنَّهُ لَعَلَيَّ وَمَا هُوَ عَلَيْكُمْ خَلُّوا لَهُ عَنْ جِيرَانِهِ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Bahz bin Hakim] dari [Ayahnya] dari [Kakenya] bahwa saudaranya atau pamannya pernah datang kepada Rasulullah Shallalahu 'alaihi wasallam sambil berkata; \"Dengan alasan apa tetanggaku ditangkap (ditahan)? Beliau kemudian berpaling darinya. Kemudian ayah atau kakeknya berujar lagi; \"Beritahukanlah kepadaku, karena alasan apa mereka ditahan?\" Beliau masih tetap berpaling. Maka ayah atau kakeknya berujar; \"Kalau aku katakan sesuatu, maka orang-orang akan beranggapan bahwa anda melarang kejahatan (penyimpangan), namun anda sendiri melakukannya.\" Nabi shallallahu 'alaihi wasallam mengucapkan sebagaimana yang beliau ucapkan. Lantas saudara atau keponakan dari ayah atau kakeknya melaporkan; \"Hai Rasulullah, ia telah berkata demikian-demikian.\" Beliau bersabda: \"Kalian atau salah seorang dari kalian telah mengomel sedemikian rupa, kalaulah aku lakukan yang demikian, itu tanggung jawabku bukan tanggung jawab kalian, dan sekarang tolong suruh ia melepaskan tetangganya.\""},"2540":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَتَيْتُهُ فَقُلْتُ وَاللَّهِ مَا أَتَيْتُكَ حَتَّى حَلَفْتُ أَكْثَرَ مِنْ عَدَدِ أُولَاءِ أَنْ لَا آتِيَكَ وَلَا آتِيَ دِينَكَ وَجَمَعَ بَهْزٌ بَيْنَ كَفَّيْهِ وَقَدْ جِئْتُ امْرَأً لَا أَعْقِلُ شَيْئًا إِلَّا مَا عَلَّمَنِي اللَّهُ تَبَارَكَ وَتَعَالَى وَرَسُولُهُ وَإِنِّي أَسْأَلُكَ بِوَجْهِ اللَّهِ بِمَ بَعَثَكَ اللَّهُ إِلَيْنَا قَالَ بِالْإِسْلَامِ قُلْتُ وَمَا آيَاتُ الْإِسْلَامِ قَالَ أَنْ تَقُولَ أَسْلَمْتُ وَجْهِيَ لِلَّهِ وَتَخَلَّيْتُ وَتُقِيمَ الصَّلَاةَ وَتُؤْتِيَ الزَّكَاةَ كُلُّ مُسْلِمٍ عَلَى مُسْلِمٍ مُحَرَّمٌ أَخَوَانِ نَصِيرَانِ لَا يَقْبَلُ اللَّهُ مِنْ مُشْرِكٍ أَشْرَكَ بَعْدَ مَا أَسْلَمَ عَمَلًا وَتُفَارِقَ الْمُشْرِكِينَ إِلَى الْمُسْلِمِينَ مَا لِي أُمْسِكُ بِحُجَزِكُمْ عَنْ النَّارِ أَلَا إِنَّ رَبِّي عَزَّ وَجَلَّ دَاعِيَّ وَإِنَّهُ سَائِلِي هَلْ بَلَّغْتُ عِبَادَهُ وَإِنِّي قَائِلٌ رَبِّ إِنِّي قَدْ بَلَّغْتُهُمْ فَلْيُبَلِّغْ الشَّاهِدُ مِنْكُمْ الْغَائِبَ ثُمَّ إِنَّكُمْ مَدْعُوُّونَ مُفَدَّمَةً أَفْوَاهُكُمْ بِا��ْفِدَامِ ثُمَّ إِنَّ أَوَّلَ مَا يُبِينُ عَنْ أَحَدِكُمْ لَفَخِذُهُ وَكَفُّهُ قُلْتُ يَا نَبِيَّ اللَّهِ هَذَا دِينُنَا قَالَ هَذَا دِينُكُمْ وَأَيْنَمَا تُحْسِنْ يَكْفِكَ","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Bahz bin Hakim] dari [Ayahnya] dari [kakeknya], dia berkata; Aku datang menemui Nabi Shallalahu 'alaihi wasallam. Ketika aku bertemu dengan beliau, aku berkata; \"Demi Allah, dulu aku bersumpah tidak akan menemuimu, hingga aku bersumpah sebanyak mungkin untuk tidak mendatangimu dan tidak akan memeluk agamamu. -Bahz mengepalkan tangannya-, sekarang aku datang tanpa mengetahui sesuatu pun kecuali agar Allah Tabaraka wa Ta'ala dan Rasul-Nya mengajariku, dan aku bertanya kepadamu dengan mengharap wajah Allah, dengan apakah Allah mengutus anda kepada kami?.\" Beliau bersabda: \"Dengan agama Islam.\" Aku bertanya; \"Wahai Rasulullah, apa ciri-ciri Islam?.\" Beliau menjawab: \"Hendaklah kamu mengucapkan; Aku menyerahkan diri pada Allah dengan sepenuhnya dan membuang sesembahan selain Allah, mendirikan shalat, menunaikan zakat. Setiap muslim dengan muslim yang lain adalah haram (kehormatannya), (ibarat) dua saudara yang saling membela. Allah tidak akan menerima taubat seseorang yang menyekutukan-Nya setelah keIslamannya secara amalan atau hingga ia memisahkan diri dari orang-orang musyrik menuju (kumpulan) orang-orang muslim, sungguh aku tidak bisa menolong kalian dari Neraka, ketahuilah Tuhanku memanggilku dan bertanya: \"Apakah engkau telah menyampaikannya kepada hamba-hamba-Ku?, \"aku menjawab: \"Wahai rabbku, sungguh aku telah menyampaikannya pada mereka. Dan agar orang yang hadir di antara kalian menyampaikan pada yang tidak hadir, lalu mulut-mulut kalian akan terkunci dengan tutup, sesungguhnya yang pertama kali menjelaskan (berbicara) tentang diri kalian adalah pahanya (kakinya) dan telapak tangannya.\" aku pun bertanya; \"Wahai Nabiyullah, apakah ini termasuk dari perkara agama kita?\" beliau menjawab: \"Ini termasuk dari perkara agama kalian, dan manasaja kebaikan yang kamu perbuat, itu sudah cukup bagimu.\""},"2541":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ بَهْزِ بْنِ حَكِيمِ بْنِ مُعَاوِيَةَ بْنِ حَيْدَةَ الْقُشَيْرِيِّ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَقُلْتُ يَا رَسُولَ اللَّهِ نِسَاؤُنَا مَا نَأْتِي مِنْهُنَّ وَمَا نَذَرُ قَالَ حَرْثُكَ ائْتِ حَرْثَكَ أَنَّى شِئْتَ فِي أَنْ لَا تَضْرِبَ الْوَجْهَ وَلَا تُقَبِّحْ وَأَطْعِمْ إِذَا أُطْعِمْتَ وَاكْسُ إِذَا اكْتَسَيْتَ وَلَا تَهْجُرْ إِلَّا فِي الْبَيْتِ كَيْفَ وَقَدْ أَفْضَى بَعْضُكُمْ إِلَى بَعْضٍ إِلَّا بِمَا حَلَّ عَلَيْهِنَّ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Bahz bin Hakim bin Mu'awiyah bin Haidah Al Qusyairi], telah menceritakan kepadaku [Ayahku] dari [kakekku] ia berkata; Aku bertanya; \"Wahai Rasulullah, terhadap siteri-isteri kami, apa yang harus kami lakukan dan apa yang harus kami tinggalkan?.\" Beliau menjawab: \"Isteri-siterimu adalah ladang bagimu, datangilah ladang kalian dari mana saja kalian suka, namun jangan kamu memukul wajahnya, jangan menjelekkannya, kamu memberinya makan sebagaimana kamu makan, memberinya pakaian sebagaimana kamu berpakaian, dan jangan menghajrnya (memisahkan dari tempat tidur) kecuali dalam satu rumah, lalu bagaimana lagi, kalian juga telah bersebadan antara satu sama lain, selain sesuatu yang telah di halalkan baginya.\""},"2542":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ بَهْزِ بْنِ حَكِيمٍ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَيْلٌ لِلَّذِي يُحَدِّثُ فَيَكْذِبُ لِيُضْحِكَ بِهِ الْقَوْمَ وَيْلٌ لَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Bahz bin Hakim], telah menceritakan kepadaku [Ayahku] dari [kakekku], ia berkata; \" Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Celakalah orang yang berbicara kemudian berbohong agar orang lain mentertawakannya, celakalah dia, celakalah dia.\""},"2543":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ بَهْزِ بْنِ حَكِيمٍ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَأْتِي رَجُلٌ مَوْلًى لَهُ يَسْأَلُهُ مِنْ فَضْلٍ عِنْدَهُ فَيَمْنَعُهُ إِلَّا دُعِيَ لَهُ يَوْمَ الْقِيَامَةِ شُجَاعٌ يَتَلَمَّظُ فَضْلَهُ الَّذِي مَنَعَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Bahz bin Hakim], telah menceritakan kepadaku [Ayahku] dari [kakekku] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang yang memiliki budak, lalu budak tersebut dating kepadanya untuk meminta (sedikit) dari kelebihan hartanya, namun ia menolaknya, maka akan didatangkan untuknya di hari kiamat seekor ular raksasa (Syuja' Al 'Aqra') yang akan merebut kelebihan (harta) yang ia tahan.\""},"2544":{"ar":"حَدَّثَنَا يَحْيَى عَنْ بَهْزٍ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّكُمْ وَفَيْتُمْ سَبْعِينَ أُمَّةً أَنْتُمْ آخِرُهَا وَأَكْرَمُهَا عَلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Yahya] dari [Bahz], telah menceritakan kepadaku [Ayahku] dari [kakekku] dia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Jumlah) Kalian sebanding dengan tujuh puluh ummat, kalian adalah yang terakhir dan yang paling mulia di sisi Allah Azza Wa Jalla.\""},"2545":{"ar":"حَدَّثَنَا يَحْيَى عَنْ بَهْزٍ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيْنَ تَأْمُرُنِي خِرْ لِي فَقَالَ بِيَدِهِ نَحْوَ الشَّامِ وَقَالَ إِنَّكُمْ مَحْشُورُونَ رِجَالًا وَرُكْبَانًا وَتُجَرُّونَ عَلَى وُجُوهِكُمْ","id":"Telah menceritakan kepada kami [Yahya] dari [Bahz], telah menceritakan kepadaku [Ayahku] dari [Kakekku] berkata; aku bertanya; \"Wahai Rasulullah, kemanakah engkau akan menyuruhku, dan pilihlah (tempat yang cocok) untukku!.' Maka beliau menunjukkan tangan beliau ke arah Syam sambil bersabda: \"Sungguh kalian akan dikumpulkan, baik yang berjalan kaki dan berkendaraan serta diseretlah wajah-wajah kalian.\""},"2546":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ أَبِي بَهْزٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الْجَنَّةِ بَحْرُ اللَّبَنِ وَبَحْرُ الْمَاءِ وَبَحْرُ الْعَسَلِ وَبَحْرُ الْخَمْرِ ثُمَّ تَشَقَّقُ الْأَنْهَارُ مِنْهَا بَعْدَهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan pada kami [Al Jurairi] dari [Hakim bin Mu'awiyah Abu Bahz] dari [Ayahnya] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di surga ada lautan susu, lautan air, lautan madu dan lautan khamr, kemudian dari situlah sungai-sungai dialirkan.\""},"2547":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي قَزَعَةَ الْبَاهِلِيِّ عَنْ حَكِيمِ بْنِ مُعَاوِيَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْبَلُ اللَّهُ عَزَّ وَجَلَّ تَوْبَةَ عَبْدٍ أَشْرَكَ بِاللَّهِ بَعْدَ إِسْلَامِهِ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad], telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Qaza'ah Al Bahili] dari [Hakim bin Mu'awiyah] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Azza Wa Jalla tidak menerima taubat seorang hamba yang menyekutukan Allah setelah keIslamannya.\""},"2548":{"ar":"حَدَّثَنَا هَاشِمٌ وَبَهْزٌ قَالَا حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ قَالَ حَدَّثَنِي مَنْ سَمِعَ الْأَعْرَابِيَّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَالَ فَرَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَرَفَعَ كَفَّيْهِ حَتَّى حَاذَتَا أَوْ بَلَغَتَا فُرُوعَ أُذُنَيْهِ كَأَنَّهُمَا مِرْوَحَتَانِ","id":"Telah menceritakan kepada kami [Hasyim] dan [Bahz], keduanya berkata; telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Humaid bin Hilal], dia berkata; 'Aku diberitahu oleh orang yang pernah mendengar [seorang Arab Badui] dia mengatakan; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam sedang shalat.' Dia berkata lagi, 'Beliau kemudian mengangkat kepalanya dari rukuk lalu mengangkat kedua telapak tangannya hingga sejajar atau sampai kedua daun telinganya, seakan-akan seperti kipas.\""},"2549":{"ar":"حَدَّثَنَا هَاشِمٌ وَبَهْزٌ قَالَا حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ حُمَيْدٍ قَالَ وَحَدَّثَنِي مَنْ سَمِعَ الْأَعْرَابِيَّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي وَعَلَيْهِ نَعْلَانِ مِنْ بَقَرٍ قَالَ فَتَفَلَ عَنْ يَسَارِهِ ثُمَّ حَكَّ حَيْثُ تَفَلَ بِنَعْلِهِ","id":"Telah menceritakan kepada kami [Hasyim] dan [Bahz], keduanya berkata; telah telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Humaid], dia berkata; 'Aku diberitahu oleh orang yang pernah mendengar [seorang Arab Badui] mengatakan; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam sedang shalat dengan mengenakan sandal dari kulit sapi.\" Katanya lagi, \"Beliau kemudian meludah ke kiri lalu menggosok tempat beliau meludah tadi dengan sandalnya.\""},"2550":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ يَزِيدَ بْنِ الشِّخِّيرِ عَنْ مُطَرِّفِ بْنِ الشِّخِّيرِ قَالَ أَخْبَرَنِي أَعْرَابِيٌّ لَنَا قَالَرَأَيْتُ نَعْلَ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَخْصُوفَةً","id":"Telah menceritakan kepada kami [Abu Ahmad]; telah telah menceritakan kepada kami [Sufyan] dari [Khalid Al Khadza`] dari [Yazid bin Syikhkhir] dari [Mutharrif bin Syikhkhir], dia berkata; \"Seorang [Arab Badui] pernah mengabari kami, katanya, \"Kulihat sandal Nabi kalian shallallahu 'alaihi wasallam ada jahitannya.\""},"2551":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ رَجُلٍ مِنْ بَنِي تَمِيمٍ وَأَحْسَنَ الثَّنَاءَ عَلَيْهِ عَنْ أَبِيهِ أَوْ عَمِّهِ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْنَاهُ عَنْ قَدْرِ رُكُوعِهِ وَسُجُودِهِ فَقَالَ قَدْرُ مَا يَقُولُ الرَّجُلُ سُبْحَانَ اللَّهِ وَبِحَمْدِهِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahman Ath Thufawy] dari [Sa'id Al Jurairy], dari [seorang laki-laki] dari Bani Tamim -dia memujinya dengan pujian yang baik- dari [Ayahnya], atau [Pamannya], dia berkata; \"Aku pernah shalat di belakang Rasulullah shallallahu 'alaihi wasallam, lantas kami bertanya kepada beliau tentang kadar lama rukuk dan sujudnya.\" Beliau menjawab: \"Sebagaimana seseorang mengucapkan subhanallahi wa bihamdihi (Maha suci Allah dan segala puji bagi-Nya), sebanyak tiga kali.\""},"2552":{"ar":"حَدَّثَنَا عَفَّانُ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ الْحَسَنَ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِأَنَّ رَجُلًا وَقَعَ عَلَى جَارِيَةِ امْرَأَتِهِ فَرُفِعَ ذَاكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كَانَتْ طَاوَعَتْهُ فَهِيَ لَهُ وَعَلَيْهِ مِثْلُهَا لَهَا وَإِنْ كَانَ اسْتَكْرَهَهَا فَهِيَ حُرَّةٌ وَعَلَيْهِ مِثْلُهَا لَهَا","id":"Telah menceritakan kepada kami ['Affan], telah mengabarkan kepada kami [Hammad bin Zaid]; telah telah menceritakan kepada kami ['Amru bin Dinar]; ia berkata; Aku mendengar [Al Hasan] dari [Salamah bin Al Muhabbiq], bahwa seorang laki-laki menyetubuhi budak perempuan istrinya. Perkara itu lalu diajukan kepada Nabi shallallahu 'alaihi wasallam. Beliau bersabda: \"Jika ia (budak) menurutinya (tidak ada paksaan), maka ia tetap milik laki-laki tersebut dengan kewajiban memberi mahar seperti kepada isterinya (yang lain). Akan tetapi, jika laki-laki memaksanya, maka budak itu merdeka dan ia wajib memberikan mahar seperti kepada isterinya.\""},"2553":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنِ الْحَسَنِ عَنْ جَوْنِ بْنِ قَتَادَةَ عَنْ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى عَلَى بَيْتٍ قُدَّامُهُ قِرْبَةٌ مُعَلَّقَةٌ فَسَأَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّرَابَ فَقَالُوا إِنَّهَا مَيْتَةٌ فَقَالَ دِبَاغُهَا ذَكَاتُهَا","id":"Telah menceritakan kepada kami ['Affan], dari [Hammam] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Jaun bin Qatadah] dari [Salamah], bahwa Nabi shallallahu 'alaihi wasallam pernah singgah kerumah yang bagian depannya terdapat qirbah (kantong air dari kulit) yang tergantung. Lalu Nabi shallallahu 'alaihi wasallam meminta minum. Mereka berkata; \"Wahai Rasulullah, sesungguhnya qirbah itu (terbuat dari kulit) bangkai.\" Beliau bersabda: \"Disamaknya ia (kulit tersebut) adalah penyuciannya.\""},"2554":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِأَنَّ رَجُلًا غَشِيَ جَارِيَةَ امْرَأَتِهِ وَهُوَ فِي غَزْوٍ فَرُفِعَ ذَلِكَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كَانَ اسْتَكْرَهَهَا فَهِيَ حُرَّةٌ مِنْ مَالِهِ وَعَلَيْهِ شِرَاؤُهَا لِسَيِّدَتِهَا وَإِنْ كَانَتْ طَاوَعَتْهُ فَمِثْلُهَا مِنْ مَالِهِ لِسَيِّدَتِهَا","id":"Telah menceritakan kepada kami [Abdullah bin Bakr], telah menceritakan kepada kami [Sa'id yaitu Ibnu Abu 'Arubah] dari [Qatadah] dari [Al Hasan] dari [Salamah bin Al Muhabbiq] bahwa seseorang laki-laki telah menyetubuhi budak perempuan istrinya ketika dalam peperangan. Perkara itu lalu diajukan kepada Nabi shallallahu 'alaihi wasallam. Beliau bersabda: \"Jika laki-laki itu memaksanya, maka budak tersebut merdeka, dan ia wajib memberikan mahar kepada istrinya. Namun jika budak tersebut menurutinya, maka budak tersebut tetap miliknya (laki-laki itu) dengan kewajiban memberi mahar kepada istrinya.\""},"2555":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ يُونُسَ عَنِ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِأَنَّ رَجُلًا خَرَجَ فِي غَزَاةٍ وَمَعَهُ جَارِيَةٌ لِامْرَأَتِهِ فَوَقَعَ بِهَا فَذُكِرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كَانَ اسْتَكْرَهَهَا فَهِيَ عَتِيقَةٌ وَلَهَا عَلَيْهِ مِثْلُهَا وَإِنْ كَانَتْ طَاوَعَتْهُ فَهِيَ أَمَتُهُ وَلَهَا عَلَيْهِ مِثْلُهَا وَقَالَ إِسْمَاعِيلُ مَرَّةً إِنَّ رَجُلًا كَانَ فِي غَزْوَةٍحَدَّثَنَا هُشَيْمٌ عَنْ يُونُسَ عَنِ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Isma'il] dari [Yunus] dari [Al Hasan] dari [Salamah bin Al Muhabbiq] bahwa seseorang seorang laki-laki mengikuti peperangan, sementara seorang budak wanita milik istrinya ikut dengannya, ternyata laki-laki itu telah menyetubuhi budak wanita milik isterinya. Perkara itu lalu diajukan kepada Nabi shallallahu 'alaihi wasallam. Beliau bersabda: \"Jika laki-laki itu memaksanya, maka ia (budak itu) merdeka dan laki-laki itu wajib memberikan mahar yang semisal kepadanya. Tapi jika budak tersebut menurutinya, maka ia tetap milik laki-laki itu dengan kewajiban memberi mahar semisal kepadanya. Sesekali [Isma'il] berkata; \"Pernah seorang lelaki yang sedang mengikuti peperangan...\" Telah menceritakan kepada kami [Hasyim] dari [Yunus] dari [Al Hasan] dari [Salamah bin Al Muhabbiq] dari Nabi Shallalahu 'alaihi wasalam lalu menyebutkan makna haditsnya. Telah menceritakan kepada kami [Muhammad bin Ja'far], telah telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Salamah bin Al Muhabbiq] dari Nabi Shallallahu 'alaihi wasalam seperti itu."},"2556":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ جَوْنِ بْنِ قَتَادَةَ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى عَلَى قِرْبَةٍ يَوْمَ حُنَيْنٍ فَدَعَا مِنْهَا بِمَاءٍ وَعِنْدَهَا امْرَأَةٌ فَقَالَتْ إِنَّهَا مَيْتَةٌ فَقَالَ سَلُوهَا أَلَيْسَ قَدْ دُبِغَتْ فَقَالَتْ بَلَى فَأَتَى مِنْهَا لِحَاجَتِهِ فَقَالَ ذَكَاةُ الْأَدِيمِ دِبَاغُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far]; telah telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Jaun bin Qatadah] dari [Salamah bin Al Muhabbiq] bahwa pada saat perang Hunain, Nabiyullah Shallallahu 'alaihi wasalam pernah mendatangi rumah seorang wanita yang memiliki qirbah, lalu wanita itu berkata; \"Itu terbuat dari (kulit) bangkai.\" Rasulullah Shallallahu 'alaihi wasalam bersabda: \"Tanyakan padanya apakah sudah disamak?.\" Wanita itu berkata; \"Ya.\" Setelah hajat beliau terpenuhi, beliau bersabda: \"Kulit bangkai sucinya dengan disamak.\" "},"2557":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنِ الْحَسَنِ عَنْ جَوْنِ بْنِ قَتَادَةَ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِ أَنَّهُكَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَأَتَى عَلَى بَيْتٍ قُدَّامُهُ قِرْبَةٌ مُعَلَّقَةٌ فَسَأَلَ الشَّرَابَ فَقِيلَ إِنَّهَا مَيْتَةٌ فَقَالَ ذَكَاتُهَا دِبَاغُهَا","id":"Telah menceritakan kepada kami [Bahz]; telah telah menceritakan kepada kami [Hammam]; telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Jaun bin Qatadah] dari [Salamah bin Al Muhabbiq] bahwa ia pernah bersama Nabi Shallallahu 'alaihi wasalam pada saat perang Tabuk, lalu beliau mendatangi rumah yang didepannya tergantung sebuah qirbah untuk meminta minum, lalu beritahukan bahwa qirbah itu terbuat dari (kulit) bangkai, maka Rasulullah Shallallahu 'alaihi wasalam bersabda: \"Sucinya adalah dengan disamak.\""},"2558":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ قَبِيصَةَ بْنِ حُرَيْثٍ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَجُلٍ وَطِئَ جَارِيَةَ امْرَأَتِهِ إِنْ كَانَ اسْتَكْرَهَهَا فَهِيَ حُرَّةٌ وَعَلَيْهِ لِسَيِّدَتِهَا مِثْلُهَا","id":"Telah menceritakan kepada kami [Abdurrazaq], telah menceritakan kepada kami [Ma'mar] dari [Qatadah] dari [Al Hasan] dari [Qabishah bin Huraits] dari [Salamah bin Al Muhabbiq] dia berkata; \"Rasulullah Shallallahu 'alaihi wasalam pernah menghukumi seseorang yang telah menyetubuhi budak istrinya, yaitu; apabila ia terpaksa maka ia merdeka dan suaminya harus membayar mahar kepada istrinya.\""},"2559":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدُ الْكَرِيمِ بْنُ أَبِي الْمُخَارِقِ عَنْ مُعَاذِ بْنِ سَعْوَةَ الرَّاسِبِيِّ عَنْ سِنَانِ بْنِ سَلَمَةَ الْهُذَلِيِّ عَنْ أَبِيهِ سَلَمَةَ وَكَانَ قَدْ صَحِبَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ بَعَثَ بَدَنَتَيْنِ مَعَ رَجُلٍ وَقَالَ إِنْ عَرَضَ لَهُمَا فَانْحَرْهُمَا وَاغْمِسْ النَّعْلَ فِي دِمَائِهِمَا ثُمَّ اضْرِبْ بِهِ صَفْحَتَيْهِمَا حَتَّى يُعْلَمَ أَنَّهُمَا بَدَنَتَانِ قَالَ صَفْحَتَيْ كُلِّ وَاحِدَةٍ قَالَ وَلَا تَأْكُلْ مِنْهَا أَنْتَ وَلَا أَحَدٌ مِنْ رُفْقَتِكَ وَدَعْهَا لِمَنْ بَعْدَكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Bakr], telah mengabarkan kepada kami [Ibnu Juraij], telah telah mengabarkan padaku [Abdul Karim bin Abul Mukhariq] dari [Mu'adz bin Sa'wah Arrasibi] dari [Sinan bin Salamah Al Hudzali], dari ayahnya [Salamah] -dia adalah salah seorang sahabat Nabi shallallahu 'alaihi wasallam-, dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah mengirim dua unta qurban bersama seorang laki-laki. Beliau berpesan, \"Jika bisa, sembelihlah keduanya dan celupkanlah sandal pada darah keduanya. Setelah itu, pukulkanlah pada kedua sisi tubuh kedua unta tersebut hingga diketahui bahwa keduanya adalah unta qurban.\" Dia mengatakan; \"Kedua sisi masing-masing.\" beliau bersabda lagi: \"Janganlah kalian dan orang yang menyertai kalian ikut memakannya. Tinggalkanlah ia untuk orang selain kalian.\""},"2560":{"ar":"حَدَّثَنَا عَمْرُو بْنُ الْهَيْثَمِ وَأَبُو دَاوُدَ وَعَبْدُ الصَّمَدِ الْمَعْنَى قَالُوا أَخْبَرَنَا هِشَامٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ جَوْنِ بْنِ قَتَادَةَ عَنْ سَلَمَةَ بْنِ الْمُحَبِّقِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا بِمَاءٍ مِنْ قِرْبَةٍ عِنْدَ امْرَأَةٍ فَقَالَتْ إِنَّهَا مَيْتَةٌ فَقَالَ أَلَيْسَ قَدْ دَبَغْتِهَا قَالَتْ بَلَى قَالَ دِبَاغُهَا ذَكَاتُهَا","id":"Telah menceritakan kepada kami ['Amru bin Al Haitsam] dan [Abu Dawud] dan [Abdushamad], maksudnya sama, mereka berkata; telah mengabarkan kepada kami [Hisyam] dari [Qatadah] dari [Al Hasan] dari [Jaun bin Qatadah] dari [Salamah bin Al Muhabbiq] bahwa Nabi Shallallahu 'alaihi wasalam pernah meminta air dari qirbah milik seorang wanita, lalu wanita itu berkata; \"Qirbah itu terbuat dari (kulit) bangkai.\" Maka Rasululah Shallallahu 'alaihi wasalam bersabda: \"Bukankah kamu telah menyamaknya?.\" Ia menjawab; \"Ya.\" Rasulullah Shallallahu 'alaihi wasalam bersabda: \"Menyamaknya telah menjadikan ia suci.\" "},"2561":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ حَبِيبٍ الْعَوْذِيُّ حَدَّثَنِي أَبِي قَالَ غَزَوْنَا مَعَ سِنَانِ بْنِ سَلَمَةَ مُكْرَانَ فَقَالَ سِنَانُ بْنُ سَلَمَةَ حَدَّثَنِي أَبِي سَلَمَةُ بْنُ الْمُحَبِّقِ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَدْرَكَهُ رَمَضَانُ لَهُ حُمُولَةٌ يَأْوِي إِلَى شِبَعٍ فَلْيَصُمْ رَمَضَانَ حَيْثُ أَدْرَكَهُو قَالَ سِنَانٌ وُلِدْتُ يَوْمَ حُنَيْنٍ فَبُشِّرَ بِي أَبِي فَقَالُوا لَهُ وُلِدَ لَكَ غُلَامٌ فَقَالَ سَهْمٌ أَرْمِي بِهِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ إِلَيَّ مِمَّا بَشَّرْتُمُونِي بِهِ وَسَمَّانِي سِنَانًا","id":"Telah menceritakan kepada kami [Abdusshamad] dia berkata; telah menceritakan kepada kami [Abdussamad bin Habib Al Audzi]; telah menceritakan padaku [Ayahku], ia berkata, Kami pernah berperang bersama [Sinan bin Salamah] telah telah menceritakan kepada kami dari [Salamah bin Al Muhabbiq], bahwa ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berada di bulan Ramadhan, sementara ia memiliki muatan (makanan) yang dapat menjadikannya tenang, maka hendaklah berpuasa Ramadhan ketika memasukinya.\" [Sinan] menuturkan; \"Aku dilahirkan pada hari Hunain. Ayahku diberi kabar gembira tentang (kelahiran) ku. Mereka berkata, \"Anak laki-lakimu telah lahir.\" [Ayahku] malah berujar: \"Satu anak panah yang kulesatkan demi membela Rasulullah shallallahu 'alaihi wasallam lebih aku sukai daripada apa yang kalian kabarkan kepadaku.' kemudian ayahku memberiku nama Sinan.\""},"2562":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا بَهْزٌ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَيْلٌ لِلَّذِي يُحَدِّثُ فَيَكْذِبُ لِيُضْحِكَ بِهِ الْقَوْمَ وَيْلٌ لَهُ وَيْلٌ لَهُ","id":"Telah telah menceritakan kepada kami [Yazid], telah telah menceritakan kepada kami [Bahz] dari [Ayahnya] dari [Kakeknya] ia berkata; Aku mendengar Rasuslullah Shallallahu 'alaihi wasalam bersabda: \" Celaka orang yang berbicara lalu berdusta agar orang lain tertawa, celakalah ia, celakalah ia!.\""},"2563":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا الْهِرْمَاسُ بْنُ زِيَادٍ الْبَاهِلِيُّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي مُرْدِفِي خَلْفَهُ عَلَى حِمَارٍ وَأَنَا صَغِيرٌ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ بِمِنًى عَلَى نَاقَتِهِ الْعَضْبَاءِ","id":"Telah menceritakan kepada kami [Bahz], telah telah menceritakan kepada kami [Ikrimah bin 'Amar], telah telah menceritakan kepada kami [Al Hirmaz bin Ziyad Al Bahili] berkata; 'Aku pernah melihat Rasulullah Shallallahu 'alaihi wasalam sedangkan ayahku memboncengkanku di belakangnya di atas keledai, ketika itu aku masih kecil dan aku sempat melihat Rasulullah Shallallahu 'alaihi wasalam berada diatas untanya Al Adlba' tengah berkhutbah di Mina.'"},"2564":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا الْهِرْمَاسُ بْنُ زِيَادٍ الْبَاهِلِيُّ قَالَكَانَ أَبِي مُرْدِفِي فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ يَوْمَ النَّحْرِ بِمِنًى عَلَى نَاقَتِهِ الْعَضْبَاءِ","id":"Telah menceritakan kepada kami [Abdusshamad]; telah mengabarkan kepada kami [Ikrimah bin 'Ammar], telah menceritakan kepada kami [Al Hirmas bin Ziyad Al Bahili] ia berkata; \"Ayahku pernah memboncengkanku di belakangnya, maka aku melihat Rasulullah Shallallahu 'alaihi wasalam di atas untanya Al Adlba' tengah berkutbah di hadapan orang-orang pada hari kurban di Mina.\""},"2565":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَبْدُ الْمَلِكِ أَبُو جَعْفَرٍ ع��نْ أَبِي نَضْرَةَ عَنْ سَعْدِ بْنِ الْأَطْوَلِأَنَّ أَخَاهُ مَاتَ وَتَرْكَ ثَلَاثَ مِائَةِ دِرْهَمٍ وَتَرَكَ عِيَالًا فَأَرَدْتُ أَنْ أُنْفِقَهَا عَلَى عِيَالِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخَاكَ مَحْبُوسٌ بِدَيْنِهِ فَاقْضِ عَنْهُ فَقَالَ يَا رَسُولَ اللَّهِ فَقَدْ أَدَّيْتُ عَنْهُ إِلَّا دِينَارَيْنِ ادَّعَتْهُمَا امْرَأَةٌ وَلَيْسَ لَهَا بَيِّنَةٌ قَالَ فَأَعْطِهَا فَإِنَّهَا مُحِقَّةٌحَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنِ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Abdul Malik Abu Ja'far] dari [Abu Nadhrah] dari [Sa'id bin Al Athwal] bahwa saudara laki-lakinya telah meninggal dunia dengan meninggalkan tiga ratus dirham dan keluarga (anak dan isteri). Maka aku ingin mensedekahkannya kepada keluarganya, Nabi Shallallahu 'alaihi wasalam bersabda: \"Sesungguhnya saudara lelakimu tertahan karena hutangnya, maka bayarlah hutangnya.\" Lalu aku berkata; \"Wahai Rasululah, aku telah melunasinya, kecuali dua dinar yang diklaim oleh seorang wanita sementara ia tidak memiliki bukti yang jelas.\" Beliau bersabda: \"Bayarkanlah kepada wanita itu, karena ia lebih berhak.\" Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah] dari [Al Jurairi] dari [Abu Nadhrah] dari [seorang] sahabat Nabi Shallallahu 'alaihi wasalam seperti hadits di atas."},"2566":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ رَبِيعِ بْنِ عَمِيلَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُسَمِّ غُلَامَكَ أَفْلَحَ وَلَا نَجِيحًا وَلَا يَسَارًا وَلَا رَبَاحًا فَإِنَّكَ إِذَا قُلْتَ أَثَمَّ هُوَ أَوْ أَثَمَّ فُلَانٌ قَالُوا لَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Hilal bin Yasaf] dari [Rabi' bin 'Amilah] dari [Samurah bin Jundub], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan kamu beri nama anak laki-lakimu Aflah, Najih, Yasar, ataupun Rabah. Sebab kalau kamu bertanya; 'Apakah disana ada orang yang bernama demikian?, ' atau 'Apakah di sana ada Fulan? ' Mereka akan menjawab; 'Tidak.\""},"2567":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَرَوْحٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ شَيْخٍ مِنْ بَنِيٍ قُشَيْرٍ قَالَ رَوْحٌ قَالَ سَمِعْتُ سَوَادَةَ الْقُشَيْرِيَّ وَكَانَ إِمَامَهُمْ قَالَ سَمِعْتُ سَمُرَةَ بْنَ جُنْدُبٍ يَخْطُبُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَغُرَّنَّكُمْ نِدَاءُ بِلَالٍ وَهَذَا الْبَيَاضُ حَتَّى يَنْفَجِرَ الْفَجْرُ أَوْ يَطْلُعَ الْفَجْرُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Rauh] keduanya berkata, telah mengabarkan kepada kami [Syu'bah] dari seorang syaikh dari Bani Qusyair. -Rauh berkata; Aku mendengar [Sawadah Al Qusyairi] - ia adalah pemimpin kaum tersebut, ia berkata; \"Aku mendengar [Samurah bin Jundub] sedang berkhutbah, katanya; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah adzan Bilal dan warna putih ini (mendung) mengecoh kalian, hingga fajar telah menyingsing atau fajar telah terbit.\""},"2568":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنِ سَمُرَةَ بْنِ جُنْدُبٍ قَالَكَانَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَكْتَتَانِ فِي صَلَاتِهِوَقَالَ عِمْرَانُ بْنُ حُصَيْنٍ أَنَا مَا أَحْفَظُهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَتَبُوا فِي ذَلِكَ إِلَى أُبَيِّ بْنِ كَعْبٍ يَسْأَلُونَهُ عَنْهُ فَكَتَبَ أُبَيٌّ أَنَّ سَمُرَةَ قَدْ حَفِظَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam diam sejenak pada dua tempat dalam shalatnya.\" Imran bin Hushain berkata; \"Aku belum pernah mendengar kedua tempat tersebut dari Rasulullah shallallahu 'alaihi wasallam. Mereka lalu mengirim surat kepada [Ubay bin Ka'ab] untuk menanyakan hal itu. Ubay membalas bahwa Samurah pernah menghafalnya.\""},"2569":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَرَوْحٌ قَالَا حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هِيَ الْعَصْرُ قَالَ ابْنُ جَعْفَرٍ سُئِلَ عَنْ صَلَاةِ الْوُسْطَى","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Rauh], keduanya berkata; telah telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah (shalat) Ashar.\" [Ibnu Ja'far] mengatakan; \"Yaitu ketika beliau ditanya tentang shalat al-Wustha.\""},"2570":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ وَبَهْزٌ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنِ الْحَسَنِ عَنْ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى جَائِزَةٌ لِأَهْلِهَا قَالَ ابْنُ جَعْفَرٍ فِي حَدِيثِهِ لِأَهْلِهَا أَوْ مِيرَاثٌ لِأَهْلِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Sa'id] dan [Bahz], telah menceritakan kepada kami [Hammam]; telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Samurah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Umra adalah hadiah bagi keluarganya.\" Dalam haditsnya, Ibnu Ja'far mengatakan; \"Bagi keluarganyanya, atau warisan bagi keluarganya.\" "},"2571":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَشَكَّ فِيهِ فِي كِتَابِ الْبُيُوعِ فَقَالَ عَنْ عُقْبَةَ أَوْ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ زَوَّجَهَا وَلِيَّانِ فَهِيَ لِلْأَوَّلِ مِنْهُمَا وَمَنْ بَاعَ بَيْعًا مِنْ رَجُلَيْنِ فَهُوَ لِلْأَوَّلِ مِنْهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi Shallallahu 'alaihi wasalam -Ia ragu di dalam kitab Al Buyu'-, ia berkata dari ['Uqbah] atau [Samurah] bahwa Nabi Shallallahu 'alaihi wasalam bersabda: \"Wanita manasaja yang dinikahkan oleh dua orang walinya, maka ia bagi yang pertama dari keduanya dan barangsiapa membeli barang dari dua orang maka yang berhak adalah yang pertama.\""},"2572":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَمُحَمَّدُ بْنُ بِشْرٍ قَالَا حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَى الْيَدِ مَا أَخَذَتْ حَتَّى تُؤَدِّيَهُ وَقَالَ ابْنُ بِشْرٍ حَتَّى تُؤَدِّيَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Muhammad bin Bisyr], keduanya berkata; telah mengabarkan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] dari Nabi Shallallahu 'alaihi wasalam bersabda: \"Bagi tangan bertanggung jawab terhadap apa yang diambil hingga ia menunaikannya (mengembalikannya).\" [Ibnu Bisyr] berkata; \"Hingga kamu menunaikannya.\""},"2573":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَارُ الدَّارِ أَحَقُّ بِالدَّارِ مِنْ غَيْرِهِ","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan], keduanya berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Samurah], ia berkata; Nabi Shallallahu 'alaihi wasalam bersabda: \"Tetangga rumah lebih berhak (ditawari terlebih dahulu untuk membeli) rumah sebelahnya dari yang lain.\""},"2574":{"ar":"حَدَّثَنَا بَهْزٌ وَعَبْدُ الصَّمَدِ قَالَا حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَبِهَا وَنِعْمَتْ وَمَنْ اغْتَسَلَ فَذَلِكَ أَفْضَلُ قَالَ عَبْدُ الصَّمَدِ فِي حَدِيثِهِ حَدَّثَنَا قَتَادَةُ","id":"Telah menceritakan kepada kami [Bahz] dan [Abdusshamad], keduanya berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Samurah] dia berkata; Rasulullah Shallallahu 'alaihi wasalam bersabda: \"Barangsiapa berwudlu, maka itu baik dan barangsiapa mandi (pada hari Jum'at) maka itu lebih utama.\" [Abdusshamad] berkata dalam haditsnya; telah menceritakan kepada kami [Qatadah]."},"2575":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ عَنِ الْحَسَنِ عَنْ سَمُرَةَأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَافِظُوا عَلَى الصَّلَوَاتِ قَالَ عَفَّانُ الصَّلَاةِ وَالصَّلَاةِ الْوُسْطَى وَسَمَّاهَا لَنَا إِنَّمَا هِيَ صَلَاةُ الْعَصْرِ","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan], keduanya berkata; telah menceritakan kepada kami [Aban]; telah bercerita kepada kami [Qatadah] dari [Al Hasan] dari [Samurah] bahwa Nabiyallah Shallallahu 'alaihi wasalam bersabda: \"Jagalah shalat-shalat kalian.\" 'Affan berkata; \"Shalat yaitu shalat wustha, \" Dan beliau menyebutkan shalat wustha adalah shalat Ashar.\""},"2576":{"ar":"حَدَّثَنَا أَبُو عُبَيْدَةَ عَبْدُ الْوَاحِدِ بْنُ وَاصِلٍ حَدَّثَنَا سَلْمٌ يَعْنِي ابْنَ زَرِيرٍ وَأَبُو الْأَشْهَبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَأَنَّ جَدَّهُ عَرْفَجَةَ بْنَ أَسْعَدَ أُصِيبَ أَنْفُهُ فِي الْجَاهِلِيَّةِ يَوْمَ الْكُلَابِ فَاتَّخَذَ أَنْفًا مِنْ وَرِقٍ فَأَنْتَنَ عَلَيْهِ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَّخِذَ أَنْفًا يَعْنِي مِنْ ذَهَبٍحَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا أَبُو الْأَشْهَبِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ طَرَفَةَ عَنْ جَدِّهِ عَرْفَجَةَ بْنِ أَسْعَدَ أَنَّهُ أُصِيبَ أَنْفُهُ يَوْمَ الْكُلَابِ فِي الْجَاهِلِيَّةِ فَذَكَرَ الْحَدِيثَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu 'Ubaidah Abdul Wahid bin Washil], telah menceritakan kepada kami [Salm yaitu Ibnu Zarir] dan [Abul Asyhab] dari [Abdurrahman bin Tharafah] bahwa kakeknya yaitu [Arfajah bin As'ad] Bahwa hidungnya terluka saat terjadi perang Kulab pada masa Jahiliyah. Kemudian ia memakai hidung palsu dari perak, namun hal itu menimbulkan bau busuk. Maka Nabi shallallahu 'alaihi wasallam memerintahkannya untuk memakai hidung dari emas.\" Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Abu Al Asyhab] telah menceritakan kepada kami [Abdurrahman bin Tharfah] dari [Kakeknya] bahwa hidungnya pernah terluka pada perang Kulab di masa Jahiliyah…\" kemudian ia menyebutkan hadits tersebut."},"2577":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا أَبُو الْأَشْهَبِ الْعُطَارِدِيُّ جَعْفَرُ بْنُ حَيَّانَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ طَرَفَةَ بْنِ عَرْفَجَةَ قَالَ وَزَعَمَ عَبْدُ الرَّحْمَنِ أَنَّهُ رَأَى عَرْفَجَةَ قَالَأُصِيبَ أَنْفُ عَرْفَجَةَ يَوْمَ الْكُلَابِ فَاتَّخَذَ أَنْفًا مِنْ وَرِقٍ فَأَنْتَنَ عَلَيْهِ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَّخِذَ أَنْفًا مِنْ ذَهَبٍحَدَّثَنَا أَبُو عَامِرٍ الْعَدَوِيُّ حَوْثَرَةُ بْنُ أَشْرَسَ أَخْبَرَنِي أَبُو الْأَشْهَبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَ بْنِ عَرْفَجَةَ بْنِ أَسْعَدَ أَنَّ جَدَّهُ عَرْفَجَةَ بْنَ أَسْعَدَ أُصِيبَ أَنْفُهُ فِي الْجَاهِلِيَّةِ يَوْمَ الْكُلَابِ فَذَكَرَ الْحَدِيثَ قَالَ أَبُو الْأَشْهَبِ وَزَعَمَ عَبْدُ الرَّحْمَنِ أَنَّهُ قَدْ رَأَى جَدَّهُ يَعْنِي عَرْفَجَةَ حَدَّثَنَا مُحَمَّدُ بْنُ تَمِيمٍ النَّهْشَلِيُّ حَدَّثَنِي أَبُو الْأَشْهَبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَ بْنِ عَرْفَجَةَ بْنِ أَسْعَدَ عَنْ جَدِّهِ عَرْفَجَةَ بْنِ أَسْعَدَ أَنَّ أَنْفَهُ أُصِيبَ يَوْمَ الْكُلَابِ فِي الْجَاهِلِيَّةِ فَذَكَرَ مِثْلَهُ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ جَعْفَرِ بْنِ حَيَّانَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ طَرَفَةَ بْنِ عَرْفَجَةَ أَنَّ جَدَّهُ عَرْفَجَةَ أُصِيبَ أَنْفُهُ يَوْمَ الْكِلَابِ فَذَكَرَ الْحَدِيثَ حَدَّثَنَا يَحْيَى بْنُ عُثْمَانَ يَعْنِي الْجَرْمِىَّ السِّمْسَارَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ جَعْفَرِ بْنِ حَيَّانَ الْعُطَارِدِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَ بْنِ عَرْفَجَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ أُصِيبَ أَنْفُهُ يَوْمَ الْكُلَابِ يَعْنِي مَاءً اقْتَتَلُوا عَلَيْهِ فِي الْجَاهِلِيَّةِ فَذَكَرَ مِثْلَهُ قَالَ فَمَا أَنْتَنَ عَلَيَّ","id":"Telah menceritakan kepada kami Abdullah, telah menceritakan kepada kami [Syaiban], telah menceritakan kepada kami [Abul Asyhab Al 'Utharidi Ja'far bin Hayyan], telah menceritakan kepada kami [Abdurrahman bin Tharafah bin Arfajah] ia berkata -sedangkan Abdurrahman menyangka bila dirinya pernah melihat [Arfajah] - ia berkata; \"Hidung Arfajah terluka pada peristiwa Yaum Kulab, lalu ia menggantinya dengan hidung dari perak, ternyata hal itu menimbulkan bau busuk, lalu Rasulullah Shallalahu 'alaihi wasallam memerintahkannya supaya mengenakan hidung dari emas.\" Telah menceritakan kepada kami [Abu 'Amir Al 'Adawi Hautsarah bin Asyras], telah menceritakan kepadaku [Abul Asyhab] dari [Abdurrahman bin Tharafah bin Arfajah bin As'ad] bahwa hidungnya terluka pada peristiwa Yaum Kulab di masa Jahiliyah, lalu ia menyebutkan hadits tersebut. [Abul Asyhab] mengatakan; bahwa ia pernah melihat kakeknya yaitu 'Arfajah. Telah menceritakan kepada kami [Muhammad bin Tamim An Nahsyali] telah menceritakan kepadaku [Abu Al Asyhab] dari [Abdurrahman bin Tharfah bin 'Arfajah bin As'ad] dari kakeknya ['Arfajah bin As'ad] bahwa hidungnya pernah terluka (terpotong) pada hari Yaum Kulab di masa Jahiliyah, lalu ia sebutkan hadits seperti itu. Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami [Abdullah bin Mubarak] dari [Ja'far bin Hayyan], telah menceritakan kepadaku [Abdurrahman bin Tharafah bin 'Arfajah] bahwa kakeknya ['Arfajah] hidungnya pernah terluka (terpotong) dalam peristiwa Yaum Kilab, lalu ia menyebutkan hadits. Telah menceritakan kepada kami [Yahya bin Utsman yaitu Al Jarmii As Simsara], telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Ja'far bin Hayyan Al 'Utharidi] dari [Abdurrahman bin Tharafah bin 'Arfajah] dari [Ayahnya] dari [kakeknya] ia berkata; bahwa Hidungnya terluka pada Yaum Kulab yaitu peperangan di atas air di masa jahiliyah, lalu ia menyebutkan hadits tersebut, ia berkata; \"Tanpa lafadz 'antana 'alayya' (menimbulkan bau busuk).\""},"2578":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ حَمَّادِ بْنِ أَبِي سُلَيْمَانَ الْكُوفِيِّ قَالَرَأَيْتُ الْمُغِيرَةَ بْنَ عَبْدِ اللَّهِ قَدْ شَدَّ أَسْنَانَهُ بِالذَّهَبِ فَذُكِرَ مِثْلَ ذَلِكَ لِإِبْرَاهِيمَ فَقَالَ لَا بَأْسَ بِهِحَدَّثَنَا عَبْد اللَّهِ أَبُو عَبْد الرَّحْمَنِ قَالَ سَمِعْت أَبِي يَقُولُ جَاءَ قَوْمٌ مِنْ أَصْحَابِ الْحَدِيثِ فَاسْتَأْذَنُوا عَلَى أَبِي الْأَشْهَبِ فَأَذِنَ لَهُمْ فَقَالُوا حَدِّثْنَا قَالَ سَلُوا فَقَالُوا مَا مَعَنَا شَيْءٌ نَسْأَلُكَ عَنْهُ فَقَالَتْ ابْنَتُهُ مِنْ وَرَاءِ السِّتْرِ سَلُوهُ عَنْ حَدِيثِ عَرْفَجَةَ بْنِ أَسْعَدَ أُصِيبَ أَنْفُهُ يَوْمَ الْكُلَابِ","id":"Telah menceritakan kepada kami Abdullah, telah menceritakan kepada kami [Syaiban], telah menceritakan kepada kami [Abul Asyhab] dari [Hammad bin Abu Sulaiman Al Kufi] ia berkata; saya melihat Al Mughirah bin Abdullah telah mengganti giginya dengan emas, maka hal itu disebutkan kepada [Ibrahim], namun ia berkata; 'Tidak mengapa.\" Telah menceritakan kepada kami Abdulah Abu Abdurrahman, ia berkata; saya mendengar Ayahku berkata; \"Telah datang suatu kaum dari ahli hadits kepada Abul Al Asyhab, mereka meminta izin menemuinya, setelah Abu Al Asyhab mengizinkannya, mereka bertanya; \"Sampaikanlah hadits kepada kami!.\" Ia bekata; \"Tanyakanlah!.\" Mereka menjawab; \"Tidak ada sesuatu yang kami tanyakan padamu.\" putrinya yang berada di balik satir berkata; \"Tanyakanlah kepadanya tentang hadits 'Arfajah bin As'ad yang hidungnya terluka dalam peristiwa Kulab.\""},"2579":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَرْفَجَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ سَتَكُونُ هَنَاتٌ وَهَنَاتٌ فَمَنْ أَرَادَ أَنْ يُفَرِّقَ أَمْرَ هَذِهِ الْأُمَّةَ وَهُمْ جَمِيعٌ فَاضْرِبُوهُ بِالسَّيْفِ كَائِنًا مَنْ كَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Ziyad bin 'Ilaqah] ia berkata, saya mendengar ['Arfajah] berkata; \"Aku mendengar Rasulullah Shallalahu 'alaihi wasallam bersabda: 'Akan datang gelombang fitnah yang diteruskan dengan fitnah-fitnah, barangsiapa ingin memecah belah urusan umat ini sedang mereka dalam keadaan bersatu, maka bunuhlah ia dengan pedang kapan dan dimanapun saja.\""},"2580":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ حَدَّثَنِي رَجُلٌ مِنْ بَنِي سَلِيطٍأَنَّهُ مَرَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ جَالِسٌ عَلَى بَابِ الْمَسْجِدِ وَعَلَيْهِ ثَوْبٌ قِطْرِيٌّ لَيْسَ عَلَيْهِ غَيْرُهُ مُحْتَبٍ بِهِ وَهُوَ يَقُولُ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يَخْذُلُهُ التَّقْوَى هَاهُنَا وَيُشِيرُ بِيَدِهِ إِلَى صَدْرِهِ","id":"Telah menceritakan kepada kami [Abdurrahman], telah menceritakan kepada kami ['Abbad bin Rasyid], ia berkata; Aku mendengar [Al Hasan] berkata; telah menceritakan kepadaku [seseorang] dari bani Salith bahwa ia pernah melewati Rasulullah Shallalahu 'alaihi wasallam ketika beliau tengah duduk ihtiba' (duduk dengan meletakan kedua lutut pada dada) di pintu masjid sambil mengenakan pakaian katun yang tebal, tanpa mengenakan pakaian yang lain, beliau bersabda: \"Seorang muslim adalah saudara muslim lainnya, janganlah ia menzhalimi saudaranya, jangan menghinanya, takwa itu disini!.\" -beliau sambil menunjuk ke dadanya-."},"2581":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ يُونُسَ حَدَّثَنِي أَبُو الْعَلَاءِ بْنُ الشِّخِّيرِ حَدَّثَنِي أَحَدُ بَنِي سُلَيْمٍ وَلَا أَحْسَبُهُ إِلَّا قَدْرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَبْتَلِي عَبْدَهُ بِمَا أَ��ْطَاهُ فَمَنْ رَضِيَ بِمَا قَسَمَ اللَّهُ عَزَّ وَجَلَّ لَهُ بَارَكَ اللَّهُ لَهُ فِيهِ وَوَسَّعَهُ وَمَنْ لَمْ يَرْضَ لَمْ يُبَارِكْ لَهُ","id":"Telah menceritakan kepada kami [Isma'il] dari [Yunus], telah menceritakan padaku [Abul 'Alaa' bin Syikhir], telah menceritakan kepadaku [seseorang] dari bani Sulaim, dan aku tidak pernah menyangka kecuali telah melihat Rasulullah Shallalahu 'alaihi wasallam bahwa Allah Tabaraka Wa Ta'ala akan menguji hamba-Nya dengan pemberian, barangsiapa ridha terhadap pemberian Allah Azza wa Jalla, maka Allah akan memberkahinya dan barangsiapa tidak ridha maka Allah tidak akan memberkahinya.\""},"2582":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ عَمْرٍو الضَّبِّيُّ حَدَّثَنَا عَلِيُّ بْنُ هَاشِمٍ يَعْنِي ابْنَ الْبَرِيدِ عَنْ أَبِي بِشْرٍ الْحَلَبِيِّ عَنْ أَبِي مَلِيحِ بْنِ أُسَامَةَ عَنْ أَبِيهِ قَالَأَصَابَ النَّاسَ فِي يَوْمِ جُمُعَةٍ يَعْنِي مَطَرًا فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُودِيَ أَنَّ الصَّلَاةَ الْيَوْمَ أَوْ الْجُمُعَةَ الْيَوْمَ فِي الرِّحَالِحَدَّثَنَا دَاوُدُ بْنُ عَمْرٍو حَدَّثَنَا نَافِعُ بْنُ عُمَرَ بْنِ جَمِيلٍ الْجُمَحِيُّ قَالَ رَأَيْتُ عَطَاءً وَابْنَ أَبِي مُلَيْكَةَ وَعِكْرِمَةَ بْنَ خَالِدٍ يَرْمُونَ الْجَمْرَةَ قَبْلَ الْفَجْرِ يَوْمَ النَّحْرِ فَقَالَ لَهُ أَبِي يَا أَبَا سُلَيْمَانَ فِي أَيِّ سَنَةٍ سَمِعْتَ مِنْ نَافِعِ بْنِ عُمَرَ قَالَ سَنَةَ تِسْعٍ وَسِتِّينَ وَمِائَةٍ سَنَةَ وَقْعَةِ الْحُسَيْنِ","id":"Telah menceritakan kepada kami [Dawud bin 'Amru Adh Dhabbi], telah menceritakan kepada kami [Ali bin Hasyim yaitu Ibnul Barid] dari [Abu Bisyr Al Halabi] dari [Abu Malih bin Usamah] dari [Ayahnya] ia berkata; \"Pernah hujan turun di hari Jum'at, maka Nabi Shalallahu 'alaihi wasallam memerintahkan supaya shalat Jum'at hari itu dikerjakan di persinggahan masing-masing.\" Telah menceritakan kepada kami Dawud bin 'Amru, telah menceritakan kepada kami Nafi' bin Umar bin Jamil Al Jumahi ia berkata; saya pernah melihat 'Atha` dan Abu Mulaikah serta Ikrimah bin Khalid melempar jumrah sebelum fajar pada hari Idul Qurban, lantas ayahku berkata; \"Wahai Abu Sulaiman, pada tahun berapakah anda mendengar dari Nafi' bin Umar?.\" Ia berkata; \"Ketika terjadi peristiwa pembunuhan Husain di tahun seratus enam puluh sembilan.\""},"2583":{"ar":"حَدَّثَنَا دَاوُدُ بْنُ عَمْرٍو حَدَّثَنَا نَافِعُ بْنُ عُمَرَ الْجُمَحِيُّ عَنِ الْقَاسِمِ بْنِ أَبِي بَزَّةَفِي قَوْلِهِ تَبَارَكَ وَتَعَالَى{ وَلَا تَمْنُنْ تَسْتَكْثِرُ }قَالَ لَا تُعْطِي شَيْئًا تَطْلُبُ أَكْثَرَ مِنْهُ","id":"Telah menceritakan kepada kami [Dawud bin 'Amru], telah menceritakan kepada kami [Nafi' bin Umar Al Jumahi] dari [Al Qasim bin Abu Bazzah], tentang firman Allah Tabaraka wa Ta'ala, \"Dan janganlah kamu memberi (dengan maksud) memperoleh (balasan) yang lebih banyak.\" Dia berkata; \"Janganlah engkau memberi sesuatu untuk meminta lebih banyak dari pemberian tersebut.\""},"2584":{"ar":"حَدَّثَنَا نُوحُ بْنُ حَبِيبٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثِ بْنِ طَلْقِ بْنِ مُعَاوِيَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ ثَعْلَبَةَ بْنِ عَاصِمٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجَبًا لِلْمُؤْمِنِ لَا يَقْضِي اللَّهُ لَهُ شَيْئًا إِلَّا كَانَ خَيْرًا لَهُ","id":"Telah menceritakan kepada kami [Nuh bin Habib], telah menceritakan kepada kami [Hafsh bin Ghiyats bin Thalq bin Mu'awiyah] dari ['Ashim Al Ahwal] dari [Tsa'labah bin 'Ashim] dari [Anas bin Malik] ia berkata; Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Sungguh mengherankan orang mukmin itu, tidaklah Allah menetapkan sesuatu kecuali baik baginya.\""},"2585":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ قَالَ قَالَ رَجُلٌكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ وَالنَّاسُ يَعْتَقِبُونَ وَفِي الظَّهْرِ قِلَّةٌ فَحَانَتْ نَزْلَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَزْلَتِي فَلَحِقَنِي مِنْ بَعْدِي فَضَرَبَ مَنْكِبَيَّ فَقَالَ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ فَقُلْتُ أَعُوذُ بِرَبِّ الْفَلَقِ فَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَرَأْتُهَا مَعَهُ ثُمَّ قَالَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَرَأْتُهَا مَعَهُ قَالَ إِذَا أَنْتَ صَلَّيْتَ فَاقْرَأْ بِهِمَا","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Al Jurairi] dari [Abul Alaa`] ia berkata; [seseorang] berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Sementara orang-orang mengitari beliau. Ketika waktu zhuhur telah dekat, Rasulullah shallallahu 'alaihi wasallam turun dan aku pun ikut turun. Beliau menemuiku lalu menepuk kedua pundakku. Sabda beliau: \"Ucapkanlah, 'Qul a'udzu birabbil falaq.\" Maka aku pun mengucapkan, \"A'udzu birabbil falaq.\" Rasulullah shallallahu 'alaihi wasallam membacanya lagi lalu aku pun membacanya bersama beliau. Beliau lantas bersabda: \"Ucapkanlah 'Qul a'udzu birabbinnas'!, Rasulullah shallallahu 'alaihi wasallam membacanya dan aku pun membacanya bersama beliau. Sabda beliau: \"Jika kau shalat, bacalah kedua surat tersebut.\""},"2586":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ رِجَالٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَتَّقِ اللَّهَ عَزَّ وَجَلَّ وَلْيُكْرِمْ جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَتَّقِ اللَّهَ وَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَتَّقِ اللَّهَ وَلْيَقُلْ حَقًّا أَوْ لِيَسْكُتْحَدَّثَنَا حَجَّاجٌ حَدَّثَنِي شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ رِجَالٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah], ia berkata; Aku mendengar [Qatadah] menceritakan dari ['Alqamah bin Abdullah Al Muzanni] dari [beberapa sahabat] Rasulullah Shallalahu 'alaihi wasallam bahwa beliau bersabda: \"Barangsiapa beriman kepada Allah dan hari akhir, hendaklah ia bertakwa kepada Allah 'azza wajalla dan memuliakan tetangganya. Barangsiapa beriman kepada Allah dan hari akhir, hendaklah ia bertakwa kepada Allah dan memuliakan tamunya. Barangsiapa beriman kepada Allah dan hari akhir, hendaklah ia bertakwa kepada Allah dan berkata benar atau diam.\" Telah menceritakan kepada kami [Hajjaj], telah menceritakan kepadaku [Syu'bah], dia berkata; \"Aku mendengar [Qatadah] menceritakan dari ['Alqamah bin 'Abdillah al-Muzanni] dari [beberapa orang] sahabat Nabi shallallahu 'alaihi wasallam dari Nabi shallallahu 'alaihi wasallam, lalu ia menyebutkan yang hadits semisal itu."},"2587":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ رَجُلٍ مِنْهُمْأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمَ عَلَى أَنَّهُ لَا يُصَلِّي إِلَّا صَلَاتَيْنِ فَقَبِلَ ذَلِكَ مِنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Nashr bin 'Ashim] dari seorang [laki-laki] di antara mereka, bahwa laki-laki itu pernah dating menemui Nabi shallallahu 'alaihi wasallam dan menyatakan keIslamannya dengan syarat tidak mengerjakan shalat kecuali dua shalat, beliau pun menerima hal itu.\""},"2588":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ حَدَّثَنَا الْحَسَنُ قَالَ وَأَخْبَرَنِي رَجُلٌ مِنْ بَنِي سَلِيطٍ قَالَدُفِعْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ يَقُولُ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يَخْذُلُهُ التَّقْوَى هَاهُنَا التَّقْوَى هَاهُنَا مَرَّتَيْنِ أَوْ ثَلَاثًا وَأَشَارَ بِيَدِهِ إِلَى صَدْرِهِ","id":"Telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Ali bin Zaid]; telah menceritakan kepada kami [Al Hasan], ia berkata; telah mengabarkan kepadaku [seseorang] dari bani Salith, ia berkata; aku telah di laporkan kepada Rasulullah shallallahu 'alaihi wasallam, lalu aku mendengar beliau bersabda: \"Seorang muslim adalah saudara muslim lainnya, maka janganlah ia menzhaliminya dan jangan menghinanya, taqwa itu di sini.\" -beliau menyebutkan dua atau tiga kali sambil menunjuk ke dadanya.-"},"2589":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سَوَادَةُ بْنُ أَبِي الْأَسْوَدِ عَنْ أَبِيهِ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَاعٍ اسْتُرْعِيَ رَعِيَّةً فَغَشَّهَا فَهُوَ فِي النَّارِ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sawadah bin Abul Aswad] dari [Ayahnya] dari [Ma'qil bin Yasar], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemimpin mana saja yang dipercaya memimpin rakyat, lalu ia menipu mereka, maka ia akan masuk Neraka.\""},"2590":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ قَالَ سَمِعْتُ إِسْمَاعِيلَ الْبَصْرِيَّ يُحَدِّثُ عَنْ ابْنَةِ مَعْقِلِ بْنِ يَسَارٍ عَنْ أَبِيهَا مَعْقِلٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ مِنْ وَالِي أُمَّةٍ قَلَّتْ أَوْ كَثُرَتْ لَا يَعْدِلُ فِيهَا إِلَّا كَبَّهُ اللَّهُ تَبَارَكَ وَتَعَالَى عَلَى وَجْهِهِ فِي النَّارِ","id":"Telah menceritakan kepada kami [Waki'] dari [Isma'il bin Abu Khalid] ia berkata; saya mendengar [Isma'il Al Bashri] menceritakan dari [putrinya Ma'qil bin Yasar] dari ayahnya yaitu [Ma'qil] ia berkata; Aku mendengar Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Tidaklah seorang pemimpin kaum baik sedikit atau banyak, kemudian ia tidak adil kecuali Allah akan melemparkan wajahnya ke Neraka.\""},"2591":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ يُونُسَ عَنِ الْحَسَنِ أَنَّ مَعْقِلَ بْنَ يَسَارٍ اشْتَكَى فَدَخَلَ عَلَيْهِ عَبْدُ اللَّهِ بْنُ زِيَادٍ يَعْنِي يَعُودُهُ فَقَالَ أَمَا إِنِّي سَأُحَدِّثُكَ حَدِيثًا لَمْ أَكُنْ حَدَّثْتُكَ بِهِ إِنِّيسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَسْتَرْعِي اللَّهُ تَبَارَكَ وَتَعَالَى عَبْدًا رَعِيَّةً فَيَمُوتُ يَوْمَ يَمُوتُ وَهُوَ لَهَا غَاشٌّ إِلَّا حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Isma'il] dari [Yunus] dari [Al Hasan] bahwa [Ma'qil bin Yasar] pernah menemuinya karena suatu kepentingan, lalu datanglah Abdullah bin Ziyad menjenguknya dan berkata; Aku akan menceritakan kepadamu satu hadits yang belum pernah aku sampaikan padamu, sesungguhnya aku mendengar Rasulullah Shallalahu 'alaihi wasallam bersabda -atau sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda-: \"Tidaklah Allah Tabaraka wa Ta'ala memberikan kepemimpinan pada seorang hamba lalu ia mati padahal ia telah menipu, melainkan Allah mengharamkan kepadanya surga.\""},"2592":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ الثَّقَفِيُّ أَبُو مُحَمَّدٍ حَدَّثَنَا خَالِدٌ عَنِ الْحَكَمِ بْنِ عَبْدِ اللَّهِ الْأَعْرَجِ عَنْ مَعْقِلِ بْنِ يَسَارٍ أَنَّهُشَهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ وَهُوَ رَافِعٌ غُصْنًا مِنْ أَغْصَانِ الشَّجَرَةِ بِيَدِهِ عَنْ رَأْسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَايِعُ النَّاسَ فَبَايَعُوهُ عَلَى أَنْ لَا يَفِرُّوا وَهُمْ يَوْمَئِذٍ أَلْفٌ وَأَرْبَعُ مِائَةٍحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ عَنْ سُفْيَانَ عَنْ خَالِدٍ عَنِ الْحَكَمِ بْنِ الْأَعْرَجِ{ يَ��ُ اللَّهِ فَوْقَ أَيْدِيهِمْ }قَالَ أَنْ لَا يَفِرُّوا","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Abdul Majid Ats Tsaqafi Abu Muhammad], telah menceritakan kepada kami [Khalid] dari [Al Hakam bin Abdullah Al A'raj] dari [Ma'qil bin Yasar], bahwa ia pernah ikut menyaksikan Rasulullah shallallahu 'alaihi wasallam saat peristiwa Hudaibiyah. Kala itu, ia mengangkat ranting di antara beberapa ranting pohon dengan tangannya untuk menjauhkannya dari kepala Rasulullah shallallahu 'alaihi wasallam, ketika para sahabat sedang berbaiat kepada beliau. Mereka berbai'at untuk tidak melarikan diri. Hari itu mereka berjumlah seribu empat ratus orang.\" Telah menceritakan kepada kami Abdullah, telah menceritakan kepada kami ['Ubaidullah bin 'Umar Al Qawarizmi], telah menceritakan kepada kami [Yahya bin Yaman] dari [Sufyan] dari [Khalid] dari [Al Hakam bin Al A'raj] bahwa \"Tangan Allah di atas tangan mereka\" katanya, \"Agar mereka tidak melarikan diri.\""},"2593":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي عِيَاضٌ أَبُو خَالِدٍ قَالَ كَانَ بَيْنَ جَارَيْنِ لمَعْقِلِ بْنِ يَسَارٍ كَلَامٌ فَصَارَتْ الْيَمِينُ عَلَى أَحَدِهِمَا فَسَمِعْتُ مَعْقِلَ بْنَ يَسَارٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ يَقْتَطِعُ بِهَا مَالَ أَخِيهِ لَقِيَ اللَّهَ وَهُوَ عَلَيْهِ غَضْبَانُحَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ إِسْمَاعِيلَ الْأَوْدِيِّ عَنِ ابْنَةِ مَعْقِلٍ الْمُزَنِيِّ قَالَتْ لَمَّا ثَقُلَ أَبِي أَتَاهُ ابْنُ زِيَادٍ وَسَاقَهُ يَعْنِي وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id], dari [Syu'bah], telah menceritakan kepadaku ['Iyadh Abu Khalid] ia berkata; Dua orang tetanga Ma'ql bin Yasar tengah adu mulut, hingga salah seorang diantara keduanya bersumpah atas yang lain, lalu aku mendengar [Ma'qil bin Yasar] mengatakan; Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Barangsiapa mengucapkan sumpah yang dengannya ia mengambil harta saudaranya, niscaya ia akan menemui Allah dalam keadaan murka kepadanya.\" Telah menceritakan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Isma'il yaitu Ibnu Abu Khalid] dari [Isma'il Al Audi] dari [putrinya Ma'qil Al Muzanni] ia berkata; Ketika [Ayahku] sedang dalam keadaan payah, Ibnu Ziyad dating menjenguk lalu ia menyebutkan hadits tersebut.\""},"2594":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْفَضْلُ بْنُ دَلْهَمٍ عَنِ ابْنِ سِيرِينَ عَنْ مَعْقِلِ بْنِ يَسَارٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ تَزَوَّجَ امْرَأَةً فَسَقَطَ شَعَرُهَا فَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِصَالِ فَلَعَنَ الْوَاصِلَةَ وَالْمَوْصُولَةَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Al Fadhl bin Dalham] dari [Ibnu Sirin] dari [Ma'qil bin Yasar] bahwa seorang laki-laki Anshar menikah dengan seorang wanita. Ternyata rambutnya wanita itu rontok. Ketika Nabi shallallahu 'alaihi wasallam ditanya tentang wishal (menyambung rambut), beliau melaknat wanita yang menyambung dan yang minta disambungkan rambutnya.\""},"2595":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَعَفَّانُ قَالَا حَدَّثَنَا الْمُثَنَّى بْنُ عَوْفٍ حَدَّثَنَا أَبُو عَبْدِ اللَّهِ الْجَسْرِيُّ قَالَ سَأَلْتُ مَعْقِلَ بْنَ يَسَارٍعَنْ الشَّرَابِ فَقَالَ كُنَّا بِالْمَدِينَةِ وَكَانَتْ كَثِيرَةَ التَّمْرِ فَحَرَّمَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَضِيخَوَأَتَاهُ رَجُلٌ فَسَأَلَهُ عَنْ أُمٍّ لَهُ عَجُوزٍ كَبِيرَةٍ أَنَسْقِيهَا النَّبِيذَ فَإِنَّهَا لَا تَأْكُلُ الطَّعَامَ فَنَهَاهُ مَعْقِلٌ","id":"Telah menceritakan kepada kami [Abdushamad] dan ['Affan], keduanya berkata; telah menceritakan kepada kami [Al Mutsanna bin 'Auf], telah menceritakan kepada kami [Abu 'Abdillah Al Jasri] dia berkata; saya pernah bertanya kepada [Ma'qil bin Yasar] tentang minuman, dia menjawab; \"Kami pernah berada di Madinah, saat itu, di sana tengah musim buah kurma, kemudian Rasulullah shallallahu 'alaihi wasallam mengharamkan perasan buah (kurma atau anggur) terhadap kami.\" Beberapada saat kemudian seorang laki-laki datang sambil menanyakan perihal ibunya yang telah tua renta; \"Apakah kami boleh memberinya minuman tersebut? mengingat ia tidak makan makanan? ' Namun Ma'qil tetap melarangnya.\""},"2596":{"ar":"حَدَّثَنَا عَارِمٌ حَدَّثَنَا مُعْتَمِرٌ عَنْ أَبِيهِ عَنْ رَجُلٍ عَنْ أَبِيهِ عَنْ مَعْقِلِ بْنِ يَسَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَقَرَةُ سَنَامُ الْقُرْآنِ وَذُرْوَتُهُ نَزَلَ مَعَ كُلِّ آيَةٍ مِنْهَا ثَمَانُونَ مَلَكًا وَاسْتُخْرِجَتْ{ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }مِنْ تَحْتِ الْعَرْشِ فَوُصِلَتْ بِهَا أَوْ فَوُصِلَتْ بِسُورَةِ الْبَقَرَةِ وَيس قَلْبُ الْقُرْآنِ لَا يَقْرَؤُهَا رَجُلٌ يُرِيدُ اللَّهَ تَبَارَكَ وَتَعَالَى وَالدَّارَ الْآخِرَةَ إِلَّا غُفِرَ لَهُ وَاقْرَءُوهَا عَلَى مَوْتَاكُمْ","id":"Telah menceritakan kepada kami ['Arim], telah menceritakan kepada kami [Mu'tamir] dari [Ayahnya] dari [Seseorang] dari Ayahnya dari [Ma'qil bin Yasar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al Baqarah adalah Al Qur'an kedudukan yang tertinggi dan puncaknya. Delapan puluh Malaikat turun menyertai masing-masing ayatnya. Laa ilaaha illaahu wal hayyul qayyuum di bawah 'Arsy, lalu ia digabungkan dengannya, atau digabungkan dengan surat Al Baqarah. Sedangkan Yasin adalah hati Al Qur'an. Tidaklah seseorang membacanya, sedang ia mengharap (ridla) Allah Tabaraka wa Ta'ala dan akhirat, melainkan dosanya akan di ampuni. Bacakanlah surat tersebut terhadap orang-orang yang mati di antara kalian.\""},"2597":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ حَدَّثَنَا الْحَكَمُ بْنُ عَطِيَّةَ عَنْ أَبِي الرَّبَابِ قَالَ سَمِعْتُ مَعْقِلَ بْنَ يَسَارٍ يَقُولُكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسِيرٍ لَهُ فَنَزَلْنَا فِي مَكَانٍ كَثِيرِ الثُّومِ وَإِنَّ أُنَاسًا مِنْ الْمُسْلِمِينَ أَصَابُوا مِنْهُ ثُمَّ جَاءُوا إِلَى الْمُصَلَّى يُصَلُّونَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَاهُمْ عَنْهَا ثُمَّ جَاءُوا بَعْدَ ذَلِكَ إِلَى الْمُصَلَّى فَنَهَاهُمْ عَنْهَا ثُمَّ جَاءُوا بَعْدَ ذَلِكَ إِلَى الْمُصَلَّى فَنَهَاهُمْ عَنْهَا ثُمَّ جَاءُوا بَعْدَ ذَلِكَ إِلَى الْمُصَلَّى فَوَجَدَ رِيحَهَا مِنْهُمْ فَقَالَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ فَلَا يَقْرَبْنَا فِي مَسْجِدِنَاحَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْحَكَمُ بْنُ أَبِي الْقَاسِمِ الْحَنَفِيُّ أَبُو عَزَّةَ الدَّبَّاغُ عَنْ أَبِي الرَّبَابِ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسِيرٍ لَهُ فَذَكَرَ مَعْنَاهُ حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا أَبُو يَعْقُوبَ يَعْنِي إِسْحَاقَ بْنَ عُثْمَانَ حَدَّثَنِي حُمْرَانُ أَوْ حَمْدَانُ مَوْلَى مَعْقِلِ بْنِ يَسَارٍ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَ صَحِبْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Zubair], telah menceritakan kepada kami [Al Hakam bin 'Athiyah] dari [Abu Rabab], dia mengatakan; saya mendengar [Ma'qil bin Yasar] ia berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan. Kami singgah di suatu tempat yang terdapat banyak bawang putihnya, sementara kaum muslimin banyak yang memakannya. Mereka lantas datang ke tempat shalat, dan shalat bersama Nabi shallallahu 'alaihi wasallam, lalu beliau pun melarang mereka memakannya. Setelah itu, mereka datang lagi ke tempat shalat dan beliau mendapati baunya dari mereka. Beliau bersabda: \"Barangsiapa memakan tumbuhan ini, maka janganlah mendekat di masjid kami.\" Telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Al Hakam bin Abu Al Qasim Al Hanafi Abu 'Azzah Ad Dabbagh], dari [Abu Ar Rabbab] dari [Ma'qil bin Yasar] dia berkata; \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan.\" Ia kemudian menyebutkan makna serupa. Telah menceritakan kepada kami [Abu Sa'id] bekas budak Bani Hasyim, telah menceritakan kepada kami [Abu Ya'qub yaitu Ishaq bin 'Utsman], telah mengabarkan kepadaku [Humran] atau Hamdan bekas budak Ma'qil bin Yasar, dari [Ma'qil bin Yasar] dia berkata; \"Saya pernah menemani Nabi shallallahu 'alaihi wasallam sekian dan sekian.\""},"2598":{"ar":"حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ أَبُو الْيَمَانِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ أَبِي شَيْبَةَ يَحْيَى بْنِ يَزِيدَ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ نُفَيْعِ بْنِ الْحَارِثِ عَنْ مَعْقِلٍ الْمُزَنِيِّ قَالَأَمَرَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَقْضِيَ بَيْنَ قَوْمٍ فَقُلْتُ مَا أَحْسَنَ أَنْ أَقْضِيَ يَا رَسُولَ اللَّهِ قَالَ اللَّهُ مَعَ الْقَاضِي مَا لَمْ يَحِفْ عَمْدًا","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi' Abul Yaman], telah menceritakan kepada kami [Isma'il bin 'Ayyasy] dari [Abu Syaibah Yahya bin Yazid] dari [Zaid bin Abu 'Unaisah] dari [Nufai' bin Al Harits] dari [Ma'qil Al Muzani] dia berkata; \"Nabi shallallahu 'alaihi wasallam memerintahkanku mengadili (perkara) beberapa orang, Kukatakan; \"Betapa bagusnya apa yang hendak aku putuskan, wahai Rasulullah.' Beliau bersabda: \"Allah akan bersama seorang hakim, selama tidak berbuat curang dengan sengaja.\""},"2599":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا أَنَسُ بْنُ سِيرِينَ عَنْ عَبْدِ الْمَلِكِ بْنِ قَتَادَةَ بْنِ مِلْحَانَ الْقَيْسِيِّ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا بِصِيَامِ لَيَالِي الْبِيضِ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ وَقَالَ هِيَ كَصَوْمِ الدَّهْرِ","id":"Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Anas bin Sirin] dari [Abdul Malik bin Qatadah bin Milhan Al Qaissy] dari [Ayahnya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam dulu pernah memerintahkan kami berpuasa yaumul bidl (pertengahan bulan), yaitu; tanggal tiga belas, empat belas, dan lima belas. Sabda beliau: \"puasa yaumul bidl seperti puasa setahun.\""},"2600":{"ar":"حَدَّثَنَا عَارِمٌ حَدَّثَنَا مُعْتَمِرٌ قَالَ وَحَدَّثَ أَبِي عَنِ الْعَلَاءِ بْنِ عُمَيْرٍ قَالَ كُنْتُ عِنْدَ قَتَادَةَ بْنِ مِلْحَانَ حِينَ حُضِرَ فَمَرَّ رَجُلٌ فِي أَقْصَى الدَّارِ قَالَ فَأَبْصَرْتُهُ فِي وَجْهِ قَتَادَةَ قَالَوَكُنْتُ إِذَا رَأَيْتُهُ كَأَنَّ عَلَى وَجْهِهِ الدِّهَانَ قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ عَلَى وَجْهِهِقَالَ أَبُو عَبْد الرَّحْمَنِ حَدَّثَنَا يَحْيَى بْنُ مَعِينٍ وَهُرَيْمٌ أَبُو حَمْزَةَ قَالَا حَدَّثَنَا مُعْتَمِرٌ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Arim], telah menceritakan kepada kami [Mu'tamir] ia berkata; dan [ayahku] telah bercerita kepadaku dari [Al 'Ala` bin 'Umair], dia berkata; 'Aku pernah bersama [Qatadah bin Milhan] ketika ia tengah sekarat. Lalu, lewatlah seorang laki-laki dari dalam rumah, Al 'Alla` berkata; \"Kulihat wajah Qatadah.\" Katanya lagi, \"Ketika aku melihatnya, seakan-akan ada kilapan minyak di wajahnya.\" Katanya; \"Rasulullah shallallahu 'alaihi wasallam dulu pernah mengusap wajahnya.\" Abu Abdurrahman berkata; telah menceritakan kepada kami [Yahya bin Ma'in] dan [Huraim Abu Hamzah] keduanya berkata; telah menceritakan kepada kami [Mu'tamir] lalu ia menyebutkan seperti hadits di atas.\""},"2601":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي أَنَسُ بْنُ سِيرِينَ عَنْ عَبْدِ الْمَلِكِ رَجُلٍ مِنْ بَنِي قَيْسِ بْنِ ثَعْلَبَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُهُمْ بِصِيَامِ أَيَّامِ الْبِيضِ وَيَقُولُ هُنَّ صِيَامُ الشَّهْرِ أَوْ قَالَ الدَّهْرِ","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Syu'bah], telah menceritakan kepada kami [Anas bin Sirin] dari [Abdul Malik] seorang laki-laki dari bani Qais bin Tsa'labah dari [Ayahnya] bahwa Rasulullah Shallalahu 'alaihi wasallam pernah memerintahkan puasa Ayyam Bidh dan beliau bersabda: \"Seperti puasa sebulan atau selama-lamanya.\" "},"2602":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا هَمَّامٌ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ عَبْد�� الْمَلِكِ بْنِ قَتَادَةَ بْنِ مِلْحَانَ الْقَيْسِيِّ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا أَنْ نَصُومَ اللَّيَالِي الْبِيضَ ثَلَاثَ عَشْرَةَ وَأَرْبَعَ عَشْرَةَ وَخَمْسَ عَشْرَةَ وَقَالَ هُنَّ كَهَيْئَةِ الدَّهْرِ","id":"Telah menceritakan kepada kami [Rauh], telah menceritakan kepada kami [Hammam] dari [Anas bin Sirin] dari [Abdul Malik bin Qatadah bin Milhan AL Qaisy] dari [Ayahnya] ia berkata; \"Rasulullah Shallalahu 'alaihi wasallam pernah memerintahkan kami berpuasa yaumul bidh, yaitu; tanggal tiga belas, empat belas dan lima belas, dan beliau bersabda: \"ia seperti puasa selamanya.\" "},"2603":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَنَسَ بْنَ سِيرِينَ قَالَ سَمِعْتُ عَبْدَ الْمَلِكِ بْنَ الْمِنْهَالِ يُحَدِّثُ عَنْ أَبِيهِ قَالَ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا بِصِيَامِ أَيَّامِ الْبِيضِ الثَّلَاثَةِ وَيَقُولُ هُنَّ صِيَامُ الدَّهْرِ","id":"Telah menceritakan kepada kami [Rauh], telah menceritakan kepada kami [Syu'bah], ia berkata; saya mendengar [Anas bin Sirin] berkata; saya mendengar [Abdul Malik bin Minhal] menceritakan dari [Ayahnya], ia berkata; -dan bapaknya adalah salah seorang sahabat Rasulullah Shallalahu 'alaihi wasallam- Rasulullah Shallalahu 'alaihi wasallam pernah memerintahkan puasa yaumul Bidh, beliau bersabda: \"Ia seperti puasa selama-lamanya.\" "},"2604":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا شُعْبَةُ عَنْ حُمَيْدِ بْنِ هِلَالٍ قَالَ سَمِعْتُ مُطَرِّفًا يُحَدِّثُ عَنْ أَعْرَابِيٍّ قَالَرَأَيْتُ فِي رِجْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعْلًا مَخْصُوفَةً","id":"Telah menceritakan kepada kami [Abdurrahman], telah menceritakan kepada kami [Syu'bah] dari [Humaid bin Hilal], ia berkata; saya mendengar [Mutharrif] menceritakan dari [seorang Arab badui] ia berkata; \"Saya melihat Rasulullah Shallalahu 'alaihi wasallam mengenakan sandal yang ditambal (dijahit).\""},"2605":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ أَبِي السَّلِيلِ قَالَ حَدَّثَتْنِي مُجِيبَةُ عَجُوزٌ مِنْ بِاهِلَةَ عَنْ أَبِيهَا أَوْ عَنْ عَمِّهَا قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَةٍ مَرَّةً فَقَالَ مَنْ أَنْتَ قَالَ أَوَ مَا تَعْرِفُنِي قَالَ وَمَنْ أَنْتَ قَالَ أَنَا الْبَاهِلِيُّ الَّذِي أَتَيْتُكَ عَامَ أَوَّلٍ قَالَ فَإِنَّكَ أَتَيْتَنِي وَجِسْمُكَ وَلَوْنُكَ وَهَيْئَتُك حَسَنَةٌ فَمَا بَلَغَ بِكَ مَا أَرَى فَقَالَ إِنِّي وَاللَّهِ مَا أَفْطَرْتُ بَعْدَكَ إِلَّا لَيْلًا قَالَ مَنْ أَمَرَكَ أَنْ تُعَذِّبَ نَفْسَكَ مَنْ أَمَرَكَ أَنْ تُعَذِّبَ نَفْسَكَ مَنْ أَمَرَكَ أَنْ تُعَذِّبَ نَفْسَكَ ثَلَاثَ مَرَّاتٍ صُمْ شَهْرَ الصَّبْرِ رَمَضَانَ قُلْتُ إِنِّي أَجِدُ قُوَّةً وَإِنِّي أُحِبُّ أَنْ تَزِيدَنِي فَقَالَ فَصُمْ يَوْمًا مِنْ الشَّهْرِ قُلْتُ إِنِّي أَجِدُ قُوَّةً وَإِنِّي أُحِبُّ أَنْ تَزِيدَنِي قَالَ فَيَوْمَيْنِ مِنْ الشَّهْرِ قُلْتُ إِنِّي أَجِدُ قُوَّةً وَإِنِّي أُحِبُّ أَنْ تَزِيدَنِي قَالَ وَمَا تَبْغِي عَنْ شَهْرِ الصَّبْرِ وَيَوْمَيْنِ فِي الشَّهْرِ قَالَ قُلْتُ إِنِّي أَجِدُ قُوَّةً وَإِنِّي أُحِبُّ أَنْ تَزِيدَنِي قَالَ فَثَلَاثَةَ أَيَّامٍ مِنْ الشَّهْرِ قَالَ وَأَلْحَمَ عِنْدَ الثَّالِثَةِ فَمَا كَادَ قُلْتُ إِنِّي أَجِدُ قُوَّةً وَإِنِّي أُحِبُّ أَنْ تَزِيدَنِي قَالَ فَمِنْ الْحُرُمِ وَأَفْطِرْ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Al Jurairi] dari [Abu Salil] ia berkata; telah menceritakan kepadaku [Mujibah] seorang yang sudah lanjut usia dari Bahilah, dari [Ayahnya] atau dari pamannya, dia berkata; \"Suatu kali, aku pernah datang kepada Rasulullah shallallahu 'alaihi wasallam untuk suatu keperluan. Beliau kemudian bersabda: \"Siapakah kamu?.\" Dia berkata, 'Tidakkah Anda mengenal saya? ' Beliau bersabda lagi: \"Siapakah kamu?.\" Dia berkata; 'Saya adalah orang Bahili yang mendatangi Anda pada tahun pertama.' Beliau bersabda: \"Sesungguhnya kamu dulu mendatangiku dengan badan, warna kulit, dan penampilan yang bagus. Lantas apa yang menyebabkanmu menjadi sebagaimana yang kulihat ini?.\" Dia menjawab; 'Demi Allah, saya tidak pernah makan setelah (aku berpisah dengan) anda kecuali di malam hari.' Sabda beliau: \"Siapakah yang memerintahkanmu menyiksa diri? 'Siapakah yang memerintahkanmu menyiksa diri? 'Siapakah yang memerintahkanmu menyiksa diri?.\" (beliau mengulanginya hingga tiga kali), Berpuasalah pada bulan kesabaran, yaitu Ramadhan.\" Aku berkata; 'Sesungguhnya saya masih kuat dan saya ingin Anda menambahnya untuk saya'. Sabda beliau: \"Berpuasalah satu hari setiap bulan.\" Kukatakan, 'Sesungguhnya saya masih kuat dan saya ingin Anda menambahnya untuk saya.' Beliau bersabda: \"Berpuasalah dua hari setiap bulan.\" Kukatakan; 'Sesungguhnya saya masih kuat dan saya ingin Anda menambahnya untuk saya.' Beliau bersabda: \"Kamu tidak akan mampu melaksanakan pada bulan kesabaran (Ramadhan) dan dua hari pada tiap bulan.\" 'Aku berkata; 'Sesungguhnya saya masih kuat dan saya ingin Anda menambahnya untuk saya.' Beliau bersabda: \"Kalau begitu, tiga hari.\" Beliau berkata sembari menajamkan pandangannya pada kali yang ketiga. Aku tetap saja berkata; 'Sesungguhnya saya masih kuat dan saya ingin Anda menambahnya untuk saya.' Beliau bersabda: \"(Berpuasalah) pada bulan-bulan haram, dan berbukalah.\""},"2606":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ الثَّقَفِيِّ أَنَّ رَجُلًا أَعْوَرَ مِنْ ثَقِيفٍ قَالَ قَتَادَةُ كَانَ يُقَالُ لَهُ مَعْرُوفٌ أَيْ يُثْنَى عَلَيْهِ خَيْرًا يُقَالُ لَهُ زُهَيْرُ بْنُ عُثْمَانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلِيمَةُ حَقٌّ وَالْيَوْمُ الثَّانِي مَعْرُوفٌ وَالْيَوْمُ الثَّالِثُ سُمْعَةٌ وَرِيَاءٌ","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Abdullah bin Utsman Ats TSaqafi] bahwa seorang lelaki juling matanya dari bani Tsaqif, Qatadah mengatakan; Ia biasa dipanggil dengan Ma'ruf -maksudnya ia digelari dengan kebaikan ia disebut juga [Zuhair bin 'Utsman] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Walimah adalah hak, pada hari kedua adalah perbuatan ma'ruf, sedangkan pada hari ketiga adalah sum'ah dan riya.\" "},"2607":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنِ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ الثَّقَفِيِّ عَنْ رَجُلٍ أَعْوَرَ مِنْ ثَقِيفٍ قَالَ قَتَادَةُ وَكَانَ يُقَالُ لَهُ مَعْرُوفٌ إِنْ لَمْ يَكُنْ اسْمُهُ زُهَيْرَ بْنَ عُثْمَانَ فَلَا أَدْرِي مَا اسْمُهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلِيمَةُ أَوَّلَ يَوْمٍ حَقٌّ وَالثَّانِي مَعْرُوفٌ وَالْيَوْمَ الثَّالِثَ سُمْعَةٌ وَرِيَاءٌ","id":"Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Abdullah bin Utsman Ats Tsaqafi] dari seorang lelaki juling matanya dari bani Tsaqif, [Qatadah] berkata; Ia biasa dipanggil dengan Ma'ruf kalu tidak salah namanya [Zuhair bin 'Utsman] sebenarnya aku tidak tahu nama aslinya, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Walimah adalah hak, pada hari kedua adalah perbuatan ma'ruf, sedangkan pada hari ketiga adalah sum'ah dan riya.\" "},"2608":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ قَالَ كَانَ أَبُو قِلَابَةَ حَدَّثَنِي بِهَذَا الْحَدِيثِ ثُمَّ قَالَ لِي هَلْ لَكَ فِي الَّذِي حَدَّثَنِيهِ قَالَ فَدَلَّنِي عَلَيْهِ فَأَتَيْتُهُ فَقَالَ حَدَّثَنِي قَرِيبٌ لِي يُقَالُ لَهُ أَنَسُ بْنُ مَالِكٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِبِلٍ لِجَارٍ لِي أُخِذَتْ فَوَافَقْتُهُ وَهُوَ يَأْكُلُ فَدَعَانِي إِلَى طَعَامِهِ فَقُلْتُ إِنِّي صَائِمٌ فَقَالَ ادْنُ أَوْ قَالَ هَلُمَّ أُخْبِرْكَ عَنْ ذَلِكَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى وَضَعَ عَنْ الْمُسَافِرِ الصَّوْمَ وَشَطْرَ الصَّلَاةِ وَعَنْ الْحُبْلَى وَالْمُرْضِعِ قَالَ كَانَ بَعْدَ ذَلِكَ يَتَلَهَّفُ يَقُولُ أَلَا أَكُونُ أَكَلْتُ مِنْ طَعَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ دَعَانِي إِلَيْهِحَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا أَبُو هِلَالٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَوَادَةَ الْقُشَيْرِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ أَحَدُ بَنِي كَعْبٍ أَخُو بَنِي قُشَيْرٍ قَالَ أَغَارَتْ عَلَيْنَا خَيْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْتَهَيْتُ إِلَيْهِ وَهُوَ يَأْكُلُ فَقَالَ لِيَ ادْنُ فَكُلْ فَقُلْتُ إِنِّي صَائِمٌ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Ayyub], ia berkata; [Abu Qilabah] menceritakan padaku dengan hadits ini, lalu ia mengatakan padaku; \"Apakah kamu tahu mengenai [orang] yang telah menyampaikan hadits kepadaku?.\" Ayyub berkata; Lalu Abu Qilabah menunjukiku dan aku mendatangi orang tersebut, lalu orang itu berkata; telah menceritakan padaku orang yang dekat denganku namanya [Anas bin Malik], ia berkata; Aku datang kepada Rasulullah Shallalahu 'alaihi wasallam karena unta tetanggaku yang ditahan. Lalu aku berhenti karena beliau sedang makan dan beliau menawariku makan, namun aku memberitahukannya bila aku sedang berpuasa, beliau bersabda: \"Teruskan atau lanjutkanlah! Aku kabarkan padamu bahwa Allah Tabaraka Wa Ta'ala menjadikan orang yang sedang musafir tapi berpuasa dan meneruskan shalat (tidak mengqasar), demikian juga wanita yang hamil dan menyusui bahwa mereka akan menyesal.\" Anas berkata; \"Ketahuilah, akhirnya aku berbuka dan makan bersama dengan Rasulullah Shallalahu 'alaihi wasallam ketika ia mengundangku untuk makan.\" Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Abu Hilal], telah menceritakan kepada kami [Abdullah bin Sawadah Al Qusyairi] dari [Anas bin Malik] salah seorang bani Ka'ab saudara dari bani Qusyair, ia berkata; \"Kami iri dengan kuda Rasulullah Shallalahu 'alaihi wasallam, lalu kami mendatangi beliau, sesampainya di sana beliau tengah keadaan makan, beliau lalu berkata kepadaku: \"Mari makan!.\" Aku berkata; \"Sungguh aku sedang berpuasa.\" Lalu ia menyebutkan hadits tersebut."},"2609":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي قَتَادَةُ وَبَهْزٌ قَالَ وَحَدَّثَنِي شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ زُرَارَةَ بْنَ أَوْفَى يُحَدِّثُ عَنْ أُبَيِّ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ أَدْرَكَ وَالِدَيْهِ أَوْ أَحَدَهُمَا ثُمَّ دَخَلَ النَّارَ مِنْ بَعْدِ ذَلِكَ فَأَبْعَدَهُ اللَّهُ وَأَسْحَقَهُ","id":"Telah menceritakan kepada kami [Hajjaj], telah menceritakan kepada kami [Syu'bah], telah mengabarkan kepadaku [Qatadah] -dan [Bahz] berkata; telah menceritakan kepadaku [Syu'bah] dari [Qatadah] berkata; saya mendengar- [Zurarah bin Aufa] menceritakan dari [Ubay bin Malik] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa mendapati kedua orang tuanya, atau salah satunya, kemudian setelah itu ia masuk Neraka, berarti Allah telah menjauhkan dan membinasakannya.\""},"2610":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنِي شُعْبَةُ عَنْ قَتَادَةَ عَنْ عَبْدِ الرَّحْمَنِ أَبِي الْمِنْهَالِ بْنِ سَلَمَةَ الْخُزَاعِيِّ عَنْ عَمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَسْلَمَ صُومُوا الْيَوْمَ فَقَالُوا إِنَّا قَدْ أَكَلْنَا قَالَ صُومُوا بَقِيَّةَ يَوْمِكُمْ يَعْنِي يَوْمَ عَاشُورَاءَ","id":"Telah menceritakan kepada kami [Hajjaj], telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abdurrahman Abu Al Minhal bin Salamah Al Khuza'i], dari [pamannya] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada kabilah Aslam, \"Puasalah kalian pada hari ini.\" Mereka berkata; \"Sesungguhnya kami telah makan.\" Beliau bersabda lagi: \"Puasalah kalian pada sisa hari kalian ini.\" Yakni, hari 'Asyura."},"2611":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَلِيَّ بْنَ زَيْدٍ يُحَدِّثُ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ رَجُلٍ مِنْ قَوْمِهِ يُقَالُ لَهُ مَالِكٌ أَوْ ابْنُ مَالِكٍ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ أَيُّمَا مُسْلِمٍ ضَمَّ يَتِيمًا بَيْنَ أَبَوَيْنِ مُسْلِمَيْنِ إِلَى طَعَامِهِ وَشَرَابِهِ حَتَّى يَسْتَغْنِيَ وَجَبَتْ لَهُ الْجَنَّةُ الْبَتَّةَ وَأَيُّمَا مُسْلِمٍ أَعْتَقَ رَقَبَةً أَوْ رَجُلًا مُسْلِمًا كَانَتْ فِكَاكَهُ مِنْ النَّارِ وَمَنْ أَدْرَكَ وَالِدَيْهِ أَوْ أَحَدَهُمَا فَدَخَلَ النَّارَ فَأَبْعَدَهُ اللَّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] berkata; Aku mendengar [Ali bin Zaid] menceritakan dari [Zurarah bin `Aufa] dari seseorang dari kaumnya, ada yang menyebutnya [Malik atau Ibnu Malik] menceritakan dari Rasulullah Shallalahu 'alaihi wasallam bahwa beliau bersabda: \"Siapa saja seorang muslim yang menjamin makan dan minum anak yatim karena ditinggal orang tuanya yang muslim, hingga ia mandiri, maka wajib baginya surga. Dan siapa saja dari orang muslim yang memerdekakan budak atau membebaskan seorang muslim, maka ia terbebas dari Neraka, dan barangsiapa mendapatkan kedua orang tuanya atau salah satu dari keduanya masuk Neraka maka Allah telah menjauhkannya.\""},"2612":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ عَلِيُّ بْنُ زَيْدٍ أَخْبَرَنَا عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ مَالِكِ بْنِ الْحَارِثِ رَجُلٍ مِنْهُمْ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ضَمَّ يَتِيمًا بَيْنَ أَبَوَيْنِ مُسْلِمَيْنِ إِلَى طَعَامِهِ وَشَرَابِهِ حَتَّى يَسْتَغْنِيَ عَنْهُ وَجَبَتْ لَهُ الْجَنَّةُ الْبَتَّةَ وَمَنْ أَعْتَقَ امْرَأً مُسْلِمًا كَانَ فِكَاكَهُ مِنْ النَّارِ يُجْزَى بِكُلِّ عُضْوٍ مِنْهُ عُضْوًا مِنْهُ","id":"Telah menceritakan kepada kami [Husyaim], berkata [Ali bin Zaid], telah mengabarkan kepada kami [Zurarah bin Aufa] dari [Malik bin Harits] salah seorang dari mereka bahwa ia mendengar Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Barangsiapa menjamin kehidupan seorang yatim yang ditinggal orang tuanya muslim, dengan memberinya makan dan minum hingga ia mandiri, maka wajib baginya surga. Dan barangsiapa seorang muslim yang memerdekakan budak atau membebaskan dari urusan seorang muslimlainnya, maka ia terbebas dari Neraka, dan akan dibalas pada setiap anggota badannya dengan angota badan budak tersebut.\""},"2613":{"ar":"سَنَةَ ثَمَانٍ وَعِشْرِينَ وَمِئَتَيْنِ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرُ بْنُ حَبِيبٍ الْجَرْمِيُّ حَدَّثَنِي عَمْرُو بْنُ سَلِمَةَ عَنْ أَبِيهِأَنَّهُمْ وَفَدُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَرَادُوا أَنْ يَنْصَرِفُوا قَالُوا يَا رَسُولَ اللَّهِ مَنْ يَؤُمُّنَا قَالَ أَكْثَرُكُمْ جَمْعًا لِلْقُرْآنِ أَوْ أَخْذًا لِلْقُرْآنِ قَالَ فَلَمْ يَكُنْ أَحَدٌ مِنْ الْقَوْمِ جَمَعَ مِنْ الْقُرْآنِ مَا جَمَعْتُ قَالَ فَقَدَّمُونِي وَأَنَا غُلَامٌ فَكُنْتُ أَؤُمُّهُمْ وَعَلَيَّ شَمْلَةٌ لِي قَالَ فَمَا شَهِدْتُ مَجْمَعًا مِنْ جَرْمٍ إِلَّا كُنْتُ إِمَامَهُمْ وَأُصَلِّي عَلَى جَنَائِزِهِمْ إِلَى يَوْمِي هَذَا","id":"Tahun seratus dua puluh delapan. Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Mis'ar bin Habib Al Jarmi], telah menceritakan kepada kami ['Amru bin Salimah] dari [ayahnya], bahwa mereka datang sebagai utusan kepada Nabi shallallahu 'alaihi wasallam. Ketika hendak beranjak pergi, mereka bertanya; \"Wahai Rasulullah, siapakah yang (berhak) mengimami kami?\" Beliau menjawab: \"Orang yang paling banyak menghafal Al Qur'an, atau mengambil Al Qur'an.\" Salimah berkata; \"Saat itu, di antara orang-orang tersebut, tidak ada yang paling banyak hapalan Al Qur'annya sebagaimana aku.\" Katanya lagi, \"Mereka lantas menyuruhku maju, padahal saat itu aku masih kanak-kanak. Aku mengimami mereka dengan menggunakan jubah.\" Dia berkata lagi, \"Tidaklah aku mendapati sekumpulan orang, melainkan akulah yang menjadi imam mereka. Dan, aku pulalah yang menyalati jenazah mereka hingga hari ini.\""},"2614":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ عَمْرِو بْنِ سَلِمَةَ قَالَكُنَّا عَلَى حَاضِرٍ فَكَانَ الرُّكْبَانُ وَقَالَ إِسْمَاعِيلُ مَرَّةً النَّاسُ يَمُرُّونَ بِنَا رَاجِعِينَ مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَدْنُو مِنْهُمْ فَأَسْمَعُ حَتَّى حَفِظْتُ قُرْآنًا وَكَانَ النَّاسُ يَنْتَظِرُونَ بِإِسْلَامِهِمْ فَتْحَ مَكَّةَ فَلَمَّا فُتِحَتْ جَعَلَ الرَّجُلُ يَأْتِيهِ فَيَقُولُ يَا رَسُولَ اللَّهِ أَنَا وَافِدُ بَنِي فُلَانٍ وَجِئْتُكَ بِإِسْلَامِهِمْ فَانْطَلَقَ أَبِي بِإِسْلَامِ قَوْمِهِ فَرَجَعَ إِلَيْهِمْ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِّمُوا أَكْثَرَكُمْ قُرْآنًا قَالَ فَنَظَرُوا وَأَنَا لَعَلَى حِوَاءٍ عَظِيمٍ فَمَا وَجَدُوا فِيهِمْ أَحَدًا أَكْثَرَ قُرْآنًا مِنِّي فَقَدَّمُونِي وَأَنَا غُلَامٌ فَصَلَّيْتُ بِهِمْ وَعَلَيَّ بُرْدَةٌ وَكُنْتُ إِذَا رَكَعْتُ أَوْ سَجَدْتُ قَلَصَتْ فَتَبْدُو عَوْرَتِي فَلَمَّا صَلَّيْنَا تَقُولُ عَجُوزٌ لَنَا دَهْرِيَّةٌ غَطُّوا عَنَّا اسْتَ قَارِئِكُمْ قَالَ فَقَطَعُوا لِي قَمِيصًا فَذَكَرَ أَنَّهُ فَرِحَ بِهِ فَرَحًا شَدِيدًا","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Ayyub] dari ['Amru bin Salimah] ia berkata; Suatu kali kami melewati seseorang yang bermukim di sebuah mata air. Amru bin Salimah ketika itu adalah diantara pasukan pengendara. Pada kesempatan yang lain Isma'il berkata; \"Sering kali orang-orang berlalu lalang berpapasan dengan kami sepulang mereka dari Rasulullah Shallalahu 'alaihi wasallam, lantas aku mendekati mereka dan aku mendengar hingga aku hafal Al Qur`an sedang orang-orang saling menunggu waktu penaklukan kota Makkah dengan keIslaman mereka, hingga ketika Makkah telah ditaklukan, seseorang datang kepada beliau dan berkata; \"Wahai Rasulullah, aku seorang utusan bani fulan dan aku datang kepada anda atas keIslaman mereka, \" maka [Ayahku] juga menyebutkan keIslaman kaumnya lalu ia pulang kepada kaumnya dan berkata; Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Angkatlah yang banyak hafalan Qur`annya sebagai imam.\" Salimah berkata; Maka mereka memandang ke arahku, seolah-olah aku adalah orang yang menyandang kemuliaan tersebut, sementara mereka tiada mendapat orang yang paling banyak hafalannya dibanding aku. Mereka lantas menyuruhku menjadi imam, padahal saat itu aku masih kanak-kanak. Aku mengimami mereka dengan menggunakan mantel (yang sempit), apabila aku ruku' atau sujud, maka tersingkaplah auratku. Seusai kami melaksanakan shalat, seorang wanita tua berkata; \"Tutupilah dari (pandangan) kami belakang (pantat) imam kalian.\" Salimah berkata; \"Lalu mereka (kaumku) menjahitkan jubah untukku.\" Salimah menyebutkan bahwa saat itu dirinya sangat gembira sekali.\""},"2615":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ قَالَ خَالِدٌ الْحَذَّاءُ أَخْبَرَنِي عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ سَلِمَةَ قَالَكَانَتْ تَأْتِينَا الرُّكْبَانُ مِنْ قِبَلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْتَقْرِئُهُمْ فَيُحَدِّثُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيَؤُمَّكُمْ أَكْثَرُكُمْ قُرْآنًا","id":"Telah menceritakan kepada kami [Ali bin 'Ashim], berkata [Khalid Al Hadza`] telah mengabarkan kepadaku dari [Abu Qilabah] dari ['Amru bin Salimah], ia berkata; \"Telah datang [beberapa pengendara] dari arah Rasulullah Shallalahu 'alaihi wasallam, lalu kami memintanya untuk menceritakan apa yang ia dapat, maka ia menceritakan bahwa Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Hendaklah orang yang banyak (hafalan) Al Qur'an menjadi imam di antara kalian.\""},"2616":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنِي عَبْدُ الْمَجِيدِ أَبُو عَمْرٍو حَدَّثَنِي الْعَدَّاءُ بْنُ خَالِدِ بْنِ هَوْذَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ يَوْمَ عَرَفَةَ عَلَى بَعِيرٍ قَائِمًا فِي الرِّكَابَيْنِ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan padaku [Abdul Majid Abu 'Amru], telah menceritakan padaku [Al 'Adda` bin Khalid bin Haudzah], dia berkata; \"Aku melihat Rasulullah shallallahu 'alaihi wasallam tengah berkhutbah di hadapan orang-orang pada hari Arafah di atas unta, beliau berdiri di atas dua pijakan kaki (pada pelana).\""},"2617":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا عُمَرُ بْنُ إِبْرَاهِيمَ الْيَشْكُرِيُّ حَدَّثَنَا شَيْخٌ كَبِيرٌ مِنْ بَنِي عُقَيْلٍ يُقَالُ لَهُ عَبْدُ الْمَجِيدِ الْعُقَيْلِيُّ قَالَانْطَلَقْنَا حُجَّاجًا لَيَالِيَ خَرَجَ يَزِيدُ بْنُ الْمُهَلَّبِ وَقَدْ ذُكِرَ لَنَا أَنَّ مَاءً بِالْعَالِيَةِ يُقَالُ لَهُ الزُّجَيْجُ فَلَمَّا قَضَيْنَا مَنَاسِكَنَا جِئْنَا حَتَّى أَتَيْنَا الزُّجَيْجَ فَأَنَخْنَا رَوَاحِلَنَا قَالَ فَانْطَلَقْنَا حَتَّى أَتَيْنَا عَلَى بِئْرٍ عَلَيْهِ أَشْيَاخٌ مُخَضَّبُونَ يَتَحَدَّثُونَ قَالَ قُلْنَا هَذَا الَّذِي صَحِبَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ بَيْتُهُ قَالُوا نَعَمْ صَحِبَهُ وَهَذَاكَ بَيْتُهُ فَانْطَلَقْنَا حَتَّى أَتَيْنَا الْبَيْتَ فَسَلَّمْنَا قَالَ فَأَذِنَ لَنَا فَإِذَا هُوَ شَيْخٌ كَبِيرٌ مُضْطَجِعٌ يُقَالُ لَهُ الْعَدَّاءُ بْنُ خَالِدٍ الْكِلَابِيُّ قُلْتُ أَنْتَ الَّذِي صَحِبْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ وَلَوْلَا أَنَّهُ اللَّيْلُ لَأَقْرَأْتُكُمْ كِتَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيَّ قَالَ فَمَنْ أَنْتُمْ قُلْنَا مِنْ أَهْلِ الْبَصْرَةِ قَالَ مَرْحَبًا بِكُمْ مَا فَعَلَ يَزِيدُ بْنُ الْمُهَلَّبِ قُلْنَا هُوَ هُنَاكَ يَدْعُو إِلَى كِتَابِ اللَّهِ تَبَارَكَ وَتَعَالَى وَإِلَى سُنَّةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِيمَا هُوَ مِنْ ذَاكَ فِيمَا هُوَ مِنْ ذَاكَ قَالَ قُلْتُ أَيًّا نَتَّبِعُ هَؤُلَاءِ أَوْ هَؤُلَاءِ يَعْنِي أَهْلَ الشَّامِ أَوْ يَزِيدَ قَالَ إِنْ تَقْعُدُوا تُفْلِحُوا وَتَرْشُدُوا إِنْ تَقْعُدُوا تُفْلِحُوا وَتَرْشُدُوا لَا أَعْلَمُهُ إِلَّا قَالَ ثَلَاثَ مَرَّاتٍ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ وَهُوَ قَائِمٌ فِي الرِّكَابَيْنِ يُنَادِي بِأَعْلَى صَوْتِهِ يَا أَيُّهَا النَّاسُ أَيُّ يَوْمِكُمْ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَأَيُّ شَهْرٍ شَهْرُكُمْ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَأَيُّ بَلَدٍ بَلَدُكُمْ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ يَوْمُكُمْ يَوْمٌ حَرَامٌ وَشَهْرُكُمْ شَهْرٌ حَرَامٌ وَبَلَدُكُمْ بَلَدٌ حَرَامٌ قَالَ فَقَالَ أَلَا إِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا إِلَى يَوْمِ تَلْقَوْنَ رَبَّكُمْ تَبَارَكَ وَتَعَالَى فَيَسْأَلُكُمْ عَنْ أَعْمَالِكُمْ قَالَ ثُمَّ رَفَعَ يَدَيْهِ إِلَى السَّمَاءِ فَقَالَ اللَّهُمَّ اشْهَدْ عَلَيْهِمْ اللَّهُمَّ اشْهَدْ عَلَيْهِمْ ذَكَرَ مِرَارًا فَلَا أَدْرِي كَمْ ذَكَرَهُ","id":"Telah menceritakan kepada kami [Yunus], telah menceritakan kepada kami [Umar bin Ibrahim Al Yasykuri], telah menceritakan kepada kami seorang guru besar dari bani 'Uqail yang disebut dengan [Abdul Majid Al 'Uqaili], ia berkata; kami bertolak untuk menunaikan haji di malam hari, lalu keluarlah Yazid bin Al Muhallab -telah disebutkan sebelumnya kepada kami mengenai mata air di 'Aliyah yang disebut dengan 'Zujaij'- ketika kami selesai dari manasik, kami mendatangi 'Zujaij', hingga ketika sampai kami beristirahat, sedang aku berjalan-jalan hingga mendapati suatu mata air, ternyata di sana terdapat beberapa orang tua yang tengah berbincang-bincang. kami berkata; 'Orang inikah yang telah menemani Rasulullah shallallahu 'alaihi wasallam, dimanakah rumahnya?, mereka menjawab; 'Ya, dia telah menemani Rasulullah shallallahu 'alaihi wasallam dan itu rumahnya. Akupun beranjak menuju rumahnya hingga sampai di depan pintu, kami memberi salam. Setelah ia mempersilahkan kami masuk, ternyata ada seorang syaikh tergolek di pembaringan, ia biasa dikenal dengan [Al 'Adda` bin Khalid Al Kilabi], aku lalu bertanya; 'Engkaukah yang telah menemani Rasulullah shallallahu 'alaihi wasallam?.' Ia menjawab; 'Ya, kalaulah bukan malam hari, aku akan membacakan padamu hadits-hadits Rasulullah shallallahu 'alaihi wasallam, sebenarnya kalian ini siapa?.' Kami menjawab; 'Kami dari penduduk Bashrah.' Syaikh itu berkata; 'Selamat datang buat kalian, apa yang dikerjakan Yazid bin Muhallab?.' Aku menjawab; 'Ia menyeru kitabullah Tabaraka wa Ta'ala dan sunah Rasulullah shallallahu 'alaihi wasallam, ' Syaikh itu berkata; 'Sejauh mana ia menyampaikan hal itu? Sejauh mana ia menyampaikan hal itu?.' Aku berkata; 'Mari kita ikut mereka, ikut mereka yaitu penduduk Syam atau Yazid.' Syaikh itu berkata; 'Kalau kalian bergaul dengannya, maka kalian akan beruntung dan dapat petunjuk, kalau kalian bergaul denganya, maka kalian akan beruntung dan mendapat petunjuk, ' -Aku tidak mengerti kecuali ia mengulangi perkataan tersebut hingga tiga kali- (syaikh itu melanjutkan); \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berkhutbah di hari Arafah, beliau berdiri di atas dua pikakan kaki (di atas pelananya) sambil berseru dengan suara yang keras: 'Wahai sekailan manusia, hari apakah ini?.' Mereka menjawab; 'Allah dan Rasul-Nya yang lebih tahu.' Kemudian beliau bertanya: 'Bulan apakah ini?.' Mereka menjawab; 'Allah dan Rasul-Nya yang tahu.' Beliau bersabda: 'Dan negeri apakah ini?.' Mereka juga menjawab; 'Allah dan Rasul-Nya yang tahu.' Beliau bersabda: 'Sekarang Ini adalah hari haram kalian, bulan haram kalian dan negeri haram kalian, sesungguhnya darah kalian, harta kalian, adalah haram sebagaimana keharaman hari kalian ini, di bulan kalian ini dan di negeri kalian ini, sampai kalian menemui Rabb kalian Tabraka wa Ta'ala, kemduian Dia akan menanyai kalian tentang amalan-amalan kalian.\" Setelah itu Beliau mengangkat tangannya ke arah langit sambil bersabda: 'Ya Allah, saksikanlah atas mereka?, Ya Allah saksikanlah atas mereka!.\" Beliau mengulang-ulanginya hingga aku tidak tahu berapa kali beliau mengulanginya."},"2618":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ عَنِ الْحَسَنِ حَدَّثَنَا أَحْمَرُ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَإِنْ كُنَّا لَنَأْوِي لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا يُجَافِي بِيَدَيْهِ عَنْ جَنْبَيْهِ إِذَا سَجَدَحَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ حَدَّثَنَا الْحَسَنُ حَدَّثَنِي أَحْمَرُ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنَّا لَيَأْوِي لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا يُجَافِي بِيَدَيْهِ عَنْ جَنْبَيْهِ إِذَا سَجَدَ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami ['Abbad bin Rasyid] dari [Al Hasan], telah menceritakan kepada kami [Ahmar] salah seorang sahabat Rasulullah Shallalahu 'Alaihi Wasallam, ia berkata; \"Kami mendapati Rasulullah shallallahu 'alaihi wasallam, beliau menjauhkan kedua tangannya dari perut ketika sujud.\" Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami ['Abbad bin Rasyid], telah menceritakan kepada kami [Al Hasan], telah menceritakan kepadaku [Ahmar] seorang sahabat Rasulullah shallallahu 'alaihi wasallam bahwa kami mendapatkan Rasulullah shallallahu 'alaihi wasallam menjauhkan kedua tangannya dari perutnya ketika sujud.\""},"2619":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الضَّحَّاكُ بْنُ يَسَارٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صُحَارٍ الْعَبْدِيِّ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي رَجُل�� مِسْقَامٌ فَأْذَنْ لِي فِي جَرِيرَةٍ أَنْتَبِذُ فِيهَا قَالَ فَأَذِنَ لَهُ فِيهَا","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Adh Dlahak bin Yasar] dari [Yazid bin Abdullah bin Syikhkhir] dari [Abdurrahman bin Shuhar Al 'Abdi] dari [Ayahnya] ia berkata; Aku bertanya; \"Wahai Rasulullah, aku seorang yang sering sakit, maka izinkanlah aku menaruh perasan (buah) di bejana tembaga, lalu beliau mengizinkanku.'"},"2620":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ صُحَارٍ الْعَبْدِيِّ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَقُومُ السَّاعَةُ حَتَّى يُخْسَفَ بِقَبَائِلَ حَتَّى يُقَالَ مَنْ بَقِيَ مِنْ بَنِي فُلَانٍفَعَرَفْتُ أَنَّهُ يَعْنِي الْعَرَبَ لِأَنَّ الْعَجَمَ إِنَّمَا تُنْسَبُ إِلَى قُرَاهَا","id":"Telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan kepada kami [Al Jurairi] dari [Abul 'Ala` bin Syikhkhir] dari [Abdurrahman bin Shuhar Al 'Abdi] dari [Ayahnya] ia berkata; Aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tidak akan terjadi kiamat hingga para kabilah saling berperang, hingga dikatakan; \"Siapa yang tersisa dari kabilah fulan?\" Dan Aku tahu, ternyata maksud beliau adalah orang-orang Arab, karena orang-orang 'Ajam dinasabkan kepada perkampungannya.\""},"2621":{"ar":"حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا الْمُشْمَعِلُّ حَدَّثَنِي عَمْرُو بْنُ سُلَيْمٍ الْمُزَنِيُّ أَنَّهُ سَمِعَ رَافِعَ بْنَ عَمْرٍو الْمُزَنِيَّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَأَنَا وَصِيفٌ يَقُولُ الْعَجْوَةُ وَالشَّجَرَةُ مِنْ الْجَنَّةِ","id":"Telah menceritakan kepadaku [Yahya bin Sa'id], telah menceritakan kepada kami [Al Musyma'il], telah menceritakan padaku ['Amru bin Sulaim Al Muzanni] bahwa [Rafi' bin 'Amru Al Muzanni] berkata; Aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: -Dan ketika itu aku adalah seorang pemuda- beliau bersabda; \"'Ajwah adalah pepohonan dari Surga.\""},"2622":{"ar":"حَدَّثَنَا بَهْزٌ وَأَبُو النَّضْرِ وَعَفَّانُ قَالُوا حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ حُمَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ بَعْدِي مِنْ أُمَّتِي قَوْمًا يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَلَاقِيمَهُمْ يَخْرُجُونَ مِنْ الدِّينِ كَمَا يَخْرُجُ السَّهْمُ مِنْ الرَّمِيَّةِ ثُمَّ لَا يَعُودُونَ فِيهِ شَرُّ الْخَلْقِ وَالْخَلِيقَةِقَالَ ابْنُ الصَّامِتِ فَلَقِيتُ رَافِعًا قَالَ بَهْزٌ أَخَا الْحَكَمِ بْنِ عَمْرٍو فَحَدَّثْتُهُ هَذَا الْحَدِيثَ قَالَ وَأَنَا أَيْضًا قَدْ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Bahz] dan [Abu Nasdlr] serta ['Affan] mereka berkata; telah menceritakan kepada kami [Sulaiman bin Mughirah] dari [Humaid] dari [Abdullah bin Shamit] dari [Abu Dzarr], dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sepeninggalku kelak, akan ada segolongan orang dari umatku yang membaca Al Qur'an, tapi tidak melebihi tenggorokan mereka. Mereka keluar dari agama sebagaimana anak panah melesat dari busurnya. Setelah itu, mereka tidak akan kembali lagi kepadanya (agama). (Mereka adalah) seburuk-buruk makhluk dan ciptaan.\" [Ibnu Shamit] berkata; \"Kutemui [Rafi'], [Bahz] Saudara al-Hakam bin 'Amr mengatkan; lantas hadits ini aku sampaikan kepadanya.\" Dia berkata; \"Aku juga mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},"2623":{"ar":"حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ ابْنَ أَبِي الْحَكَمِ الْغِفَارِيَّ يَقُولُ حَدَّثَتْنِي جَدَّتِي عَنْ عَمِّ أَبِيهَا رَافِعِ بْنِ عَمْرٍو الْغِفَارِيِّ قَالَكُنْتُ وَأَنَا غُلَامٌ أَرْمِي نَخْلًا لِلْأَنْصَارِ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقِيلَ إِنَّ هَاهُنَا غُلَامًا يَرْمِي نَخْلَنَا فَأُتِيَ بِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا غُلَامُ لِمَ تَرْمِي النَّخْلَ قَالَ قُلْتُ آكُلُ قَالَ فَلَا تَرْمِ النَّخْلَ وَكُلْ مَا يَسْقُطُ فِي أَسَافِلِهَا ثُمَّ مَسَحَ رَأْسِي وَقَالَ اللَّهُمَّ أَشْبِعْ بَطْنَهُ","id":"Telah menceritakan kepada kami [Mu'tamir], ia berkata; Aku mendengar [Ibnu Abul Hakam Al Ghifari] berkata; telah menceritakan kepadaku [Nenekku] dari paman ayahnya yaitu [Rafi' bin 'Amr Al Ghifari], dia berkata; \"Saat masih kecil, aku pernah melempari pohon kurma milik orang Anshar. Kemudian Nabi shallallahu 'alaihi wasallam di datangi, dan di beritahukan kepada beliau; \"Sesungguhnya di sini terdapat seorang anak kecil yang suka melempari pohon kurma kami.\" Aku pun dibawa ke hadapan Nabi shallallahu 'alaihi wasallam. Beliau kemudian bersabda: \"Wahai anak kecil, kenapa kau lempari pohon itu?\" Rafi' berkata; \"Kujawab, 'Untuk saya makan.' Sabda beliau: \"Kalau begitu, janganlah kau melempari pohon kurma itu. Makanlah (buah) yang jatuh di bawahnya.\" Beliau lantas mengusap kepalaku dan berdoa; 'Ya Allah, kenyangkanlah perutnya.\""},"2624":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا الْمُشْمَعِلُّ بْنُ عَمْرٍو الْمُزَنِيُّ حَدَّثَنَا عَمْرُو بْنُ سُلَيْمٍ الْمُزَنِيُّ عَنْ رَافِعِ بْنِ عَمْرٍو الْمُزَنِيِّ يَقُولُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَجْوَةُ وَالصَّخْرَةُ أَوْ قَالَ الْعَجْوَةُ وَالشَّجَرَةُ فِي الْجَنَّةِ شَكَّ الْمُشْمَعِلُّ","id":"Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Al Musyma'il bin 'Amru Al Muzanni], telah menceritakan kepada kami ['Amru bin Sulaim Al Muzanni] dari [Rafi' bin 'Amru Al Muzanni] ia berkata; saya mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Ajwah dan syakhrah -atau beliau bersabda- Ajwah dan syajarah berasal dari Surga.\" Al Musyma'il ragu-ragu. "},"2625":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا الْمُشْمَعِلُّ بْنُ إِيَاسٍ قَالَ سَمِعْتُ عَمْرَو بْنَ سُلَيْمٍ يَقُولُ سَمِعْتُ رَافِعَ بْنَ عَمْرٍو الْمُزَنِيَّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَجْوَةُ وَالصَّخْرَةُ مِنْ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Al Musyma'il bin Iyyas] ia berkata; saya mendengar ['Amru bin Sulaim] berkata; saya mendengar [Rafi' bin 'Amru Al Muzanni] berkata; saya mendengar Rasulullah Shallalahu 'alaihi wasallam bersabda: \"Ajwah dan Syakhrah berasal dari surga.\" "},"2626":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَعْدِي مِنْ أُمَّتِي قَوْمًا يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَلَاقِيمَهُمْ يَخْرُجُونَ مِنْ الدِّينِ كَمَا يَخْرُجُ السَّهْمُ مِنْ الرَّمِيَّةِ ثُمَّ لَا يَعُودُونَ إِلَيْهِ شَرُّ الْخَلْقِ وَالْخَلِيقَةِقَالَ ابْنُ الصَّامِتِ فَلَقِيتُ رَافِعًا فَحَدَّثْتُهُ فَقَالَ وَأَنَا أَيْضًا قَدْ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Sulaiman bin Mughirah], telah menceritakan kepada kami [Humaid], telah menceritakan kepada kami [Abdullah bin Shamit] dari [Abu Dzarr] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Sesungguhnya sepeninggalku kelak, akan ada segolongan orang dari umatku yang membaca Al Qur'an, tapi tidak melebihi tenggorokan mereka. Mereka keluar dari agama sebagaimana anak panah melesat dari busurnya. Setelah itu, mereka tidak akan kembali lagi kepadanya (agama). Mereka adalah seburuk-buruk makhluk dan ciptaan.\" [Ibnu Shamit] mengatakan; \"Kutemui [Rafi'], lantas aku sampaikan hadits ini kepadanya.\" Dia berkata; \"Aku juga mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},"2627":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا كَهْمَسٌ وَيَزِيدُ قَالَ أَخْبَرَنَا كَهْمَسٌ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ شَقِيقٍ قَالَ مِحْجَنُ بْنُ الْأَدْرَعِبَعَثَنِي نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ ثُمَّ عَرَضَ لِي وَأَنَا خَارِجٌ مِنْ طَرِيقٍ مِنْ طُرُقِ الْمَدِينَةِ قَالَ فَانْطَلَقْتُ مَعَهُ حَتَّى صَعِدْنَا أُحُدًا فَأَقْبَلَ عَلَى الْمَدِينَةِ فَقَالَ وَيْلُ أُمِّهَا قَرْيَةً يَوْمَ يَدَعُهَا أَهْلُهَا قَالَ يَزِيدُ كَأَيْنَعِ مَا تَكُونُ قَالَ قُلْتُ يَا نَبِيَّ اللَّهِ مَنْ يَأْكُلُ ثَمَرَتَهَا قَالَ عَافِيَةُ الطَّيْرِ وَالسِّبَاعُ قَالَ وَلَا يَدْخُلُهَا الدَّجَّالُ كُلَّمَا أَرَادَ أَنْ يَدْخُلَهَا تَلَقَّاهُ بِكُلِّ نَقْبٍ مِنْهَا مَلَكٌ مُصْلِتًا قَالَ ثُمَّ أَقْبَلْنَا حَتَّى إِذَا كُنَّا بِبَابِ الْمَسْجِدِ قَالَ إِذَا رَجُلٌ يُصَلِّي قَالَ أَتَقُولُهُ صَادِقًا قَالَ قُلْتُ يَا نَبِيَّ اللَّهِ هَذَا فُلَانٌ وَهَذَا مِنْ أَحْسَنِ أَهْلِ الْمَدِينَةِ أَوْ قَالَ أَكْثَرِ أَهْلِ الْمَدِينَةِ صَلَاةً قَالَ لَا تُسْمِعْهُ فَتُهْلِكَهُ مَرَّتَيْنِ أَوْ ثَلَاثًا إِنَّكُمْ أُمَّةٌ أُرِيدَ بِكُمْ الْيُسْرُحَدَّثَنَا حَجَّاجٌ حَدَّثَنِي شُعْبَةُ عَنْ أَبِي بِشْرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ شَقِيقٍ يُحَدِّثُ عَنْ رَجَاءِ بْنِ أَبِي رَجَاءٍ الْبَاهِلِيِّ عَنْ مِحْجَنٍ رَجُلٍ مِنْ أَسْلَمَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Kahmas] -dan [Yazid], dia berkata; telah mengabarkan kepada kami [Kahmas] - ia berkata; Aku mendengar [Abdullah bin Syaqiq] bahwa [Mihjan bin Al `Adra'] berkata; Nabiyullah Shallalahu 'Alaihi Wasallam pernah mengutusku untuk suatu keperluan, kemudian beliau mencegatku ketika aku berada di luar dari salah satu jalan kota Madinah. -Ia melanjutkan; - Lalu aku bertolak bersama beliau hingga kami mendaki gunung Uhud dan kami menghadap ke Madinah, beliau berkata; \"Celakalah induk kampung ini, pada suatu hari ketika penduduknya meninggalkannya, \" -menurut lafadz [Yazid] berkata; seperti buah-buahan yang matang, - Mihjan berkata; aku bertanya; 'Wahai nabi Allah, siapa yang makan buah-buahannya?.' Beliau bersabda: \"Burung-burung yang sehat dan hewan buas.\" Beliau menlanjutkan: \"Dan dajjal tidak akan memasukinya, setiap kali ia hendak memasukinya, maka di setiap jalan setapak ia berhadapan dengan malaikat yang menghunus (pedang), ' kemudian kami kembali hingga sampai di pintu masjid, disana ada seseorang yang sedang shalat, beliau bertanya; \"Apakah kamu mengira ia adalah orang yang jujur?\" Aku berkata; 'Wahai Nabi Allah si fulan ini adalah orang yang baik di Madinah, ' atau dia berkata; 'orang Madinah yang paling banyak shalatnya.' Belaiu bersabda: \"Janganlah engkau memperdengarkannya, hingga kamu dapat merusak shalatnya\" (beliau mengatakannya dua atau tiga kali), \"sungguh kalian adalah umat yang dikehendaki mendapatkan keringanan.\" Telah menceritakan kepada kami [Hajjaj], telah menceritakan kepadaku [Syu'bah] dari [Abu Bisyr] berkata; Aku mendengar [Abdullah bin Syaqiq] menceritakannya dari [Raja` bin Abu Raja` Al Bahili] dari [Mihjan] seseorang dari kalangan Aslam, lalu dia menyebutkan seperti diatas."},"2628":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا أَبُو بِشْرٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ رَجَاءِ بْنِ أَبِي رَجَاءٍ الْبَاهِلِيِّ عَنْ مِحْجَنٍ قَالَ عَفَّانُ وَهُوَ ابْنُ الْأَدْرَعِ قَالَ وَحَدَّثَنَا حَمَّادٌ عَنِ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ مِحْجَنِ بْنِ الْأَدْرَعِ قَالَقَالَ رَجَاءٌ أَقْبَلْتُ مَعَ مِحْجَنٍ ذَاتَ يَوْمٍ حَتَّى إِذَا انْتَهَيْنَا إِلَى مَسْجِدِ الْبَصْرَةِ فَوَجَدْنَا بُرَيْدَةَ الْأَسْلَمِيَّ عَلَى بَابٍ مِنْ أَبْوَابِ الْمَسْجِدِ جَالِسًا قَالَ وَكَانَ فِي الْمَسْجِدِ رَجُلٌ يُقَالُ لَهُ سُكْبَةُ يُطِيلُ الصَّلَاةَ فَلَمَّا انْتَهَيْنَا إِلَى بَابِ الْمَسْجِدِ وَعَلَيْهِ بُرَيْدَةُ قَالَ وَكَانَ بُرَيْدَةُ صَاحِبَ مُزَاحَاتٍ قَالَ يَا مِحْجَنُ أَلَا تُصَلِّي كَمَا يُصَلِّي سُكْبَةُ قَالَ فَلَمْ يَرُدَّ عَلَيْهِ مِحْجَنٌ شَيْئًا وَرَجَعَ قَالَ وَقَالَ لِي مِحْجَنٌ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ بِيَدِي فَانْطَلَقَ يَمْشِي حَتَّى صَعِدَ أُحُدًا فَأَشْرَفَ عَلَى الْمَدِينَةِ فَقَالَ وَيْلُ أُمِّهَا مِنْ قَرْيَةٍ يَتْرُكُهَا أَهْلُهَا كَأَعْمَرِ مَا تَكُونُ يَأْتِيهَا الدَّجَّالُ فَيَجِدُ عَلَى كُلِّ بَابٍ مِنْ أَبْوَابِهَا مَلَكًا مُصْلِتًا فَلَا يَدْخُلُهَا قَالَ ثُمَّ انْحَدَرَ حَتَّى إِذَا كُنَّا بِسُدَّةِ الْمَسْجِدِ رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي فِي الْمَسْجِدِ وَيَسْجُدُ وَيَرْكَعُ وَيَسْجُدُ وَيَرْكَعُ قَالَ فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذَا قَالَ فَأَخَذْتُ أُطْرِيهِ لَهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ هَذَا فُلَانٌ وَهَذَا وَهَذَا قَالَ اسْكُتْ لَا تُسْمِعْهُ فَتُهْلِكَهُ قَالَ ثُمَّ انْطَلَقَ يَمْشِي حَتَّى إِذَا كُنَّا عِنْدَ حُجْرَةٍ لَكِنَّهُ رَفَضَ يَدِي ثُمَّ قَالَ إِنَّ خَيْرَ دِينِكُمْ أَيْسَرُهُ إِنَّ خَيْرَ دِينِكُمْ أَيْسَرُهُ إِنَّ خَيْرَ دِينِكُمْ أَيْسَرُهُ","id":"Telah menceritakan kepada kami ['Affan]; telah menceritakan kepada kami [Abu 'Awanah]; telah menceritakan kepada kami [Abu Bisyr] dari [Abdullah bin Syaqiq] dari [Raja` bin Abu Raja` Al Bahili] dari [Mihjan], 'Affan menjelaskan; dia adalah Ibnu Al `Adra'. Ahmad bin Hambal berkata; telah menceritakan kepada kami [Hammad] dari [Al Jurairi] dari [Abdullah bin Syaqiq] dari [Mihjan bin Al `Adra'], Raja`menuturkan; Aku berangkat bersama Mihjan di suatu hari hingga ketika kami sampai di masjid Bashrah kami bertemu dengan Buraidah Al Aslami di salah satu pintu masjid sedang duduk, -ia melanjutkan; - dan di dalam masjid ada seseorang yang dipanggil dengan sebutan Subkah, ia memanjangkan shalatnya. Ketika kami sampai di pintu masjid dan Buraidah sedang ada disana, -dan Buraidah adalah orang yang suka berkelakar- dia bertanya; 'Wahai Mihjan, kenapa engkau tidak melaksanakan shalat sebagaimana shalatnya Sukbah? ' Raja` melanjutkan; Mihjan tidak menjawab sepatah kata pun kepadanya dan ia pun pulang. Kemudian [Mihjan] berkata padaku; sesungguhnya Rasulullah Shallalahu 'Alaihi Wasallam pernah menggandeng tanganku menaiki gunung Uhud kemudian menghadap ke arah Madinah dan bersabda: \"Celakalah ibu suatu negri yang di tinggalkan penduduknya, seperti halnya negri yang penuh dengan aktifitas. Kemudian Dajjal datang, akan tetapi dia mendapati di setiap pintunya terdapat Malaikat menghunus senjata, maka dia tidak dapat memasukinya.\" Kemudian beliau turun sehingga kami sampai di pelataran masjid, Rasulullah shallallahu 'alaihi wasallam melihat seseorang yang shalat di masjid, dia bersujud dan ruku, bersujud dan ruku, kemudian beliau bertanya padaku; \"Siapa orang ini?\" maka Aku menghadap beliau dan berkata; 'wahai Rasulullah, dia ini adalah fulan, dia ini seperti ini dan seperti ini.' Beliau bersabda: \"Diam kamu, janganlahkamu memperdengarkan kepadanya, karena bisa jadi kamu merusak (shalat) nya, \" kemudian beliau pergi hingga sampai di rumah, beliau melepas pegangan tanganku seraya bersabda: \"Sungguh kebaikan agama kalian adalah kemudahannya, kebaikan agama kalian adalah kemudahannya, kebaikan agama kalian adalah karena kemudahannya.\""},"2629":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا هِشَامٌ وَيَزِيدُ قَالَ أَخْبَرَنَا هِشَامٌ عَنْ حَفْصَةَ عَنْ أَبِي الْعَالِيَةِ عَنِ الْأَنْصَارِيِّ قَالَ يَزِيدُ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ قَالَخَرَجْتُ مِنْ أَهْلِي أُرِيدُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا أَنَا بِهِ قَائِمٌ وَرَجُلٌ مَعَهُ مُقْبِلٌ عَلَيْهِ فَظَنَنْتُ أَنَّ لَهُمَا حَاجَةً قَالَ فَقَالَ الْأَنْصَارِيُّ وَاللَّهِ لَقَدْ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى جَعَلْتُ أَرْثِي لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ طُولِ الْقِيَامِ فَلَمَّا انْصَرَفَ قُلْتُ يَا رَسُولَ اللَّهِ لَقَدْ قَامَ بِكَ الرَّجُلُ حَتَّى جَعَلْتُ أَرْثِي لَكَ مِنْ طُولِ الْقِيَامِ قَالَ وَلَقَدْ رَأَيْتُهُ قُلْتُ نَعَمْ قَالَ أَتَدْرِي مَنْ هُوَ قُلْتُ لَا قَالَ ذَاكَ جِبْرِيلُ عَلَيْهِ السَّلَام مَا زَالَ يُوصِينِي بِالْجَارِ حَتَّى ظَنَنْتُ أَنَّهُ سَيُوَرِّثُهُ ثُمَّ قَالَ أَمَا إِنَّكَ لَوْ سَلَّمْتَ عَلَيْهِ رَدَّ عَلَيْكَ السَّلَامَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Hisyam] dan [Yazid], ia berkata; telah mengabarkan kepada kami [Hisyam] dari [Hafshah] dari [Abu 'Aliyah] dari [Al Anshari], [Yazid] mengatakan dari [seorang laki-laki] Anshar, dia berkata; \"Aku keluar dari keluargaku hendak menemui Nabi shallallahu 'alaihi wasallam. Ketika aku berdiri di sisi beliau, tiba-tiba ada seseorang yang sedang menghadap beliau. Aku mengira ada urusan di antara mereka berdua.\" Orang Anshar tadi berkata; 'Demi Allah, Rasulullah shallallahu 'alaihi wasallam telah berdiri (lama) hingga aku kasihan terhadap Rasulullah shallallahu 'alaihi wasallam karena lamanya berdiri. Ketika akan beranjak, kukatakan; 'Wahai Rasulullah, laki-laki itu telah bersama Anda hingga saya kasihan terhadap Anda karena lamanya berdiri.' Beliau bersabda: \"Apakah kau benar-benar melihatnya.\" Kujawab, 'Ya.' Beliau bertanya: \"Tahukah kau siapa dia?\" Kujawab; 'Tidak.' Beliau bersabda: \"Dia adalah Jibril alaihissalam. Jibril selalu berwasiat kepadaku (suapaya berbuat baik) terhadap tetangga hingga kukira seakan-akan tetangga juga akan memperoleh harta warisan.\" Sabda beliau lagi; \"Ketahuilah, sesungguhnya jika kau mengucap salam kepadanya, niscaya ia akan menjawab salammu.\""},"2630":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ بُدَيْلٍ الْعُقَيْلِيِّ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ شَقِيقٍ أَنَّهُ أَخْبَرَهُ مَنْسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِوَادِي الْقُرَى وَهُوَ عَلَى فَرَسِهِ فَسَأَلَهُ رَجُلٌ مِنْ بُلْقِينَ فَقَالَ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَؤُلَاءِ قَالَ هَؤُلَاءِ الْمَغْضُوبُ عَلَيْهِمْ وَأَشَارَ إِلَى الْيَهُودِ قَالَ فَمَنْ هَؤُلَاءِ قَالَ هَؤُلَاءِ الضَّالِّينَ يَعْنِي النَّصَارَى قَالَ وَجَاءَهُ رَجُلٌ فَقَالَ اسْتُشْهِدَ مَوْلَاكَ أَوْ قَالَ غُلَامُكَ فُلَانٌ فَقَالَ بَلْ يُجَرُّ إِلَى النَّارِ فِي عَبَاءَةٍ غَلَّهَا","id":"Telah menceritakan kepada kami [Abdurrazaq], telah menceritakan kepada kami [Ma'mar] dari [Budail Al 'Uqaili], telah mengabarkan kepadaku ['Abdullah bin Syaqiq], bahwa ia diberitahu oleh [orang] yang pernah mendengar Nabi shallallahu 'alaihi wasallam ketika di wadi al-Qura, saat itu beliau sedang berada di atas kudanya. Beliau ditanya oleh seorang laki-laki dari Bulqin. Katanya; \"Wahai Rasulullah, siapakah mereka.\" Beliau menjawab; \"Mereka adalah orang-orang yang di murkai\" -sambil menunjuk ke arah orang-orang Yahudi- Dia bertanya lagi, \"Lalu, siapakah orang-orang itu?\" Beliau menjawab: \"Mereka adalah orang-orang yang sesat.\" Yaitu, orang-orang Nashrani. Kata dia; \"Lalu ada seseorang mendatanginya dan mengatakan, 'Maula, atau budakmu Fulan mati syahid.' Beliau bersabda: \"Bahkan, ia diseret ke Neraka karena mantel yang telah ia curi.\""},"2631":{"ar":"حَدَّثَنَا بَهْزٌ وَعَبْدُ الصَّمَدِ قَالَا حَدَّثَنَا أَبُو هِلَالٍ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ مُرَّةَ الْبَهْزِيِّ قَالَكُنْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ بَهْزٌ فِي حَدِيثِهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَهِيجُ فِتْنَةٌ كَالصَّيَاصِي فَهَذَا وَمَنْ مَعَهُ عَلَى الْحَقِّ قَالَ فَذَهَبْتُ فَأَخَذْتُ بِمَجَامِعِ ثَوْبِهِ فَإِذَا هُوَ عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Bahz] dan [Abdushamad], keduanya berkata; telah menceritakan kepada kami [Abu Hilal] dari [Qatadah] dari [Abdullah bin Syaqiq] dari [Murrah Al Bahzi], dia berkata; \"Aku pernah berada di sisi Rasulullah shallallahu 'alaihi wasallam. [Bahz] mengatakan dalam haditsnya, dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan terjadi fitnah layaknya tanduk sapi. Sedangkan orang Ini dan orang-orang yang bersamanya berada di atas kebenaran.\" Dia berkata, \"Lalu aku segera bangkit, lalu kutarik semua kainnya, ternyata ia adalah 'Utsman bin 'Affan Radhiyallaahu 'Anhu.\""},"2632":{"ar":"حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَنْبَأَنَا كَهْمَسٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ شَقِيقٍ حَدَّثَنَا هَرَمِيُّ بْنُ الْحَارِثِ وَأُسَامَةُ بْنُ خُرَيْمٍ وَكَانَا يُغَازِيَانِ فَحَدَّثَانِي حَدِيثًا وَلَا يَشْعُرُ كُلُّ وَاحِدٍ مِنْهُمَا أَنَّ صَاحِبَهُ حَدَّثَنِيهِ عَنْ مُرَّةَ الْبَهْزِيِّ قَالَبَيْنَمَا نَحْنُ مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَرِيقٍ مِنْ طُرُقِ الْمَدِينَةِ فَقَالَ كَيْفَ فِي فِتْنَةٍ تَثُورُ فِي أَقْطَارِ الْأَرْضِ كَأَنَّهَا صَيَاصِي بَقَرٍ قَالُوا نَصْنَعُ مَاذَا يَا نَبِيَّ اللَّهِ قَالَ عَلَيْكُمْ هَذَا وَأَصْحَابَهُ أَوْ اتَّبِعُوا هَذَا وَأَصْحَابَهُ قَالَ فَأَسْرَعْتُ حَتَّى عَطَفْتُ عَلَى الرَّجُلِ فَقُلْتُ هَذَا يَا نَبِيَّ اللَّهِ قَالَ هَذَا فَإِذَا هُوَ عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Abu Usamah], ia berkata; telah memberitakan pada kami [Kahmas], telah menceritakan kepada kami [Abdullah bin Syaqiq], telah menceritakan kepada kami [Harami bin Al Harits] dan [Usamah bin Khuraim] -keduanya adalah seorang pejuang- mereka menceritakan satu hadits dan keduanya tidak merasa bila yang mereka ceritakan adalah dari [Murrah Al BAhzi], ia berkata; \"Ketika kami bersama Rasulullah Shallalahu 'Alaihi Wasallam di suatu jalan di jalanan Madinah, beliau bersabda: \"Bagaimana jika terjadi fitnah yang meliputi bumi layaknya tanduk sapi?.\" Mereka bertanya; \"Lalu bagaimana yang harus kami lakukan wahai Nabiyullah?.\" Beliau bersabda: \"Hendaknya kalian bersama orang ini dan para sahabatnya -atau bersabda- ikutilah orang ini dan para sahabatnya.\" Lalu aku segera menoleh ke arah seorang laki-laki, kemudian aku berkata; Orang ini wahai Nabiyullah? Beliau menjawab; \"Ya, orang ini.\" Ternyata ia adalah Utsman bin 'Affan radliallahu 'anhu."},"2633":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا كَهْمَسُ بْنُ الْحَسَنِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ شَقِيقٍ حَدَّثَنِي رَجُلٌ مِنْ عَنَزَةَ يُقَالُ لَهُ زَائِدَةُ أَوْ مَزِيدَةُ بْنُ حَوَالَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ مِنْ أَسْفَارِهِ فَنَزَلَ النَّاسُ مَنْزِلًا وَنَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ظِلِّ دَوْحَةٍ فَرَآنِي وَأَنَا مُقْبِلٌ مِنْ حَاجَةٍ لِي وَلَيْسَ غَيْرُهُ وَغَيْرُ كَاتِبِهِ فَقَالَ أَنَكْتُبُكَ يَا ابْنَ حَوَالَةَ قُلْتُ عَلَامَ يَا رَسُولَ اللَّهِ قَالَ فَلَهَا عَنِّي وَأَقْبَلَ عَلَى الْكَاتِبِ قَالَ ثُمَّ دَنَوْتُ دُونَ ذَلِكَ قَالَ فَقَالَ أَنَكْتُبُكَ يَا ابْنَ حَوَالَةَ قُلْتُ عَلَامَ يَا رَسُولَ اللَّهِ قَالَ فَلَهَا عَنِّي وَأَقْبَلَ عَلَى الْكَاتِبِ قَالَ ثُمَّ جِئْتُ فَقُمْتُ عَلَيْهِمَا فَإِذَا فِي صَدْرِ الْكِتَابِ أَبُو بَكْرٍ وَعُمَرُ فَظَنَنْتُ أَنَّهُمَا لَنْ يُكْتَبَا إِلَّا فِي خَيْرٍ فَقَالَ أَنَكْتُبُكَ يَا ابْنَ حَوَالَةَ فَقُلْتُ نَعَمْ يَا نَبِيَّ اللَّهِ فَقَالَ يَا ابْنَ حَوَالَةَ كَيْفَ تَصْنَعُ فِي فِتْنَةٍ تَثُورُ فِي أَقْطَارِ الْأَرْضِ كَأَنَّهَا صَيَاصِي بَقَرٍ قَالَ قُلْتُ أَصْنَعُ مَاذَا يَا رَسُولَ اللَّهِ قَالَ عَلَيْكَ بِالشَّامِ ثُمَّ قَالَ كَيْفَ تَصْنَعُ فِي فِتْنَةٍ كَأَنَّ الْأُولَى فِيهَا نَفْجَةُ أَرْنَبٍ قَالَ فَلَا أَدْرِي كَيْفَ قَالَ فِي الْآخِرَةِ وَلَأَنْ أَكُونَ عَلِمْتُ كَيْفَ قَالَ فِي الْآخِرَةِ أَحَبُّ إِلَيَّ مِنْ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Yazid], telah mengabarkan kepada kami [Kahmas bin Al Hasan], telah menceritakan kepada kami ['Abdullah bin Syaqiq], telah menceritakan kepada kami seorang laki-laki dari 'Anazah yang bernama [Za`idah] atau Mazidah bin Hawalah ia berkata; \"Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Orang-orang singgah di suatu tempat sementara Nabi shallallahu 'alaihi wasallam pun singgah di teteduhan pohon besar. Beliau melihat aku yang baru saja selesai dari suatu hajat. Pada saat itu, tidak ada orang lain selain beliau dan asistennya. Beliau bersabda: \"Maukah kau kami cantumkan, wahai Ibnu Hawalah?\" Kukatakan; \"Untuk apa, wahai Rasulullah?\" Beliau tidak menghiraukanku dan menuju ke juru tulis. Dia berkata; \"Aku lebih mendekat lagi. Katanya; 'Beliau bersabda lagi: \"Maukah kau kami cantumkan, wahai Ibnu Hawalah?\" Kukatakan; \"Untuk apa, wahai Rasulullah?\" Beliau tidak menghiraukanku dan mendatangi juru tulis. Dia berkata; \"Aku datang ke sana dan berdiri di sisi mereka. Di depan pasukan ternyata ada Abu Bakr dan Umar. Menurutku, mereka tidak diikutsertakan melainkan untuk kebaikan. Beliau berkata lagi, 'Maukah kau kami cantumkan, wahai Ibnu Hawalah? ' Kukatakan; 'Mau, wahai Nabi Allah.' Sabda beliau: \"Wahai Ibnu Hawalah, apakah yang akan kau perbuat ketika terjadi suatu fitnah yang menggejolak di seluruh penjuru bumi hingga seolah-olah ia bagaikan tanduk sapi?.' 'Aku balik bertanya; 'Apakah yang harus saya lakukan, wahai Rasulullah?.' Beliau bersabda: \"Tinggallah di Syam.\" Beliau kemudian bersabda: \"Apakah yang akan kau lakukan ketika terjadi fitnah di mana yang paling utama pada saat itu adalah melompat seperti kelinci.\" Dia berkata; 'Saya tidak tahu bagaimana jawaban akhirnya. Sungguh, aku mengetahui apa yang beliau ucapkan di akhir itu lebih kusukai dari pada sekian dan sekian.\""},"2634":{"ar":"حَدَّثَنَا يَحْيَى بْنُ إِسْحَاقَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ رَبِيعَةَ بْنِ لَقِيطٍ عَنْ عَبْدِ اللَّهِ بْنِ حَوَالَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَجَا مِنْ ثَلَاثٍ فَقَدْ نَجَا ثَلَاثَ مَرَّاتٍ مَوْتِي وَالدَّجَّالِ وَقَتْلِ خَلِيفَةٍ مُصْطَبِرٍ بِالْحَقِّ مُعْطِيهِ","id":"Telah menceritakan kepada kami [Yahya bin Ishaq], telah menceritakan kepada kami [Yahya bin Ayyub], telah menceritakan padaku [Yazid bin Abu Habib] dari [Rabi'ah bin Laqith] dari [Abdullah bin Hawalah] bahwa Nabi Shalallahu 'Alaihi Wasallam bersabda: \"Barang siapa yang selamat dari tiga hal maka ia telah selamat tiga kali; kematianku, Dajjal dan pembunuhan seorang khalifah yang sabat mempertahankan kebenaran, dan khalifah tersebut telah memasrahkan supaya kebenaran dituntaskan.\""},"2635":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ وَهَاشِمُ بْنُ الْقَاسِمِ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ حَدَّثَنَا مَكْحُولٌ عَنْ عَبْدِ اللَّهِ بْنِ حَوَالَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَيَكُونُ جُنْدٌ بِالشَّامِ وَجُنْدٌ بِالْيَمَنِ فَقَالَ رَجُلٌ فَخِرْ لِي يَا رَسُولَ اللَّهِ إِذَا كَانَ ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكَ بِالشَّامِ عَلَيْكَ بِالشَّامِ ثَلَاثًا عَلَيْكَ بِالشَّامِ فَمَنْ أَبَى فَلْيَلْحَقْ بِيَمَنِهِ وَلْيَسْقِ مِنْ غُدُرِهِ فَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى قَدْ تَكَفَّلَ لِي بِالشَّامِ وَأَهْلِهِ قَالَ أَبُو النَّضْرِ مَرَّتَيْنِ فَلْيَلْحَقْ بِيَمَنِهِ","id":"Telah menceritakan kepada kami [Abu Sa'id] maula bani Hasyim dan [Hasyim bin Al Qasim], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Rasyid], telah menceritakan kepada kami [Makhul] dari [Abdullah bin Hawalah] bahwa Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Akan ada pasukan di Syam dan di Yaman.\" Seseorang berkata; \"Pilihkanlah (antara kedua pasukan) buatku wahai Rasulullah jika keadaannya demikian?.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Ikutlah dengan pasukan Syam, Ikutlah dengan pasukan Syam (sebanyak tiga kali), ikutlah dengan pasukan Syam, maka barangsiapa yang enggan hendaklah bergabung dengan yang di yaman dan minumlah dari telaganya, Karena Allah Tabaraka Wata'ala telah menjamin untukku negri Syam dan penduduknya.\" Dalam lafadz Abu Nadhar berkata; \"Ikutilah Yaman (sebanyak dua kali).\""},"2636":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنِ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ عَمٍّ يُقَالُ لَهُ جَارِيَةُ بْنُ قُدَامَةَ السَّعْدِيُّ أَنَّهُسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ قُلْ لِي قَوْلًا يَنْفَعُنِي وَأَقْلِلْ عَلَيَّ لَعَلِّي أَعِيهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَغْضَبْ فَأَعَادَ عَلَيْهِ مِرَارًا كُلُّ ذَلِكَ يَقُولُ لَا تَغْضَبْحَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ أَخْبَرَنَا هِشَامٌ أَخْبَرَنِي أَبِي عَنِ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ عَمٍّ لَهُ يُقَالُ لَهُ جَارِيَةُ بْنُ قُدَامَةَ أَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ قُلْ لِي قَوْلًا وَأَقْلِلْ عَلَيَّ وَذَكَرَ الْحَدِيثَ قَالَ حَدَّثَنَا يَحْيَى كَذَا قَالَ هِشَامٌ قُلْتُ يَا رَسُولَ اللَّهِ وَهُمْ يَقُولُونَ لَمْ يُدْرِكْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي يَحْيَى بْنَ سَعِيدٍ يَقُولُ وَهُمْ يَقُولُونَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنِ الْأَحْنَفِ بْنِ قَيْسٍ عَنْ جَارِيَةَ بْنِ قُدَامَةَ قَالَ وَحَدَّثَنِي عَمٌّ لِي أَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ عَلِّمْنِي شَيْئًا يَنْفَعُنِي وَأَقْلِلْ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ibnu Numair], telah menceritakan kepada kami [Hisyam] dari [Ayahnya] dari [Al Ahnaf bin Qais] dari pamannya yang dikenal dengan [Jariyah bin Qudamah As Sa'di] bahwa ia bertanya pada Rasulullah Shallalahu 'Alaihi Wasallam.\"Wahai Rasululah, katakanlah padaku satu kalimat yang dengannya dapat memberi manfaat untukku, dan tunjukan yang tidak baik agar aku dapat berpaling darinya!.\" Beliau bersabda: \"Jangan kamu marah.\" Ia punm mengulangi pertanyaannya terus-menerus.\" Namun Beliau tetap menjawab: \"Jangan kamu marah.\" Telah menceritakan kepada kami [Yahya bin Sa'id], telah mengabarkan kepada kami [Hisyam], telah mengabarkan kepadaku [Ayahku] dari [Ahnaf bin Qais] dari pamannya yang dikenal dengan [Jariyah bin Qudamah As Sa'di] bahwa ia bertanya; \"Wahai Rasululah, katakanlah padaku satu kalimat (yang bermanfaat untukku), dan tunjukan yang tidak baik (agar aku dapat berpaling darinya)!.\" Lalu ia menyebutkan hadits tersebut. perawi berkata; telah menceritakan kepada kami Yahya seperti ini, telah menceritakan kepada kami Hisyam, aku bertanya; \"Wahai Rasulullah….\" Namun mereka mengatakan; \"ia tidak pernah bertemu Nabi shallallahu 'alaihi wasallam yaitu Yahya bin Sa'id, ia berkata dan mereka pun bertutur pula. Telah menceritakan kepada kami [Abu Mu'awiyah]; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Ahnaf bin Qais] dari [Jariyah bin Qudamah] ia berkata; telah menceritakan kepadaku pamanku bahwa ia menemui Rasulullah Shallalahu 'Alaihi Wasallam dan bertanya; \"Wahai Rasululah, katakanlah padaku satu kalimat (yang manfaat untukku), dan tunjukan yang tidak baik (agar aku dapat berpaling darinya)!.\" Lalu ia menyebutkan hadits tersebut."},"2637":{"ar":"حَدَّثَنَا يَزِيدُ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ أَبِي السَّلِيلِ قَالَ وَقَفَ عَلَيْنَا رَجُلٌ فِي مَجْلِسِنَا بِالْبَقِيعِ فَقَالَ حَدَّثَنِي أَبِي أَوْ عَمِّي أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَقِيعِ وَهُوَ يَقُولُ مَنْ يَتَصَدَّقُ بِصَدَقَةٍ أَشْهَدُ لَهُ بِهَا يَوْمَ الْقِيَامَةِ قَالَ فَحَلَلْتُ مِنْ عِمَامَتِي لَوْثًا أَوْ لَوْثَيْنِ وَأَنَا أُرِيدُ أَنْ أَتَصَدَّقَ بِهِمَا فَأَدْرَكَنِي مَا يُدْرِكُ بَنِي آدَمَ فَعَقَدْتُ عَلَيَّ عِمَامَتِي فَجَاءَ رَجُلٌ وَلَمْ أَرَ بِالْبَقِيعِ رَجُلًا أَشَدَّ سَوَادًا أَصْفَرَ مِنْهُ وَلَا آدَمَ يَعْبُرُ بِنَاقَةٍ لَمْ أَرَ بِالْبَقِيعِ نَاقَةً أَحْسَنَ مِنْهَا فَقَالَ يَا رَسُولَ اللَّهِ أَصَدَقَةٌ قَالَ نَعَمْ قَالَ دُونَكَ هَذِهِ النَّاقَةَ قَالَ فَلَزِمَهُ رَجُلٌ فَقَالَ هَذَا يَتَصَدَّقُ بِهَذِهِ فَوَاللَّهِ لَهِيَ خَيْرٌ مِنْهُ قَالَ فَسَمِعَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَذَبْتَ بَلْ هُوَ خَيْرٌ مِنْكَ وَمِنْهَا ثَلَاثَ مِرَارٍ ثُمَّ قَالَ وَيْلٌ لِأَصْحَابِ الْمِئِينَ مِنْ الْإِبِلِ ثَلَاثًا قَالُوا إِلَّا مَنْ يَا رَسُولَ اللَّهِ قَالَ إِلَّا مَنْ قَالَ بِالْمَالِ هَكَذَا وَهَكَذَا وَجَمَعَ بَيْنَ كَفَّيْهِ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ ثُمَّ قَالَ قَدْ أَفْلَحَ الْمُزْهِدُ الْمُجْهِدُ ثَلَاثًا الْمُزْهِدُ فِي الْعَيْشِ الْمُجْهِدُ فِي الْعِبَادَةِ","id":"Telah menceritakan kepada kami [Yazid], telah menceritakan kepada kami [Al Jurairi] dari [Abu Salil], dia berkata; \"Seorang laki-laki berhenti di majelis kami di Baqi'. Ia lantas berkata, telah menceritakan kepadaku [Ayahku] atau pamanku bahwa ia pernah melihat Rasulullah shallallahu 'alaihi wasallam di Baqi' tengah bersabda: \"Barang siapa bersedekah dengan suatu sedekah, maka aku akan bersaksi untuknya pada hari Kiamat kelak.\" Ayah atau pamanku berkata; \"Segera kuurai satu atau dua lembar kain surbanku. Aku ingin bersedekah dengan keduanya. Tapi, aku tertimpa sesuatu (sifat kikir) sebagaimana menimpa bani Adam yang lain. Segera kuikat kainku kembali. Tak lama Kemudian datanglah seorang laki-laki yang aku tak pernah melihatnya di Baqi' orang yang lebih legam, kuning, (atau sawo matang) dari pada dia. Ia melaju dengan sebuah unta yang tidak pernah kulihat di Baqi' ini seekor unta yang lebih bagus daripadanya. Ia lantas berkata; \"Wahai Rasulullah, apakah ia (bernilai) sedekah? ' Beliau bersabda: \"Ya.\" Laki-laki itu berkata; 'Ambillah unta ini.\" Ayah atau pamanku berkata; 'Kemudian seorang laki-laki membuntutinya lalu berkata, 'Orang ini telah bersedekah dengannya. Demi Allah, unta itu benar-benar lebih baik daripadanya.\" Dia berkata; 'Ternyata Rasulullah shallallahu 'alaihi wasallam mendengar hal itu lalu bersabda: \"Kau salah, bahkan ia lebih baik daripada kamu dan dari padanya (maksudnya adalah unta disebutkan hingga tiga kali).\" Kemudian beliau bersabda: \"Celakalah para pemilik ratusan unta (beliau mengulangi hingga tiga kali).\" Mereka berkata; \"Kecuali siapa, wahai Rasulullah? ' Beliau bersabda: \"Kecuali orang yang mengeluarkan hartanya seperti ini dan seperti ini.\" Beliau himpun kedua telapak tangannya dari kanan dan kirinya kemudian bersabda: \"Sungguh beruntung orang yang zuhud lagi bekerja keras, \" (beliau mengulangnya sampai tiga kali) Zuhud dalam kehidupan (dunia), bekerja keras dalam ibadah.\""},"2638":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا فَسَدَ أَهْلُ الشَّامِ فَلَا خَيْرَ فِيكُمْ وَلَنْ تَزَالَ طَائِفَةٌ مِنْ أُمَّتِي مَنْصُورِينَ لَا يَضُرُّهُمْ مَنْ خَذَلَهُمْ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah], telah menceritakan kepadaku dari [Mu'awiyah bin Qurrah], dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, dan [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah], dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika penduduk Syam telah rusak (akhlaknya), maka tidak ada kebaikan pada diri kalian. Dan akan selalu ada sekelompok orang dari umatku yang senantiasa menang, tidak akan membahayakan mereka orang-orang yang menghinakan mereka hingga tiba hari Kiamat.\""},"2639":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَمَسَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَأْسِي","id":"Telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Ayahnya] ia berkata; \"Nabi Shallalahu 'Alaihi Wasallam pernah mengusap kepalaku.\""},"2640":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا زِيَادُ بْنُ مِخْرَاقٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنِّي لَأَذْبَحُ الشَّاةَ وَإِنِّي أَرْحَمُهَا أَوْ قَالَ إِنِّي لَأَرْحَمُ الشَّاةَ أَنْ أَذْبَحَهَا فَقَالَ وَالشَّاةُ إِنْ رَحِمْتَهَا رَحِمَكَ اللَّهُ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim], telah menceritakan kepada kami [Ziyad bin Mikhraq], telah menceritakan kepada kami [Mu'awiyah bin Qurrah] dari [Ayahnya] bahwa seorang laki-laki berkata; \"Wahai Rasulullah, aku telah menyembelih seekor kambing, akan tetapi aku merasa kasihan padanya -atau berkata; sesungguhnya aku merasa kasihan jika menyembelihnya.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: Beliau bersabda: \"Sekiranya engkau menyayangi kambing, maka Allah akan menyayangimu.\""},"2641":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِي��ِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صِيَامُ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ صِيَامُ الدَّهْرِ وَإِفْطَارُهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Ayahnya] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Puasa tiga hari setiap bulan sama halnya dengan puasa dan berbuka sepanjang tahun.\""},"2642":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَإِنَّ رَجُلًا كَانَ يَأْتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ ابْنٌ لَهُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُحِبُّهُ فَقَالَ يَا رَسُولَ اللَّهِ أَحَبَّكَ اللَّهُ كَمَا أُحِبُّهُ فَفَقَدَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا فَعَلَ ابْنُ فُلَانٍ قَالُوا يَا رَسُولَ اللَّهِ مَاتَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِيهِ أَمَا تُحِبُّ أَنْ لَا تَأْتِيَ بَابًا مِنْ أَبْوَابِ الْجَنَّةِ إِلَّا وَجَدْتَهُ يَنْتَظِرُكَ فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ أَلَهُ خَاصَّةً أَوْ لِكُلِّنَا قَالَ بَلْ لِكُلِّكُمْحَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنَا شُعْبَةُ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ قُرَّةَ يُحَدِّثُ عَنْ أَبِيهِ أَنَّ رَجُلًا كَانَ يَأْتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Ayahnya] ia berkata; Seseorang mendatangi Rasulullah Shallalahu 'Alaihi Wasallam sambil membawa anaknya, lalu Nabi Shalallahu 'Alaihi Wasallam bertanya padanya: \"Apakah engkau mencintainya?.\" Ia menjawab; \"Wahai Rasulullah, Allah mencintaimu, demikianlah aku mencintainya.\" Rasulullah Shallalahu 'Alaihi Wasallam lama tidak melihatnya lalu beliau bersabda: \"Dimanakah anak si fulan?.\" Orang-orang menjawab; \"Wahai Rasulullah, sesungguhnya ia telah meninggal.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda pada ayahnya: \"Tidakkah engkau suka, bila engkau memasuki surga dari satu pintu diantara pintu-pintunya kecuali engkau mendapatkan anakmu sedang menungguimu?.\" Seseorang bertanya; \"Wahai Rasulullah, apakah itu khusus buatnya atau buat semuanya?.\" Beliau menjawab: \"Bahkan untuk semua dari kalian.\" Telah menceritakan kepada kami [Muhammad bin Ja'far], telah mengabarkan kepada kami [Syu'bah] dia berkata; saya mendengar [Mu'awiyah bin Qurrah] dari [Ayahnya] ia berkata; seorang laki-laki datang kepada Rasulullah Shallalahu 'Alaihi Wasallam, lalu ia menyebutkan hadits semisal itu."},"2643":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا فَسَدَ أَهْلُ الشَّامِ فَلَا خَيْرَ فِيكُمْ وَلَا يَزَالُ نَاسٌ مِنْ أُمَّتِي مَنْصُورِينَ لَا يُبَالُونَ مَنْ خَذَلَهُمْ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah menceritakan kepada kami [Yazid], telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Ayahnya] dia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Apabila penduduk Syam mengalami kerusakan, maka tiada kebaikan bagi kalian. Dan akan ada sekelompok dari umatku yang senantiasa mendapatkan pertolongan, mereka tidak mempedulikan terhadap orang-orang yang merendahkannya hingga datangnya hari kiamat.\""},"2644":{"ar":"حَدَّثَنَا حَسَنٌ يَعْنِي الْأَشْيَبَ وَأَبُو النَّضْرِ قَالَا حَدَّثَنَا زُهَيْرٌ عَنْ عُرْوَةَ بْنِ عَبْدِ اللَّهِ بْنِ قُشَيْرٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ قَالَ أَبُو النَّضْرِ فِي حَدِيثِهِ حَدَّثَنِي زُهَيْرٌ حَدَّثَنَا عُرْوَةُ بْنُ عَبْدِ اللَّهِ بْنِ قُشَيْرٍ أَبُو مَهَلٍ الْجُعْفِيُّ حَدَّثَنِي مُعَاوِيَةُ بْنُ قُرَّةَ عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ مُزَيْنَةَ فَبَايَعْنَاهُ وَإِنَّ قَمِيصَهُ لَمُطْلَقٌ قَالَ فَبَايَعْنَاهُ ثُمَّ أَدْخَلْتُ يَدِي فِي جَيْبِ قَمِيصِهِ فَمَسِسْتُ الْخَاتَمَ قَالَ عُرْوَةُ فَمَا رَأَيْتُ مُعَاوِيَةَ وَلَا ابْنَهُ قَالَ وَأُرَاهُ يَعْنِي إِيَاسًا فِي شِتَاءٍ قَطُّ وَلَا حَرٍّ إِلَّا مُطْلِقَيْ إِزَارِهِمَا لَا يَزُرَّانِ","id":"Telah menceritakan kepada kami [Hasan yaitu Al Asy-yab] dan [Abu Nadhar], keduanya berkata; telah menceritakan kepada kami [Zuhair] dari ['Urwah bin Abdullah bin Qusyair] dari [Mu'awiyah bin Qurrah] dari [Ayahnya] - [Abu Nadhar] berkata dalam haditsnya; telah menceritakan kepada kami [Zuhair], telah menceritakan kepada kami ['Urwah bin Abdullah bin Qusyair Abu Mahal Al Ju'fi], telah menceritakan kepadaku [Mu'awiyah bin Qurrah] dari [Ayahnya] ia berkata; \"Saya datang kepada Rasulullah Shallalahu 'Alaihi Wasallam bersama beberapa orang dari suku Muzainah, lalu kami berbaiat kepada beliau, sungguh (kancing) baju gamis beliau terlepas, Qurrah berkata; \"Lantas kami pun berbai'at kepada beliau, kemudian aku masukkan tanganku ke saku (gamis) beliau dan aku sempat memegang cincinnya.\" [Urwah] berkata; \"Aku belum pernah melihat Mu'awiyah maupun anaknya, -Urwah berkata; dan setahu saya yang di maksud anaknya adalah Iyas- di musim dingin maupun di musim panas, kecuali kancing kain sarungnya (bajunya) terbuka.\""},"2645":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ قُرَّةَ يُحَدِّثُ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنْتُهُ أَنْ أُدْخِلَ يَدِي فِي جُرُبَّانِهِ لِيَدْعُوَ لِي فَمَا مَنَعَهُ وَأَنَا أَلْمِسُهُ أَنْ دَعَا لِي قَالَ فَوَجَدْتُ عَلَى نُغْضِ كَتِفِهِ مِثْلَ السِّلْعَةِ","id":"Telah menceritakan kepada kami [Rauh], telah menceritakan kepada kami [Qurrah bin Khalid], ia berkata; saya mendengar [Mu'awiyah bin Qurrah] menceritakan dari [Ayahnya] ia berkata; \"Saya datang kepada Rasulullah Shallalahu 'Alaihi Wasallam untuk meminta izin memasukkan tanganku ke kantong bajunya agar beliau mendoakanku dan beliau tidak melarangnya, kemudian aku memohonnya agar mendoakanku, maka aku menemukan di atas pundaknya terdapat (sesuatu) seperti daging tumbuh.\""},"2646":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِيَاسٍ عَنْ أَبِيهِأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا لَهُ وَمَسَحَ رَأْسَهُ","id":"Telah menceritakan kepada kami [Wahab bin Jarir] dari [Syu'bah] dari [Abu Iyyas] dari [Ayahnya] bahwa ia pernah datang kepada Nabi Shalallahu 'Alaihi Wasallam lalu Rasulullah Shallalahu 'Alaihi Wasallam mendo'akannya sembari mengusap kepalanya.\""},"2647":{"ar":"حَدَّثَنَا وَهْبٌ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي صِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ الشَّهْرِ صَوْمُ الدَّهْرِ وَإِفْطَارُهُ","id":"Telah menceritakan kepada kami [Wahb], telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Ayahnya] dari Nabi Shalallahu 'Alaihi Wasallam, beliau bersabda: \"Puasa tiga hari di setiap bulan sama halnya dengan puasa dan berbuka sepanjang tahun.\""},"2648":{"ar":"حَدَّثَنَا أَبُو أُسَامَةَ حَمَّادُ بْنُ أُسَامَةَ أَخْبَرَنَا كَهْمَسٌ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ حَدَّثَنِي هَرَمِيُّ بْنُ الْحَارِثِ وَأُسَامَةُ بْنُ خُرَيْمٍ وَكَانَا يُغَازِيَانِ فَحَدَّثَانِي حَدِيثًا وَلَمْ يَشْعُرْ كُلُّ وَاحِدٍ مِنْهُمَا أَنَّ صَاحِبَهُ حَدَّثَنِيهِ عَنْ مُرَّةَ الْبَهْزِيِّ قَالَبَيْنَمَا نَحْنُ مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَرِيقٍ مِنْ طُرُقِ الْمَدِينَةِ فَقَالَ كَيْفَ تَصْنَعُونَ فِي فِتْنَةٍ تَثُورُ فِي أَقْطَارِ الْأَرْضِ كَأَنَّهَا صَيَاصِي بَقَرٍ قَالُوا نَصْنَعُ مَاذَا يَا نَبِيَّ اللَّهِ قَالَ عَلَيْكُمْ هَذَا وَأَصْحَابَهُ أَوْ اتَّبِعُوا هَذَا وَأَصْحَابَهُ قَالَ فَأَسْرَعْتُ حَتَّى عَيِيتُ فَلَحِقْتُ الرَّجُلَ فَقُلْتُ هَذَا يَا رَسُولَ اللَّهِ قَالَ هَذَا فَإِذَا هُوَ عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ فَقَالَ هَذَا وَأَصْحَابُهُ وَذَكَرَهُ","id":"Telah menceritakan kepada kami [Abu Usamah Hammad bin Usamah], telah mengabarkan kepada kami [Kahmas] dari [Abdullah bin Syaqiq], telah menceritakan kepadaku [Harami bin Al Harits] dan [Usamah bin Khuraim], -keduanya adalah seorang pejuang- mereka menceritakan satu hadits dan keduanya tidak merasa bila hadits yang mereka sampaikan dari [Murrah Al Bahzi], ia berkata; \"Ketika kami bersama Rasulullah Shallalahu 'Alaihi Wasallam di suatu jalan di jalanan Madinah, beliau bersabda: \"Bagaimana jika terjadi fitnah yang meliputi bumi layaknya tanduk sapi?.\" Mereka bertanya; \"Lalu bagaimana yang harus kami lakukan wahai Nabiyullah?.\" Beliau bersabda: \"Hendaknya kalian bersama orang ini dan para sahabatnya -atau bersabda- ikutilah orang ini dan para sahabatnya.\" Murrah Al Bahzi melanjutkan; \"Lalu aku kejar sehingga aku tak kuasa lagi, lalu aku menemui seorang laki-laki, aku berkata; Orang ini wahai Nabiyullah? Beliau menjawab; \"Ya, orang ini.\" Ternyata ia adalah Utsman bin 'Affan radliallahu 'anhu.\""},"2649":{"ar":"حَدَّثَنَا يَحْيَى عَنْ عُيَيْنَةَ قَالَ حَدَّثَنِي أَبِي عَنْ أَبِي بَكْرَةَ وَوَكِيعٌ قَالَ حَدَّثَنَا عُيَيْنَةُ وَيَزِيدُ أَخْبَرَنَا عُيَيْنَةُ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ ذَنْبٍ أَحْرَى أَنْ يُعَجِّلَ بِصَاحِبِهِ الْعُقُوبَةَ مَعَ مَا يُؤَخَّرُ لَهُ فِي الْآخِرَةِ مِنْ بَغْيٍ أَوْ قَطِيعَةِ رَحِمٍ قَالَ وَكِيعٌ أَنْ يُعَجِّلَ اللَّهُ وَقَالَ يَزِيدُ يُعَجِّلُ اللَّهُ وَقَالَ مَعَ مَا يُدَّخَرُ لَهُ","id":"Telah menceritakan kepada kami [Yahya] dari ['Uyainah] ia berkata; telah menceritakan kepadaku [Ayahku] dari [Abu Bakrah] dan [Waki'] ia berkata; telah menceritakan kepada kami ['Uyainah] -dan [Yazid] telah mengabarkan kepada kami ['Uyainah] dari [Ayahnya] dari [Abu Bakrah] - dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada dosa yang di segerakan terhadap pelakunya, dengan siksa yang tetap ia terima di akhirat, daripada kezhaliman atau memutus silaturahmi.\" [Waqi'] ia berkata; \"An Yu'ajjilallahu) Allah menyegerakan.\" [Yazid] berkata dengan redaksi; \"Yu'ajjilullah (Disegerakan Allah).\" Katanya lagi, \"Dengan (tetap merasakan) siksa yang ditangguhkan untuknya.\""},"2650":{"ar":"حَدَّثَنَا يَحْيَى عَنْ عُيَيْنَةَ وَوَكِيعٌ حَدَّثَنَا عُيَيْنَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَ قَالَلَقَدْ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّا لَنَكَادُ أَنْ نَرْمُلَ بِهَا قَالَ وَكِيعٌ أَنْ نَرْمُلَ بِالْجِنَازَةِ رَمَلًا","id":"Telah menceritakan kepada kami [Yahya] dari [Uyainah] dan [Waki'], telah menceritakan kepada kami ['Uyainah bin Abdurrahman] dari [Ayahnya] dari [Abu Bakrah] dia berkata; \"Sesungguhnya aku sendiri pernah bersama Rasulullah shallallahu 'alaihi wasallam, dan sungguh kami membawanya (jenazah) sambil berlari-lari kecil (cepat).\" [Waqi'] berkata; \"Membawa jenazah sambil berlari-lari kecil.\""},"2651":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عُيَيْنَةُ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ لِتِسْعٍ يَبْقَيْنَ أَوْ لِسَبْعٍ يَبْقَيْنَ أَوْ لِخَمْسٍ أَوْ لِثَلَاثٍ أَوْ آخِرِ لَيْلَةٍ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami ['Uyainah] dari [Ayahnya] dari [Abu Bakrah], dia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Carilah ia (lailatul Qadr) di sepuluh hari terakhir, pada hari kedua puluh satu, dua puluh tiga, dua puluh lima, dua puluh tujuh, atau akhir malam (dua puluh sembilan).\""},"2652":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَكَرِيَّا أَبُو عِمْرَانَ شَيْخٌ بَصْرِيٌّ قَالَ سَمِعْتُ شَيْخًا يُحَدِّثُ عَنِ ابْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَمَ امْرَأَةً فَحَفَرَ لَهَا إِلَى الثَّنْدُوَةِ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Zakaria Abu Imran] seorang guru besar di Bashrah, ia berkata; saya mendengar seorang [Syaikh] menceritakan dari [Ibnu Abu Bakrah] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam pernah merajam seorang wanita, beliau menggali lubang untuknya hingga (setinggi) dada.\""},"2653":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ وَعَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ أَنَّهُ كَتَبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَقْضِي الْحَاكِمُ بَيْنَ اثْنَيْنِ وَهُوَ غَضْبَانُ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sufyan] dan [Abdurrahman] dari [Sufyan] dari [Abdul Malik bin Umair] dari [Abdurrahman bin Abi Bakrah] dari [Ayahnya] ia pernah menulis bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang hakim mengadili dua orang (yang bersengketa) dalam keadaan marah.\""},"2654":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنِي عُثْمَانُ الشَّحَّامُ عَنْ مُسْلِمِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكُفْرِ وَالْفَقْرِ وَعَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan padaku [Utsman Asy Syakham] dari [Muslim bin Abu Bakrah] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam biasa berdo'a: \"ALLAHUMMA INNI A'UUDZUBIKA MINAL KUFRI WAL FAQRI WA 'ADZAABIL QABRI. (Ya Allah, sesungguhnya aku berlindung kepada-Mu dari kekufuran, kefakiran, dan adzab kubur).\""},"2655":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عُثْمَانُ أَبُو سَلَمَةَ الشَّحَّامُ حَدَّثَنِي مُسْلِمُ بْنُ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيَخْرُجُ قَوْمٌ أَحْدَاثٌ أَحِدَّاءُ أَشِدَّاءُ ذَلِقَةٌ أَلْسِنَتُهُمْ بِالْقُرْآنِ يَقْرَءُونَهُ لَا يُجَاوِزُ تَرَاقِيَهُمْ فَإِذَا لَقِيتُمُوهُمْ فَأَنِيمُوهُمْ ثُمَّ إِذَا لَقِيتُمُوهُمْ فَاقْتُلُوهُمْ فَإِنَّهُ يُؤْجَرُ قَاتِلُهُمْ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Utsman Abu Salamah Asy Syakham], telah menceritakan kepadaku [Muslim bin Abu Bakrah] dari [Ayahnya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan keluar sekelompok orang muda usia, bengis, dan keras. Lisan mereka fasih dengan Al Qur'an. Mereka membacanya, tapi tidak sampai tenggorokan mereka. Jika kalian bertemu dengan mereka, maka bunuhlah mereka. Kemudian jika kalian bertemu dengan mereka, maka bunuhlah mereka, karena sesungguhnya membunuh mereka akan mendapatkan pahala.\""},"2656":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنِ الْحَكَمِ بْنِ الْأَعْرَجِ عَنِ الْأَشْعَثِ بْنِ ثُرْمُلَةَ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ نَفْسًا مُعَاهَدَةً بِغَيْرِ حِلِّهَا حَرَّمَ اللَّهُ عَلَيْهِ الْجَنَّةَ أَنْ يَجِدَ رِيحَهَا","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sufyan] dari [Yunus bin 'Ubaid] dari [Al Hakam bin Al A'raj] dari [Al Asy'ats bin Turmulah] dari [Abu Bakrah] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Barangsiapa membunuh jiwa yang berada dalam perjanjian (mu'ahad) tanpa sebab yang di halalkan, maka Allah mengharamkan baginya surga dan tiada mencium baunya.\""},"2657":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا الْجُرَيْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَ وَقَالَ إِسْمَاعِيلُ مَرَّةً كُنَّا جُلُوسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا أُنَبِّئُكُمْ بِأَكْبَرِ الْكَبَائِرِ ثَلَاثًا الْإِشْرَاكُ بِاللَّهِ عَزَّ وَجَلَّ قَالَوَذُكِرَ الْكَبَائِرُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْإِشْرَاكُ بِاللَّهِ عَزَّ وَجَلَّ وَعُقُوقُ الْوَالِدَيْنِ وَكَانَ مُتَّكِئًا فَجَلَسَ وَقَالَ وَشَهَادَةُ الزُّورِ وَشَهَادَةُ الزُّورِ وَشَهَادَةُ الزُّورِ أَوْ قَوْلُ الزُّورِ وَشَهَادَةُ الزُّورِ فَمَا زَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَرِّرُهَا حَتَّى قُلْنَا لَيْتَهُ سَكَتَ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Al Jurairi], telah menceritakan kepada kami [Abdurrahman bin Abu Bakrah] dari [Ayahnya] ia berkata; dan di kesempatan lain [Isma'il] berkata; \"Suatu ketika, kami sedang duduk-duduk bersama Nabi Shalallahu 'Alaihi Wasallam, lalu beliau bersabda: \"Maukah aku ceritakan kepada kalian tentang dosa besar yang paling besar?. -beliau mengulanginya hingga tiga kali- yaitu menyekutukan Allah Azza Wa Jalla.\" Isma'il berkata; Lalu disebutkan dosa-dosa besar di sisi Rasulullah Shallalahu 'Alaihi Wasallam, maka beliau bersabda: \"Mempersekutukan Allah dan durhaka kepada orang tua.\" Beliau bersabda demikian sambil bersandar, lalu beliau duduk dan bersabda: \"Persaksian palsu, persaksian palsu, persaksian palsu, atau perkataan palsu dan persaksian palsu.\" Rasulullah Shallalahu 'Alaihi Wasallam mengulang-ulanginya hingga kami mengira beliau tidak akan berhenti (diam)."},"2658":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي بَكْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فِي حَجَّتِهِ فَقَالَ أَلَا إِنَّ الزَّمَانَ قَدْ اسْتَدَارَ كَهَيْئَتِهِ يَوْمَ خَلَقَ اللَّهُ السَّمَوَاتِ وَالْأَرْضَ السَّنَةُ اثْنَا عَشَرَ شَهْرًا مِنْهَا أَرْبَعَةٌ حُرُمٌ ثَلَاثٌ مُتَوَالِيَاتٌ ذُو الْقَعْدَةِ وَذُو الْحِجَّةِ وَالْمُحَرَّمُ وَرَجَبُ مُضَرَ الَّذِي بَيْنَ جُمَادَى وَشَعْبَانَ ثُمَّ قَالَ أَلَا أَيُّ يَوْمٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ قَالَ أَلَيْسَ يَوْمَ النَّحْرِ قُلْنَا بَلَى ثُمَّ قَالَ أَيُّ شَهْرٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ فَقَالَ أَلَيْسَ ذَا الْحِجَّةِ قُلْنَا بَلَى ثُمَّ قَالَ أَيُّ بَلَدٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ قَالَ أَلَيْسَتْ الْبَلْدَةَ قُلْنَا بَلَى قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ قَالَ وَأَحْسَبُهُ قَالَ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا وَسَتَلْقَوْنَ رَبَّكُمْ فَيَسْأَلُكُمْ عَنْ أَعْمَالِكُمْ أَلَا لَا تَرْجِعُوا بَعْدِي ضُلَّالًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ أَلَا هَلْ بَلَّغْتُ أَلَا لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ مِنْكُمْ فَلَعَلَّ مَنْ يُبَلَّغُهُ يَكُونُ أَوْعَى لَهُ مِنْ بَعْضِ مَنْ يَسْمَعُهُقَالَ مُحَمَّدٌ وَقَدْ كَانَ ذَاكَ قَالَ قَدْ كَانَ بَعْضُ مَنْ بُلِّغَهُ أَوْعَى لَهُ مِنْ بَعْضِ مَنْ سَمِعَهُ","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Ayyub] dari [Muhamad bin Sirin] dari [Abu Bakrah] bahwa Nabi Shalallahu 'Alaihi Wasallam berkhutbah di musim haji, beliau bersabda: \"Ketahuilah bahwa zaman telah berputar sebagaimana mestinya sebagaimana hari ketika Allah menciptakan langit dan bumi, setahun ada dua belas bulan, diantaranya adalah empat bulan haram, tiga bulan berturut-turut, yaitu; Dzul Qa'dah, Dzul Hijjah dan Muharram, sedangkan bulan Rajab terpisah, antara bulan Jumadil (akhir) dan Sya'ban.\" Rasulullah Shallalahu 'Alaihi Wasallam bertanya: \"Hari apakah ini?.\" Mereka menjawab; \"Allah dan Rasul-Nya yang lebih tahu.\" Kemudian beliau terdiam, kami menyangka beliau hendak menyebutkan dengan nama yang lain, beliau bertanya: \"Bukankah ini hari Nahr (penyembelihan hewan kurban)?.\" Kami berkata; \"Ya, benar.\" Lalu beliau bertanya lagi: \"Bulan apakah ini?.\" Mereka menjawab; \"Allah dan Rasul-Nya yang lebih tahu.\" Kemudian beliau terdiam, hingga kami menyangka beliau akan menyebutkan dengan nama yang lain, Beliau lalu bersabda: \"Bukankah ini bulan Dzul Hijjah?.\" Kami pun menjawab; \"Ya, benar.\" Dan beliau bertanya lagi: \"Negeri apakah ini?.\" Mereka menjawab; \"Allah dan Rasul-Nya yang lebih tahu.\" Kemudian beliau terdiam hingga kami menyangka bila beliau akan menyebutkan dengan nama yang lain. Kemudian beliau bersabda: \"Bukankah ini tanah (haram)?.\" Kami menjawab; \"ya.\" Beliau melanjutkan: \"Sesungguhnya darah kalian, harta kalian, -dan aku menyangka beliau bersabda; kehormatan kalian- adalah haram, sebagaimana keharaman hari kalian ini, di bulan kalian ini dan di tanah kalian ini, kalian akan menemui Rabb kalian lalu Dia akan bertanya tentang amalan-amalan kalian, oleh karena itu, ketahuilah… janganlah kalian menjadi sesat sepeninggalku, dengan saling berperang diantara kalian. Ketahuilah, bukankah aku telah menyampaikannya?. Dan hendaklah yang hadir menyampaikan pada yang tidak hadir diantara kalian?. Dan semoga yang menyampaikannya lebih memperhatikan dari orang yang hanya mendengarnya.\" Muhammad berkata; \"Dan waktu itu beliau juga bersabda: \"Sungguh telah ada sebagian yang menyampaikan lebih perhatian daripada yang hanya mendengarkan.\""},"2659":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا ابْنُ جُرَيْجٍ وَابْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ وَأَبُو عَاصِمٍ عَنِ ابْنِ جُرَيْجٍ أَخْبَرَنِي إِسْمَاعِيلُ بْنُ مُحَمَّدِ بْنِ سَعِيدٍ أَنَّهُ أَخْبَرَهُ حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّ السَّائِبَ بْنَ يَزِيدَ أَخْبَرَهُ أَنَّهُ سَمِعَ الْعَلَاءَ بْنَ الْحَضْرَمِيِّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْكُثُ الْمُهَاجِرُ بِمَكَّةَ بَعْدَ قَضَاءِ نُسُكِهِ ثَلَاثًا قَالَ أَبُو عَاصِمٍ ثَلَاثَ لَيَالٍ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah menceritakan kepada kami [Ibnu Juraij] dan [Ibnu Bakr] bahwa [Isma'il bin Muhammad bin Sa'id] telah menceritakan kepadaku bahwa [Humaid bin Abdurrahman bin 'Auf] telah menceritakan kepadanya bahwa [As Sa'ib bin Yazid] telah menceritakan kepadanya bahwa dia mendengar [Al 'Ala` Bin Al Hadlrami] berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Orang-orang muhajirin tinggal di Makkah selama tiga hari setelah menyelesaikan Ibadah haji mereka.\" [Abu 'Ashim] mengatakan; \"Tiga malam.\""},"2660":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حُمَيْدٍ قَالَ سَمِعْتُ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ يَسْأَلُ السَّائِبَ مَا سَمِعْتَ فِي السُّكْنَى بِمَكَّةَ فَقَالَ حَدَّثَنِي الْعَلَاءُ بْنُ الْحَضْرَمِيِّأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْمُهَاجِرِ ثَلَاثًا بَعْدَ الصَّدَرِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abdurrahman bin Humaid] ia berkata; Aku mendengar Umar bin Abdul 'Aziz bertanya pada [Sa`ib]; \"Apa yang pernah kamu dengar tentang menginap di Makkah?\" Sa`ib menjawab; telah menceritakan kepadaku [Al 'Ala` Bin Al Hadlrami] bahwa Nabi Shalallahu 'Alaihi Wasallam bersabda kepada orang-orang Muhajirin yaitu (untuk tinngal) tiga hari tiga malam setelah mengerjakan ibadah haji.\""},"2661":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبِي وَيَحْيَى بْنُ مَعِينٍ قَالَا حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ حَدَّثَنَا أَبُو حَمْزَةَ قَالَ سَمِعْتُ الْمُغِيرَةَ الْأَزْدِيَّ عَنْ مُحَمَّدِ بْنِ زَيْدٍ عَنْ حَيَّانَ الْأَعْرَجِ عَنِ الْعَلَاءِ بْنِ الْحَضْرَمِيِّ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْبَحْرَيْنِ أَوْ أَهْلِ هَجَرَ شَكَّ أَبُو حَمْزَةَ قَالَ وَكُنْتُ آتِي الْحَائِطَ يَكُونُ بَيْنَ الْإِخْوَةِ فَيُسْلِمُ أَحَدُهُمْ فَآخُذُ مِنْ الْمُسْلِمِ الْعُشْرَ وَمِنْ الْآخَرِ الْخَرَاجَ","id":"Telah menceritakan kepada kami Abdullah; telah menceritakan kepadaku ayahku dan [Yahya bin Ma'in], keduanya berkata; telah menceritakan kepada kami ['Attab bin Ziyad], telah menceritakan kepada kami [Abu Hamzah], ia berkata; Aku mendengar [Al Mugirah Al `Azdy] dari [Muhammad bin Zaid] dari [Hayyan Al A'raj] dari [Al 'Ala` Bin Al Hadlrami] dia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam pernah mengutusku ke negeri Bahrain atau penduduk Hajar -Abu Hamzah ragu (mengenai redaksinya) - Al 'Ala` berkata; \"Lalu aku datang ke suatu kebun yang dimiliki oleh beberapa orang bersaudara, lalu salah seorang dari mereka masuk Islam, maka aku mengambil dari seorang muslim sepersepuluh sedangkan dari yang lain sebagai kharaj (pajak).\""},"2662":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا عَوْفٌ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ قَالَ حَدَّثَنِي رَجُلٌ قَالَكُنْتُ ��ِي مَجْلِسٍ فِيهِ عُمَرُ بْنُ الْخَطَّابِ بِالْمَدِينَةِ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ لِرَجُلٍ مِنْ جُلَسَائِهِ كَيْفَ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْإِسْلَامَ بَدَأَ جَذَعًا ثُمَّ ثَنِيًّا ثُمَّ رَبَاعِيًا ثُمَّ سَدَاسِيًّا ثُمَّ بَازِلًا قَالَ فَقَالَ عُمَرُ فَمَا بَعْدَ الْبُزُولِ إِلَّا النُّقْصَانُ","id":"Telah menceritakan kepada kami [Rauh], telah menceritakan kepada kami ['Auf] dari ['Alqamah bin Abdullah Al Muzanni] ia berkata; telah menceritakan padaku [seseorang] ia berkata; Aku pernah bermajlis di Madinah, sedangkan Umar bin Khathab berada di majlis tersebut, lalu Umar radliallahu 'anhu berkata kepada seseorang dari orang yang bermajlis; \"Bagaimana engkau pernah mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda?\" laki-laki itu berkata; Aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Islam berawal mula (ibarat) unta yang berumur enam tahun, tujuh tahun, delapan tahun, kemudian sembilan tahun. Kata Umar, tak ada harapan setelah sembilan tahun kecuali melemah (kurang kekuatannya)."},"2663":{"ar":"حَدَّثَنَا سُرَيْجٌ وَيُونُسُ قَالَا حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ اللَّيْثِيِّ قَالَقَدِمْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ شَبَبَةٌ قَالَ فَأَقَمْنَا عِنْدَهُ نَحْوًا مِنْ عِشْرِينَ لَيْلَةً فَقَالَ لَنَا لَوْ رَجَعْتُمْ إِلَى بِلَادِكُمْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِيمًا فَعَلَّمْتُمُوهُمْ قَالَ سُرَيْجٌ وَأَمَرْتُمُوهُمْ أَنْ يُصَلُّوا صَلَاةَ كَذَا حِينَ كَذَا قَالَ يُونُسُ وَمُرُوهُمْ فَلْيُصَلُّوا صَلَاةَ كَذَا فِي حِينِ كَذَا وَصَلَاةَ كَذَا فِي حِينِ كَذَا فَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah menceritakan kepada kami [Suraij] dan [Yunus] keduanya berkata; telah menceritakan kepada kami [Hammad yaitu Ibnu Zaid], telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Malik bin Huwairits Al Laitsi] ia berkata; \"Kami datang kepada Nabi Shalallahu 'Alaihi Wasallam ketika itu kami masih muda, lalu kami menginap selama dua puluh malam. Lalu beliau bersabda: \"Kalaulah nanti kalian kembali ke negeri kalian -Rasulullah Shallalahu 'Alaihi Wasallam adalah sosok yang belas kasih- maka ajarkanlah kepada kaum kalian.\" [Suraij] mengatakan (dengan tambahan redaksi); \"Dan suruhlah mereka shalat ini di waktu ini, \" Sedangkan [Yunus] mengatakan (dengan redaksi); \"Dan ajarilah mereka shalat ini di waktu ini serta shalat itu di waktu ini, apabila telah datang waktu shalat, maka hendaklah salah seorang dari kalian mengumandangkan adzan dan yang paling tua menjadi imam kalian.\""},"2664":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ وَهُوَ أَبُو سُلَيْمَانَأَنَّهُمْ أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ وَصَاحِبٌ لَهُ أَوْ صَاحِبَانِ لَهُ فَقَالَ أَحَدُهُمَا صَاحِبَيْنِ لَهُ أَيُّوبُ أَوْ خَالِدٌ فَقَالَ لَهُمَا إِذَا حَضَرَتْ الصَّلَاةُ فَأَذِّنَا وَأَقِيمَا وَلْيَؤُمَّكُمَا أَكْبَرُكُمَا وَصَلُّوا كَمَا تَرَوْنِي أُصَلِّي","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Khalid] dari [Abu Qilabah] dari [Malik bin Huwairits yaitu Abu Sulaiman] bahwa mereka datang menemui Nabi Shalallahu 'Alaihi Wasallam, ketika itu disamping beliau ada seorang sahabat, -atau dua orang sahabat, lalu salah satu dari keduanya berkata -Ayyub atau Khalid-, lalu beliau bersabda kepada keduanya: \"Apabila datang waktu shalat, maka kumandangkanlah, dan dirikanlah shalat, hendaklah orang yang lebih tua diantara kalian menjadi imam, lalu shalatlah kalian sebagaimana kalian melihat aku shalat.\""},"2665":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنَا قَتَادَةُ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ إِذَا دَخَلَ فِي الصَّلَاةِ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ إِلَى أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah], telah menceritakan kepada kami [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwairits] -ia termasuk dari sahabat Nabi Shalallahu 'Alaihi Wasallam- katanya; Nabi Shalallahu 'Alaihi Wasallam mengangkat tangannya ketika memulai shalat, ruku' dan saat mengangkat kepala (`I'tidal) dari ruku', hingga kedua telinganya.\""},"2666":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ الْعُقَيْلِيِّ عَنْ رَجُلٍ مِنْهُمْ يُكَنَّى أَبَا عَطِيَّةَ قَالَ كَانَ مَالِكُ بْنُ الْحُوَيْرِثِيَأْتِينَا فِي مُصَلَّانَا يَتَحَدَّثُ قَالَ فَحَضَرَتْ الصَّلَاةُ يَوْمًا فَقُلْنَا تَقَدَّمْ فَقَالَ لَا لِيَتَقَدَّمْ بَعْضُكُمْ حَتَّى أُحَدِّثَكُمْ لِمَ لَا أَتَقَدَّمُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مَنْ زَارَ قَوْمًا فَلَا يَؤُمَّهُمْ وَلْيَؤُمَّهُمْ رَجُلٌ مِنْهُمْحَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَاه إِبْرَاهِيمُ بْنُ الْحَجَّاجِ وَمُحَمَّدُ بْنُ أَبَانَ الْوَاسِطِيُّ قَالَا حَدَّثَنَا أَبَانُ حَدَّثَنَا بُدَيْلٌ مِثْلَهُ حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا أَبَانُ بْنُ يَزِيدَ الْعَطَّارُ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ حَدَّثَنِي أَبُو عَطِيَّةَ مَوْلًى لَنَا قَالَ كَانَ مَالِكُ بْنُ الْحُوَيْرِثِ يَأْتِينَا فِي مُصَلَّانَا فَذَكَرَ الْحَدِيثَ يَعْنِي حَدِيثَ أَبِي","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Aban bin Yazid] dari [Budail bin Maisarah Al 'Uqaili] dari seseorang yang biasa dijuluki dengan [Abu 'Athiyyah] ia berkata; Suatu ketika [Malik bin Huwairits] datang dan bercerita kepada kami di mushalla, lalu tibalah waktu shalat, kami pun berkata; \"Majulah (untuk jadi imam)!.\" ia berkata; \"Tidak, jadilah imam salah seorang diantara kalian, hingga aku akan ceritakan satu hadits yang menyebabkan aku tidak maju untuk mengimami, saya mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Barangsiapa berziarah pada suatu kaum, maka janganlah ia menjadi imam dan tunjuklah salah seorang dari kaum tersebut menjadi imam.\" Telah menceritakan kepada kami Abdullah, ia berkata; telah menceritakan kepada kami [Ibrahimm bin Hajjaj] dan [Muhammad bin Aban Al Washiti], keduanya berkata; telah menceritakan kepada kami [Aban], telah menceritakan kepada kami [Budail] seperti hadits diatas. Dan telah menceritakan kepada kami [Yazid], ia berkata; telah mengabarkan kepada kami [Aban bin Yazid Al 'Athar] dari [Budail bin Maisarah], telah menceritakan kepadaku [Abu 'Athiyyah] bekas budak kami, ia berkata; \"Suatu ketika [Malik bin Huwairits] mendatangi kami di mushala…\" lalu ia ceritakan hadits tersebut yaitu hadits dari ayahku.\""},"2667":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَأَبُو عَامِرٍ قَالَا حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا كَبَّرَ رَفَعَ يَدَيْهِ حَتَّى يَجْعَلَهُمَا قَرِيبًا مِنْ أُذُنَيْهِ وَإِذَا رَكَعَ صَنَعَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Abdushamad] dan [Abu Amir] keduanya berkata; telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Huwairits] bahwa apabila Rasulullah Shallalahu 'Alaihi Wasallam bertakbir, beliau mengangkat kedua tangannya hingga mendekati kedua telinganya, apabila ruku, serta ketika bangkit dari ruku'.\""},"2668":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ فِي الصَّلَاةِ رَفَعَ يَدَيْهِ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ حَتَّى حَاذَتَا فُرُوعَ أُذُنَيْهِ","id":"Telah menceritakan kepada kami [Isma'il] dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Huwairits] ia berkata; \"Aku melihat Rasulullah Shallalahu 'Alaihi Wasallam mengangkat kedua tangannya ketika memulai shalat, ketika ruku dan bangkit dari ruku' hingga sejajar dengan kedua daun telinga beliau.\""},"2669":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْفَعُ يَدَيْهِ حِيَالَ فُرُوعِ أُذُنَيْهِ فِي الرُّكُوعِ وَالسُّجُودِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Huwairits] bahwa Nabi Shalallahu 'Alaihi Wasallam mengangkat kedua tangan sejajar dengan kedua telinganya, demikian juga ketika hendak ruku' dan sujud.\""},"2670":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ الْعَطَّارُ حَدَّثَنَا بُدَيْلُ بْنُ مَيْسَرَةَ حَدَّثَنَا أَبُو عَطِيَّةَ مَوْلًى مِنَّا عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَكَانَ يَأْتِينَا فِي مُصَلَّانَا فَلَمَّا أُقِيمَتْ الصَّلَاةُ قِيلَ لَهُ تَقَدَّمْ فَصَلِّهْ قَالَ لِيُصَلِّ بَعْضُكُمْ حَتَّى أُحَدِّثَكُمْ لِمَ لَا أُصَلِّي بِكُمْ فَلَمَّا صَلَّى الْقَوْمُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا زَارَ أَحَدُكُمْ قَوْمًا فَلَا يُصَلِّيَنَّ بِهِمْ يُصَلِّي بِهِمْ رَجُلٌ مِنْهُمْ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Abaan bin Athar], telah menceritakan kepada kami [Budail bin Maisarah], telah menceritakan kepada kami [Abu 'Athiyah] bekas budak kami, dari [Malik bin Al Huwairits] ia berkata; bahwa ia pernah datang ke mushala kami, ketika iqamah telah di kumandangkan, dikatakan padanya; \"Silahkan maju untuk mengimami shalat kami!.\" Malik berkata; \"Suruhlah di antara kalian menjadi imam shalat, akan aku ceritakan satu hadits yang menyebabkan aku tidak mau menjadi imam shalat kalian.\" Seusai orang-orang mengerjakan shalat, ia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Barangsiapa berziarah pada suatu kaum, hendaknya ia tidak menjadi imam dan suruhlah salah seorang dari kalian menjadi imam.\""},"2671":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ اللَّيْثِيِّ أَنَّهُقَالَ لِأَصْحَابِهِ يَوْمًا أَلَا أُرِيكُمْ كَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَذَلِكَ فِي غَيْرِ حِينِ صَلَاةٍ فَقَامَ فَأَمْكَنَ الْقِيَامَ ثُمَّ رَكَعَ فَأَمْكَنَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ وَانْتَصَبَ قَائِمًا هُنَيَّةً ثُمَّ سَجَدَ ثُمَّ رَفَعَ رَأْسَهُ وَيُكَبِّرُ فِي الْجُلُوسِ ثُمَّ انْتَظَرَ هُنَيَّةً ثُمَّ سَجَدَقَالَ أَبُو قِلَابَةَ فَصَلَّى صَلَاةً كَصَلَاةِ شَيْخِنَا هَذَا يَعْنِي عَمْرَو بْنَ سَلِمَةَ الْجَرْمِيَّ وَكَانَ يَؤُمُّ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّوبُ فَرَأَيْتُ عَمْرَو بْنَ سَلِمَةَ يَصْنَعُ شَيْئًا لَا أَرَاكُمْ تَصْنَعُونَهُ كَانَ إِذَا رَفَعَ رَأْسَهُ مِنْ السَّجْدَتَيْنِ اسْتَوَى قَاعِدًا ثُمَّ قَامَ مِنْ الرَّكْعَةِ الْأُولَى وَالثَّانِيَةِ","id":"Telah menceritakan kepada kami [Yunus], telah menceritakan kepada kami [Hammad yaitu Ibnu Zaid], telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Malik bin Al Huwairits Al Laitsi] bahwa suatu hari ia pernah berkata kepada para sahabatnya; \"Maukah kalian aku perlihatkan bagaimana shalat Rasulullah Shallalahu 'Alaihi Wasallam?.\" Abu Qilabah berkata; \"Ketika itu bukan di waktu shalat, \" lalu Malik berdiri dan memantapkan berdirinya lalu ruku' dan hingga benar-benar ruku' lalu mangangkat kepalanya dan tegak berdiri dengan tenang kemudian sujud, lalu mengangkat kepalanya seraya bertakbir di waktu duduk kemudian bersimpuh dengan tenang lalu sujud kembali.\" [Abu Qilabah] berkata; \"Lalu Malik bin AL Huwairits mempraktekkan shalat sebagaimana shalatnya guru kami ini yaitu [Amru bin Salamah Al Jarmi] dan ia telah menjadi imam di masa Nabi Shalallahu 'Alaihi Wasallam, [Ayyub] berkata; \"Lalu aku melihat [Amru bin Salimah] mengerjakan sesuatau yang aku tidak melihat kalian mengerjakannya, yaitu apabila ia mengangkat kepalanya dari dua sujud, ia duduk dengan simbang lalu berdiri di raka'at pertama dan kedua.\""},"2672":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ وَمُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَتَادَةُ عَنْ عُقْبَةَ بْنِ صُهْبَانَ عَنِ ابْنِ مُغَفَّلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْخَذْفِ وَقَالَ إِنَّهُ لَا يَنْكَأُ عَدُوًّا وَلَا يَصِيدُ وَلَكِنَّهُ يَكْسِرُ السِّنَّ وَيَفْقَأُ الْعَيْنَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] -dari [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] - telah menceritakan kepada kami [Qatadah] dari [Uqbah bin Shuhban] dari [Ibnu Mughaffal] bahwa Rasulullah Shallalahu 'Alaihi Wasallam melarang 'khadzaf.' Ibnu Mughaffal berkata; \"Karena khadzaf tidak akan mengalahkan musuh atau memburunya, akan tetapi hanya mematahkan gigi dan membutakan mata.' "},"2673":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ أَبِي سُفْيَانَ بْنِ الْعَلَاءِ عَنِ الْحَسَنِ عَنِ ابْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرَتْ الصَّلَاةُ وَأَنْتُمْ فِي مَرَابِضِ الْغَنَمِ فَصَلُّوا وَإِذَا حَضَرَتْ وَأَنْتُمْ فِي أَعْطَانِ الْإِبِلِ فَلَا تُصَلُّوا فَإِنَّهَا خُلِقَتْ مِنْ الشَّيَاطِينِ","id":"Telah menceritakan kepada kami [Waki'] dari [Abu Sufyan bin 'Ala`] dari [Al Hasan] dari [Ibnu Mughaffal] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Apabila datang waktu shalat, sementara kalian berada di kandang kambing, maka shalatlah kalian. Apabila telah tiba waktu shalat, sementara kalian berada di kandang unta, maka janganlah kalian shalat (di tempat tersebut), karena ia diciptakan dari setan.\""},"2674":{"ar":"حَدَّثَنَا وَكِيعٌ وَابْنُ جَعْفَرٍ قَالَا ثَنَا كَهْمَسُ بْنُ الْحَسَنِ عَنِ ابْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ ثَلَاثَ مَرَّاتٍ لِمَنْ شَاءَ","id":"Telah menceritakan kepada kami [Waki'] dan [Ibnu Ja'far] keduanya berkata; telah menceritakan kepada kami [Kahmas bin Hasan] dari [Ibnu Buraidah] dari [Abdullah bin Mughaffal] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Di antara dua adzan ada shalat -beliau mengucapkan hingga tiga kali- bagi yang menghendakinya.\""},"2675":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُثْمَانَ بْنِ غِيَاثٍ حَدَّثَنِي أَبُو نَعَامَةَ عَنِ ابْنِ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَكَانَ أَبُونَا إِذَا سَمِعَ أَحَدًا مِنَّا يَقُولُ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ يَقُولُ إِهِي إِهِي صَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ فَلَمْ أَسْمَعْ أَحَدًا مِنْهُمْ يَقُولُ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Utsman bin Ghiyats]; telah menceritakan kepadaku [Abu Na'amah] dari [Ibnu Abdullah bin Al Mughaffal] dia berkata; \"Apabila [ayah kami] mendengar salah seorang dari kami membaca \"BISMILLAAHIR RAHMAANIR RAHIIM, \" dia berkata; \"ihi…ihi…, aku telah shalat di belakang Rasulullah Shallalahu 'Alaihi Wasallam, Abu Bakar dan Umar, namun aku tidak mendengar dari seorangpun dari mereka yang membaca \"BISMILLAAHIR RAHMAANIR RAHIIM.\""},"2676":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ أَبِي جَعْفَرٍ الرَّازِيِّ عَنِ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ أَوْ عَنْ غَيْرِهِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ وَكَانَ أَحَدَ الرَّهْطِ الَّذِينَ نَزَلَتْ فِيهِمْ هَذِهِ الْآيَةُ{ وَلَا عَلَى الَّذِينَ إِذَا مَا أَتَوْكَ لِتَحْمِلَهُمْ }إِلَى آخِرِ الْآيَةِ قَالَإِنِّي لَآخِذٌ بِغُصْنٍ مِنْ أَغْصَانِ الشَّجَرَةِ أُظِلُّ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ يُبَايِعُونَهُ فَقَالُوا نُبَايِعُكَ عَلَى الْمَوْتِ قَالَ لَا وَلَكِنْ لَا تَفِرُّوا","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Rabi' bin Anas] dari [Abu 'Aliyah] atau yang lain dari [Abdullah bin Mughaffal] -dia adalah salah seorang yang diturunkan ayat ini kepada mereka, yaitu; \"WALAA 'ALAL LADZIINA IDZA MAA ATAUKA LITAHMILAHUM (Dan tiada pula berdosa atas orang-orang yang apabila mereka datang kepadamu, supaya kamu memberi mereka kendaraan).\" (QS At Taubah: 92) sampai akhir ayat, Abdullah bin Mughaffal berkata; \"Sesungguhnya aku pernah mengambil dahan pohon untuk kujadikan tempat naungan Nabi shallallahu 'alaihi wasallam dan para sahabat ketika mereka berbai'at kepada beliau, lalu mereka berkata; \"Apakah kami berbai'at kepadamu untuk mati.\" beliau bersabda: \"Akan tetapi (berbai'atlah) untuk tidak lari.\""},"2677":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ أَبِي سُفْيَانَ بْنِ الْعَلَاءِ قَالَ سَمِعْتُ الْحَسَنَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنَّ الْكِلَابَ أُمَّةٌ مِنْ الْأُمَمِ لَأَمَرْتُ بِقَتْلِهَا فَاقْتُلُوا مِنْهَا كُلَّ أَسْوَدَ بَهِيمٍ قَالَ فَقَالَ لَهُ رَجُلٌ يَا أَبَا سَعِيدٍ مِمَّنْ سَمِعْتَ هَذَا قَالَ فَقَالَ حَدَّثَنِيهِ وَحَلَفَ عَبْدُ اللَّهِ بْنُ مُغَفَّلٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنْذُ كَذَا وَكَذَا وَلَقَدْ حَدَّثَنَا فِي ذَلِكَ الْمَجْلِسِ","id":"Telah menceritakan kepada kami [Waki'] dari [Abu Sufyan bin 'Ala`] ia berkata; \"aku mendengar [Al Hasan] menceritakan bahwa Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Kalau sekiranya anjing-anjing itu bukan termasuk dari golongan umat (dari hewan), tentulah aku perintahkan kalian membunuhnya, oleh karena itu bunuhlah yang berwarna hitam legam.\" Sufyan berkata; \"lalu seseorang bertanya kepada Al Hasan; \"Wahai Abu Sa'id, dari siapakah kalian mendengar hadits ini? Ceritakanlah padaku!.\" Lalu [Abdullah bin Mughaffal] bersumpah bahwa itu dari Nabi Shalallahu 'Alaihi Wasallam sejak sekian dan sekian, sungguh dua telah menceritakan kepada kami di majelis itu.\""},"2678":{"ar":"حَدَّثَنَا سَعْدُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا عَبِيدَةُ بْنُ أَبِي رَائِطَةَ الْحَذَّاءُ التَّمِيمِيُّ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ زِيَادٍ أَوْ عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهَ اللَّهَ فِي أَصْحَابِي اللَّهَ اللَّهَ فِي أَصْحَابِي لَا تَتَّخِذُوهُمْ غَرَضًا بَعْدِي فَمَنْ أَحَبَّهُمْ فَبِحُبِّي أَحَبَّهُمْ وَمَنْ أَبْغَضَهُمْ فَبِبُغْضِي أَبْغَضَهُمْ وَمَنْ آذَاهُمْ فَقَدْ آذَانِي وَمَنْ آذَانِي فَقَدْ آذَى اللَّهَ تَبَارَكَ وَتَعَالَى وَمَنْ آذَى اللَّهَ فَيُوشِكُ أَنْ يَأْخُذَهُحَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَوْنٍ الْخَرَّازُ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ عَبِيدَةَ بْنِ أَبِي رَائِطَةَ بِمِثْلِ هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Sa'ad bin Ibrahim bin Sa'ad], telah menceritakan kepada kami ['Abidah bin Abu Ra`ithah Al Hadza` At Tamimi], ia berkata; telah menceritakan kepadaku [Abdurrahman bin Ziyad] atau Abdurrahman bin Abdullah dari [Abdullah bin Mughaffal Al Muzani] dia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Takutlah kepada Allah terhadap para sahabatku, takutlah kepada Allah terhadap para sahabatku, janganlah kalian menjadikan mereka sebagai sasaran (cacian dan cercaan) sepeninggalku, barangsiapa mencintai mereka maka dengan kecintaanku aku pun mencintai mereka (yang mencintai sahabat), dan barangsiapa membenci mereka, maka dengan kebencianku aku pun membenci mereka (orang yang membenci para sahabat), dan barangsiapaa menyakiti mereka berarti dia telah menyakitiku dan barangsiapa yang menyakitiku berarti dia telah menyakiti Allah Tabaraka Wata'ala, dan barangsiapa menyakiti Allah, maka hampir saja Allah menyiksanya.\" Telah menceritakan kepada kami [Abdullah bin 'Aun Al Kharraz] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari ['Abidah bin Abu Ra`ithah] seperti hadits di atas.\""},"2679":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنِي أَبِي وَحَدَّثَنَا حَسَنٌ وَعَفَّانُ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا حُسَيْنٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ الْمُزَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلُّوا قَبْلَ الْمَغْرِبِ رَكْعَتَيْنِ ثُمَّ قَالَ صَلُّوا قَبْلَ الْمَغْرِبِ رَكْعَتَيْنِ ثُمَّ قَالَ عِنْدَ الثَّالِثَةِ لِمَنْ شَاءَ كَرَاهِيَةَ أَنْ يَتَّخِذَهَا النَّاسُ سُنَّةً","id":"Telah menceritakan kepada kami [Abdussamad], telah menceritakan kepadaku [Ayahku] dan telah menceritakan kepada kami [Al Hasan] dan [Affan], telah menceritakan kepada kami [Abdul Warits], telah menceritakan kepada kami [Husain], telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Abdullah Al Muzani] bahwa Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Laksanakanlah shalat (sunnah) dua raka'at sebelum Maghrib.\" kemudian beliau bersabda: \"Laksanakanlah shalat (sunnah) dua raka'at sebelum Maghrib.\" Kemudian yang ketiga kalinya beliau bersabda: \"Bagi siapa yang berkendak.\" Karena dikhawatir orang-orang menganggap sebagai kebiasaan.\""},"2680":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنِي أَبِي حَدَّثَنَا حُسَيْنٌ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ حَدَّثَنِي عَبْدُ اللَّهِ الْمُزَنِيُّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَغْلِبَنَّكُمْ الْأَعْرَابُ عَلَى اسْمِ صَلَاةِ الْمَغْرِبِقَالَ وَتَقُولُ الْأَعْرَابُ هِيَ الْعِشَاءُ","id":"Telah menceritakan kepada kami [Abdussamad], telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al Husain] dari [Abdullah bin Buraidah] telah menceritakan kepadaku [Abdullah Al Muzani] bahwa Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Janganlah kalian terkecoh dengan orang-orang badui ketika menyebut shalat Maghrib, \" Perawi berkata; orang-orang badui biasa menyebutnya dengan shalat Isya'.\""},"2681":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَعَفَّانُ قَالَا ثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنِ الْجُرَيْرِيِّ وَقَالَ عَفَّانُ فِي حَدِيثِهِ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ أَبِي نَعَامَةَأَنَّ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ سَمِعَ ابْنَهُ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ الْقَصْرَ الْأَبْيَضَ عَنْ يَمِينِ الْجَنَّةِ إِذَا دَخَلْتُهَا فَقَالَ يَا بُنَيَّ سَلْ اللَّهَ تَبَارَكَ وَتَعَالَى الْجَنَّةَ وَعُذْ بِهِ مِنْ النَّارِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكُونُ قَوْمٌ يَعْتَدُونَ فِي الدُّعَاءِ وَالطَّهُورِ","id":"Telah menceritakan kepada kami [Abdussamad] dan ['Affan] keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Al Jurairi], - ['Affan] berkata dalam haditsnya; telah mengabarkan kepadaku [Al Jurairi] - dari [Abu Na'amah] bahwa [Abdullah bin Mughaffal] mendengar anaknya berkata; 'ALLAHUMMA INNI AS`ALUKA QASHRA' ABYADH 'AN YAMINIL JANNAH, IDZA DAKHALTUHA (Ya Allah aku bermohon istana putih dari sisi kanan surga bila aku memasukinya).' Lalu ia berkata pada anaknya; 'Wahai anakkku, mintalah pada Allah Tabaraka Wa Ta'ala surga dan berlindunglah pada-Nya dari neraka, karena aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Akan ada suatu kaum yang berlebihan dalam do'a dan bersuci.'"},"2682":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ أَبِي عُمَيْرِ بْنِ أَنَسٍ عَنْ عُمُومَتِهِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُجَاءَ رَكْبٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَهِدُوا أَنَّهُمْ رَأَوْهُ بِالْأَمْسِ يَعْنُونَ الْهِلَالَ فَأَمَرَهُمْ أَنْ يُفْطِرُوا وَأَنْ يَخْرُجُوا مِنْ الْغَدِقَالَ شُعْبَةُ أُرَاهُ مِنْ آخِرِ النَّهَارِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Abu Umair bin Anas] dari [kebanyakan para sahabat Nabi] shallallahu 'alaihi wasallam, bahwa serombongan orang datang kepada Nabi shallallahu 'alaihi wasallam, kemudian mereka bersaksi bahwa mereka kemarin melihat yaitu melihat hilal (bulan sabit), lalu beliau menyuruh orang-orang untuk berbuka dan agar besoknya mereka keluar (untuk shalat ied).\" Syu'bah berkata; \"Aku mengiranya di akhir siang.\""},"2683":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ أَبِي عُمَيْرِ بْنِ أَنَسٍ عَنْ عُمُومَةٍ لَهُ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَشْهَدُهُمَا مُنَافِقٌ يَعْنِي صَلَاةَ الصُّبْحِ وَالْعِشَاءِقَالَ أَبُو بِشْرٍ يَعْنِي لَا يُوَاظِبُ عَلَيْهِمَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Abu Umair bin Anas] dari [beberapa sahabat Nabi] shallallahu 'alaihi wasallam dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Orang munafiq tidak akan menghadiri keduanya yaitu shalat Shubuh dan Isya'.\" [Abu Bisyr] berkata (dengan redaksi); \"Tidak membiasakan keduanya.\""},"2684":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَا أَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَلَّامِ بْنِ عَمْرٍو عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِخْوَانُكُمْ فَأَحْسِنُوا إِلَيْهِمْ أَوْ فَأَصْلِحُوا إِلَيْهِمْ وَاسْتَعِينُوهُمْ عَلَى مَا غَلَبَكُمْ وَأَعِينُوهُمْ عَلَى مَا غَلَبَهُمْ قَالَ حَجَّاجٌ فِي حَدِيثِهِ قَالَ سَمِعْتُ سَلَّامَ بْنَ عَمْرٍو وَرَجُلًا مِنْ قَوْمِهِ وَقَالَ حَجَّاجٌ وَأَصْلِحُوا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] -dan [Hajjaj]; keduanya berkata; telah menceritakan kepada kami [Syu'bah] - dari [Abu Bisyr] dari [Sallam bin 'Amr] dari [salah seorang sahabat Nabi] shallallahu 'alaihi wasallam dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Berbuat baiklah kalian terhadap saudara-saudara kalian, atau perbaikilah (hubungan) kepada mereka dan bantulah mereka atas sesuatu yang kalian mampu dan bantulah mereka terhadap sesuatu yang menimpa mereka.\" [Hajjaj] berkata dalam haditsnya; \"Aku mendengar [Sallam bin Amr] dan [salah seorang] dari kaumnya, dan [Hajjaj] mengatakan; \"Dan perbaikilah (hubungan).\""},"2685":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ مَطَرٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ رَجُلٍ مِنَ الْأَنْصَارِأَنَّ رَجُلًا أَوْطَأَ بَعِيرَهُ أُدْحِيَّ نَعَامٍ وَهُوَ مُحْرِمٌ فَكَسَرَ بَيْضَهَا فَانْطَلَقَ إِلَى عَلِيٍّ رَضِيَ اللَّهُ تَعَالَى عَنْهُ فَسَأَلَه�� عَنْ ذَلِكَ فَقَالَ لَهُ عَلِيٌّ عَلَيْكَ بِكُلِّ بَيْضَةٍ جَنِينُ نَاقَةٍ أَوْ ضِرَابُ نَاقَةٍ فَانْطَلَقَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ عَلِيٌّ بِمَا سَمِعْتَ وَلَكِنْ هَلُمَّ إِلَى الرُّخْصَةِ عَلَيْكَ بِكُلِّ بَيْضَةٍ صَوْمٌ أَوْ إِطْعَامُ مِسْكِينٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Sa'id] dari [Mathar] dari [Mu'awiyah bin Qurrah] dari [seorang laki-laki dari Anshar] bahwa seorang lelaki yang menderumkan untanya di tempat yang biasa di gunakan binatang bertelur, sementara dia dalam keadaan ihram, tanpa sengaja dia memecahakan telur binatang, kemudian dia pergi menemui Ali radliallahu 'anhu dan menanyakannya tentang hal itu, lalu Ali menjawab; \"Kamu harus mengganti setiap telur dengan satu janin unta atau anak unta, kemudian dia pergi menemui Rasulullah Shallalahu 'Alaihi Wasallam dan menceritakan hal itu, lalu Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Ali telah menjawab sebagaimana yang telah kamu dengar, akan tetapi kemarilah untuk meringankanmu, kamu harus menggantinya setiap telur dengan berpuasa atau memberi makan orang miskin.\""},"2686":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَوْفٌ عَنْ حَسْنَاءَ امْرَأَةٍ مِنْ بَنِي صُرَيْمٍ عَنْ عَمِّهَا قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ النَّبِيُّ فِي الْجَنَّةِ وَالشَّهِيدُ فِي الْجَنَّةِ وَالْمَوْلُودُ فِي الْجَنَّةِ وَالْوَئِيدُ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami ['Auf] dari [Hasna`] salah seorang wanita dari Bani Shuraim dari [Pamannya] dia berkata; aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Para Nabi akan berada di Syurga, orang yang mati Syahid akan berada di syurga, bayi yang lahir akan berada di Syurga dan orang orang yang dikubur hidup-hidup akan berada di Syurga.\""},"2687":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ أَبِي عُمَيْرِ بْنِ أَنَسٍ حَدَّثَنِي عُمُومَةٌ لِي مِنَ الْأَنْصَارِ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَغُمَّ عَلَيْنَا هِلَالُ شَوَّالٍ فَأَصْبَحْنَا صِيَامًا فَجَاءَ رَكْبٌ مِنْ آخِرِ النَّهَارِ فَشَهِدُوا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ رَأَوْا الْهِلَالَ بِالْأَمْسِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُفْطِرُوا مِنْ يَوْمِهِمْ وَأَنْ يَخْرُجُوا لِعِيدِهِمْ مِنْ الْغَدِ","id":"Telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Abu Bisyr] dari [Abu Umair bin Anas], telah menceritakan kepadaku [kebanyakan para sahabat Anshar] dari sahabat Rasulullah Shallalahu 'Alaihi Wasallam bahwa ia berkata; \"Hilal bulan Syawal telah tertutup awan, maka kami pun berpuasa, lalu seorang pengendara di akhir siang datang sambil bersaksi dihadapan Rasulullah Shallalahu 'Alaihi Wasallam bahwa kemarin mereka telah menyaksikan hilal, kemudian Rasulullah Shallalahu 'Alaihi Wasallam menyuruh orang-orang berbuka di hari itu, dan agar di esok hari mereka keluar untuk berhari raya.\""},"2688":{"ar":"حَدَّثَنَا إِسْحَاقُ يَعْنِي الْأَزْرَقَ أَخْبَرَنَا عَوْفٌ حَدَّثَتْنِي حَسْنَاءُ ابْنَةُ مُعَاوِيَةَ الصُّرَيْمِيَّةُ عَنْ عَمِّهَا قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ فِي الْجَنَّةِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّبِيُّ فِي الْجَنَّةِ وَالشَّهِيدُ فِي الْجَنَّةِ وَالْمَوْلُودُ فِي الْجَنَّةِ وَالْمَوْءُودَةُ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Ishaq yaitu Al `Azraq], telah mengabarkan kepada kami ['Auf], telah menceritakan kepadaku [Hasna` binti Mu'awiyah Ash Shuraimiyyah] dari [Pamannya] ia berkata; Aku berkata; \"Wahai RAsulullah, siapa saja yang berada di surga?.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Para Nabi akan berada di Syurga, orang yang mati Syahid akan berada di syurga, bayi yang lahir akan berada di Syurga dan orang orang yang dikubur hidup-hidup akan berada di Syurga.\""},"2689":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ إِسْحَاقَ بْنَ سُوَيْدٍ قَالَ سَمِعْتُ مُطَرِّفَ بْنَ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ يُحَدِّثُ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ بِالْكُوفَةِ أَمِيرٌ قَالَ فَخَطَبَ يَوْمًا فَقَالَ إِنَّ فِي إِعْطَاءِ هَذَا الْمَالِ فِتْنَةً وَفِي إِمْسَاكِهِ فِتْنَةً وَبِذَلِكَ قَامَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خُطْبَتِهِ حَتَّى فَرَغَ ثُمَّ نَزَلَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] ia berkata; aku mendengar [Ishaq bin Suwaid] berkata; Aku mendengar [Mutharrif bin Abdullah bin Syikhkhir] bercerita dari [salah seorang sahabat Nabi] shallallahu 'alaihi wasallam, dia berkata; \"Dahulu di Kufah ada seorang gubernur, dia melanjutkan; \"Pada suatu hari, gubernur itu berkhutbah dan berkata; \"Sesungguhnya pada pemberian harta ini adalah fitnah (ujian) dan menyimpannya juga fitnah, oleh karena itulah Nabi shallallahu 'alaihi wasallam berdiri dalam khutbahnya, sehingga beliau selesai dan turun dari mimbar.\""},"2690":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ حُمَيْدَ بْنَ هِلَالٍ يُحَدِّثُ عَنْ مُطَرِّفٍ عَنْ أَعْرَابِيٍّ أَنَّهُرَأَى عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعْلَيْنِ مَخْصُوفَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] ia berkata; Aku mendengar [Humaid bin Hilal] bercerita dari [Mutharrif] dari [seorang badui] bahwa ia melihat Nabi Shalallahu 'Alaihi Wasallam memakai sandal yang ditambal (dijahit).\""},"2691":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عُثْمَانُ بْنُ غِيَاثٍ قَالَ سَمِعْتُ أَبَا السَّلِيلِ قَالَكَانَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُ النَّاسَ حَتَّى يُكْثَرَ عَلَيْهِ فَيَصْعَدَ عَلَى ظَهْرِ بَيْتٍ فَيُحَدِّثَ النَّاسَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ آيَةٍ فِي الْقُرْآنِ أَعْظَمُ قَالَ فَقَالَ رَجُلٌ{ اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ فَوَضَعَ يَدَهُ بَيْنَ كَتِفَيَّ قَالَ فَوَجَدْتُ بَرْدَهَا بَيْنَ ثَدْيَيَّ أَوْ قَالَ فَوَضَعَ يَدَهُ بَيْنَ ثَدْيَيَّ فَوَجَدْتُ بَرْدَهَا بَيْنَ كَتِفَيَّ قَالَ يَهْنِكَ يَا أَبَا الْمُنْذِرِ الْعِلْمَ الْعِلْمَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Utsman bin Ghiyats], dia berkata; aku mendengar [Abu As Salil] berkata; [Salah seorang sahabat Nabi] shallallahu 'alaihi wasallam menyampaikan hadits kepada khalayak sehingga orang-orang banyak berkumpul disekitarnya, kemudian dia naik ke atap rumah dan menyampaikan hadits kepada orang-orang, dia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Ayat apakah yang paling agung dalam Al Qur'an?.\" Sahabat Nabi itu berkata; \"kemudian salah seorang lelaki menjawab: \"Allaahu laa ilaaha illaa huwal hayyul qoyyuum\" dia berkata lagi; \"lalu beliau meletakkan tangannya di antara kedua bahuku, dia berkata; \"Maka aku rasakan dingin di antara kedua dadaku.\" atau dia berkata; \"Lalu dia meletakkan tangannya di antara dadaku, maka aku merasakan dinginnya di antara kedua bahuku, \" lalu beliau bersabda; \"Berbahagialah kamu wahai [Abul Mundzir], itulah ilmu, itulah ilmu.\""},"2692":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا ابْنُ عَوْنٍ حَدَّثَنَا رَجُلٌ مِنْ أَهْلِ الْبَادِيَةِ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ حَجَّ مَعَ ذِي قَرَابَةٍ لَهُ مُقْتَرِنًا بِهِ فَرَآهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا هَذَا قَالَ إِنَّهُ نَذْرٌ فَأَمَرَ بِالْقِرَانِ أَنْ يُقْطَعَ","id":"Telah menceritakan kepada kami [Husyaim] telah menceritakan kepada kami [Ibnu 'Aun] telah menceritakan kepada kami [seorang lelaki] dari penduduk dusun dari [Ayahnya] dari [Kakeknya] bahwa dia pernah melaksanakan haji diiringi dengan kerabatnya, lalu Nabi shallallahu 'alaihi wasallam melihatnya dan beliau bertanya: \"Ada apa ini?\" dia menjawab; \"Ini adalah Nadzar, \" kemudian beliau memerintahkan untuk memutuskan (memulangkan) orang yang menyertainya.\""},"2693":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ وَعَبْدَةُ قَالَا ثَنَا عَاصِمٌ عَنْ أَبِي الْعَالِيَةِ قَالَ حَدَّثَنِي مَنْ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُأَعْطُوا كُلَّ سُورَةٍ حَظَّهَا مِنْ الرُّكُوعِ وَالسُّجُودِ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] dan ['Abdah], keduanya berkata; telah menceritakan kepada kami ['Ashim] dari [Abu 'Aliyah] dia berkata; telah menceritakan kepadaku [orang yang mendengar Nabi] shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Berikanlah setiap surat haknya dari Ruku' dan sujud.\""},"2694":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ عَاصِمٍ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَمَّنْ كَانَ رَدِيفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكُنْتُ رَدِيفَهُ عَلَى حِمَارٍ فَعَثَرَ الْحِمَارُ فَقُلْتُ تَعِسَ الشَّيْطَانُ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُلْ تَعِسَ الشَّيْطَانُ فَإِنَّكَ إِذَا قُلْتَ تَعِسَ الشَّيْطَانُ تَعَاظَمَ الشَّيْطَانُ فِي نَفْسِهِ وَقَالَ صَرَعْتُهُ بِقُوَّتِي فَإِذَا قُلْتَ بِسْمِ اللَّهِ تَصَاغَرَتْ إِلَيْهِ نَفْسُهُ حَتَّى يَكُونَ أَصْغَرَ مِنْ ذُبَابٍ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah menceritakan kepada kami [Ma'mar] dari ['Ashim] dari [Abu Tamimah Al Hujaimi] dari [orang yang pernah membonceng Nabi] shallallahu 'alaihi wasallam dia berkata; \"Aku pernah memboncengkan beliau menunggang keledai, kemudian keledai itu tergelincir, maka aku berkata; \"Celakalah syetan, \" Kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Janganlah kamu katakan celakalah syetan, karena jika kamu mengatakan celakalah syetan, maka syetan akan membanggakan dirinya. Syetan berkata; \"Aku telah melawannya dengan kekuatanku, \" dan jika kamu membaca BISMILLAAH maka syetan akan merasa dirinya kecil hingga lebih kecil dari seekor lalat.\""},"2695":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ قَالَ سَمِعْتُ أَبَا تَمِيمَةَ يُحَدِّثُ عَنْ رَدِيفِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شُعْبَةُ قَالَ عَاصِمٌ عَنْ أَبِي تَمِيمَةَ عَنْ رَجُلٍ عَنْ رَدِيفِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَعَثَرَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِمَارُهُ فَقُلْتُ تَعِسَ الشَّيْطَانُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُلْ تَعِسَ الشَّيْطَانُ فَإِنَّكَ إِذَا قُلْتَ تَعِسَ الشَّيْطَانُ تَعَاظَمَ وَقَالَ بِقُوَّتِي صَرَعْتُهُ وَإِذَا قُلْتَ بِسْمِ اللَّهِ تَصَاغَرَ حَتَّى يَصِيرَ مِثْلَ الذُّبَابِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari ['Ashim] ia berkata; Aku mendengar [Abu Tamimah] menceritakan dari [seorang yang membonceng Nabi] Shalallahu 'Alaihi Wasallam. [Syu'bah] mengatakan; telah menceritakan kepada kami ['Ashim] dari [Abu Tamimah] dari [seseorang yang membonceng keledai Nabi] Shalallahu 'Alaihi Wasallam, kemudian keledai itu tergelincir, maka aku berkata; \"Celakalah syetan, \" maka Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu katakan celakalah syetan, karena jika kamu mengatakan celakalah syetan, maka syetan akan membanggakan dirinya. Syetan akan berkata; \"Aku telah melawannya dengan kekuatanku, \" namun jika kamu membaca BISMILLAAH, maka syetan akan merasa kecil dirinya sehingga lebih kecil dari seekor lalat.\""},"2696":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُ عَنْ صَعْصَعَةَ بْنِ مُعَاوِيَةَ عَمِّ الْفَرَزْدَقِأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ عَلَيْهِ{ فَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ }قَالَ حَسْبِي لَا أُبَالِ أَنْ لَا أَسْمَعَ غَيْرَهَاحَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا جَرِيرٌ قَالَ سَمِعْتُ الْحَسَنَ قَالَ ثَنَا صَعْصَعَةُ بْنُ مُعَاوِيَةَ عَمُّ الْفَرَزْدَقِ قَالَ قَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ يَقْرَأُ هَذِهِ الْآيَةَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Yazid bin Harun], telah menceritakan kepada kami [Jarir bin Hazim], telah menceritakan kepada kami [Al Hasan] dari [Sha'sha'ah bin Mu'awiyah] pamannya Farazdaq bahwa dia datang kepada Nabi shallallahu 'alaihi wasallam lalu beliau membacakan kepadanya: \"Faman Ya'mal Mitsqaala Dzarratin Khairay Yarah Wa Man Ya'mal Mitsqaala Dzaratin Syarray Yarah (Barangsiapa yang mengerjakan kebaikan seberat dzarrahpun, niscaya dia akan melihat (balasan) nya. Dan barangsiapa yang mengerjakan kejahatan sebesar dzarrahpun, niscaya dia akan melihat (balasan) nya pula) QS Al Zalzalah; 7-8. Dia berkata; \"cukuplah bagiku, aku tidak perduli dan tidak akan mendengarkan yang lainnya.\" Telah menceritakan kepada kami [Aswad bin Amir] telah menceritakan kepada kami [Jarir] ia berkata; \"Aku mendengar [Al Hasan] berkata; telah menceritakan kepada kami [Sha'sha'ah bin Mu'awiyah] pamannya Al Farazdaq, dia berkata; \"Aku datang kepada Nabi shallallahu 'alaihi wasallam, kemudian aku mendengar beliau membaca ayat ini, lalu dia menyebutkan hadits yang semakna.\""},"2697":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ سَمِعْتُ الْحَسَنَ قَالَقَدِمَ عَمُّ الْفَرَزْدَقِ صَعْصَعَةُ الْمَدِينَةَ لَمَّا سَمِعَ{ مَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ }قَالَ حَسْبِي لَا أُبَالِ أَنْ لَا أَسْمَعَ غَيْرَ هَذَا","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Jarir bin Hazim], ia berkata; Aku mendengar [Al Hasan] berkata; Ketika Pamannya Farazdaq yaitu [Sha'sha'ah] tiba di Madinah, ia mendengar; \"Faman Ya'mal Mitsqaala Dzarratin Khairay Yarah Wa Man Ya'mal Mitsqaala Dzarratin Syarray Yarah (Barangsiapa yang mengerjakan kebaikan seberat dzarrahpun, niscaya dia akan melihat (balasan) nya. Dan barangsiapa yang mengerjakan kejahatan sebesar dzarrahpun, niscaya dia akan melihat (balasan) nya pula) QS Al Zalzalah; 7-8. Dia berkata; \"cukuplah bagiku, aku tidak perduli akan mendengarkan yang lainnya.\""},"2698":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مَنْصُورُ بْنُ سَعْدٍ عَنْ بُدَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ مَيْسَرَةَ الْفَجْرِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَتَى كُتِبْتَ نَبِيًّا قَالَ وآدَمُ عَلَيْهِ السَّلَام بَيْنَ الرُّوحِ وَالْجَسَدِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Manshur bin Sa'd] dari [Budail] dari [Abdullah bin Syaqiq] dari [Maysarah Al Fajr] dia berkata; aku bertanya; \"Wahai Rasulullah, kapankah engkau dicatat sebagai seorang Nabi?\" Beliau bersabda: \"Ketika Adam 'alaihis salam antara Ruh dan Jasad.\""},"2699":{"ar":"حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ يَعْنِي التَّيْمِيَّ عَنْ أَنَسٍ عَنْ بَعْضِ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْلَةَ أُسْرِيَ بِهِ مَرَرْتُ عَلَى مُوسَى صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فِي قَبْرِهِ","id":"Telah menceritakan kepada kami [Ibnu Abi 'Adi] dari [Sulaiman yaitu At Taimi] dari [Anas] dari [sebagian sahabat Nabi] shallallahu 'alaihi wasallam bahwa Nabi shallallahu 'alaihi wasallam bersabda pada malam Isra`: \"Aku melewati Musa 'alaihis salam, ketikaitu Musa tengah melaksanakan shalat di kuburannya.\""},"2700":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنِي عُمَرُ بْنُ فَرُّوخَ حَدَّثَنِي بِسْطَامُ عَنْ أَعْرَابِيٍّ تَضَيَّفَهُمْأَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ تَسْلِيمَتَيْنِ","id":"Telah menceritakan kepada kami [Abdusshamad], telah menceritakan kepada kami [Amr bin Farrukh] telah menceritakan kepadaku [Bistham] dari [seorang arab badui] yang menjamu mereka bahwa dia melaksanakan shalat bersama Nabi shallallahu 'alaihi wasallam, lalu beliau salam dengan dua kali salam.\""},"2701":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا عُمَرُ بْنُ فَرُّوخَ حَدَّثَنَا بِسْطَامُ الْكُوفِيُّ قَالَتَضَيَّفَنَا أَعْرَابِيٌّ فَحَدَّثَ الْأَعْرَابِيُّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ تَسْلِيمَتَيْنِ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ","id":"Telah menceritakan kepada kami [Abu Sa'id], telah menceritakan kepada kami [Umar bin Farrukh] telah menceritakan kepada kami [Bistham Al Kufi] ia berkata; seorang badui pernah menjamu kami, lalu [seorang badui] bercerita dari Nabi shallallahu 'alaihi wasallam, bahwa dirinya pernah melaksanakan shalat bersama Nabi shallallahu 'alaihi wasallam, lalu beliau salam dengan dua kali salam, ke kanan dan ke kiri.\""},"2702":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا سُفْيَانُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ مُحَمَّدِ بْنِ أَبِي عَائِشَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكُمْ تَقْرَءُونَ خَلْفَ الْإِمَامِ وَالْإِمَامُ يَقْرَأُ قَالُوا إِنَّا لَنَفْعَلُ ذَلِكَ قَالَ فَلَا تَفْعَلُوا إِلَّا أَنْ يَقْرَأَ أَحَدُكُمْ بِأُمِّ الْكِتَابِ أَوْ قَالَ فَاتِحَةِ الْكِتَابِ","id":"Telah menceritakan kepada kami [Yahya bin Adam], telah menceritakan kepada kami [Sufyan] dari [Khalid] dari [Abu Qilabah] dari [Muhammad bin Abu 'Aisyah] dari [seorang sahabat Nabi] Shalallahu 'Alaihi Wasallam, ia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Apakah kalian membaca di belakang imam sedang imam jiga membaca (ayat)?\" Mereka menjawab; \"Ya, sungguh kami melakukan hal itu.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Janganlah kalian lakukan lagi, kecuali kalian membaca Ummul Kitab -atau bersabda- membaca Al Fatihah.\""},"2703":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ هَارُونَ بْنِ رِئَابٍ عَنْ كِنَانَةَ بْنِ نُعَيْمٍ عَنْ قَبِيصَةَ بْنِ الْمُخَارِقِ قَالَحُمِّلْتُ حَمَالَةً فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ فِيهَا فَقَالَ أَقِمْ حَتَّى تَأْتِيَنَا الصَّدَقَةُ فَإِمَّا أَنْ نَحْمِلَهَا وَإِمَّا أَنْ نُعِينَكَ فِيهَا وَقَالَ إِنَّ الْمَسْأَلَةَ لَا تَحِلُّ إِلَّا لِثَلَاثَةٍ لِرَجُلٍ تَحَمَّلَ حَمَالَةَ قَوْمٍ فَيَسْأَلُ فِيهَا حَتَّى يُؤَدِّيَهَا ثُمَّ يُمْسِكُ وَرَجُلٍ أَصَابَتْهُ جَائِحَةٌ اجْتَاحَتْ مَالَهُ فَيَسْأَلُ فِيهَا حَتَّى يُصِيبَ قَوَامًا مِنْ عَيْشٍ أَوْ سِدَادًا مِنْ عَيْشٍ ثُمَّ يُمْسِكُ وَرَجُلٍ أَصَابَتْهُ فَاقَةٌ فَيَسْأَلُ حَتَّى يُصِيبَ قَوَامًا مِنْ عَيْشٍ أَوْ سِدَادًا مِنْ عَيْشٍ ثُمَّ يُمْسِكُ وَمَا سِوَى ذَلِكَ مِنْ الْمَسَائِلِ سُحْتًا يَا قَبِيصَةُ يَأْكُلُهُ صَاحِبُهُ سُحْتًا","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Ayyub] dari [Harun bin Ri`ab] dari [Kinanah bin Nu'aim] dari [Qabishah bin Al Mukhariq] ia berkata; \"Saya mempunyai tanggungan hutang, maka kutemui Nabi shallallahu 'alaihi wasallam dan kuminta beliau untuk memberesi hutangku. Kata beliau: \"Tetaplah engkau berdiam disini, nanti kami yang akan memberesi tanggunganmu atau aku sekedar menolongmu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Qabishah, meminta-minta tidak halal kecuali bagi salah satu dari tiga orang yaitu; Pertama, orang yang mempunyai tanggungan (hutang) yang menjadikannya terpaksa meminta sehingga bisa ia melunasi tanggungannya, lalu ia menahan diri (tidak meminta), kedua, seseorang yang tertekan oleh keterbatasan (pailit) yang menjadikan hartanya ludes sehingga ia terpaksa meminta hingga ia memperoleh penopang kehidupan atau solusi kehidupan, kemudian ia menahan diri (tidak meminta), dan ketiga, seseorang yang betul-betul terhimpit kefakiran atau kebutuhan mendesak, sehingga ia terpaksa meminta, sampai ia peroleh penopang kehidupan atau solusi kehidupan, selanjutnya ia menahan diri, adapun meminta-minta selain karena tiga alasan ini, wahai Qabishah, adalah dosa yang disantap oleh pelakunya.\""},"2704":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنِ الْحَسَنِ عَنْ أَبِي كَرِيمَةَ حَدَّثَنِي رَجُلٌ مِنْ أَهْلِ الْبَصْرَةِ عَنْ قَبِيصَةَ بْنِ الْمُخَارِقِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي يَا قَبِيصَةُ مَا جَاءَ بِكَ قُلْتُ كَبِرَتْ سِنِّي وَرَقَّ عَظْمِي فَأَتَيْتُكَ لِتُعَلِّمَنِي مَا يَنْفَعُنِي اللَّهُ عَزَّ وَجَلَّ بِهِ قَالَ يَا قَبِيصَةُ مَا مَرَرْتَ بِحَجَرٍ وَلَا شَجَرٍ وَلَا مَدَرٍ إِلَّا اسْتَغْفَرَ لَكَ يَا قَبِيصَةُ إِذَا صَلَّيْتَ الْفَجْرَ فَقُلْ ثَلَاثًا سُبْحَانَ اللَّهِ الْعَظِيمِ وَبِحَمْدِهِ تُعَافَى مِنْ الْعَمَى وَالْجُذَامِ وَالْفَالِجِ يَا قَبِيصَةُ قُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِمَّا عِنْدَكَ وَأَفِضْ عَلَيَّ مِنْ فَضْلِكَ وَانْشُرْ عَلَيَّ رَحْمَتَكَ وَأَنْزِلْ عَلَيَّ مِنْ بَرَكَاتِكَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] dari [Al Hasan] dari [Abu Karimah] telah menceritakan kepadaku [seorang lelaki] dari penduduk Bashrah, dari [Qabishah bin Al Mukhariq], dia berkata; \"Aku datang menemui Rasulullah Shallalahu 'Alaihi Wasallam, lalu beliau bertanya kepadaku: \"Wahai Qobishah, apa yang membuatmu datang kesini?.\" aku menjawab; \"Usiaku semakin tua, tulang-tulangku mulai rapuh, maka aku datang kepadamu agar supaya engkau mengajariku sesuatu yang bermanfaat bagiku kepada Allah Azza Wa Jalla.\" Beliau lalu bersabda: \"Wahai Qabishah, tidaklah kamu melewati sebongkah batu atau sebatang pohon atau perkampungan, melainkan mereka akan memohonkan ampun untukmu, wahai Qabishah, apabila kamu (selesai) mengerjakan shalat Shubuh, maka bacalah tiga kali \"subhaanallaahal 'adziim wa bihamdihi (Maha suci Allah lagi maha Agung, dan segala puji bagi-Mu) \" niscaya kamu akan terhindar dari kebutaan, penyakit kusta dan setruk, wahai Qabishah bacalah \"Allaahumma innii as'aluka mimmaa 'indaka wa afidl 'alaiya min fadlika wansyur 'alaiya rahmataka wa anzil 'alaiya min barakaatika.\" (ya Allah, sesungguhnya aku memohon kepadaMu apa apa yang ada di sisiMu, berikanlah kemurahan-Mu kepadaku, curahkanlah rahmatMu kepadaku dan turunkanlah keberkahanMu kepadaku).\""},"2705":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا عَوْفٌ عَنْ حَيَّانَ أَبِي الْعَلَاءِ عَنْ قَطَنِ بْنِ قَبِيصَةَ عَنْ قَبِيصَةَ بْنِ الْمُخَارِقِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعِيَافَةَ وَالطِّيَرَةَ وَالطَّرْقَ مِنْ الْجِبْتِ","id":"Telah menceritakan kepada kami [Rauh], telah menceritakan kepada kami ['Auf] dari [Hayyan Abul Ala`] dari [Qathan bin Qabishah] dari [Qabishah bin Mukhariq] dari Nabi Shalallahu 'Alaihi Wasallam, beliau bersabda: \"Sesungguhnya 'iyafah, thayarah dan tharq termasuk jibt.\" "},"2706":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَوْفٌ عَنْ حَيَّانَ حَدَّثَنِي قَطَنُ بْنُ قَبِيصَةَ عَنْ أَبِيهِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعِيَافَةَ وَالطَّرْقَ وَالطِّيَرَةَ مِنْ الْجِبْتِقَالَ عَوْفٌ الْعِيَافَةُ زَجْرُ الطَّيْرِ وَالطَّرْقُ الْخَطُّ يُخَطُّ فِي الْأَرْضِ وَالْجِبْتُ قَالَ الْحَسَنُ إِنَّهُ الشَّيْطَانُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami ['Auf] dari [Hayyan], telah menceritakan kepadaku [Qathan bin Qabishah] dari [Qabishah bin Al Mukharriq] dari Nabi Shalallahu 'Alaihi Wasallam, beliau bersabda: \"Sesungguhnya 'iyafah, thayarah dan tharq termasuk jibt.\" ['Auf] berkata; \"'iyafah adalah meramal dengan burung, sedangkan tharq adalah mempercayai garis-garis yang digambar di atas tanah, kata Al Hasan al Jibt adalah setan.\" "},"2707":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ وَزُهَيْرِ بْنِ عَمْرٍو قَالَلَمَّا نَزَلَتْ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }صَعِدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَقْمَةً مِنْ جَبَلٍ عَلَى أَعْلَاهَا حَجَرٌ فَجَعَلَ يُنَادِي يَا بَنِي عَبْدِ مَنَافٍ إِنَّمَا أَنَا نَذِيرٌ إِنَّمَا مَثَلِي وَمَثَلُكُمْ كَرَجُلٍ رَأَى الْعَدُوَّ فَذَهَبَ يَرْبَأُ أَهْلَهُ فَخَشِيَ أَنْ يَسْبِقُوهُ فَجَعَلَ يُنَادِي وَيَهْتِفُ يَا صَبَاحَاهْحَدَّثَنَا إِسْمَاعِيلُ عَنِ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ وَزُهَيْرِ بْنِ عَمْرٍو قَالَا لَمَّا نَزَلَتْ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id], telah menceritakan kepada kami [At Taimi] dari [Abu Utsman] dari [Qabishah bin Mukhariq] dan [Zuhair bin 'Amru] berkata; \"Ketika turun ayat wa andzir 'asyirataka wal `aqrabiin (dan serulah keluarga dan sanak dekatmu!) Rasulullah Shallalahu 'Alaihi Wasallam langsung naik bukit yang disekitarnya bebatuan, beliau menyeru: \"Wahai bani Abdu Manaf, sungguh aku hanyalah pemberi peringatan, permisalan aku dengan kalian adalah semisal seorang yang melihat musuhnya, lalu ia pergi dan menjaga keselamatan keluarganya, dan ia khawatir jika musuh tersebut akan mendahului (menyerang), lalu berteriak dengan suara yang lantang; \"Pagi yang berbahaya.\" Telah menceritakan kepada kami [Isma'il] dari [At Taimi] dari [Abu Utsman] dari [Qabishah bin Mukhariq] dan [Zuhair bin 'Amru] ia berkata; \"Ketika turun ayat wa andzir 'syirataka wal `aqrabiin (dan serulah keluarga dan sanak dekatmu!), lalu ia menyebutkan hadits yang serupa."},"2708":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ قَبِيصَةَ قَالَانْكَسَفَتْ الشَّمْسُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَكْعَتَيْنِ فَأَطَالَ فِيهِمَا الْقِرَاءَةَ فَانْجَلَتْ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ تَبَارَكَ وَتَعَالَى يُخَوِّفُ بِهِمَا عِبَادَهُ فَإِذَا رَأَيْتُمْ ذَلِكَ فَصَلُّوا كَأَحْدَثِ صَلَاةٍ صَلَّيْتُمُوهَا مِنْ الْمَكْتُوبَةِحَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ قَبِيصَةَ الْهِلَالِيِّ قَالَ انْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا يَوْمَئِذٍ مَعَهُ بِالْمَدِينَةِ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abdul Wahab Ats Tsaqafi], telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Qabishah] dia berkata; \"Telah terjadi gerhana matahari, lalu Rasulullah Shallalahu 'Alaihi Wasallam keluar untuk melaksanakan shalat dua raka'at, beliau memanjangkan bacaannya dalam dua raka'at tersebut, hingga matahari nampak kembali, lalu beliau bersabda: \"Sesungguhnya matahari dan bulan adalah dua tanda di antara tanda-tanda kekuasaan Allah Tabaraka wa Ta'ala, dengan maksud memberikan rasa takut kepada hamba-hambaNya, apabila kalian melihat gerhana (matahari atau bulan), maka laksanakanlah shalat seperti shalat yang pertama kali kalian lakukan dari shalat wajib.\" Telah menceritakan kepada kami [Abu Sa'id] bekas budak Bani Hasyim, telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Qabishah Al Hilali] dia berkata; \"Pernah terjadi gerhana matahari pada masa Rasulullah Shallalahu 'Alaihi Wasallam, ketika itu aku bersama beliau di Madinah, kemudian dia menyebutkan hadits yang semakna.\""},"2709":{"ar":"حَدَّثَنِي وَكِيعٌ حَدَّثَنَا قُرَّةُ عَنْ حُمَيْدِ بْنِ هِلَالٍ الْعَدَوِيِّ عَنْ رَجُلٍ مِنْهُمْ يُقَالُ لَهُ خَالِدُ بْنُ عُمَيْرٍ فَقَالَ أَبُو نَعَامَةَ سَمِعْتُهُ مِنْ خَالِدِ بْنِ عُمَيْرٍ قَالَخَطَبَنَا عُتْبَةُ بْنُ غَزْوَانَ قَالَ أَبُو نَعَامَةَ عَلَى الْمِنْبَرِ وَلَمْ يَقُلْهُ قُرَّةُ فَقَالَ أَلَا إِنَّ الدُّنْيَا قَدْ آذَنَتْ بِصَرْمٍ وَوَلَّتْ حَذَّاءَ وَلَمْ يَبْقَ مِنْهَا إِلَّا صُبَابَةٌ كَصُبَابَةِ الْإِنَاءِ وَأَنْتُمْ فِي دَارٍ مُنْتَقِلُونَ عَنْهَا فَانْتَقِلُوا بِخَيْرِ مَا بِحَضْرَتِكُمْ فَلَقَدْ رَأَيْتُنِي سَابِعَ سَبْعَةٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَنَا ��َعَامٌ نَأْكُلُهُ إِلَّا وَرَقُ الشَّجَرِ حَتَّى قَرِحَتْ أَشْدَاقُنَاقَالَ أَبُو عَبْد الرَّحْمَنِ سَمِعْت أَبِي يَقُولُ مَا حَدَّثَ بِهَذَا الْحَدِيثِ غَيْرُ وَكِيعٍ يَعْنِي أَنَّهُ غَرِيبٌ حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ رَجُلٍ قَالَ أَيُّوبُ أُرَاهُ خَالِدَ بْنَ عُمَيْرٍ قَالَ سَمِعْتُ عُتْبَةَ بْنَ غَزْوَانَ يَخْطُبُ فَذَكَرَ الْحَدِيثَ قَالَ وَلَقَدْ رَأَيْتُنِي سَابِعَ سَبْعَةٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا لَنَا طَعَامٌ إِلَّا الشَّجَرَ أَوْ قَالَ وَرَقَ الشَّجَرِ حَتَّى قَرِحَتْ أَشْدَاقُنَا قَالَ أَبِي أَبُو نَعَامَةَ هَذَا عَمْرُو بْنُ عِيسَى وَأَبُو نَعَامَةَ السَّعْدِيُّ آخَرُ أَقْدَمُ مِنْ هَذَا وَهَذَا أَكْبَرُ مِنْ ذَاكَ","id":"Telah menceritakan padaku [Waki'], telah menceritakan kepada kami [Qurrah] dari [Humaid bin Hilal Al 'Adawi] dari seseorang dari mereka yang dikenal dengan [Khalid bin 'Umair]. - [Abu Na'amah] berkata; Aku mendengranya dari [Khalid bin 'Umair] - berkata; [Utbah bin Ghazwan] pernah berkhutbah dihadapan kami; - [Abu Na'amah] mengatakan; di atas mimbar- namun [Qurrah] tidak menyebutkan (diatas mimbar), lalu Utbah berkata; \"Sungguh dunia itu fana dan akan sirna dengan cepat, dan tidak ada yang tersisa kecuali seperti sisa air di dalam bejana, sementara kalian akan berpindah darinya, maka berpindahlah dengan kebaikan dari yang telah kalian dapat, aku telah mendapatkan bersama Rasulullah shallallahu 'alaihi wasallam selama tujuh hari berturut, tidak mendapatkan makanan kecuali dedaunan pohon, hingga mulut-mulut kami terluka.\" Abu Abdurrahman berkata; Aku mendengar ayahku mengatakan; 'Tidaklah menceritakan hadits ini selain Waki' yaitu bahwa hadits ini gharib. Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] dari seseorang, [Ayyub] mengatakan; menurutku dia adalah [Khalid bin 'Umair], ia berkata; Aku mendengar [Utbah bin Ghazwan] berkhutbah dan ia menyebutkan hadits ini, ia berkata; \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam selama tujuh hari berturut-turut.\" Atau (dengan redaksi yang lain) salah seorang sahabat Nabi shallallahu 'alaihi wasallam berkata; 'Dan tidaklah kami mendapat makanan kecuali pohon -atau berkata; dedaunan pohon- hingga mulut-mulut kami terluka.' Ayahku berkata; Abu 'Na'amah adalah 'Amru bin Isa, sedangkan Abu Na'amah As Sa'di adalah orang lain, ia lebih didahulukan karena ia lebih tua darinya."},"2710":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنِ الْأَغَرِّ عَنْ خَلِيفَةَ بْنِ حُصَيْنٍ عَنْ جَدِّهِ قَيْسِ بْنِ عَاصِمٍأَنَّهُ أَسْلَمَ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَغْتَسِلَ بِمَاءٍ وَسِدْرٍ","id":"Telah menceritakan kepada kami [Abdurrahman], telah menceritakan kepada kami [Sufyan] dari [Aghar] dari [Khalifah bin Hushain] dari kakeknya yaitu [Qais bin 'Ashim] bahwa dia masuk Islam, kemudian Nabi shallallahu 'alaihi wasallam memerintahkannya agar mandi dengan air yang di campur dengan daun bidara.\""},"2711":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ مُطَرِّفِ بْنِ الشِّخِّيرِ وَحَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ قَالَ حَجَّاجٌ فِي حَدِيثِهِ سَمِعْتُ مُطَرِّفَ بْنَ الشِّخِّيرِ يُحَدِّثُ عَنْ حَكِيمِ بْنِ قَيْسِ بْنِ عَاصِمٍ عَنْ أَبِيهِأَنَّهُ أَوْصَى وَلَدَهُ عِنْدَ مَوْتِهِ قَالَ اتَّقُوا اللَّهَ عَزَّ وَجَلَّ وَسَوِّدُوا أَكْبَرَكُمْ فَإِنَّ الْقَوْمَ إِذَا سَوَّدُوا أَكْبَرَهُمْ خَلَفُوا أَبَاهُمْ فَذَكَرَ الْحَدِيثَ وَإِذَا مُتُّ فَلَا تَنُوحُوا عَلَيَّ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُنَحْ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] ia berkata; Aku mendengar [Qatadah] menceritakan dari [Mutharrif bin Asy Syikhir] -dan [Hajjaj] berkata; [Syu'bah] telah bercerita kepadaku, [Hajjaj] mengatakan dalam haditsnya; \"Aku mendengar [Mutharrif bin Asy Syikhir] bercerita- dari [Hakim bin Qais bin 'Ashim] dari [Ayahnya] bahwa menjelang wafat, dia sempat berwasiat kepada anak-anaknya, katanya; \"Bertakwalah kalian kepada Allah 'azza wajalla dan jadikanlah orang yang paling tua di antara kalian sebagai pemimpin, karena bila suatu kaum menjadikan orang yang paling tua sebagai pemimpin, maka mereka mewakili bapak-bapak mereka.\" Kemudian dia menyebutkan hadits, dan jika aku meninggal, maka janganlah kalian meratapiku, karena Rasulullah shallallahu 'alaihi wasallam tidaklah diratapi.\""},"2712":{"ar":"حَدَّثَنَا هُشَيْمٌ قَالَ مُغِيرَةُ أَخْبَرَ عَنْ أَبِيهِ عَنْ شُعْبَةَ بْنِ التَّوْأَمِ عَنْ قَيْسِ بْنِ عَاصِمٍأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحِلْفِ فَقَالَ مَا كَانَ مِنْ حِلْفٍ فِي الْجَاهِلِيَّةِ فَتَمَسَّكُوا بِهِ وَلَا حِلْفَ فِي الْإِسْلَامِحَدَّثَنَا إِبْرَاهِيمُ بْنُ زِيَادٍ سَبَلَانُ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ عَنْ شُعْبَةَ عَنْ مُغِيرَةَ عَنْ أَبِيهِ عَنْ شُعْبَةَ بْنِ التَّوْأَمِ عَنْ قَيْسِ بْنِ عَاصِمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Husyaim]. [Mughirah] mengatakan; ia dikabari dari [Ayahnya] dari [Syu'bah bin Tau`am] dari [Qais bin 'Ashim] bahwa dia bertanya kepada Nabi shallallahu 'alaihi wasallam tentang sumpah.\" Kemudian beliau bersabda: \"(Sekarang) tak berlaku lagi ikrar kesepakatan (koalisi) yang terjadi semasa jahiliyah lantas mereka pertahankan, dan tak ada ikrar kesepakatan (koalisi) karena dorongan kejahiliyahan dalam Islam.\" Telah menceritakan kepada kami [Ibrahim bin Ziyad Sabalan], telah menceritakan kepada kami ['Abbad bin 'Abbad] dari [Syu'bah] dari [Mughirah] dari [Ayahnya] dari [Syu'bah bin At Tau'am] dari [Qais bin 'Ashim] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas.\""},"2713":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ الْأَغَرِّ الْمِنْقَرِيِّ عَنْ خَلِيفَةَ بْنِ حُصَيْنِ بْنِ قَيْسِ بْنِ عَاصِمٍ عَنْ أَبِيهِأَنَّ جَدَّهُ أَسْلَمَ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يَغْتَسِلَ بِمَاءٍ وَسِدْرٍ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sufyan] dari [Al Aghar Al Minqari] dari [Khalifah bin Hushain bin Qais bin 'Ashim] dari [Ayahnya] bahwa Kakeknya, dia masuk Islam di zaman Nabi Shalallahu 'Alaihi Wasallam, lalu beliau memerintahkannya untuk mandi dengan air dan daun bidara.\""},"2714":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مَنْصُورٌ وَيُونُسُ عَنِ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ بْنَ سَمُرَةَ إِذَا آلَيْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ عَنْ يَمِينِكَ","id":"Telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Manshur] dan [Yunus] dari [Al Hasan] dari [Abdurrahman bin Samurah] dia berkata; \"Nabi Shallalahu 'Alaihi Wasallam bersabda kepadaku: \"Wahai Abdurrahman bin Samurah, jika kamu telah bersumpah, kemudian melihat ada yang lebih baik darinya, maka lakukanlah yang lebih baik darinya dan bayarlah kafarat sumpahmu.\""},"2715":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ حَيَّانَ بْنِ عُمَيْرٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ قَالَبَيْنَمَا أَنَا أَتَرَامَى بِأَسْهُمِي فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ إِذْ كُسِفَتِ الشَّمْسُ فَنَبَذْتُهُنَّ وَسَعَيْتُ أَنْظُرُ مَا حَدَثَ كُسُوفِ الشَّمْسِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِذَا هُوَ رَافِعٌ يَدَيْهِ يُسَبِّحُ اللَّهَ عَزَّ وَجَلَّ وَيَحْمَدُ وَيُهَلِّلُ وَيُكَبِّرُ وَيَدْعُو فَلَمْ يَزَلْ كَذَلِكَ حَتَّى حُسِرَ عَنْ الشَّمْسِ فَقَرَأَ سُورَتَيْنِ وَرَكَعَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim], telah menceritakan kepada kami [Al Jurairi] dari [Hayyan bin Umair] bahwa [Abdurrahman bin Samurah] telah menceritakan kepada kami, dia berkata; \"Ketika aku sedang latihan melempar anak panah pada masa Rasulullah Shallalahu 'Alaihi Wasallam, tiba-tiba terjadi gerhana matahari, kemudian aku lemparkan anak panah itu dan berusaha untuk melihat apa yang dilakukan oleh Rasulullah Shallalahu 'Alaihi Wasallam dengan gerhana matahari itu, ternyata beliau mengangkat kedua tangannya bertasbih kepada Allah 'azza wajalla, bertahmid, bertahlil, bertakbir dan berdo'a, beliau terus-menerus tak henti-hentinya melaksanakan hal itu hingga matahari nampak kembali, kemudian beliau membaca dua surat dan melaksanakan shalat dua raka'at.\""},"2716":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا يُونُسُ عَنِ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِنْ أُعْطِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ عَنْ يَمِينِكَ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Yunus] dari [Al Hasan] dari [Abdurrahman bin Samurah] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda kepadaku: \"Wahai Abdurrahman, janganlah kamu meminta jabatan, sebab jika engkau diberi karena meminta, kamu akan ditelantarkan, dan jika kamu diberi karena tidak meminta, maka kamu akan ditolong, dan jika kamu melakukan sumpah, lantas kamu melihat suatu hal yang lebih baik, maka lakukanlah yang lebih baik dan bayarlah kaffarat sumpahmu.\""},"2717":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ أَبِي لَبِيدٍ قَالَغَزَوْنَا مَعَ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ كَابُلَ فَأَصَابَ النَّاسُ غَنَمًا فَانْتَهَبُوهَا فَأَمَرَ عَبْدُ الرَّحْمَنِ مُنَادِيًا يُنَادِي إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ انْتَهَبَ نُهْبَةً فَلَيْسَ مِنَّا فَرُدُّوا هَذِهِ الْغَنَمَ فَرَدُّوهَا فَقَسَمَهَا بِالسَّوِيَّةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Jarir bin Hazim] dari [Ya'la bin Hakim] dari [Abu Lubaid] dia berkata; \"Kami pernah ikut berperang bersama Abdurrahman bin Samurah di Kabul, kemudian kaum muslimin mendapatkan ghanimah, lalu mereka berebut mengambilnya, maka [Abdurrahman] menyuruh salah seorang untuk menyeru; \"Sesungguhnya aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: 'Barangsiapa mengambil ghanimah (sebelum dibagi), maka bukan termasuk dari golongan kami, ' maka kembalikanlah ghanimah ini, \" lalu mereka mengembalikannya kemudian Abdurrahman membagikannya dengan rata.\""},"2718":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا الْمُبَارَكُ حَدَّثَنَا الْحَسَنُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ الْقُرَشِيُّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ أُوكِلْتَ إِلَيْهَا وَإِنْ أُعْطِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ عَنْ يَمِينِكَحَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا سِمَاكُ بْنُ عَطِيَّةَ وَيُونُسُ بْنُ عُبَيْدٍ عَنِ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim], telah menceritakan kepada kami [Al Mubarak], telah menceritakan kepada kami [Al Hasan], telah menceritakan kepadaku [Abdurrahman bin Samurah Al Qurasyi] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda kepadaku: \"Wahai Abdurrahman, janganlah kamu meminta jabatan, sebab jika engkau diberi karena meminta, kamu akan ditelantarkan, dan jika kamu diberi karena tidak meminta, maka kamu akan ditolong, dan jika kamu melakukan sumpah, lantas kamu melihat ada suatu hal yang lebih baik, maka lakukanlah yang lebih baik dan bayarlah kafarat sumpahmu.\" Telah menceritakan kepada kami [Abu Kamil Al Jahdari], telah menceritakan kepada kami [Hammad bin Zaid], telah menceritakan kepada kami [Simak bin 'Athiyah] dan [Yunus bin 'Ubaid] dari [Al Hasan] dari [Abdurrahman bin Samurah] dari Nabi Shalallahu 'Alaihi Wasallam seperti hadits di atas."},"2719":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ عَنِ الْحَسَنِ عَنِ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَحْلِفُوا بِآبَائِكُمْ وَلَا بِالطَّوَاغِيتِ وَقَالَ يَزِيدُ وَالطَّوَاغِي","id":"Telah menceritakan kepada kami [Yazid bin Harun], telah menceritakan kepada kami [Hisyam] dari [Al Hasan] dari [Abdurrahman bin Samurah] dari Nabi Shallalahu 'Alaihi Wasallam beliau bersabda: \"Janganlah kalian bersumpah dengan (nama) bapak-bapak kalian, dan jangan pula dengan para thagut.\" [Yazid] berkata (dengan redaksi); \"At Thawaghi (thagut).\" "},"2720":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنِ ابْنِ عَوْنٍ عَنِ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَذَكَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَالَ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ تُعْطَهَا عَنْ غَيْرِ مَسْأَلَةٍ تُعَنْ عَلَيْهَا وَإِنْ تُعْطَهَا عَنْ مَسْأَلَةٍ تُكَلْ إِلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَأْتِ الَّذِي هُوَ خَيْرٌ وَكَفِّرْ عَنْ يَمِينِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Ibnu 'Aun] dari [Al Hasan] dari [Abdurrahman bin Samurah] ia berkata; Nabi Shalallahu 'Alaihi Wasallam pernah menyebutkan sesuatu, lalu beliau bersabda: \"Janganlah kamu meminta jabatan, sebab jika engkau diberi karena tidak memintanya, maka kamu akan ditolong, dan jika kamu diberi karena memintanya, maka kamu akan ditelantarkan, dan jika kamu bersumpah, lantas kamu melihat ada suatu hal yang lebih baik, maka lakukanlah yang lebih baik dan bayarlah kafarat sumpahmu.\""},"2721":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَكْرٍ حَدَّثَنَا هِشَامٌ عَنِ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَهُ يَا عَبْدَ الرَّحْمَنِ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِنْ أُعْطِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَكَفِّرْ عَنْ يَمِينِكَ وَأْتِ الَّذِي هُوَ خَيْرٌ","id":"Telah menceritakan kepada kami [Abdullah bin Bakar], telah menceritakan kepada kami [Hisyam] dari [Al Hasan] dari [Abdurrahman bin Samurah] dari Nabi Shalallahu 'Alaihi Wasallam beliau bersabda: \"Wahai Abdurrahman, janganlah kamu meminta jabatan, sebab jika kamu diberi karena memintanya, maka kamu akan ditelantarkan, dan jika kamu diberi karena tidak memintanya, maka kamu akan ditolong, dan jika kamu bersumpah, lalu kamu melihat ada suatu hal yang lebih baik, maka bayarlah kafarat sumpahmu dan lakukanlah yang lebih baik.\""},"2722":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ وَعَفَّانُ قَالَا ثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ سَمِعْتُ الْحَسَنَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُوتِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِنْ أُوتِيتَهَا عَنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا وَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَكَفِّرْ عَنْ يَمِينِكَ وَأْتِ الَّذِي هُوَ خَيْرٌقَالَ أَبِي اتَّفَقَ عَفَّانُ وَأَسْوَدُ فِي حَدِيثِهِمَا فَقَالَ فَكَفِّرْ عَنْ يَمِينِكَ ثُمَّ ائْتِ الَّذِي هُوَ خَيْرٌ و قَالَ أَبُو الْأَشْهَبِ عَنِ الْحَسَنِ فِي هَذَا الْحَدِيثِ فَبَدَأَ بِالْكَفَّارَةِ حَدَّثَنَا حُسَيْنٌ حَدَّثَنَا الْمُبَارَكُ عَنِ الْحَسَنِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ الْقُرَشِيُّ وَنَحْنُ بِكَابُلَ قَالَ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ لَا تَسْأَلْ الْإِمَارَةَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir] dan ['Affan] keduanya berkata; telah menceritakan kepada kami [Jarir bin Hazim], ia berkata; Aku mendengar hadits ini dari [Al Hasan] dari [Abdurrahman bin Samurah] berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda kepadaku: \"Wahai Abdurrahman, janganlah kamu meminta jabatan, sebab jika kamu diberi karena memintanya, maka kamu akan diterlantarkan, dan jika kamu diberi karena tidak memintanya, maka kamu akan ditolong, dan jika kamu bersumpah, lantas kamu melihat ada suatu hal yang lebih baik, maka bayarlah kafarat sumpahmu dan lakukanlah yang lebih baik.\" Ayahku berkata; Affan dan Aswad sepakat dalam hadits keduanya, maka ayahku berkata; \"Bayarlah kafarat sumpahmu, lalu kerjakanlah yang lebih baik darinya.\" [Abul Asyhab] berkata dari [Al Hasan] mengenai hadits ini, ia memulainya dengan \"kafarat\" Telah menceritakan kepada kami [Husain], telah menceritakan kepada kami [Al Mubarak] dari [Al Hasan], telah menceritakan kepada kami [Abdurrahman bin Samurah Al Quraisyi] seadngkan ketika itu kami berada di Kabul, ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda padaku: \"Wahai Abdurrahman, janganlah kamu meminta jawaban, \" Lalu menyebutkan hadits tersebut."},"2723":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا يَعْلَى بْنُ حَكِيمٍ عَنْ أَبِي لَبِيدٍ قَالَغَزَوْنَا مَعَ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ كَابُلَ قَالَ فَأَصَابَ النَّاسُ غَنِيمَةً فَانْتَهَبُوهَا فَأَمَرَ عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ مُنَادِيًا يُنَادِي فَنَ��دَى فَاجْتَمَعَ النَّاسُ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ انْتَهَبَ فَلَيْسَ مِنَّا رُدُّوهَا فَرَدُّوهَا فَقَسَمَهَا بَيْنَهُمْ بِالسَّوِيَّةِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Jarir bin Hazim], telah menceritakan kepada kami [Ya'la bin Hakim] dari [Abu Labid] ia berkata; \"Aku pernah berperang bersama Abdurrahman bin Samurah di Kabul, kemudian kaum muslimin mendapatkan ghanimah, lantas mereka berebut mengambilnya, maka [Abdurrahman bin Samurah] menyuruh salah seorang untuk menyeru, hingga orang-orang berkumpul, ia menyeru; \"Aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Barangsiapa mengambil ghanimah (sebelum dibagi), maka bukan termasuk dari golongan kami, oleh karena itu kembalikanlah ghanimah ini, \" lalu mereka mengembalikannya, kemudian Abdurrahman membagikannya dengan rata.\""},"2724":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ عَبْدِ رَبِّهِ الْهُجَيْمِيِّ عَنْ جَابِرِ بْنِ سُلَيْمٍ أَوْ سُلَيْمٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ جَالِسٌ مَعَ أَصْحَابِهِ قَالَ فَقُلْتُ أَيُّكُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِمَّا أَنْ يَكُونَ أَوْمَأَ إِلَى نَفْسِهِ وَإِمَّا أَنْ يَكُونَ أَشَارَ إِلَيْهِ الْقَوْمُ قَالَ فَإِذَا هُوَ مُحْتَبٍ بِبُرْدَةٍ قَدْ وَقَعَ هُدْبُهَا عَلَى قَدَمَيْهِ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَجْفُو عَنْ أَشْيَاءَ فَعَلِّمْنِي قَالَ اتَّقِ اللَّهَ عَزَّ وَجَلَّ وَلَا تَحْقِرَنَّ مِنْ الْمَعْرُوفِ شَيْئًا وَلَوْ أَنْ تُفْرِغَ مِنْ دَلْوِكَ فِي إِنَاءِ الْمُسْتَسْقِي وَإِيَّاكَ وَالْمَخِيلَةَ فَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى لَا يُحِبُّ الْمَخِيلَةَ وَإِنْ امْرُؤٌ شَتَمَكَ وَعَيَّرَكَ بِأَمْرٍ يَعْلَمُهُ فِيكَ فَلَا تُعَيِّرْهُ بِأَمْرٍ تَعْلَمُهُ فِيهِ فَيَكُونَ لَكَ أَجْرُهُ وَعَلَيْهِ إِثْمُهُ وَلَا تَشْتُمَنَّ أَحَدًا","id":"Telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Yunus bin Ubaid], dari [Abdurrabbih Al Hujaimi] dari [Jabir bin Sulaim] atau Sulaim dia berkata; \"Aku datang kepada Nabi Shallalahu 'Alaihi Wasallam ketika beliau sedang duduk bersama para sahabatnya, Sulaim berkata; kemudian aku bertanya; \"Siapakah di antara kalian yang disebut sebagai Nabi Shallalahu 'Alaihi Wasallam?, Sulaim melanjutkan; -Beliau waktu itu menunjuk dirinya sendiri atau mungkin ditunjuk oleh para sahabatnya- dan ternyata dia berselimutkan selendang yang ujungnya sampai menyentuh kedua kakinya.\" Sulaim berkata; maka aku bertanya; \"Wahai Rasulullah, aku merasa bodoh terhadap banyak hal, maka ajarilah aku!\" beliau menjawab: \"Bertakwalah kepada Allah 'azza wajalla, dan janganlah meremehkan kebaikan sekecil apapun, sekalipun hanya dengan menuangkan ember airmu ke bejana orang yang membutuhkan air, dan jauhilah olehmu kesombongan, karena Allah Tabaraka Wata'ala menykai kesombongan, jika ada seseorang yang mencacimu dan menghinamu karena dia tahu tentang dirimu, maka janganlah kamu membalas menghinanya karena kamu tahu tentang dia, maka itu akan menjadi pahalamu dan akan menjadi dosa baginya, dan janganlah kamu sekali-kali mencaci seseorang.\""},"2725":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا سَلَّامُ بْنُ مِسْكِينٍ عَنْ عَقِيلِ بْنِ طَلْحَةَ حَدَّثَنَا أَبُو جُرَىٍّ الْهُجَيْمِيُّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ مِنْ أَهْلِ الْبَادِيَةِ فَعَلِّمْنَا شَيْئًا يَنْفَعُنَا اللَّهُ تَبَارَكَ وَتَعَالَى بِهِ قَالَ لَا تَحْقِرَنَّ مِنْ الْمَعْرُوفِ شَيْئًا وَلَوْ أَنْ تُفْرِغَ مِنْ دَلْوِكَ فِي إِنَاءِ الْمُسْتَسْقِي وَلَوْ أَنْ تُكَلِّمَ أَخَاكَ وَوَجْهُكَ إِلَيْهِ مُنْبَسِطٌ وَإِيَّاكَ وَتَسْبِيلَ الْإِزَارِ فَإِنَّهُ مِنْ الْخُيَلَاءِ وَالْخُيَلَاءُ لَا يُحِبُّهَا اللَّهُ عَزَّ وَجَلَّ وَإِنْ امْرُؤٌ سَبَّكَ بِمَا يَعْلَمُ فِيكَ فَلَا تَسُبَّهُ بِمَا تَعْلَمُ فِيهِ فَإِنَّ أَجْرَهُ لَكَ وَوَبَالَهُ عَلَى مَنْ قَالَهُحَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا سَلَّامٌ حَدَّثَنَا عَقِيلُ بْنُ طَلْحَةَ عَنْ أَبِي جُرَيٍّ الْهُجَيْمِيِّ أَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُنَاسٍ مِنْ أَهْلِ الْبَادِيَةِ فَقَالُوا إِنَّا مِنْ أَهْلِ الْبَادِيَةِ فَذَكَرَ الْحَدِيثَ إِلَّا أَنَّهُ قَالَ فَلَا تَشْتُمْهُ بِمَا تَعْلَمُ فِيهِ فَإِنَّ أَجْرَ ذَلِكَ لَكَ وَوَبَالَهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Yazid], telah mengabarkan kepada kami [Sallam bin Miskin] dari ['Aqil bin Thalhah], telah menceritakan kepada kami [Abu Jurai Al Hujaimi] ia berkata; Aku datang kepada Rasulullah Shallalahu 'Alaihi Wasallam, lalu aku bertanya; \"Wahai Rasulullah, sesungguhnya kami adalah satu kaum dari penduduk dusun, maka ajarkanlah pada kami seseuatu yang Allah Tabaraka wa Ta'ala akan memberikan manfaat buat kami!.\" Beliau bersabda: \"Janganlah meremehkan kebaikan sekecil apapun, sekalipun hanya dengan menuangkan ember airmu ke bejana orang yang membutuhkan air, dan sekalipun kamu berbicara dengan saudaramu dengan wajah berseri-seri, dan janganlah engkau menurunkan kain di bawah mata kaki (isbal) karena ia bagian dari sifat sombong, sementara Allah 'azza wajalla tidak menyukai menyukai sifat sombong, jika ada seseorang yang mencacimu dan menghinamu karena dia tahu tentang dirimu, maka janganlah kamu menghinanya karena kamu tahu tentang dia, maka itu akan menjadi pahalamu dan akan menjadi dosa baginya.\" Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Sallam], telah menceritakan kepada kami ['Aqil bin Thalhah] dari [Abu Jurai Al Hujaimi] bahwa ia datang bersama dengan penduduk dusun kepada Rasulullah Shallalahu 'Alaihi Wasallam, lalu mereka berkata; \"Sugguh kami dari penduduk dusun… lalu ia menyebutkan hadits, kecuali ada tambahan dengan redaksi; \"Maka janganlah kamu menghinanya dengan apa yang engkau tahu, karena pahalanya untukmu dan dosanya untuknya.\""},"2726":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا يُونُسُ حَدَّثَنَا عَبِيدَةُ الْهُجَيْمِيُّ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ أَبِي جُرَيٍّ جَابِرِ بْنِ سُلَيْمٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْتَبٍ بِشَمْلَةٍ لَهُ وَقَدْ وَقَعَ هُدْبُهَا عَلَى قَدَمَيْهِ فَقُلْتُ أَيُّكُمْ مُحَمَّدٌ أَوْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَوْمَأَ بِيَدِهِ إِلَى نَفْسِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي مِنْ أَهْلِ الْبَادِيَةِ وَفِيَّ جَفَاؤُهُمْ فَأَوْصِنِي فَقَالَ لَا تَحْقِرَنَّ مِنْ الْمَعْرُوفِ شَيْئًا وَلَوْ أَنْ تَلْقَى أَخَاكَ وَوَجْهُكَ مُنْبَسِطٌ وَلَوْ أَنْ تُفْرِغَ مِنْ دَلْوِكَ فِي إِنَاءِ الْمُسْتَسْقِي وَإِنْ امْرُؤٌ شَتَمَكَ بِمَا يَعْلَمُ فِيكَ فَلَا تَشْتُمْهُ بِمَا تَعْلَمُ فِيهِ فَإِنَّهُ يَكُونُ لَكَ أَجْرُهُ وَعَلَيْهِ وِزْرُهُ وَإِيَّاكَ وَإِسْبَالَ الْإِزَارِ فَإِنَّ إِسْبَالَ الْإِزَارِ مِنْ الْمَخِيلَةِ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يُحِبُّ الْمَخِيلَةَ وَلَا تَسُبَّنَّ أَحَدًا فَمَا سَبَبْتُ بَعْدَهُ أَحَدًا وَلَا شَاةً وَلَا بَعِيرًا","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah menceritakan kepada kami [Yunus], telah menceritakan kepada kami ['Abidah Al Hujaimi] dari [Abu Tamimah Al Hujaimi] dari [Abu Jurai Jabir bin Sulaim] ia berkata; Aku datang kepada Rasulullah Shallalahu 'Alaihi Wasallam, waktu itu beliau tengah berselimutkan selendang yang ujungnya sampai menyentuh kedua kakinya, kemudian aku bertanya; \"Siapakah yang bernama Muhammad atau Rasulullah shallallahu 'alaihi wasallam di antara kalian?, lalu beliau menunjuk pada dirinya. aku pun berkata; \"Wahai Rasulullah, sesungguhnya aku dari penduduk dusun, sementara diriku adalah orang yang bodoh diantara mereka, maka berilah aku wasiat!\" beliau bersabda: \"Janganlah kamu meremehkan kebaikan sekecil apapun, sekalipun hanya dengan menuangkan ember airmu ke bejana orang yang membutuhkan air. Jika ada seseorang yang mencacimu dan menghinamu karena dia tahu tentang dirimu, maka janganlah kamu membalas menghinanya, dengan sesuatu yang kamu tahu dengan dia, karena itu akan menjadi pahalamu dan akan menjadi dosa baginya. Janganlah kamu sekali-kali mencaci seseorang, dan jauhilah olehmu isbal (menurunkan kain dibawah mata kaki), karena isbal adalah bagian dari kesombongan, karena Allah Azza wa Jalla sangat membencinya, dan janganlah kamu menghina seseorang!.\" Setelah itu aku tidak pernah menghina seorang pun, tidak juga menghina kambing atau keledai.\""},"2727":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَاهُ وُهَيْبٌ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ رَجُلٍ مِنْ بَلْهُجَيْمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِلَامَ تَدْعُو قَالَ أَدْعُو إِلَى اللَّهِ وَحْدَهُ الَّذِي إِنْ مَسَّكَ ضُرٌّ فَدَعَوْتَهُ كَشَفَ عَنْكَ وَالَّذِي إِنْ ضَلَلْتَ بِأَرْضٍ قَفْرٍ دَعَوْتَهُ رَدَّ عَلَيْكَ وَالَّذِي إِنْ أَصَابَتْكَ سَنَةٌ فَدَعَوْتَهُ أَنْبَتَ عَلَيْكَ قَالَ قُلْتُ فَأَوْصِنِي قَالَ لَا تَسُبَّنَّ أَحَدًا وَلَا تَزْهَدَنَّ فِي الْمَعْرُوفِ وَلَوْ أَنْ تَلْقَى أَخَاكَ وَأَنْتَ مُنْبَسِطٌ إِلَيْهِ وَجْهُكَ وَلَوْ أَنْ تُفْرِغَ مِنْ دَلْوِكَ فِي إِنَاءِ الْمُسْتَسْقِي وَاتَّزِرْ إِلَى نِصْفِ السَّاقِ فَإِنْ أَبَيْتَ فَإِلَى الْكَعْبَيْنِ وَإِيَّاكَ وَإِسْبَالَ الْإِزَارِ فَإِنَّ إِسْبَالَ الْإِزَارِ مِنْ الْمَخِيلَةِ وَإِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى لَا يُحِبُّ الْمَخِيلَةَ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Wuhaib], telah menceritakan kepada kami [Khalid Al Hadza`] dari [Abu Tamimah Al Hujaimi] dari [seorang] yang berasal dari pendudukl Balhujaim, ia berkata; Aku bertanya; \"Wahai Rasulullah, kepada siapakah engkau menyeru?.\" Rasulullah Shallalahu 'Alaihi Wasallam menjawab: \"Aku menyeru kepada Allah semata, Dzat yang apabila kamu terkena bencana lalu kamu memohon pada-Nya, maka Dia akan menjauhkanmu dari bencana tersebut, Dzat yang apabila kamu tersesat di suatu padang tandus, lalu kamu meminta-Nya, maka Dia akan menunjukimu, Dzat yang apabila kamu terkena paceklik, lalu kamu memohon kepada-Nya, maka Dia akan tumbuhkan tanaman-tanaman untukmu.\" Aku berkata; \"Lalu wasiatkanlah untukku!.\" Beliau menjawab: \"Janganlah kamu menghina seseorang dan jangan meremehkan kebaikan sedikit pun, walau dengan memberi senyuman kepada saudaramu bila bertemu, atau hanya dengan menuangkan ember airmu ke bejana orang yang membutuhkan air, dan bercelanalah setangah betis, bila kamu merasa enggan, maka (bercelanalah) hingga mata kaki. Janganlah engkau berbuat isbal karena isbal merupakan bagian dari kesombongan dan Allah membenci kesombongan.\""},"2728":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ وَيَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُ قَالَدَخَلَ عَائِذُ بْنُ عَمْرٍو قَالَ يَزِيدُ وَكَانَ مِنْ صَالِحِي أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عُبَيْدِ اللَّهِ بْنِ زِيَادٍ فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ شَرُّ الرِّعَاءِ الْحُطَمَةُ قَالَ عَبْدُ الرَّحْمَنِ فَأَظُنُّهُ قَالَ إِيَّاكَ أَنْ تَكُونَ مِنْهُمْ وَلَمْ يَشُكَّ يَزِيدُ فَقَالَ اجْلِسْ إِنَّمَا أَنْتَ مِنْ نُخَالَةِ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ وَهَلْ كَانَتْ لَهُمْ أَوْ فِيهِمْ نُخَالَةٌ إِنَّمَا كَانَتْ النُّخَالَةُ بَعْدَهُمْ وَفِي غَيْرِهِمْ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Jarir bin Hazim] ia berkata; aku mendengar [Al Hasan] ia berkata; -dan [Yazid bin Harun] mengatakan; telah mengabarkan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Al Hasan] - ia berkata; [A'idz bin Amru] datang -sedangkan Yazid mengatakan; A'idz bin 'Amru termasuk salah seorang yang paling shalih di antara sahabat Nabi Shallalahu 'Alaihi Wasallam- menemui Ubaidillah bin Ziyad, kemudian dia berkata; \"Sesungguhnya aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Sejahat-jahat penguasa adalah yang berlaku dzalim.\" Abdurrahman mengatakan; \"Aku mengira A'idz mengatakan: \"Dan janganlah kalian termasuk dari mereka.\" dan Yazid tidak ragu (mengenai redaksi haditsnya), lalu Ubaidullah bin Ziyad berkata; \"Duduklah, karena kamu termasuk dari pemuka nukhalah para sahabat Muhammad Shallalahu 'Alaihi Wasallam.\" 'Aidz bertanya; \"Apakah di antara mereka memiliki nukhalah atau di antara mereka ada nukhalah? hanyasannya nukhalah itu untuk (generasi) setelah mereka dan untuk selain mereka.\" "},"2729":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي شِمْرٍ الضُّبَعِيِّ قَالَسَمِعْتُ عَائِذَ بْنَ عَمْرٍو يَنْهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ فَقُلْتُ لَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Syimr Adluba'i], dia berkata; aku mendengar [A'idz bin 'Amru] melarang dari dubba', Hantam, Al Muzaffat, dan An Naqir.\" Lalu aku bertanya; \"Apakah ini dari Nabi Shalallahu 'Alaihi Wasallam?.\" Ia menjawab; \"Ya.\" "},"2730":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ سُلَيْمَانَ يَعْنِي التَّيْمِيَّ عَنْ شَيْخٍ فِي مَجْلِسِ أَبِي عُثْمَانَ عَنْ عَائِذِ بْنِ عَمْرٍو قَالَكَانَ فِي الْمَاءِ قِلَّةٌ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَدَحٍ أَوْ فِي جَفْنَةٍ فَنَصَحَنَا بِهِ قَالَ وَالسَّعِيدُ فِي أَنْفُسِنَا مَنْ أَصَابَهُ وَلَا نُرَاهُ إِلَّا قَدْ أَصَابَ الْقَوْمَ كُلَّهُمْ قَالَ ثُمَّ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الضُّحَى","id":"Telah menceritakan kepada kami [Muhammad bin Abu Adi] dari [Sulaiman At Taimi] dari [seorang syaikh] di majelisnya Abu Utsman dari [A'idz bin 'Amru] dia berkata; \"Ketika krisis air, Rasulullah Shallalahu 'Alaihi Wasallam biasa berwudlu menggunakan cangkir atau mangkok besar, kemudian beliau menganjurkan kami menggunakannya, beliau bersabda: \"Dan kebahagiaan yang ada di dalam jiwa kami adalah orang yang telah berwudlu dan kami tidak mengiranya kecuali dia telah memberikan wudlu kepada semua kaum, \" A'idz berkata; \"Kemudian Rasulullah Shallalahu 'Alaihi Wasallam shalat bersama kami diwaktu Dluha.\""},"2731":{"ar":"حَدَّثَنَا مُهَنَّأُ بْنُ عَبْدِ الْحَمِيدِ أَبُو شِبْلٍ وَحَسَنٌ يَعْنِي ابْنَ مُوسَى قَالَا ثَنَا حَمَّادُ بْنُ سَلَمَةَ الْمَعْنَى عَنْ ثَابِتٍ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ عَائِذِ بْنِ عَمْرٍوأَنَّ سَلْمَانَ وَصُهَيْبًا وبِلَالًا كَانُوا قُعُودًا فِي أُنَاسٍ فَمَرَّ بِهِمْ أَبُو سُفْيَانَ بْنُ حَرْبٍ فَقَالُوا مَا أَخَذَتْ سُيُوفُ اللَّهِ تَبَارَكَ وَتَعَالَى مِنْ عُنُقِ عَدُوِّ اللَّهِ مَأْخَذَهَا بَعْدُ فَقَالَ أَبُو بَكْرٍ أَتَقُولُونَ هَذَا لِشَيْخِ قُرَيْشٍ وَسَيِّدِهَا قَالَ فَأُخْبِرَ بِذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا أَبَا بَكْرٍ لَعَلَّكَ أَغْضَبْتَهُمْ فَلَئِنْ كُنْتَ أَغْضَبْتَهُمْ لَقَدْ أَغْضَبْتَ رَبَّكَ تَبَارَكَ وَتَعَالَى فَرَجَعَ إِلَيْهِمْ فَقَالَ أَيْ إِخْوَتَنَا لَعَلَّكُمْ غَضِبْتُمْ فَقَالُوا لَا يَا أَبَا بَكْرٍ يَغْفِرُ اللَّهُ لَكَحَدَّثَنَا هُدْبَةُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ مِثْلَهُ بِإِسْنَادِهِ","id":"Telah menceritakan kepada kami [Muhanna` bin Abdul Hamid Abu Syibl] dan [Hasan yaitu Ibnu Musa], keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dengan maksud yang sama, dari [Tsabit] dari [Mu'awiyah bin Qurrah] dari [A'idz bin 'Amru] bahwa Salman, Shuhaib dan Bilal tengah duduk-duduk di antara kerumunan orang banyak, kemudian Abu Sufyan bin Harb lewat di hadapan mereka, lalu mereka berkata; \"Pedang-pedang Allah Tabaraka Wata'ala tidak akan di cabut dari tempatnya dari leher musuh Allah selamnya, maka Abu Bakar berkata; \"Apakah kalian mengatakan seperti ini kepada sesepuh Quraisy dan pemimpinnya?.\" A'idz berkata; \"Lantas hal itu diberitahukan kepada Nabi Shallalahu 'Alaihi Wasallam, beliau bersabda: \"Wahai Abu Bakar, mungkin saja kamu memarahi mereka, jika kamu memarahi mereka berarti kamu telah memarahi Rabbmu Tabaraka wa Ta'ala.\" Kemudian Abu Bakar kembali menemui mereka dan berkata; \"Wahai saudara kami, barangkali kalian kalian marah.\" Mereka menjawab; \"Tidak, wahai Abu Bakar, semoga Allah mengampunimu.\" Telah menceritakan kepada kami [Hudbah] telah menceritakan kepada kami [Hammad bin Salamah] dengan hadits dan sanad seperti di atas.\""},"2732":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا أَبُو الْأَشْهَبِ حَدَّثَنَا عَامِرٌ الْأَحْولُ شَيْخٌ لَهُ عَنْ عَائِذِ بْنِ عَمْرٍو قَالَأَحْسَبُهُ رَفَعَهُ قَالَ مَنْ عَرَضَ لَهُ شَيْءٌ مِنْ هَذَا الرِّزْقِ فَلْيُوَسِّعْ بِهِ فِي رِزْقِهِ فَإِنْ كَانَ عَنْهُ غَنِيًّا فَلْيُوَجِّهْهُ إِلَى مَنْ هُوَ أَحْوَجُ إِلَيْهِ مِنْهُحَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ عَائِذِ بْنِ عَمْرٍو أَنَّ صُهَيْبًا وَسَلْمَانَ وَبِلَالًا كَانُوا قُعُودًا فَذَكَرَ نَحْوَهُ إِلَّا أَنَّهُ قَالَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِذَلِكَ فَقَالَ يَا أَبَا بَكْرٍ حَدَّثَنَا رَوْحٌ حَدَّثَنَا بِسْطَامُ بْنُ مُسْلِمٍ قَالَ سَمِعْتُ خَلِيفَةَ بْنَ عَبْدِ اللَّهِ الْغُبَرِيَّ يَقُولُ سَمِعْتُ عَائِذَ بْنَ عَمْرٍو الْمُزَنِيَّ قَالَ بَيْنَا نَحْنُ مَعَ نَبِيِّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ حَدِيثَ الْمَسْأَلَةِ","id":"Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Abul Asyhab], telah menceritakan kepada kami guru mereka [Amir Al Ahwal] dari [A'idz bin 'Amru] dia berkata; -Aku mengira 'Aidz merafa'kan hadits ini- Dia berkata; \"Barangsiapa mendapatkan sesuatu dari anugerah ini (rizqi), hendaklah ia berlapang-lapang dengan rizqinya, jika dia tidak membutuhkannya lagi, hendaknya ia berikan kepada orang yang lebih membutuhkannya.\" Telah menceritakan kepada kami 'Affan telah menceritakan kepada kami Hammad telah mengabarkan kepada kami Tsabit dari Mu'awiyah bin Qurrah dari A'idz bin 'Amru bahwa Shuhaib, Salman dan Bilal tengah duduk-duduk, kemudian dia menyebutkan hadits yang semakna, namun Aidz mengatakan; \"Kemudian Abu Bakar datang menemui Nabi Shallalahu 'Alaihi Wasallam, dan memberitahukan hal itu kepada beliau, lalu beliau bersabda: \"Wahai Abu Bakar...\" telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Bistham bin Muslim] dia berkata; saya mendengar [Khalifah bin Abdullah Al Ghubari] berkata; aku mendengar [A'idz bin 'Amru Al Muzani] berkata; \"Ketika kami sedang bersama Nabi kami Shallalahu 'Alaihi Wasallam, lalu dia menyebutkan hadits tentang masalah tersebut.\""},"2733":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ قَالَ سَمِعْتُ أَبَا شِمْرٍ الضُّبَعِيَّ قَالَ سَمِعْتُ عَائِذَ بْنَ عَمْرٍو قَالَ أَبُو عَبْد الرَّحْمَنِ قَالَ أَبِي قُلْتُ لِيَحْيَى بْنِ سَعِيدٍ الْمُزَنِيِّ قَالَ نَعَمْإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحَنْتَمِ وَالدُّبَّاءِ وَالنَّقِيرِ وَالْمُزَفَّتِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] ia berkata; Aku mendengar [Abu Syimr Adh Dhuba'i] ia berkata; Aku mendengar [A'idz bin 'Amru] ia berkata. -Abu Abdurrahman berkata; ayahku berkata; aku bertanya kepada Yahya bin Sa'id Al Muzanni, ia menjawab; Ya- Nabi Shalallahu 'Alaihi Wasallam telah melarang Hantam, Ad dubba', An Naqir dan Al Muzaffat.\" "},"2734":{"ar":"حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا بِسْطَامُ بْنُ مُسْلِمٍ قَالَ سَمِعْتُ خَلِيفَةَ بْنَ عَبْدِ اللَّهِ الْغُبَرِيَّ يَقُولُ سَمِعْتُ عَائِذَ بْنَ عَمْرٍو الْمُزَنِيَّ قَالَبَيْنَمَا نَحْنُ مَعَ نَبِيِّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَعْرَابِيٌّ قَدْ أَلَحَّ عَلَيْهِ فِي الْمَسْأَلَةِ يَقُولُ يَا رَسُولَ اللَّهِ أَطْعِمْنِي يَا رَسُولَ اللَّهِ أَعْطِنِي قَالَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ الْمَنْزِلَ وَأَخَذَ بِعِضَادَتَيْ الْحُجْرَةِ وَأَقْبَلَ عَلَيْنَا بِوَجْهِهِ وَقَالَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ تَعْلَمُونَ مَا أَعْلَمُ فِي الْمَسْأَلَةِ مَا سَأَلَ رَجُلٌ رَجُلًا وَهُوَ يَجِدُ لَيْلَةً تُبِيتُهُ فَأَمَرَ لَهُ بِطَعَامٍ","id":"Telah menceritakan kepada kami [Rauh bin 'Ubadah], telah menceritakan kepada kami [Bistham bin Muslim], ia berkata; Aku mendengar [Khalifah bin Abdullah Al Ghubari] berkata; Aku mendengar [A'idz bin 'Amru Al Muzani] berkata; \"Ketika kami tengah bersama Nabi kami Shallalahu 'Alaihi Wasallam, tiba-tiba seorang Arab badui meminta kepada beliau setengah memaksa, dia berkata; \"Wahai Rasulullah berilah aku makan, wahai Rasulullah berilah aku.\" A'idz berkata; \"Kemudian Rasulullah Shallalahu 'Alaihi Wasallam berdiri dan masuk ke dalam rumah, dan mengambil sesuatu di sebelah kamar beliau, setelah itu beliau menghadapkan wajahnya ke arah kami sambil bersabda: \"Demi Dzat yang jiwa Muhammad berada di tangannya, seandainya kalian tahu apa yang aku ketahui dalam masalah meminta-minta, niscaya tidak akan ada seorangpun yang meminta kepada orang lain, sementara dirinya masih bisa untuk bermalam, \" lalu beliau memerintahkan untuk memberi makan kepada orang tersebut.\""},"2735":{"ar":"حَدَّثَنَا يُونُسُ وَعَبْدُ الصَّمَدِ قَالَا ثَنَا أَبُو الْأَشْهَبِ حَدَّثَنَا عَامِرٌ الْأَحْوَلُ قَالَ عَبْدُ الصَّمَدِ شَيْخٌ لَهُ عَنْ عَائِذِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَبْدُ الصَّمَدِ أَحْسَبُهُ رَفَعَهُ قَالَ مَنْ عَرَضَ لَهُ شَيْءٌ مِنْ هَذَا الرِّزْقِ وَقَالَ يُونُسُ مِنْ غَيْرِ مَسْأَلَةٍ وَلَا إِشْرَافٍ فَلْيُوَسِّعْ بِهِ فِي رِزْقِهِ فَإِنْ كَانَ عَنْهُ غَنِيًّا فَلْيُوَجِّهْهُ إِلَى مَنْ هُوَ أَحْوَجُ إِلَيْهِ مِنْهُ","id":"Telah menceritakan kepada kami [Yunus] dan [Abdushamad], keduanya berkata; telah menceritakan kepada kami [Abul Asyhab], telah menceritakan kepada kami [Amir Al Ahwal], syaikhnya Abdushamad, dari [A'idz bin 'Amru] dari Nabi Shalallahu 'Alaihi Wasallam. - [Abdushamad] mengatakan; aku kira hadits ini marfu'- bahwa Nabi Shalallahu 'Alaihi Wasallam bersabda: \"Barangsiapa mendapatkan sesuatu dari anugerah ini (rizqi) tanpa meminta-minta dan berlebihan, hendaklah ia berlapang-lapang dengan rizqinya, jika dia tidak membutuhkannya lagi, hendaknya ia berikan kepada orang yang lebih membutuhkannya.\""},"2736":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ عَامِرٍ الْأَحْوَلِ قَالَ قَالَ عَائِذُ بْنُ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ عَرَضَ لَهُ شَيْءٌ مِنْ هَذَا الرِّزْقِ مِنْ غَيْرِ مَسْأَلَةٍ وَلَا إِشْرَافٍ فَلْيُوَسِّعْ بِهِ فِي رِزْقِهِ فَإِنْ كَانَ عَنْهُ غَنِيًّا فَلْيُوَجِّهْهُ إِلَى مَنْ هُوَ أَحْوَجُ إِلَيْهِ مِنْهُ","id":"Telah menceritakan kepada kami [Hasan bin Musa], telah menceritakan kepada kami [Abul Asyhab] dari [Amir Al Ahwal] ia berkata; [A'idz bin 'Amru] berkata dari Nabi Shalallahu 'Alaihi Wasallam, beliau bersabda: \"Barangsiapa mendapatkan sesuatu dari anugerah ini (rizqi) tanpa meminta-minta dan berlebihan, hendaklah ia berlapang-lapang dengan rizqinya, jika dia tidak membutuhkannya lagi, hendaknya ia berikan kepada orang yang lebih membutuhkannya.\""},"2737":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو الْأَشْهَبِ عَنْ عَامِرٍ الْأَحْوَلِ عَنْ عَائِذِ بْنِ عَمْرٍو قَالَ أَبُو الْأَشْهَبِ أُرَاهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ آتَاهُ اللَّهُ تَبَارَكَ وَتَعَالَى رِزْقًا مِنْ غَيْرِ مَسْأَلَةٍ فَلْيَقْبَلْهُقَالَ عَبْد اللَّهِ سَأَلْتُ أَبِي مَا الْإِشْرَافُ قَالَ تَقُولُ فِي نَفْسِكَ سَيَبْعَثُ إِلَيَّ فُلَانٌ سَيَصِلُنِي فُلَانٌ","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Abul Asyhab] dari ['Amir Al Ahwal] dari [A'idz bin 'Amru] dia berkata; bahwa [Abul `Asyhab] berkata; aku kira dia mengatakan; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Barangsiapa dianugerahi rizqi oleh Allah Tabaraka wa Ta'ala tanpa meminta-minta, maka terimalah.\" Abdullah berkata; Aku bertanya kepada ayahku \"Apa yang dimaksud dengan Isyraf?\" ayahku menjawab; \"Yaitu kamu mengatakan pada dirimu \"si Fulan akan mengirimku, si Fulan akan menghampiriku.\""},"2738":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُشْمَعِلُّ بْنُ إِيَاسٍ قَالَ سَمِعْتُ عَمْرَو بْنَ سُلَيْمٍ الْمُزَنِيَّ يَقُولُ سَمِعْتُ رَافِعَ بْنَ عَمْرٍو الْمُزَنِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى ال��َّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعَجْوَةُ وَالصَّخْرَةُ مِنْ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Musyma'il bin Iyas], ia berkata; Aku mendengar ['Amru bin Sulaim] ia berkata; Aku mendengar [Rafi' bin 'Amru Al Muzanni] berkata; Aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Ajwah (kurma terbaik) dan Shahrah (batu yang berada di Baitul Maqdis) berasal dari surga.\""},"2739":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ عَنْ عَاصِمٍ قَالَ ثَنَا أَبُو الْعَالِيَةِ قَالَ أَخْبَرَنِي مَنْ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُلِكُلِّ سُورَةٍ حَظُّهَا مِنْ الرُّكُوعِ وَالسُّجُودِقَالَ ثُمَّ لَقِيتُهُ بَعْدُ فَقُلْتُ لَهُ إِنَّ ابْنَ عُمَرَ كَانَ يَقْرَأُ فِي الرَّكْعَةِ بِالسُّوَرِ فَتَعْرِفُ مَنْ حَدَّثَكَ هَذَا الْحَدِيثَ قَالَ إِنِّي لَأَعْرِفُهُ وَأَعْرِفُ مُنْذُ كَمْ حَدَّثَنِيهِ حَدَّثَنِي مُنْذُ خَمْسِينَ سَنَةٍ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id Al Umawi] dari ['Ashim] ia berkata; telah menceritakan kepada kami [Abul 'Aliyah] ia berkata; telah mengabarkan kepadaku [seseorang yang mendengar Rasulullah] Shallalahu 'Alaihi Wasallam bersabda: \"Setiap surat ada haknya di waktu sujud dan ruku'.\" Perawi berkata; \"Kemudian aku bertemu dengan orang tersebut, lalu aku mengatakan kepadanya bahwa Ibnu Umar telah membaca surat-surat (dari Al qur`an di tiap raka'atnya, \"Siapa yang menceritakan hadits ini padamu?.\" Laki-laki itu berkata; \"Sungguh aku telah mengetahuinya dan aku tahu semenjak hadits itu disampaikan yaitu sejak lima puluh tahun.\""},"2740":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ قَالَرُبَّمَا أَمَّنَا ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا بِالسُّورَتَيْنِ وَالثَّلَاثِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dia berkata; \"Mungkin saja [Ibnu Umar] radliallahu 'anhu mengimmi kami dengan dua surat atau tiga surat.\""},"2741":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَاسْتُعْمِلَ الْحَكَمُ بْنُ عَمْرٍو الْغِفَارِيُّ عَلَى خُرَاسَانَ قَالَ فَتَمَنَّاهُ عِمْرَانُ بْنُ حُصَيْنٍ حَتَّى قِيلَ لَهُ يَا أَبَا نُجَيْدٍ أَلَا نَدْعُوهُ لَكَ قَالَ لَا فَقَامَ عِمْرَانُ بْنُ حُصَيْنٍ فَلَقِيَهُ بَيْنَ النَّاسِ قَالَ تَذْكُرُ يَوْمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا طَاعَةَ لِمَخْلُوقٍ فِي مَعْصِيَةِ اللَّهِ قَالَ نَعَمْقَالَ عِمْرَانُ اللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb], telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] dia berkata; [Al Hakam bin 'Amru Al Ghifari] pernah di utus ke daerah Khurasan, Muhammad berkata; \"Maka Imran bin Hushain termenung hingga dikatakan kepadanya; \"Wahai Abu Nujaid (panggilan Imran), perlukah kami memanggilkan untukmu?.\" dia menjawab; \"Tidak, \" lalu [Imran bin Hushain] berdiri dan menemuinya di antara kerumunan orang-orang, dia berkata; \"Ingatkah kamu pada hari Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tidak ada ketaatan kepada mahluk dalam bermaksiat kepada Allah?\" dia menjawab; \"Ya.\" Imran berkata; \"Allahu akbar.\""},"2742":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدٌ يَعْنِي ابْنَ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ قَالَأَرَادَ زِيَادٌ أَنْ يَبْعَثَ عِمْرَانَ بْنَ حُصَيْنٍ عَلَى خُرَاسَانَ فَأَبَى عَلَيْهِمْ فَقَالَ لَهُ أَصْحَابُهُ أَتَرَكْتَ خُرَاسَانَ أَنْ تَكُونَ عَلَيْهَا قَالَ فَقَالَ إِنِّي وَاللَّهِ مَا يَسُرُّنِي أَنْ أُصَلِّيَ بِحَرِّهَا وَتُصَلُّونَ بِبَرْدِهَا إِنِّي أَخَافُ إِذَا كُنْتُ فِي نُحُورِ الْعَدُوِّ أَنْ يَأْتِيَنِي كِتَابٌ مِنْ زِيَادٍ فَإِنْ أَنَا مَضَيْتُ هَلَكْتُ وَإِنْ رَجَعْتُ ضُرِبَتْ عُنُقِي قَالَ فَأَرَادَ الْحَكَمَ بْنَ عَمْرٍو الْغِفَارِيَّ عَلَيْهَا قَالَ فَانْقَادَ لِأَمْرِهِ قَالَ فَقَالَ عِمْرَانُ أَلَا أَحَدٌ يَدْعُو لِي الْحَكَمَ قَالَ فَانْطَلَقَ الرَّسُولُ قَالَ فَأَقْبَلَ الْحَكَمُ إِلَيْهِ قَالَ فَدَخَلَ عَلَيْهِ قَالَ فَقَالَ عِمْرَانُ لِلْحَكَمِ أَسَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا طَاعَةَ لِأَحَدٍ فِي مَعْصِيَةِ اللَّهِ تَبَارَكَ وَتَعَالَى قَالَ نَعَمْفَقَالَ عِمْرَانُ لِلَّهِ الْحَمْدُ أَوْ اللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Sulaiman bin Mughirah], telah menceritakan kepada kami [Humaid yaitu Ibnu Hilal] dari [Abdulah bin Shamit] ia berkata; Ziyad pernah menunjuk 'Imran bin Hushain untuk mengurusi daerah Khurasan, namun ia menolaknya, lantas para sahabatnya berkata padanya; \"Akankah engkau tinggalkan khurasan dan engkau tiada akan ke sana?.\" 'Imran menjawab; \"Demi Allah, aku tiada hendak melaksanakan shalat di musim panasnya sedang kalian shalat di musim dingin, aku takut bila aku berada pada pertempuran dengan musuh, lalu datanglah surat dari Ziyad, bila aku teruskan maka aku akan hancur dan bila aku pulang maka aku akan mati.\" Perawi berkata; Maka Hakam bin Amru Al Ghifari bermaksud menerima tawaran itu, setelah itu Hakam berangkat melaksanakann titah Ziyad, 'Imran berkata; \"Adakah seseorang yang mau memanggilkan Al Hakam?, lalu datanglah seorang utusan hingga bertemu dengan Al Hakam, lalu Al Hakam menemui Imran. Lalu ['Imran] berkata kepada [Al Hakam]; \"Tidakkah engkau mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tiada ketaatan bagi seseorang dalam bermaksiat pada Allah Tabaraka Wata'ala?.\" Hakam menjawab; \"Ya.\" ['Imran] langsung berkata; \"Segala piuji bagi Allah\" atau \"Allahu Akbar.\""},"2743":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي حَاجِبٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَنِي غِفَارٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَتَوَضَّأَ الرَّجُلُ مِنْ فَضْلِ طَهُورِ الْمَرْأَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Sulaiman At Taimi] dari [Abu Hajib] dari [seseorang sahabat Nabi] Shalallahu 'Alaihi Wasallam dari bani Ghifar bahwa Rasulullah Shallalahu 'Alaihi Wasallam melarang seseorang berwudhu' dari sisa air wudlu' wanita.\""},"2744":{"ar":"حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ هَارُونَ أَخْبَرَنَا هِشَامٌ عَنْ مُحَمَّدٍ قَالَجَاءَ رَجُلٌ إِلَى عِمْرَانَ بْنِ حُصَيْنٍ وَنَحْنُ عِنْدَهُ فَقَالَ اسْتُعْمِلَ الْحَكَمُ بْنُ عَمْرٍو الْغِفَارِيُّ عَلَى خُرَاسَانَ فَتَمَنَّاهُ عِمْرَانُ حَتَّى قَالَ لَهُ رَجُلٌ مِنْ الْقَوْمِ أَلَا نَدْعُوهُ لَكَ فَقَالَ لَهُ لَا ثُمَّ قَامَ عِمْرَانُ فَلَقِيَهُ بَيْنَ النَّاسِ فَقَالَ عِمْرَانُ إِنَّكَ قَدْ وُلِّيتَ أَمْرًا مِنْ أَمْرِ الْمُسْلِمِينَ عَظِيمًا ثُمَّ أَمَرَهُ وَنَهَاهُ وَوَعَظَهُ ثُمَّ قَالَ هَلْ تَذْكُرُ يَوْمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا طَاعَةَ لِمَخْلُوقٍ فِي مَعْصِيَةِ اللَّهِ تَبَارَكَ وَتَعَالَى قَالَ الْحَكَمُ نَعَمْقَالَ عِمْرَانُ اللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Yazid] yaitu Ibnu Harun, telah mengabarkan kepada kami [Hisyam] dari [Muhammad] ia berkata; \"Seseorang datang menmui ['Imran bin Hushain], ketika itu kami tengah bersamanya, orang itu mengatakan bahwa [Al Hakam bin Amru Al Ghifari] di utus menuju daerah Khurasan, tiba-tiba Imran termenung, hingga seseorang berkata kepadanya; \"Perlukah kami memanggilkannya untukmu?.\" dia menjawab; \"Tidak, \" lalu Imran berdiri dan menemuinya di antara kerumunan orang-orang, [Imran] berkata; \"Ingatkah kamu pada hari Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tidak ada ketaatan kepada mahluk dalam bermaksiat kepada Allah Tabaraka wa Ta'ala?\" Al Hakam menjawab; \"Ya.\" Imran berkata; \"Allahu Akbar.\""},"2745":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَ سَمِعْتُ أَبَا حَاجِبٍ يُحَدِّثُ عَنِ الْحَكَمِ بْنِ عَمْرٍو الْغِفَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَتَوَضَّأَ الرَّجُلُ مِنْ فَضْلِ وَضُوءِ الْمَرْأَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud]; telah menceritakan kepada kami [Syu'bah] dari ['Ashim Al Ahwal] berkata; \"Aku mendengar [Abu Hajib] menceritakan dari [Al Hakam bin 'Amru Al Ghifari] bahwa Rasulullah Shallalahu 'Alaihi Wasallam melarang seseorang berwudhu' dari bekas air wudlu' wanita.\""},"2746":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ إِبْرَاهِيمَ قَالَسَأَلْتُ مُحَمَّدًا عَنْ حَدِيثِ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ نُبِّئْتُ أَنَّ عِمْرَانَ بْنَ حُصَيْنٍ قَالَ لِلْحَكَمِ الْغِفَارِيِّ وَكِلَاهُمَا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تَعْلَمُ يَوْمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا طَاعَةَ فِي مَعْصِيَةِ اللَّهِ تَبَارَكَ وَتَعَالَى قَالَ نَعَمْقَالَ عِمْرَانُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ","id":"Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Yazid yaitu Ibnu Ibrahim] ia berkata; Aku bertanya kepada [Muhammad] tentang hadits 'Imran bin Hushain, ia; [telah diberitakan kepadaku] bahwa ['Imran bin Hushain] berkata kepada [Al Hakam Al Ghifari] -keduanya adalah sahabat Rasulullah Shallalahu 'Alaihi Wasallam- \"Apakah kamu ingat hari ketika Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tidak ada ketaatan kepada mahluk dalam bermaksiat kepada Allah Tabaraka wa Ta'ala?\" Al Hakam menjawab; \"Ya\" [Imran] berkata; \"Allahu Akbar, Allahu Akbar.\""},"2747":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا يُونُسُ وَحُمَيْدٌ عَنِ الْحَسَنِأَنَّ زِيَادًا اسْتَعْمَلَ الْحَكَمَ الْغِفَارِيَّ عَلَى جَيْشٍ فَأَتَاهُ عِمْرَانُ بْنُ حُصَيْنٍ فَلَقِيَهُ بَيْنَ النَّاسِ فَقَالَ أَتَدْرِي لِمَ جِئْتُكَ فَقَالَ لَهُ لِمَ قَالَ هَلْ تَذْكُرُ قَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلرَّجُلِ الَّذِي قَالَ لَهُ أَمِيرُهُ قَعْ فِي النَّارِ فَأَدْرَكَ فَاحْتَبَسَ فَأُخْبِرَ بِذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ وَقَعَ فِيهَا لَدَخَلَا النَّارَ جَمِيعًا لَا طَاعَةَ فِي مَعْصِيَةِ اللَّهِ تَبَارَكَ وَتَعَالَى قَالَ نَعَمْ قَالَ إِنَّمَا أَرَدْتُ أَنْ أُذَكِّرَكَ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Yunus] dan [Humaid] dari [Al Hasan] bahwa Ziyad menunjuk [Al Hakam Al Ghifari] untuk membawahi sekelmpok pasukan, lalu ['Imran bin Hushain] datang menemuinya diantara kerumunan orang-orang, Imran berkata; \"Tahukah kamu, kenapa aku menemuimu?.\" Hakam menimpali; \"Memangnya ada apa?\" 'Imran berkata; \"Apakah engkau ingat ketika Rasulullah Shallalahu 'Alaihi Wasallam bersabda pada seseorang yang disuruh oleh pemimpinnya; \"Terjunlah kamu ke api!, orang itu berfikir dan menahan diri darinya, setelah kejadian tersebut dilaporkan kepada Rasulullah Shallalahu 'Alaihi Wasallam, beliau bersabda: \"Sekiranya ia sampai masuk ke dalam api, niscaya mereka semua akan masuk ke dalam neraka, tidak ada ketaatan kepada mahluk dalam bermaksiat kepada Allah Tabaraka wa Ta'ala?\" Hakam menjawab; \"Ya.\" Imran berkata; \"Aku hanya ingin mengingatkanmu tantang hadits ini.\""},"2748":{"ar":"حَدَّثَنَا هَاشِمٌ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ حَبِيبِ بْنِ عَبْدِ اللَّهِ الْأَزْدِيُّ قَالَ حَدَّثَنِي أَبِي عَنِ الْحَكَمِ بْنِ عَمْرٍو الْغِفَارِيِّ قَالَدَخَلْتُ أَنَا وَأَخِي رَافِعُ بْنُ عَمْرٍو عَلَى أَمِيرِ الْمُؤْمِنِينَ عُمَرَ بْنِ الْخَطَّابِ وَأَنَا مَخْضُوبٌ بِالْحِنَّاءِ وَأَخِي مَخْضُوبٌ بِالصُّفْرَةِ فَقَالَ لِي عُمَرُ بْنُ الْخَطَّابِ هَذَا خِضَابُ الْإِسْلَامِ وَقَالَ لِأَخِي رَافِعٍ هَذَا خِضَابُ الْإِيمَانِ","id":"Telah menceritakan kepada kami [Hasyim], telah menceritakan kepada kami [Abdushamad bin Habib bin Abdullah Al Azdi] ia berkata; telah menceritakan kepada kami [Ayahku], dari [Al Hakam bin 'Amru Al Ghifari] dia berkata; \"Aku dan saudaraku yaitu Rafi' bin Amru masuk menemui Amirul mukminin [Umar bin Al Khattab], ketika itu aku tengah mewarnai (rambutku) dengan inai, sedangkan saudaraku mewarnai (rambutnya) dengan Za'faran, lalu Umar bin Al Khattab berkata kepadaku; \"Ini adalah pewarna Islam, \" dia berkata kepada saudaraku; \"Ini adalah pewarna Iman.\""},"2749":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ غَيْرِ وَاحِدٍ مِنْهُمْ أَيُّوبُ عَنِ ابْنِ سِيرِينَأَنَّ زِيَادًا اسْتَعْمَلَ الْحَكَمَ بْنَ عَمْرٍو الْغِفَارِيَّ فَقَالَ عِمْرَانُ بْنُ حُصَيْنٍ وَدِدْتُ أَنِّي أَلْقَهُ قَبْلَ أَنْ يَخْرُجَ قَالَ فَلَقِيَهُ فَقَالَ لَهُ عِمْرَانُ أَمَا عَلِمْتَ أَوَمَا سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا طَاعَةَ لِأَحَدٍ فِي مَعْصِيَةِ اللَّهِ تَبَارَكَ وَتَعَالَى قَالَ بَلَى قَالَ فَذَاكَ الَّذِي أَرَدْتُ أَنْ أَقُولَ لَكَ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Ma'mar] dari beberapa sumber, diantaranya [Ayyub] dari [Ibnu Sirin] bahwa Ziyad pernah mengutus [Al Hakam bin 'Amru Al Ghifari], maka 'Imran bin Hushain berkata; \"Aku ingin bertemu dengannya sebelum ia berangkat.\" Ibnu Sirin berkata; \"Lalu [Imran] menemuinya dan berkata padanya; \"Tidakkah kamu kamu ingat atau mendengar ketika Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tidak ada ketaatan kepada mahluk dalam bermaksiat kepada Allah Tabaraka wa Ta'ala?\" dia menjawab; \"Tentu.\" Imran berkata; \"Begitulah, aku hanya ingin mengatakan hal itu kepadamu.\""},"2750":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْأَسْوَدُ بْنُ شَيْبَانَ عَنْ أَبِي نَوْفَلِ بْنِ أَبِي عَقْرَبٍ عَنْ أَبِيهِأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فَقَالَ صُمْ يَوْمًا مِنْ كُلِّ شَهْرٍ فَاسْتَزَادَهُ فَقَالَ بِأَبِي وَأُمِّي إِنِّي أَجِدُنِي أَقْوَى فَزِدْنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَجِدُنِي قَوِيًّا إِنِّي أَجِدُنِي قَوِيًّا فَمَا كَانَ أَنْ يَزِيدَهُ فَاسْتَزَادَهُ فَقَالَ صُمْ يَوْمَيْنِ مِنْ كُلِّ شَهْرٍ قَالَ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ إِنِّي أَجِدُنِي قَوِيًّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَجِدُنِي قَوِيًّا إِنِّي أَجِدُنِي قَوِيًّا فَمَا كَانَ أَنْ يَزِيدَهُ فَلَمَّا أَلْحَمَ عَلَيْهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan kepada kami [Al Aswad bin Syaiban] dari [Abu Naufal bin Abu 'Aqrab] dari [Ayahnya] bahwa ia bertanya kepada Nabi Shalallahu 'Alaihi Wasallam tentang puasa, lalu beliau bersabda: \"Berpuasalah sehari setiap bulan.\" Namun ia minta tambah, seraya berkata; 'Bapak dan ibuku sebagai tebusannya, aku masih kuat -melakukan lebih dari itu-.' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sungguh aku masih kuat, sungguh aku masih kuat.' Hampir saja beliau tidak menambahkan untuknya. Namun dia tetap Lalu beliau menambahinya seraya bersabda: 'Berpuasalah dua hari setiap bulan.' ia berkata; 'Bapak dan ibuku sebagai tebusannya, wahai Rasulullah, sungguh aku masih kuat! ' Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sungguh aku masih kuat, sungguh aku masih kuat.' Hampir saja beliau tidak menambahkan untuknya. Setelah ia mendesak terus, Rasulullah shallallahu 'alaihi wasallam bersabda: 'Berpuasalah tiga hari setiap bulan.'"},"2751":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا الْأَسْوَدُ بْنُ شَيْبَانَ قَالَ سَمِعْتُ أَبَا نَوْفَلِ بْنَ أَبِي عَقْرَبٍ يَقُولُسَأَلَ أَبِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فَقَالَ صُمْ يَوْمًا مِنْ كُلِّ شَهْرٍ فَقَالَ يَا رَسُولَ اللَّهِ بِأَبِي وَأُمِّي زِدْنِي قَالَ يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زِدْنِي زِدْنِي صُمْ يَوْمَيْنِ مِنْ كُلِّ شَهْرٍ فَقَالَ يَا رَسُولَ اللَّهِ بِأَبِي وَأُمِّي زِدْنِي فَإِنِّي أَجِدُنِي قَوِيًّا قَالَ يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَجِدُنِي قَوِيًّا إِنِّي أَجِدُنِي قَوِيًّا إِنِّي أَجِدُنِي قَوِيًّا قَالَ فَأَلْحَمَ أَيْ أَمْسَكَ حَتَّى ظَنَنْتُ أَنَّهُ لَنْ يَزِيدَنِي قَالَ ثُمَّ قَالَ صُمْ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah menceritakan kepada kami ['Affan], telah mengabarkan kepada kami [Al Aswad bin Syaiban] ia berkata; aku mendengar [Abu Naufal bin Abu 'Aqrab] berkata; [Ayahku] bertanya kepada Nabi Shalallahu 'Alaihi Wasallam tentang puasa, lalu beliau bersabda: \"Puasalah sehari setiap bulan!.\" Lalu ia meminta tambah seraya berkata; \"Wahai Rasulullah, demi ayah dan ibuku, aku lebih kuat -melakukan lebih dari itu- maka tambahkanlah untukku!.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"tambahkan, tambahkan, berpuasalah dua hari setiap bulan.\" Dia berkata lagi; \"Wahai Rasulullah, demi ayah dan ibuku, tambahkanlah untukku, karena aku lebih kuat -melakukan lebih dari itu-.\" Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sungguh aku masih kuat, sungguh aku masih kuat, sungguh aku masih kuat.' Beliau tetap mendesak maksudnya menahan hingga aku menyangka beliau tidak akan menambahkan lagi untukku, \" ayahku berkata; \"Kemudian beliau bersabda: \"Puasalah tiga hari setiap bulan.\""},"2752":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ عَنْ حُمَيْدٍ يَعْنِي ابْنَ هِلَالٍ قَالَكَانَ رَجُلٌ مِنْ الطُّفَاوَةِ طَرِيقُهُ عَلَيْنَا فَأَتَى عَلَى الْحَيِّ فَحَدَّثَهُمْ قَالَ قَدِمْتُ الْمَدِينَةَ فِي عِيرٍ لَنَا فَبِعْنَا بِيَاعَتَنَا ثُمَّ قُلْتُ لَأَنْطَلِقَنَّ إِلَى هَذَا الرَّجُلِ فَلَآتِيَنَّ مَنْ بَعْدِي بِخَبَرِهِ قَالَ فَانْتَهَيْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ يُرِينِي بَيْتًا قَالَ إِنَّ امْرَأَةً كَانَتْ فِيهِ فَخَرَجَتْ فِي سَرِيَّةٍ مِنْ الْمُسْلِمِينَ وَتَرَكَتْ ثِنْتَيْ عَشْرَةَ عَنْزًا لَهَا وَصِيصِيَتَهَا كَانَتْ تَنْسِجُ ��ِهَا قَالَ فَفَقَدَتْ عَنْزًا مِنْ غَنَمِهَا وَصِيصِيَتَهَا فَقَالَتْ يَا رَبِّ إِنَّكَ قَدْ ضَمِنْتَ لِمَنْ خَرَجَ فِي سَبِيلِكَ أَنْ تَحْفَظَ عَلَيْهِ وَإِنِّي قَدْ فَقَدْتُ عَنْزًا مِنْ غَنَمِي وَصِيصِيَتِي وَإِنِّي أَنْشُدُكَ عَنْزِي وَصِيصِيَتِي قَالَ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ شِدَّةَ مُنَاشَدَتِهَا لِرَبِّهَا تَبَارَكَ وَتَعَالَى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَصْبَحَتْ عَنْزُهَا وَمِثْلُهَا وَصِيصِيَتُهَا وَمِثْلُهَا وَهَاتِيكَ فَأْتِهَا فَاسْأَلْهَا إِنْ شِئْتَ قَالَ قُلْتُ بَلْ أُصَدِّقُكَ","id":"Telah menceritakan kepada kami [Abdushamad bin Abdul Warits], telah menceritakan kepada kami [Sulaiman yaitu Ibnu Mughirah] dari [Humaid yaitu Ibnu Hilal] dia berkata; [Seorang lelaki] dari Thufawithah yang jalannya melewati (tempat) kami, kemudian dia datang ke perkampungan dan bercerita kepada penduduk kampung, dia berkata; \"Aku tiba di Madinah dengan kafilah dagang kami, kemudian kami menjual barang dagangan kami, lalu aku berkata; \"Aku harus pergi menemui laki-laki ini, supaya orang setelahku datang membawa berita tentang dia, \" laki-laki itu berkata; \"Kemudian aku sampai kepada Rasulullah Shallalahu 'Alaihi Wasallam dan beliau memperlihatkan kepadaku suatu rumah.\" Beliau bersabda: \"Sesungguhnya di dalamnya ada seorang wanita, dia keluar ikut dalam pasukan kaum muslimin dan meinggalkan dua belas kambing miliknya dan tali-tali yang dia gunakan untuk memintal, beliau melanjutkan: \"Kemudian salah satu kambingnya dan alat pintalnya juga hilang, lalu dia berkata; \"Wahai Rabbku, sesungguhnya Engkau telah menjamin bagi orang yang keluar berperang di jalan-Mu bahwa Engkau akan menjaganya, dan sesungguhnya aku telah kehilangan seekor kambing dan alat pintalku, dan sesungguhnya aku mengadukan perihal kambing dan alat pintalku kepadaMu.\" Laki-laki itu melanjutkan; \"Maka Rasulullah Shallalahu 'Alaihi Wasallam menyebutkan kesungguhan (keseriusan) wanita itu dalam mengadu kepada Rabbnya Tabaraka Wata'ala.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Maka wanita itu menemukan kambingnya dengan yang semisalnya dan menemukan alat pintalnya dengan yang semisalnya.\" Dan inilah, aku telah beritakan maka datangilah wanita itu dan tanyakan padanya jika kamu menghendaki!.\" Laki-laki itu berkata; \"Maka aku menjawab: \"Bahkan aku sudah percaya kepadamu.\""},"2753":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا ذَيَّالُ بْنُ عُبَيْدِ بْنِ حَنْظَلَةَ قَالَ سَمِعْتُ حَنْظَلَةَ بَنَ حِذْيَمٍ جَدِّيأَنَّ جَدَّهُ حَنِيفَةَ قَالَ لِحِذْيَمٍ اجْمَعْ لِي بَنِيَّ فَإِنِّي أُرِيدُ أَنْ أُوصِيَ فَجَمَعَهُمْ فَقَالَ إِنَّ أَوَّلَ مَا أُوصِي أَنَّ لِيَتِيمِي هَذَا الَّذِي فِي حِجْرِي مِائَةً مِنْ الْإِبِلِ الَّتِي كُنَّا نُسَمِّيهَا فِي الْجَاهِلِيَّةِ الْمُطَيَّبَةَ فَقَالَ حِذْيَمٌ يَا أَبَتْ إِنِّي سَمِعْتُ بَنِيكَ يَقُولُونَ إِنَّمَا نُقِرُّ بِهَذَا عِنْدَ أَبِينَا فَإِذَا مَاتَ رَجَعْنَا فِيهِ قَالَ فَبَيْنِي وَبَيْنَكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ حِذْيَمٌ رَضِينَا فَارْتَفَعَ حِذْيَمٌ وَحَنِيفَةُ وحَنْظَلَةُ مَعَهُمْ غُلَامٌ وَهُوَ رَدِيفٌ لِحِذْيَمٍ فَلَمَّا أَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَّمُوا عَلَيْهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا رَفَعَكَ يَا أَبَا حِذْيَمٍ قَالَ هَذَا وَضَرَبَ بِيَدِهِ عَلَى فَخِذِ حِذْيَمٍ فَقَالَ إِنِّي خَشِيتُ أَنْ يَفْجَأَنِي الْكِبَرُ أَوْ الْمَوْتُ فَأَرَدْتُ أَنْ أُوصِيَ وَإِنِّي قُلْتُ إِنَّ أَوَّلَ مَا أُوصِي أَنَّ لِيَتِيمِي هَذَا الَّذِي فِي حِجْرِي مِائَةً مِنْ الْإِبِلِ كُنَّا نُسَمِّيهَا فِي الْجَاهِلِيَّةِ الْمُطَيَّبَةَ فَغَضِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى رَأَيْنَا الْغَضَبَ فِي وَجْهِهِ وَكَانَ قَاعِدًا فَجَثَا عَلَى رُكْبَتَيْهِ وَقَالَ لَا لَا لَا الصَّدَقَةُ خَمْسٌ وَإِلَّا فَعَشْرٌ وَإِلَّا فَخَمْسَ عَشْرَةَ وَإِلَّا فَعِشْرُونَ وَإِلَّا فَخَمْسٌ وَعِشْرُونَ وَإِلَّا فَثَلَاثُونَ وَإِلَّا فَخَمْسٌ وَثَلَاثُونَ فَإِنْ كَثُرَتْ فَأَرْبَعُونَ قَالَ فَوَدَعُوهُ وَمَعَ الْيَتِيمِ عَصًا وَهُوَ يَضْرِبُ جَمَلًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَظُمَتْ هَذِهِ هِرَاوَةُ يَتِيمٍ قَالَ حَنْظَلَةُ فَدَنَا بِي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ لِي بَنِينَ ذَوِي لِحًى وَدُونَ ذَلِكَ وَإِنَّ ذَا أَصْغَرُهُمْ فَادْعُ اللَّهَ لَهُ فَمَسَحَ رَأْسَهُ وَقَالَ بَارَكَ اللَّهُ فِيكَ أَوْ بُورِكَ فِيهِقَالَ ذَيَّالٌ فَلَقَدْ رَأَيْتُ حَنْظَلَةَ يُؤْتَى بِالْإِنْسَانِ الْوَارِمِ وَجْهُهُ أَوْ الْبَهِيمَةِ الْوَارِمَةِ الضَّرْعُ فَيَتْفُلُ عَلَى يَدَيْهِ وَيَقُولُ بِسْمِ اللَّهِ وَيَضَعُ يَدَهُ عَلَى رَأْسِهِ وَيَقُولُ عَلَى مَوْضِعِ كَفِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَمْسَحُهُ عَلَيْهِ وَقَالَ ذَيَّالٌ فَيَذْهَبُ الْوَرَمُ","id":"Telah menceritakan kepada kami [Abu Sa'id] bekas budak bani Hasyim, telah menceritakan kepada kami [Dzayyal bin Ubaid bin Handzalah] ia berkata; saya mendengar [Hadzalah bin Hidzyam] kakekku, bahwa kakeknya yaitu Hanifah berkata kepada Hidzyam; \"Kumpulkan kepadaku anak-anakku, karena aku ingin berwasiat!.\" Lalu dia mengumpulkan mereka, kemudian Hanifah berkata; \"Sesungguhnya yang pertama kali aku wasiatkan untuk anak yatim yang menjadi tanggunganku adalah seratus ekor unta, yang pada masa Jahiliyah kami menamakannya dengan \"Al Muthayyabah.\" kemudian Hidzyam berkata; \"Wahai ayahku, sesungguhnya aku mendengar anak-anakmu mengatakan; \"Hanyasannya kami mengakui ini di sisi ayah kami, bila ia meninggal kami akan kembali (mengambil seratus unta).\" Ia berkata; \"Dan antara aku dan kalian ada Rasulullah Shallalahu 'Alaihi Wasallam (sebagai saksi).\" Judzyam berkata; \"Kami ridha.\" Setelah itu Hidzyam, Hanifah dan Handzalah bersama dengan seorang anak yang membonceng kendaraan Hidzyam beranjak pergi, hingga ketika mereka menjumpai Nabi Shalallahu 'Alaihi Wasallam, mereka memberi salam dan Nabi Shalallahu 'Alaihi Wasallam bersabda: \"Ada apa denganmu wahai Abu Hidzyam?.\" Abu Hidzam berkata; \"Ini.\" Sambil menepuk paha Hidzyam dengan tangannya. Ia berkata; \"Aku takut bila aku tua nanti atau kematian menjemputku, aku telah berwasiat dan aku telah mengatakan bahwa wasiat yang pertama aku sampaikan pada anak yatimku dengan memberikan seratus unta yang aku miliki, yang di masa jahiliyah kami menyebutnya dengan \"Al Muthayyibah.\" Maka Rasulullah Shallalahu 'Alaihi Wasallam marah hingga kami melihat kemarahan di wajah beliau, beliau lalu duduk sambil bertumpu pada lututnya seraya bersabda: \"Tidak, tidak, tidak, sedekah itu hanya seperlima, kalau tidak maka sepersepuluh, kalau tidak maka seperlima belas, kalau tidak maka seperduapuluh, kalau tidak maka seperdua puluh lima, kalau tidak maka sepertiga puluh, kalau tidak maka seper tiga puluh lima, dan bila hartanya banyak maka seperempat puluh.\" Lalu aku menitipkan kepada mereka dan aku berikan tongkat untuk memukul unta kepada si yatim. Lalu Nabi Shalallahu 'Alaihi Wasallam bersabda: \"Alangkah besar tongkat anak yatim ini.\" Handzalah berkata; \"Lalu aku mendekati Rasulullah Shallalahu 'Alaihi Wasallam dan mengadu; \"Sungguh aku punya banyak anak yang sudah dewasa dan selainnya dan mereka juga punya anak-anak mereka, maka berdo'alah pada Allah untuknya!.\" Maka beliau mengusap kepalanya dan bersabda: \"Barakallah fiik au burika fiihi (semoga Allah memberi keberkahan padamu atau diberkai padanya.\" [Dzayyal] berkata; \"Aku telah melihat [Handzalah] didatangkan seseorang yang wajahnya bengkak atau bintang yang susunya bengkak, lalu ia meludahi kedua tangannya dan berkata; \"Bismillah (dengan menyebut nama Allah) dan meletakkan tangannya di atas kepala orang atau binatang yang bengkak, dan mengucapkan sambil meletakkan tangannya persis di tempat tangan Rasulullah Shalallahu 'Alaihi Wasallam dahulu meletakkan, lalu beliau mengusapnya. Dzayyal berkata; \"Maka bengkaknya pun sembuh.\""},"2754":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ وَعَفَّانُ قَالَا ثَنَا رَبِيعَةُ بْنُ كُلْثُومٍ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ أَبَا غَادِيةَ يَقُولُبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو سَعِيدٍ فَقُلْتُ لَهُ بِيَمِينِكَ قَالَ نَعَمْ قَالَا جَمِيعًا فِي الْحَدِيثِ وَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْعَقَبَةِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ إِلَى يَوْمِ تَلْقَوْنَ رَبَّكُمْ عَزَّ وَجَلَّ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا هَلْ بَلَّغْتُ قَالُوا نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ ثُمَّ قَالَ أَلَا لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami [Abu Sa'id] dan ['Affan], keduanya berkata; telah menceritakan kepada kami [Rabi'ah bin Kultsum] telah menceritakan kepadaku [Ayahku] ia berkata; saya mendengar [Abu Ghadiyah] berkata; \"Aku berbai'at kepada Rasulullah Shallalahu 'Alaihi Wasallam, \" Abu Sa'id mengatakan; kemudian aku berkata kepadanya; \"Dengan sumpahmu kah?.\" Dia menjawab; \"Ya.\" Keduanya sama berkata dalam hadits mereka; \"Dan Rasulullah Shallalahu 'Alaihi Wasallam berkhutbah di hadapan kami pada hari Bai'at 'Aqabah, lalu beliau bersabda: \"Wahai manusia, sesungguhnya darah kalian dan harta kalian adalah haram atas kalian sampai kalian bertemu dengan Rabb kalian 'azza wajalla, sebagaimana haramnya hari kalian ini, di bulan kalian ini dan di negeri kalian ini, ketahuilah bukankah aku telah menyampaikan?.\" Para sahabat menjawab; \"ya\" beliau bersabda: \"Yaa Allah saksikanlah!.\" beliau melanjutkan: \"Ketahuilah, janganlah kalian kembali kepada kekafiran sepeninggalku, dengan saling membunuh satu sama lain.\""},"2755":{"ar":"حَدَّثَنَا يُونُسُ وَحُسَيْنٌ قَالَا ثَنَا شَيْبَانُ عَنْ قَتَادَةَ قَالَ وَجَدْتُ مِرْثَدَ بْنَ ظَبْيَانَ قَالَجَاءَنَا كِتَابٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا وَجَدْنَا لَهُ كَاتِبًا يَقْرَؤُهُ عَلَيْنَا حَتَّى قَرَأَهُ رَجُلٌ مِنْ بَنِي ضُبَيْعَةَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بَكْرِ بْنِ وَائِلٍ أَسْلِمُوا تَسْلَمُوا","id":"Telah menceritakan kepada kami [Yunus] dan [Husain] keduanya berkata; telah menceritakan kepada kami [Syaiban] dari [Qatadah] dia berkata; Aku mendapati [Mirtsad bin Dlabyan] berkata; telah datang kepada kami surat dari Rasulullah Shallalahu 'Alaihi Wasallam, dan kami tidak menemukan seorang penulis yang dapat membacakannya kepada kami, sampai seorang lelaki dari Bani Dlubai'ah membacanya; \"Dari Rasulullah Shallalahu 'Alaihi Wasallam kepada Bakar bin Wa`il, masuk Islamlah kalian niscaya kalian akan aman.\""},"2756":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ قَالَمَرِضَ رَجُلٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ عَلَيْهِ أَصْحَابُهُ يَعُودُونَهُ فَبَكَى فَقِيلَ لَهُ مَا يُبْكِيكَ يَا عَبْدَ اللَّهِ أَلَمْ يَقُلْ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْ مِنْ شَارِبِكَ ثُمَّ اقْرِرْهُ حَتَّى تَلْقَانِي قَالَ بَلَى وَلَكِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى قَبَضَ قَبْضَةً بِيَمِينِهِ فَقَالَ هَذِهِ لِهَذِهِ وَلَا أُبَالِ وَقَبْضَةً أُخْرَى يَعْنِي بِيَدِهِ الْأُخْرَى فَقَالَ هَذِهِ لِهَذِهِ وَلَا أُبَالِ فَلَا أَدْرِي فِي أَيِّ الْقَبْضَتَيْنِ أَنَا","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Sa'id Al Jurairi] dari [Abu Nadhrah] ia berkata; [Seorang sahabat Nabi] Shalallahu 'Alaihi Wasallam sakit hingga para sahabat berduyun-duyun menjenguknya, lalu ia menangis, dikatakan padanya; \"Apa yang menyebabkanmu menangis wahai Abdullah, bukankan Rasulullah Shallalahu 'Alaihi Wasallam telah bersabda padamu: \"Ambillah minummu hingga sembuh sampai kamu bertemu denganku!.\" Ia menjawab; \"Ya, tetapi aku pernah mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Sesungguhnya Allah telah mencabut nyawa dengan tangan kanan-Nya lalu berfirman: \"ini untuk ini dan Aku tidak peduli, \" lalu Dia mencabut yang lain dengan tangan-Nya yang lain dan berfirman: \"ini untuk ini dan Aku tidak peduli, \" dan aku tidak tahu aku akan dicabut dengan tangan yang mana.\""},"2757":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَار��ونَ أَخْبَرَنَا عَاصِمُ بْنُ هِلَالٍ حَدَّثَنَا غَاضِرَةُ بْنُ عُرْوَةَ الْفُقَيْمِيُّ حَدَّثَنِي أَبُو عُرْوَةَ قَالَكُنَّا نَنْتَظِرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ رَجِلًا يَقْطُرُ رَأْسُهُ مِنْ وُضُوءٍ أَوْ غُسْلٍ فَصَلَّى فَلَمَّا قَضَى الصَّلَاةَ جَعَلَ النَّاسُ يَسْأَلُونَهُ يَا رَسُولَ اللَّهِ أَعَلَيْنَا حَرَجٌ فِي كَذَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَيُّهَا النَّاسُ إِنَّ دِينَ اللَّهِ عَزَّ وَجَلَّ فِي يُسْرٍ ثَلَاثًا يَقُولُهَا وَقَالَ يَزِيدُ مَرَّةً جَعَلَ النَّاسُ يَقُولُونَ يَا رَسُولَ اللَّهِ مَا نَقُولُ فِي كَذَا مَا نَقُولُ فِي كَذَا","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami ['Ashim bin Hilal] telah mengabarkan kepada kami [Ghadirah bin Urwah Al Fuqaimi] telah menceritakan kepadaku [Abu 'Urwah] dia berkata; \"Kami tengah menunggu Nabi Shallalahu 'Alaihi Wasallam, tiba-tiba keluarlah seorang lelaki yang kepalanya basah karena berwudlu atau mandi, lalu dia shalat, seusai shalat orang-orang bertanya tentang dia; \"Wahai Rasulullah, apakah ada dosa bagi kami dalam hal ini?\" Rasulullah Shallalahu 'Alaihi Wasallam menjawab: \"Tidak, wahai sekalian manusia, sesungguhnya Agama Allah 'azza wajalla itu mudah.\" beliau mengatakannya hingga tiga kali, pada kesempatan yang lain [Yazid] mengatakan; \"Orang-orang berkata; \"Wahai Rasulullah, apa yang kami katakan dalam masalah ini, apa yang kami katakan dalam masalah ini.\""},"2758":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُبَيْدٍ الدِّيلِيُّ عَنْ عُدَيْسَةَ ابْنَةِ أُهْبَانَ بْنِ صَيْفِيٍّأَنَّهَا كَانَتْ مَعَ أَبِيهَا فِي مَنْزِلِهِ فَمَرِضَ فَأَفَاقَ مِنْ مَرَضِهِ ذَلِكَ فَقَامَ عَلِيُّ بْنُ أَبِي طَالِبٍ بِالْبَصْرَةِ فَأَتَاهُ فِي مَنْزِلِهِ حَتَّى قَامَ عَلَى بَابِ حُجْرَتِهِ فَسَلَّمَ وَرَدَّ عَلَيْهِ الشَّيْخُ السَّلَامَ فَقَالَ لَهُ عَلِيٌّ كَيْفَ أَنْتَ يَا أَبَا مُسْلِمٍ قَالَ بِخَيْرٍ فَقَالَ عَلِيٌّ أَلَا تَخْرُجُ مَعِي إِلَى هَؤُلَاءِ الْقَوْمِ فَتُعِينَنِي قَالَ بَلَى إِنْ رَضِيتَ بِمَا أُعْطِيكَ قَالَ عَلِيٌّ وَمَا هُوَ فَقَالَ الشَّيْخُ يَا جَارِيَةُ هَاتِ سَيْفِي فَأَخْرَجَتْ إِلَيْهِ غِمْدًا فَوَضَعَتْهُ فِي حِجْرِهِ فَاسْتَلَّ مِنْهُ طَائِفَةً ثُمَّ رَفَعَ رَأْسَهُ إِلَى عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ فَقَالَ إِنَّ خَلِيلِي عَلَيْهِ السَّلَام وَابْنَ عَمِّكَ عَهِدَ إِلَيَّ إِذَا كَانَتْ فِتْنَةٌ بَيْنَ الْمُسْلِمِينَ أَنْ اتَّخِذْ سَيْفًا مِنْ خَشَبٍ فَهَذَا سَيْفِي فَإِنْ شِئْتَ خَرَجْتُ بِهِ مَعَكَ فَقَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ لَا حَاجَةَ لَنَا فِيكَ وَلَا فِي سَيْفِكَ فَرَجَعَ مِنْ بَابِ الْحُجْرَةِ وَلَمْ يَدْخُلْ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Abdullah bin Ubaid Ad Daili] dari ['Udaisah binti Uhban bin Shaifi] bahwa dia pernah bersama [Ayahnya] di rumah, kemudian ayahnya sakit, setelah sembuh dari sakitnya, Ali bin Abu Thalib yang berada di Bashrah menjenguknya di rumah, ketika ia berdiri di depan pintu kamarnya, ia mengucapkan salam, maka orang tua itu menjawab salamnya, kemudian Ali bertanya kepadanya; \"Bagaimana kondsisimu wahai Abu Muslim?\" dia menjawab; \"Baik.\" Kemudian Ali berkata; \"Tidakkah kamu keluar bersamaku menemui orang-orang itu untuk menolongku?\" dia menjawab; \"Tentu, jika kamu ridla dengan apa yang aku berikan kepadamu.\" Ali berkata; \"Apakah itu?\" orang tua itu berkata; \"Wahai anakku, berikan pedangku.\" Lalu anak gadisnya mengeluarkan pedang yang masih dalam sarungnya kepadanya, lalu dia meletakkan di pangkuannya, maka sekelompok orang membuka pedang dengan hati-hati, lalu dia mengangkat kepalanya ke Ali radliallahu 'anhu dan berkata; \"Sesungguhnya kekasihku dan anak pamanmu telah menasehatiku, apabila terjadi fitnah di antara kaum muslimin supaya mengambil pedang dari kayu, maka ini adalah pedangku, jika kamu berkehendak aku keluar bersamamu dengan membawanya.\" Maka Ali radliallahu 'anhu menjawab; \"Kami tidak butuh kepada kamu dan kepada pedangmu.\" kemudian dia keluar kamar dan tidak masuk lagi.\""},"2759":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي عَمْرٍو الْقَسْمَلِيِّ عَنْ ابْنَةِ أُهْبَانَأَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ أَتَى أُهْبَانَ فَقَالَ مَا يَمْنَعُكَ مِنْ اتِّبَاعِي فَقَالَ أَوْصَانِي خَلِيلِي وَابْنُ عَمِّكِ يَعْنِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَتَكُونُ فِتَنٌ وَفُرْقَةٌ فَإِذَا كَانَ ذَلِكَ فَاكْسِرْ سَيْفَكَ وَاتَّخِذْ سَيْفًا مِنْ خَشَبٍ فَقَدْ وَقَعَتْ الْفِتْنَةُ وَالْفُرْقَةُ وَكَسَرْتُ سَيْفِي وَاتَّخَذْتُ سَيْفًا مِنْ خَشَبٍ وَأَمَرَ أَهْلَهُ حِينَ ثَقُلَ أَنْ يُكَفِّنُوهُ وَلَا يُلْبِسُوهُ قَمِيصًا قَالَ فَأَلْبَسْنَاهُ قَمِيصًا فَأَصْبَحْنَا وَالْقَمِيصُ عَلَى الْمِشْجَبِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu 'Amru Al Qasmali] dari [putrinya Uhban] bahwa Ali bin Abu Thalib datang menemui [Uhban] dan berkata; \"Apa yang menghalangimu tidak ikut denganku?.\" Uhban menjawab; \"Kekasihku dan anak pamanmu telah mewasiatkan kepadaku yaitu Rasulullah Shallalahu 'Alaihi Wasallam, beliau bersabda: \"Akan terjadi fitnah dan perpecahan, apabila hal itu telah terjadi, maka patahkanlah pedangmu dan buatlah pedang dari kayu.\" Sungguh saat ini telah terjadi fitnah dan perpecahan, dan aku telah mematahkan pedangku serta membuat pedang dari kayu, \" lalu Uhban menyuruh keluarganya untuk mengkafaninya dan tidak memakaikan gamis, setelah itu kami memakaikannya gamis, dan kami gantungkan gamis itu ke hangernya.\""},"2760":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ سَمِعْتُ الْحَسَنَ حَدَّثَنَا عَمْرُو بْنُ تَغْلِبَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهُ شَيْءٌ فَأَعْطَاهُ نَاسًا وَتَرَكَ نَاسًا وَقَالَ جَرِيرٌ أَعْطَى رِجَالًا وَتَرَكَ رِجَالًا قَالَ فَبَلَغَهُ عَنْ الَّذِينَ تَرَكَ أَنَّهُمْ عَتِبُوا وَقَالُوا قَالَ فَصَعِدَ الْمِنْبَرَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنِّي أُعْطِي نَاسًا وَأَدَعُ نَاسًا وَأُعْطِي رِجَالًا وَأَدَعُ رِجَالًا قَالَ عَفَّانُ قَالَ ذِي وَذِي وَالَّذِي أَدَعُ أَحَبُّ إِلَيَّ مِنْ الَّذِي أُعْطِي أُعْطِي أُنَاسًا لِمَا فِي قُلُوبِهِمْ مِنْ الْجَزَعِ وَالْهَلَعِ وَأَكِلُ قَوْمًا إِلَى مَا جَعَلَ اللَّهُ فِي قُلُوبِهِمْ مِنْ الْغِنَى وَالْخَيْرِ مِنْهُمْ عَمْرُو بْنُ تَغْلِبَ قَالَ وَكُنْتُ جَالِسًا تِلْقَاءَ وَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا أُحِبُّ أَنَّ لِي بِكَلِمَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُمْرَ النَّعَمِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Jarir bin Hazim] dia berkata; aku mendengar [Al Hasan], telah menceritakan kepada kami [Amr bin Taghlib] bahwa Rasulullah Shallalahu 'Alaihi Wasallam mendapat kiriman sesuatu, lalu beliau memberikannya kepada orang tertentu dan tidak beliau berikan kepada yang lain. Jarir mengatakan; \"Beliau memberikan kepada beberapa orang dan tidak memberikan kepada yang lain. Lantas sampailah berita kepada beliau tentang orang-orang yang tidak beliau beri bagian, mereka telah mencela dan ngomel. Maka beliau naik mimbar, setelah memuji Allah dan mengagungkanNya, beliau bersabda: \"Sesungguhnya aku memberikan kepada orang-orang tertentu dan tidak memberikan yang lain, aku memberikan kepada beberapa orang dan tidak memberikan kepada yang lain.\" 'Affan mengatakan; beliau bersabda: \"Memberi ini dan ini, dan orang yang tidak saya beri lebih aku cintai dari orang yang aku beri, aku memberikan kepada orang-orang itu karena di hati mereka ada keluh dan kesah, dan aku pasrahkan kepada ketetapan Allah dalam hati orang-orang yang merasa cukup dan baik di antara mereka.\" Amr bin Taghlib berkata; \"Ketika itu aku duduk di hadapan Rasulullah Shallalahu 'Alaihi Wasallam, lalu dia berkata; \"Kalimat yang Rasulullah ucapkan untuk saya lebih aku cintai dari pada unta merah.\""},"2761":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ الْحَسَنَ قَالَ ثَنَا عَمْرُو بْنُ تَغْلِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أُعْطِي أَقْوَامًا وَأَرُدُّ آخَرِينَ وَالَّذِينَ أَدَعُ أَحَبُّ إِلَيَّ مِنْ الَّذِينَ أُعْطِي أُعْطِي أَقْوَامًا لِمَا أَخَافُ مِنْ هَلَعِهِمْ قَالَ وَأَكِلُ أَقْوَامًا إِلَى مَا جَعَلَ اللَّهُ عَزَّ وَجَلَّ فِي قُلُوبِهِمْ مِنْ الْغِنَى وَالْخَيْرِ مِنْهُمْ عَمْرُو بْنُ تَغْلِبَ قَالَ قَالَ عَمْرٌو فَوَاللَّهِ مَا أُحِبُّ أَنَّ لِي بِكَلِمَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُمْرَ النَّعَمِ","id":"Telah menceritakan kepada kami [Wahab bin Jarir]; telah menceritakan kepada kami [ayahku], ia berkata; \"Aku mendengar [Al Hasan] berkata; telah menceritakan kepada kami [Amr bin Taghlib], ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Sesungguhnya aku memberi orang-orang tertentu dan tidak memberi yang lain, orang yang tidak saya beri adalah lebih aku cintai dari orang yang aku beri, aku memberikan kepada orang-orang itu karena di hati mereka ada keluh dan kesah, dan aku pasrahkan kepada ketetapan Allah dalam hati orang-orang yang merasa kaya dan baik di antara mereka.\" Amr bin Taghlib berkata; \"Dan aku duduk di hadapan Rasulullah Shallalahu 'Alaihi Wasallam, lalu dia berkata; \"Kalimat yang Rasulullah ucapkan untuk saya lebih aku cintai dari pada unta merah.\""},"2762":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ ثَنَا عَمْرُو بْنُ تَغْلِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُقَاتِلُونَ بَيْنَ يَدَيْ السَّاعَةِ قَوْمًا يَنْتَعِلُونَ الشَّعَرَ وَلَتُقَاتِلُنَّ قَوْمًا كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ","id":"Telah menceritakan kepada kami [Wahab bin Jarir] telah menceritakan kepada kami [Ayahku] dia berkata; saya mendengar [Al Hasan] berkata; telah menceritakan kepada kami [Amr bin Taghlib] dia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Menjelang hari kiamat, kalian akan memerangi suatu kaum yang memakai sandal dari rambut (bulu), dan kalian akan memerangi suatu kaum seakan-akan wajah mereka seperti tameng.\""},"2763":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُ حَدَّثَنَا عَمْرُو بْنُ تَغْلِبَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ تُقَاتِلُوا قَوْمًا عِرَاضَ الْوُجُوهِ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ","id":"Telah menceritakan kepada kami [Aswad bin 'Amir], telah menceritakan kepada kami [Jarir bin Hazim], telah menceritakan kepada kami [Al Hasan], ia berkata; telah menceritakan kepada kami [Amr bin Taghlib] dia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Di antara tanda-tanda hari Kiamat adalah kalian memerangi suatu kaum yang lebar wajahnya seakan-akan wajah mereka seperti tameng.\""},"2764":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا جَرِيرٌ عَنِ الْحَسَنِ عَنْ عَمْرِو بْنِ تَغْلِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ تُقَاتِلُوا أَقْوَامًا يَنْتَعِلُونَ الشَّعْرَ","id":"Telah menceritakan kepada kami [Aswad bin Amir], telah menceritakan kepada kami [Jarir], telah menceritakan kepada kami [Al Hasan], ia berkata; telah menceritakan kepada kami [Amr bin Taghlib] dia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Di antara tanda-tanda hari Kiamat adalah kalian memerangi suatu kaum yang mengenakan sandal dari rambut (bulu).\""},"2765":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ سَمِعْتُ الْحَسَنَ حَدَّثَنَا عَمْرُو بْنُ تَغْلِبَ قَالَسَمَعَتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ تُقَاتِلُوا قَوْمًا نِعَالُهُمْ الشَّعْرُ أَوْ يَنْتَعِلُونَ الشَّعَرَ وَإِنَّ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ تُقَاتِلُوا قَوْمًا عِرَاضَ الْوُجُوهِ كَأَنَّ وُجُوهَهُمْ الْمَجَانُّ الْمُطْرَقَةُ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Jarir bin Hazim], telah menceritakan kepada kami [Al Hasan], ia berkata; telah menceritakan kepada kami [Amr bin Taghlib] dia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Sesungguhnya diantara tanda-tanda dekatnya hari Kiamat adalah kalian memerangi suatu kaum yang sandal mereka terbuat dari rambut (bulu) atau mengenakan sandal dari rambut (bulu), dan diantara tanda-tanda dekatnya hari Kiamat adalah kalian memerangi suatu kaum yang berwajah lebar, seakan-akan wajah mereka seperti tameng.\""},"2766":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ هَوْذَةَ الْقُرَيْعِيُّ أَنَّهُ قَالَ حَدَّثَنِي رَجُلٌ سَمِعَ جَرْمُوزًا الْهُجَيْمِيَّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَوْصِنِي قَالَ أُوصِيكَ أَنْ لَا تَكُونَ لَعَّانًا","id":"Telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami ['Ubaidullah bin Haudah Al Qurai'i] dia berkata; telah menceritakan kepadaku [seorang lelaki] yang mendengar [Jarmuzan Al Hujaimi] bahwa dia berkata; \"Aku berkata; \"Wahai Rasulullah, berilah aku nasehat!.\" beliau menjawab: \"Aku nasehatkan kepadamu supaya jangan menjadi orang yang suka melaknat.\""},"2767":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَلِيٌّ يَعْنِي ابْنَ مُبَارَكٍ عَنْ يَحْيَى حَدَّثَنِي حَيَّةُ التَّمِيمِيُّ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا شَيْءَ فِي الْهَامِ وَالْعَيْنُ حَقٌّ وَأَصْدَقُ الطِّيَرِ الْفَأْلُ","id":"Telah menceritakan kepada kami [Abu Amir], telah menceritakan kepada kami [Ali yaitu Ibnu Mubarak] dari [Yahya], telah menceritakan padaku [Hayyat bin Habis At Tamimi] bahwa [ayahnya] telah mengabarkan kepadanya bahwa dia mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tidak ada ham, sedangkan 'Ain adalah benar, dan firasat yang paling baik adalah sikap optomis.\" "},"2768":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَرْبٌ حَدَّثَنَا يَحْيَى حَدَّثَنِي حَيَّةُ بْنُ حَابِسٍ التَّمِيمِيُّ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا شَيْءَ فِي الْهَامِ وَالْعَيْنُ حَقٌّ وَأَصْدَقُ الطِّيَرَةِ الْفَأْلُ","id":"Telah menceritakan kepada kami [Abdushamad], telah menceritakan kepada kami [Harb], telah menceritakan kepada kami [Yahya] telah menceritakan kepadaku [Hayyah bin Habis At Tamimi] bahwa [Ayahnya] telah mengabarkan kepadanya, bahwa Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tidak ada ham, sedangkan 'Ain adalah benar, dan firasat yang paling baik adalah sikap optomis.\" "},"2769":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَحَدَّثَنَا حَسَنُ بْنُ مُوسَى وَحُسَيْنُ بْنُ مُحَمَّدٍ قَالَا ثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ حَيَّةَ حَدَّثَهُ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا شَيْءَ فِي الْهَامِ وَالْعَيْنُ حَقٌّ وَأَصْدَقُ الطِّيَرِ الْفَأْلُ","id":"Telah menceritakan kepada kami [Abdushamad], dan telah menceritakan kepada kami [Hasan bin Musa] dan [Husain bin Muhammad], keduanya berkata; telah menceritakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari [Hayyah] bahwa dia telah menceritakan dari [Ayahnya] dari [Abu Hurairah] bahwa Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Tidak ada ham, sedangkan 'Ain adalah benar, dan firasat yang paling baik adalah sikap optomis.\" "},"2770":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ بِلَالِ بْنِ يَقْطُرَأَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتُعْمِلَ عَلَى سِجِسْتَانَ فَلَقِيَهُ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تَذْكُرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ اسْتَعْمَلَ رَجُلًا عَلَى جَيْشٍ وَعِنْدَهُ نَارٌ قَدْ أُجِّجَتْ فَقَالَ لِرَجُلٍ مِنْ أَصْحَابِهِ قُمْ فَانْزُهَا فَقَامَ فَنَزَاهَا فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ وَقَعَ فِيهَا لَدَخَلَا النَّارَ إِنَّهُ لَا طَاعَةَ فِي مَعْصِيَةِ اللَّهِ تَبَارَكَ وَتَعَالَى وَإِنَّمَا أَرَدْتُ أَنْ أُذَكِّرَكَ هَذَا وَقَالَ حَمَّادٌ أَيْضًا قُمْ فَانْزِهَا فَأَبَى فَعَزَمَ عَلَيْهِ وَقَدْ قَالَ حَمَّادٌ أَيْضًا لَا طَاعَةَ فِي مَعْصِيَةِ اللَّهِ تَعَالَى قَالَ نَعَمْ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami ['Atha` bin Sa`ib] dari [Bilal bin Yaqthur] bahwa seorang lelaki dari Sahabat Nabi Shallalahu 'Alaihi Wasallam diangkat menjadi pejabat di Sijistan, kemudian dia bertemu dengan [salah seorang] sahabat Nabi Shallalahu 'Alaihi Wasallam, laki-laki itu berkata; \"Ingatkah kamu ketika Rasulullah Shallalahu 'Alaihi Wasallam mengangkat seorang lelaki untuk memimpin suatu pasukan, sementara di sisinya ada api yang telah dinyalakan?, kemudian komandan itu berkata kepada salah seorang sahabatnya; \"Bangun dan lompatlah!.\" laki-laki tadi bangun dan melompat, \" Setelah perkara ini disampaikan kepada Rasulullah Shallalahu 'Alaihi Wasallam, beliau bersabda: \"Seandainya dia benar-benar menceburkan dirinya ke dalam api, niscaya keduanya akan masuk neraka, sesungguhnya tidak ada ketaatan dalam bermaksiat kepada Allah Tabaraka wa Ta'ala, \" hanyasannya aku ingin mengingatkanmu tentang hal ini.\" Dan [Hammad] mengatakan (dalam riwayatnya); \"Bangunlah dan lompatlah!.\" Laki-laki itu menolak, namun dia tetap dipaksa.\" Dan dalam riwayat yang lain [Hammad] mengatakan; \"Tidak ada ketaatan dalam bermaksiat kepada Allah Ta'ala, \" dia menjawab \"Ya.\""},"2771":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ قَالَ حَدَّثَنِي الْحَسَنُ بِحَدِيثِ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ عُمَرَ فِي الدِّيبَاجِ قَالَ فَقَالَ الْحَسَنُ أَخْبَرَنِي رَجُلٌ مِنَ الْحَيِّأَنَّهُ دَخَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ جُبَّةٌ لَبِنَتُهَا دِيبَاجٌ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبِنَةٌ مِنْ نَارٍ","id":"Telah menceritakan kepada kami [Ali bin 'Ashim] telah mengabarkan kepada kami [Sulaiman At Taimi] -dia berkata; telah menceritakan kepadaku Al Hasan, dengan dengan haditsnya Abu Utsman An Nahdi dari Umar tentang masalah sutera- dia berkata; [Al Hasan] berkata; telah menceritakan kepadaku [seseorang lelaki dari penduduk kampong] bahwa dia masuk menemui Rasulullah Shallalahu 'Alaihi Wasallam, sementara laki-laki itu mengenakan jubah yang kantongnya terbuat dari sutera, Al Hasan berkata; maka Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Kantong dari api neraka.\""},"2772":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي عُثْمَانَ عَنْ مُجَاشِعِ بْنِ مَسْعُودٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا مُجَالِدُ بْنُ مَسْعُودٍ يُبَايِعُكَ عَلَى الْهِجْرَةِ فَقَالَ لَا هِجْرَةَ بَعْدَ فَتْحِ مَكَّةَ وَلَكِنْ أُبَايِعُهُ عَلَى الْإِسْلَامِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Yazid bin Zura'i], telah menceritakan kepada kami [Khalid Al Khadza`] dari [Abu Utsman] dari [Mujasyi' bin Mas'ud] dia berkata; aku berkata; \"Wahai Rasulullah, inilah Mujalid bin Mas'ud berbai'at kepadamu untuk berhijrah, \" beliau menjawab: \"Tidak ada hijrah setelah penaklukan kota Makkah, akan tetapi aku membai'atnya atas Islam.\""},"2773":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي أَيُّوبُ قَالَ سَمِعْتُ عَمْرَو بْنَ سَلِمَةَ قَالَلَمَّا كَانَ يَوْمُ الْفَتْحِ جَعَلَ النَّاسُ يَمُرُّونَ عَلَيْنَا قَدْ جَاءُوا مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ أَقْرَأُ وَأَنَا غُلَامٌ فَجَاءَ أَبِي بِإِسْلَامِ قَوْمِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّكُمْ أَكْثَرُكُمْ قُرْآنًا فَنَظَرُوا فَكُنْتُ أَكْثَرَهُمْ قُرْآنًا قَالَ فَقَالَتْ امْرَأَةٌ غَطُّوا اسْتَ قَارِئِكُمْ قَالَ فَاشْتَرَوْا لَهُ بُرْدَةً قَالَ فَمَا فَرِحْتُ أَشَدَّ مِنْ فَرَحِي بِذَلِكَ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Syu'bah], telah menceritakan kepadaku [Ayyub] ia berkata; aku mendengar ['Amru bin Salamah] berkata; \"Ketika terjadi penaklukan kota Makkah, orang-orang banyak yang lewat berlalu-lalang di depan (perkampungan) kami, mereka datang dari sisi Rasulullah Shallalahu 'Alaihi Wasallam, sementara aku termasuk orang yang banyak hafalan Qur`an, ketika itu aku masih kecil. Lalu ayahku datang kepada Rasulullah Shallalahu 'Alaihi Wasallam untuk keIslaman kaumku, maka Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Hendaklah orang yang paling banyak hafalannya diantara kalian menjadi imam.\" Mereka lalu saling melihat, sementara aku termasuk dari orang yang banyak hafalannya. 'Amru berkata; Lalu seorang wanita berkata; \"Tutuplah pantat imam kalian.\" Amru berkata; \"Lantas mereka membelikan kain burdah, 'Amru mengatakan; \"Tidaklah aku sangat bahagia dibanding waktu itu.\""},"2774":{"ar":"حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ وَاصِلٍ الْحَدَّادُّ حَدَّثَنَا مِسْعَرٌ أَبُو الْحَارِثِ الْجَرْمِيُّ قَالَ سَمِعْتُ عَمْرَو بْنَ سَلِمَةَ الْجَرْمِيَّيُحَدِّثُ أَنَّ أَبَاهُ وَنَفَرًا مِنْ قَوْمِهِ وَفَدُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ ظَهَرَ أَمْرُهُ وَتَعَلَّمَ النَّاسُ فَقَضَوْا حَوَائِجَهُمْ ثُمَّ سَأَلُوهُ مَنْ يُصَلِّي لَنَا أَوْ يُصَلِّي بِنَا فَقَالَ يُصَلِّي لَكُمْ أَوْ بِكُمْ أَكْثَرُكُمْ جَمْعًا لِلْقُرْآنِ أَوْ أَخْذًا لِلْقُرْآنِفَقَدِمُوا عَلَى قَوْمِهِمْ فَسَأَلُوا فِي الْحَيِّ فَلَمْ يَجِدُوا أَحَدًا جَمَعَ أَكْثَرَ مِمَّا جَمَعْتُ فَقَدَّمُونِي بَيْنَ أَيْدِيهِمْ فَصَلَّيْتُ بِهِمْ وَأَنَا غُلَامٌ عَلَيَّ شَمْلَةٌ لِي قَالَ فَمَا شَهِدْتُ مَجْمَعًا مِنْ جَرْمٍ إِلَّا كُنْتُ إِمَامَهُمْ إِلَى يَوْمِي هَذَا","id":"Telah menceritakan kepada kami [Abdul Wahid bin Washil Al Haddad], telah menceritakan kepada kami [Mis'ar Abul Harits Al Jarmi] ia berkata; aku mendengar ['Amru bin Salamah Al Jarmi] bercerita bahwa ayahnya bersama beberapa orang dari kaumnya mengutus utusan kepada Rasulullah Shallalahu 'Alaihi Wasallam, ketika banyak sekali masalah dan manusia banyak belajar serta menyelesaikan hajat mereka, mereka bertanya; \"Siapakah kiranya yang pantas menjadi imam kami atau mengimami kami?, \" beliau bersabda: \"Yang menjadi imam (shalat) kalian atau yang mengimami kalian adalah yang paling banyak mengumpulkan al Qur'an atau hafalan Al Qur`annya.\" Kemudian mereka kembali ke kaumnya dan mencari seseorang yang sekiranya cocok, namuan mereka tidak menemukan seorang pun yang lebih banyak mengumpulkan (menghafal) al qur'an selain aku, akhirnya mereka menyuruhku kedepan untuk menjadi imam shalat mereka, padahal aku masih kecil dan tengah mengenakan kain, tidaklah aku melihat setiap manusia kecuali akulah yang mengimami mereka hingga hari ini.\""},"2775":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ سَلِمَةَ قَالَكَانُوا يَأْتُونَا الرُّكْبَانُ مِنْ قِبَلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْتَقْرِئُهُمْ فَيُحَدِّثُونَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيَؤُمَّكُمْ أَكْثَرُكُمْ قُرْآنًا","id":"Telah menceritakan kepada kami [Ali bin 'Ashim], telah menceritakan kepada kami [Khalid Al Hadza`] dari [Abu Qilabah] dari [Amru bin Salimah] ia berkata; \"Mereka mendatangi [para pengendara] dari arah Rasulullah Shallalahu 'Alaihi Wasallam, lantas kami mengumpulkan mereka, lantas mereka menceritakannya kepada kami bahwa Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Hendaklah orang yang banyak hafalan Qur`annya menjadi imam diantara kalian.\""},"2776":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا الْمُبَارَكُ بْنُ فَضَالَةَ حَدَّثَنَا الْحَسَنُ أَخْبَرَنِي شَيْخٌ مَنْ بَنِي سَلِيطٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُكَلِّمُهُ فِي سَبْيٍ أُصِيبَ لَنَا فِي الْجَاهِلِيَّةِ فَإِذَا هُوَ يُحَدِّثُ الْقَوْمَ وَحَلْقَةٌ قَدْ أَطَافَتْ بِهِ فَإِذَا هُوَ قَاعِدٌ عَلَيْهِ إِزَارُ قِطْرٍ لَهُ غَلِيظٌ أَوَّلُ شَيْءٍ سَمِعْتُهُ مِنْهُ يَقُولُ وَهُوَ يَقُولُ بِيَدِهِ هَكَذَا وَأَشَارَ الْمُبَارَكُ بِإِصْبَعِهِ السَّبَّابَةِ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يَخْذُلُهُ التَّقْوَى هَاهُنَا التَّقْوَى هَاهُنَا أَيْ فِي الْقَلْبِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Al Mubarak bin Fadhalah], telah menceritakan kepada kami [Al Hasan], telah mengabarkan kepadaku [seorang syaikh] dari bani Salith, ia berkata; \"Aku pernah datang menemui Nabi Shalallahu 'Alaihi Wasallam, lalu saya berbincang kepada beliau mengenai tawanan perang dari kalangan anak-anak dan wanita yang kami dapatkan pada masa jahiliyah. Saat itu beliau sedang bercerita kepada jama'ah, sementara mereka duduk mengelilingi beliau, dan beliau memakai sarung katun tebal miliki beliau. Hal yang pertama kali aku dengar dari beliau adalah, dan beliau memberi isyarat dengan tangannya seperti ini, -Mubarrak memberi isyarat dengan jari telunjuknya- \"Seorang muslim itu saudara muslim lainnya, tidak boleh menganiayanya dan tidak boleh merendahkannya. Takwa itu letaknya di sini, takwa itu letaknya di sini.\" maksudnya di hati."},"2777":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنِ الْحَسَنِ حَدَّثَنِي رَجُلٌ مِنْ بَنِي سَلِيطٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي أَزْفَلَةٍ مِنْ النَّاسِ فَسَمِعْتُهُ يَقُولُ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَظْلِمُهُ وَلَا يَخْذُلُهُ التَّقْوَى هَاهُنَا قَالَ حَمَّادٌ وَقَالَ بِيَدِهِ إِلَى صَدْرِهِ وَمَا تَوَادَّ اثْنَانِ فِي اللَّهِ عَزَّ وَجَلَّ لَا يُفَرِّقُ بَيْنَهُمَا إِلَّا حَدَثٌ يُحْدِثُهُ أَحَدُهُمَا وَالْمُحْدِثُ شَرٌّ وَالْمُحْدِثُ شَرٌّ وَالْمُحْدِثُ شَرٌّ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad], telah mengabarkan kepada kami [Ali bin Zaid] dari [Al Hasan], telah menceritakan kepadaku [seseorang] dari bani Salith, ia berkata; \"Aku mendatangi Rasulullah Shallalahu 'Alaihi Wasallam ketika beliau berada dikerumunan orang-orang, lalu aku mendengar beliau bersabda: \"Muslim itu saudara muslim lainnya, tidak boleh menzhaliminya dan tidak boleh merendahkannya, taqwa itu di sini!, \" - [Hammad] berkata; Beliau menunjuk ke dadanya- Dan tidaklah dua orang yang mencintai karena Allah 'azza wajalla, keduanya tidak akan berpisah kecuali karena perkataan yang menyakitkan dari salah satunya, maka yang berkata-kata itu jahat, yang berkata-kata itu jahat, dan yang berkata-kata itu jahat.\""},"2778":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي تَمِيمَةَ عَنْ رِدْفِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ عَنْ رَجُلٍ عَنْ رِدْفِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ كَانَ عَلَى حِمَارٍ فَعَثَرَ فَقَالَ الَّذِي خَلْفَهُ تَعِسَ الشَّيْطَانُ فَقَالَ لَا تَقُلْ تَعِسَ الشَّيْطَانُ فَإِنَّكَ إِذَا قُلْتَ تَعِسَ الشَّيْطَانُ تَعَاظَمَ وَقَالَ بِعِزَّتِي صَرَعْتُكَ وَإِذَا قُلْتَ بِسْمِ اللَّهِ تَصَاغَرَ حَتَّى يَصِيرَ مِثْلَ ذُبَابٍ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Syu'bah] dari [Ashim Al Ahwal] dari [Abu Tamimah] dari [seorang yang membonceng Nabi] Shalallahu 'Alaihi Wasallam, bahwa beliau pernah berada di atas keledai, lalu keledainya jatuh tergelincir, serentak orang yang membonceng di belakang beliau berkata; \"Celakalah setan, \" Maka beliau bersabda: \"Janganlah kamu katakan \"celakalah setan, \" sebab jika kamu mengatakan \"celakalah setan, \" maka setan akan membanggakan dirinya, setan akan berkata; \"Aku telah melawannya dengan kekuatanku, \" namuan bila kamu membaca BISMILLAAH maka setan akan menjadi kecil, lebih kecil dari seekor lalat.\""},"2779":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَمَّنْسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ{ فَيَوْمَئِذٍ لَا يُعَذِّبُ عَذَابَهُ أَحَدٌ وَلَا يُوثِقُ وَثَاقَهُ أَحَدٌ }يَعْنِي يَفْعَلُ بِهِقَالَ خَالِدٌ وَسَأَلْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرَةَ قَالَ{ فَيَوْمَئِذٍ لَا يُعَذِّبُ }أَيْ يَفْعَلُ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Khalid Al Hadza`] dari [Abu Qilabah] dari [seseorang] yang pernah mendengar Nabi Shallalahu 'Alaihi Wasallam ketika beliau membaca ayat \"FAYAUMA'IDZIN LAA YU'ADZABU 'ADZAABAHU AHAD WALAA YUU TSIQU WATSAAQOHU AHAD (Maka pada hari itu tiada seorangpun yang menyiksa seperti siksa-Nya. Dan tiada seorangpun yang mengikat seperti ikatan-Nya) \". QS Al fajr: 25-26, maksudnya mengerjakannya.\" [Khalid] berkata; \"Aku bertanya kepada [Abdurrahman bin Abu Bakrah], dia menjawab; \"fayauma'idzin laa yu'adzabu\" maksudnya melakukannya.\""},"2780":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا الْأَزْرَقُ بْنُ قَيْسٍ عَنْ يَحْيَى بْنِ يَعْمُرَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَوَّلُ مَا يُحَاسَبُ بِهِ الْعَبْدُ يَوْمَ الْقِيَامَةِ صَلَاتُهُ فَإِنْ أَتَمَّهَا كُتِبَتْ لَهُ تَامَّةً وَإِنْ لَمْ يَكُنْ أَتَمَّهَا قَالَ انْظُرُوا تَجِدُونَ لِعَبْدِي مِنْ تَطَوُّعٍ فَأَكْمِلُوا مَا ضَيَّعَ مِنْ فَرِيضَتِهِ ثُمَّ الزَّكَاةُ ثُمَّ تُؤْخَذُ الْأَعْمَالُ عَلَى حَسَبِ ذَلِكَ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Al Azraq bin Qais] dari [Yahya bin Ya'mar] dari [salah seorang sahabat Nabi] Shalallahu 'Alaihi Wasallam beliau bersabda: \"Amalan yang pertama kali dihisab dari seorang hamba pada hari kiamat adalah shalatnya, bila sempurna maka ditulis dengan lengkap, bila tidak maka Allah berfirman: \"Lihatlah apakah dia memiliki shalat sunah, lengkapilah sesuatu yang kurang sempurna dari shalat wajibnya, kemudian zakat, setelah itu semua amal dihitung sesuai kadarnya.\""},"2781":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَجَلَسَ إِلَيْنَا شَيْخٌ فِي مَكَانِ أَيُّوبَ فَسَمِعَ الْقَوْمَ يَتَحَدَّثُونَ فَقَالَ حَدَّثَنِي مَوْلَايَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ مَا اسْمُهُ قَالَ قُرَّةُ بْنُ دَعْمُوصٍ النُّمَيْرِيُّ قَالَ قَدِمْتُ الْمَدِينَةَ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَوْلَهُ النَّاسُ فَجَعَلْتُ أُرِيدُ أَنْ أَدْنُوَ مِنْهُ فَلَمْ أَسْتَطِعْ فَنَادَيْتُهُ يَا رَسُولَ اللَّهِ اسْتَغْفِرْ لِلْغُلَامِ النُّمَيْرِيِّ فَقَالَ غَفَرَ اللَّهُ لَكَ قَالَ وَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الضَّحَّاكَ بْنَ قَيْسٍ سَاعِيًا فَلَمَّا رَجَعَ رَجَعَ بِإِبِلٍ جُلَّةٍ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَيْتَ هِلَالَ بْنَ عَامِرٍ وَنُمَيْرَ بْنَ عَامِرٍ وَعَامِرَ بْنَ رَبِيعَةَ فَأَخَذْتَ جُلَّةَ أَمْوَالِهِمْ قَالَ يَا رَسُولَ اللَّهِ إِنَّنِي سَمِعْتُكَ تَذْكُرُ الْغَزْوَ فَأَحْبَبْتُ أَنْ آتِيَكَ بِإِبِلٍ تَرْكَبُهَا وَتَحْمِلُ عَلَيْهَا فَقَالَ وَاللَّهِ لَلَّذِي تَرَكْتَ أَحَبُّ إِلَيَّ مِنْ الَّذِي أَخَذْتَ ارْدُدْهَا وَخُذْ مِنْ حَوَاشِي أَمْوَالِهِمْ صَدَقَاتِهِمْ قَالَ فَسَمِعْتُ الْمُسْلِمِينَ يُسَمُّونَ تِلْكَ الْإِبِلَ الْمَسَانَّ الْمُجَاهِدَاتِ","id":"Telah bercerita kepada kami ['Affan] telah menceritakan kepada kami [Jarir bin Hazim] dia berkata; seorang [Syeikh] duduk bersama kami ditempatnya Ayyub, lalu ia mendengar orang-orang tengah berbicara, ia berkata; telah menceritakan kepadaku budakku dari Rasulullah Shallalahu 'Alaihi Wasallam, aku bertanya \"Siapa namanya?.\" Syaikh itu menjawab; [Qurrah bin Da'mus An Numairi], dia berkata; Aku datang ke Madinah untuk menemui Rasulullah Shallalahu 'Alaihi Wasallam, sementara di sekitar beliau berkumpul banyak orang, aku ingin mendekat kepadanya namun tidak bisa, maka aku memanggil beliau; \"Wahai Rasulullah, mohonkanlah ampunan untuk anak lelaki An Numairi!.\" Beliau menjawab: \"Semoga Allah mengampunimu.\" Qurrah berkata; lalu Rasulullah Shallalahu 'Alaihi Wasallam mengutus Ad Dlahhak bin Qais untuk memungut zakat, ketika kembali ia membawa seekor unta terbaik, lalu Rasulullah Shallalahu 'Alaihi Wasallam bersabda kepadanya: \"Kamu mendatangi Hilal bin Amir, Numair bin Amir dan Amir bin Rabi'ah, kemudian kamu mengambil harta mereka yang terbaik.\" Dia menjawab; \"Wahai Rasulullah sungguh aku mendengar engkau menyebutkan suatu peperangan, maka aku ingin membawakan kepadamu seekor unta yang dapat engkau kendarai dan dapat engkau isi muatan.\" Beliau bersabda: \"Demi Allah, sesuatu yang kamu tinggalkan (harta atau unta) lebih aku cintai daripada yang kamu ambil, oleh karena itu kembalikanlah unta terbaik dan ambilah dari bagian harta mereka (harta biasa) sebagai zakat mereka!.\" [Qurrah] berkata; \"Maka aku mendengar kaum muslimin menamakan unta itu dengan Al Massan Al Mujahidat.\""},"2782":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا ثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ طُفَيْلِ بْنِ سَخْبَرَةَ أَخِي عَائِشَةَ لِأُمِّهَاأَنَّهُ رَأَى فِيمَا يَرَى النَّائِمُ كَأَنَّهُ مَرَّ بِرَهْطٍ مِنْ الْيَهُودِ فَقَالَ مَنْ أَنْتُمْ قَالُوا نَحْنُ الْيَهُودُ قَالَ إِنَّكُمْ أَنْتُمْ الْقَوْمُ لَوْلَا أَنَّكُمْ تَزْعُمُونَ أَنَّ عُزَيْرًا ابْنُ اللَّهِ فَقَالَتْ الْيَهُودُ وَأَنْتُمْ الْقَوْمُ لَوْلَا أَنَّكُمْ تَقُولُونَ مَا شَاءَ اللَّهُ وَشَاءَ مُحَمَّدٌ ثُمَّ مَرَّ بِرَهْطٍ مِنْ النَّصَارَى فَقَالَ مَنْ أَنْتُمْ قَالُوا نَحْنُ النَّصَارَى فَقَالَ إِنَّكُمْ أَنْتُمْ الْقَوْمُ لَوْلَا أَنَّكُمْ تَقُولُونَ الْمَسِيحُ ابْنُ اللَّهِ قَالُوا وَإِنَّكُمْ أَنْتُمْ الْقَوْمُ لَوْلَا أَنَّكُمْ تَقُولُونَ مَا شَاءَ اللَّهُ وَمَا شَاءَ مُحَمَّدٌ فَلَمَّا أَصْبَحَ أَخْبَرَ بِهَا مَنْ أَخْبَرَ ثُمَّ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ فَقَالَ هَلْ أَخْبَرْتَ بِهَا أَحَدًا قَالَ عَفَّانُ قَالَ نَعَمْ فَلَمَّا صَلَّوْا خَطَبَهُمْ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ طُفَيْلًا رَأَى رُؤْيَا فَأَخْبَرَ بِهَا مَنْ أَخْبَرَ مِنْكُمْ وَإِنَّكُمْ كُنْتُمْ تَقُولُونَ كَلِمَةً كَانَ يَمْنُعُنِي الْحَيَاءُ مِنْكُمْ أَنْ أَنْهَاكُمْ عَنْهَا قَالَ لَا تَقُولُوا مَا شَاءَ اللَّهُ وَمَا شَاءَ مُحَمَّدٌ","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan], keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Abdul Malik bin 'Umair] dari [Rib'i bin Hirasy] dari [Thufail bin Sakhbarah] saudara seibu A'isyah, bahwa dia pernah bermimpi sebagaimana orang yang tidur bermimpi, seakan akan dia melewati sekelompok pemuka Yahudi, lalu dia berkata; \"Siapakah kalian?\" mereka menjawab; \"Kami adalah orang-orang Yahudi.\" ia berkata; \"Sungguh kalian adalah kaum yang meyakini bahwa Uzair adalah anak Allah.\" Orang-orang Yahudi pun menjawab; \"Dan kalian adalah kaum yang mengatakan apa yang Allah kehendaki dan Muhammad kehendaki.\" Lalu ia melewati sekelompok pemuka Nasrani dan bertanya; \"Siapakah kalian?.\" Mereka menjawab; \"Kami orang-orang Nasrani.\" ia pun berkata; \"Sungguh kalian adalah kaum yang mengatakan Al Masih adalah anak Allah.\" Mereka menjawab; \"Dan kalian adalah kaum yang mengatakan apa yang Allah dan Muhammad kehendaki.\" Keesokan harinya, seseorang memberitakan mimpi itu kepada Nabi Shallalahu 'Alaihi Wasallam, kemudian beliau bertanya; \"Apakah kamu telah menceritakannya kepada seseorang?\" 'Affan mengatakan; Dia menjawab; \"ya, \" Seusai shalat, beliau pun berkhutbah kepada para sahabat, lalu memuji Allah dan menyucikannya, seraya bersabda: \"Sungguh Thufail telah bermimpi sesuatu, kemudian dia menceritakannya kepada beberapa orang diantara kalian, Sungguh kalian mengatakan suatu kalimat, karena sebab malu menghalangiku untuk melarang kalian mengatakannya, beliau bersabda: \"Janganlah kalian mengatakan; \"apa yang Allah kehendaki dan apa yang Muhammad kehendaki.\""},"2783":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ أَبِي حُرَّةَ الرَّقَاشِيِّ عَنْ عَمِّهِ قَالَكُنْتُ آخِذًا بِزِمَامِ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَوْسَطِ أَيَّامِ التَّشْرِيقِ أَذُودُ عَنْهُ النَّاسَ فَقَالَ يَا أَيُّهَا النَّاسُ أَتَدْرُونَ فِي أَيِّ شَهْرٍ أَنْتُمْ وَفِي أَيِّ يَوْمٍ أَنْتُمْ وَفِي أَيِّ بَلَدٍ أَنْتُمْ قَالُوا فِي يَوْمٍ حَرَامٍ وَشَهْرٍ حَرَامٍ وَبَلَدٍ حَرَامٍ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا إِلَى يَوْمِ تَلْقَوْنَهُ ثُمَّ قَالَ اسْمَعُوا مِنِّي تَعِيشُوا أَلَا لَا تَظْلِمُوا أَلَا لَا تَظْلِمُوا أَلَا لَا تَظْلِمُوا إِنَّهُ لَا يَحِلُّ مَالُ امْرِئٍ إِلَّا بِطِيبِ نَفْسٍ مِنْهُ أَلَا وَإِنَّ كُلَّ دَمٍ وَمَالٍ وَمَأْثَرَةٍ كَانَتْ فِي الْجَاهِلِيَّةِ تَحْتَ قَدَمِي هَذِهِ إِلَى يَوْمِ الْقِيَامَةِ وَإِنَّ أَوَّلَ دَمٍ يُوضَعُ دَمُ رَبِيعَةَ بْنِ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ كَانَ مُسْتَرْضِعًا فِي بَنِي لَيْثٍ فَقَتَلَتْهُ هُذَيْلٌ أَلَا وَإِنَّ كُلَّ رِبًا كَانَ فِي الْجَاهِلِيَّةِ مَوْضُوعٌ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَضَى أَنَّ أَوَّلَ رِبًا يُوضَعُ رِبَا الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ لَكُمْ رُءُوسُ أَمْوَالِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ أَلَا وَإِنَّ الزَّمَانَ قَدْ اسْتَدَارَ كَهَيْئَتِهِ يَوْمَ خَلَقَ اللَّهُ السَّمَوَاتِ وَالْأَرْضَ ثُمَّ قَرَأَ{ إِنَّ عِدَّةَ الشُّهُورِ عِنْدَ اللَّهِ اثْنَا عَشَرَ شَهْرًا فِي كِتَابِ اللَّهِ يَوْمَ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ مِنْهَا أَرْبَعَةٌ حُرُمٌ ذَلِكَ الدِّينُ الْقَيِّمُ فَلَا تَظْلِمُوا فِيهِنَّ أَنْفُسَكُمْ }أَلَا لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ أَلَا إِنَّ الشَّيْطَانَ قَدْ أَيِسَ أَنْ يَعْبُدَهُ الْمُصَلُّونَ وَلَكِنَّهُ فِي التَّحْرِيشِ بَيْنَكُمْ فَاتَّقُوا اللَّهَ عَزَّ وَجَلَّ فِي النِّسَاءِ فَإِنَّهُنَّ عِنْدَكُمْ عَوَانٌ لَا يَمْلِكْنَ لِأَنْفُسِهِنَّ شَيْئًا وَإِنَّ لَهُنَّ عَلَيْكُمْ وَلَكُمْ عَلَيْهِنَّ حَقًّا أَنْ لَا يُوطِئْنَ فُرُشَكُمْ أَحَدًا غَيْرَكُمْ وَلَا يَأْذَنَّ فِي بُيُوتِكُمْ لِأَحَدٍ تَكْرَهُونَهُ فَإِنْ خِفْتُمْ نُشُوزَهُنَّ فَعِظُوهُنَّ وَاهْجُرُوهُنَّ فِي الْمَضَاجِعِ وَاضْرِبُوهُنَّ ضَرْبًا غَيْرَ مُبَرِّحٍ قَالَ حُمَيْدٌ قُلْتُ لِلْحَسَنِ مَا الْمُبَرِّحُ قَالَ الْمُؤَثِّرُ وَلَهُنَّ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِالْمَعْرُوفِ وَإِنَّمَا أَخَذْتُمُوهُنَّ بِأَمَانَةِ اللَّهِ وَاسْتَحْلَلْتُمْ فُرُوجَهُنَّ بِكَلِمَةِ اللَّهِ عَزَّ وَجَلَّ وَمَنْ كَانَتْ عِنْدَهُ أَمَانَةٌ فَلْيُؤَدِّهَا إِلَى مَنْ ائْتَمَنَهُ عَلَيْهَا وَبَسَطَ يَدَيْهِ فَقَالَ أَلَا هَلْ بَلَّغْتُ أَلَا هَلْ بَلَّغْتُ أَلَا هَلْ بَلَّغْتُ ثُمَّ قَالَ لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَإِنَّهُ رُبَّ مُبَلَّغٍ أَسْعَدُ مِنْ سَامِعٍقَالَ حُمَيْدٌ قَالَ الْحَسَنُ حِينَ بَلَّغَ هَذِهِ الْكَلِمَةَ قَدْ وَاللَّهِ بَلَّغُوا أَقْوَامًا كَانُوا أَسْعَدَ بِهِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Ali bin Zaid] dari [Abu Hurrah Ar Raqasyi] dari [Pamannya] dia berkata; \"Aku memegang tali kekang unta Rasulullah Shallalahu 'Alaihi Wasallam pada pertengahan hari Tasyrik (yaitu tanggal sebelas, dua belas dan tiga belas Dzulhijjah), aku mendesak orang-orang dari beliau, beliau bertanya: \"Wahai manusia, tahukah kalian di bulan apa kalian sekarang, di hari dan negeri mana kalian sekarang?.\" Para sahabat menjawab; \"Di hari haram, bulan haram dan negeri haram, \" beliau bersabda: \"Sungguh darah, harta dan kehormatan kalian adalah haram atas kalian, sebagaimana sucinya hari, bulan dan negeri kalian ini sampai datangnya hari kalian bertemu Allah.\" Beliau melanjutkan: \"Dengarkanlah aku, hiduplah kalian dan janganlah berbuat kezhaliman, ingatlah jangan berbuat dzalim, Sungguh tidak halal harta seseorang kecuali dengan kerelaan hati darinya, ketahuilah sesungguhnya setiap darah, harta dan kebanggaan yang ada pada masa jahiliyah, berada di bawah telapak kakiku ini sampai hari Kiamat, dan sesungguhnya darah yang pertama kali akan diletakkan adalah darah Rabi'ah bin Al Harits bin Abdul Muthallib, dia mencari seorang wanita yang bisa menyusui di Bani Laits, kemudian dibunuh oleh orang-orang Hudzail, ketahuilah sesungguhnya setiap riba di masa jahiliyah adalah jelek, dan sesungguhnya Allah 'azza wajalla telah memutuskan bahwa riba yang pertama kali akan diletakkan adalah riba Al Abbas bin Abdul Muthallib, bagi kalian adalah pokok harta kalian, janganlah kalian menzhalimi dan jangan pula terzhalimi, ketahuilah sesungguhnya zaman telah berputar sebagaimana perputaran pada hari Allah menciptakan langit dan bumi, kemudian beliau membaca ayat \"INNA 'IDDATASY SYUHUURI 'INDALLAAHI ITSNAA 'ASYARA SYAHRAN FII KITAABILLAAHI YAUMA KHOLAQAS SAMAAWAATI WAL ARDLA MINHAA ARBA'ATUN HURUM DZAALIKAD DIINUL QAYYIMU FALAA TADLIMUU FIIHINNA ANFUSAKUM (Sesungguhnya bilangan bulan pada sisi Allah adalah dua belas bulan, dalam ketetapan Allah di waktu dia menciptakan langit dan bumi, di antaranya empat bulan haram. Itulah (ketetapan) agama yang lurus, Maka janganlah kamu menganiaya diri kamu dalam bulan yang empat itu) \". QS At Taubah: 36, ketahuilah janganlah kalian kembali kepada kekafiran sepeninggalku, dengan saling membunuh satu sama lain, ketahuilah sesungguhnya setan telah putus asa untuk disembah oleh orang-orang yang shalat, akan tetapi dia tidak berputus asa untuk mengadu domba diantara kalian, maka takutlah kepada Allah 'azza wajalla dalam masalah wanita, karena sesungguhnya mereka di sisi kalian ibarat tawanan yang tidak dapat menguasai diri mereka sedikitpun, dan sungguh mereka mempunyai hak dari kalian dan kalianpun mempunyai hak atas mereka, janganlah mereka memasukkan kedalam rumah kalian selain kalian sendiri, janganlah mereka mengizinkan masuk ke dalam rumah kalian seseorang yang tidak kalian sukai, jika kalian khawatir akan nusyuz (durhaka) mereka, maka nasehatilah mereka lalu jauhilah mereka di tempat tidur dan pukulah mereka dengan pukulan yang tidak menyakitkan.\" [Humaid] berkata; Aku bertanya kepada [Al Hasan]; \"Apa yang dimaksud dengan \"Al Mubarrih?.\" dia menjawab; \"Yang membekas, \" dan hak bagi mereka adalah mendapatkan makan dan pakaian dengan cara ma'ruf, hanyasannya kalian mengambil mereka adalah dengan amanat dari Allah dan kalian menghalalkan farji (kehormatan) mereka adalah dengan kalimat Allah 'azza wajalla, dan barangsiapa mendapat amanat, maka sampaikanlah amanat itu kepada orang yang diamanati.\" Kemudian beliau membentangkan kedua tangannya seraya bersabda; \"ketahuilah bukankah aku telah menyampaikan, ketahuilah bukankah aku telah menyampaikan, ketahuilah bukankah aku telah menyampaikan?.\" Kemudian beliau melanjutkan sabdanya: \"Hendaknya orang yang hadir menyampaikan kepada yang tidak hadir, karena betapa banyak orang yang disampaikan berita kepadanya, dia lebih faham dari orang yang mendengar langsung.\" Humaid berkata; \" Al Hasan berkata ketika menyampaikan kalimat ini; \"Sungguh, demi Allah, mereka menyampaikan kepada suatu kaum dan mereka lebih bahagia dengannya.\""},"2784":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ رَجُلٍ مِنْ أَهْلِ الشَّامِ يُقَالُ لَهُ عَمَّارٌ قَالَأَدْرَبْنَا عَامًا ثُمَّ قَفَلْنَا وَفِينَا شَيْخٌ مِنْ خَثْعَمٍ فَذُكِرَ الْحَجَّاجُ فَوَقَعَ فِيهِ وَشَتَمَهُ فَقُلْتُ لَهُ لِمَ تَسُبُّهُ وَهُوَ يُقَاتِلُ أَهْلَ الْعِرَاقِ فِي طَاعَةِ أَمِيرِ الْمُؤْمِنِينَ فَقَالَ إِنَّهُ هُوَ الَّذِي أَكْفَرَهُمْ ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكُونُ فِي هَذِهِ الْأُمَّةِ خَمْسُ فِتَنٍ فَقَدْ مَضَتْ أَرْبَعٌ وَبَقِيَتْ وَاحِدَةٌ وَهِيَ الصَّيْلَمُ وَهِيَ فِيكُمْ يَا أَهْلَ الشَّامِ فَإِنْ أَدْرَكْتَهَا فَإِنْ اسْتَطَعْتَ أَنْ تَكُونَ حَجَرًا فَكُنْهُ وَلَا تَكُنْ مَعَ وَاحِدٍ مِنْ الْفَرِيقَيْنِ أَلَا فَاتَّخِذْ نَفَقًا فِي الْأَرْضِ وَقَدْ قَالَ حَمَّادٌ وَلَا تَكُنْوَقَدْ حَدَّثَنَا بِهِ حَمَّادٌ قَبْلَ ذَا قُلْتُ أَأَنْتَ سَمِعْتَهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قُلْتُ يَرْحَمُكَ اللَّهُ أَفَلَا كُنْتَ أَعْلَمْتَنِي أَنَّكَ رَأَيْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أُسَائِلَكَ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Daud bin Abu Hind] dari seorang lelaki penduduk Syam yang biasa dipanggil dengan [Ammar] dia berkata; selama setahun, kami terbiasa tak ada masalah kemudian kami merasa gersang, sedangkan di antara kami ada seorang [syeikh] dari Khats'am, ketika disebut nama Al Hajjaj, serta merta dia mencelanya, maka aku bertanya kepadanya; \"Kenapa kamu mencelanya, padahal dia memerangi orang-orang Irak dalam rangka taat kepada Amirul Mukminin?.\" Syaikh itu menjawab; \"Sungguh dialah yang telah mengkafirkan mereka, lalu dia berkata; \"Aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Akan terjadi lima fitnah pada umat ini, yang empat telah terjadi dan yang tersisa satu lagi yaitu Ash Shailam (perpecahan yang hebat), dan akan terjadi pada kalian wahai penduduk Syam, jika kamu menjumpainya, sementara dirimu dapat menjadi batu, lebih baik menjadi batu dan janganlah kamu bergabung dengan salah satu dari dua golongan, ketahuilah ambilah nafkahmu di bumi.\" Hammad berkata;; \"Janganlah kamu menjadi.\" Dan telah menceritakan kepada kami Hammad sebelum ini, aku berkata; \"Apakah kamu mendengarnya dari Nabi Shallalahu 'Alaihi Wasallam?.\" dia menjawab; \"ya.\" Aku berkata; \"Semoga Allah merahmatimu, kenapa kamu tidak memberitahuku bahwa kamu pernah melihat Nabi Shallalahu 'Alaihi Wasallam sehingga aku bisa bertanya banyak hal kepadamu.\""},"2785":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ أَخْبَرَنَا عَمَّارٌ يَعْنِي ابْنَ أَبِي عَمَّارٍ عَنِ ابْنِ عَبَّاسٍ قَالَأَتَى عَلَيَّ زَمَانٌ وَأَنَا أَقُولُ أَوْلَادُ الْمُسْلِمِينَ مَعَ الْمُسْلِمِينَ وَأَوْلَادُ الْمُشْرِكِينَ مَعَ الْمُشْرِكِينَ حَتَّى حَدَّثَنِي فُلَانٌ عَنْ فُلَانٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْهُمْ فَقَالَ اللَّهُ أَعْلَمُ بِمَا كَانُوا عَامِلِينَ قَالَ فَلَقِيتُ الرَّجُلَ فَأَخْبَرَنِي فَأَمْسَكْتُ عَنْ قَوْلِي","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad yaitu Ibnu Salamah], telah mengabarkan kepada kami [Ammar yaitu Ibnu Abu Amar] dari [Ibnu Abbas] dia berkata; telah tiba masaku untuk mengatakan; \"Anak-anak kaum muslimin bersama kaum muslimin sedangkan anak-anak kaum musyrikin bersama orang-orang musyrik, \" hingga si fulan bercerita kepadaku dari [fulan] bahwa Rasulullah Shallalahu 'Alaihi Wasallam pernah ditanya tentang mereka (anak-anak tersebut), beliau menjawab: \"Allah yang lebih tahu terhadap apa yang mereka lakukan.\" Ibnu Abbas berkata; \"Kemudian aku bertemu dengan seorang lelaki, lalu dia mengabarkan kepadaku, namun aku menahan ucapanku.\""},"2786":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ سَمِعْتُ شَيْخًا مِنْ قَيْسٍ يُحَدِّثُ عَنْ أَبِيهِ أَنَّهُ قَالَجَاءَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَنَا بَكْرَةٌ صَعْبَةٌ لَا يُقْدَرُ عَلَيْهَا قَالَ فَدَنَا مِنْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَ ضَرْعَهَا فَحَفَلَ فَاحْتَلَبَ قَالَ وَلَمَّا مَاتَ أَبِي جَاءَ وَقَدْ شَدَدْتُهُ فِي كَفَنِ��ِ وَأَخَذْتُ سُلَّاءَةً فَشَدَدْتُ بِهَا الْكَفَنَ فَقَالَ لَا تُعَذِّبْ أَبَاكَ بِالسُّلَّى قَالَهَا حَمَّادٌ ثَلَاثًا قَالَ ثُمَّ كَشَفَ عَنْ صَدْرِهِ وَأَلْقَى السُّلَّى ثُمَّ بَزَقَ عَلَى صَدْرِهِ حَتَّى رَأَيْتُ رُضَاضَ بُزَاقِهِ عَلَى صَدْرِهِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah], dia berkata; aku mendengar [seorang syaikh] dari bani Qais yang bercerita dari [Ayahnya] bahwa dia berkata; Nabi Shallalahu 'Alaihi Wasallam datang kepada kami, sementara kami hanya memiliki seekor unta muda yang payah dan tidak termanfaatkan, dia berkata; \"Kemudian Rasulullah Shallalahu 'Alaihi Wasallam mendekatinya lalu mengusap susunya, menampung dan memerahnya, ketika ayahku wafat, beliau datang sementara aku tengah mengencangkan kafannya, aku mengambil duri pohon kurma yang aku gunakan sebagai pengencang kafan, lalu beliau bersabda: \"Janganlah kamu menyiksa bapakmu dengan duri kurma!.\" [Hammad] berkata (dalam riwayat); \"Beliau mengatakannya hingga tiga kali, \" dia berkata; \"Kemudian beliau membuka bagian dadanya dan membuang duri kurma, dan meludahi dadanya, sehingga aku melihat tetesan ludah beliau di atas dada ayahku.\""},"2787":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ مُعَاذِ بْنِ رِفَاعَةَ الْأَنْصَارِيِّ عَنْ رَجُلٍ مِنْ بَنِي سَلِمَةَ يُقَالُ لَهُ سُلَيْمٌأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ مُعَاذَ بْنَ جَبَلٍ يَأْتِينَا بَعْدَمَا نَنَامُ وَنَكُونُ فِي أَعْمَالِنَا بِالنَّهَارِ فَيُنَادِي بِالصَّلَاةِ فَنَخْرُجُ إِلَيْهِ فَيُطَوِّلُ عَلَيْنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ بْنَ جَبَلٍ لَا تَكُنْ فَتَّانًا إِمَّا أَنْ تُصَلِّيَ مَعِي وَإِمَّا أَنْ تُخَفِّفَ عَلَى قَوْمِكَ ثُمَّ قَالَ يَا سُلَيْمُ مَاذَا مَعَكَ مِنْ الْقُرْآنِ قَالَ إِنِّي أَسْأَلُ اللَّهَ الْجَنَّةَ وَأَعُوذُ بِهِ مِنْ النَّارِ وَاللَّهِ مَا أُحْسِنُ دَنْدَنَتَكَ وَلَا دَنْدَنَةَ مُعَاذٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَلْ تَصِيرُ دَنْدَنَتِي وَدَنْدَنَةُ مُعَاذٍ إِلَّا أَنْ نَسْأَلَ اللَّهَ الْجَنَّةَ وَنَعُوذَ بِهِ مِنْ النَّارِثُمَّ قَالَ سُلَيْمٌ سَتَرَوْنَ غَدًا إِذَا الْتَقَى الْقَوْمُ إِنْ شَاءَ اللَّهُ قَالَ وَالنَّاسُ يَتَجَهَّزُونَ إِلَى أُحُدٍ فَخَرَجَ وَكَانَ فِي الشُّهَدَاءِ رَحْمَةُ اللَّهِ وَرِضْوَانُهُ عَلَيْهِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami ['Amru bin Yahya] dari [Mu'adz bin Rifa'ah Al Anshari] dari seorang lelaki bani Salamah yang dipanggil dengan [Sulaim], dia pernah datang kepada Rasulullah Shallalahu 'Alaihi Wasallam seraya berkata; \"Wahai Rasulullah, sungguh Mu'adz bin Jabal datang kepada kami ketika kami sedang tertidur, dan ketika kami tengah bekerja di siang hari, kemudian dia menyeru untuk shalat, lantas kami pun keluar menemuinya, namun dia malah memanjangkan (shalatnya).\" Rasulullah Shallalahu 'Alaihi Wasallam lalu bersabda: \"Wahai Mu'adz, janganlah kamu menjadi pembuat fitnah, hendaknya jika kamu shalat dengan aku maka ringankanlah (shalatmu) atas kaummu!.\" kemudian beliau bertanya: \"Wahai Sulaim, apa yang kamu hafal dari Al Qur'an?.\" Dia menjawab; \"Sesungguhnya aku memohon Surga kepada Allah dan berlindung kepadaNya dari api neraka, demi Allah aku tidak bisa seperti bacaan engkau dan tidak juga bacaan Mu'adz.\" Kemudian Rasulullah Shallalahu 'Alaihi Wasallam bertanya: \"Bukankah bacaanku dan bacaan Mu'adz tidak lain agar kita memohon Surga kepada Allah dan berlindung kepadanya dari api neraka?.\" Kemudian Sulaim berkata; 'Besok insya`allah (jika Allah menghendaki) kalian akan melihat apabila dua pasukan telah berhadapan.' Mu'adz berkata; Orang-orang bersiap siap menuju Uhud, kemudian ia keluar (ikut bertempur), dan dia termasuk dalam kelompok orang-orang yang mati Syahid, semoga Rahmat Allah dan keridla`anNya di berikan kepadanya."},"2788":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِأَنَّ يَوْمَ حُنَيْنٍ كَانَ مَطِيرًا قَالَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنَادِيَهُ أَنَّ الصَّلَاةَ فِي الرِّحَالِحَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ سَوَاءً","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] dari [Abu Malih] dari [Ayahnya] bahwa terjadi hujan lebat pada saat perang Hunain, maka Rasulullah Shallalahu 'Alaihi Wasallam memerintahkan mu`adzinnya supaya menyerukan shalat di persinggahan masing-masing.\" Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi Shalallahu 'Alaihi Wasallam dengan lafadz yang sama.\""},"2789":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا أَبُو الْمَلِيحِ عَنْ أَبِيهِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ حُنَيْنٍ فِي يَوْمٍ مَطِيرٍ الصَّلَاةُ فِي الرِّحَالِ","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Aban], telah menceritakan kepada kami [Qatadah] dari [Abu Malih] dari [Ayahnya] bahwa Nabi Shalallahu 'Alaihi Wasallam bersabda pada saat perang Hunain di waktu turun hujan: \"Shalatlah di persinggahan masing-masing.\""},"2790":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ قَالَصَلَّيْتُ الْعِشَاءَ الْآخِرَةَ بِالْبَصْرَةِ وَمُطِرْنَا ثُمَّ جِئْتُ أَسْتَفْتِحُ قَالَ فَقَالَ لِي أَبُو أُسَامَةَ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْحُدَيْبِيَةِ مُطِرْنَا فَلَمْ تَبُلَّ السَّمَاءُ أَسَافِلَ نِعَالِنَا فَنَادَى مُنَادِي النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ صَلُّوا فِي رِحَالِكُمْ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Sufyan] dari [Khalid Al Hadza`] dari [Abu Qilabah] dari [Abu Malih] ia berkata; Saya pernah shalat isya' di Bashrah, karena kehujanan aku datang meminta dibukakan pintu. Abu Malih berkata; lantas [Abu Usamah] berkata kepadaku; \"Aku pernah mengalami saat bersama Rasulullah Shallalahu 'Alaihi Wasallam di peristiwa Hudaibiyah, saat itu juga terjadi hujan, padahal air langit tidak membasahi sandal-sandal kami, namun mu`adzin Rasulullah Shallalahu 'Alaihi Wasallam menyerukan untuk shalat di rumah persinggahan masing-masing."},"2791":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا سَعِيدٌ وَابْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ جُلُودِ السِّبَاعِ","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Sa'id] -dan [Ibnu Ja'far] telah menceritakan kepada kami [Sa'id] - dari [Qatadah] dari [Abu Malih bin Usamah] dari [Ayahnya] bahwa Rasulullah Shallalahu 'Alaihi Wasallam melarang (mengkonsumsi) kulit binatang buas.\""},"2792":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ قَالَخَرَجْتُ إِلَى الْمَسْجِدِ فِي لَيْلَةٍ مَطِيرَةٍ فَلَمَّا رَجَعْتُ اسْتَفْتَحْتُ فَقَالَ أَبِي مَنْ هَذَا قَالُوا أَبُو الْمَلِيحِ قَالَ لَقَدْ رَأَيْتُنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْحُدَيْبِيَةِ وَأَصَابَتْنَا سَمَاءٌ لَمْ تَبُلَّ أَسَافِلَ نِعَالِنَا فَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ صَلُّوا فِي رِحَالِكُمْ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dari [Abu MAlih bin Usamah] ia berkata; Aku keluar di saat malam turunnya hujan menuju masjid, ketika aku pulang dan minta dibukakan pintu, [Ayahku] bertanya; \"Siapa ini?.\" Mereka menjawab; \"Abu Malih.\" Ayahkku berkata; \"Sungguh kami telah menyaksikan bersama Nabi Shalallahu 'Alaihi Wasallam saat perjanjian Hudaibiyah, kami kehujanan padahal hujan tidak sampai membasahi sandal-sandal kami, lantas mu`adzin Rasulullah Shallalahu 'Alaihi Wasallam menyerukan; \"Shalatlah kalian di persinggahan masing-masing.\""},"2793":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ حَدَّثَنِي شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَبَا الْمَلِيحِ يُحَدِّثُ عَنْ أَبِيهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتٍ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يَقْبَلُ صَلَاةً بِغَيْرِ طُهُورٍ وَلَا صَدَقَةً مِنْ غُلُولٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] -dan [Hajjaj] telah menceritakan kepadaku [Syu'bah] - dari [Qatadah] dia berkata; saya mendengar [Abul Malih] bercerita dari [Ayahnya] bahwa dia mendengar Nabi Shallalahu 'Alaihi Wasallam ketika berada dalam rumah, beliau bersabda: \"Sesungguhnya Allah 'azza wajalla tidak menerima shalat tanpa bersuci dan tidak menerima harta sedekah dari hasil Ghulul (mengambil harta ghanimah sebelum dibagi).\""},"2794":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا هَمَّامٌ أَخْبَرَنَا قَتَادَةُ أَنَّ أَبَا الْمَلِيحِ أَخْبَرَهُ عَنْ أَبِيهِأَنَّ يَوْمَ حُنَيْنٍ كَانَ يَوْمًا مَطِيرًا فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنَادِيَهُ يُنَادِي الصَّلَاةُ فِي الرِّحَالِ","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Hammam], telah mengabarkan kepada kami [Qatadah] bahwa [Abu Malih] telah mengabarkan kepadanya, dari [Ayahnya] bahwa terjadi hujan pada saat perang Hunain, lalu Nabi Shallalahu 'Alaihi Wasallam memerintahkan mu`adzinnya supaya menyerukan shalat di persinggahan masing-masing."},"2795":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ جُلُودِ السِّبَاعِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'id] dari [Qatadah] dari [Abu Malih] dari [Ayahnya] bahwa Rasulullah Shallalahu 'Alaihi Wasallam melarang (menkonsumsi) kulit binatang buas.\""},"2796":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدٍ حَدَّثَنَا قَتَادَةُ قَالَ سَمِعْتُ أَبَا الْمَلِيحِ يُحَدِّثُ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يَقْبَلُ صَدَقَةً مِنْ غُلُولٍ وَلَا صَلَاةً بِغَيْرِ طُهُورٍ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'id], telah menceritakan kepada kami [Qatadah] ia berkata; aku mendengar [Abul Malih] bercerita dari [Ayahnya] bahwa dia mendengar Nabi Shallalahu 'Alaihi Wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla tidak menerima harta sedekah dari hasil Ghulul (mengambil harta ghanimah sebelum dibagi) dan tidak menerima shalat tanpa bersuci.\""},"2797":{"ar":"حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِأَنَّهُ شَهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحُنَيْنٍ فِي يَوْمٍ مَطِيرٍ أَمَرَ مُنَادِيَهُ فَيُنَادِي إِنَّ الصَّلَاةَ فِي الرِّحَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Sa'id] dari [Qatadah] bahwa [Abu Malih] dari [Ayahnya] bahwa ia pernah menyaksikan Rasulullah Shallalahu 'Alaihi Wasallam pada perang Hunain di saat terjadi hujan, lalu beliau menyuruh mu`adzinnya, lantas mu`adzinnya menyeru; \"Sesungguhnya shalat di kerjakan di persinggahan masing-masing.\""},"2798":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ بْنُ زَيْدٍ عَنْ عَطَاءٍ الْخُرَاسَانِيِّ قَالَكَانَ نُبَيْشَةُ الْهُذَلِيُّ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْمُسْلِمَ إِذَا اغْتَسَلَ يَوْمَ الْجُمُعَةِ ثُمَّ أَقْبَلَ إِلَى الْمَسْجِدِ لَا يُؤْذِي أَحَدًا فَإِنْ لَمْ يَجِدْ الْإِمَامَ خَرَجَ صَلَّى مَا بَدَا لَهُ وَإِنْ وَجَدَ الْإِمَامَ قَدْ خَرَجَ جَلَسَ فَاسْتَمَعَ وَأَنْصَتَ حَتَّى يَقْضِيَ الْإِمَامُ جُمُعَتَهُ وَكَلَامَهُ إِنْ لَمْ يُغْفَرْ لَهُ فِي جُمُعَتِهِ تِلْكَ ذُنُوبُهُ كُلُّهَا أَنْ تَكُونَ كَفَّارَةً لِلْجُمُعَةِ الَّتِي قَبْلَهَا","id":"Telah menceritakan kepada kami [Ali bin Ishaq], telah mengabarkan kepada kami [Abdullah], telah mengabarkan kepada kami [Yunus bin Zaid] dari [Atha` Al Khurasani] dia berkata; [Nubaisyah Al Hudzali] bercerita dari Rasulullah Shallalahu 'Alaihi Wasallam bahwa apabila seorang muslim mandi pada hari Jum'at, lalu menuju masjid dan tidak menyakiti seseorang, dan ia mendapati Imam belum muncul, maka dia telah melaksanakan shalat dengan sempurna, dan apabila mendapati imam sudah muncul, lalu ia duduk, mendengarkan dan merenungkan sehingga imam menyelesaikan khutbah Jum'atnya dan ucapannya, jika dosa-dosanya seluruhnya tidak diampuni pada hari jum'atnya itu, niscaya hal itu akan menjadi penghapus dosa-dosanya pada hari Jum'at sebelumnya.\""},"2799":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا خَالِدٌ عَنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَ الْهُذَلِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيَّامُ التَّشْرِيقِ أَيَّامُ أَكْلٍ وَشُرْبٍ وَذِكْرِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Husyaim], telah mengabarkan kepada kami [Khalid] dari [Abul Malih] dari [Nubaisyah Al Hudzali] dia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Hari-hari Tasyrik (tanggal sebelas, dua belas dan tiga belas Dzulhijah) adalah hari-hari untuk makan, minum, dan berdzikir kepada Allah 'azza wajalla.\""},"2800":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ عَنْ نُبَيْشَةَ الْهُذَلِيِّ قَالَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً فِي الْجَاهِلِيَّةِ فَمَا تَأْمُرُنَا قَالَ اذْبَحُوا لِلَّهِ عَزَّ وَجَلَّ فِي أَيِّ شَهْرٍ مَا كَانَ وَبَرُّوا اللَّهَ تَبَارَكَ وَتَعَالَى وَأَطْعِمُوا قَالُوا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نُفَرِّعُ فِي الْجَاهِلِيَّةِ فَرَعًا فَمَا تَأْمُرُنَا قَالَ فِي كُلِّ سَائِمَةٍ فَرَعٌ تَغْذُوهُ مَاشِيَتُكَ حَتَّى إِذَا اسْتَحْمَلَ ذَبَحْتَهُ فَتَصَدَّقْتَ بِلَحْمِهِ قَالَ خَالِدٌ أُرَاهُ قَالَ عَلَى ابْنِ السَّبِيلِ فَإِنَّ ذَلِكَ هُوَ خَيْرٌ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا كُنَّا نَهَيْنَاكُمْ أَنْ تَأْكُلُوا لُحُومَهَا فَوْقَ ثَلَاثٍ كَيْ تَسَعَكُمْ فَقَدْ جَاءَ اللَّهُ بِالسَّعَةِ فَكُلُوا وَادَّخِرُوا وَاتَّجِرُوا أَلَا وَإِنَّ هَذِهِ الْأَيَّامَ أَيَّامُ أَكْلٍ وَشُرْبٍ وَذِكْرِ اللَّهِ تَبَارَكَ وَتَعَالَىقَالَ خَالِدٌ قُلْتُ لِأَبِي قِلَابَةَ كَمْ السَّائِمَةُ قَالَ مِائَةٌ","id":"Telah menceritakan kepada kami [Isma'il] dari [Khalid Al Hadza`] dari [Abul Malih bin Usamah] dari [Nubaisyah Al Hudzali] ia berkata; orang-orang bertanya; \"Wahai Rasulullah, dahulu kami biasa menyembelih hewan sembelihan di bulan Rajab pada zaman jahiliyah, lantas apa yang engkau perintahkan kepada kami?.\" beliau bersabda: \"Sembelihlah sembelihan karena Allah Tabaraka Wata'ala di bulan manapun, berbuat baiklah kepada Allah dan berilah makan (dari daging sembelihan)!.\" Mereka bertanya lagi; \"Wahai Rasulullah, kamipun biasa menyembelih anak unta di zaman jahiliyah, bagaimana pendapatmu?.\" Beliau bersabda: \"Di setiap sa`imah yang kalian gembalakan dan telah cukup umur untuk di sembelih, maka sembelihdan sedekahkanlah dagingnya.\" Khalid berkata; \"Aku mengira belaiu bersabda; \"Pada ibnu sabiil (orang-orang yang mengadakan perjalanan), maka itu merupakan kebaikan buat kalian, \" Nubaisyah berlata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku melarang kalian memakan dagingnya (daging sembelihan kurban) melewati tiga hari supaya kalian merasa lapang, sekarang Allah telah melapangkan kalian, oleh karena itu makanlah, simpanlah dan sedekahkanlah untuk memperoleh pahala, ketahuilah sesungguhnya hari ini adalah hari makan, minum dan berzikir kepada Allah Tabaraka wa Ta'ala.\" Khalid berkata; Aku berktanya kepada Abu Qilabah; \"Berapa sa`imah-kah (yang disembelih saat itu)?.\" Ia menjawab; \"Seratus.\" "},"2801":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا الْمُعَلَّى بْنُ رَاشِدٍ الْهُذَلِيُّ قَالَ حَدَّثَتْنِي جَدَّتِي أُمُّ عَاصِمٍ عَنْ رَجُلٍ مِنْ هُذَيْلٍ يُقَالُ لَهُ نُبَيْشَةُ الْخَيْرِ وَكَانَتْ لَهُ صُحْبَةٌ قَالَتْدَخَلَ عَلَيْنَا نُبَيْشَةُ وَنَحْنُ نَأْكُلُ فِي قَصْعَةٍ فَقَالَ لَنَا حَدَّثَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَنْ أَكَلَ فِي قَصْعَةٍ ثُمَّ لَحَسَهَا اسْتَغْفَرَتْ لَهُ الْقَصْعَةُحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا رَوْحُ بْنُ عَبْدِ المُؤْمِنِ وَعُبَيْدُ اللَّهِ الْقَوَارِيرِيُّ حَدَّثَنَا عَبْد اللَّهِ قَالَ وَحَدَّثَنِي مُحَمَّدُ بْنُ صُدْرَانَ قَالُوا ثَنَا الْمُعَلَّى بْنُ رَاشِدٍ قَالَ أَحَدُ الْمُحَدِّثِينَ فِيهِ أَبُو الْيَمَانِ النَبَّالُ قَالَ حَدَّثَتْنِي جَدَّتِي أُمُّ عَاصِمٍ عَنْ نُبَيْشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Al Mu'alla bin Rasyid Al Hudzali] ia berkata; telah menceritakan kepadaku nenekku yaitu [Ummu 'Ashim] dari seorang laki-laki dari bani Hudzail yang disebut [Nubaisyah Al Khair] -dia termasuk dari sahabat Nabi shallallahu 'alaihi wasallam- dia berkata; Nubaisyah pernah menemuiku ketika kami tengah makan dengan nampan, lalu ia berkata kepada kami; Nabi Shalallahu 'Alaihi Wasallam telah menceritakan kepada kami bahwa: \"Barangsiapa makan dengan nampan, lalu ia menjilatinya, maka nampan tersebut akan memohon ampunan untuknya.\" Telah menceritakan kepada kami Abdullah, telah menceritakan kepada kami [Rauh bin Abdul Mukmin] dan [Ubaidullah Al Qawariri] telah menceritakan kepada kami Abdullah dia berkata; telah menceritakan kepadaku [Muhammad bin Shudran], mereka berkata; telah menceritakan kepada kami [Al Mu'alla bin Rasyid], telah berkata salah seorang ahli hadits diantaranya adalah Abul Yaman An Nabal, ia berkata; telah menceritakan kepadaku nenekku yaitu [Ummu 'Ashim] dari [Nubaisyah] dari Nabi Shalallahu 'Alaihi Wasallam seperti itu."},"2802":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ قَالَ ابْنُ عَوْنٍ حَدَّثَنَا عَنْ جَمِيلٍ عَنْ أَبِي مَلِيحٍ عَنْ نُبَيْشَةَ قَالَذُكِرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنَّا نَعْتِرُ فِي الْجَاهِلِيَّةِ قَالَ اذْبَحُوا لِلَّهِ تَبَارَكَ وَتَعَالَى فِي أَيِّ شَهْرٍ مَا كَانَ وَبَرُّوا اللَّهَ عَزَّ وَجَلَّ وَأَطْعِمُوا","id":"Telah menceritakan kepada kami [Muhammad bin Abu Adi], [Ibnu 'Aun] berkata; telah menceritakan kepada kami [Jamil] dari [Abul Malih] dari [Nusyaibah] berkata; ia menyebutkan kepada Nabi Shalallahu 'Alaihi Wasallam; Dahulu kami biasa menyembelih hewan kurban pada bulan rajab di zaman jahiliyah, lalu beliau bersabda: \"Sembelihlah sembelihan karena Allah Tabaraka wa Ta'ala di bulan manapun, berbuat baiklah kepada Allah dan berilah makan (dari daging sembelihan tersebut)!.\""},"2803":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا خَالِدٌ عَنْ أَبِي مَلِيحٍ عَنْ نُبَيْشَةَ الْهُذَلِيِّ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً لَنَا فِي الْجَاهِلِيَّةِ فَمَا تَأْمُرُنَا قَالَ قَالَ اذْبَحُوا فِي أَيِّ شَهْرٍ مَا كَانَ وَبَرُّوا اللَّهَ تَبَارَكَ وَتَعَالَى وَأَطْعِمُوا قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نُفَرِّعُ فَرَعًا فِي الْجَاهِلِيَّةِ فَمَا تَأْمُرُنَا قَالَ فِي كُلِّ سَائِمَةٍ فَرَعٌ تَغْذُوهُ مَاشِيَتُكَ فَإِذَا اسْتَحْمَلَ ذَبَحْتَهُ وَتَصَدَّقْتَ بِلَحْمِهِ قَالَ أَحْسَبُهُ قَالَ عَلَى ابْنِ السَّبِيلِ فَإِنَّ ذَلِكَ خَيْرٌ","id":"Telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Khalid] dari [Abu Malih] dari [Nubaisyah Al Hudzali] ia berkata; Aku bertanya kepada Rasulullah Shallalahu 'Alaihi Wasallam; \"Sesunguhnya kami dulu biasa menyembelih hewan sembelihan (di bulan Rajab) pada zaman jahiliyah, lantas apa yang engkau perintahkan pada kami?.\" beliau bersabda: \"Sembelihlah sembelihan di bulan manapun, berbuat baiklah kepada Allah Tabaraka Wata'ala dan bagi-bagikanlah makanan (sembelihan) tersebut!.\" Mereka bertanya lagi; \"Wahai Rasulullah, kamipun biasa menyembelih domba (untuk Tuhan-tuhan) di zaman jahiliyah, bagaimana pendapatmu?.\" Beliau bersabda: \"Di setiap sa`imah dari far' yang kalian gembalakan, dan ketika sudah cukup umur untuk di sembelih, maka sedekahkanlah dagingnya kepada orang-orang yang dalam perjalanan.\" Aku menyangka beliau bersabda: \"Pada ibnu sabil (orang-orang yang mengadakan perjalanan), karena hal itu lebih baik.\" "},"2804":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا خَالِدٌ عَنْ أَبِي مَلِيحِ بْنِ أُسَامَةَ عَنْ نُبَيْشَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا كُنَّا نَهَيْنَاكُمْ أَنْ تَأْكُلُوا لُحُومَهَا فَوْقَ ثَلَاثٍ كَيْ يَسَعَكُمْ فَقَدْ جَاءَ اللَّهُ تَبَارَكَ وَتَعَالَى بِالسَّعَةِ فَكُلُوا وَادَّخِرُوا وَاتَّجِرُوا أَلَا وَإِنَّ هَذِهِ الْأَيَّامَ أَيَّامُ أَكْلٍ وَشُرْبٍ وَذِكْرِ اللَّهِ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Khalid] dari [Abu Malih bin Usamah] dari [Nubaisyah] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"sesungguhnya kami telah melarang kalian memakan daging kurban lebih dari tiga hari, agar kalian menjadi lapang, dan sungguh Allah Tabaraka wa Ta'ala telah datang dengan kelapangan, maka makanlah, dan simpanlah serta bersedekahlah untuk memperoleh pahala darinya. Ketahuilah hari ini adalah hari makan, minum dan berzikir kepada Allah Tabaraka Wata'ala.\""},"2805":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ قَالَ خَالِدٌ وَأَحْسَبُنِي قَدْ سَمِعْتُهُ عَنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَ رَجُلٍ مِنْ هُذَيْلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُ قَالَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ فَوْقَ ثَلَاثٍ كَيْمَا تَسَعَكُمْ فَقَدْ جَاءَ اللَّهُ تَعَالَى بِالْخَيْرِ فَكُلُوا وَادَّخِرُوا وَاتَّجِرُوا وَإِنَّ هَذِهِ الْأَيَّامَ أَيَّامُ أَكْلٍ وَشُرْبٍ وَذِكْرٍ لِلَّهِ تَعَالَى فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَعْتِرُ عَتِيرَةً فِي الْجَاهِلِيَّةِ فِي رَجَبٍ فَمَا تَأْمُرُنَا فَقَالَ اذْبَحُوا لِلَّهِ تَبَارَكَ وَتَعَالَى فِي أَيِّ شَهْرٍ مَا كَانَ وَبَرُّوا اللَّهَ عَزَّ وَجَلَّ وَأَطْعِمُوا فَقَالَ رَجُلٌ آخَرُ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نُفَرِّعُ فَرَعًا فِي الْجَاهِلِيَّةِ فَمَا تَأْمُرُنَا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كُلِّ سَائِمَةٍ مِنْ الْغَنَمِ فَرَعٌ تَغْذُوهُ غَنَمُكَ حَتَّى إِذَا اسْتَحْمَلَ ذَبَحْتَهُ فَتَصَدَّقْتَ بِلَحْمِهِ عَلَى ابْنِ السَّبِيلِ فَإِنَّ ذَلِكَ هُوَ خَيْرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Khalid] dari [Abu Qilabah] dari [Abu Malih bin Usamah] dari [Nubaisyah] -seorang laki-laki dari penduduk Hudzail dan termasuk dari sahbat Nabi shallallahu 'alaihi wasallam-, bahwa beliau (Nabi) bersabda; \"Hanyasanya aku melarang kalian memakan daging kurban lebih dari tiga hari hingga kalian merasa lapang, dan (sekarang) Allah Ta'ala telah mendatangkan kebaikan. Oleh Karena itu, makanlah, dan simpanlah serta bersedekahlah untuk memperoleh pahala darinya, karena hari ini adalah hari makan, minum dan berzikir kepada Allah Ta'ala.\" Lalu seseorang bertanya; \"Wahai Rasulullah, kami biasa menyembelih hewan sembelihan (di bulan Rajab) pada zaman jahiliyah, lantas apa yang engkau perintahkan (sekarang) kepada kami?.\" beliau bersabda: \"Sembelihlah karena Allah Tabrakan wa Ta'ala di bulan manapun, berbuat baiklah kepada Allah Azza wa Jalla dan bagi-bagikanlah daging sembelihannya!.\" Mereka bertanya lagi; \"Wahai Rasulullah, kamipun biasa menyembelih domba (untuk Tuhan-tuhan) di zaman jahiliyah, bagaimana pendapatmu?.\" Maka Raasulullah shallallahu 'alaihi wasallam bersabda: \"Di setiap sa`imah dari far' yang kalian gembalakan, dan ketika sudah cukup umur untuk di sembelih, maka sedekahkanlah dagingnya kepada orang-orang yang dalam perjalanan, karena hal itu lebih baik.\" "},"2806":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدُ الْكَرِيمِ عَنْ حَبِيبِ بْنِ مِخْنَفٍ قَالَانْتَهَيْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ قَالَ وَهُوَ يَقُولُ هَلْ تَعْرِفُونَهَا قَالَ فَمَا أَدْرِي مَا رَجَعُوا عَلَيْهِ قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كُلِّ بَيْتٍ أَنْ يَذْبَحُوا شَاةً فِي كُلِّ رَجَبٍ وَكُلِّ أَضْحَى شَاةً","id":"Telah menceritakan kepada kami [Abdurrazaq], telah menceritakan kepada kami [Ibnu Juraij], telah mengabarkan kepadaku [Abdul Karim] dari [Habib bin Mikhnaf] IA berkata; Aku menemui Nabi Shalallahu 'Alaihi Wasallam di hari Arafah, lalu beliau bertanya; \"Tahukah kalian?.\" Dia berkata; 'Aku tidak mengerti apa yang mereka kembalikan.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Hendaklah setiap rumah menyembelih seekor kambing di setiap bulan Rajab dan hari Adha (Dzulhijjah) seekor kambing juga.\""},"2807":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٌٍ حَدَّثَنَا ابْنُ عَوْنٍ قَالَ أَنْبَأَنِي أَبُو رَمْلَةَ عَنْ مِخْنَفِ بْنِ سُلَيْمٍ قَالَ رَوْحٌ الْغَامِدِيّ�� قَالَوَنَحْنُ وُقُوفٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّ عَلَى أَهْلِ كُلِّ بَيْتٍ فِي كُلِّ عَامٍ أَضْحَاةً وَعَتِيرَةً أَتَدْرُونَ مَا الْعَتِيرَةُ هِيَ الَّتِي يُسَمِّيهَا النَّاسُ الرَّجَبِيَّةُ","id":"Telah menceritakan kepada kami [Mu'adz bin Mu'adz], telah menceritakan kepada kami [Ibnu 'Aun], ia berkata; telah memberitakan kepadaku [Abu Ramlah] dari [Mikhnaf bin Sulaim], [Rauh Al Ghamidi] berkata; \"Kami sedang wukuf bersama Nabi Shalallahu 'Alaihi Wasallam di Arafah, lalu beliau bersabda: \"Wahai manusia, hendaklah setiap penghuni rumah di tiap tahunnya berkurban dengan satu kurban dan 'atirah, tahukah kalian apa itu 'atirah? Yaitu yang biasa di sebut orang-orang dengan rajabiyah.\" "},"2808":{"ar":"حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ قَالَ حَدَّثَنِي عَزْرَةُ الْأَنْصَارِيُّ حَدَّثَنَا عِلْبَاءُ بْنُ أَحْمَرَ حَدَّثَنَا أَبُو زَيْدٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْتَرِبْ مِنِّي فَاقْتَرَبْتُ مِنْهُ فَقَالَ أَدْخِلْ يَدَكَ فَامْسَحْ ظَهْرِي قَالَ فَأَدْخَلْتُ يَدِي فِي قَمِيصِهِ فَمَسَحْتُ ظَهْرَهُ فَوَقَعَ خَاتَمُ النُّبُوَّةِ بَيْنَ إِصْبَعَيَّ قَالَ فَسُئِلَ عَنْ خَاتَمِ النُّبُوَّةِ فَقَالَ شَعَرَاتٌ بَيْنَ كَتِفَيْهِ","id":"Telah menceritakan kepada kami [Harami bin Umarah] ia berkata; telah menceritakan padaku ['Azrah Al Anshari], telah menceritakan kepada kami ['Ilba' bin Ahmar] telah menceritakan kepada kami [Abu Zaid], ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda kepadaku: \"Mendekatlah padaku!.\" Akupun mendekat ke beliau, beliau bersabda: \"Masukkanlah tanganmu dan usaplah punggungku!.\" Akupun memasukkan tanganku ke gamis beliau, aku mengusap punggung beliau hingga jari-jemariku menyentuh tanda kenabian, \" 'Ilba` berkata; kemudian Abu Zaid di tanya mengenai tanda kenabian tersebut, ia menjawab; \"Yaitu rambut-rambut halus yang Itumbuh) diantara dua pundak beliau.\""},"2809":{"ar":"حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ حَدَّثَنَا عِلْبَاءُ بْنُ أَحْمَرَ حَدَّثَنَا أَبُو زَيْدٍ الْأَنْصَارِيُّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْنُ مِنِّي قَالَ فَمَسَحَ بِيَدِهِ عَلَى رَأْسِهِ وَلِحْيَتِهِ قَالَ ثُمَّ قَالَ اللَّهُمَّ جَمِّلْهُ وَأَدِمْ جَمَالَهُقَالَ فَلَقَدْ بَلَغَ بِضْعًا وَمِائَةَ سَنَةٍ وَمَا فِي رَأْسِهِ وَلِحْيَتِهِ بَيَاضٌ إِلَّا نَبْذٌ يَسِيرٌ وَلَقَدْ كَانَ مُنْبَسِطَ الْوَجْهِ وَلَمْ يَنْقَبِضْ وَجْهُهُ حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Harami bin Umarah] ia berkata; telah menceritakan kepadaku ['Azrah bin Tsabit Al Anshari], telah menceritakan kepada kami ['Ilba` bin Ahmar] telah menceritakan kepada kami [Abu Zaid Al Anshari], ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda kepadaku: \"Mendekatlah padaku!.\" Lalu beliau mengusap rambut kepalanya dan jenggotnya dengan tangan beliau, Abu Zaid berkata; kemudian beliau berdo'a: \"Ya Allah, indahkanlah dan kekalkan keindahannya.\" Perawi berkata; \"Sungguh umurnya (Abu Zaid) Telah mencapai seratus tahun lebih, namun tiada warna putih di rambut dan jenggotnya kecuali sedikit, ia adalah sosok yang bermuka ceria, dan wajahnya tidak berubah hingga ia meninggal.\""},"2810":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ بُجْدَانَ عَنْ أَبِي زَيْدٍ الْأَنْصَارِيِّ قَالَمَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَظْهُرِ دِيَارِنَا فَوَجَدَ قُتَارًا فَقَالَ مَنْ هَذَا الَّذِي ذَبَحَ قَالَ فَخَرَجَ إِلَيْهِ رَجُلٌ مِنَّا فَقَالَ يَا رَسُولَ اللَّهِ كَانَ هَذَا يَوْمٌ الطَّعَامُ فِيهِ كَرِيهٌ فَذَبَحْتُ لِآكُلَ وَأُطْعِمَ جِيرَانِي قَالَ فَأَعِدْ قَالَ لَا وَالَّذِي لَا إِلَهَ إِلَّا هُوَ مَا عِنْدِي إِلَّا جَذَعٌ مِنْ الضَّأْنِ أَوْ حَمَلٌ قَالَهَا ثَلَاثَ مِرَارٍ قَالَ فَاذْبَحْهَا وَلَا تُجْزِئُ عَنْ أَحَدٍ بَعْدَكَ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Abdul Warits], telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dari ['Amru bin Bujdan] dari [Abu Zaid Al Anshari] dia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam pernah melewati belakang rumah-rumah kami dan mencium bau masakan, maka beliau bertanya: \"Siapa yang telah menyembelih (hewan kurban)?.\" maka salah seorang lelaki dari kami keluar dan berkata; \"Wahai Rasulullah, hari ini adalah hari makan-makan, maka aku menyembelih untuk aku makan dan aku berikan kepada tetanggaku.\" beliau bersabda: \"Ulangilah (kurbanmu).\" dia menjawab; \"Tidak, demi Dzat yang tidak ada Ilah selain Dia, aku tidak punya lagi selain Jadza'ah, atau kambing yang tengah hamil.\" dia mengatakannya hingga tiga kali, beliau lalu bersabda: \"Sembelihlah, dan (ini) tidak berlaku untuk orang lain setelahmu.\" "},"2811":{"ar":"حَدَّثَنَا يُونُسُ وَعَفَّانُ قَالَا ثَنَا غَسَّانُ بْنُ بُرْزِينَ حَدَّثَنَا سَيَّارُ بْنُ سَلَامَةَ الرِّيَاحِيُّ عَنِ الْبَرَاءِ السَّلِيطِيِّ عَنْ نُقَادَةَ الْأَسَدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ بَعَثَ نُقَادَةَ الْأَسَدِيَّ إِلَى رَجُلٍ يَسْتَمْنِحُهُ نَاقَةً لَهُ وَأَنَّ الرَّجُلَ رَدَّهُ فَأَرْسَلَ بِهِ إِلَى رَجُلٍ آخَرَ سِوَاهُ فَبَعَثَ إِلَيْهِ بِنَاقَةٍ فَلَمَّا أَبْصَرَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ جَاءَ بِهَا نُقَادَةُ يَقُودُهَا قَالَ اللَّهُمَّ بَارِكْ فِيهَا وَفِيمَنْ أَرْسَلَ بِهَا قَالَ نُقَادَةُ يَا رَسُولَ اللَّهِ وَفِيمَنْ جَاءَ بِهَا قَالَ وَفِيمَنْ جَاءَ بِهَا فَأَمَرَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحُلِبَتْ فَدَرَّتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ أَكْثِرْ مَالَ فُلَانٍ وَوَلَدَهُ يَعْنِي الْمَانِعَ الْأَوَّلَ اللَّهُمَّ اجْعَلْ رِزْقَ فُلَانٍ يَوْمًا بِيَوْمٍ يَعْنِي صَاحِبَ النَّاقَةِ الَّذِي أَرْسَلَ بِهَا","id":"Telah menceritakan kepada kami [Yunus] dan ['Affan], keduanya berkata; telah menceritakan kepada kami [Ghassan bin Burzin], telah menceritakan kepada kami [Sayyar bin Salamah Ar Riyahi] dari [Al Bara' As Salithi] dari [Nuqadah Al Asadi] bahwa Rasulullah Shallalahu 'Alaihi Wasallam pernah mengutus Nuqadah Al Asadi menemui seorang lelaki yang meminta seekor untanya kepada beliau, dan lelaki tadi menolaknya kemudian diberikan kepada orang lain selain dia, kemudian dia mengirimkan kepadanya seekor unta, maka ketika Rasulullah Shallalahu 'Alaihi Wasallam melihat Nuqadah datang dengan membawanya kembali, beliau bersabda: \"Ya Allah berkahilah dalam unta ini dan orang yang mengirimkannya.\" Nuqadah berkata; \"Wahai Rasulullah, dan juga orang yang datang membawanya?.\" Beliau menjawab: \"Dan juga orang yang datang membawanya, \" Kemudian Rasulullah Shallalahu 'Alaihi Wasallam memerintahkan agar unta diperah dan ketika diperah susunya mengeluarkan banyak, maka Rasulullah Shallalahu 'Alaihi Wasallam berdo'a: \"Ya Allah perbanyaklah harta fulan dan anaknya.\" (yaitu orang yang pertama kali menolak), \"Ya Allah jadikanlah rizqi Fulan terus menerus setiap hari, \" yaitu pemilik unta yang mengirimkannya."},"2812":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ بُدَيْلٍ الْعُقَيْلِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ شَقِيقٍ أَنَّهُ أَخْبَرَهُ مَنْسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِوَادِي الْقُرَى وَهُوَ عَلَى فَرَسِهِ وَسَأَلَهُ رَجُلٌ مِنْ بُلْقِينٍ فَقَالَ يَا رَسُولَ اللَّهِ مَنْ هَؤُلَاءِ قَالَ هَؤُلَاءِ الْمَغْضُوبُ عَلَيْهِمْ فَأَشَارَ إِلَى الْيَهُودِ فَقَالَ مَنْ هَؤُلَاءِ قَالَ هَؤُلَاءِ الضَّالُّونَ يَعْنِي النَّصَارَى قَالَ وَجَاءَهُ رَجُلٌ فَقَالَ اسْتُشْهِدَ مَوْلَاكَ أَوْ قَالَ غُلَامُكَ فُلَانٌ قَالَ بَلْ هُوَ يُجَرُّ إِلَى النَّارِ فِي عَبَاءَةٍ غَلَّهَا","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan pada kami [Ma'mar] dari [Budail Al 'Uqaili], ia berkata; telah mengabarkan kepadaku [Abdullah bin Syaqiq] bahwa [seseorang] yang mendengar Nabi Shallalahu 'Alaihi Wasallam pernah mengabarkan kepadanya, ketika beliau berada di Wadil Qura' tengah mengendarai kudanya, lalu salah seorang lelaki dari Bulqin bertanya kepadanya; \"Wahai Rasulullah siapakah mereka?.\" Beliau menjawab: \"Mereka adalah orang-orang yang mendapat laknat.\" -Sambil menunjuk ke arah orang-orang Yahudi- kemudian laki-laki itu bertanya lagi; \"Siapakah mereka?.\" Beliau menjawab: \"Mereka adalah orang-orang yang sesat yaitu Nasrani.\" Abdullah bin Syaqiq berkata; \"Lalu seorang lelaki datang kepada laki-laki dari Bulqin seraya berkata; \"Bekas budakmu si fulan telah syahid, \" atau dia mengatakan; \"Budakmu si fulan.\" Beliau menimpali: \"Bahkan dia di seret ke dalam api neraka karena mantel yang ia ambil.\""},"2813":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ قَالَكُنْتُ مَعَ مُطَرِّفٍ فِي سُوقِ الْإِبِلِ فَجَاءَ أَعْرَابِيٌّ مَعَهُ قِطْعَةُ أَدِيمٍ أَوْ جِرَابٍ فَقَالَ مَنْ يَقْرَأُ أَوَفِيكُمْ مَنْ يَقْرَأُ قُلْتُ نَعَمْ فَأَخَذْتُهُ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِبَنِي زُهَيْرِ بْنِ أُقَيْشٍ حَيٍّ مِنْ عُكْلٍ إِنَّهُمْ إِنْ شَهِدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَفَارَقُوا الْمُشْرِكِينَ وَأَقَرُّوا بِالْخُمُسِ فِي غَنَائِمِهِمْ وَسَهْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفِيَّهُ فَإِنَّهُمْ آمِنُونَ بِأَمَانِ اللَّهِ وَرَسُولِهِ فَقَالَ لَهُ بَعْضُ الْقَوْمِ هَلْ سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا تُحَدِّثُنَاهُ قَالَ نَعَمْ قَالُوا فَحَدِّثْنَا رَحِمَكَ اللَّهُ قَالَ سَمِعْتُهُ يَقُولُ مَنْ سَرَّهُ أَنْ يَذْهَبَ كَثِيرٌ مِنْ وَحَرِ صَدْرِهِ فَلْيَصُمْ شَهْرَ الصَّبْرِ أَوْ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ فَقَالَ لَهُ الْقَوْمُ أَوْ بَعْضُهُمْ أَأَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا أُرَاكُمْ تَتَّهِمُونِي أَنْ أَكْذِبَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِسْمَاعِيلُ مَرَّةً تَخَافُونَ وَاللَّهِ لَا حَدَّثْتُكُمْ حَدِيثًا سَائِرَ الْيَوْمِ ثُمَّ انْطَلَقَ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Al Jurariri] dari [Abul Ala' bin Asy Syikhkhir] dia berkata; \"Aku pernah bersama Mutharrif didalam pasar unta, tiba-tiba [seorang badui] datang dengan membawa potongan kulit atau potongan bejana kulit, dia bertanya; \"Siapa yang bisa membaca atau adakah di antara kalian yang bisa membaca?.\" Aku menjawab; \"ya, \" Aku mengambilnya dan ternyata isinya \"Bismillaahir rahmanir rahiim, dari Muhammad utusan Allah Shallalahu 'Alaihi Wasallam, kepada bani Zuhair bin Uqais penduduk 'Uqlin, sesungguhnya jika mereka bersaksi bahwa tidak ada Illah (yang berhak disembah) selain Allah dan Muhammad adalah utusan Allah, kemudian mereka memisahkan diri dari orang-orang musyrik, mengakui seperlima harta ghanimah mereka dan bagian Nabi Shallalahu 'Alaihi Wasallam dan hamba pilihan-Nya, niscaya mereka akan aman dengan keamanan Allah dan RasulNya.\" Sebagian orang bertanya; \"Apakah kamu mendengar sesuatu dari Rasulullah Shallalahu 'Alaihi Wasallam yang dapat kamu ceritakan kepada kami?.\" Abu Al 'Ala` menjawab; \"Ya, \" mereka berkata; \"Ceritakanlah kepada kami semoga Allah merahmatimu!.\" Dia menjawab; Aku mendengar beliau bersabda: \"Barangsiapa senang agar rasa dengki di dalam hatinya hilang, maka hendaknya dia berpuasa di bulan Ramadhan, atau tiga hari dalam setiap bulan, \" kemudian sebagian orang-orang bertanya kepadanya; \"Apakah kamu benar mendengar hal ini dari Rasulullah Shallalahu 'Alaihi Wasallam?, \" Abu Al 'Ala` menjawab; \"Ketahuilah, apakah kalian menuduhku berdusta kepada Rasulullah Shallalahu 'Alaihi Wasallam.\" Di kesempatan lain [Isma'il] menyebutkan (dalam riwayatnya) kalimat; \"Apakah kalian merasa khawatir?, demi Allah, jika seperti itu, aku tidak akan menyampaikan kepada kalian satu haditspun sepanjang hari, \" kemudian dia pergi."},"2814":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ هَارُونَ بْنِ رِئَابٍ عَنِ ابْنِ الشِّخِّيرِ عَنْ رَجُلٍ مَنْ بَنِي أُقَيْشٍ قَالَمَعَهُ كِت��ابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صِيَامُ ثَلَاثَةِ أَيَّامٍ مِنْ الشَّهْرِ يُذْهِبُ وَحَرَ الصَّدْرِ","id":"Telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Harun bin Ri`ab] dari [Ibnu Syikhkhir] dari [seorang] dari bani 'Uqaisy, dia berkata; -sedangkan ia membawa kitab Nabi Shalallahu 'Alaihi Wasallam-, Nabi Shalallahu 'Alaihi Wasallam bersabda: \"Puasa tiga hari di setiap bulan dapat menghilangkan kedengkian dalam dada.\""},"2815":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي قَتَادَةَ وَأَبِي الدَّهْمَاءِ قَالَاكَانَا يُكْثِرَانِ السَّفَرَ نَحْوَ هَذَا الْبَيْتِ قَالَا أَتَيْنَا عَلَى رَجُلٍ مِنْ أَهْلِ الْبَادِيَةِ فَقَالَ الْبَدَوِيُّ أَخَذَ بِيَدِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يُعَلِّمُنِي مِمَّا عَلَّمَهُ اللَّهُ تَبَارَكَ وَتَعَالَى وَقَالَ إِنَّكَ لَنْ تَدَعَ شَيْئًا اتِّقَاءَ اللَّهِ عَزَّ وَجَلَّ إِلَّا أَعْطَاكَ اللَّهُ خَيْرًا مِنْهُحَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ قَالَ سَمِعْتُ يَزِيدَ بْنَ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ قَالَ كُنَّا بِالْمِرْبَدِ جُلُوسًا فَأَتَى عَلَيْنَا رَجُلٌ مِنْ أَهْلِ الْبَادِيَةِ لَمَّا رَأَيْنَاهُ قُلْنَا هَذَا كَأَنَّ رَجُلٌ لَيْسَ مِنْ أَهْلِ الْبَلَدِ قَالَ أَجَلْ فَإِذَا مَعَهُ كِتَابٌ فِي قِطْعَةِ أَدِيمٍ قَالَ وَرُبَّمَا قَالَ فِي قِطْعَةِ جِرَابٍ فَقَالَ هَذَا كِتَابٌ كَتَبَهُ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا فِيهِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ هَذَا كِتَابٌ مِنْ مُحَمَّدٍ النَّبِيِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِبَنِي زُهَيْرِ بْنِ أُقَيْشٍ وَهُمْ حَيٌّ مِنْ عُكْلٍ إِنَّكُمْ إِنْ أَقَمْتُمْ الصَّلَاةَ وَآتَيْتُمْ الزَّكَاةَ وَفَارَقْتُمْ الْمُشْرِكِينَ وَأَعْطَيْتُمْ الْخُمُسَ مِنْ الْمَغْنَمِ ثُمَّ سَهْمَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّفِيَّ وَرُبَّمَا قَالَ وَصَفِيَّهُ فَأَنْتُمْ آمِنُونَ بِأَمَانِ اللَّهِ تَبَارَكَ وَتَعَالَى وَأَمَانِ رَسُولِهِ فَذَكَرَ يَعْنِي حَدِيثَ الْجُرَيْرِىِّ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Sulaiman bin Mughirah] dari [Humaid bin Hilal] dari [Abu Qatadah] dan [Abu Ad Dahma'] keduanya berkata; -keduanya sering bepergian bersama menuju bait (Makkah) ini-, keduanya berkata; \"Kami pernah mendatangi salah [seorang] penduduk dusun, kemudian lelaki itu berkata; Rasulullah Shallalahu 'Alaihi Wasallam pernah memegang tanganku kemudian mengajariku sesuatu yang telah Allah Tabaraka Wata'ala ajarkan padanya, beliau bersabda: \"Sungguh, tidaklah sekali-kali kamu meniggalkan sesuatu karena takut kepada Allah 'azza wajalla, melainkan Allah akan memberikan kepadamu kebaikan dari rasa takut tersebut.\" Telah menceritakan kepada kami Rauh bin Ubadah, telah menceritakan kepada kami Qurrah bin Khalid ia berkata; aku mendengar Yazid bin Abdullah bin Asy Syikhkhir berkata; Ketika kami sedang duduk-duduk di Mirbad, tiba-tiba datang seorang lelaki dari penduduk dusun, kami melihatnya dan berkata kepadanya; \"Sepertinya orang ini bukan penduduk kampung ini, \" laki-laki itu menjawab; \"Ya.\" Ternyata ia membawa surat dari potongan kulit. Abdullah bin Asy Syikhkhir berkata; sepertinya ia mengatakan dari potongan bejana kulit. orang dusun itu berkata; \"Ini adalah tulisan yang ditulis oleh Rasulullah Shallalahu 'Alaihi Wasallam untukku.\" Ternyata isinya bertuliskan \"Bismillaahir rahmaanir rahiim, ini adalah tulisan dari Muhammad seorang Nabi utusan Allah Shallalahu 'Alaihi Wasallam untuk bani Zuhair bin Uqais, dan mereka adalah penduduk dari 'Uklin, sesungguhnya jika kalian menegakkan shalat, membayar zakat, memisahkan diri dari orang-orang musyrik dan kalian memberikan seperlima dari harta ghanimah (harta rampasan perang), kemudian (menyisihkan) bagian Nabi Shallalahu 'Alaihi Wasallam dan hamba pilihan-Nya, -mungkin beliau bersabda dengan lafadz shafiyyah (dan hamba pilihanNya), - maka kalian akan aman dengan keamanan Allah Tabaraka Wata'ala dan RasuluNya.\" Kemudian dia menyebutkan hadits Al Jurairi."},"2816":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ سَوَادَةَ الْقُشَيْرِيُّ قَالَ حَدَّثَنِي رَجُلٌ مِنْ أَهْلِ الْبَادِيَةِ عَنْ أَبِيهِ وَكَانَ أَبُوهُ أَسِيرًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَسَمِعْتُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُقْبَلُ صَلَاةٌ لَا يُقْرَأُ فِيهَا بِأُمِّ الْكِتَابِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepadaku [Abdullah bin Sawadah Al Qusyairi] ia berkata; telah menceritakan kepadaku [seorang lelaki] dari penduduk dusun dari [Ayahnya]. -Ayahnya pernah menjadi tawanan Rasulullah Shallalahu 'Alaihi Wasallam- dia berkata; \"Aku mendengar Muhammad Shallalahu 'Alaihi Wasallam bersabda: \"Tidak diterima shalat seseorang yang tidak membaca Ummul Kitab (al Fatehah).\""},"2817":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَنَسِ بْنِ سِيرِينَ عَنْ مَعْبَدِ بْنِ سِيرِينَ عَنْ رَجُلٍ مِنْ الْأَنْصَارِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَتَ مِنْ عِرْقِ النَّسَا أَنْ تُؤْخَذَ أَلْيَةُ كَبْشٍ عَرَبِيٍّ لَيْسَتْ بِصَغِيرَةٍ وَلَا عَظِيمَةٍ فَتُذَابَ ثُمَّ تُجَزَّأَ ثَلَاثَةَ أَجْزَاءٍ فَيُشْرَبَ كُلَّ يَوْمٍ عَلَى رِيقِ النَّفَسِ جُزْءًا","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Hammad bin Salamah] dari [Anas bin sirin] dari [Ma'bad bin Sirin Al Anshari] dari [seorang lelaki] Anshar dari [Ayahnya] bahwa Rasulullah Shallalahu 'Alaihi Wasallam menjelaskan obat penyakit yang menyerang paha, hendaknya bagian ekor (sumsum tulang ekor) kambing dusun diambil, -kambingnya tidak terlalu kecil dan tidak juga terlalu besar-, kemudian dilelehkan dan dibagi menjadi tiga bagian, lalu diminum setiap harinya, yaitu sekali minum satu bagian.\""},"2818":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا أَنَسُ بْنُ سِيرِينَ عَنْ أَخِيهِ مَعْبَدِ بْنِ سِيرِينَ عَنْ رَجُلٍ مَنْ الْأَنْصَارِ عَنْ أَبِيهِ قَالَنَعَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِرْقِ النَّسَا أَنْ تُؤْخَذَ أَلْيَةُ كَبْشٍ عَرَبِيٍّ لَا عَظِيمَةٌ وَلَا صَغِيرَةٌ فَيُذِيبَهَا فَتُجَزَّأَ ثَلَاثَةَ أَجْزَاءٍ فَيَشْرَبَ عَلَى رِيقِ النَّفَسِ كُلَّ يَوْمٍ جُزْءًا","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah] dari [Anas bin Sirin] dari saudaranya yaitu [Ma'bad bin Sirin] dari [seorang lelaki Anshar] dari [Ayahnya] bahwa Rasulullah Shallalahu 'Alaihi Wasallam pernah menjelaskan obat penyakit yang menyerang paha, hendaknya bagian ekor kambing dusun (sumsum tulang ekor) diambil, -kambingnya tidak terlalu kecil dan tidak juga terlalu besar, - kemudian dilelehkan dan dibagi menjadi tiga bagian, lalu diminum setiap harinya, yaitu satu sekali minum satu bagian.\""},"2819":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ عَنْ الْجُرَيْرِيِّ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ رَجُلٍ مِنْ قَوْمِهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ فَقَالَ اقْرَأْ بِهِمَا فِي صَلَاتِكَ بِالْمُعَوِّذَتَيْنِ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Syu'bah] dari [Al Jurairi] dari [Yazid bin Abdullah bin Syikhkhir] dari [seorang lelaki kaumnya] bahwa Rasulullah Shallalahu 'Alaihi Wasallam pernah melewatinya dan bersabda: \"Bacalah dalam shalatmu mu'awwidzatain ('a'udzubillahi minasy syaithanir Rajim).\""},"2820":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ قَالَ قَالَ رَجُلٌكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ وَالنَّاسُ يَعْتَقِبُونَ وَفِي الظَّهْرِ قِلَّةٌ فَحَانَتْ نَزْلَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَزْلَتِي فَلَحِقَنِي مِنْ بَعْدِي فَضَرَبَ مَنْكِبِي فَقَالَ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ فَقُلْتُ أَعُوذُ بِرَبِّ الْفَلَقِ فَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَرَأْتُهَا مَعَهُ ثُمَّ قَالَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَرَأْتُهَا مَعَهُ فَقَالَ إِذَا صَلَّيْتَ فَاقْرَأْ بِهِمَا","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Al Jurariri] dari [Abul 'Ala`] ia berkata; [seseorang] berkata; \"Kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Sementara orang-orang mengikuti beliau. Pada saat Zhuhur tiba, jumlah orang-orang mulai sedikit, Kemudian Rasulullah shallallahu 'alaihi wasallam turun dan aku pun ikut turun. Beliau menemuiku lalu menepuk kedua pundakku. Sabda beliau: \"Ucapkanlah, 'Qul a'udzu birabbil falaq.\" Maka aku pun mengucapkan, \"A'udzu birabbil falaq.\" Rasulullah shallallahu 'alaihi wasallam membacanya lagi lalu aku pun membacanya bersama beliau. Beliau lantas bersabda: \"Ucapkanlah 'Qul a'udzu birabbinnas'!, Rasulullah shallallahu 'alaihi wasallam membacanya dan aku pun membacanya bersama beliau. Sabda beliau: \"Jika kau shalat, bacalah kedua surat tersebut.\""},"2821":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا ثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ قَالَ عَفَّانُ فِي حَدِيثِهِ حَدَّثَنَا أَبُو قَتَادَةَ وَأَبُو الْدَّهْمَاءِ قَالَ عَفَّانُ وَكَانَا يُكْثِرَانِ الْحَجَّ قَالَاأَتَيْنَا عَلَى رَجُلٍ مِنْ أَهْلِ الْبَادِيَةِ فَقَالَ الْبَدَوِيُّ أَخَذَ بِيَدِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يُعَلِّمُنِي مِمَّا عَلَّمَهُ اللَّهُ فَكَانَ فِيمَا حَفِظْتُ عَنْهُ أَنْ قَالَ إِنَّكَ لَنْ تَدَعَ شَيْئًا اتِّقَاءَ اللَّهِ تَبَارَكَ وَتَعَالَى إِلَّا آتَاكَ اللَّهُ خَيْرًا مِنْهُ","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan] keduanya berkata; telah menceritakan kepada kami [Sulaiman bin Mughirah], telah menceritakan kepada kami [Humaid bin Hilal], - ['Affan] mengatakan dalam haditsnya, telah menceritakan kepada kami [Abu Qatadah] dan [Abu Ad Dahma'] - ['Affan] mengatakan; keduanya sering pergi haji bersama, keduanya berkata; Kami pernah mendatangi [salah seorang penduduk dusun], kemudian orang itu berkata; Rasulullah Shallalahu 'Alaihi Wasallam pernah memegang tanganku kemudian mengajariku sesuatu yang telah Allah ajarkan padanya dan aku menghafalnya, beliau bersabda: \"Sungguh, tidaklah sekali-kali kamu meniggalkan sesuatu karena takut kepada Allah 'azza wajalla, melainkan Allah akan memberikan kepadamu kebaikan dari rasa takut tersebut.\""},"2822":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ شَيْخٍ مِنْ بَنِي تَمِيمٍ عَنْ أَبِي سُودٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْيَمِينُ الْفَاجِرَةُ الَّتِي يَقْتَطِعُ بِهَا الرَّجُلُ مَالَ الْمُسْلِمِ تَعْقِمُ الرَّحِمَ","id":"Telah menceritakan kepada kami [Yahya bin Adam], telah menceritakan kepada kami [Ibnu Mubarak] dari [Ma'mar] dari seorang [syaikh] dari bani Tamim dari [Abu Suud] dia berkata; aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Sumpah palsu yang diucapkan seseorang untuk memutuskan perkara harta seorang muslim dapat merusak hubungan silaturrahim.\""},"2823":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ الْقَاسِمِ حَدَّثَنَا مُحَمَّدُ بْنُ ثَابِتٍ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ قَالَ حَدَّثَنِي بَعْضُ أَصْحَابِ مُحَمَّدٍ وَغَزَوْنَا نَحْوَ فَارِسَ فَقَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَاتَ فَوْقَ بَيْتٍ لَيْسَتْ لَهُ إِجَّارٌ فَوَقَعَ فَمَاتَ فَبَرِئَتْ مِنْهُ الذِّمَّةُ وَمَنْ رَكِبَ الْبَحْرَ عِنْدَ ارْتِجَاجِهِ فَمَاتَ فَقَدْ بَرِئَتْ مِنْهُ الذِّمَّةُ","id":"Telah menceritakan kepada kami ['Azhar bin Qasim], telah menceritakan kepada kami [Muhammad bin Tsabit] dari [Abu Imran Al Jauni] dia berkata; telah menceritakan kepadaku [Sebagian sahabat Muhammad]; Kami berperang ke arah Persia, kemudian dia (salah seorang sahabat) Berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Barangsiapa bermalam di atap rumah tanpa ada sesuatu yang menghalangi rumah tersebut (pagar), kemudian dia terjatuh dan mati, maka lepaslah tanggung-jawab darinya, dan barangsiapa mengarungi lautan ketika bergelombang (ombaknya menggulung) kemudian mati, maka terlepaslah tanggungan darinya.\""},"2824":{"ar":"حَدَّثَنَا أَزْهَرُ حَدَّثَنَا هِشَامٌ يَعْنِي الدَّسْتُوَائِيَّ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ قَالَكُنَّا بِفَارِسَ وَعَلَيْنَا أَمِيرٌ يُقَالُ لَهُ زُهَيْرُ بْنُ عَبْدِ اللَّهِ فَقَالَ حَدَّثَنِي رَجُلٌ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَاتَ فَوْقَ إِجَّارٍ أَوْ فَوْقَ بَيْتٍ لَيْسَ حَوْلَهُ شَيْءٌ يَرُدُّ رِجْلَهُ فَقَدْ بَرِئَتْ مِنْهُ الذِّمَّةُ وَمَنْ رَكِبَ الْبَحْرَ بَعْدَ مَا يَرْتَجُّ فَقَدْ بَرِئَتْ مِنْهُ الذِّمَّةُ","id":"Telah menceritakan kepada kami [Azhar], telah menceritakan kepada kami [Hisyam yaitu Ad Dastuwa`i] dari [Abu Imran Al Jauni] ia berkata; Ketika kami menuju Persia sementara kami bersama seorang pemimpin bernama [Zuhair bin Abdullah], Ia berkata; telah menceritakan kepadaku [seorang laki-laki] bahwa Nabi Shalallahu 'Alaihi Wasallam bersabda: \"Barangsiapa bermalam di atap rumah atau loteng tanpa ada sesuatu yang dapat menghalangi dari kakinya (pagar), kemudian dirinya terjerembab lalu mati, maka lepaslah tanggungan darinya, dan barangsiapa mengarungi lautan bergelombang (ombaknya menggulung) kemudian mati, maka terlepaslah tanggungan darinya.\""},"2825":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ قَالَ قَالَ عُبَادَةُ بْنُ قُرْطٍإِنَّكُمْ تَأْتُونَ أَشْيَاءَ هِيَ أَدَقُّ فِي أَعْيُنِكُمْ مِنْ الشَّعْرِ كُنَّا نَعُدُّهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُوبِقَاتِ قَالَ فَذَكَرُوا ذَلِكَ لِمُحَمَّدٍ قَالَ فَقَالَ صَدَقَ أَرَى جَرَّ الْإِزَارِ مِنْهُ","id":"Telah menceritakan kepada kami [Isma'il], telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] ia berkata; [Ubadah bin Qurth] berkata; \"Sungguh kalian mengerjakan amalan yang lebih halus dari rambut di mata kalian, sementara bila amalan tersebut kami kembalikan ke zaman Rasulullah Shallalahu 'Alaihi Wasallam termasuk hal yang membinasakan.\" Humaid berkata; \"Lalu orang-orang memberitahukannya kepada Muhammad (bin Sirin), Muhammad berkata; Ubadah benar, aku melihat kain sarung menjulur (ke tanah).\""},"2826":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا سُلَيْمَانُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي قَتَادَةَ عَنْ عُبَادَةَ بْنِ قُرْطٍ أَوْ قُرْصٍ قَالَإِنَّكُمْ تَعْمَلُونَ أَعْمَالًا هِيَ أَدَقُّ فِي أَعْيُنِكُمْ مِنْ الشَّعْرِ إِنْ كُنَّا لَنَعُدُّهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُوبِقَاتِ","id":"Telah menceritakan kepada kami [Hasyim bin Qasim], telah menceritakan kepada kami [Sulaiman] dari [Humaid bin Hilal] dari [Abu Qatadah] dari [Ubadah bin Qurth atau Qursh] ia berkata; \"Sungguh kalian tahu amalan yang lebih halus dari rambut di mata kalian, namun apabila amalan tersebut kami kembalikan ke zaman Rasulullah Shallalahu 'Alaihi Wasallam termasuk hal yang membinasakan.\""},"2827":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ حَدَّثَنَا أَبُو قَتَادَةَ عَنْ عُبَادَةَ بْنِ قُرْصٍ أَوْ قُرْطٍإِنَّكُمْ لَتَعْمَلُونَ الْيَوْمَ أَعْمَالًا هِيَ أَدَقُّ فِي أَعْيُنِكُمْ مِنْ الشَّعْرِ كُنَّا نَعُدُّهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُوبِقَاتِفَقُلْتُ لِأَبِي قَتَادَةَ فَكَيْفَ لَوْ أَدْرَكَ زَمَانَنَا هَذَا فَقَالَ أَبُو قَتَادَةَ لَكَانَ لِذَلِكَ أَقْوَلَ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Sulaiman bin Mughirah] dari [Humaid bin Hilal], telah menceritakan kepada kami [Abu Qatadah] dari dari [Ubadah bin Qurth atau Qursh] ia berkata; \"Sungguh hari ini kalian tahu amalan yang lebih halus dari rambut di mata kalian, namun sekiranya amalan tersebut kami kembalikan ke zaman Rasulullah Shallalahu 'Alaihi Wasallam, termasuk dari hal yang membinasakan.\" Aku bertanya pada Abu Qatadah bagaimana jika kami mendapatkannya di zaman kami?, [Abu Qatadah] berkata; \"Karena itulah aku mengatakannya.\""},"2828":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ قَالَ قَالَ أَبُو رِفَاعَةَانْتَهَيْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ فَقُلْتُ يَا رَسُولَ اللَّهِ رَجُلٌ غَرِيبٌ جَاءَ يَسْأَلُ عَنْ دِينِهِ لَا يَدْرِي مَا دِينُهُ قَالَ فَأَقْبَلَ إِلَيَّ فَأَتَى بِكُرْسِيٍّ فَقَعَدَ عَلَيْهِ فَجَعَلَ يُعَلِّمُنِي مِمَّا عَلَّمَهُ اللَّهُ تَعَالَى قَالَ ثُمَّ أَتَى خُطْبَتَهُ فَأَتَمَّ آخِرَهَا","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Sulaiman bin Al Mughirah], telah menceritakan kepada kami [Humaid bin Hilal] ia berkata; [Abu Rifa'ah] berkata; \"Aku pernah menemui Rasulullah Shallalahu 'Alaihi Wasallam ketika beliau sedang berkhutbah, aku bertanya; \"Wahai Rasulullah, seorang lelaki asing datang dan bertanya tentang agamanya, dia tidak tahu persoalan agamanya.\" Abu Rifa'ah berkata; \"Beliau lalu mendatangiku dengan membawa kursi lalu duduk di atasnya, beliau mengajariku sesuatu yang telah Allah Ta'ala ajarkan kepadanya. Abu Rifa'ah berkata; \"Kemudian beliau melanjutkan khutbahnya dan menyempurnakan akhir khutbahnya.\""},"2829":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ عَنْ مُطَرِّفٍ قَالَ حَدِيثَانِ بَلَغَانِي عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ عَرَفْتُ أَنِّي قَدْ صَدَّقْتُهُمَا لَا أَدْرِي أَيُّهُمَا قَبْلَ صَاحِبِهِ حَدَّثَنَا أَبُو مُسْلِمٍ الْجَذْمِيُّ جَذِيمَةُ عَبْدِ الْقَيْسِ حَدَّثَنَا الْجَارُودُ قَالَبَيْنَمَا نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ وَفِي الظَّهْرِ قِلَّةٌ إِذْ تَذَاكَرَ الْقَوْمُ الظَّهْرَ فَقُلْتُ يَا رَسُولَ اللَّهِ قَدْ عَلِمْتُ مَا يَكْفِينَا مِنْ الظَّهْرِ فَقَالَ وَمَا يَكْفِينَا قُلْتُ ذَوْدٌ نَأْتِي عَلَيْهِنَّ فِي جُرُفٍ فَنَسْتَمْتِعُ بِظُهُورِهِمْ قَالَ لَا ضَالَّةُ الْمُسْلِمُ حَرَقُ النَّارِ فَلَا تَقْرَبَنَّهَا ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ فَلَا تَقْرَبَنَّهَا ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ فَلَا تَقْرَبَنَّهَا وَقَالَ فِي اللُّقَطَةِ الضَّالَّةُ تَجِدُهَا فَانْشُدَنَّهَا وَلَا تَكْتُمْ وَلَا تُغَيِّبْ فَإِنْ عُرِفَتْ فَأَدِّهَا وَإِلَّا فَمَالُ اللَّهِ يُؤْتِيهِ مَنْ يَشَاءُ","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan pada kami [Sa'id Al Jurairi] dari [Abul 'Ala` bin Syikhkhir] dari [Mutharrif] dia berkata; \"Dua hadits yang telah sampai kepadaku dari Rasulullah Shallalahu 'Alaihi Wasallam, aku tahu bahwa aku telah membenarkan keduanya, dan aku tidak tahu manakah di antara keduanya yang lebih dahulu, telah menceritakan kepada kami [Abu Muslim Al Jadmi Jadzimah Abdul Qais] telah menceritakan kepada kami [Al Jarud] dia berkata; \"Kami bersama Rasulullah Shallalahu 'Alaihi Wasallam dalam suatu perjalanan, sementara waktu zhuhur hampir tiba, orang-orang mengingatkan waktu Zhuhur, aku berkata; \"Wahai Rasulullah aku tahu bahwa kita tidak akan mencukupi waktu Zhuhur.\" Beliau bersabda: \"Apa yang tidak mencukupi kita?.\" Aku berkata; \"Beberapa ekor unta yang kita datangi di ujung sana, kemudian kita bersenang-senang dengan menaikinya.\" Beliau bersabda: \"Tidak, hewan seorang muslim yang hilang adalah pembakar neraka, maka janganlah kamu mendekatinya, hewan seorang muslim yang hilang adalah pembakar api neraka, maka janganlah kamu mendekatinya, hewan seorang muslim yang hilang adalah pembakar api neraka, maka janganlah kamu mendekatinya!.\" Lalu beliau bersabda berkenaan barang temuan: \"Hewan temuan yang kamu dapatkan hendaknya diberitahukan sifat sifatnya dan jangan kamu sembunyikan dan kamu tutup-tutupi, jika diketahui maka berikanlah (kepada pemiliknya), jika tidak maka itu adalah harta Allah yang diberikan kepada siapa yang dikehendakiNya.\""},"2830":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ وَأَحْمَدُ الْحَدَّادُ قَالَ ثَنَا سُفْيَانُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ مُطَرِّفِ بْنِ الشِّخِّيرِ عَنِ الْجَارُودِ الْعَبْدِيِّ يَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ فَلَا تَقْرَبَنَّهَا","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Sufyan] dan [Ahmad Al Haddad] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Khalid Al Hadza`] dari [Yazid bin Abdullah bin Syikhkhir] dari [Mutharrif bin Syikhkhir] dari [Al Jarud Al 'Abdi] secara marfu' kepada Nabi Shalallahu 'Alaihi Wasallam, beliau bersabda: \"Hewan (barang) seorang muslim yang hilang adalah pembakar api neraka, maka janganlah sekali-kali kamu mendekatinya.\""},"2831":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِي مُسْلِمٍ الْجَذْمِيِّ عَنِ الْجَارُودِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ","id":"Telah menceritakan kepada kami [Abdul Wahab], telah menceritakan kepada kami [Khalid] dari [Yazid bin Abdullah bin Syikhkhir] dari [Abu Muslim Al Jadzmi] dari [Al Jarud] bahwa Nabi Shalallahu 'Alaihi Wasallam bersabda: \"Hewan (barang) seorang muslim yang hilang adalah pembakar api neraka.\""},"2832":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا الْمُثَنَّي بْنُ سَعِيدٍ عَنْ قَتَادَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِي مُسْلِمٍ الْجَذْمِيِّ عَنِ الْجَارُودِ بْنِ مُعَلَّي الْعَبْدِيِّأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الضَّوَالِّ فَقَالَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud], telah menceritakan kepada kami [Al Mutsanna bin Sa'id] dari [Qatadah] dari [Yazid bin Abdullah bin Syikhkhir] dari [Abu Muslim Al Jadzmi] dari [Al Jarud bin Mu'alla Al 'Abdi] bahwa ia bertanya kepada Nabi Shalallahu 'Alaihi Wasallam mengenai hewan (barang) temuan, beliau bersabda: \"Hewan (barang) seorang muslim yang hilang adalah pembakar api neraka.\""},"2833":{"ar":"حَدَّثَنَا سُرَيْجٌ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي الْعَلَاءِ عَنْ أَبِي مُسْلِمٍ عَنِ الْجَارُودِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ","id":"Telah menceritakan kepada kami [Suraij], telah menceritakan kepada kami [Hammad yaitu Ibnu Zaid] dari [Ayyub] dari [Abul 'Ala`] dari [Abu Muslim] dari [Al Jarud] ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Hewan (barang) seorang muslim yang hilang adalah pembakar api neraka.\""},"2834":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِي مُسْلِمٍ الْجَذْمِيِّ عَنِ الْجَارُودِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ","id":"Telah menceritakan kepada kami [Bahz], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] dari [Yazid bin Abdullah bin Syikhkhir] dari [Abu Muslim Al Jadzmi] dari [Al Jarud] bahwa Nabi Shalallahu 'Alaihi Wasallam bersabda: \"Hewan (barang) seorang muslim yang hilang adalah pembakar api neraka.\""},"2835":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ حُضَيْنٍ أَبِي سَاسَانَ الرَّقَاشِيِّ عَنِ الْمُهَاجِرِ بْنِ قُنْفُذِ بْنِ عُمَيْرِ بْنِ جُدْعَانَ قَالَسَلَّمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَوَضَّأُ فَلَمْ يَرُدَّ عَلَيَّ فَلَمَّا فَرَغَ مِنْ وُضُوئِهِ قَالَ لَمْ يَمْنَعْنِي أَنْ أَرُدَّ عَلَيْكَ إِلَّا أَنِّي كُنْتُ عَلَى غَيْرِ وُضُوءٍ","id":"Telah menceritakan kepada kami [Rauh], telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Hudhain Abu Sasan Ar Raqasyi] dari [Muhajir bin Qunfudz bin Umair bin Jud'an] dia berkata; \"Aku beruluk salam kepada Nabi Shallalahu 'Alaihi Wasallam ketika beliau sedang berwudlu, maka beliau tidak menjawab salamku, seusai berwudlu beliau bersabda: \"Tidak ada yang menghalangiku dari menjawab salammu, kecuali karena aku belum berwudlu.\""},"2836":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ سَعِيدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ حُضَيْنٍ أَبِي سَاسَانَ عَنِ الْمُهَاجِرِ بْنِ قُنْفُذٍ قَالَ عَبْدُ الْوَهَّابِ ابْنُ عُمَيْرِ بْنِ جُدْعَانَأَنَّهُ سَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَوَضَّأُ فَلَمْ يَرُدَّ عَلَيْهِ فَلَمَّا فَرَغَ مِنْ وُضُوئِهِ قَالَ إِنَّهُ لَمْ يَمْنَعْنِي أَنْ أَرُدَّ عَلَيْكَ إِلَّا أَنِّي كَرِهْتُ أَنْ أَذْكُرَ اللَّهَ تَبَارَكَ وَتَعَالَى إِلَّا عَلَى طَهَارَةٍ","id":"Telah menceritakan kepada kami [Abdul Wahab] dari [Sa'id] dan [Muhammad bin Ja'far], telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Hudhain Abu Sasan Ar Raqasyi] dari [Muhajir bin Qunfudz], - [Abdul Wahab bin Umair bin Jud'an] mengatakan- bahwa Muhajir beruluk salam kepada Nabi Shallalahu 'Alaihi Wasallam ketika beliau sedang berwudlu, namun beliau tidak menjawab salamnya, seusai berwudlu beliau bersabda: \"Tidak ada yang menghalangiku menjawab salammu, selain karena aku tidak suka menyebut nama Allah Tabaraka wa Ta'ala kecuali dalam keadaan suci.\""},"2837":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ عَنْ حُمَيْدٍ عَنِ الْحَسَنِ عَنِ الْمُهَاجِرِ بْنِ قُنْفُذٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَبُولُ أَوْ قَدْ بَالَ فَسَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ حَتَّى تَوَضَّأَ ثُمَّ رَدَّ عَلَيَّ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad] dari [Humaid] dari [Al Hasan] dari [Al Muhajir bin Qunfudz] bahwa Nabi Shalallahu 'Alaihi Wasallam sedang buang air kecil, lalu ia beruluk salam, namun beliau tidak menjawab salamnya hingga beliau selesai wudlu, setelah itu beliau menjawab salamnya."},"2838":{"ar":"حَدَّثَنَا عَارِمٌ حَدَّثَنَا مُعْتَمِرٌ قَالَ وَحَدَّثَ أَبِي عَنْ أَبِي الْعَلَاءِ بْنِ عُمَيْرٍ الْجُرَيْرِيِّ قَالَكُنْتُ عِنْدَ قَتَادَةَ بْنِ مِلْحَانَ حِينَ حَضَرَ فَمَرَّ رَجُلٌ فِي أَقْصَى الدَّارِ قَالَ فَأَبْصَرْتُهُ فِي وَجْهِ قَتَادَةَ قَالَ وَكُنْتُ إِذَا رَأَيْتُهُ كَانَ عَلَى وَجْهِهِ الدِّهَانُ قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسَحَ وَجْهَهُحَدَّثَنَا يَحْيَى بْنُ مَعِينٍ وَهُرَيْمُ بْنُ عَبْدِ الْأَعْلَى قَالَا ثَنَا مُعْتَمِرٌ قَالَ قَالَ أَبِي عَنْ أَبِي الْعَلَاءِ بْنِ عُمَيْرٍ كُنْتُ عِنْدَ قَتَادَةَ بْنِ مِلْحَانَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Arim], telah menceritakan kepada kami [Mu'tamir] ia berkata; dan [Ayahku] telah menceritakan dari [Abul 'Ala` bin Umair Al Jurairi], ia berkata; \"Aku pernah bersama [Qatadah bin Milhan] ketika ia tengah sekarat. Lalu, lewatlah seorang laki-laki dari dalam rumah, lalu aku melihat wajah Qatadah.\" Katanya lagi; \"Ketika aku melihatnya, seakan-akan ada kilapan minyak di wajahnya.\" Kata Al 'Ala`; \"Rasulullah shallallahu 'alaihi wasallam dahulu pernah mengusap wajahnya.\" Abu Abdurrahman berkata; telah menceritakan kepada kami [Yahya bin Ma'in] dan [Huraim bin Abdul A'la] keduanya berkata; telah menceritakan kepada kami [Mu'tamir] lalu ia menyebutkan seperti hadits di atas.\""},"2839":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ قَالَ سَمِعْتُ أَبَا قِلَابَةَ يُحَدِّثُ عَنْ مُحَمَّدِ بْنِ أَبِي عَائِشَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَتَقْرَءُونَ وَالْإِمَامُ يَقْرَأُ أَوْ قَالَ تَقْرَءُونَ خَلْفَ الْإِمَامِ وَالْإِمَامُ يَقْرَأُ قَالُوا نَعَمْ قَالَ فَلَا تَفْعَلُوا إِلَّا أَنْ يَقْرَأَ أَحَدُكُمْ فَاتِحَةَ الْكِتَابِ فِي نَفْسِهِقَالَ خَالِدٌ وَحَدَّثَنِي بَعْدُ وَلَمْ يَقُلْ إِنْ شَاءَ فَقُلْتُ لِأَبِي قِلَابَةَ إِنْ شَاءَ قَالَ لَا أَذْكُرُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Khalid] ia berkata; Aku mendengar [Abu Qilabah] bercerita dari [Muhammad bin Abu A'isyah] dari [seorang] sahabat Nabi Shalallahu 'Alaihi Wasallam, beliau bertanya: \"Apakah kamu membaca (surat) padahal imam sedang membaca? -atau- apakah kamu membaca di belakang imam sedang ia membaca surat?.\" Mereka menjawab; \"Ya.\" Beliau bersabda: \"Janganlah kalian melakukan hal itu kecuali salah seorang dari kalian membaca fatihah dalam hatinya.\" [Khalid] berkata; ia menceritakan padaku setelah itu tanpa menyebutkan (tambahan) \"Insyaa`a (bagi siapa yang menghendakinya), \" lalu aku menyebutkan di depan Abu Qilabah; 'In syaa'a, namun ia berkata; \"Aku tidak menyebutkannya.\""},"2840":{"ar":"حَدَّثَنَا بَهْزٌ وَأَبُو كَامِلٍ قَالَا ثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي عِمْرَانَ يَعْنِي الْجَوْنِيَّ عَنْ أَبِي عَسِيبٍ أَوْ أَبِي عَسِيمٍ قَالَ بَهْزٌإِنَّهُ شَهِدَ الصَّلَاةَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا كَيْفَ نُصَلِّي عَلَيْهِ قَالَ ادْخُلُوا أَرْسَالًا أَرْسَالًا قَالَ فَكَانُوا يَدْخُلُونَ مِنْ هَذَا الْبَابِ فَيُصَلُّونَ عَلَيْهِ ثُمَّ يَخْرُجُونَ مِنْ الْبَابِ الْآخَرِ قَالَ فَلَمَّا وُضِعَ فِي لَحْدِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُغِيرَةُ قَدْ بَقِيَ مِنْ رِجْلَيْهِ شَيْءٌ لَمْ يُصْلِحُوهُ قَالُوا فَادْخُلْ فَأَصْلِحْهُ فَدَخَلَ وَأَدْخَلَ يَدَهُ فَمَسَّ قَدَمَيْهِ فَقَالَ أَهِيلُوا عَلَيَّ التُّرَابَ فَأَهَالُوا عَلَيْهِ التُّرَابَ حَتَّى بَلَغَ أَنْصَافَ سَاقَيْهِ ثُمَّ خَرَجَ فَكَانَ يَقُولُ أَنَا أَحْدَثُكُمْ عَهْدًا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Bahz] dan [Abu Kamil], keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu 'Imran yaitu Al Jauni] dari [Abu 'Asib atau Abu 'Ashim], -Bahz berkata; bahwa Abu 'Ashim pernah menyaksikan pelaksanaan shalat jenazah Rasulullah Shallalahu 'Alaihi Wasallam, lantas para sahabat bertanya; \"Bagaimana kita menshalati beliau?.\" Dia menjawab; \"Masuklah kalian secara berkelompok!.\" Lalu mereka masuk dari pintu ini untuk menshalati beliau, dan keluar dari pintu yang lain, ketika beliau Shallalahu 'Alaihi Wasallam diletakkan ke dalam liang lahat, \" Al Mughirah berkata; \"Ada sedikit yang belum mereka rapikan.\" Para sahabat berkata; \"Masuklah dan benarkan dahulu!.\" maka Al Mughirah masuk dan memasukkan tangannya, ia menyentuh kedua telapak kaki beliau, lalu berkata; \"Masukkanlah tanah!.\" Para sahabatpun memasukkan tanah kepadanya hingga sampai setinggi pertengahan kedua betisnya, lalu dia keluar kemudian dia berkata; \"Aku adalah orang yang paling muda di antara kalian masanya dengan Rasulullah Shallalahu 'Alaihi Wasallam.\""},"2841":{"ar":"حَدَّثَنَا يَزِيدُ حَدَّثَنَا مُسْلِمُ بْنُ عُبَيْدٍ أَبُو نُصَيْرَةَ قَالَ سَمِعْتُ أَبَا عَسِيبٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي جِبْرِيلُ عَلَيْهِ السَّلَام بِالْحُمَّى وَالطَّاعُونِ فَأَمْسَكْتُ الْحُمَّى بِالْمَدِينَةِ وَأَرْسَلْتُ الطَّاعُونَ إِلَى الشَّامِ فَالطَّاعُونُ شَهَادَةٌ لِأُمَّتِي وَرَحْمَةٌ لَهُمْ وَرِجْسٌ عَلَى الْكَافِرِينَ","id":"Telah menceritakan kepada kami [Yazid] telah menceritakan kepada kami [Muslim bin Ubaid Abu Nushairah] ia berkata; aku mendengar [Abu 'Asib bekas budak Rasulullah] Shallalahu 'Alaihi Wasallam, ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Jibril 'alaihis salam datang kepadaku membawa demam dan tha'un (kolera), maka aku tahan demam di Madinah, sedangkan Tha'un aku lepaskan ke negeri Syam, oleh karena itu penyakit tha'un adalah sebagai Syahid bagi ummatku dan rahmat bagi mereka, sedangkan bagi orang kafir sebagai penyakit.\""},"2842":{"ar":"حَدَّثَنَا سُرَيْجٌ حَدَّثَنَا حَشْرَجٌ عَنْ أَبِي نُصَيْرَةَ عَنْ أَبِي عَسِيبٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلًا فَمَرَّ بِي فَدَعَانِي إِلَيْهِ فَخَرَجْتُ ثُمَّ مَرَّ بِأَبِي بَكْرٍ فَدَعَاهُ فَخَرَجَ إِلَيْهِ ثُمَّ مَرَّ بِعُمَرَ فَدَعَاهُ فَخَرَجَ إِلَيْهِ فَانْطَلَقَ حَتَّى دَخَلَ حَائِطًا لِبَعْضِ الْأَنْصَارِ فَقَالَ لِصَاحِبِ الْحَائِطِ أَطْعِمْنَا بُسْرًا فَجَاءَ بِعِذْقٍ فَوَضَعَهُ فَأَكَلَ فَأَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ ثُمَّ دَعَا بِمَاءٍ بَارِدٍ فَشَرِبَ فَقَالَ لَتُسْأَلُنَّ عَنْ هَذَا يَوْمَ الْقِيَامَةِ قَالَ فَأَخَذَ عُمَرُ الْعِذْقَ فَضَرَبَ بِهِ الْأَرْضَ حَتَّى تَنَاثَرَ الْبُسْرُ قِبَلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ أَئِنَّا لَمَسْئُولُونَ عَنْ هَذَا يَوْمَ الْقِيَامَةِ قَالَ نَعَمْ إِلَّا مِنْ ثَلَاثٍ خِرْقَةٍ كَفَّ بِهَا الرَّجُلُ عَوْرَتَهُ أَوْ كِسْرَةٍ سَدَّ بِهَا جَوْعَتَهُ أَوْ حَجَرٍ يَتَدَخَّلُ فِيهِ مِنْ الْحَرِّ وَالْقُرِّ","id":"Telah menceritakan kepada kami [Suraij], telah menceritakan kepada kami [Hasyraj] dari [Abu Nushairah] dari [Abu 'Asib] dia berkata; \"Suatu malam Rasulullah Shallalahu 'Alaihi Wasallam keluar dan melewatiku, beliau memanggilku, maka akupun keluar, kemudian beliau melewati Abu Bakar dan memanggilnya, maka diapun keluar menemui beliau, beliau melewati Umar dan memanggilnya, Umarpun keluar menemui beliau, beliau berjalan hingga memasuki suatu kebun milik salah seorang sahabat Anshar, seraya bersabda kepada pemilik kebun; \"Berilah kami kurma!.\" Si pemilik kebun datang dengan membawa segantang kurma, lalu ia meletakkan kurma tersebut dan memakannya, Rasulullah beserta para sahabatnyapun ikut memakannya, kemudian beliau meminta air dingin dan meminumnya lalu bersabda: \"Pasti nikmat ini akan di tanyakan pada hari Kiamat kelak.\" [Abu 'Asib] berkata; kemudian Umar mengambil segantang kurma dan membantingnya ke tanah sehingga berceceranlah kurma itu di hadapan Rasulullah Shallalahu 'Alaihi Wasallam, ia bertanya; \"Wahai Rasulullah, apakah kita akan ditanya tentang ini pada hari Kiamat kelak?.\" Beliau menjawab: \"Ya, kecuali dari tiga hal; secarik kain yang digunakan seseorang untuk menutup auratnya atau secuil makanan untuk menghilangkan rasa laparnya atau sebongkah batu yang dia masukkan untuk menghindari panas dan dingin.\""},"2843":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ بْنُ عُبَيْدٍ أَخْبَرَنِي مُخْبِرٌ عَنْ حُصَيْنِ بْنِ أَبِي الْحَرِّ عَنِ الْخَشْخَاشِ الْعَنْبَرِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي ابْنٌ لِي فَقَالَ ابْنُكَ قَالَ قُلْتُ نَعَمْ قَالَ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ","id":"Telah menceritakan kepada kami [Husyaim], telah menceritakan kepada kami [Yunus bin Ubaid], telah mengabarkan kepadaku [seseorang yang mengabarinya] dari [Hushain bin Abul Harri] dari [Al Khasykhasy Al 'Anbari] ia berkata; aku bersama anakku mendatangi Nabi Shalallahu 'Alaihi Wasallam, beliau bertanya: \"Apakah ini anakmu?\" jawabku; \"Ya.\" Beliau bersabda: \"Ia tidak akan durhaka padamu dan kamu tidak akan menyiakannya.\""},"2844":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ عَاصِمِ بْنِ سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَتَرَوْنَ هَذَا الشَّيْخَ يَعْنِي نَفْسَهُ كَلَّمْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَكَلْتُ مَعَهُ وَرَأَيْتُ الْعَلَامَةَ الَّتِي بَيْنَ كَتِفَيْهِ وَهِيَ فِي طَرَفِ نُغْضِ كَتِفِهِ الْيُسْرَى كَأَنَّهُ جُمْعٌ يَعْنِي الْكَفَّ الْمُجْتَمِعَ وَقَالَ بِيَدِهِ فَقَبَضَهَا عَلَيْهِ خِيلَانٌ كَهَيْئَةِ الثَّآلِيلِ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan pada kami [Ma'mar] dari ['Ashim bin Sulaiman] dari [Abdullah bin Sarjis] dia berkata; \"Kalian melihat syaikh ini -yaitu dirinya-, aku pernah berbicara dengan Nabi Shalallahu 'Alaihi Wasallam, makan bersamanya dan aku melihat tanda yang ada di antara kedua pundaknya, yaitu berada di ujung punuk pundaknya yang sebelah kiri, seakan-akan ia adalah kumpulan yaitu telapak tangan yang dikepalkan\" Abdullah bin Sarjis mengisyaratkan sambil menggenggam tanda (yang berada di tubuh) dengan tangannya, sebagaimana daging tumbuh.\""},"2845":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ مُسَافِرًا يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Ma'mar] dari ['Ashim] dari [Abdullah bin Sarjis] dia berkata; \"Apabila Nabi Shallalahu 'Alaihi Wasallam keluar bepergian, beliau membaca do'a: \"ALLAAHUMMA INNII 'A'UUDZUBIKA MIN WA'TSAA'IS SAFARI WA KAAABTIL MUNQALABI WAL HAURI BA'DAL KUURI WA DA'WATIL MADZLUUM WA SUU'IL MANDZARI FIL AHLI WAL MAALI (ya Allah, sesungguhnya aku berlindung kepadaMu dari lelahnya perjalanan, kepulangan yang menyedihkan, kekurangan setelah kecukupan, terzhalimi dan pandangan yang menyeramkan dalam keluarga maupun harta.\""},"2846":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَاصِمٌ بِالْكُوفَةِ فَلَمْ أَكْتُبْهُ فَسَمِعْتُ شُعْبَةَ يُحَدِّثُ بِهِ فَعَرَفْتُهُ بِهِ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَافَرَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ","id":"Telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan kepada kami ['Ashim] di Kufah, namun aku tidak mencatatnya, aku mendengar [Syu'bah] bercerita dan aku mengetahuinya dari ['Ashim] dari [Abdullah bin Sarjis] dia berkata; \"Apabila Nabi Shallalahu 'Alaihi Wasallam keluar bepergian, beliau membaca do'a: \"ALLAAHUMMA INNII 'A'UUDZUBIKA MIN WA'TSAA'IS SAFARI WA KAAABTIL MUNQALABI WAL HAURI BA'DAL KAURI WA DA'WATIL MADZLUUM WA SUU'IL MANDZARI FIL AHLI WAL MAALI (ya Allah, sesungguhnya aku berlindung kepadaMu dari lelahnya perjalanan, kepulangan yang menyedihkan, kekurangan setelah kecukupan, terzhalimi dan pandangan yang menyeramkan dalam keluarga maupun harta.\""},"2847":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari ['Ashim] dari [Abdullah bin Sarjis] dia berkata; \"Apabila Nabi Shallalahu 'Alaihi Wasallam keluar bepergian, beliau membaca do'a: \"ALLAAHUMMA INNII 'A'UUDZUBIKA MIN WA'TSAA'IS SAFARI WA KAAABTIL MUNQALABI WAL HAURI BA'DAL KUURI WA DA'WATIL MADZLUUM WA SUU'IL MANDZARI FIL AHLI WAL MAALI (ya Allah, sesungguhnya aku berlindung kepadaMu dari lelahnya perjalanan, kepulangan yang menyedihkan, kekurangan setelah kecukupan, terzhalimi dan pemandangan yang buruk dalam keluarga maupun harta.\""},"2848":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا ثَابِتٌ حَدَّثَنَا عَاصِمٌ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَأَنَّهُ رَأَى الْخَاتَمَ الَّذِي بَيْنَ كَتِفَيْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ تَكُنْ لَهُ صُحْبَةٌ","id":"Telah menceritakan kepada kami [Abu Sa'id], telah menceritakan kepada kami [Tsabit], telah menceritakan kepada kami ['Ashim] dari [Abdullah bin Sarjis] bahwa ia pernah melihat tanda kenabian diantara dua pundak Nabi shallallahu 'alaihi wasallam, dan dia melihat Nabi Shalallahu 'Alaihi Wasallam ketika dirinya belum menjadi sahabat beliau.\""},"2849":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَ عَاصِمٌ وَقَدْ كَانَ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ فِي سَفَرٍ قَالَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَالْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْمَالِ وَالْأَهْلِ وَإِذَا رَجَعَ قَالَ مِثْلَهَا إِلَّا أَنَّهُ يَقُولُ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِ يَبْدَأُ بِالْأَهْلِ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami ['Ashim Al Ahwal] dari [Abdullah bin Sarjis], 'Ashim berkata; \"Apabila Nabi Shallalahu 'Alaihi Wasallam keluar bepergian, beliau membaca do'a: \"ALLAAHUMMA INNII 'A'UUDZUBIKA MIN WA'TSAA'IS SAFARI WA KAAABTIL MUNQALABI WAL HAURI BA'DAL KAURI WA DA'WATIL MADZLUUM WA SUU'IL MANDZARI FIL MAALI WAL AHLI (ya Allah, sesungguhnya aku berlindung kepadaMu dari lelahnya perjalanan, kepulangan yang menyedihkan, kekurangan setelah kecukupan, terzhalimi dan pandangan yang menyeramkan dalam harta dan keluarga).\" Demikian bila beliau pulang juga mengucapkan seperti itu, akan tetapi memulai dari Ahli (keluarga), beliau bersabda: \"…WA SUU`IL MANDLARI FIL AHLI WAL MAALI (dan dari pandangan yang menyeramkan dalam keluarga dan harta).\""},"2850":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَأُقِيمَتْ الصَّلَاةُ صَلَاةُ الصُّبْحِ فَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي رَكْعَتَيْ الْفَجْرِ فَقَالَ لَهُ بِأَيِّ صَلَاتَيْكَ احْتَسَبْتَ بِصَلَاتِكَ وَحْدَكَ أَوْ صَلَاتِكَ الَّتِي صَلَّيْتَ مَعَنَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari ['Ashim] dari [Abdullah bin Sarjis] dia berkata; \"Ketika IqAmat shalat Shubuh telah dikumandangkan, Rasulullah Shallalahu 'Alaihi Wasallam melihat seorang lelaki yang masih melaksanakan shalat dua raka'at sunnah fajar, maka beliau bertanya kepadanya: \"Manakah di antara dua shalatmu yang kamu harapkan pahalanya, apakah shalatmu yang sendirian ataukah shalatmu yang kamu laksanakan bersama kami?.\""},"2851":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ الْأَحْوَلِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ سَرْجِسَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلْتُ مَعَهُ مِنْ طَعَامِهِ فَقُلْتُ غَفَرَ اللَّهُ لَكَ يَا رَسُولَ اللَّهِ فَقُلْتُ أَسْتَغْفَرَ لَكَ قَالَ شُعْبَةُ أَوْ قَالَ لَهُ رَجُلٌ قَالَ نَعَمْ وَلَكُمْ وَقَرَأَ{ وَاسْتَغْفِرْ لِذَنْبِكَ وَلِلْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ }ثُمَّ نَظَرْتُ إِلَى نُغْضِ كَتِفِهِ الْأَيْمَنِ أَوْ كَتِفِهِ الْأَيْسَرِ شُعْبَةُ الَّذِي يَشُكُّ فَإِذَا هُوَ كَهَيْئَةِ الْجُمْعِ عَلَيْهِ الثَّآلِيلُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari ['Ashim Al Ahwal] dia berkata; saya mendengar [Abdullah bin Sarjis] dia berkata; \"Aku pernah menemui Rasulullah Shalallahu 'Alaihi Wasallam dan makan bersamanya dari makanan beliau, aku berkata; \"Semoga Allah mengampunimu wahai Rasulullah.\" [Syu'bah] berkata atau laki-laki itu berkata kepada beliau; beliau menjawab: \"Ya, begitu juga denganmu, lalu beliau membaca ayat; \"Wastaghfir lidzanbika walilmu'minin wal mu'minat\" (dan mohonlah ampunan bagi dosamu dan bagi (dosa) orang-orang mukmin, laki-laki dan perempuan…\" QS Muhammad; 19. Dan aku sempat melihat tanda yang ada di pundak kanan atau kirinya -Syu'bah ragu mengenai redaksinya- seakan-akan gumpalan tahi lalat layaknya daging tumbuh.\""},"2852":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ وَأَسْوَدُ بْنُ عَامِرٍ قَالَا ثَنَا شَرِيكٌ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَخَلْتُ عَلَيْهِ وَأَكَلْتُ مِنْ طَعَامِهِ وَشَرِبْتُ مِنْ شَرَابِهِ وَرَأَيْتُ خَاتَمَ النُّبُوَّةِ قَالَ هَاشِمٌ فِي نُغْضِ كَتِفِهِ الْيُسْرَى كَأَنَّهُ جُمْعٌ فِيهَا خِيلَانٌ سُودٌ كَأَنَّهَا الثَّآلِيلُ","id":"Telah menceritakan kepada kami [Hasyim bin Qasim] dan [Aswad bin Amir], keduanya berkata; telah menceritakan kepada kami [Syarik] dari ['Ashim] dari [Abdullah bin Sarjis] ia berkata; \"Aku melihat Rasulullah Shallalahu 'Alaihi Wasallam, aku menemui dan makan dan minum bersamanya dari makanan dan minuman beliau, lalu aku melihat khatam (tanda) kenabiannya.\" [Hasyim] mengatakan; \"yaitu di pundaknya atas sebelah kiri seperti gumpalan tahi lalat layaknya daging tumbuh.\""},"2853":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ أَنَّهُكَانَ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ قَالَ اللَّهُمَّ أَنْتَ الصَّاحِبُ فِي السَّفَرِ وَالْخَلِيفَةُ فِي الْأَهْلِ اللَّهُمَّ اصْحَبْنَا فِي سَفَرِنَا وَاخْلُفْنَا فِي أَهْلِنَا اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ وَعْثَاءِ السَّفَرِ وَكَآبَةِ الْمُنْقَلَبِ وَمِنْ الْحَوْرِ بَعْدَ الْكَوْرِ وَدَعْوَةِ الْمَظْلُومِ وَسُوءِ الْمَنْظَرِ فِي الْأَهْلِ وَالْمَالِقَالَ وَسُئِلَ عَاصِمٌ عَنْ الْحَوْرِ بَعْدَ الْكَوْرِ قَالَ حَارَ بَعْدَ مَا كَانَ","id":"Telah menceritakan kepada kami [Hasan bin Musa], telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ashim] dari [Abdullah bin Sarjis] bahwa ia pernah melihat Nabi Shallalahu 'Alaihi Wasallam, ia berkata; apabila Rasulullah Shallalahu 'Alaihi Wasallam keluar bepergian, beliau membaca do'a: \"ALLAHUMMA ANTA SHAAHIBU FIS SAFARI WAL KHALIIFATU FIL AHLI, ALLAHUMMA ASHABNAA FII SAFARINA WAKHLUFNAA FII AHLINA, ALLAAHUMMA INNII 'A'UUDZUBIKA MIN WA'TSAA'IS SAFARI WA KAAABTIL MUNQALIBI WAMINAL HAURI BA'DAL KAURI WA DA'WATIL MADZLUUM WA SUU'IL MANDZARI FIL AHLI WAL MAALI (Ya Allah, Engkau adalah teman dalam bepergian dan yang mengurusi keluargaku, ya Allah, temanilah kami dalam perjalanan kami dan urusilah keluarga kami. Ya Allah, sesungguhnya aku berlindung kepadaMu dari lelahnya perjalanan, kepulangan yang menyedihkan, kekurangan setelah kecukupan, terzhalimi dan pandangan yang menyeramkan dalam keluarga dan harta, \" 'Ashim ditanya maksud Al Haur ba'dal Kaur\" ia menjawab; \"kepanasan.\""},"2854":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا هِشَامٌ عَنِ ابْنِ سِيرِينَ عَنِ امْرَأَةٍ يُقَالُ لَهَا رَجَاءُ قَالَتْكُنْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَتْهُ امْرَأَةٌ بِابْنٍ لَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ لِي فِيهِ بِالْبَرَكَةِ فَإِنَّهُ قَدْ تُوُفِّيَ لِي ثَلَاثَةٌ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمُنْذُ أَسْلَمْتِ قَالَتْ نَعَمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُنَّةٌ حَصِينَةٌفَقَالَ لِي رَجُلٌ اسْمَعِي يَا رَجَاءُ مَا يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan pada kami [Hisyam] dari [Ibnu Sirin] dari seorang perempuan yang dipanggil dengan nama [Raja'] dia berkata; \"Ketika aku berada di sisi Rasulullah Shallalahu 'Alaihi Wasallam, tiba-tiba seorang wanita datang dengan membawa anak laki-lakinya, lalu dia berkata; \"Wahai Rasulullah mohonkanlah keberkahan kepada Allah untukku dengan adanya anak ini, karena tiga orang dari anakku telah meninggal.\" Rasulullah Shallalahu 'Alaihi Wasallam bertanya kepadanya: \"Apakah hal itu terjadi sejak kamu masuk Islam?\" dia menjawab; \"Ya.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Benteng yang melindungi.\" Lantas seorang lelaki berkata kepadaku; \"Dengarkanlah wahai Raja' apa yang dikatakan oleh Rasulullah Shallalahu 'Alaihi Wasallam!.\""},"2855":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا هِشَامٌ عَنْ مُحَمَّدٍ قَالَ حَدَّثَتْنَا امْرَأَةٌ كَانَتْ تَأْتِينَا يُقَالُ لَهَا مَاوِيَّةُكَانَتْ تُرْزَأُ فِي وَلَدِهَا وَأَتَيْتُ عُبَيْدَ اللَّهِ بْنَ مَعْمَرٍ الْقُرَشِيَّ وَمَعَهُ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثَ ذَلِكَ الرَّجُلُ أَنَّ امْرَأَةً أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ تَبَارَكَ وَتَعَالَى أَنْ يُبْقِيَهُ لِي لَقَدْ مَاتَ لِي قَبْلَهُ ثَلَاثَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمُنْذُ أَسْلَمْتِ فَقَالَتْ نَعَمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُنَّةٌ حَصِينَةٌقَالَتْ مَاوِيَّةُ قَالَ لِي عُبَيْدُ اللَّهِ بْنُ مَعْمَرٍ اسْمَعِي يَا مَاوِيَّةُ قَالَ مُحَمَّدٌ فَخَرَجَتْ مِنْ عِنْدِ ابْنِ مَعْمَرٍ فَأَتَتْنَا فَحَدَّثَتْنَا هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yazid], telah mengabarkan pada kami [Hisyam] dari [Muhammad] ia berkata; telah menceritakan kepada kami seorang wanita yang mendatangi kami dan biasa disebut [Mawiyyah] yang diuji dengan kematian anaknya, lalu aku mendatangi Ubaidullah bin Ma'mar Al Qurasyi, ketika itu dia bersama dengan [seorang sahabat Nabi Shalallahu 'Alaihi Wasallam], orang tersebut menceritakan bahwa ada seorang wanita membawa anak laki-lakinya datang kepada Nabi shallallahu 'alaihi wasallam, dia berkata; \"Wahai Rasulullah mohonkanlah keberkahan kepada Allah untukku dengan adanya anak ini, karena tiga anakku telah meninggal.\" Rasulullah Shallalahu 'Alaihi Wasallam bertanya kepadanya: \"Apakah kejadian tersebut sejak kamu masuk Islam?\" dia menjawab; \"Ya, \" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Benteng yang melindungi.\" [Mawiyyah] berkata; Ubaidullah bin Ma'mar berkata padaku; \"Dengarkanlah wahai Mawiyyah.\" [Muhammad] berkata; lalu wanita itu keluar meninggalkan Ibnu Ma'mar, lalu kami mendatanginya dan ia menceritakan perihal hadits tersebut.\""},"2856":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنِي أَسْوَدُ بْنُ شَيْبَانَ عَنْ خَالِدِ بْنِ سُمَيْرٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ بَشِيرِ ابْنِ الْخَصَاصِيَةِ بَشِيرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَمْشِي فِي نَعْلَيْنِ بَيْنَ الْقُبُورِ فَقَالَ يَا صَاحِبَ السَّبْتِيَّتَيْنِ أَلْقِهِمَا","id":"Telah menceritakan kepada kami [Waki'], telah menceritakan kepadaku [Aswad bin Syaiban] dari [Khalid bin Sumair] dari [Basyir bin Nahik] dari [Basyir bin Al Khashashiyah], salah seorang yang mendapat kabar gembira dari Rasulullah Shallalahu 'Alaihi Wasallam, bahwa Rasulullah Shallalahu 'Alaihi Wasallam melihat seorang lelaki yang berjalan di antara kuburan dengan memakai dua sandal, maka beliau menegurnya dengan bersabda: \"Wahai pemilik sandal kulit, lepaskanlah keduanya!.\""},"2857":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا ثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ رَجُلٍ مِنْ بَنِي سَدُوسٍ يُقَالُ لَهُ دَيْسَمٌ قَالَقُلْنَا لِبَشِيرِ ابْنِ الْخَصَاصِيَةِ قَالَ وَمَا كَانَ اسْمُهُ بَشِيرًا فَسَمَّاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشِيرًا إِنَّ لَنَا جِيرَةً مِنْ بَنِي تَمِيمٍ لَا تَشُدُّ لَنَا قَاصِيَةٌ إِلَّا ذَهَبُوا بِهَا وَإِنَّهَا تَجِيءُ لَنَا مِنْ أَمْوَالِهِمْ أَشْيَاءُ أَفَنَأْخُذُهَا قَالَ لَاحَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ حَدَّثَنِي شَيْخٌ مِنْ بَنِي سَدُوسٍ يُقَالُ لَهُ دَيْسَمٌ عَنْ بَشِيرِ ابْنِ الْخَصَاصِيَةِ وَكَانَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّاهُ بَشِيرًا فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan], keduanya berkata; telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari seorang lelaki bani Sadus yang disebut dengan [Daisam] dia berkata; \"Kami berkata kepada [Basyir bin Al Khashashiyah], -Ayyub mengatakan; \"Dahulu namanya bukan Basyir kemudian Rasulullah Shallalahu 'Alaihi Wasallam memberinya nama Basyir-, sesungguhnya kami mempunyai sebongkah batu kapur dari bani Tamim, tidaklah kami bepergian ke suatu tempat yang jauh kecuali mereka membawanya, dan ia dapat menghasilkan untuk kami sesuatu dari harta mereka, apakah kami boleh mengambilnya?.\" Dia menjawab; \"Tidak.\" Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] bahwa seorang syaikh dari bani Sadus yang bernama [Daisam] dari [Basyir bin Al Khashashiyah], dia pernah datang kepada Nabi Shallalahu 'Alaihi Wasallam, kemudian beliau memberinya nama Basyir, lalu dia menyebutkan hadits tersebut.\""},"2858":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَسْوَدُ بْنُ شَيْبَانَ عَنْ خَالِدِ بْنِ سُمَيْرٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ بَشِيرِ ابْنِ الْخَصَاصِيَةِ بَشِيرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكُنْتُ أُمَاشِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آخِذًا بِيَدِهِ فَقَالَ لِي يَا ابْنَ الْخَصَاصِيَةِ مَا أَصْبَحْتَ تَنْقِمُ عَلَى اللَّهِ تَبَارَكَ وَتَعَالَى أَصْبَحْتَ تُمَاشِي رَسُولَهُ قَالَ أَحْسَبُهُ قَالَ آخِذًا بِيَدِهِ قَالَ قُلْتُ مَا أَصْبَحْتُ أَنْقِمُ عَلَى اللَّهِ شَيْئًا قَدْ أَعْطَانِي اللَّهُ تَبَارَكَ وَتَعَالَى كُلَّ خَيْرٍ قَالَ فَأَتَيْنَا عَلَى قُبُورِ الْمُشْرِكِينَ فَقَالَ لَقَدْ سَبَقَ هَؤُلَاءِ خَيْرًا كَثِيرًا ثَلَاثَ مَرَّاتٍ ثُمَّ أَتَيْنَا عَلَى قُبُورِ الْمُسْلِمِينَ فَقَالَ لَقَدْ أَدْرَكَ هَؤُلَاءِ خَيْرًا كَثِيرًا ثَلَاثَ مَرَّاتٍ يَقُولُهَا قَالَ فَبَصُرَ بِرَجُلٍ يَمْشِي بَيْنَ الْمَقَابِرِ فِي نَعْلَيْهِ فَقَالَ وَيْحَكَ يَا صَاحِبَ السِّبْتِيَّتَيْنِ أَلْقِ سِبْتِيَّتَكَ مَرَّتَيْنِ أَوْ ثَلَاثًا فَنَظَرَ الرَّجُلُ فَلَمَّا رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلَعَ نَعْلَيْهِحَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا الْأَسْوَدُ حَدَّثَنَا خَالِدُ بْنُ سُمَيْرٍ حَدَّثَنَا بَشِيرُ بْنُ نَهِيكٍ قَالَ حَدَّثَنِي بَشِيرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ اسْمُهُ فِي الْجَاهِلِيَّةِ زَحْمَ بْنَ مَعْبَدٍ فَهَاجَرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَقَالَ مَا اسْمُكَ قَالَ زَحْمٌ قَالَ لَا بَل�� أَنْتَ بَشِيرٌ فَكَانَ اسْمَهُ قَالَ بَيْنَا أَنَا أُمَاشِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ قَالَ يَا ابْنَ الْخَصَاصِيَةِ مَا أَصْبَحْتَ تَنْقِمُ عَلَى اللَّهِ تَبَارَكَ وَتَعَالَى أَصْبَحْتَ تُمَاشِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو شَيْبَانَ وَهُوَ الْأَسْوَدُ بْنُ شَيْبَانَ أَحْسَبُهُ قَالَ آخِذًا بِيَدِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي وَأُمِّي مَا أَنْقِمُ عَلَى اللَّهِ عَزَّ وَجَلَّ شَيْئًا فَذَكَرَ الْحَدِيثَ وَقَالَ يَا صَاحِبَ السِّبْتِيَّتَيْنِ أَلْقِ سِبْتِيَّتَكَ","id":"Telah menceritakan kepada kami [Yazid bin Harun], telah mengabarkan pada kami [Aswad bin Syaiban] dari [Khalid bin Sumair] dari [Basyir bin Nahik] dari [Basyir bin Al Khashashiyah] -salah seorang yang mendapat kabar gembira dari Rasulullah Shallalahu 'Alaihi Wasallam- ia berkata; Aku berjalan bersama Rasulullah Shallalahu 'Alaihi Wasallam sambil menggamit tangan beliau, beliau bersabda padaku: \"Wahai ibnu Al Khashashiyah, tidak mungkin kamu mencela Allah Tabaraka wa Ta'ala kemudian kamu berjalan dengan Rasul-Nya.\" Perawi berkata; Aku menyangka Basyir berkata; dengan menggamit tangan beliau.\" Basyir menjawab; \"Tidak mungkin aku mencela Allah Tabaraka wa Ta'ala yang telah memberiku segala kebaikan.\" Kemudian kami melewati kuburan orang-orang musyrikin, lalu beliau bersabda: \"Mereka telah menyiakan kebaikan, \" -beliau menyebutnya hingga tiga kali- lalu kami melewati kuburan kaum muslimin, beliau pun bersabda: \"Sungguh mereka telah mendapatkan kebaikan yang banyak, \" -beliau menyebutnya hingga tiga kali- Kemudian beliau melihat seseorang yang melewati kuburan dengan mengenakan sandalnya, beliau bersabda: \"Celaka kamu wahai pemilik sandal, copotlah sandalmu!.\" -beliau ulangi hingga dua tau tiga kali- lalu orang tersebut melihat kami, ketika ia mengetahui Rasulullah, serta merta ia melepas dua sandalnya.\" Telah menceritakan kepada kami [Abdussamad], telah menceritakan kepada kami [Al Aswad], telah menceritakan kepada kami [Khalid bin Samurah], telah menceritakan kepada kami [Basyir bin Nahik] ia berkata; telah menceritakan kepadaku [seorang pemberi kabar gembira Rasulullah] shallallahu 'alaihi wasallam, nama jahiliyahnya adalah Zahm bin Ma'bad, lalu ia berhijrah kepada Rasulullah shallallahu 'alaihi wasallam. beliau bertanya: 'Siapa namamu?.' Ia berkata; 'Zahm.' Beliau bersabda: \"Tidak tapi engkau adalah Basyir (yang memberi kabar gembira).\" Ketika kami bersama Rasulullah shallallahu 'alaihi wasallam, beliau bersabda; 'Wahai Ibnu Khashashiyah, tidak mungkin kamu cela Allah Tabaraka Wata'ala, lalu kamu berjalan dengan Rasulullah shallallahu 'alaihi wasallam.\" Abu Syaiban yaitu Al `Aswad bin Syaiban, aku kira dia berkata; \"Dengan menggapit tangan beliau, lalu aku berkata; 'Wahai Rasulullah, demi ayah ibuku, tidak mungkin aku akan mencela Allah Azza wa Jalla.' Lalu ia menyebutkan hadits tersebut. Dan beliau bersabda; 'Wahai pemilik sandal, lepas sandalmu!.\""},"2859":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ قَالَتْكُنَّا نَمْنَعُ عَوَاتِقَنَا أَنْ يَخْرُجْنَ فَقَدِمَتْ امْرَأَةٌ فَنَزَلَتْ قَصْرَ بَنِي خَلَفٍ فَحَدَّثَتْ أَنَّ أُخْتَهَا كَانَتْ تَحْتَ رَجُلٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ غَزَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اثْنَتَيْ عَشْرَةَ غَزْوَةً قَالَتْ أُخْتِي غَزَوْتُ مَعَهُ سِتَّ غَزَوَاتٍ قَالَتْ كُنَّا نُدَاوِي الْكَلْمَى وَنَقُومُ عَلَى الْمَرْضَى فَسَأَلَتْ أُخْتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ هَلْ عَلَى إِحْدَانَا بَأْسٌ لِمَنْ لَمْ يَكُنْ لَهَا جِلْبَابٌ أَنْ تَخْرُجَ فَقَالَ لِتُلْبِسْهَا صَاحِبَتُهَا مِنْ جِلْبَابِهَا وَلْتَشْهَدْ الْخَيْرَ وَدَعْوَةَ الْمُؤْمِنِينَ قَالَتْ فَلَمَّا قَدِمَتْ أُمُّ عَطِيَّةَ فَسَأَلْتُهَا أَوْ سَأَلْنَاهَا هَلْ سَمِعْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَذَا وَكَذَا قَالَتْ وَكَانَتْ لَا تَذْكُرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَدًا إِلَّا قَالَتْ بَيْبًا فَقَالَتْ نَعَمْ بَيْبًا قَالَ لِيَخْرُجْ الْعَوَاتِقُ ذَوَاتُ الْخُدُورِ أَوْ قَالَتْ الْعَوَاتِقُ وَذَوَاتُ الْخُدُورِ وَالْحُيَّضُ فَيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُؤْمِنِينَ وَيَعْتَزِلْنَ الْحُيَّضُ الْمُصَلَّىفَقُلْتُ لِأُمِّ عَطِيَّةَ الْحَائِضُ فَقَالَتْ أَوَلَيْسَ يَشْهَدْنَ عَرَفَةَ وَتَشْهَدُ كَذَا وَتَشْهَدُ كَذَا","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Ayyub] dari [Hafshah binti Sirin] dia berkata; kami melarang gadis-gadis kami untuk keluar rumah, kemudian seorang wanita datang dan singgah di benteng bani Khalaf, lalu dia bercerita bahwa saudara perempuannya -ia berada dalam asuhan salah seorang sahabat Rasulullah Shallalahu 'Alaihi Wasallam- ikut serta berperang bersama Rasulullah Shallalahu 'Alaihi Wasallam sebanyak dua belas kali, saudara perempuanku bercerita; \"Aku ikut berperang bersama beliau sebanyak enam kali peperangan, \" dia melanjutkan; \"Kami bertugas mengobati orang yang terluka dan merawat yang sakit.\" Lalu saudaraku perempuanku bertanya kepada Rasulullah Shallalahu 'Alaihi Wasallam; \"Apakah salah seorang dari kami berdosa bila keluar rumah, sementara dirinya tidak memiliki jilbab?\" Beliau menjawab: \"Hendaknya saudara perempuannya memberikan jilbab kepadanya, barulah ia dapat menyaksikan acara-acara yang baik dan memenuhi undangan kaum muslimin.\" Dia berkata lagi; \"Ketika [Ummu 'Athiyyah] datang, aku bertanya kepadanya atau kami bertanya kepadanya; \"Apakah kamu sudah mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda begini dan begini?.\" dan Ummu 'Athiyyah tidak menyebut nama Rasulullah Shallalahu 'Alaihi Wasallam sama sekali kecuali diiringi dengan kata \"Demi ayahku\" lalu dia berkata; \"Ya, demi ayahku, beliau bersabda supaya para perawan dan gadis, -atau beliau bersabda- para perawan, gadis pingitan dan wanita yang sedang haid, keluar untuk menyaksikan kebaikan dan menghadiri dakwah kaum mukminin, hendaknya wanita yang sedang haid menjauh dari tempat shalat.\" Aku bertanya kepada Ummu 'Athiyyah; \"Wanita-wanita yang sedang haid?. Dia menjawab; \"Bukankah mereka juga menyaksikan hari Arafah, menyaksikan ini dan ini?.\""},"2860":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَغْسِلُ ابْنَتَهُ عَلَيْهَا السَّلَام فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي قَالَتْ فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حَقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُقَالَ وَقَالَتْ حَفْصَةُ قَالَ اغْسِلْنَهَا وِتْرًا ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًا قَالَ وَقَالَتْ أُمُّ عَطِيَّةَ مَشَطْنَاهَا ثَلَاثَةَ قُرُونٍ","id":"Telah menceritakan kepada kami [Isma'il], telah mengabarkan kepada kami [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] dia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam datang menemui kami, sementara kami sedang memandikan putrinya, lalu beliau bersabda: \"Siramlah dengan air dan daun bidara sebanyak tiga atau lima kali atau lebih dari itu jika kalian lihat perlu, dan jadikan pada siraman terakhir dengan air kapur barus atau sesuatu dari kapur barus, apabila kalian sudah selesai, beritahukanlah kepadaku!.\" Ummu 'Athiyyah berkata; \"Seusai memandikan, kami memberitahukan kepada beliau, lalu beliau melemparkan kain (kafan) kepadaku sambil bersabda: \"Pakaikanlah kain itu padanya!.\" Muhammad berkata; Hafshah berkata; lalu beliau bersabda: \"Mandikanlah dengan bilangan ganjil sebanyak tiga, lima atau tujuh kali.\" Muhammad berkata; Ummu 'Athiyyah mengatakan; \"lalu kami menyisir rambutnya menjadi tiga kepang.\""},"2861":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا هِشَامٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ أَخْلُفُهُمْ فِي رِحَالِهِمْ وَأَصْنَعُ لَهُمْ الطَّعَامَ وَأَقُومُ عَلَى مَرْضَاهُمْ وَأُدَاوِي جَرْحَاهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Hisyam] dari [Hafshah] dari [Ummu 'Athiyyah] dia berkata; \"Kami berperang bersama Rasulullah Shallalahu 'Alaihi Wasallam sebanyak tujuh kali, kami berada di garis belakang, membuatkan makanan, merawat orang sakit dan mengobati mereka yang terluka.\""},"2862":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا هِشَامٌ وَيَزِيدُ أَخْبَرَنَا هِشَامٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَبِي وَأُمِّي أَنْ نُخْرِجَ الْعَوَاتِقَ وَذَوَاتِ الْخُدُورِ وَالْحُيَّضَ يَوْمَ الْفِطْرِ وَيَوْمَ النَّحْرِ فَأَمَّا الْحُيَّضُ فَيَعْتَزِلْنَ الْمُصَلَّى وَيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُسْلِمِينَ قَالَ قِيلَ أَرَأَيْتَ إِحْدَاهُنَّ لَا يَكُونُ لَهَا جِلْبَابٌ قَالَ فَلْتُلْبِسْهَا أُخْتُهَا مِنْ جِلْبَابِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Hisyam] dan [Yazid]. Telah menceritakan kepada kami [Hisyam] dari [Hafshah] dari [Ummu 'Athiyyah] dia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam menyuruh kami, demi ayah dan ibuku agar kami menyuruh keluar semua gadis, orang tua dan orang yang menstruasi di hari raya idul fitri dan idul adha, sedangkan orang-orang yang sedang haidh hendaknya menjauhi tempat shalat, dan untuk menyaksikan (acara) yang baik serta memenuhi undangan kaum mulimin, dikatakan; bagaimana pendapatmu jika salah seorang dari kami tidak memiliki jilbab untuk ia kenakan?\" Ia menjawab; \"Hendaknya saudara perempuannya memberi jilbab kepadanya.\""},"2863":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ حَدَّثَنَا هِشَامٌ وَيَزِيدُ أَخْبَرَنَا هِشَامُ بْنُ حَسَّانَ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ الْأَنْصَارِيَّةِ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَزِيدُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُحِدُّ الْمَرْأَةُ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ فَإِنَّهَا تُحِدُّ عَلَيْهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا وَلَا تَلْبَسُ ثَوْبًا مَصْبُوغًا إِلَّا عَصْبًا وَلَا تَكْتَحِلُ وَلَا تَمَسُّ طِيبًا إِلَّا عِنْدَ طُهْرِهَا قَالَ يَزِيدُ أَوْ فِي طُهْرِهَا فَإِذَا طَهُرَتْ مِنْ حَيْضِهَا نُبْذَةً مِنْ قُسْطٍ وَأَظْفَارٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahman Ath Thufawi], telah menceritakan kepada kami [Hisyam] -dan [Yazid] telah mengabarkan pada kami [Hisyam bin Hasan] - dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah Al Anshariyah] dia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: [Yazid] mengatakan; dari Nabi Shallalahu 'Alaihi Wasallam- beliau bersabda: \"Janganlah seorang wanita berkabung melebihi tiga hari, kecuali karena kematian suaminya, maka dia berkabung selama empat bulan sepuluh hari, jangan memakai pakaian yang berwarna warni kecuali pakaian beludru (pakaian kasar), jangan bercelak dan jangan pula memakai wewangian kecuali setelah suci.\" Yazid berkata; \"Atau pada waktu sucinya, apabila telah suci dari haidnya, maka di perbolehkan baginya memakai sedikit qusth (gaharu) dan Adlfar (sejenis tanaman yang berbau harum).\""},"2864":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا عَاصِمٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ يُبَايِعْنَكَ عَلَى أَنْ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا إِلَى قَوْلِهِ وَلَا يَعْصِينَكَ فِي مَعْرُوفٍ }قَالَتْ كَانَ مِنْهُ النِّيَاحَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِلَّا آلَ فُلَانٍ فَإِنَّهُمْ قَدْ كَانُوا أَسْعَدُونِي فِي الْجَاهِلِيَّةِ فَلَا بُدَّ لِي مِنْ أَنْ أُسْعِدَهُمْ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا آلَ فُلَانٍ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah], telah menceritakan kepada kami ['Ashim] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah] ia berkata; \"Ketika turun ayat; YUBAAYI'NAAKA AN LAA YUSYRIKNA BILLAHI SYAIAN (mereka berbai'at kepadamu untuk tidak menyekutukan Allah dengan sesuatupun) sampai ayat WALAA YA'SHIINAKA FIE MA'RUUF (dan tidak menyalahimu dalam perkara yang baik) ia berkata; termasuk di dalamnya adalah urusan niyahah, lalu aku berkata; \"Wahai Rasulullah, kecuali keluarga fulan, karena mereka telah membahagiakanku di zaman jahiliyah, sehingga aku harus membahagiakan mereka.\" Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Kecuali keluarga si fulan.\""},"2865":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا إِسْحَاقُ بْنُ عُثْمَانَ الْكِلَابِيُّ أَبُو يَعْقُوبَ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ الرَّحْمَنِ ابْنِ عَطِيَّةَ الْأَنْصَارِيُّ عَنْ جَدَّتِهِ أُمِّ عَطِيَّةَ قَالَتْلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ جَمَعَ نِسَاءَ الْأَنْصَارِ فِي بَيْتٍ ثُمَّ بَعَثَ إِلَيْهِنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَامَ عَلَى الْبَابِ فَسَلَّمَ فَرَدَدْنَ عَلَيْهِ السَّلَامَ فَقَالَ أَنَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْكُنَّ قُلْنَا مَرْحَبًا بِرَسُولِ اللَّهِ وَرَسُولِ رَسُولِ اللَّهِ وَقَالَ تُبَايِعْنَ عَلَى أَنْ لَا تُشْرِكْنَ بِاللَّهِ شَيْئًا وَلَا تَزْنِينَ وَلَا تَقْتُلْنَ أَوْلَادَكُنَّ وَلَا تَأْتِينَ بِبُهْتَانٍ تَفْتَرِينَهُ بَيْنَ أَيْدِيكُنَّ وَأَرْجُلِكُنَّ وَلَا تَعْصِينَهُ فِي مَعْرُوفٍ قُلْنَا نَعَمْ فَمَدَدْنَا أَيْدِيَنَا مِنْ دَاخِلِ الْبَيْتِ وَمَدَّ يَدَهُ مِنْ خَارِجِ الْبَيْتِ ثُمَّ قَالَ اللَّهُمَّ اشْهَدْ وَأَمَرَنَا بِالْعِيدَيْنِ أَنْ نُخْرِجَ الْعُتَّقَ وَالْحُيَّضَ وَنَهَى عَنْ اتِّبَاعِ الْجَنَائِزِ وَلَا جُمُعَةَ عَلَيْنَا وَسَأَلْتُهَا عَنْ قَوْلِهِ{ وَلَا يَعْصِينَكَ فِي مَعْرُوفٍ }قَالَتْ نُهِينَا عَنْ النِّيَاحَةِ","id":"Telah menceritakan kepada kami [Abu Sa'id], telah menceritakan kepada kami [Ishaq bin Utsman Al Kilabi Abu Ya'qub] telah menceritakan kepada kami [Isma'il bin Abdurrahman bin 'Athiyyah Al Anshari] dari neneknya yaitu [Ummu 'Athiyyah] ia berkata; \"Setibanya Rasulullah Shallalahu 'Alaihi Wasallam di Madinah, beliau mengumpulkan para wanita Anshar di suatu rumah. Lalu beliau mengutus Umar radliallahu 'anhu menemui mereka, Umar lalu berdiri di depan pintu mengucap salam, mereka pun menjawab salamnya, ia berkata; \"Aku adalah utusan Rasulullah Shallalahu 'Alaihi Wasallam untuk kalian.\" Kami menjawab; \"Selamat datang Rasulullah dan utusan Rasulullah Shallalahu 'Alaihi Wasallam.\" Umar berkata; \"Hendaklah kalian berbai'at untuk tidak menyukutkan Allah dengan sesuatupun, tidak berzina, tidak membunuh anak-anak kalian, tiada berdusta yang kalian ada-adakan antara tangan dan kaki kalian dan kalian tidak durhaka dalam urusan yang baik,!.\" Kami menjawab; \"Ya, \" Kamipun melambaikan tangan-tangan kami dari dalam rumah, sedangkan beliau melambaikan tangannya dari luar rumah seraya bersabda: \"Ya Allah, saksikanlah!, \" beliau juga menyuruh kami berhari raya di dua hari raya, dengan mengeluarkan seluruh orang tua dan orang yang sedang haid, melarang kami mengikuti jenazah dan shalat jum'at.\" Akupun bertanya kepada Ummu 'Athiyah tentang firman Allah Tidak durhaka dalam urusan yang baik. QS Al Mumtahanah; 12, dia menjawab; beliau melarang kami melakukan niyahah.\" "},"2866":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ الْأَنْصَارِيَّةِ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا أَنْ نُخْرِجَ الْعَوَاتِقَ وَالْحُيَّضَ وَذَوَاتِ الْخُدُورِ فَأَمَّا الْحُيَّضُ فَيَعْتَزِلْنَ الْمُصَلَّى وَيَشْهَدْنَ الْخَيْرَ وَالدَّعْوَةَ مَعَ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Husain bin Muhammad], telah menceritakan kepada kami [Jarir yaitu Ibnu Hazim] dari [Muhammad] dari [Ummu 'Athiyyah Al Anshariyyah] ia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam menyuruh kami mengeluarkan orang-orang yang sedang haid, para orang tua, perawan dan gadis-gadis pingitan untuk menyaksikan kebaikan dan dakwah kaum mukminin, adapun wanita yang sedang haid hendaknya menjauh dari tempat shalat.\""},"2867":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ أَخَذَ ابْنُ سِيرِينَ غُسْلَهُ عَنْ أُمِّ عَطِيَّةَ قَالَتْغَسَّلْنَا ابْنَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنَا أَنْ نَغْسِلَهَا بِالسِّدْرِ ثَلَاثًا فَإِنْ أَنْجَتْ وَإِلَّا فَخَمْسًا فَإِنْ أَنْجَتْ وَإِلَّا فَأَكْثَرَ مِنْ ذَلِكَ قَالَتْ فَرَأَيْنَا أَنَّ أَكْثَرَ مِنْ ذَلِكَ سَبْعٌ","id":"Telah menceritakan kepada kami ['Afan], telah menceritakan kepada kami [Hammam], telah menceritakan kepada kami [Qatadah] ia berkata; [Ibnu Sirin] mengambil hadits tentang memandikan mayit dari [Ummu 'Athiyyah] ia berkata; \"Kami memandikan puteri Rasulullah Shallalahu 'Alaihi Wasallam, lalu beliau menyuruh kami memandikannya dengan daun bidara sebanyak tiga kali (guyuran), bila kurang maka lima kali, bila masih kurang, maka lebih banyak dari itu.\" Ia berkata; \"Kami berpendapat paling banyak adalah tujuh kali.\""},"2868":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا يَزِيدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ سِيرِينَ قَالَ نُبِّئْتُ أَنَّ أُمَّ عَطِيَّةَ قَالَتْتُوُفِّيَ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنَا أَنْ نَغْسِلَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ وَأَنْ نَجْعَلَ فِي الْغَسْلَةِ الْآخِرَةِ شَيْئًا مِنْ سِدْرٍ وَكَافُورٍ","id":"Telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Yazid bin Ibrahim], telah menceritakan kepada kami [Muhammad bin Sirin], ia berkata; \" [Aku diberitahu] bahwa [Ummu 'Athiyyah] berkata; \"Salah seorang puteri Rasulullah Shallalahu 'Alaihi Wasallam meninggal dunia, lalu beliau menyuruh kami memandikannya sebanyak tiga atau lima kali atau lebih banyak dari itu, bila kami memandang perlu, dan bilasan terakhir dengan bidara atau kapur.\""},"2869":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ سَمُرَةَ يَقُولُأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بمَاعِزِ بْنِ مَالِكٍ رَجُلٍ قَصِيرٍ فِي إِزَارِهِ مَا عَلَيْهِ رِدَاءٌ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئٌ عَلَى وِسَادَةٍ عَلَى يَسَارِهِ فَكَلَّمَهُ وَمَا أَدْرِي مَا يُكَلِّمُهُ وَأَنَا بَعِيدٌ مِنْهُ بَيْنِي وَبَيْنَهُ قَوْمٌ فَقَالَ اذْهَبُوا بِهِ ثُمَّ قَالَ رُدُّوهُ فَكَلَّمَهُ وَأَنَا أَسْمَعُ فَقَالَ اذْهَبُوا بِهِ فَارْجُمُوهُ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا وَأَنَا أَسْمَعُهُ قَالَ فَقَالَ أَكُلَّمَا نَفَرْنَا فِي سَبِيلِ اللَّهِ خَلَفَ أَحَدُهُمْ لَهُ نَبِيبٌ كَنَبِيبِ التَّيْسِ يَمْنَحُ إِحْدَاهُنَّ الْكُثْبَةَ مِنْ اللَّبَنِ وَاللَّهِ لَا أَقْدِرُ عَلَى أَحَدِهِمْ إِلَّا نَكَّلْتُ بِهِ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan pada kami [Isra`il] dari [Simak] bahwa dia mendengar [Jabir bin Samurah] berkata; Ma'iz bin Malik di hadapkan kepada Nabi Shallalahu 'Alaihi Wasallam, dia adalah seorang lelaki berbadan pendek, di kain sarungnya tidak mengenakan selendang (sabuk), Jabir mengatakan; Sementara Rasulullah Shallalahu 'Alaihi Wasallam tengah bersandar ke sebelah kiri dengan bantal, lalu beliau berbicara kepadanya, namun aku tidak tahu apa yang dibicarakannya karena aku jauh darinya. antara aku dan beliau terhalang sekelompok orang, kemudian beliau bersabda: \"Bawalah dan rajamlah dia!.\" Beliau bersabda lagi: \"Kembalikanlah dia ke sini.\" Lalu beliau berbicara dengannya dan akupun dapat mendengarnya, beliau bersabda: \"Bawalah dan rajamlah dia!.\" Lalu Rasulullah Shallalahu 'Alaihi Wasallam berdiri berkhutbah dan saya mendengarkannya, [Jabir] berkata; beliau bersabda: \"Ketahuilah, setiap kali kita pergi berperang di jalan Allah, ternyata salah seorang dari mereka ada yang tertinggal, dia memberikan sesuatu (kepada isterinya) seperti suara kambing pejantan yang sedang terbakar nafsu birahi, salah seorang dari mereka memberikan sedikit susunya, demi Allah jika aku mampu menangkap mereka niscaya aku akan menghukum mereka.\""},"2870":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا إِسْرَائِيلُ قَالَ أَخْبَرَنِي سِمَاكٌ أَنَّهُ سَمِعَ جَابِرَ بْنَ سَمُرَةَ يَقُولُكَانَ مُؤَذِّنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤَذِّنُ ثُمَّ يُمْهِلُ فَلَا يُقِيمُ حَتَّى إِذَا رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ خَرَجَ أَقَامَ الصَّلَاةَ حِينَ يَرَاهُ","id":"Telah menceritakan kepada kami [Abdurrazaq], telah mengabarkan kepada kami [Isra`il], dia berkata; telah mengabarkan kepada kami [Simak] bahwa ia mendengar [Jabir bin Samurah] berkata; \"Mu'adzin Rasulullah Shallalahu 'Alaihi Wasallam mengumandangkan adzan, lalu ia menunggu sebentar tidak mengumandangkan iqamat, ketika Rasulullah Shallalahu 'Alaihi Wasallam keluar, barulah shalat ditegakkan, yaitu setelah melihat beliau keluar.\""},"2871":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا مِسْعَرٌ عَنْ عُبَيْدِ اللَّهِ ابْنِ الْقِبْطِيَّةِ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكُنَّا إِذَا صَلَّيْنَا وَرَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا السَّلَامُ عَلَيْكُمْ بِأَيْدِينَا يَمِينًا وَشِمَالًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَالُ أَقْوَامٍ يَرْمُونَ بِأَيْدِيهِمْ كَأَنَّهَا أَذْنَابُ الْخَيْلِ الشُّمْسِ أَلَا يَسْكُنُ أَحَدُكُمْ وَيُشِيرُ بِيَدِهِ عَلَى فَخِذِهِ ثُمَّ يُسَلِّمُ عَلَى صَاحِبِهِ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ","id":"Telah menceritakan kepada kami [Yazid], telah mengabarkan pada kami [Mis'ar] dari [Ubaidullah bin Al Qibthiyah] dari [Jabir bin Samurah] dia berkata; \"Apabila kami shalat di belakang Rasulullah Shallalahu 'Alaihi Wasallam, kami mengucapkan \"Assalaamu'alaikum\" sambil memberikan isyarat dengan tangan ke kanan dan ke kiri, maka Rasulullah Shallalahu 'Alaihi Wasallam bertanya: \"Kenapa orang-orang mengangkat tangannya seakan-akan ekor kuda yang kepanasan, hendaklah salah seorang dari kalian tenang dan menunjuk dengan tangannya di atas pahanya, kemudian memberikan salam atas sahabatnya ke kanan dan ke kiri.\""},"2872":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَخْبَرَنَا شُعْبَةُ عَنْ سِمَاكٍ قَالَ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَوَسُئِلَ عَنْ شَيْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ فِي رَأْسِهِ شَعَرَاتٌ إِذَا دَهَنَ رَأْسَهُ لَمْ تَتَبَيَّنْ وَإِذَا لَمْ يَدْهُنْهُ تَتَبَيَّنُ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud], telah mengabarkan pada kami [Syu'bah] dari [Simak] dia berkata; aku mendengar [Jabir bin Samurah] ketika ditanya tentang uban Rasulullah Shallalahu 'Alaihi Wasallam, dia menjawab; \"Di kepala beliau hanya ada beberapa helai uban, apabila diminyaki, maka ubannya tidak tampak, namun apabila tidak diminyaki maka ubannya akan tampak.\""},"2873":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ سَمِعَ جَابِرًا يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَنَحْوَهَا وَفِي الصُّبْحِ بِأَطْوَلَ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud], telah menceritakan kepada kami [Syu'bah] dari [Simak] dia mendengar [Jabir] berkata; pada waktu shalat Zhuhur Rasulullah Shallalahu 'Alaihi Wasallam biasa membaca \"SABBIHISMA RABBIKAL A'LA\" dan yang semisalnya, sedangkan pada waktu shalat Shubuh beliau membaca surat yang lebih panjang dari surat itu.\""},"2874":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ قَالَ قُلْتُ لِجَابِرِ بْنِ سَمُرَةَأَكُنْتَ تُجَالِسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ فَكَانَ طَوِيلَ الصَّمْتِ قَلِيلَ الضَّحِكِ وَكَانَ أَصْحَابُهُ يَذْكُرُونَ عِنْدَهُ الشِّعْرَ وَأَشْيَاءَ مِنْ أُمُورِهِمْ فَيَضْحَكُونَ وَرُبَّمَا تَبَسَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud], telah menceritakan kepada kami [Syarik] dari [Simak] dia berkata; aku bertanya kepada [Jabir bin Samurah]; \"Apakah kamu pernah bergaul dengan Rasulullah Shallalahu 'Alaihi Wasallam?.\" Dia menjawab; \"Ya, beliau adalah sosok yang pendiam, sedikit tertawa, suatu ketika para sahabatnya berada disisi beliau tengah menyampaikan sya'ir dan sesuatu dari perkara-perkara mereka, yang di iringi dengan gelak tawa, namun beliau hanya tersenyum.\""},"2875":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْوَلِيدِ وَمُؤَمَّلٌ الْمَعْنَى وَهَذَا لَفْظُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَعْفَرِ بْنِ أَبِي ثَوْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَوَضَّأُ مِنْ لُحُومِ الْغَنَمِ قَالَ لَا قَالَ فَأُصَلِّي فِي مُرَاحِ الْغَنَمِ قَالَ نَعَمْ قَالَ أَتَوَضَّأُ مِنْ لُحُومِ الْإِبِلِ قَالَ نَعَمْ قَالَ فَأُصَلِّي فِي أَعْطَانِهَا قَالَ لَا","id":"Telah menceritakan kepada kami [Abdullah bin Walid] dan [Mu`ammal] dengan maksud yang sama, dan ini adalah lafadz dari Abdullah, keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Simak bin Harb] dari [Ja'far bin Abu Tsaur] dari [Jabir bin Samurah] bahwa seorang lelaki bertanya kepada Nabi Shallalahu 'Alaihi Wasallam; \"Apakah aku harus berwudlu setelah makan daging kambing?.\" Beliau menjawab: \"Tidak\" dia bertanya lagi; \"Apakah aku boleh shalat di kandang kambing?.\" beliau menjawab: \"Ya, \" dia bertanya lagi; \"Apakah aku harus berwudlu setelah makan daging unta?.\" Beliau menjawab: \"Ya, \" dia bertanya lagi; \"Apakah aku boleh shalat di kandang unta?.\" Beliau menjawab: \"Tidak boleh.\""},"2876":{"ar":"حَدَّثَنَا عُمَرُ بْنُ سَعْدٍ أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَة�� قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا وَيَجْلِسُ بَيْنَ الْخُطْبَتَيْنِ وَيَقْرَأُ آيَاتٍ وَيُذَكِّرُ النَّاسَ","id":"Telah menceritakan kepada kami [Umar bin Sa'd Abu Dawud Al Hafari] dari [Sufyan] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Rasulullah Shallalahu 'Alaihi Wasallam berkhutbah sambil berdiri, kemudian beliau duduk di antara dua khutbah, lalu membacakan beberapa ayat dan mengingatkan manusia.\""},"2877":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ أُسَامَةَ حَدَّثَنَا مُجَالِدٌ عَنْ عَامِرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ السُّوَائِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي حَجَّةِ الْوَدَاعِ إِنَّ هَذَا الدِّينَ لَنْ يَزَالَ ظَاهِرًا عَلَى مَنْ نَاوَأَهُ لَا يَضُرُّهُ مُخَالِفٌ وَلَا مُفَارِقٌ حَتَّى يَمْضِيَ مِنْ أُمَّتِي اثْنَا عَشَرَ خَلِيفَةً قَالَ ثُمَّ تَكَلَّمَ بِشَيْءٍ لَمْ أَفْهَمْهُ فَقُلْتُ لِأَبِي مَا قَالَ قَالَ كُلُّهُمْ مِنْ قُرَيْشٍ","id":"Telah menceritakan kepada kami [Hammad bin Usamah], telah menceritakan kepada kami [Mujalid] dari [Amir] dari [Jabir bin Samurah As Suwa`i] ia berkata; Aku mendengar Rasulullah Shallalahu 'Alaihi Wasallam bersabda di haji wada': \"Agama ini akan selalu tampak kuat dari yang memusuhinya, tiada akan membahayakan orang-orang yang menyelisihi atau yang memporak-porandakannya hingga berlalu dua belas khalifah dari umatku, \" Lalu beliau berbicara dengan kalimat yang tidak aku fahami, lantas aku tanyakan maksudnya kepada ayahku, ia berkata; Rasulullah Shallalahu 'Alaihi Wasallam bersabda: \"Semuanya dari Quraisy.\""},"2878":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ أَهْلَ بَيْتٍ كَانُوا بِالْحَرَّةِ مُحْتَاجِينَ قَالَ فَمَاتَتْ عِنْدَهُمْ نَاقَةٌ لَهُمْ أَوْ لِغَيْرِهِمْ فَرَخَّصَ لَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَكْلِهَا قَالَ فَعَصَمَتْهُمْ بَقِيَّةَ شِتَائِهِمْ أَوْ سَنَتِهِمْ","id":"Telah menceritakan kepada kami [Abu Kamil], telah menceritakan kepada kami [Syarik] dari [Simak] dari [Jabir bin Samurah] bahwa suatu penduduk rumah di Harrah dalam keadaan sangat membutuhkan, Jabir berkata; \"lantas seekor unta milik mereka atau orang lain mati, maka Nabi Shallalahu 'Alaihi Wasallam memberikan keringanan kepada mereka untuk memakannya.\" Jabir berkata; \"Maka mereka terlindungi dari sisa musim dingin atau musim paceklik.\""},"2879":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ الْحِمْصِيُّ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ ح وَأَبُو الْيَمَانِ أَنْبَأَنَا شُعَيْبٌ قَالَ وَقَالَ الزُّهْرِيُّ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِيهِ خَبَّابِ بْنِ الْأَرَتِّ مَوْلَى بَنِي زُهْرَةَ وَكَانَ قَدْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَرَاقَبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي لَيْلَةٍ صَلَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلَّهَا حَتَّى كَانَ مَعَ الْفَجْرِ سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ صَلَاتِهِ جَاءَهُ خَبَّابٌ فَقَالَ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي لَقَدْ صَلَّيْتَ اللَّيْلَةَ صَلَاةً مَا رَأَيْتُكَ صَلَّيْتَ نَحْوَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجَلْ إِنَّهَا صَلَاةُ رَغَبٍ وَرَهَبٍ سَأَلْتُ رَبِّي تَبَارَكَ وَتَعَالَى ثَلَاثَ خِصَالٍ فَأَعْطَانِي اثْنَتَيْنِ وَمَنَعَنِي وَاحِدَةً سَأَلْتُ رَبِّي تَبَارَكَ وَتَعَالَى أَنْ لَا يُهْلِكَنَا بِمَا أَهْلَكَ بِهِ الْأُمَمَ قَبْلَنَا فَأَعْطَانِيهَا وَسَأَلْتُ رَبِّي عَزَّ وَجَلَّ أَنْ لَا يُظْهِرَ عَلَيْنَا عَدُوًّا غَيْرَنَا فَأَعْطَانِيهَا وَسَأَلْتُ رَبِّي تَبَارَكَ وَتَعَالَى أَنْ لَا يَلْبِسَنَا شِيَعًا فَمَنَعَنِيهَاحَدَّثَنَا عَبْد اللَّهِ قَالَ سَمِعْت أَبِي يَقُولُ عَلِيُّ بْنُ عَيَّاشٍ سَمِعَ هَذَا الْحَدِيثَ مِنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ سَمَاعًا","id":"Telah menceritakan kepada kami [Ali bin Ayyasy Al Himshi] telah menceritakan kepada kami [Syu'aib bin Abu Hamzah]. (dalam jalur lain disebutkan) [Abu Al Yaman] telah memberitakan kepada kami [Syu'aib] ia berkata, [Az Zuhri] berkata, telah menceritakan kepadaku [Abdullah bin Abdullah bin Al Harits bin Naufal] dari [Abdullah bin Khabab] dari bapaknya [Khabab bin Al Arts] budak Bani Zuhrah -Ia pernah ikut perang badar bersama Rasulullah shallallahu 'alaihi wasallam- bahwa ia berkata, \"Pada suatu malam aku memperhatikan Rasulullah shallallahu 'alaihi wasallam shalat sepanjang malam, sehingga katika waktu fajar tiba Rasulullah shallallahu 'alaihi wasallam salam dari shalatnya. Kemudian Khabab menemuinya dan berkata, \"Wahai Rasulullah demi bapak dan ibuku sebagai tebusanmu, sungguh aku tidak pernah sebelumnya melihatmu shalat seperti shalatmu malam ini!\" Rasulullah shallallahu 'alaihi wasallam kemudian menjawab \"Benar, itu adalah shalatnya orang yang yang penuh harap dan takut. Aku memohon kepada Rabbku Tabaraka Wa Ta'ala tiga hal, lalu Allah menerima dari dua hal dan menolak satu hal. Aku memohon kepada Rabbku Tabaraka Wa Ta'ala agar kita tidak dibinasakan sebagaimana ummat ummat sebelum kita lalu Allah mengabulkannya, aku memohon kepada Rabbku 'azza wajalla agar musuh tidak menang atas kita lalu Allah mengabulkannya, kemudian aku memohon kepada Rabbku Tabaraka Wa Ta'ala agar tidak menjadikan kita pecah berkelompok-kelompok, lalu Allah tidak mengabulkannya.\" Telah bercerita kepada kami Abdullah dia berkata, \"Aku mendengar bapakku berkata, \"'Ali bin 'Iyas mendengar hadits ini dari Syu'aib bin Abu Hamzah dengan cara sama' (mendengar).\""},"2880":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَاقَ عَنْ حَارِثَةَ قَالَأَتَيْنَا خَبَّابًا نَعُودُهُ فَقَالَ لَوْلَا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَتَمَنَّيَنَّ أَحَدُكُمْ الْمَوْتَ لَتَمَنَّيْتُهُحَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابِ بْنِ الْأَرَتِّ أَنَّ خَبَّابًا قَالَ رَمَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةٍ صَلَّاهَا حَتَّى إِذَا كَانَ مَعَ الْفَجْرِ فَلَمَّا سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ صَلَاتِهِ جَاءَهُ خَبَّابٌ فَقَالَ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي لَقَدْ صَلَّيْتَ فَذَكَرَ مِثْلَ حَدِيثِ شُعْبَةَ","id":"Telah menceritakan kepada kami [Al Aswad bin Amir] Telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Haritsah] dia berkata, \"Kami mendatangi [Khabab] untuk menjenguknya, ia berkata, \"Seandainya aku tidak mendengar sabda Rasulullah shallallahu 'alaihi wasallam yang berbunyi, 'Janganlah salah seorang dari kalian berangan-angan untuk mati, ' niscaya aku akan berangan-angan untuk mati.\" Telah bercerita kepada kami [Ya'qub] dia berkata, telah bercerita kepada kami [Bapakku] dari [Shalih], [Ibnu Abu Syihab] berkata, telah memberitakan kepadaku [Abdullah bin Al Harits bin Naufal] dari [Abdullah bin Khabab bin Al Arts] bahwa [Khabab] berkata, \"Aku memperhatikan Rasulullah shallallahu 'alaihi wasallam shalat hingga ketika tiba waktu fajar, Rasulullah shallallahu 'alaihi wasallam selesai dari shalatnya. Kemudian Khabab menemuinya dan berkata, \"Wahai Rasulullah, demi bapak dan ibuku sebagai tebusanmu! Sungguh engkau telah shalat…kemudian dia menyebutkan seperti hadits Syu'bah.\""},"2881":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ عُمَارَةَ بْنَ عُمَيْرٍ يُحَدِّثُ عَنْ أَبِي مَعْمَرٍ قَالَسَأَلْنَا خَبَّابًا أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ قَالَ نَعَمْ قَالَ فَمِنْ أَيْنَ كُنْتُمْ تَعْلَمُونَ قَالَ بِتَحَرُّكِ لِحْيَتِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] berkata, Aku mendengar [Umarah bin Umair] menceritakan dari [Abu Ma'mar] ia berkata, \"Kami bertanya pada [Khabab] 'Apakah Rasulullah shallallahu 'alaihi wasallam membaca ayat di shalat zhuhurnya? ' Ia menjawab, \"Ya.\" Abu Ma'mar bertanya lagi, \"Dari mana kalian mengetahuinya?\" Ia menjawab, \"Dari gerakan jenggot beliau.\""},"2882":{"ar":"حَدَّثَنَا يَحْيَى قَالَ سَمِعْتُ الْأَعْمَشَ قَالَ سَمِعْتُ شَقِيقًا سَمِعْتُ خَبَّابًا ح وَأَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ خَبَّابٍ قَالَهَاجَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبْتَغِي وَجْهَ اللَّهِ تَبَارَكَ وَتَعَالَى فَوَجَبَ أَجْرُنَا عَلَى اللَّهِ عَزَّ وَجَلَّ فَمِنَّا مَنْ مَضَى لَمْ يَأْكُلْ مِنْ أَجْرِهِ شَيْئًا مِنْهُمْ مُصْعَبُ بْنُ عُمَيْرٍ قُتِلَ يَوْمَ أُحُدٍ فَلَمْ نَجِدْ شَيْئًا نُكَفِّنُهُ فِيهِ إِلَّا نَمِرَةً كُنَّا إِذَا غَطَّيْنَا بِهَا رَأْسَهُ خَرَجَتْ رِجْلَاهُ وَإِذَا غَطَّيْنَا رِجْلَيْهِ خَرَجَ رَأْسُهُ فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُغَطِّيَ بِهَا رَأْسَهُ وَنَجْعَلَ عَلَى رِجْلَيْهِ إِذْخِرًا وَمِنَّا مَنْ أَيْنَعَتْ لَهُ ثَمَرَتُهُ فَهُوَ يَهْدِبُهَا يَعْنِي يَجْتَنِيهَا","id":"Telah menceritakan kepada kami [Yahya] ia berkata, Aku mendengar [Al A'masy] berkata, Aku mendenagr [Syaqiq] berkata, Aku mendengar [Khabbab]. (dalam jalur lain disebutkan) Dan [Abu Mu'awiyah] berkata, Telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Khabbab] ia berkata, \"Kami berhijrah bersama Rasulullah shallallahu 'alaihi wasallam untuk mengharap wajah Allah Tabaaraka Wa Ta'ala, maka wajiblah kami untuk mendapatkan balasan dari Allah Azza Wa Jalla. Di antara kami ada yang tidak mendapatkan buah pahalanya seperti Mus'ab bin Umair yang terbunuh di perang Uhud, kami tidak mendapatkan kain untuk mengkafaninya kecuali namirah (sejenis kain selendang yang bersulam sutera). Jika kain tersebut kami tutupkan pada kepala maka terbukalah kakinya, sementara jika ditutupkan kakinya terbukalah kepalanya. Lalu Rasulullah shallallahu 'alaihi wasallam menyuruh kami agar kain tersebut ditutupkan pada kepalanya, sementara kedua kakinya ditutup dengan daun 'Idzkhir', dan kami juga ada yang menjual buahnya yaitu dengan memetiknya.\""},"2883":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي خَالِدٍ عَنْ قَيْسٍ قَالَدَخَلْنَا عَلَى خَبَّابٍ نَعُودُهُ وَهُوَ يَبْنِي حَائِطًا لَهُ فَقَالَ الْمُسْلِمُ يُؤْجَرُ فِي كُلِّ شَيْءٍ خَلَا مَا يَجْعَلُ فِي هَذَا التُّرَابِ وَقَدْ اكْتَوَى سَبْعًا فِي بَطْنِهِ وَقَالَ لَوْلَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ لَدَعَوْتُ بِهِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ibnu Abu Khalid] dari [Qais] berkata, \"Kami menemui [Khabbab] untuk menjenguknya, sementara ia sedang membangun tembok miliknya. Lalu ia berkata, \"Seorang Muslim akan mendapatkan pahala dari segala sesuatunya, kecuali apa yang ia buat dari tanah ini (bangunan).\" Sementara pada perutnya ada tujuh bekas sulutan besi panas (kay), kemudian ia berkata lagi, \"Kalaulah Rasulullah shallallahu 'alaihi wasallam tidak melarang salah seorang dari kita berangan-angan untuk mati, niscaya aku akan berangan-angan untuk mati.\""},"2884":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ أَبِي مَعْمَرٍ عَنْ خَبَّابٍ قَالَقِيلَ لَهُ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ قَالَ نَعَمْ قِيلَ بِأَيِّ شَيْءٍ كُنْتُمْ تَعْرِفُونَ ذَلِكَ قَالَ بِاضْطِرَابِ لِحْيَتِهِوَابْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ عُمَارَةَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Sulaiman Al A'masy] dari [Umarah] dari [Abu Ma'mar] dari [Khabbab] berkata, bahwasanya telah ditanyakan kepadanya 'Apakah Rasulullah shallallahu 'alaihi wasallam membaca (ayat) dalam shalat zhuhur dan asar?\" Ia menjawab, \"Ya.\" Ditanyakan lagi, \"Dengan apa kalian mengetahui bacaan Rasulullah shallallahu 'alaihi wasallam?\" Ia menjawab, \"Dengan gerakan jenggot beliau.\" [Ibnu Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] Ia berkata, Aku telah mendengar [Umarah] secara makna.\""},"2885":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ ح وَابْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ وَهْبٍ عَنْ خَبَّابٍ قَالَشَكَوْنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شِدَّةَ الرَّمْضَاءِ فَمَا أَشْكَانَا يَعْنِي فِي الصَّلَاةِ وَقَالَ ابْنُ جَعْفَرٍ فَلَمْ يُشْكِنَا","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dan [Ibnu Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Sa'id bin Wahab] dari [Khabab] ia berkata, \"Kami mengeluhkan kepada Nabi shallallahu 'alaihi wasallam tentang panasnya pasir -yaitu saat shalat-. Ibnu Ja'far menyebutkan, \"Namun beliau tidak menggubris keluhan kami.\""},"2886":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ رَجُلٍ مِنْ عَبْدِ الْقَيْسِ كَانَ مَعَ الْخَوَارِجِ ثُمَّ فَارَقَهُمْ قَالَدَخَلُوا قَرْيَةً فَخَرَجَ عَبْدُ اللَّهِ بْنُ خَبَّابٍ ذَعِرًا يَجُرُّ رِدَاءَهُ فَقَالُوا لَمْ تُرَعْ قَالَ وَاللَّهِ لَقَدْ رُعْتُمُونِي قَالُوا أَنْتَ عَبْدُ اللَّهِ بْنُ خَبَّابٍ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قَالَ فَهَلْ سَمِعْتَ مِنْ أَبِيكَ حَدِيثًا يُحَدِّثُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُحَدِّثُنَاهُ قَالَ نَعَمْ سَمِعْتُهُ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ذَكَرَ فِتْنَةً الْقَاعِدُ فِيهَا خَيْرٌ مِنْ الْقَائِمِ وَالْقَائِمُ فِيهَا خَيْرٌ مِنْ الْمَاشِي وَالْمَاشِي فِيهَا خَيْرٌ مِنْ السَّاعِي قَالَ فَإِنْ أَدْرَكْتَ ذَاكَ فَكُنْ عَبْدَ اللَّهِ الْمَقْتُولَ قَالَ أَيُّوبُ وَلَا أَعْلَمُهُ إِلَّا قَالَ وَلَا تَكُنْ عَبْدَ اللَّهِ الْقَاتِلَ قَالُوا أَأَنْتَ سَمِعْتَ هَذَا مِنْ أَبِيكَ يُحَدِّثُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قَالَ فَقَدَّمُوهُ عَلَى ضَفَّةِ النَّهَرِ فَضَرَبُوا عُنُقَهُ فَسَالَ دَمُهُ كَأَنَّهُ شِرَاكُ نَعْلٍ مَا ابْذَقَرَّ وَبَقَرُوا أُمَّ وَلَدِهِ عَمَّا فِي بَطْنِهَاحَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا سُلَيْمَانُ عَنْ حُمَيْدِ بْنِ هِلَالٍ نَحْوَهُ إِلَّا أَنَّهُ قَالَ مَا ابْذَقَرَّ يَعْنِي لَمْ يَتَفَرَّقْ وَقَالَ لَا تَكُنْ عَبْدَ اللَّهِ الْقَاتِلَ وَكَذَلِكَ قَالَ بَهْزٌ أَيْضًا","id":"Telah bercerita kepada kami [Isma'il] dia berkata, telah mengkabarkan kepada kami [Ayyub] dari [Humaid bin Bilal] dari [seorang lelaki Abdul Qais] ia pernah bergabung dengan kaum Khawarij kemudian memisahkan diri dari mereka, ia berkata, \"Orang-orang Khawarij memasuki sebuah kampung, kemudian [Abdullah bin Khabab] keluar dengan ketakutan sambil menjulurkan kain selendangnya, mereka pun bertanya, \"Apakah kamu tidak takut?\" Abdullah menjawab, \"Demi Allah, kalian telah menakutiku.\" Mereka bertanya lagi, \"Apakah kamu Abdullah bin Khabab sahabat Rasulullah shallallahu 'alaihi wasallam?\" Abdullah menjawab, \"Ya.\" Kemudian ada yang bertanya kepadanya, \"Lalu apakah kamu telah mendengar dari [bapakmu] sebuah hadits yang dia ceritakan dari Rasulullah shallallahu 'alaihi wasallam untuk kamu ceritakan kepada kami?\" Abdullah menjawab, \"Ya, aku telah mendengarnya bercerita dari Rasulullah shallallahu 'alaihi wasallam, beliau menyebutkan tentang fitnah: \"Orang yang duduk ketika terjadi fitnah adalah lebih baik dari orang yang berdiri, dan orang yang berdiri adalah lebih baik dari orang yang berjalan, sedangkan orang yang berjalan adalah lebih baik dari orang yang berlari.\" Kemudian Nabi melanjutkan: \"Jika kamu mendapati masa itu maka jadilah kamu hamba Allah yang terbunuh.\" [Ayyub] menyebutkan, \"Dan aku tidak mengetahuinya kecuali beliau bersabda: 'Dan janganlah menjadi hamba Allah yang membunuh'.\" Kemudian orang-orang Khawarij itu bertanya lagi, \"Apakah kamu mendengar ini dari bapakmu yang telah bercerita dari Rasulullah shallallahu 'alaihi wasallam?\" Abdullah menjawab, \"Ya.\" Perawi (lelaki dari Abdu Qais) Berkata, \"Kemudian mereka membawanya ke tepian sungai dan memenggal lehernya, sehingga mengalirlah darahnya seakan-akan tali sandal yang tidak terputus. Dan mereka juga membelah janin yang ada di perut Ummul waladnya (budak wanitanya).\" Telah bercerita kepada kami [Abu Nadlar] dia berkata, telah bercerita kepada kami [Sulaiman] dari [Humaid bin Hilal] dengan hadits yang semakna, akan tetapi dia menambahkan, \"Mabdzaqarra', yaitu tidak berpisah. Dan Nabi bersabda: \"Janganlah menjadi hamba Allah yang membunuh.\" Maka demikian juga yang dikatakan oleh [Bahz]."},"2887":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ قَالَ قَالَ خَبَّابُ بْنُ الْأَرَتِّكُنْتُ قَيْنًا بِمَكَّةَ فَكُنْتُ أَعْمَلُ لِلْعَاصِ بْنِ وَائِلٍ فَاجْتَمَعَتْ لِي عَلَيْهِ دَرَاهِمُ فَجِئْتُ أَتَقَاضَاهُ فَقَالَ لَا أَقْضِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ قَالَ قُلْتُ وَاللَّهِ لَا أَكْفُرُ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمُوتَ ثُمَّ تُبْعَثَ قَالَ فَإِذَا بُعِثْتُ كَانَ لِي مَالٌ وَوَلَدٌ قَالَ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا حَتَّى بَلَغَ فَرْدًا }","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengkabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Dluha] dari [Masruq] dia berkata, bahwa [Khabab bin Al Arts] telah berkata, \"Dulu aku adalah seorang pandai besi di Makkah dan aku bekerja untuk Al Ash bin Wa'il hingga terkumpullah padanya beberapa dirham untukku, kemudian aku datang untuk menagihnya, namun dia berkata, \"Aku tidak akan membayarnya sampai kamu mendustakan Muhammad!\" Khabab berkata, \"Aku lalu berkata, \"Demi Allah, aku tidak akan mendustakan Muhammad shallallahu 'alaihi wasallam sampai kamu mati kemudian kamu dibangkitkan lagi.\" Al Ash bin Wa`il menjawab, \"Jika aku dibangkitkan lagi maka aku akan memiliki harta dan anak.\" Khabab berkata, \"Kemudian hal itu aku sampaikan kepada Nabi shallallahu 'alaihi wasallam, lalu Allah Tabaraka Wa Ta'ala menurunkan ayat: '(Maka apakah kamu Telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak) ' sampai ayat (seorang diri).' (QS. Maryam: 77-80)."},"2888":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ قَالَأَتَيْنَا خَبَّابَ بْنَ الْأَرَتِّ رَضِيَ اللَّهُ عَنْهُ نَعُودُهُ وَقَدْ اكْتَوَى فِي بَطْنِهِ سَبْعًا فَقَالَ لَوْلَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا أَنْ نَدْعُوَ بِالْمَوْتِ لَدَعَوْتُ بِهِ فَقَدْ طَالَ بِي مَرَضِيثُمَّ قَالَ إِنَّ أَصْحَابَنَا الَّذِينَ مَضَوْا لَمْ تُنْقِصْهُمْ الدُّنْيَا شَيْئًا وَإِنَّا أَصَبْنَا بَعْدَهُمْ مَا لَا نَجِدُ لَهُ مَوْضِعًا إِلَّا التُّرَابَ وَقَالَ كَانَ يَبْنِي حَائِطًا لَهُ وَإِنَّ الْمَرْءَ الْمُسْلِمَ يُؤْجَرُ فِي نَفَقَتِهِ كُلِّهَا إِلَّا فِي شَيْءٍ يَجْعَلُهُ فِي التُّرَابِ","id":"Telah menceritakan kepada kami [Yazid] telah mengkabarkan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] ia berkata, \"Kami menjenguk [Khabab bin Al Arat] radliallahu 'anhu sementara di perutnya ada bekas sulutan kay (besi panas untuk pengobatan) sebanyak tujuh tempat. Lalu ia berkata, \"Kalaulah Rasulullah shallallahu 'alaihi wasallam tidak melarang kami untuk mengharap mati, niscaya aku akan berharap supaya mati. Sungguh telah lama sakitku ini.\" Kemudian ia melanjutkan perkataannya, \"Para sahabatku yang telah tiada, mereka tak terkalahkan oleh dunia sedikitpun, namun setelah mereka kami diuji dengan sesuatu yang tidak ada hasil akhirnya kecuali tanah (kematian) -Qais berkata; waktu itu Khabbab sedang membuat bangunan miliknya-. Sesungguhnya seorang Muslim akan mendapatkan pahala dari setiap yang ia nafkahkan, kecuali sesuatu yang ia jadikan dalam tanah (bangunan).\""},"2889":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي عَمْرُو بْنُ مُحَمَّدِ بْنِ بُكَيْرٍ النَّاقِدُ حَدَّثَنَا عُبَيْدَةُ بْنُ حُمَيْدٍ عَنْ عُبَيْدَةَ الضَّبِّيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ يَعْنِي قَاضِي الرَّيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ ذِي الْغُرَّةِ قَالَعَرَضَ أَعْرَابِيٌّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِيرُ فَقَالَ يَا رَسُولَ اللَّهِ تُدْرِكُنَا الصَّلَاةُ وَنَحْنُ فِي أَعْطَانِ الْإِبِلِ فَنُصَلِّي فِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا فَقَالَ أَنَتَوَضَّأُ مِنْ لُحُومِهَا قَالَ نَعَمْ قَالَ أَفَنُصَلِّي فِي مَرَابِضِ الْغَنَمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ قَالَ أَفَنَتَوَضَّأُ مِنْ لُحُومِهَا قَالَ لَا","id":"Telah menceritakan kepada kami Abdulah telah menceritakan kepada kami [Amru bin Muhammad bin Bukair An Naqid] telah menceritakan kepada kami [Ubaidah bin Humaid] dari [Ubaidah Adl Dlibbi] dari [Abdullah bin Abdullah] hakim di kota Ray, dari [Abdurrahman bin Abu Laila] dari [Dzi Ghurrah] ia berkata, \"Seorang badui Arab datang menemui Rasulullah shallallahu 'alaihi wasallam saat beliau sedang mengadakan perjalanan. Badui itu bertanya, \"Wahai Rasulullah, saat waktu shalat datang kami sedang berada di kandang unta, apakah kami boleh melaksanakan shalat di situ?\" Beliau menjawab: \"Jangan.\" Ia bertanya lagi, \"Apakah aku harus berwudlu seusai makan daging unta?\" Beliau menjawab: \"Ya.\" Ia bertanya lagi, \"Apakah kami boleh shalat di kandang kambing?\" Beliau menjawab: \"Ya.\" ia bertanya lagi, \"Apakah aku harus berwudlu seusai makan daging kambing?\" Beliau menjawab: \"Tidak.\""},"2890":{"ar":"حَدَّثَنَا أَبُو عُثْمَانَ سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدِ بْنِ أَبَانَ بْنِ سَعِيدِ بْنِ الْعَاصِ حَدَّثَنِي أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَاقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ قَالَ سَمِعْتُ زِيَادَ بْنَ ضَمْرَةَ بْنِ سَعْدٍ السُّلَمِيَّ يُحَدِّثُ عُرْوَةَ بْنَ الزُّبَيْرِ قَالَ حَدَّثَنِي أَبِي وَجَدِّي وَكَانَا قَدْ شَهِدَا حُنَيْنًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَاصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ ثُمَّ جَلَسَ إِلَى ظِلِّ شَجَرَةٍ فَقَامَ إِلَيْهِ الْأَقْرَعُ بْنُ حَابِسٍ وَعُيَيْنَةُ بْنُ حِصْنِ بْنِ بَدْرٍ يَطْلُبُ بِدَمِ الْأَشْجَعِيِّ عَامِرِ بْنِ الْأَضْبَطِ وَهُوَ يَوْمَئِذٍ سَيِّدُ قَيْسٍ وَالْأَقْرَعُ بْنُ حَابِسٍ يَدْفَعُ عَنْ مُحَلِّمِ بْنِ جَثَّامَةَ لِخِنْدِفٍ فَاخْتَصَمَا بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَأْخُذُونَ الدِّيَةَ خَمْسِينَ فِي سَفَرِنَا هَذَا وَخَمْسِينَ إِذَا رَجَعْنَا قَالَ يَقُولُ عُيَيْنَةُ وَاللَّهِ يَا رَسُولَ اللَّهِ لَا أَدَعُهُ حَتَّى أُذِيقَ نِسَاءَهُ مِنْ الْحُزْنِ مَا أَذَاقَ نِسَائِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلْ تَأْخُذُونَ الدِّيَةَ فَأَبَى عُيَيْنَةُ فَقَامَ رَجُلٌ مِنْ لَيْثٍ يُقَالُ لَهُ مُكَيْتِلٌ رَجُلٌ قَصِيرٌ مَجْمُوعٌ فَقَالَ يَا نَبِيَّ اللَّهِ مَا وَجَدْتُ لِهَذَا الْقَتِيلِ شَبِيهًا فِي غُرَّةِ الْإِسْلَامِ إِلَّا كَغَنَمٍ وَرَدَتْ فَرُمِيَ أَوَّلُهَا فَنَفَرَ آخِرُهَا اسْنُنْ الْيَوْمَ وَغَيِّرْ غَدًا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ ثُمَّ قَالَ بَلْ تَقْبَلُونَ الدِّيَةَ فِي سَفَرِنَا هَذَا خَمْسِينَ وَخَمْسِينَ إِذَا رَجَعْنَا فَلَمْ يَزَلْ بِالْقَوْمِ حَتَّى قَبِلُوا الدِّيَةَ قَالَ فَلَمَّا قَبِلُوا الدِّيَةَ قَالَ قَالُوا أَيْنَ صَاحِبُكُمْ يَسْتَغْفِرُ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ رَجُلٌ آدَمُ طَوِيلٌ ضَرَبَ عَلَيْهِ حُلَّةً كَانَ تَهَيَّأَ لِلْقَتْلِ حَتَّى جَلَسَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا جَلَسَ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا اسْمُكَ قَالَ أَنَا مُحَلِّمُ بْنُ جَثَّامَةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ لَا تَغْفِرْ لِمُحَلِّمٍ اللَّهُمَّ لَا تَغْفِرْ لِمُحَلِّمٍ ثَلَاثَ مَرَّاتٍ فَقَامَ مِنْ بَيْنِ يَدَيْهِ وَهُوَ يَتَلَقَّى دَمْعَهُ بِفَضْلِ رِدَائِهِ فَأَمَّا نَحْنُ بَيْنَنَا فَنَقُولُ قَدْ اسْتَغْفَرَ لَهُ وَلَكِنَّهُ أَظْهَرَ مَا أَظْهَرَ لِيَدَعَ النَّاسُ بَعْضُهُمْ مِنْ بَعْضٍ","id":"Telah menceritakan kepada kami [Abu Utsman Sa'id bin Yahya bin Sa'id bin Aban bin Sa'id bin Al 'Ash] telah menceritakan kepadaku [Ayahku] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Muhammad bin Ja'far bin Zubair] dia berkata, aku mendengar [Ziyad bin Dlamrah bin Sa'd As Sulami] ia menceritakan kepada Urwah bin Zubair dia berkata, [Bapakku] dan [Kakekku] bercerita kepadaku -keduanya pernah ikut perang Hunain bersama Rasulullah shallallahu 'alaihi wasallam-, keduanya berkata, \"Rasulullah shallallahu 'alaihi wasallam melaksanakan shalat zhuhur bersama kami, setelah itu beliau duduk di bawah sebuah pohon. Kemudian berdirilah Al 'Aqra bin Habis dan Uyainah bin Hisn bin Badr di hadapan beliau menuntut darah Al Asyja'i 'Amir bin Al Adlbath -seorang pemimpin bani Qais-, sedangkan Al Aqra' bin Habis membela Muhallim bin Jutsamah dari Khindif, kemudian keduanya berselisih di hadapan Rasulullah shallallahu 'alaihi wasallam. Lantas kami mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: Kalian bisa mengambil tebusan lima puluh dalam perjalanan kami ini (sekarang), dan lima puluhnya lagi setelah kita kembali.\" Urwah berkata, \"Uyainah lalu berkata, \"Demi Allah, wahai Rasulullah aku tidak akan membiarkannya sampai isteri-isterinya merasakan kesedihan sebagaimana yang dirasakan oleh isteri isteriku!\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Akan tetapi kalian mengambil diyat!\", namun Uyainah tetap menolak sehingga bangkitlah salah seorang dari kabilah Laits yang dipanggil dengan nama Mukaitil, seorang lelaki pendek dan berbadan gempal, seraya berkata, \"Wahai Nabiyullah, aku tidak mendapatkan pada korban ini kemiripan dengan apa yang ada pada permulaan Islam, kecuali seperti kambing yang lewat untuk minum kemudian yang pertama dilempar sedangkan yang lainnya kabur, maka putuskanlah hari ini dan rubahlah besok.\" Urwah berkata, \"Rasulullah shallallahu 'alaihi wasallam kemudian mengangkat tangannya dan bersabda: \"Bahkan kalian tetap akan menerima tebusan dalam perjalanan kami ini lima puluh, sedangkan yang lima puluh lagi setelah kami kembali.\" Beliau tetap di situ hingga mereka menerima terbusan tersebut.\" Urwah melanjutkan, \"Kemudian mereka bertanya, \"Di mana sahabat kalian karena Rasulullah akan memohonkan ampunan untuknya?\" Lalu berdirilah seorang lelaki berkulit coklat sawo dan berbadan tinggi dengan memegang kain, ia duduk di hadapan Rasulullah shallallahu 'alaihi wasallam dalam posisi siap untuk diqishash. Setelah dia duduk Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya: \"Siapa namamu?\" Dia menjawab, \"Saya Muhallim bin Jatstsamah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berdoa: \"Ya Allah, jangan berikan ampunan kepada Muhallim. Ya Allah jangan berikan ampunan kepada Muhallim.\" Sebanyak tiga kali, kemudian ia bangkit dari sisi Rasulullah sambil mengusap air matanya dengan ujung kainnya. Sementara kami saling memohonkan ampunan untuknya, akan tetapi dia menampakkan apa yang nampak agar manusia satu sama lain pergi meninggalkannya.\""},"2891":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبَّادٍ الْمَكِّيُّ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ عَنْ عَبْدِ الْمَلِكِ بْنِ حَسَنٍ الْجَارِيِّ عَنْ عُمَارَةَ بْنِ حَارِثَةَ عَنْ عَمْرِو بْنِ يَثْرِبِيٍّ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا وَلَا يَحِلُّ لِامْرِئٍ مِنْ مَالِ أَخِيهِ شَيْءٌ إِلَّا بِطِيبِ نَفْسٍ مِنْهُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ لَقِيتُ غَنَمَ ابْنِ عَمِّي أَجْتَزِرُ مِنْهَا شَاةً فَقَالَ إِنْ لَقِيتَهَا نَعْجَةً تَحْمِلُ شَفْرَةً وَأَزْنَادًا بِخَبْتِ الْجَمِيشِ فَلَا تَهِجْهَا قَالَ يَعْنِي خَبْتَ الْجَمِيشِ أَرْضًا بَيْنَ مَكَّةَ وَالْجَارِ لَيْسَ بِهَا أَنِيسٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abbad Al Makki] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Abdul Malik bin Hasan Al Jari] dari [Umarah bin Haritsah] dari [Amru bin Yatsribi] Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah di hadapan kami, beliau bersabda: \"Ketahuilah, harta seseorang tidak halal untuk saudaranya kecuali atas kerelaan hatinya.\" Aku bertanya, \"Wahai Rasulullah, Bagaimana menurutmu apabila aku mendapatkan sekawanan kambing milik keponakanku, lalu aku mengambil satu kambing muda dan aku sembelih, apakah aku berdosa?\" Beliau menjawab: \"Jika kamu mendapatkan kambing yang gemuk dan berbulu tebal (bagus) di Khabtil Jamisy (padang rumput), sedang kamu membawa pisau dan kayu bakar (untuk masak), maka janganlah engkau sentuh kambing itu.\" Amru berkata, \"Khabtil jamisy adalah padang rumput di antara Makkah dan Al Jar dan tidak ada binarang yang jinak di situ.\""},"2892":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الْحَسَنِ يَعْنِي الْجَارِيَّ حَدَّ��َنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي سَعِيدٍ قَالَ سَمِعْتُ عِمَارَةَ بْنَ حَارِثَةَ يُحَدِّثُ عَنْ عَمْرِو بْنِ يَثْرِبِيٍّ الضَّمْرِيِّ قَالَشَهِدْتُ خُطْبَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى فَكَانَ فِيمَا خَطَبَ بِهِ أَنْ قَالَ وَلَا يَحِلُّ لِامْرِئٍ مِنْ مَالِ أَخِيهِ إِلَّا مَا طَابَتْ بِهِ نَفْسُهُ قَالَ فَلَمَّا سَمِعْتُ ذَلِكَ قُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ لَوْ لَقِيتُ غَنَمَ ابْنِ عَمِّي فَأَخَذْتُ مِنْهَا شَاةً فَاجْتَزَرْتُهَا عَلَيَّ فِي ذَلِكَ شَيْءٌ قَالَ إِنْ لَقِيتَهَا نَعْجَةً تَحْمِلُ شَفْرَةً وَأَزْنَادًا فَلَا تَمَسَّهَاهَذَا آخِرُ مُسْنَدِ الْبَصْرِيِّينَ رَضِيَ اللَّهُ عَنْهُمْ","id":"Telah menceritakan kepada kami [Abu Amir] telah menceritakan kepada kami [Abdul Malik bin Hasan Al Jari] telah menceritakan kepada kami [Abdurrahman bin Abu Sa'id] ia berkata, Aku mendengar [Imarah bin Haritsah] menceritakan dari [Amru bin Yatsribi Adl Dlamri] Ia berkata, \"Aku mendapatkan Rasulullah shallallahu 'alaihi wasallam sedang berkhutbah di Mina, beliau bersabda: Ketahuilah, harta seseorang tidak halal untuk saudaranya kecuali atas kerelaan hatinya.\" Aku lalu bertanya, \"Wahai Rasulullah, bagaimana pendapatmu jika aku mendapatkan sekawanan kambing milik keponakanku, lalu aku mengambil satu kambing muda dan aku sembelih, apakah aku berdosa?\" Beliau menjawab: \"Jika kamu mendapatkan kambing yang gemuk sedang kamu membawa pisau dan kayu bakar (untuk masak), maka janganlah engkau sentuh kambing itu.\" Dan ini adalah akhir musnad orang-orang Bashrah radliallahu 'anhum.\""},"2893":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُعَلِيٌّ أَقْضَانَا وَأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ كَثِيرًا مِنْ لَحْنِ أُبَيٍّ وَأُبَيٌّ يَقُولُ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدَعُهُ لِشَيْءٍ وَاللَّهُ تَبَارَكَ وَتَعَالَى يَقُولُ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata, \" [Umar] radliallahu 'anhu berkata, \"Ali adalah orang yang paling paham dengan hukum di antara kami dan Ubai adalah orang yang paling pandai dalam membaca Al-Qur'an di antara kami, sementara kami banyak meninggalkan qira`ah Ubay (dalam membaca Al-Qur'an). [Ubay] pernah berkata, \"Aku telah mendengar dari Rasulullah shallallahu 'alaihi wasallam, maka aku tidak akan meninggalkannya karena sesuatu. Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya, kami datangkan yang lebih baik daripadanya atau yang sebanding dengannya) ' (QS. Al Baqarah: 106)."},"2894":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ حَدَّثَنِي حَبِيبٌ يَعْنِي ابْنَ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ قَالَ عُمَرُعَلِيٌّ أَقْضَانَا وَأُبَيٌّ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ مِنْ قَوْلِ أُبَيٍّ وَأُبَيٌّ يَقُولُ أَخَذْتُ مِنْ فَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدَعُهُ وَاللَّهُ يَقُولُ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا }","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] telah menceritakan kepadaku [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] radliallahu 'anhu berkata, \" [Umar]? radliallahu 'anhu berkata, \"Ali adalah orang yang paling paham dengan hukum di antara kami dan Ubai adalah orang yang paling pandai dalam membaca Al-Qur'an di antara kami, sementara kami telah meninggalkan qira`ah (bacaan Al-Qur'an) Ubay. Dan [Ubay] berkata, \"Aku mengambilnya dari mulut Rasulullah shallallahu 'alaihi wasallam, maka aku tidak akan meninggalkanya karena sesuatu apapun, dan Allah Tabaraka Wa Ta'ala berfirman: '(Ayat mana saja yang kami nasakhkan, atau kami jadikan (manusia) lupa kepadanya..) ' (QS. Al Baqarah: 106)."},"2895":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ فِي سَنَةِ سِتٍّ وَعِشْرِينَ وَمِائَتَيْنِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَخَطَبَنَا عُمَرُ رَضِيَ اللَّهُ عَنْهُ عَلَى مِنْبَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ أَقْضَانَا وَأُبَيٌّ رَضِيَ اللَّهُ عَنْهُ أَقْرَؤُنَا وَإِنَّا لَنَدَعُ مِنْ قَوْلِ أُبَيٍّ شَيْئًا وَإِنَّ أُبَيًّا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْيَاءَ وَأُبَيٌّ يَقُولُ لَا أَدَعُ مَا سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ نَزَلَ بَعْدَ أُبَيٍّ كِتَابٌ","id":"Telah menceritakan kepada kami Abdullah, telah menceritakan kepadaku [Suwaid bin Sa'id] di tahun dua ratus dua puluh enam, telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \" [Umar] radliallahu 'anhu berkhutbah di mimbar Rasulullah shallallahu 'alaihi wasallam, ia mengatakan, \"Ali? radliallahu 'anhu adalah orang yang paling paham dengan hukum di antara kami dan Ubay? radliallahu 'anhu adalah orang yang paling pandai dalam membaca Al-Qur'an di antara kami, sementara kami banyak meninggalkan qira`ah Ubay. Dan [Ubay] telah mengambil sesuatu (qira`ah) dari Rasulullah Shallallahu 'alaihi wa.\" Ubay pernah berkata, \"Aku tidak akan meninggalkanya apa yang pernah aku dengar dari Rasulullah shallallahu 'alaihi wasallam.\" padahal setelah Ubay telah turun ayat.\""},"2896":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ أَخْبَرَنَا أَبِي أَخْبَرَنِي أَبُو أَيُّوبَ أَنَّ أُبَيًّا حَدَّثَهُ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ الرَّجُلُ يُجَامِعُ أَهْلَهُ فَلَا يُنْزِلُ قَالَ يَغْسِلُ مَا مَسَّ الْمَرْأَةَ مِنْهُ وَيَتَوَضَّأُ وَيُصَلِّيحَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أَبِي أَيُّوبَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah mengkabarkan kepada kami [Hisyam bin Urwah] telah mengabarkan kepada kami [Ayahku] telah mengkabarkan kepadaku [Abu Ayyub] bahwa [Ubay] menceritakan padanya, ia berkata, \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, aku katakan, 'Seorang laki-laki mensetubuhi isterinya, namun ia tidak orgasme? ' beliau menjawab: \"Hendaknya Ia mencuci apa yang bersentuhan dengan istrinya, lalu wudlu dan shalat.'\" Telah menceritakan kepada kami Abdullah ia berkata, telah menceritakan kepadaku Ayahku ia berkata, telah menceritakan kepada kami [Abu Mu'awiyah] ia berkata, telah menceritakan kepada kami [Hisyam bin Urwah] dari [Ayahnya] dari [Abu Ayyub] dari [Ubay bin Ka'ab] berkata, \"Aku bertanya pada Rasulullah shallallahu 'alaihi wasallam… lalu ia sebutkan hadits tersebut.\""},"2897":{"ar":"قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ حَدَّثَنِي أَبِي عَنْ الْمَلِيِّ عَنْ الْمَلِيِّ يَعْنِي بِقَوْلِهِ الْمَلِيِّ عَنْ الْمَلِيِّ أَبَا أَيُّوبَ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يَأْتِي أَهْلَهُ ثُمَّ لَا يُنْزِلُ يَغْسِلُ ذَكَرَهُ وَيَتَوَضَّأُقَالَ عَبْد اللَّهِ قَالَ أَبِي الْمَلِيُّ عَنْ الْمَلِيِّ ثِقَةٌ عَنْ ثِقَةٍ","id":"Ia berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] ia berkata, telah menceritakan kepada kami [Syu'bah] dari [Hisyam bin Urwah] ia berkata, telah menceritakan kepadaku [Ayahku] -dari Al Mali dari Al Mali, yaitu dengan perkataannya Al Mali dari Al Mali-, [Abu Ayyub] dari [Ubai bin Ka'ab] dari Rasulullah shallallahu 'alaihi wasallam tentang seorang laki-laki yang mendatangi isterinya namun tidak keluar air mani: \"Hendaklah ia cuci kemaluannya, lalu berwudlu.\" Abdullah berkata, Ayahku berkata, \"Al Mali dari Al Mali adalah dari seorang tsiqah kepada orang yang tsiqah.\""},"2898":{"ar":"قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَ بَلَغَنِي عَنْ أَبِي أَيُّوبَ بْنِ زَيْدٍ حَدِيثٌ وَهُوَ بِأَرْضِ الرُّومِ قَالَ فَلَقِيتُ أَبَا أَيُّوبَ فَحَدَّثَنِي عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَامَعَ الرَّجُلُ امْرَأَتَهُ ثُمَّ أَكْسَلَ فَلْيَغْسِلْ مَا أَصَابَ الْمَرْأَةَ مِنْهُ ثُمَّ لِيَتَوَضَّأْ","id":"Ia berkata, telah menceritakan kepadaku [Ubaidullah bin Umar Al Qawariri] ia berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam bin Urwah] dari [Ayahnya] berkata; telah sampai kepadaku dari [Abu Ayyub bin Zaid] sebuah hadits -sementara ia sedang berada di Romawi- ia berkata, \"Aku bertemu Abu Ayyub ia menceritakan kepadaku dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang laki-laki mensetubuhi isterinya kemudian malas (tidak melanjutkannya), maka hendaklah ia mencuci apa yang bersentuhan dengan isterinya (kemaluan) lalu berwudlu.\""},"2899":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسٍ عَنْ عُبَادَةَ أَنَّ أُبَيَّ بْنَ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُنْزِلَ الْقُرْآنُ عَلَى سَبْعَةِ أَحْرُفٍ","id":"Ia berkata, telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad] ia berkata, telah mengabarkan kepada kami [Humaid] dari [Anas] dari [Ubadah] bahwa [Ubay bin Ka'b] berkata, \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Al Qur'an diturunkan dengan tujuh huruf.\""},"2900":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّ أُبَيَّ بْنَ كَعْبٍ قَالَأَقْرَأَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آيَةً وَأَقْرَأَهَا آخَرَ غَيْرَ قِرَاءَةِ أُبَيٍّ فَقُلْتُ مَنْ أَقْرَأَكَهَا قَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ وَاللَّهِ لَقَدْ أَقْرَأَنِيهَا كَذَا وَكَذَا قَالَ أُبَيٌّ فَمَا تَخَلَّجَ فِي نَفْسِي مِنْ الْإِسْلَامِ مَا تَخَلَّجَ يَوْمَئِذٍ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ يَا رَسُولَ اللَّهِ أَلَمْ تُقْرِئْنِي آيَةَ كَذَا وَكَذَا قَالَ بَلَى قَالَ فَإِنَّ هَذَا يَدَّعِي أَنَّكَ أَقْرَأْتَهُ كَذَا وَكَذَا فَضَرَبَ بِيَدِهِ فِي صَدْرِي فَذَهَبَ ذَاكَ فَمَا وَجَدْتُ مِنْهُ شَيْئًا بَعْدُ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي جِبْرِيلُ وَمِيكَائِيلُ عَلَيْهِمَا السَّلَام فَقَالَ جِبْرِيلُ اقْرَأْ الْقُرْآنَ عَلَى حَرْفٍ فَقَالَ مِيكَائِيلُ اسْتَزِدْهُ قَالَ اقْرَأْهُ عَلَى حَرْفَيْنِ قَالَ اسْتَزِدْهُ حَتَّى بَلَغَ سَبْعَةَ أَحْرُفٍ قَالَ كُلٌّ شَافٍ كَافٍحَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ أَنَّ أُبَيًّا قَالَ مَا حَكَّ فِي صَدْرِي شَيْءٌ مُنْذُ أَسْلَمْتُ إِلَّا أَنِّي قَرَأْتُ آيَةً فَذَكَرَ الْحَدِيثَ وَلَمْ يَذْكُرْ فِيهِ عُبَادَةَ","id":"Perawi berkata, telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad] ia berkata, telah mengkabarkan kepada kami [Humaid bin Anas] dari [Anas] dari [Ubadah bin Shamit] bahwa [Ubay bin Ka'b] berkata, \"Rasulullah shallallahu 'alaihi wasallam telah membacakan ayat kepadaku, dan aku (Ubadah) membacakannya kepada orang lain dengan selain bacaaan Ubay. Maka aku bertanya padanya, \"Siapa yang membacakannya padamu?\" Ubay menjawab, \"Rasulullah shallallahu 'alaihi wasallam yang membacakannya padaku.\" Aku berkata lagi, \"Demi Allah, beliau telah membacakannya kepadaku begini dan begitu.\" Ubay lantas menyaut, \"Aku tidak pernah merasakan keraguan dalam Islam semisal saat hari itu, maka aku pun datang menemui Nabi shallallahu 'alaihi wasallam, aku katakan, \"Wahai Rasulullah, bukankah engkau telah membacakan ayat ini kepadaku begini dan begitu?\" Beliau menjawab: \"Ya.\" Ubay berkata, \"Orang ini mengatakan bahwa engkau juga telah membacakannya begini dan begitu!\" Beliau lalu memukulkan tangannya ke dadaku, hingga aku tidak lagi mendapati karaguan dalam hatiku setelah itu.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Jibril dan Mikail Alaihimassalam mendatangiku. Jibril berkata, 'Bacalah Al Qur`an dengan satu huruf! ' lalu Mika`il berkata, 'Mintalah tambahan, ' lalu Jibril berkata lagi, 'Bacalah dengan dua huruf! ' Mika`il berkata lagi, 'Mintalah tambahan, ' hingga menjadi tujuh huruf. Maka setiap bacaan adalah sempurna dan mencukupi.\" Telah menceritakan kepada kami Abdullah ia berkata, telah menceritakan kepadaku Ayahku Ia berkata, telah menceritakan kepadaku [Yahya bin Sa'id] dari [Humaid] dari [Anas] bahwa [Ubay] berkata, \"Tiada yang menyempitkan dadaku semenjak aku masuk Islam kecuali aku membaca ayat.. lalu ia sebutkan hadits tersebut, namun tidak disebutkan dalam hadits tesebut nama Ubadah.\""},"2901":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَهَذَا لَفْظُ حَدِيثِ ابْنِ نُمَيْرٍ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنِ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَعْقُوبَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ أُبَيِّ بْنِ كَعْبٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِي التَّوْرَاةِ وَلَا فِي الْإِنْجِيلِ مِثْلَ أُمِّ الْقُرْآنِ وَهِيَ السَّبْعُ الْمَثَانِي وَهِيَ مَقْسُومَةٌ بَيْنِي وَبَيْنَ عَبْدِي وَلِعَبْدِي مَا سَأَلَ","id":"Abdullah berkata, telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Abdullah bin Numair] dan ini adalah lafadz Ibnu Numair, Ia berkata, telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] dari [Ala` bin Abdurrahman bin Ya'qub] dari [Ayahnya] dari [Abu Hurairah] dari [Ubay bin Ka'b] radhiallahu Ta'ala 'anhuma, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza Wa Jalla tidak menurunkan dalam Taurat maupun Injil seperti Ummul Qur'an, ia adalah As Sab'ul Matsani (tujuh ayat yang dibaca berulang-ulang), ia terbagi untuk-Ku dan untuk hamba-Ku, dan bagi hamba-Ku ia akan mendapat apa yang ia minta.\""},"2902":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنِي أَبُو مَعْمَرٍ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُعَلِّمُكَ سُورَةً مَا أُنْزِلَ فِي التَّوْرَاةِ وَلَا فِي الزَّبُورِ وَلَا فِي الْإِنْجِيلِ وَلَا فِي الْقُرْآنِ مِثْلُهَا قُلْتُ بَلَى قَالَ فَإِنِّي أَرْجُو أَنْ لَا أَخْرُجَ مِنْ ذَلِكَ الْبَابِ حَتَّى تَعْلَمَهَا ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُمْتُ مَعَهُ فَأَخَذَ بِيَدِي فَجَعَلَ يُحَدِّثُنِي حَتَّى بَلَغَ قُرْبَ الْبَابِ قَالَ فَذَكَّرْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ السُّورَةَ الَّتِي قُلْتَ لِي قَالَ فَكَيْفَ تَقْرَأُ إِذَا قُمْتَ تُصَلِّي فَقَرَأَ بِفَاتِحَةِ الْكِتَابِ قَالَ هِيَ هِيَ وَهِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُوتِيتُ بَعْدُقَالَ عَبْد اللَّهِ سَأَلْتُ أَبِي قَالَ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ وَسُهَيْلِ بْنِ أَبِي صَالِحٍ فَقَدَّمَ الْعَلَاءَ عَلَى سُهَيْلٍ وَقَالَ لَمْ أَسْمَعْ أَحَدًا ذَكَرَ الْعَلَاءَ بِسُوءٍ و قَالَ أَبُو عَبْد الرَّحْمَنِ وَأَبُو صَالِحٍ أَحَبُّ إِلَيَّ مِنْ الْعَلَاءِ","id":"Abdullah berkata, telah menceritakan kepadaku [Abu Ma'mar] ia berkata, telah menceritakan kepada kami [Abu Usamah] dari [Abdul Hamid bin Ja'far] dari [Ala` bin Abdurrahman] dari [Ayahnya] dari [Abu Hurairah] dari [Ubay bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku ajarkan kepadamu sebuah surat yang tidak diturunkan dalam At Taurat, atau dalam Zabur, atau dalam Injil, atau dalam Al-Qur'an yang semisal itu?\" Aku menjawab, \"Tentu.\" beliau bersabda: \"Saya ingin sebelum keluar dari pintu itu kamu telah mengetahuinya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri dan akupun berdiri bersamanya, lalu beliau memegang tanganku dan berbicara denganku hingga mendekati pintu.\" Ubay berkata, \"Lantas aku mengingatkan beliau, aku katakan, \"Wahai Rasulullah, apa surat yang engkau katakan kepada saya?\" Beliau menjawab: \"Apa yang kamu baca jika kamu berdiri untuk shalat?\" Kemudian beliau membaca Fatihatul Kitab (surat Al fatihah) seraya bersabda: \"Itulah yang aku maksud, ia adalah As Sab'ul Matsani (tujuh ayat yang dibaca berulang-ulang) dan Al Qur'an yang agung yang telah diberikan kepadaku.\" Abdullah berkata, \"Aku bertanya kepada bapakku, dia menjawab, \"Dari Al 'Ala bin 'Abdurrahman dan Suhail bin Abu Shalih. Ia mendahulukan Al 'Ala ketimbnag Suhail, lalu ia berkata, \"Saya belum pernah mendengar seseorang menyebutkan Al 'Ala dengan sesuatu hal yang jelek.\" Abu Abdurrahman berkata, \"Aku lebih menyukai Abu Shalih daripada Al 'Ala.\""},"2903":{"ar":"قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا زُهَيْرٌ وَابْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَعْمَرِ بْنِ أَبِي حَبِيبَةَ عَنْ عُبَيْدِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ أَبِيهِ قَالَ زُهَيْرٌ فِي حَدِيثِهِ رِفَاعَةُ بْنُ رَافِعٍ وَكَانَ عَقَبِيًّا بَدْرِيًّا قَالَكُنْتُ عِنْدَ عُمَرَ فَقِيلَ لَهُ إِنَّ زَيْدَ بْنَ ثَابِتٍ يُفْتِي النَّاسَ فِي الْمَسْجِدِ قَالَ زُهَيْرٌ فِي حَدِيثِهِ النَّاسَ بِرَأْيِهِ فِي الَّذِي يُجَامِعُ وَلَا يُنْزِلُ فَقَالَ أَعْجِلْ بِهِ فَأُتِيَ بِهِ فَقَالَ يَا عَدُوَّ نَفْسِهِ أَوَقَدْ بَلَغْتَ أَنْ تُفْتِيَ النَّاسَ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَأْيِكَ قَالَ مَا فَعَلْتُ وَلَكِنْ حَدَّثَنِي عُمُومَتِي عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّ عُمُومَتِكَ قَالَ أُبَيُّ بْنُ كَعْبٍ قَالَ زُهَيْرٌ وَأَبُو أَيُّوبَ وَرِفَاعَةُ بْنُ رَافِعٍ فَالْتَفَتُّ إِلَى مَا يَقُولُ هَذَا الْفَتَى وَقَالَ زُهَيْرٌ مَا يَقُولُ هَذَا الْغُلَامُ فَقُلْتُ كُنَّا نَفْعَلُهُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَسَأَلْتُمْ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنَّا نَفْعَلُهُ عَلَى عَهْدِهِ فَلَمْ نَغْتَسِلْ قَالَ فَجَمَعَ النَّاسَ وَاتَّفَقَ النَّاسُ عَلَى أَنَّ الْمَاءَ لَا يَكُونُ إِلَّا مِنْ الْمَاءِ إِلَّا رَجُلَيْنِ عَلِيَّ بْنَ أَبِي طَالِبٍ وَمُعَاذَ بْنَ جَبَلٍ قَالَا إِذَا جَاوَزَ الْخِتَانُ الْخِتَانَ فَقَدْ وَجَبَ الْغُسْلُ قَالَ فَقَالَ عَلِيٌّ يَا أَمِيرَ الْمُؤْمِنِينَ إِنَّ أَعْلَمَ النَّاسِ بِهَذَا أَزْوَاجُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ إِلَى حَفْصَةَ فَقَالَتْ لَا عِلْمَ لِي فَأَرْسَلَ إِلَى عَائِشَةَ فَقَالَتْ إِذَا جَاوَزَ الْخِتَانُ الْخِتَانَ وَجَبَ الْغُسْلُقَالَ فَتَحَطَّمَ عُمَرُ يَعْنِي تَغَيَّظَ ثُمَّ قَالَ لَا يَبْلُغُنِي أَنَّ أَحَدًا فَعَلَهُ وَلَا يَغْسِلُ إِلَّا أَنْهَكْتُهُ عُقُوبَةً حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ يَزِيدَ بْنَ أَبِي حَبِيبٍ عَنْ مَعْمَرِ بْنِ حَبِيبَةَ عَنْ عُبَيْدِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ أَبِيهِ فَذَكَرَ نَحْوَهُ وَمَعْنَاهُ","id":"Ia berkata, telah menceritakan kepada kami [Yahya bin Adam] dia berkata, telah bercerita kepada kami [Zuhair] dan [Ibnu Idris] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Ma'mar bin Abu Habibah] dari [Ubaid bin Rifa'ah bin Rafi'] dari [Bapaknya], [Zuhair] menyebutkan dalam haditsnya- [Rifa'ah bin Rafi'] dan dia termasuk orang yang ikut dalam Bai'at Aqabah dan perang Badar- dia berkata, \"Ketika kami berada di sisi Umar diberitakanlah kepadanya bahwa [Zaid bin Tsabit] berfatwa kepada orang-orang di masjid.\" [Zuhair] menyebutkan dalam haditsnya, \"(Zaid) Memberi fatwa kepada orang-orang dengan dasar pikirannya tentang seorang laki-laki yang bersetubuh namun tidak keluar air mani.\" Lalu Umar berkata, \"Segera temui dia!\" Maka Zaid dipanggil dan dibawa ke hadapan Umar, Umar berkata, \"Wahai orang yang memusuhi dirinya sendiri, apakah kamu layak berfatwa kepada manusia di masjid Rasulullah shallallahu 'alaihi wasallam dengan pikiranmu?\" Zaid menjawab, \"Aku tidak melakukan demikian, hanya saja aku telah mendapatkan cerita dari pamanku yang telah mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\" Umar bertanya, \"Siapa dia?\" Zaid menjawab, \" [Ubay bin Ka'b].\" [Zuhair], [Abu Ayyub] dan [Rifa'ah bin Rafi'] lalu berkata, \"Aku lalu memperhatikan dengan apa yang dikatakan oleh pemuda ini.\" [Zuhair] menyebutkan, \"Apa yang dikatakan oleh anak laki-laki ini.\" Ubay berkata, \"Kami melakukannya pada zaman Rasulullah shallallahu 'alaihi wasallam.\" Zaid berkata, \"Kemudian kalian bertanya tentang hal itu kepada Rasulullah shallallahu 'alaihi wasallam?\" Ubay menjawab, \"Kami melakukannya pada zaman Rasulullah shallallahu 'alaihi wasallam dan kami tidak mandi, \" maka orang orang berkumpul dan bersepakat bahwa air itu karena adanya (tidak mandi jika tidak ada mani) kecuali dua orang yang tidak sepakat; Ali bin Abu Thalib dan Mu'adz bin Jabal. Keduanya mengatakan, \"Apabila dua khitan telah bertemu maka wajib mandi.\" Zaid berkata, \"Maka Ali berkata, \"Wahai Amirul Mukminin, sesungguhnya orang yang paling tahu tentang masalah ini adalah para isteri Rasulullah shallallahu 'alaihi wasallam.\" Lalu Umar pun mengutus seseorang untuk bertanya kepada Hafshah, lalu Hafshah berkata, \"Saya tidak tahu tentang hal ini.\" Uamr lalu mengutus seseorang kepada [A'isyah], dan dia berkata, \"Apabila dua khitan bertemu maka wajib mandi.\" Zaid berkata, \"Maka meluap-luaplah kemarahan Umar seraya berkata, \"Tidaklah sampai berita kepadaku bahwa seseorang melakukan persetubuhan namun ia tidak mandi kecuali aku pasti akan menghukumnya dengan hukuman yang berat!\" Telah bercerita kepada kami Abdullah dia berkata, telah bercerita kepada kami [Abu Bakar bin Abu Syaibah] dia berkata, telah bercerita kepada kami [Abdul A'la bin Abdul A'la] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Ma'mar bin Habibah] dari [Ubaid bin Rifa'ah bin Rafi'] dari [Bapaknya] kemudian dia menyebutkan hadits yang semakna dengannya.\""},"2904":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا رَجُلٌ سَمَّاهُ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ اللَّهِ الْأَشْعَرِيُّ حَدَّثَنَا عِيسَى بْنُ جَارِيَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أُبَيِّ بْنِ كَعْبٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُمَا قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ عَمِلْتُ اللَّيْلَةَ عَمَلًا قَالَ مَا هُوَ قَالَ نِسْوَةٌ مَعِي فِي الدَّارِ قُلْنَ لِي إِنَّكَ تَقْرَأُ وَلَا نَقْرَأُ فَصَلِّ بِنَا فَصَلَّيْتُ ثَمَانِيًا وَالْوَتْرَ قَالَ فَسَكَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَرَأَيْنَا أَنَّ سُكُوتَهُ رِضًا بِمَا كَانَ","id":"Telah menceritakan kepada kami Abdullah, telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah Abdullah bin Muhammad] telah menceritakan kepada kami [seseorang] yang ia sebutkan, telah menceritakan kepada kami [Ya'qub bin Abdullah Al Asy'ari] telah menceritakan kepada kami [Isa bin Jariyah] dari [Jabir bin Abdullah] dari [Ubay bin Ka'b] radliallahu 'anhu, ia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, aku tadi malam telah melakukan sesuatu.\" Nabi bertanya; \"Apa itu?\" Laki-laki itu menjawab, \"Aku bersama beberapa wanita dalam rumah, mereka mengatakan kepadaku, 'Sesungguhnya kamu bisa membaca sedang kami tidak membaca, maka shalatlah bersama kami.' Kemudian aku shalat delapan rakaat beserta witir.\" Ubay berkata, \"Kemudian Nabi shallallahu 'alaihi wasallam diam, dan kami menganggap diamnya adalah tanda bahwa beliau menyetujuinya.\""},"2905":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا حَجَّاجُ بْنُ يُوسُفَ حَدَّثَنَا شَبَابَةُ عَنْ شُعْبَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَوَاهُ","id":"Telah menceritakan kepada kami Abdullah, telah menceritakan kepada kami [Hajjaj bin yusuf] telah menceritakan kepada kami [Syababah] dari [Syu'bah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari [Ubay bin Ka'b], bahwa Nabi shallallahu 'alaihi wasallam mengobatinya dengan kay (menyulut dengan besi yang telah dipanaskan).\""},"2906":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ قَالَ سَهْلٌ الْأَنْصَارِيُّ وَكَانَ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ ابْنُ خَمْسَ عَشْرَةَ فِي زَمَانِهِ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُمَاأَنَّ الْفُتْيَا الَّتِي كَانُوا يَقُولُونَ الْمَاءُ مِنْ الْمَاءِ رُخْصَةٌ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ بِهَا فِي أَوَّلِ الْإِسْلَامِ ثُمَّ أَمَرَنَا بِالِاغْتِسَالِ بَعْدَهَا","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengkabarkan kepada kami [Yunus] dari [Az Zuhri] berkata, [Sahal Al Anshari] berkata -ia pernah berjumpa dengan Nabi shallallahu 'alaihi wasallam saat umurnya lima belas tahun-, telah menceritakan kepadaku [Ubay bin ka'b] radliallahu 'anhu, ia menyebutkan bahwa fatwa 'air (mandi) itu karena adanya air (mani) ' yang mereka katakan adalah sebuah keringanan. Keringanan itu Rasulullah shallallahu 'alaihi wasallam berikan pada masa awal-awal Islam, setelah itu beliau perintahkan agar kami mandi.\""},"2907":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ أَخْبَرَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ أَخْبَرَنِي يُونُسُ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ الْأَنْصَارِيِّ وَقَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ ابْنُ خَمْسَ عَشْرَةَ سَنَةً قَالَ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍأَنَّ الْفُتْيَا الَّتِي كَانُوا يُفْتُونَ بِهَا فِي قَوْلِهِمْ الْمَاءُ مِنْ الْمَاءِ رُخْصَةٌ كَانَ أُرْخِصَ بِهَا فِي أَوَّلِ الْإِسْلَامِ ثُمَّ أُمِرْنَا بِالِاغْتِسَالِ بَعْدَهَاحَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَهْلٍ عَنْ أُبَيٍّ نَحْوَهُ قَالَ ابْنُ الْمُبَارَكِ فَأَخْبَرَنِي مَعْمَرٌ بِهَذَا الْإِسْنَادِ نَحْوَهُ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ قَالَ ابْنُ شِهَابٍ قَالَ سَهْلُ بْنُ سَعْدٍ وَكَانَ قَدْ بَلَغَ خَمْسَ عَشْرَةَ سَنَةً حِينَ تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعَ مِنْهُ أَخْبَرَنِي أُبَيُّ بْنُ كَعْبٍ وَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Ishaq] telah mengkabarkan kepada kami [Abdullah bin Mubarak] telah mengkabarkan kepadaku [Yunus] dari [Az Zuhri] dari [Sahal bin Sa'd Al Anshaari] -ia pernah bertemu Nabi shallallahu 'alaihi wasallam saat umurnya lima belas tahun- ia berkata, \" [Ubay bin Ka'b] menceritakan kepadaku bahwa Fatwa 'air (mandi) itu karena adanya air (mani) ' yang biasa mereka katakan adalah sebuah keringanan yang diberikan pada masa awal Islam. Setelah itu kami diperintahkan untuk mandi besar.\" Telah menceritakan kepada kami [Khalaf bin Walid] telah menceritakan kepada kami [Ibnu Mubarak] dari [Yunus] dari [Az Zuhri] dari [Sahl] dari [Ubay] seperti itu. [Ibnu Mubarak] berkata, \" [Ma'mar] mengabarkan kepadaku dengan sanad ini seperti hadits tersebut.\" Telah menceritakan kepada kami [Muhammad bin Bakr] telah mengkabarkan kepada kami [Ibnu Juraij] ia berkata, [Ibnu Syihab] berkata, [Sahl bin Sa'd] berkata -Ketika Rasulullah shallallahu 'alaihi wasallam meninggal, ketika itu umurnya lima belas tahun, dan ia pernah mendengar darinya-, \" [Ubay bin Ka'b] mengabarkan kepadaku…. lalu ia menyebutkan hadits seperti itu.\""},"2908":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ سَهْلُ بْنُ سَعْدٍ الْأَنْصَارِيُّ وَكَانَ قَدْ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعَ مِنْهُ وَذَكَرَ أَنَّهُ ابْنُ خَمْسَ عَشْرَةَ سَنَةً ثُمَّ تُوُفِّيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍأَنَّ الْفُتْيَا الَّتِي كَانُوا يُفْتُونَ بِهَا رُخْصَةٌ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِيهَا فِي أَوَّلِ الْإِسْلَامِ ثُمَّ أَمَرَنَا بِالِاغْتِسَالِ بَعْدُ","id":"Telah menceritakan kepada kami [Abu Yaman] telah mengkabarkan kepada kami [Syu'aib] dari [Az Zuhri] berkata, [Sahl bin Sa'd Al Anshari] berkata -ia pernah melihat dan mendengar langsung dari Nabi shallallahu 'alaihi wasallam di umurnya yang kelima belas, lalu Rasulullah shallallahu 'alaihi wasallam wafat-, telah menceritakan kepadaku [Ubay bin Ka'b], bahwa 'air (mandi) itu karena adanya air (mani) ' yang selalu mereka bicarakan adalah sebuah keringanan, Rasulullah shallallahu 'alaihi wasallam memberikan keringanan itu di awal-awal Islam, setelah masa itu beliau menyuruh kami untuk mandi.\""},"2909":{"ar":"حَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ حَدَّثَنَا رِشْدِينُ حَدَّثَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي بَعْضُ مَنْ أَرْضَى عَنْ سَهْلِ بْنِ سَعْدٍ أَنَّ أُبَيًّا حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَهَا رُخْصَةً لِلْمُؤْمِنِينَ لِقِلَّةِ ثِيَابِهِمْ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهَا بَعْدُ يَعْنِي قَوْلَهُمْ الْمَاءُ مِنْ الْمَاءِ","id":"Telah menceritakan kepada kami [Yahya bin Ghailan] telah menceritakan kepada kami [Risydin] telah menceritakan kepadaku [Amru bin Harits] dari [Ibnu Syihab] telah menceritakan kepadaku [sebagian] yang telah ridla (para sahabat) dari [Sahal bin Sa'd] bahwa [Ubay] menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam memberikan keringanannya (tidak wajib mandi) bagi kaum mukminin karena mereka kekurangan pakaian. Setelah itu Rasulullah shallallahu 'alaihi wasallam melarangnya, yaitu perkataan mereka bahwa air (mandi) itu karena adanya air (mani).\""},"2910":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ حَدَّثَنِي الْأَسْلَمِيُّ يَعْنِي عَبْدَ اللَّهِ بْنَ عَامِرٍ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ سَهْلِ بْنِ سَعْدٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْمَسْجِدِ الَّذِي أُسِّسَ عَلَى التَّقْوَى فَقَالَ هُوَ مَسْجِدِي","id":"Telah menceritakan kepada kami [Abdullah bin Harits] telah menceritakan kepadaku [Al Aslami] -yaitu Abdullah bin Amir- dari [Imran bin Abu Anas] dari [Sahl bin Sa'd] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang masjid yang dibangun di atas dasar takwa, kemudian beliau bersabda: \"Itu adalah masjidku (masjid Nabawi).\""},"2911":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَامِرٍ الْأَسْلَمِيُّ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ سَهْلِ بْنِ سَعْدٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَسْجِدُ الَّذِي أُسِّسَ عَلَى التَّقْوَى مَسْجِدِي هَذَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abdullah bin Amir Al salami] dari [Imran bin Abu Anas] dari [Sahl bin Sa'd] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Masjid yang dibangun di atas dasar takwa adalah masjidku (masjid Nabawi) ini.\""},"2912":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ أَخْبَرَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنِ الْمُثَنَّى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أُبَيِّ بْنِ كَعْبٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُمَا قَالَقُلْتُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَأُولَاتُ الْأَحْمَالِ أَجَلُهُنَّ أَنْ يَضَعْنَ حَمْلَهُنَّ }لِلْمُطَلَّقَةِ ثَلَاثًا وَلِلْمُتَوَفَّى عَنْهَا قَالَ هِيَ لِلْمُطَلَّقَةِ ثَلَاثًا وَلِلْمُتَوَفَّى عَنْهَا","id":"Telah menceritakan kepada kami Abdullah, telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah mengkabarkan kepada kami [Abdul Wahab Ats Tsaqafi] dari [Mutsanna] dari [Amru bin Syu'aib] dari [Ayahnya] dari [Abdullah bin Amru] dari [Ubay bin Ka'b] radliallahu 'anhu, ia berkata, \"Aku bertanya kepada Nabi shallallahu 'alaihi wasallam tentang ayat: '(dan perempuan-perempuan yang hamil, waktu iddah mereka itu ialah sampai mereka melahirkan kandungannya) ' (QS. Ath Thalaaq: 4), bagi wanita yang dicerai adalah dengan tiga kali haid, lalu bagaimana dengan yang ditinggal mati suaminya?\" Nabi menjawab: \"Masa iddah dengan tiga kali haid itu berlaku bagi wanita yang dicerai dan wanita yang ditinggal mati suaminya.\""},"2913":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ وَمُحَمَّدُ بْنُ مُصْعَبٍ الْقُرْقُسَانِيُّ قَالَ الْوَلِيدُ حَدَّثَنِي الْأَوْزَاعِيُّ وَقَالَ مُحَمَّدٌ حَدَّثَنَا الْأَوْزَاعِيُّ أَنَّ الزُّهْرِيَّ حَدَّثَهُ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّهُ تَمَارَى هُوَ وَالْحُرُّ بْنُ قَيْسِ بْنِ حِصْنٍ الْفَزَارِيُّ فِي صَاحِبِ مُوسَى عَلَيْهِ السَّلَام الَّذِي سَأَلَ السَّبِيلَ إِلَى لُقِيِّهِ فَقَالَ ابْنُ عَبَّاسٍ هُوَ خَضِرٌ إِذْ مَرَّ بِهِمَا أُبَيُّ بْنُ كَعْبٍ فَنَادَاهُ ابْنُ عَبَّاسٍ فَقَالَ إِنِّي تَمَارَيْتُ أَنَا وَصَاحِبِي هَذَا فِي صَاحِبِ مُوسَى عَلَيْهِ السَّلَام الَّذِي سَأَلَ السَّبِيلَ إِلَى لُقِيِّهِ فَهَلْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ شَأْنَهُ قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَا مُوسَى عَلَيْهِ السَّلَام فِي مَلَإٍ مِنْ بَنِي إِسْرَائِيلَ إِذْ قَامَ إِلَيْهِ رَجُلٌ فَقَالَ هَلْ تَعْلَمُ أَحَدًا أَعْلَمَ مِنْكَ قَالَ لَا قَالَ فَأَوْحَى اللَّهُ تَبَارَكَ وَتَعَالَى إِلَيْهِ عَبْدُنَا خَضِرٌ فَسَأَلَ مُوسَى عَلَيْهِ السَّلَام السَّبِيلَ إِلَى لُقِيِّهِ وَجَعَلَ اللَّهُ تَبَارَكَ وَتَعَالَى لَهُ الْحُوتَ آيَةً فَقِيلَ لَهُ إِذَا فَقَدْتَ الْحُوتَ فَارْجِعْ فَإِنَّكَ سَتَلْقَاهُ قَالَ ابْنُ مُصْعَبٍ فِي حَدِيثِهِ فَنَزَلَ مَنْزِلًا فَقَالَ مُوسَى عَلَيْهِ السَّلَام لِفَتَاهُ{ آتِنَا غَدَاءَنَا لَقَدْ لَقِينَا مِنْ سَفَرِنَا هَذَا نَصَبًا }فَعِنْدَ ذَلِكَ فَقَدَ الْحُوتَ{ فَارْتَدَّا عَلَى آثَارِهِمَا قَصَصًا }فَجَعَلَ مُوسَى عَلَيْهِ السَّلَام يَتْبَعُ أَثَرَ الْحُوتِ فِي الْبَحْرِ قَالَ فَكَانَ مِنْ شَأْنِهِمَا مَا قَصَّ اللَّهُ تَبَارَكَ وَتَعَالَى فِي كِتَابهِ","id":"Telah menceritakan kepada kami [Walid bin Muslim] dan [Muhammad bin Mush'ab Al Qurqusani], Walid berkata, telah menceritakan kepadaku Al Auza'i, dan Muhammad berkata, telah menceritakan kepada kami [Al Auza'i] bahwa [Az Zuhri] menceritakan kepadanya dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas], bahwa dia dan Al Hurr bin Qais bin Hisn Al Fazari berdebat tentang sahabat Musa Alaihis Salam yang bertanya tentang jalan menuju tempat pertemuannya. Ibnu Abbas berkata, \"Orang itu adalah Hidlir.\" Lalu lewatlah [Ubay bin Ka'b] di depan keduanya, Ibnu Abbas lalu memanggilnya dan berkata, \"Sesungguhnya aku berselisih pendapat dengan sahabatku ini, siapa kawan Musa yang bertanya tentang jalan menuju tempat pertemuannya? ' Apakah engkau pernah mendengar Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang hal itu?\" Ubay bin Ka'b menjawab, \"Ya, saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika Musa duduk bersama beberapa orang Bani Israil, tiba-tiba seorang laki-laki datang dan bertanya kepadanya (Musa), 'Adakah seseorang yang lebih pandai daripada kamu? ' Musa menjawab, 'Tidak.\" Rasulullah melanjutkan: \"Maka Allah menurunkan wahyu kepada Musa, \"Ada, yaitu hamba Kami Khidlir.\" Musa lalu bertanya kepada (Allah) jalan menuju tempat pertemuannya. Maka Allah pun menjadikan ikan sebagai sebuah tanda baginya. Lalu dikatakan kepada Musa, \"Jika ikan itu hilang darimu, maka kembalilah (ke tempat di mana ikan itu hilang), karena engkau akan bertemu dengannya (Khidlir).\" Ibnu Mush'ab menyebutkan dalam haditsnya, \"Kemudian Musa singgah pada suatu tempat, lalu '(berkatalah Musa kepada muridnya: \"Bawalah kemari makanan kita; sesungguhnya kita telah merasa letih karena perjalanan kita ini) ' (Qs. Al Kahfi: 62). Maka pada saat itulah ikan yang ia bawa hilang, '(Lalu keduanya kembali, mengikuti jejak mereka semula) ' (Qs. Al Kahfi: 64). Maka Musa Alihis Salam mengikuti jejak ikan Hiu di lautan.\" Rasulullah bersabda, \"Maka itulah cerita keduanya yang telah Allah Tabaraka Wa Ta'ala ceritakan dalam kitab-Nya.\""},"2914":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ أَبِي إِسْحَاقَ الشَّيْبَانِيِّ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ رَجُلٌ إِلَى عُمَرَ يَسْأَلُهُ فَجَعَلَ يَنْظُرُ إِلَى رَأْسِهِ مَرَّةً وَإِلَى رِجْلَيْهِ أُخْرَى هَلْ يَرَى عَلَيْهِ مِنْ الْبُؤْسِ شَيْئًا ثُمَّ قَالَ لَهُ عُمَرُ كَمْ مَالُكَ قَالَ أَرْبَعُونَ مِنْ الْإِبِلِ قَالَ ابْنُ عَبَّاسٍ فَقُلْتُ صَدَقَ اللَّهُ وَرَسُولُهُ لَوْ كَانَ لِابْنِ آدَمَ وَادِيَانِ مِنْ ذَهَبً لَابْتَغَى الثَّالِثَ وَلَا يَمْلَأُ جَوْفَ ابْنِ آدَمَ إِلَّا التُّرَابُ وَيَتُوبُ اللَّهُ عَلَى مَنْ تَابَ فَقَالَ عُمَرُ مَا هَذَا فَقُلْتُ هَكَذَا أَقْرَأَنِيهَا أُبَيٌّ قَالَ فَمَرَّ بِنَا إِلَيْهِ قَالَ فَجَاءَ إِلَى أُبَيٍّ فَقَالَ مَا يَقُولُ هَذَا قَالَ أُبَيٌّ هَكَذَا أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفَأُثْبِتُهَا فَأَثْبَتَهَا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Abu Ishaq Asy Syaibani] dari [Yazid bin Asham] dari [Ibnu Abbas] berkata, \"Seorang laki-laki datang menemui Umar dan bertanya, maka sesekali Umar memandangi kepalanya dan sesekali memandangi kedua kakinya. Barangkali ia bisa melihat kondisi kekurangan yang ada padanya. Kemudian ia bertanya, \"Berapa harta yang kamu punya?\" Laki-laki itu menjawab, \"Empat puluh ekjor unta.\" Ibnu Abbas berkata, \"Maha benar Allah dan Rasul-Nya, sekiranya anak Adam memiliki dua lembah, niscaya ia akan mencari lembah yang ketiga. Dan tidak ada yang bisa memenuhi mulut anak Adam selain tanah. Dan Allah akan memberi taubat bagi orang yang mau taubat.\" Umar berkata, \"Apa-apaan ini?\" Aku menjawab, \"Beginilah yang aku dengar dari Ubay.\" Umar lalu datang menemui Ubay bersamaku, lalu Umar berkata, \"Apa yang katakan oleh orang ini (Ibnu Abbas)?\" [Ubay] menjawab, \"Beginilah Rasulullah shallallahu 'alaihi wasallam membacakannya kepadaku.\" Umar berkata, \"Apakah aku bisa mempercayainya?\" Lalu Umar pun mempercayainya."},"2915":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ وَعَفَّانُ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ قَالَ عَفَّانُ فِي حَدِيثِهِ حَدَّثَنَا الْأَسْوَدُ بْنُ قَيْسٍ عَنْ نُبَيْحٍ عَنْ ابْنِ عَبَّاسٍأَنَّ أُبَيًّا قَالَ لِعُمَرَ يَا أَمِيرَ الْمُؤْمِنِينَ إِنِّي تَلَقَّيْتُ الْقُرْآنَ مِمَّنْ تَلَقَّاهُ وَقَالَ عَفَّانُ مِمَّنْ يَتَلَقَّاهُ مِنْ جِبْرِيلَ عَلَيْهِ السَّلَام وَهُوَ رَطْبٌ","id":"Telah menceritakan kepada kami [Hisyam bin Abdul Malik], dan [Affan] keduanya berkata, telah menceritakan kepada kami [Abu Awanah] dari [Aswad bin Qais], [Affan] menyebutkan dalam haditsnya; telah menceritakan kepada kami [Aswad bin Qais] dari [Nubaih] dari [Ibnu Abbas] bahwa [Ubay] berkata kepada Umar, \"Wahai Amirul Mukminin, aku telah mengambil Al Qur'an dari orang yang telah menerimanya.\" Affan menyebutkan, \"Dari orang yang menerimanya dari Jibril Alaihis Salam (Rasulullah), sedang dia itu lunak (mudah).\""},"2916":{"ar":"قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ يَعْقُوبَ أَبُو الْهَيْثَمِ الزُّبَالِيُّ قَالَ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ أَبِي حَدَّثَنَا رَقَبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ حَدَّثَنَا أُبَيُّ بْنُ كَعْبٍ قَالَسَمِعْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَمَا مُوسَى عَلَيْهِ السَّلَام فِي قَوْمِهِ يُذَكِّرُهُمْ بِأَيَّامِ اللَّهِ وَأَيَّامُ اللَّهِ نِعَمُهُ وَبَلَاؤُهُ إِذْ قَالَ مَا أَعْلَمُ فِي الْأَرْضِ رَجُلًا خَيْرًا مِنِّي أَوْ أَعْلَمَ مِنِّي قَالَ فَأَوْحَى اللَّهُ تَبَارَكَ وَتَعَالَى إِلَيْهِ إِنِّي أَعْلَمُ بِالْخَيْرِ مَنْ هُوَ أَوْ عِنْدَ مَنْ هُوَ إِنَّ فِي الْأَرْضِ رَجُلًا هُوَ أَعْلَمُ مِنْكَ قَالَ يَا رَبِّ فَدُلَّنِي عَلَيْهِ فَقِيلَ لَهُ تَزَوَّدْ حُوتًا مَالِحًا فَفَعَلَ ثُمَّ خَرَجَ فَلَقِيَ الْخَضِرَ فَكَانَ مِنْ أَمْرِهِمَا مَا كَانَ حَتَّى كَانَ آخِرُ ذَلِكَ مَرُّوا بِالْقَرْيَةِ اللِّئَامِ أَهْلُهَا فَطَافَا فِي الْمَجَالِسِ فَاسْتَطْعَمَا فَأَبَوْا أَنْ يُضَيِّفُوهُمَا ثُمَّ قَصَّ عَلَيْهِ النَّبَأَ نَبَأَ السَّفِينَةِ وَإِنَّهُ إِنَّمَا خَرَقَهَا لِيَتَجَوَّزَهَا الْمَلِكُ فَلَا يُرِيدُهَا وَأَمَّا الْغُلَامُ فَطُبِعَ يَوْمَ طُبِعَ كَافِرًا كَانَ أَبَوَاهُ عَطَفَا عَلَيْهِ فَلَوْ أَنَّهُ أَدْرَكَ لَأَرْهَقَهُمَا طُغْيَانًا وَكُفْرًا وَأَمَّا الْجِدَارُ فَكَانَ لِغُلَامَيْنِ يَتِيمَيْنِ فِي الْمَدِينَةِ","id":"Ia berkata, telah menceritakan kepadaku [Muhammad bin Ya'qub Abul Haitsam Az Zubali] ia berkata, telah menceritakan kepada kami [Mu'tamir bin Sulaiman] ia berkata, Aku mendengar [Ayahku] telah menceritakan kepada kami [Raqabah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] telah menceritakan kepada kami [Ubay bin Ka'b] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Musa berpidato di hadapan kaumnya mengingatkan hari-hari Allah, kemenangan dan cobaannya, ia katakan, \"Di Muka bumi ini aku tidak tahu orang yang lebih pandai melebihi aku.\" Maka Allah mewahyukan padanya bahwa Allah memiliki seorang hamba yang lebih pandai darinya, Musa berkata, \"Wahai Rabbku, tampakkanlah padaku.\" Maka dikatakan kepadanya, 'Berbekallah ikan laut', lalu ia pun melaksanakannya. Setelah itu ia keluar hingga bertemulah ia dengan Hidlir. Keduanya berjalan hingga bertemu penduduk suatu kampung, keduanya minta dijamu tapi tiada seorang pun yang mau menjamunya. Lalu dikisahkan kisah perahu, ia membakarnya untuk menghindari kejahatan raja yang zhalim, adapun si anak dia telah dituliskan padanya kekafiran sedang orang tuanya adalah orang-orang shaleh, kalaulah ia mendapatkan keduanya tentu ia akan menghardik, membangkang dan kafir, sedangkan dinding rumah adalah milik dua anak yatim di Madinah.\""},"2917":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ يُونُسَ وَأَبُو الرَّبِيعِ الزَّهْرَانِيُّ قَالَا حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ عَبَّاسٍ الْهَمْدَانِيُّ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنِ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغُلَامُ الَّذِي قَتَلَهُ صَاحِبُ مُوسَى عَلَيْهِ السَّلَام طُبِعَ يَوْمَ طُبِعَ كَافِرًا","id":"Telah menceritakan kepada kami [Suraij bin Yunus] dan [Abu Rabi' Az Zahrani] keduanya berkata, telah menceritakan kepada kami [Salm bin Qutaibah] telah menceritakan kepada kami [Abdul Jabar bin Abbas Al Mahdani] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam, beliau: \"Anak lelaki yang dibunuh sahabat Musa Alaihi Salam telah ditetapkan sebagai kafir.\""},"2918":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو دَاوُدَ عُمَرُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ حَمْزَةَ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ إِنْ سَأَلْتُكَ عَنْ شَيْءٍ بَعْدَهَا فَلَا تُصَاحِبْنِي قَدْ بَلَغْتَ مِنْ لَدُنِّي عُذْرًا }","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Abu Dawud Umar bin Sa'ad] dari [Yahya bin Zakaria bin Abu Za`idah] dari [Hamzah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b], bahwa Nabi shallallahu 'alaihi wasallam membaca ayat: '(Jika aku bertanya kepadamu tentang sesuatu sesudah (kali) ini, maka janganlah kamu memperbolehkan aku menyertaimu, sesungguhnya kamu sudah cukup memberikan uzur padaku').\" (Qs. Al Kahfi: 76)."},"2919":{"ar":"حَدَّثَنَا أَبُو عَبْدِ اللَّهِ الْعَنْبَرِيُّ حَدَّثَنَا أُمَيَّةُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو الْجَارِيَةِ الْعَبْدِيُّ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَرَأَ{ قَدْ بَلَّغْتَ مِنْ لَدُنِّي عُذْرًا }يُثَقِّلُهَا","id":"Telah menceritakan kepada kami [Abu Abdullah Al 'Anbari] telah menceritakan kepada kami [Umayyah bin Khalid] telah menceritakan kepada kami [Abul Jariyah Al 'Abdi] dari [Syu'bah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam, beliau membaca: '(Sesungguhnya kamu sudah cukup memberikan uzur padaku) ' (Qs. Al Kahfi: 76) dengan tsiqal (tasdid).\""},"2920":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا حَمْزَةُ بْنُ حَبِيبٍ الزَّيَّاتُ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَعَا لِأَحَدٍ بَدَأَ بِنَفْسِهِ فَذَكَرَ ذَاتَ يَوْمٍ مُوسَى فَقَالَ رَحْمَةُ اللَّهِ عَلَيْنَا وَعَلَى مُوسَى لَوْ كَانَ صَبَرَ لَقَصَّ اللَّهُ تَعَالَى عَلَيْنَا مِنْ خَبَرِهِ وَلَكِنْ قَالَ{ إِنْ سَأَلْتُكَ عَنْ شَيْءٍ بَعْدَهَا فَلَا تُصَاحِبْنِي قَدْ بَلَغْتَ مِنْ لَدُنِّي عُذْرًا }حَدَّثَنَا حَجَّاجٌ وَأَبُو قَطَنٍ عَمْرُو بْنُ الْهَيْثَمِ قَالَا حَدَّثَنَا حَمْزَةُ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Hamzah bin Habib Az Zayyat] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b] berkata, \"Jika Nabi shallallahu 'alaihi wasallam berdoa untuk orang lain, maka beliau memulainya dari dirinya sendiri. Suatu ketika beliau menyebut-nyebut Musa: \"Semoga Allah merahmati kita dan Musa, kalaulah ia bersabar pastilah Allah akan menceritakan kabarnya pada kita, tetapi ia malah berkata, '(Jika aku bertanya kepadamu tentang sesuatu sesudah (kali) ini, maka janganlah kamu memperbolehkan aku menyertaimu, sesungguhnya kamu sudah cukup memberikan uzur padaku) ' (QS. Al Kahfi: 76). Telah menceritakan kepada kami [Hajjaj] dan [Abu Qathan Amru bin Hutsaim] keduanya berkata, telah menceritakan kepada kami [Hamzah] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam secara makna.\""},"2921":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ اللَّهِ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ الْجَعْفِيُّ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي قَوْلِهِ تَبَارَكَ وَتَعَالَى{ وَذَكِّرْهُمْ بِأَيَّامِ اللَّهِ }قَالَ بِنِعَمِ اللَّهِ تَبَارَكَ وَتَعَالَىحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو عَبْدِ اللَّهِ الْعَنْبَرِيُّ حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبَانَ عَنْ أَبِي إِسْحَاقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيٍّ نَحْوَهُ وَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami Abdullah dia berkata, telah menceritakan kepada kami [Yahya bin Abdullah] mantan budak Bani Hasim, telah meriwayatkan kepada kami [Muhammad bin Aban Al Ja'fi] dari [Abu lshaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam, tentang firman Allah Tabaaraka Wa Ta'ala: '(dan ingatkanlah mereka kepada hari-hari Allah) ' (QS Ibrahim: 5) beliau bersabda: \"Yaitu dengan nikmat-nikmat Allah Tabaaraka Wa Ta'ala.\" Telah menceritakan kepada kami Abdullah dia berkata, telah menceritakan kepada kami [Abu Abdullah Al Anbari] dia berkata, telah menceritakan kepada kami [Abul Walid At Thayalisi] dia berkata, telah menceritakan kepada kami [Muhammad bin Abban] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay] dengan hadits yang semakna, namun ia tidak memarfu'kannya (tidak sampai kepada Nabi).\""},"2922":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ الْمَكِّيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَيْمُونٍ الْقَدَّاحُ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ الصَّادِقُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَمَارَانِي رَجُلٌ مِنْ بَنِي فَزَارَةَ فِي الرَّجُلِ الَّذِي اتَّبَعَهُ مُوسَى عَلَيْهِ السَّلَام فَقُلْتُ هُوَ الْخَضِرُ عَلَيْهِ السَّلَام وَقَالَ الْفَزَارِيُّ هُوَ رَجُلٌ آخَرُ فَمَرَّ بِنَا أُبَيُّ بْنُ كَعْبٍ قَالَ ابْنُ عَبَّاسٍ فَدَعَوْتُهُ فَسَأَلْتُهُ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ الَّذِي تَبِعَهُ مُوسَى عَلَيْهِ السَّلَام قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَمَا مُوسَى جَالِسٌ فِي مَلَإٍ مِنْ بَنِي إِسْرَائِيلَ فَقَالَ لَهُ رَجُلٌ هَلْ أَحَدٌ أَعْلَمُ بِاللَّهِ تَبَارَكَ وَتَعَالَى مِنْكَ قَالَ مَا أَرَى فَأَوْحَى اللَّهُ إِلَيْهِ بَلَى عَبْدِي الْخَضِرُ فَسَأَلَ السَّبِيلَ إِلَيْهِ فَجَعَلَ اللَّهُ تَبَارَكَ وَتَعَالَى لَهُ الْحُوتَ آيَةً إِنْ افْتَقَدَهُ وَكَانَ مِنْ شَأْنِهِ مَا قَصَّ اللَّهُ تَبَارَكَ وَتَعَالَى","id":"Telah menceritakan kepada kami [Muhammad bin Abbad Al Makki] telah menceritakan kepada kami [Abdullah bin Maimun Al Qaddah] telah menceritakan kepada kami [Ja'far bin Muhammad Ash Shadiq] dari [Ibnu Syihab] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas] berkata, \"Siapakah pemuda Bani Fazarah yang mengikuti Musa Alaihi Salam?\" Aku menjawab, \"Dialah Hidlir Alaihi Salam.\" Al fazari lau berkata, \"Itu orang lain.\" Lalu lewatlah Ubay bin Ka'b. Ibnu Abbas berkata, \"Lalu aku memanggilnya dan bertanya, \"Apakah engkau pernah mendengar dari Rasulullah shallallahu 'alaihi wasallam tentang seorang laki-laki yang mengikuti Musa?\" [Ubay] menjawab, \"Ya, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika Musa sedang duduk-duduk bersama para pemimpin bani Israil, tiba-tiba ada seorang laki-laki bertanya kepadanya, \"Apakah ada seorang yang lebih pandai darimu tentang Allah Tabaaraka Wa Ta'ala?\" Musa menjawab, \"Aku tidak melihatnya.\" Maka Allah menurunkan wahyu-Nya: \"Ada. Yaitu Khidlir hamba-Ku.\" Lalu Musa menanyakan jalan kepada Hidlir dan Allah jadikan ikan hiu sebagai tanda kekuasaannya, bila ia kehilangan ikat tersebut….dan perkaranya telah Allah Tabaaraka Wa Ta'ala kisahkan.\""},"2923":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَمَا حَكَّ فِي صَدْرِي شَيْءٌ مُنْذُ أَسْلَمْتُ إِلَّا أَنِّي قَرَأْتُ آيَةً وَقَرَأَهَا رَجُلٌ غَيْرَ قِرَاءَتِي فَأَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ أَقْرَأْتَنِي آيَةَ كَذَا وَكَذَا قَالَ نَعَمْ قَالَ فَقَالَ الْآخَرُ أَلَمْ تُقْرِئْنِي آيَةَ كَذَا وَكَذَا قَالَ نَعَمْ أَتَانِي جِبْرِيلُ عَنْ يَمِينِي وَمِيكَائِيلُ عَنْ ي��سَارِي فَقَالَ جِبْرِيلُ اقْرَأْ الْقُرْآنَ عَلَى حَرْفٍ وَاحِدٍ فَقَالَ مِيكَائِيلُ اسْتَزِدْهُ حَتَّى بَلَغَ سَبْعَةَ أَحْرُفٍ كُلُّهَا شَافٍ كَافٍحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا حُمَيْدٌ قَالَ قَالَ أَنَسٌ قَالَ أُبَيٌّ مَا دَخَلَ قَلْبِي شَيْءٌ مُنْذُ أَسْلَمْتُ فَذَكَرَ مَعْنَى حَدِيثِ أُبَيٍّ عَنْ يَحْيَى بْنِ سَعِيدٍ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُعْتَمِرُ عَنْ حُمَيْدٍ عَنْ أَنَسٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ مَا دَخَلَ قَلْبِي مُنْذُ أَسْلَمْتُ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Humaid] dari [Anas] dari [Ubay bin Ka'b] ia berkata, \"Tidak ada yang menggusarkan dadaku semenjak keIslamanku kecuali aku membaca ayat, lalu ada orang lain membacanya namun tidak sebagaimana bacaanku. Kami lalu mendatangi Nabi shallallahu 'alaihi wasallam, aku bertanya, \"Tolong bacakan untukku ayat ini dan itu.\" Beliau bersabda: \"Ya.\" Lalu laki-laki lain juga berkata, \"Engkau bacakan juga padaku ayat ini dan ini.\" Beliau menjawab: \"Ya. Jibril telah mendatangiku dari sebelah kanan dan Mika`il dari sebelah kiri, lalu Jibril berkata, 'Bacalah Al-Qur'an dengan satu dialek, \" lalu Mika`il berkata, 'Mintalah tambahan, ' hingga akhirnya menjadi tujuh dialek. Semuanya sempurna dan mencukupi.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Bisyr bin Mufadhal] telah menceritakan kepada kami [Humaid] ia berkata, [Anas] berkata, [Ubay] pernah mengatakan, \"Tidak sesuatu yang masuk (mengusik) hatiku semenjak aku masuk Islam…lalu ia menyebutkan makna hadits Ubay dari Yahya bin Sa'id.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Mu'tamir] dari [Humaid] dari [Anas] dari [Ubay bin Ka'b] ia berkata, \"Tidak ada sesuatu yang masuk (mengusik) hatiku semenjak aku masuk Islam...lalu ia sebutkan hadits secara makna.\""},"2924":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ الْمَكِّيُّ حَدَّثَنَا أَبُو ضَمْرَةَ عَنْ يُونُسَ عَنِ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَ كَانَ أُبَيٌّ يُحَدِّثُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فُرِجَ سَقْفُ بَيْتِي وَأَنَا بِمَكَّةَ فَنَزَلَ جِبْرِيلُ فَفَرَجَ صَدْرِي ثُمَّ غَسَلَهُ مِنْ مَاءِ زَمْزَمَ ثُمَّ جَاءَ بِطَسْتٍ مِنْ ذَهَبٍ مَمْلُوءٍ حِكْمَةً وَإِيمَانًا فَأَفْرَغَهَا فِي صَدْرِي ثُمَّ أَطْبَقَهُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Abbad Al Makki] telah menceritakan kepada kami [Abu Dlamrah] dari [Yunus] dari [Az Zuhri] dari [Anas] berkata, [Ubay] menceritakan bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Atap rumahku terbuka dan ketika itu aku di Makkah, kemudian Jibril turun dan membelah dadaku. Jibril kemudian mencucinya dengan air zamzam, lalu ia datang dengan membawa bejana dari emas yang penuh berisi dengan hikmah dan iman. Kemudian semua itu dimasukkan ke dalam dadaku lalu menuutupnya kembali.\""},"2925":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أَجْلَحَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى أَمَرَنِي أَنْ أَعْرِضَ الْقُرْآنَ عَلَيْكَ قَالَ وَسَمَّانِي لَكَ رَبِّي تَبَارَكَ وَتَعَالَى قَالَ بِفَضْلِ اللَّهِ وَبِرَحْمَتِهِ فَبِذَلِكَ فَلْتَفْرَحُوا هَكَذَا قَرَأَهَا أُبَيٌّ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ajlah] telah menceritakan kepada kami [Abdullah bin Abdurrahman bin Abza] dari [Ayahnya] dari [Ubay bin Ka'b] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Tabaaraka Wa Ta'ala telah memerintahkan kepadaku agar membacakan Al-Qur'an kepadamu.\" Ubay berkata, \"Allah Tabaaraka Wa Ta'ala menyebutkan namaku kepadamu?! Beliau membacakan: 'QUL BIFADLILLAH WA BIRAHMATIHI, FABIDZALIKA FALTAFRAHUU' (Katakanlah: \"Dengan kurnia Allah dan rahmat-Nya, hendaklah dengan itu kamu bergembira) '. (QS Yunus: 58) Beginilah Ubay membacakannya.\""},"2926":{"ar":"حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَسْلَمُ الْمِنْقَرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَي عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُبَيُّ أُمِرْتُ أَنْ أَقْرَأَ عَلَيْكَ سُورَةَ كَذَا وَكَذَا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ وَقَدْ ذُكِرْتُ هُنَاكَ قَالَ نَعَمْ فَقُلْتُ لَهُ يَا أَبَا الْمُنْذِرِ فَفَرِحْتَ بِذَلِكَ قَالَ وَمَا يَمْنَعُنِي وَاللَّهُ تَبَارَكَ وَتَعَالَى يَقُولُ قُلْ بِفَضْلِ اللَّهِ وَبِرَحْمَتِهِ فَبِذَلِكَ فَلْتَفْرَحُوا هُوَ خَيْرٌ مِمَّا يَجْمَعُونَقَالَ مُؤَمَّلٌ قُلْتُ لِسُفْيَانَ هَذِهِ الْقِرَاءَةُ فِي الْحَدِيثِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Mu`ammal] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Aslam Al Minqari] dari [Abdullah bin Abdurrahman bin Abza] dari [Ayahnya] dari [Ubay bin Ka'b] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Hai Ubay, aku diperintahkan untuk membacakan surat ini dan ini.\" Ubay menjawab, \"Wahai Rasulullah, di sana namaku disebut?\" Beliau menjawab: \"Ya.\" Aku (perawi) lalu berkata kepadanya, \"Wahai Abu Mundzir, apakah engaku senang dengan hal itu?\" Ubay menjawab, \"Apa yang menghalangiku, sementara Allah Tabaaraa Wa Ta'ala berfirman: \"QUL BIFADLILLAH WA BIRAHMATIHI, FABIDZALIKA FALTAFRAHU' HUWA KHAIRUN MIMMA YAJMA'UUN (Dengan kurnia Allah dan rahmat-Nya, hendaklah dengan itu kamu bergembira, itulah kebaikan yang mereka telah kumpulkan) (QS. Yunus: 58). Mu`ammal berkata, \"Aku berkata pada Sufyan, \"Bacaan seperti ini ada dalam hadits?\" ia menjawab, \"Ya.\""},"2927":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّي حَدَّثَنَا أَسْبَاطُ بْنُ مُحَمَّدٍ الْقُرَشِيُّ حَدَّثَنَا الْأَعْمَشُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَي عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَسُبُّوا الرِّيحَ فَإِذَا رَأَيْتُمْ مِنْهَا مَا تَكْرَهُونَ فَقُولُوا اللَّهُمَّ إِنَّا نَسْأَلُكَ مِنْ خَيْرِ هَذِهِ الرِّيحِ وَمِنْ خَيْرِ مَا فِيهَا وَمِنْ خَيْرِ مَا أُرْسِلَتْ بِهِ وَنَعُوذُ بِكَ مِنْ شَرِّ هَذِهِ الرِّيحِ وَمِنْ شَرِّ مَا فِيهَا وَمِنْ شَرِّ مَا أُرْسِلَتْ بِهِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Abu Musa Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Asbath bin Muhammad Al Quraisyi] telah menceritakan kepada kami [Al A'masy] dari [Habib bin Abu Tsabit] dari [Sa'id bin Abdurrahman bin Abza] dari [Ayahnya] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Janganlah kalian mencela angin, jika kalian melihat angin yang tidak kalian sukai maka ucapkanlah; 'ALLAAHUMMA INNAA NAS'ALUKA MIN KHAIRI HAADZIHI AR RIIH WAMIN KHAIRI MAA FIIHAA, WAMIN KHARI MAA URSILAT BIHI WA NA'UUDZUBIKA MIN SYARRI HADZIHR RIIH WA MIN SYARRI MAA FIIHAA WA MIN SYARRI MAA URSILAT BIHI (Ya Allah kami memohon kepada-Mu dari kebaikan angin ini, dari kebaikan yang ada padanya dan dari kebaikan apa apa yang dibawanya, dan aku berlindung dari keburukan angin ini, dari keburukan apa yang ada padanya dan dari keburukan apa-apa yang dibawanya).\""},"2928":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ الْكُوفِيُّ حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا الْأَعْمَشُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ ذَرِّ بْنِ عَبْدِ اللَّهِ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَي عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا الرِّيحَ فَإِنَّهَا مِنْ رَوْحِ اللَّهِ تَبَارَكَ وَتَعَالَى وَسَلُوا اللَّهَ خَيْرَهَا وَخَيْرَ مَا فِيهَا وَخَيْرَ مَا أُرْسِلَتْ بِهِ وَتَعَوَّذُوا بِاللَّهِ مِنْ شَرِّهَا وَشَرِّ مَا فِيهَا وَشَرِّ مَا أُرْسِلَتْ بِهِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Yazid Al Kuufi] telah menceritakan kepada kami [Ibnu Fudlail] telah menceritakan kepada kami [Al A'masy] dari [Habib bin Abu Tsabit] dari [Dzar bin Abdullah] dari [Sa'id bin Abdurrahman bin Abza] dari [Ayahnya] dari [Ubay bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mencela angin karena ia adalah ciptaan Allah Tabaaraka Wa Ta'ala, memohonlah kepada Allah dari kebaikan angin itu, dari kebaikan yang ada padanya dan dari kebaikan apa-apa yang dibawanya, dan berlindunglah pada Allah dari keburukan angin tersebut, dari keburukan apa yang ada padanya dan dari keburukan apa-apa yang dibawanya.\""},"2929":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا يَحْيَى بْنُ دَاوُدَ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَاقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ سُفْيَانَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَي عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَجْرَ وَتَرَكَ آيَةً فَجَاءَ أُبَيٌّ وَقَدْ فَاتَهُ بَعْضُ الصَّلَاةِ فَلَمَّا انْصَرَفَ قَالَ يَا رَسُولَ اللَّهِ نُسِخَتْ هَذِهِ الْآيَةُ أَوْ أُنْسِيتَهَا قَالَ لَا بَلْ أُنْسِيتُهَا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Yahya bin dawud Al Washithi] telah menceritakan kepada kami [Ishaq bin Yusuf Al `Azraq] dari [Sufyan] dari [Salamah bin Kuhail] dari [Dzarr] dari [Sa'id bin Abdurrhaman bin Abza] dari [Ayahnya] dari [Ubay bin Ka'b] dia berkata, \"Nabi shallallahu 'alaihi wasallam melaksanakan shalat fajar bersama kami, kemudian meninggalkan satu ayat, maka datanglah Ubay yang saat itu ia telah tertinggal beberapa raka'at. Selesai shalat ia bertanya, \"Wahai Rasulullah, apakah ayat ini telah di nasakh (hapus) atau engkau terlupakan darinya?\" Nabi menjawab: \"Tidak, tapi aku lupa darinya.\""},"2930":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو حَفْصٍ الْأَبَّارُ عَنْ الْأَعْمَشِ عَنْ طَلْحَةَ وَزُبَيْدٍ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَي عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Hafshin Al Abbar] dari [Al A'masy] dari [Thalhah] dan [Zubaid] dari [Dzar] dari [Sa'id bin Abdurrahman bin Abza] dari [Ayahnya] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam ketika shalat witir membaca surat \"SABBIHISMA RABBIKAL A'LA (surat Al A'laa), QUL YAA AYYUHAL KAAFIRUUN (surat Al Kaafiruun) dan QUL HUWALLAAHU AHAD (surat Al ikhlash).\""},"2931":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُبَيْدَةَ حَدَّثَنَا أَبِي عَنِ الْأَعْمَشِ عَنْ طَلْحَةَ الْيَامِيِّ عَنْ ذَرٍّ عَنْ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَي عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْوَتْرِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ فَإِذَا سَلَّمَ قَالَ سُبْحَانَ الْمَلِكِ الْقُدُّوسِ ثَلَاثَ مَرَّاتٍحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ الْبَزَّازُ حَدَّثَنَا أَبُو عُمَرَ الضَّرِيرُ الْبَصْرِيُّ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ زُبَيْدٍ عَنْ ذَرٍّ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Abu Ubaydah] telah menceritakan kepada kami [Ayahku] dari [A'masy] dari [Thalhah Al Yammi] dari [Dzar] dari [Ibnu Abdurrahman bin Abza] dari [Ayahnya] dari [Ubay bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam ketika shalat witir membaca surat: \"SABBIHISMA RABBIKAL A'LA (surat Al 'Alaa), QUL YAA AYYUHAL KAAFIRUUN (surat Al Kaafiruun) dan QUL HUWALLAAHU AHAD (surat Al Ikhash). Lalu beliau membaca 'SUBHAANAL MALIKIL QUDDUUS' (Maha suci Dzat yang memiliki segala kesucian) sebanyak tiga kali.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammad bin Abdurrahim Al Bazzar] telah menceritakan kepada kami [Abu Umar Adl Dlarir Al Bashri] telah menceritakan kepada kami [Jarir bin Hazim] dari [Zubaid] dari [Dzar] dari [Sa'id bin Abdurrahman] dari [Ayahnya] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"2932":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ إِسْمَاعِيلَ بْنِ يَحْيَى بْنِ سَلَمَةَ بْنِ كُهَيْلٍ حَدَّثَنِي أَبِي عَنْ أَبِيهِ عَنْ سَلَمَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَي عَنْ أَبِيهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا إِذَا أَصْبَحْنَا أَصْبَحْنَا عَلَى فِطْرَةِ الْإِسْلَامِ وَكَلِمَةِ الْإِخْلَاصِ وَسُنَّةِ نَبِيِّنَا مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمِلَّةِ أَبِينَا إِبْرَاهِيمَ حَنِيفًا مُسْلِمًا وَمَا كَانَ مِنْ الْمُشْرِكِينَ وَإِذَا أَمْسَيْنَا مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Ibrahim bin Isma'il bin Yahya bin Salamah bin Kuhail] telah menceritakan kepadaku [Ayahku] dari [Ayahnya] dari  [Salamah] dari [Sa'id bin Abdurrahman bin Abza] dari [Ayahnya] dari [Ubay bin Ka'b] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah mengajarkan doa kepada kami apabila di pagi hari: 'ASHBAHNAA 'ALAA FITHRATIL ISLAAM WAKALIMATIL IKHLAASH WA SUNNATI NABIYYINAA MUHAMMADIN SHALLALLAAHU 'ALAIHI WASALLAM WA MILLATI ABIINAA IBRAAHIIM HANIIFAN MUSLIMAN WAMAA KAANA MINAL MUSYRIKIIN (Semoga kami di pagi ini dalam keadaan fitrah Islam (agama Islam), dalam kalimat yang ikhlas, dalam sunnah Nabi kami Muhammad shallallahu 'alaihi wasallam dan dalam millah (agama) bapak kami Ibrahim yang lurus, dan dia bukanlah termasuk orang-orang yang menyekutukan Allah) '. Dan pada sore hari juga dengan doa seperti itu.\""},"2933":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ الزُّبَيْرِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي الْهُذَيْلِ سَمِعَ ابْنَ أَبْزَى سَمِعَ عَبْدَ اللَّهِ بْنَ خَبَّابٍ سَمِعَ أُبَيًّا يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ الدَّجَّالَ فَقَالَ إِحْدَى عَيْنَيْهِ كَأَنَّهَا زُجَاجَةٌ خَضْرَاءُ وَتَعَوَّذُوا بِاللَّهِ تَبَارَكَ وَتَعَالَى مِنْ عَذَابِ الْقَبْرِ","id":"Telah menceritakan kepada kami [Sulaiman bin Dawud] telah menceritakan kepada kami [Syu'bah] dari [Habib bin Zubair] dia berkata aku telah mendengar [Abdullah bin Abu Hudzail] bahwa dia mendengar [Ibnu Abza] dia telah mendengar [Abdullah bin Khabab] dia mendengar [Ubay] menceritakan, bahwa Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang Dajjal. Beliau bersabda: \"Salah satu dari kedua matanya seperti kaca berwarna hijau, dan berlindunglah kalian kepada Allah Tabaaraka Wa Ta'ala dari siksa kubur.\""},"2934":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَرَوْحٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ الزُّبَيْرِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي الْهُذَيْلِ قَالَ رَوْحٌ الْعَنْزِيُّ يُحَدِّثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أُبَيِّ بْنِ كَعْبٍ وَقَالَ رَوْحٌ فِي حَدِيثِهِ إِنَّ عَبْدَ اللَّهِ بْنَ خَبَّابٍ حَدَّثَهُ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ ذَكَرَ الدَّجَّالَ عِنْدَهُ فَقَالَ عَيْنُهُ خَضْرَاءُ كَالزُّجَاجَةِ فَتَعَوَّذُوا بِاللَّهِ مِنْ عَذَابِ الْقَبْرِحَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبِ بْنِ الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْهُذَيْلِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الدَّجَّالِ فَذَكَرَ مِثْلَهُ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا خَلَّادُ بْنُ أَسْلَمَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا شُعْبَةُ حَدَّثَنَا حَبِيبُ بْنُ الزُّبَيْرِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي الْهُذَيْلِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يُذْكَرْ خَلَّادٌ فِي حَدِيثِ عَبْدِ اللَّهِ بْنِ خَبَّابٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Rauh] keduanya berkata, telah menceritakan kepada kami [Syu'bah] dari [Habib bin Zubair] berkata, Aku mendengar [Abdullah bin Abu Hudzail] berkata, [Rauh Al 'Anzi] menceritakan dari [Abdurrahman bin Abza] dari [Abdullah bin Khabbab] dari [Ubay bin Ka'b], dan [Rauh] menyebutkan dalam haditsnya, bahwa [Abdullah bin Khabbab] menceritakannya dari [Ubay bin Ka'ab] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau menyebutkan tentang Dajjal. Beliau bersabda: \"Salah satu dari kedua matanya seperti kaca berwarna hijau, dan berlindunglah kalian kepada Allah Tabaaraka Wa Ta'ala dari siksa kubur.\" Telah menceritakan kepada kami [Wahab bin Jarir] telah menceritakan kepada kami [Syu'bah] dari [Habib bin Zubair] dari [Abdullah bin Abu Hudzail] dari [Abdurrahman bin Abza] dari [Abdullah bin Khabbab] dari [Ubay bin Ka'b] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda tentang Dajjal, lalu ia menyebutkan seperti hadits tersebut.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Khallad bin Aslam] telah menceritakan kepada kami [Nadlr bin Syumail] telah mengabarkan kepada kami [Syu'bah] telah menceritakan kepada kami [Habib bin Zubair] ia berkata, Aku mendengar [Abdullah bin Abu Hudzail] dari [Abdurrahman bin Abza] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam, namun tidak disebutkan nama Khlalad dalam hadits Abdullah bin Khabbab ini.\""},"2935":{"ar":"عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ عَنْ أُبَيِّ بْنِ كَعْبٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُمَا قَالَقَرَأْتُ آيَةً وَقَرَأَ ابْنُ مَسْعُودٍ خِلَافَهَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَلَمْ تُقْرِئْنِي آيَةَ كَذَا وَكَذَا قَالَ بَلَى فَقَالَ ابْنُ مَسْعُودٍ أَلَمْ تُقْرِئْنِيهَا كَذَا وَكَذَا فَقَالَ بَلَى كِلَاكُمَا مُحْسِنٌ مُجْمِلٌ قَالَ فَقُلْتُ لَهُ فَضَرَبَ صَدْرِي فَقَالَ يَا أُبَيُّ بْنَ كَعْبٍ إِنِّي أُقْرِئْتُ الْقُرْآنَ فَقِيلَ لِي عَلَى حَرْفٍ أَوْ عَلَى حَرْفَيْنِ قَالَ فَقَالَ الْمَلَكُ الَّذِي مَعِي عَلَى حَرْفَيْنِ فَقُلْتُ عَلَى حَرْفَيْنِ فَقَالَ عَلَى حَرْفَيْنِ أَوْ ثَلَاثَةٍ فَقَالَ الْمَلَكُ الَّذِي مَعِي عَلَى ثَلَاثَةٍ فَقُلْتُ عَلَى ثَلَاثَةٍ حَتَّى بَلَغَ سَبْعَةَ أَحْرُفٍ لَيْسَ مِنْهَا إِلَّا شَافٍ كَافٍ إِنْ قُلْتَ غَفُورًا رَحِيمًا أَوْ قُلْتَ سَمِيعًا عَلِيمًا أَوْ عَلِيمًا سَمِيعًا فَاللَّهُ كَذَلِكَ مَا لَمْ تَخْتِمْ آيَةَ عَذَابٍ بِرَحْمَةٍ أَوْ آيَةَ رَحْمَةٍ بِعَذَابٍحَدَّثَنَا بَهْزٌ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ الْخُزَاعِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ قَرَأْتُ آيَةً وَقَرَأَ ابْنُ مَسْعُودٍ خِلَافَهَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ الْقَيْسِيُّ حَدَّثَنَا هَمَّامُ بْنُ يَحْيَى حَدَّثَنَا قَتَادَةُ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ قَرَأْتُ آيَةً وَقَرَأَ ابْنُ مَسْعُودٍ خِلَافَهَا وَقَرَأَ رَجُلٌ آخَرُ خِلَافَهَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Yahya bin Ya'mar] dari [Sulaiman bin Shurad] dari [Ubay bin Ka'b] radliallahu 'anhu berkata, \"Aku membaca ayat lalu Ibnu Mas'ud membacanya juga tapi dengan bacaan yang berbeda. Maka aku pun datang menemui Nabi shallallahu 'alaihi wasallam dan menanyakannya, \"Bukankah engkau telah membacakan ayat ini kepadaku?\" Beliau menjawab: \"Ya.\" Ibnu Mas'ud juga bertanya, \"Bukankah engkau juga membacakan ayat ini kepadaku?\" Beliau menjawab: \"Ya, bacaan kalian berdua benar dan bagus.\" Ubay berkata, \"Aku menanyakannya dan beliau memukul dadaku seraya bersabda: 'Hai Ubay bin Ka'b, Al-Qur'an dibacakan kepadaku dengan satu dan dua dialek. Lalu Malaikat yang ada bersamaku membacakan dengan dua dialek. Maka aku pun membacanya dengan dua dialek. Kemudian Malaikat berkata lagi dengan dua atau tiga dialek. Lalu Malaikat yang ada bersamaku berkata dengan tiga dialek, maka aku pun membacanya dengan tiga dialek, hingga sampai tujuh dialek. Dan tidaklah dari semua itu kecuali sempurna dan mencukupi. Sekiranya engkau membaca GHAFUURAN RAHIIMAN atau SAMII'AN 'ALIIMAN atau 'ALIIMAN SAMII'AN, maka seperti itulah Allah. Selama engkau tidak menutup ayat 'adzab dengan ayat rahmat, atau ayat rahmat dengan 'adzab.\" Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Yahya bin Ya'mar] dari [Sulaiman bin Shurad Al Khuza'i] dari [Ubay bin Ka'b] berkata, \"Aku membaca ayat dan Ibnu Mas'ud pun membacanya, tapi ia menyelisihinya (tidak sesuai dengan bacaanku). Maka aku mendatangi Nabi shallallahu 'alaihi wasallam menanyakan hal itu kepadanya…ia sebnutkan kelanjutan hadits. Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Hudbah bin Khalid Al Qaisi] telah menceritakan kepada kami [Hammam bin Yahya] telah menceritakan kepada kami [Qatadah] dari [Yahya bin Ya'mar] dari [Sulaiman bin Shurad] dari [Ubay bin Ka'ab] berkata, \"Aku membaca ayat dan Ibnu Mas'ud pun membacanya tapi ia menyelisihinya, maka ku mendatangi Nabi shallallahu 'alaihi wasallam lalu ia sebutkan hadits tersebut."},"2936":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ سُقَيْرٍ الْعَبْدِيِّ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَسَمِعْتُ رَجُلًا يَقْرَأُ فَقُلْتُ مَنْ أَقْرَأَكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ انْطَلِقْ إِلَيْهِ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ اسْتَقْرِئْ هَذَا فَقَالَ اقْرَأْ فَقَرَأَ فَقَالَ أَحْسَنْتَ فَقُلْتُ لَهُ أَوَلَمْ تُقْرِئْنِي كَذَا وَكَذَا قَالَ بَلَى وَأَنْتَ قَدْ أَحْسَنْتَ فَقُلْتُ بِيَدَيَّ قَدْ أَحْسَنْتَ مَرَّتَيْنِ قَالَ فَضَرَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ فِي صَدْرِي ثُمَّ قَالَ اللَّهُمَّ أَذْهِبْ عَنْ أُبَيٍّ الشَّكَّ فَفِضْتُ عَرَقًا وَامْتَلَأَ جَوْفِي فَرَقًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُبَيُّ إِنَّ مَلَكَيْنِ أَتَيَانِي فَقَالَ أَحَدُهُمَا اقْرَأْ عَلَى حَرْفٍ فَقَالَ الْآخَرُ زِدْهُ فَقُلْتُ زِدْنِي قَالَ اقْرَأْ عَلَى حَرْفَيْنِ فَقَالَ الْآخَرُ زِدْهُ فَقُلْتُ زِدْنِي فَقَالَ اقْرَأْ عَلَى ثَلَاثَةٍ فَقَالَ الْآخَرُ زِدْهُ فَقُلْتُ زِدْنِي قَالَ اقْرَأْ عَلَى أَرْبَعَةِ أَحْرُفٍ قَالَ الْآخَرُ زِدْهُ قُلْتُ زِدْنِي قَالَ اقْرَأْ عَلَى خَمْسَةِ أَحْرُفٍ قَالَ الْآخَرُ زِدْهُ قُلْتُ زِدْنِي قَالَ اقْرَأْ عَلَى سِتَّةٍ قَالَ الْآخَرُ زِدْهُ قَالَ اقْرَأْ عَلَى سَبْعَةِ أَحْرُفٍ فَالْقُرْآنُ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra`il] dari [Abu Ishaq] dari [Suqair Al 'Abdi] dari [Sulaiman bin Shurad] dari [Ubay bin Ka'b] ia berkata, \"Aku mendengar seseorang membaca Al-Qur'an. Lalu aku bertanya, \"Siapa yang membacakannya padamu?\" Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam. Pergilah kepada beliau!\" Maka aku pun mendatangi beliau dan berkata, \"Mintalah agar orang ini membaca.\" Beliau lalu bersabda: \"Bacalah.\" Orang itu lalu membacanya. Rasulullah shallallahu 'alaihi wasallam lantas bersabda: \"Bagus.\" Aku pun bertanya pada Rasulullah shallallahu 'alaihi wasallam; \"Bukankah engkau pernah membacakannya padaku begini dan begini?\" Beliau menjawab: \"Benar. Dan engkau juga bagus.\" Aku lalu berkata dengan isyarat kedua tanganku, \"Engkau juga bagus.\" -dua kali-. Maka Rasulullah shallallahu 'alaihi wasallam memukul dadaku dan bersabda: \"Ya Allah hilangkan keraguan dari Ubay bin Ka'b.\" Akupun berkeringat dan berdebar. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Ubay, sungguh telah datang kepadaku dua malaikat, salah seorang dari keduanya berkata, \"Bacalah dengan satu dialek (satu model bacaan)! ' lalu yang lain berkata, 'Tambahlah.' Maka akupun bermohon: 'Tambahkanlah.' Maka ia berkata, 'Bacalah dengan dua dialek! ' Maka yang lain berkata, 'Tambahlah.' Maka akupun bermohon: 'Tambahkanlah.' Maka ia berkata, 'Bacalah dengan tiga dialek! ' Maka yang lain berkata, 'Tambahlah.' Maka akupun bermohon: 'Tambahkanlah.' Maka ia berkata, 'Bacalah dengan empat dialek!.' Maka yang lain berkata, 'Tambahlah.' Maka akupun bermohon: 'Tambahkanlah.' Maka ia berkata, 'Bacalah dengan lima dialek!.' Maka yang lain berkata, 'Tambahlah.' Maka akupun bermohon: 'Tambahkanlah.' Maka ia berkata, 'Bacalah dengan enam dialek! ' Maka yang lain berkata, 'Tambahlah.' Maka akupun bermohon: 'Tambahkanlah.' Maka ia berkata, 'Bacalah dengan tujuh dialek! ' Maka Al-Qur'an diturunkan dalam tujuh dialek.\""},"2937":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ الْوَرَكَانِيُّ أَخْبَرَنَا شَرِيكٌ عَنْ أَبِي إِسْحَاقَ عَنْ سُلَيْمَانَ عَنْ أُبَيِّ بْنِ كَعْبٍرَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَانِي مَلَكَانِ فَقَالَ أَحَدُهُمَا لِلْآخَرِ أَقْرِئْهُ قَالَ عَلَى كَمْ قَالَ حَرْفٍ قَالَ زِدْهُ قَالَ حَتَّى بَلَغَ سَبْعَةَ أَحْرُفٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far Al Warakani] telah mengabarkan kepada kami [Syarik] dari [Abu Ishaq] dari [Sulaiman] dari [Ubay bin Ka'b] ia memarfu'kan kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Dua malaikat mendatangiku, lalu salah seorang dari keduanya berkata kepada yang lain, 'Bacakanlah Al-Qur'an kepadanya? ' ia balik bertanya, 'Dengan berapa dialek? ' Malaikat itu menjawab, 'Dengan satu.' ia berkata, 'Tambahlah! ' Hingga sampailah tujuh dialek.\""},"2938":{"ar":"حَدَّثَنَا يَزِيدُ بَنُ هَارُونَ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ ابْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشِّعْرِ حِكْمَةً","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Ibrahim bin Sa'ad] dari [Az Zuhri] dari [Abu Bakar bin Abdurrahman bin Harits bin Hisyam] dari [Marwan bin Hakam] dari [Ibnul Aswad bin Abdu Yaghuts] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada sya'ir ada hikmah.\""},"2939":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ قَالَ أَبُو كَامِلٍ فِي حَدِيثِهِ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ عَبْدِ اللَّهِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشِّعْرِ حِكْمَةًقَالَ أَبُو عَبْد الرَّحْمَنِ هَكَذَا يَقُولُ إِبْرَاهِيمُ بْنُ سَعْدٍ فِي حَدِيثِهِ عَبْدِ اللَّهِ بْنِ الْأَسْوَدِ وَإِنَّمَا هُوَ عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍ كَذَا يَقُولُ غَيْرُ إِبْرَاهِيمَ بْنِ سَعْدٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Abu Kamil] keduanya berkata, telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Az Zuhri], [Abu Kamil] menyebutkan dalam haditsnya, telah menceritakan kepada kami [Ibnu Syihab] dari [Abu Bakar bin Abdurrahman] dari [Marwan bin Hakam] dari Abdullah bin Al Aswad bin Abdu Yaghuts dari Ubay bin Ka'b, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada sya'ir ada hikmah.\" Abu Abdurrahman berkata, \"Seperti inilah Ibrahim bin sa'ad dalam haditsnya menyebutkan, Abdullah Ibnul Aswad. Hanyasanya ia adalah ['Abdurrahman Ibnul Aswad bin Yaghuts] dari [Ubay bin Ka'b], selain Ibrahim bin Sa'd seperti inilah mengatakannya.\""},"2940":{"ar":"حَدَّثَنِي مَنْصُورُ بْنُ أَبِي مُزَاحِمٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرٍ عَنْ مَرْوَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشِّعْرِ حِكْمَةًحَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ قَالَ أَبِي وَوَافَقَهُ ابْنُ الْمُبَارَكِ يَعْنِي اتَّفَقَا عَلَى عُرْوَةَ وَلَمْ يَقُولَا أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ","id":"Telah menceritakan kepadaku [Manshur bin Abu Muzahim] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Az Zuhri] dari [Abu Bakar] dari [Marwan] dari [Abdurrahman bin Al Aswad bin Abdu Yaghuts] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada sya'ir ada hikmah.\" Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari [Marwan bin Hakam] dari [Abdurrahman bin Al Aswad bin Abdu Yaghuts] dari [Ubay bin Ka'b] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam, lalu ia menyebutkan hadits tersebut.\" Ayahku berkata dan disetujui oleh Ibnul Mubarak, yaitu sepakat pada nama Urwah, dan keduanya tidak menyebut nama Abu Bakar bin Abdurrahman.\""},"2941":{"ar":"حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ عَبْدِ اللَّهِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الشِّعْرِ حِكْمَةًقَالَ عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَحَدَّثَنِي مَعْمَرٌ مِثْلَهُ سَوَاءً غَيْرَ أَنَّهُ جَعَلَ مَكَانَ أَبِي بَكْرٍ عُرْوَةَ","id":"Telah menceritakan kepada kami ['Attab bin Ziyad] telah menceritakan kepada kami [Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] telah menceritakan kepadaku [Abu Bakar bin Abdurrahman] dari [Marwan bin Hakam] dari [Abdullah bin Al Aswad bin Abdu Yaghuts] dari [Ubay bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada sya'ir ada hikmah.\" [Abdullah bin Mubarak] berkata, \" [Ma'mar] telah menceritakan kepadaku sama seperti itu dan ia tidak menyebut Abu Bakar [Urwah].\""},"2942":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ حَدَّثَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ الشِّعْرِ حِكْمَةًوَخَالَفَ رَبَاحٌ رِوَايَةَ ابْنِ الْمُبَارَكِ وَعَبْدِ الرَّزَّاقِ لِأَنَّهُمَا قَالَا عَنْ عُرْوَةَ قَالَ رَبَاحٌ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبُو مُكْرَمٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مَرْوَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أُبَيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي زِيَادٌ يَعْنِي ابْنَ سَعْدٍ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ أَنَّ أُبَيًّا أَخْبَرَهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي عَمْرٌو النَّاقِدُ حَدَّثَنَا الْحَجَّاجُ بْنُ أَبِي مَنِيعٍ الرُّصَافِيُّ حَدَّثَنَا جَدِّي عُبَيْدُ اللَّهِ بْنُ أَبِي زِيَادٍ عَنْ الزُّهْرِيِّ أَخْبَرَهُ أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ مَرْوَانَ بْنِ الْحَكَمِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ أَخْبَرَهُ عَنْ أُبَيِّ بْنِ كَعْبٍ أَخْبَرَهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُحَمَّدٍ الْمُوقَرِيُّ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ يَقُولُ سَمِعْتُ أُبَيَّ بْنَ كَعْبٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَذَكَرَهُ وَلَمْ يَذْكُرْ فِيهِ مَرْوَانَ حَدَّثَنَا عَبْد اللَّهِ قَالَ و حَدَّثَنِي أَبُو مَعْمَرٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ قَالَ أَبُو عَبْد الرَّحْمَنِ هَكَذَا حَدَّثَنَاهُ أَبُو مَعْمَرٍ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ وَقَالَ فِيهِ عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ وَخَالَفَ أَبُو مَعْمَرٍ رِوَايَةَ مَنْ رَوَاهُ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ لِأَنَّهُ رَوَاهُ عَدَدٌ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ وَقَالُوا فِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الْأَسْوَدِ","id":"Telah menceritakan kepada kami [Ibrahim bin Khalid] telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Az Zuhri] telah menceritakan kepadaku [Abu Bakar bin Abdurrahman] dari [Marwan bin Hakam] dari [Abdurrahman bin Aswad] dari [Ubay bin Ka'b], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebagian dari sya'ir adalah hikmah.\" Rabah menyelisihi riwayat Ibnu Mubarak dan Abdurrazaq, karena keduanya menyebutkan dari Urwah.\" Rabah berkata dari Abu Bakar bin Abdurrahman. Telah menceritakan kepada kami Abdullah, telah menceritakan kepadaku [Abu Mukram] dan [Abu Bakar bin Abu Syaibah] keduanya berkata, telah menceritakan kepada kami [Ibnu Mubarak] dari [Yunus] dari [Az Zuhri] telah menceritakan kepadaku [Abu Bakar bin Abdurrahman] dari [Marwan] dari [Abdurrahman bin Al Aswad] dari [Ubay] dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut.\" Telah menceritakan kepada kami [Utsman bin Umar] telah mengkabarkan kepada kami [Yunus] dari [Az Zuhri] telah mengkabarkan kepadaku [Abu Bakar bin Abdurrahman] dari [Abdurrahman bin Al Aswad] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam seperti itu pula.\" Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Ziyad] -yaitu Ibnu Sa'd- bahwa [Ibnu Syihab] mengabarkan kepadanya, ia berkata, telah mengkabarkan kepadaku [Abu Bakar bin Abdurrahman] dari [Marwan bin Hakam] dari [Abdurrahman bin Aswad] bahwa [Ubay] mengabarkan kepadanya dari Rasulullah shallallahu 'alaihi wasallam seperti itu.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Amru An Naqid] telah menceritakan kepada kami [Hajjaj bin Abu Mani' Ar Rushafi] telah menceritakan kepada kami kakekku [Ubaidullah bin Abu Ziyad] dari [Az Zuhri] telah mengabarkan kepadanya [Abu Bakar bin Abdurrahman bin Harits bin Hisyam] dari [Marwan bin Hakam] bahwa [Abdurrahman bin Al Aswad bin Abdu Yaghuts] mengabarkan kepadanya dari [Ubay bin Ka'b] telah mengkabarkan kepadnya dari Rasulullah shallallahu 'alaihi wasallam semisal itu.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Suwaid bin Sa'id] telah menceritakan kepada kami [Walid bin Muhammad Al Muqari] dari [Az Zuhri] ia berkata, Aku mendengar [Abu Bakar bin Abdurrahman] berkata, Aku mendengar [Abdurrahman bin Al Aswad bin Abdu Yaghuts] mengatakan, Aku mendengar [Ubay bin Ka'b] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, lalu ia menyebutkan hadits tersebut, namun ia tidak menyebutkan nama Marwan.\" Telah menceritakan kepada kami Abdullah ia berkata, telah menceritakan kepadaku [Abu Ma'mar] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [Ibnu Syihab] dari [Abu Bakar bin Abdurrahman] dari [Marwan bin Hakam] dari [Abdurrahman bin Aswad bin Abdu Yaghuts] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam…lalu ia sebutkan hadits tersebut.\" Abu Abdurrahman berkata, \"Seperti inilah Abu Ma'mar menceritakannya kepada kami dari Ibrahim bin Sa'd, 'Abdurrahman bin Al Aswad juga menyebutkan tentang hadits tersebut, namun Abu Ma'mar menyelisihi riwayat orang yang meriwayatkan dari Ibrahim bin Sa'd. Sebab ada beberapa orang yang meriwayatkan dari Ibrahim bin Sa'd, mereka mengatakan tentang hadits tersebut dari Abdullah bin Al Aswad.\""},"2943":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَبْد اللَّهِ قَالَ و حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ أَخْبَرَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ حَدَّثَنِي سُوَيْدُ بْنُ غَفَلَةَ قَالَخَرَجْتُ مَعَ زَيْدِ بْنِ صُوحَانَ وَسَلْمَانَ بْنِ رَبِيعَةَ حَتَّى إِذَا كُنَّا بِالْعُذَيْبِ الْتَقَطْتُ سَوْطًا فَقَالَا لِي أَلْقِهِ فَأَبَيْتُ فَلَمَّا قَدِمْتُ الْمَدِينَةَ لَقِيتُ أُبَيَّ بْنَ كَعْبٍ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ الْتَقَطْتُ مِائَةَ دِينَارٍ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ فَقَالَ عَرِّفْهَا سَنَةً فَعَرَّفْتُهَا سَنَةً فَلَمْ أَجِدْ أَحَدًا يَعْرِفُهَا قَالَ فَقَالَ اعْرِفْ عَدَدَهَا وَوِعَاءَهَا وَوِكَاءَهَا ثُمَّ عَرِّفْهَا سَنَةً فَإِنْ جَاءَ صَاحِبُهَا وَإِلَّا فَهِيَ كَسَبِيلِ مَالِكَ وَهَذَا لَفْظُ وَكِيعٍ وَقَالَ ابْنُ نُمَيْرٍ فِي حَدِيثِهِ فَقَالَ عَرِّفْهَا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ فَقَالَ عَرِّفْهَا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ فَقَالَ عَرِّفْهَا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ فَقَالَ اعْلَمْ عِدَّتَهَا وَوِعَاءَهَا وَوِكَاءَهَا فَإِنْ جَاءَ أَحَدٌ يُخْبِرُكَ بِعِدَّتِهَا وَوِعَائِهَا وَوِكَائِهَا فَأَعْطِهَا إِيَّاهُ وَإِلَّا فَاسْتَمْتِعْ بِهَا","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami Abdullah ia berkata, telah menceritakan kepada kami Ayahku telah menceritakan kepada kami [Abdullah bin Numair] telah mengkabarkan kepada kami [Sufyan] dari [Salamah bin Kuhail] dia berkata, telah bercerita kepadaku [Suwaid bin Ghafalah] dia berkata, \"Aku keluar bersama Zaid bin Suhan dan Salman bin Rabi'ah, hingga ketika kami sampai di 'Udzaib aku menemukan sebuah pecut. Lalu keduanya berkata, \"Letakkan dia.\" Namun aku menolaknya, ketika tiba di Madinah aku bertemu dengan [Ubay bin Ka'b], maka hal itu aku ceritakan kepadanya. Ubay kemudian berkata, \"Aku pernah menemukan seratus dinar pada masa Rasulullah shallallahu 'alaihi wasallam, kemudian hal itu aku tanyakan kepada beliau, dan beliau bersabda: \"Umumkanlah selama satu tahun.\" Maka aku umumkan barang tersebut selama tahun namun aku tidak mendapatkan seorangpun yang mengakuinya.\" Ubay berkata lagi, \"Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Kenalilah jumlahnya, wadah dan tutupnya, kemudian umumkanlah selama satu tahun. Jika pemiliknya datang berikan, namun jika tidak maka dia menjadi milik orang yang menemukannya.\"\" Dan lafadz hadits ini berasal dari Waki'. Sedangkan [Ibnu Numair] menyebutkan dalam haditsnya, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Umumkanlah!\" Maka aku umumkan selama satu tahun, kemudian aku menemui Nabi dan beliau bersabda: \"Umumkanlah.\" Maka aku umumkan selama satu tahun, kemudian aku menemui Nabi dan beliau mengatakan lagi: \"Umumkanlah.\" Maka aku umumkan selama satu tahu, kemudian aku menemui nabi dan beliau bersabda: \"Umumkanlah jumlahnya, wadah dan tutupnya, jika ada yang datang dan menyebutkan jumlah, wadah dan tutupnya maka berikanlah kepadanya, namun jika tidak maka pergunakanlah dia.\""},"2944":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ سُوَيْدَ بْنَ غَفَلَةَ و حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي سَلَمَةُ بْنُ كُهَيْلٍ قَالَ سَمِعْتُ سُوَيْدَ بْنَ غَفَلَةَ قَالَغَزَوْتُ مَعَ زَيْدِ بْنِ صُوحَانَ وَسَلْمَانَ بْنِ رَبِيعَةَ فَوَجَدْتُ سَوْطًا فَأَخَذْتُهُ فَقَالَا لِي اطْرَحْهُ فَقُلْتُ لَا وَلَكِنْ أُعَرِّفُهُ فَإِنْ وَجَدْتُ مَنْ يَعْرِفُهُ وَإِلَّا اسْتَمْتَعْتُ بِهِ فَأَبَيَا عَلَيَّ وَأَبَيْتُ عَلَيْهِمَا فَلَمَّا رَجَعْنَا مِنْ غَزَاتِنَا حَجَجْتُ فَأَتَيْتُ الْمَدِينَةَ فَلَقِيتُ أُبَيَّ بْنَ كَعْبٍ فَذَكَرْتُ لَهُ قَوْلَهُمَا وَقَوْلِي لَهُمَا فَقَالَ وَجَدْتُ صُرَّةً فِيهَا مِائَةُ دِينَارٍ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ ذَلِكَ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا فَلَمْ أَجِدْ مَنْ يَعْرِفُهَا فَأَتَيْتُهُ فَقُلْتُ لَهُ لَمْ أَجِدْ مَنْ يَعْرِفُهَا فَقَالَ عَرِّفْهَا حَوْلًا ثَلَاثَ مَرَّاتٍ وَلَا أَدْرِي قَالَ لَهُ ذَلِكَ فِي سَنَةٍ أَوْ فِي ثَلَاثِ سِنِينَ فَقَالَ لِي فِي الرَّابِعَةِ اعْرِفْ عَدَدَهَا وَوِكَاءَهَا فَإِنْ وَجَدْتَ مَنْ يَعْرِفُهَا وَإِلَّا فَاسْتَمْتِعْ بِهَا وَهَذَا لَفْظُ حَدِيثِ يَحْيَى بْنِ سَعِيدٍوَزَادَ مُحَمَّدُ بْنُ جَعْفَرٍ فِي حَدِيثِهِ قَالَ فَلَقِيتُهُ بَعْدَ ذَلِكَ بِمَكَّةَ فَقَالَ لَا أَدْرِي ثَلَاثَةَ أَحْوَالٍ أَوْ حَوْلًا وَاحِدًا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] berkata, Aku mendengar [Suwaid bin Ghaflah], dan telah menceritakan kepadaku Abdullah telah menceritakan kepadaku [Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] telah menceritakan kepadaku [Salamah bin Kuhail] berkata, Aku mendengar [Suwaid bin Ghafalah] ia berkata, \"Aku berperang bersama Zaid bin Shuhan dan Salman bin Rabi'ah, aku menemukan cambuk hingga akupun mengambilnya. Lantas keduanya berkata kepadaku, \"Letakkanlah.\" Aku lalu menjawab, \"Tidak! Namun aku akan mengumumkannya. Jika aku mendapati orang yang mengenalnya maka akan aku berikan, jika tidak maka akan aku gunakan.\" Keduanya tidak menerima apa yang aku katakan, dan aku juga tidak menerima apa yang mereka katakan. Ketika kami telah kembali dari peperangan, aku menunaikan haji, lalu menuju Madinah. Aku kemudian bertemu [Ubay bin Ka'b], maka aku ceritakan kepadanya apa yang mereka katakan dan perkataanku kepada mereka. Ubay lalu berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam aku pernah menemukan dompet, di dalamnya terdapat seratus dinar. Aku lalu menemui Rasulullah shallallahu 'alaihi wasallam, lantas hal itu aku ceritakan kepada beliau. Beliau bersabda: \"Umumkanlah selama satu tahun.\" Aku lalu mengumumkannya selama satu tahun, namun aku tidak mendapati orang yang mengenalnya. Aku lalu kembali menemui beliau dan aku katakan, \"Aku belum mendapatkan orang yang mengenalinya?\" beliau bersabda: \"Umumkan selama satu tahun.\" Beliau katakan seperti hingga tiga kali.\" Suwaid berkata, \"Aku tidak tahu beliau mengatakan hal itu kepada Ubay dalam waktu satu tahun, atau dalam tiga tahun.\" Ubay melanjutkan, \"Pada kali keempat beliau bersabda kepadaku: \"Umumkanlah jumlahnya, wadah dan tutupnya, jika kamu dapati orang yang mengenalinya maka berikanlah, jika tidak maka gunakanlah.\" Dan ini adalah lafadz Yahya bin Sa'id, dan Muhammad bin Ja'far menyebutkan dalam haditsnya, \"Setelah itu aku bertemu dengannya di Makkah. Ubay berkata, \"Aku tidak tahu tiga tahun atau satu tahun.\""},"2945":{"ar":"حَدَّثَنَا أَبُو خَيْثَمَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَكُنَّا حُجَّاجًا فَوَجَدْتُ سَوْطًا فَأَخَذْتُهُ فَقَالَ الْقَوْمُ تَأْخُذُهُ فَلَعَلَّهُ لِرَجُلٍ مُسْلِمٍ قَالَ فَقُلْتُ أَوَلَيْسَ لِي أَخْذُهُ فَأَنْتَفِعَ بِهِ خَيْرٌ مِنْ أَنْ يَأْكُلَهُ الذِّئْبُ فَلَقِيتُ أُبَيَّ بْنَ كَعْبٍ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ أَحْسَنْتَ ثُمَّ قَالَ الْتَقَطْتُ صُرَّةً فِيهَا مِائَةُ دِينَارٍ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ عَرِّفْهَا حَوْلًا فَعَرَّفْتُهَا حَوْلًا ثُمَّ أَتَيْتُهُ فَقُلْتُ قَدْ عَرَّفْتُهَا حَوْلًا فَقَالَ عَرِّفْهَا سَنَةً أُخْرَى ثُمَّ قَالَ انْتَفِعْ بِهَا وَاحْفَظْ وِكَاءَهَا وَخِرْقَتَهَا وَأَحْصِ عَدَدَهَا فَإِنْ جَاءَ صَاحِبُهَاقَالَ جَرِيرٌ فَلَمْ أَحْفَظْ مَا بَعْدَ هَذَا يَعْنِي تَمَامَ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu Khaitsamah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Salamah bin Kuhail] dari [Suwaid bin Ghafalah] ia mengatakan, \"Saat melakukan haji aku menemukan pecut, maka aku pun memungutnya. Orang-orang pun berkata, \"Kenapa kamu ambil, siapa tahu itu adalah milik seorang Muslim.\" Suwaid berkata, \"Aku menjawab, \"Bukankah lebih baik jika aku ambil dan memanfaatkannya dari pada dimakan serigala?\" setelah itu aku bertemu [Ubay bin Ka'b], kemudian hal itu aku ceritakan kepadanya. Ubay lantas berkata, \"Aku pernah menemukan kantong yang di dalamnya berisi seratus dinar, lalu aku menemui Rasulullah shallallahu 'alaihi wasallam dan menanyakan hal itu kepada beliau, beliau pun bersabda: \"Umumkanlah selama satu tahun.\" Maka akupun mengumumkannya selama satu tahun, lalu aku menemui beliau lagi dan berkata, \"Wahai Rasulullah, aku telah mengumumkannya setahun.\" Beliau bersabda: \"Umumkan lagi selama satu tahun.\" Kemudian beliau meneruskan sabdanya: \"Manfaatkanlah dan jagalah jangan sampai berkurang, jika pemiliknya datang berikan.\" Jarir berkata, \"Aku tidak hafal kesempurnaan haditsnya.\""},"2946":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ أَيُّوبَ بْنِ رَاشِدٍ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا مُحَمَّدُ بْنُ جُحَادَةَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سُوَيْدِ بْنِ غَفَلَةَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَالْتَقَطْتُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِائَةَ دِينَارٍ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَرِّفْهَا سَنَةً فَعَرَّفْتُهَا سَنَةً ثُمَّ أَتَيْتُهُ فَقُلْتُ قَدْ عَرَّفْتُهَا سَنَةً قَالَ عَرِّفْهَا سَنَةً أُخْرَى فَعَرَّفْتُهَا سَنَةً أُخْرَى ثُمَّ أَتَيْتُهُ فِي الثَّالِثَةِ فَقَالَ أَحْصِ عَدَدَهَا وَوِكَاءَهَا وَاسْتَمْتِعْ بِهَاحَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ ح و حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَجَّاجِ النَّاجِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَ حَجَجْتُ أَنَا وَزَيْدُ بْنُ صُوحَانَ وَسَلْمَانُ بْنُ رَبِيعَةَ فَذَكَرَ الْحَدِيثَ قَالَ فَعَرَّفْتُهَا عَامَيْنِ أَوْ ثَلَاثَةً قَالَ اعْرِفْ عَدَدَهَا وَوِعَاءَهَا وَوِكَاءَهَا وَاسْتَمْتِعْ بِهَا فَإِنْ جَاءَ صَاحِبُهَا فَعَرَفَ عِدَّتَهَا وَوِكَاءَهَا فَأَعْطِهَا إِيَّاهُ","id":"Telah menceritakan kepadaku [Ahmad bin Ayyub bin Rasyid Al Bashri] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Muhammad bin Juhadah] dari [Salamah bin Kuhail] dari [Suwaid bin Ghafalah] dari [Ubay bin Ka'b] berkata, \"Aku menemukan uang seratus dinar di masa Rasulullah shallallahu 'alaihi wasallam lalu aku laporkan kepada beliau, beliau bersabda: 'Umumkan setahun! ' Maka aku umumkan satu tahun. Kemudian aku datang kepada beliau dan berkata, \"Aku umumkan selama satu tahun.\" Beliau lagi dan berkata, \"Umumkanlah lagi selama satu tahun.\" Aku lalu mengumumkannya selama satu tahun, kemudian aku datang kepada beliau untuk yang ketiga kalinya, beliau bersabda: \"Hitung jumlah dan wadahnya, lalu manfaatkanlah.\" Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad bin Salamah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami Abdullah berkata, telah menceritakan kepada kami [Ibrahim bin Hajjaj An Naji] telah menceritakan kepada kami [Hammad bin Salamah] dari [Salamah bin Kuhail] dari [Suwaid bin Ghafalah] berkata, \"Aku berhaji bersama Zaid bin Shuhan dan Salman bin Rabi'ah, lalu ia sebutkan makna hadits. Ia berkata, \"Lalu aku mengumumkannya hingga dua atau tiga kali.\" Beliau bersabda: \"Kenalilah jumlah, wadah dan tali pengikatnya, lalu manfaatkanlah. Jika pemiliknya datang dan dapat mengenali berapa jumlah dan tali pengikatnya, maka berikanlah kepadanya.\""},"2947":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكُنْتُ فِي الْمَسْجِدَ فَدَخَلَ رَجُلٌ فَقَرَأَ قِرَاءَةً أَنْكَرْتُهَا عَلَيْهِ ثُمَّ دَخَلَ آخَرُ فَقَرَأَ قِرَاءَةً سِوَى قِرَاءَةِ صَاحِبِهِ فَقُمْنَا جَمِيعًا فَدَخَلْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ هَذَا قَرَأَ قِرَاءَةً أَنْكَرْتُهَا عَلَيْهِ ثُمَّ دَخَلَ هَذَا فَقَرَأَ قِرَاءَةً غَيْرَ قِرَاءَةِ صَاحِبِهِ فَقَالَ لَهُمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأَا فَقَرَأَا قَالَ أَصَبْتُمَا فَلَمَّا قَالَ لَهُمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي قَالَ كَبُرَ عَلَيَّ وَلَا إِذْ كُنْتُ فِي الْجَاهِلِيَّةِ فَلَمَّا رَأَى الَّذِي غَشِيَنِي ضَرَبَ فِي صَدْرِي فَفِضْتُ عَرَقًا وَكَأَنَّمَا أَنْظُرُ إِلَى اللَّهِ تَبَارَكَ وَتَعَالَى فَرَقًا فَقَالَ يَا أُبَيُّ إِنَّ رَبِّي تَبَارَكَ وَتَعَالَى أَرْسَلَ إِلَيَّ أَنْ اقْرَأْ الْقُرْآنَ عَلَى حَرْفٍ فَرَدَدْتُ إِلَيْهِ أَنْ هَوِّنْ عَلَى أُمَّتِي فَأَرْسَلَ إِلَيَّ أَنْ اقْرَأْهُ عَلَى حَرْفَيْنِ فَرَدَدْتُ إِلَيْهِ أَنْ هَوِّنْ عَلَى أُمَّتِي فَأَرْسَلَ إِلَيَّ أَنْ اقْرَأْهُ عَلَى سَبْعَةِ أَحْرُفٍ وَلَكَ بِكُلِّ رَدَّةٍ مَسْأَلَةٌ تَسْأَلُنِيهَا قَالَ قُلْتُ اللَّهُمَّ اغْفِرْ لِأُمَّتِي اللَّهُمَّ اغْفِرْ لِأُمَّتِي وَأَخَّرْتُ الثَّالِثَةَ لِيَوْمٍ يَرْغَبُ إِلَيَّ فِيهِ الْخَلْقُ حَتَّى إِبْرَاهِيمَ عَلَيْهِ الصَّلَاة وَالسَّلَامُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il bin Abu Khalid] telah menceritakan kepadaku [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dari [Ubay bin Ka'b] berkata, \"Aku berada di masjid lalu ada seorang yang membaca ayat dengan bacaan yang aku mengingkarinya, lalu datang lagi seseorang yang membacaa dengan bacaan yang lain pula. Maka kami pun berdiri dan melaporkannya kepada Rasulullah shallallahu 'alaihi wasallam, aku berkata, 'Wahai Rasulullah, orang ini membaca dengan bacaan yang aku mengingkarinya, lalu datang temannya yang juga membaca dengan bacaan yang lain? ' Nabi shallallahu 'alaihi wasallam bersabda: \"Bacalah oleh kalian berdua! ' Beliau lalu bersabda: \"Kalian sudah benar.\" Ketika Nabi shallallahu 'alaihi wasallam bersabda kepada keduanya, yakni orang yang mengatakan, 'Celaka aku, dan juga semasa aku jahiliyah', hingga ketika beliau melihat ada keraguan dalam hatiku, beliau memukul memukul dadaku hingga aku bercucuran keringat seakan aku melihat Allah Tabaaraka Wa Ta'ala. Beliau bersabda: 'Wahai Ubay, sesungguhnya Rabbku telah mengutus utusan kepadaku dan mengatakan; 'Bacalah dengan satu dialek (satu model bacaan) ', maka aku meminta kepadanya untuk meringankan umatku, Allah pun menjadikannya dua dialek. Lalu aku meminta agar memberikan keringanan untuk umatku, lalu Allah menjadikan agar aku membaca dalam tujuh dialek. Dan bagimu di setiap pertanyaan yang kamu ajukan aku berikan jawabannya.\" Rasulullah bersabda: \"Aku berdoa: 'Ya Allah ampunilah umatku. Ya Allah ampunilah umatku' dan aku mengakhirkan doa yang ketiga untuk hari terakhir; yang semua makhluk mengharapkanku, hingga nabi Ibrahim sekalipun.\""},"2948":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَ أَضَاءَةَ بَنِي غِفَارٍ قَالَ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى حَرْفٍ قَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ وَإِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ جَاءَ الثَّانِيَةَ فَقَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى حَرْفَيْنِ فَقَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ إِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ جَاءَ الثَّالِثَةَ فَقَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى سَبْعَةِ أَحْرُفٍ فَأَيُّمَا حَرْفٍ قَرَءُوا عَلَيْهِ فَقَدْ أَصَابُوا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Hakam] dari [Mujahid] dari [Ibnu Abu Laila] dari [Ubay bin Ka'b], bahwa Nabi shallallahu 'alaihi wasallam ketika beliau berada di perkumpulan bani Ghifar, Jibril berkata, \"Sesunggguhnya Allah menyuruhmu untuk membacakan Al Qur`an kepada umatmu dengan satu dialek.\" Beliau bersabda: \"Aku bermohon pemaafan dan ampunan Allah, sungguh umatku tidak bisa mengucapkan dengan satu dialek (satu model bacaan).\" Kemudian Jibril datang untuk kedua kalinya, Jibril berkata, \"Sesungguhnya Allah menyuruhmu untuk membacakan Al Qur`an kepada umatmu dengan dua dialek.\" Beliau bersabda: \"Aku bermohon pemaafan dan ampunan Allah, sungguh umatku tidak bisa mengucapkan dengan dua dialek.\" Kemudian Jibril datang untuk ketiga kalinya, Jibril berkata, \"Sesunggguhnya Allah menyuruhmu untuk membacakan Al Qur`an kepada umatmu dengan tujuh dialek, dengan bacaan mana saja mereka membada maka mereka telah benar.\""},"2949":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ الْحَسَنِ الْعُرَنِيِّ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ ابْنِ أَبِي لَيْلَىعَنْ أُبَيِّ بْنِ كَعْبٍ فِي هَذِهِ الْآيَةِ{ وَلَنُذِيقَنَّهُمْ مِنْ الْعَذَابِ الْأَدْنَى دُونَ الْعَذَابِ الْأَكْبَرِ }قَالَ الْمُصِيبَاتُ وَالدُّخَانُ قَدْ مَضَيَا وَالْبَطْشَةُ وَاللِّزَامُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Qatadah] dari [Azrah] dari [Hasan Al Urani] dari [Yahya bin Jazar] dari [Ibnu Abu Laila] dari [Ubay bin Ka'b] tentang ayat ini: '(Dan sesungguhnya kami merasakan kepada mereka sebahagian azab yang dekat (di dunia) sebelum azab yang lebih besar (di akhirat) ' (QS. As Sajadah: 21). Ubay berkata, \"Musibah-musibah dan kegoncangan keduanya telah berlalu, demikian juga kekerasan dan pembunuhan.\""},"2950":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ عَنْ أَبِي جَنَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ أَعْرَابِيٌّ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّ لِي أَخًا وَبِهِ وَجَعٌ قَالَ وَمَا وَجَعُهُ قَالَ بِهِ لَمَمٌ قَالَ فَأْتِنِي بِهِ فَوَضَعَهُ بَيْنَ يَدَيْهِ فَعَوَّذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفَاتِحَةِ الْكِتَابِ وَأَرْبَعِ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْبَقَرَةِ وَهَاتَيْنِ الْآيَتَيْنِ{ وَإِلَهُكُمْ إِلَهٌ وَاحِدٌ }وَآيَةِ الْكُرْسِيِّ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ وَآيَةٍ مِنْ آلِ عِمْرَانَ{ شَهِدَ اللَّهُ أَنَّهُ لَا إِلَهَ إِلَّا هُوَ }وَآيَةٍ مِنْ الْأَعْرَافِ{ إِنَّ رَبَّكُمْ اللَّهُ الَّذِي خَلَقَ السَّمَوَاتِ وَالْأَرْضَ }وَآخِرِ سُورَةِ الْمُؤْمِنِينَ{ فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ }وَآيَةٍ مِنْ سُورَةِ الْجِنِّ{ وَأَنَّهُ تَعَالَى جَدُّ رَبِّنَا }وَعَشْرِ آيَاتٍ مِنْ أَوَّلِ الصَّافَّاتِ وَثَلَاثِ آيَاتٍ مِنْ آخِرِ سُورَةِ الْحَشْرِ وَقُلْ هُوَ اللَّهُ أَحَدٌ وَالْمُعَوِّذَتَيْنِ فَقَامَ الرَّجُلُ كَأَنَّهُ لَمْ يَشْتَكِ قَطُّ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammmad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Umar bin Ali] dari [Abu Janab] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] dia berkata, telah menceritakan kepadaku [Ubay bin Ka'b] dia berkata, \"Aku berada di sisi Nabi shallallahu 'alaihi wasallam, kemudian datanglah seorang Arab badui dan berkata \"Wahai Nabiyullah, saya mempunyai seorang saudara laki laki yang sedang sakit.\" Nabi bertanya: \"Apa sakitnya?\" Dia menjawab, \"Dia terkena penyakit gila.\" Nabi bersabda: \"Bawa dia kemari.\" Kemudian dia di hadapkan kepada beliau dan Nabi shallallahu 'alaihi wasallam memohonkan perlindungan untuknya dengan membaca fatihatul kitab (surat Al fatihah), empat ayat permulaan surat Al Baqarah, dua ayat beriku ini: WA ILAAHUKUM ILAAHUW WAAHID (Dan Tuhanmu adalah Tuhan yang Maha Esa) (QS. Al Baqarah: 163) dan ayat kursi. Lalu tiga ayat terakhir dari surat Al Baqarah. satu ayat dari surat Ali Imran: SYAHIDAALLAAHU ANNAHU LAA ILAAHA ILLA HUWA (Allah menyatakan bahwasanya tidak ada Tuhan melainkan dia (yang berhak disembah) (Qs. Ali Imran: 18), satu ayat dari surat Al A'raaf: INNA RABBAKUMULLAAHUL LADZII KHALAQAS SAMAAWAATI WAL ARDL (Sesungguhnya Tuhan kamu ialah Allah yang Telah menciptakan langit dan bumi) (Qs. Al A'raaf: 54), akhir dari surat Al Mukminun: FATA'AALALLAAHUL MALIKUL HAQ (Maka Maha Tinggi Allah, raja yang Sebenarnya) (Qs. Al Mukminun: 116), satu ayat dari surat Al Jin: WA ANNAHU TA'AALA JADDU RABBINAA (Dan bahwasanya Maha Tinggi kebesaran Tuhan kami) (Qs. Al Jin: 3), sepuluh ayat permulaan dari surat Ash Shaffaat, tiga ayat terakhir dari surat surat Al Hasyr: QUL HUWALLAAHU AHAD (surat Al Ikhlash), dan Al Mu'awwidzatain (surat Al Falaq dan An Naas).\" Maka berdirilah laki laki itu seakan-akan dia tidak pernah terkena sakit sama sekali.\""},"2951":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَسَدِيُّ لُوَيْنٌ حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ بْنِ أَعْيَنَ حَدَّثَنَا عُمَرُ بْنُ سَالِمٍ الْأَفْطَسُ عَنْ أَبِيهِ عَنْ زُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ جِبْرِيلَ عَلَيْهِ السَّلَام أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي أَضَاءَةِ ب��نِي غِفَارٍ فَقَالَ يَا مُحَمَّدُ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تَقْرَأَ الْقُرْآنَ عَلَى حَرْفٍ فَلَمْ يَزَلْ يَزِيدُهُ حَتَّى بَلَغَ سَبْعَةَ أَحْرُفٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sualiman Al Asadi Luwain] telah menceritakan kepada kami [Hasan bin Muhammad bin A'yan] telah menceritakan kepada kami [Umar bin Salim Al Afthas] dari [Ayahnya] dari [Zubaid] dari [Abdurrahman bin Abu Laila] dari [Ubay bin Ka'b], bahwa Jibril mendatangi Nabi shallallahu 'alaihi wasallam ketika beliau berada di perkumpulan bani Ghifar, ia mengatakan, \"Wahai Muhammad, Allah menyuruhmu membaca Al-Qur'an dengan satu dialek (satu model bacaan).\" Dan beliau terus saja meminta tambahan hingga menjadi tujuh dialek.\""},"2952":{"ar":"حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ الْحَسَنِ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى سَبْعَةِ أَحْرُفٍ فَأَيُّمَا حَرْفٍ قَرَءُوا عَلَيْهِ فَقَدْ أَصَابُوا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Al Hasan] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ubay bin Ka'b], bahwa Nabi shallallahu 'alaihi wasallam pernah didatangi oleh Malaikat Jibril Alihis Salam, ia berkata, \"Sesunggguhnya Allah menyuruhmu untuk membacakan Al-Qur'an kepada umatmu dengan tujuh dialek (tujuh model bacaan), dengan bacaan manapun mereka membacanya maka mereka telah benar.\""},"2953":{"ar":"حَدَّثَنَا جَعْفَرُ بْنُ مِهْرَانَ السَّبَّاكُ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ مُحَمَّدِ بْنِ جُحَادَةَ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ جِبْرِيلَ عَلَيْهِ السَّلَام أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِأَضَاءَةِ بَنِي غِفَارٍ فَقَالَ إِنَّ اللَّهَ تَبَارَكَ وَتَعَالَى يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى حَرْفٍ وَاحِدٍ فَقَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ فَذَكَرَ الْحَدِيثَ إِلَى أَنْ قَالَ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى سَبْعَةِ أَحْرُفٍ فَمَنْ قَرَأَ حَرْفًا مِنْهَا فَهُوَ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Ja'far bin Mihran As Sabak Al Bashri] telah menceritakan kepada kami [Abdul Warits] dari [Muhammad bin Juhadah] dari [Hakam] dari [Mujahid] dari [Abdurrahman bin Abu Laila] dari [Ubay bin Ka'b] , bahwa Jibril Alaihis Salam mendatangi Nabi shallallahu 'alaihi wasallam ketika beliau berada di perkampungan bani Ghifar, Jibril berkata, \"Sesunggguhnya Allah menyuruhmu untuk membacakan Al-Qur'an kepada umatmu dengan satu dialek (satu model bacaa).\" Beliau lalu bersabda: \"Aku bermohon permaafan dan ampunan Allah.\" Lalu ia (perawi) sebutkan hadits tersebut hingga sampai pada pada perkataan Jibril, \"Sesunggguhnya Allah menyuruhmu untuk membacakan Al-Qur'an kepada umatmu dengan tujuh dialek, barangsiapa membaca dengan salah satunya maka telah benar.\""},"2954":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي زِيَادِ بْنِ أَبِي الْجَعْدِ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَانْتَسَبَ رَجُلَانِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُهُمَا أَنَا فُلَانُ بْنُ فُلَانٍ فَمَنْ أَنْتَ لَا أُمَّ لَكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْتَسَبَ رَجُلَانِ عَلَى عَهْدِ مُوسَى عَلَيْهِ السَّلَام فَقَالَ أَحَدُهُمَا أَنَا فُلَانُ بْنُ فُلَانٍ حَتَّى عَدَّ تِسْعَةً فَمَنْ أَنْتَ لَا أُمَّ لَكَ قَالَ أَنَا فُلَانُ بْنُ فُلَانٍ ابْنُ الْإِسْلَامِ قَالَ فَأَوْحَى اللَّهُ إِلَى مُوسَى عَلَيْهِ السَّلَام أَنَّ هَذَيْنِ الْمُنْتَسِبَيْنِ أَمَّا أَنْتَ أَيُّهَا الْمُنْتَمِي أَوْ الْمُنْتَسِبُ إِلَى تِسْعَةٍ فِي النَّارِ فَأَنْتَ عَاشِرُهُمْ وَأَمَّا أَنْتَ يَا هَذَا الْمُنْتَسِبُ إِلَى اثْنَيْنِ فِي الْجَنَّةِ فَأَنْتَ ثَالِثُهُمَا فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Yazid bin Abu Ziyad bin Abu Ja'd] dari [Abdul Malik bin Umair] dari [Abdurrahman bin Abu Laila] dari [Ubay bin Ka'b] dia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam ada dua orang lelaki yang saling menyebutkan nasabnya, yang satu berkata, 'Saya adalah fulan bin Fulan, sedangkan kamu tidak memiliki ibu! ' Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Dahulu pada masa Nabi Musa Alaihis Salam juga ada dua orang lelaki yang menyebutkan nasabnya, yang satu berkata, 'Saya adalah fulan bin Fulan -sampai dia menyebutkan sembilan keturunan-, sedangkan kamu siapa, seorang yang tidak memiliki Ibu! ' Kemudian yang kedua menjawab, 'Saya adalah Fulan bin Fulan bin Al Islam.' Nabi bersabda: \"Setelah itu Allah menurunkan wahyu kepada Musa Alaihis Salam berkenaan dengan dua orang tersebut: 'Adapun kamu wahai orang yang menginduk, atau menasabkan dirinya kepada sembilan orang yang berada di neraka, maka engkau adalah orang yang kesempuluhnya. Adapun engkau wahai orang yang menasabkan diri kepada dua orang yang berada di jannah, maka engaku adalah orang yang ketiga'.\""},"2955":{"ar":"حَدَّثَنِي وَهْبُ بْنُ بَقِيَّةَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ إِسْمَاعِيلَ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَكُنْتُ فِي الْمَسْجِدِ فَدَخَلَ رَجُلٌ فَصَلَّى فَقَرَأَ قِرَاءَةً أَنْكَرْتُهَا عَلَيْهِ فَدَخَلَ رَجُلٌ آخَرُ فَصَلَّى فَقَرَأَ قِرَاءَةً سِوَى قِرَاءَةِ صَاحِبِهِ فَلَمَّا قَضَيْنَا الصَّلَاةَ دَخَلْنَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ هَذَا قَرَأَ قِرَاءَةً أَنْكَرْتُهَا عَلَيْهِ فَدَخَلَ هَذَا فَقَرَأَ قِرَاءَةً سِوَى قِرَاءَةِ صَاحِبِهِ فَقَالَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا فَقَرَءُوا فَقَالَ قَدْ أَحْسَنْتُمْ فَسَقَطَ فِي نَفْسِي مِنْ التَّكْذِيبِ وَلَا إِذْ كُنْتُ فِي الْجَاهِلِيَّةِ فَلَمَّا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَدْ غَشِيَنِي ضَرَبَ صَدْرِي قَالَ فَفِضْتُ عَرَقًا وَكَأَنَّمَا أَنْظُرُ إِلَى رَبِّي تَبَارَكَ وَتَعَالَى فَرَقًا فَقَالَ لِي أُبَيٌّ إِنَّ رَبِّي تَبَارَكَ وَتَعَالَى أَرْسَلَ إِلَيَّ فَقَالَ لِي اقْرَأْ عَلَى حَرْفٍ فَرَدَدْتُ إِلَيْهِ أَنْ هَوِّنْ عَلَى أُمَّتِي فَرَدَّ إِلَيَّ أَنْ اقْرَأْ عَلَى حَرْفَيْنِ فَرَدَدْتُ إِلَيْهِ ثَلَاثَ مَرَّاتٍ أَنْ هَوِّنْ عَلَى أُمَّتِي فَرَدَّ عَلَيَّ أَنْ اقْرَأْ عَلَى سَبْعَةِ أَحْرُفٍ وَلَكَ بِكُلِّ رَدَّةٍ رَدَدْتَهَا سُؤْلَكَ أُعْطِيكَهَا فَقُلْتُ اللَّهُمَّ اغْفِرْ لِأُمَّتِي اللَّهُمَّ اغْفِرْ لِأُمَّتِي وَأَخَّرْتُ الثَّالِثَةَ لِيَوْمٍ يَرْغَبُ إِلَيَّ فِيهِ الْخَلْقُ حَتَّى إِبْرَاهِيمَ عَلَيْهِ السَّلَام","id":"Telah menceritakan kepadaku [Wahab bin Baqiyah] telah menceritakan kepada kami [Khalid bin Abdullah] dari [Isma'il bin Abu KHalid] dari [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] telah menceritakan kepadaku [Ubay bin Ka'b] ia berkata, \"Saat aku berada di dalam masjid masuklah seorang laki-laki, ia lalu shalat dan membaca ayat dengan bacaan yang aku mengingkarinya. Kemudian datang lagi seseorang yang membacaa dengan bacaan yang berlainan dengan bacaan temannya tersebut. Selesai kami menunaikan shalat, maka kami mendatangi Rasulullah shallallahu 'alaihi wasallam, aku berkata, 'Wahai Rasulullah, ia membaca dengan bacaan yang aku mengingkarinya, lalu datang temannya yang juga membaca dengan bacaan yang lain? ' Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Bacalah oleh kalian!\" mereka pun membacanya. Beliau lalu bersabda: \"Kalian telah benar.\" Lalu muncullah dalam hatiku rasa pendustaan kepada Nabi (rasa bersalah) yang tidak aku rasakan pada masa Jahiliyah. Maka ketika Rasulullah shallallahu 'alaihi wasallam melihat hatiku dihantui oleh perasaan tersebut, beliau menepuk dadaku.\" Ubay melanjutkan, \"Akupun bercucuran keringat seakan aku melihat kepada Rabbku Tabaaraka Wa Ta'ala, beliau bersabda: \"Wahai Ubay, sesungguhnya Rabbku telah mengutus utusan kepadaku dan mengatakan: 'Bacalah dengan satu dialek (satu model bacaan).' Aku pun meminta kepadanya agar memberi keringanan bagu umatku, lalu Allah memerintahkan agar aku membaca dengan dua dialek. Lalu aku kembali meminta agar memberi keringanan bagi umatku sampai tiga kali, sehingga Allah memerintahkan agar aku membaca dalam tujuh dialek. Dan bagimu di setiap pertanyaan yang kamu ajukan aku berikan jawabannya. Aku lalu berdoa: \"Ya Allah ampunilah umatku. Ya Allah ampunilah umatku. Lalu aku mengakhirkan permintaan yang ketiga untuk hari yang semua makhluk mengharapkanku, hingga Nabi Ibrahim Alaihis Salam sekalipun.\""},"2956":{"ar":"حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ أَخْبَرَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ أَخْبَرَنَا مُوسَى بْنُ عُقْبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زَيْدِ بْنِ عُقْبَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ أَنَا وَأُبَيٌّ وَأَبُو طَلْحَةَ جُلُوسًا فَأَكَلْنَا لَحْمًا وَخُبْزًا ثُمَّ دَعَوْتُ بِوَضُوءٍ فَقَالَا لِمَ تَتَوَضَّأُ فَقُلْتُ لِهَذَا الطَّعَامِ الَّذِي أَكَلْنَا فَقَالَا أَتَتَوَضَّأُ مِنْ الطَّيِّبَاتِ لَمْ يَتَوَضَّأْ مِنْهُ مَنْ هُوَ خَيْرٌ مِنْكَ","id":"Telah menceritakan kepada kami ['Attab bin Ziyad] telah mengabarkan kepada kami [Abdullah bin Mubarak] telah mengkabarkan kepada kami [Musa bin Uqbah] dari [Abdurahman bin Zaid bin Uqbah] dari [Anas bin Malik] ia berkata, \"Aku bersama [Ubay] dan [Abu Thalhah] duduk menyantap daging dan roti, kemudian aku meminta untuk diambilkan air wudlu, maka keduanya pun berkata, \"Kenapa kamu berwudlu?\" aku lalu menjawab, \"Karena makanan yang kita makan ini.\" Keduanya berkata, \"Kenapa kamu berwudlu dari makanan yang baik, sedang orang yang lebih baik darimu (Rasulullah shallallahu 'alaihi wasallam) tidak melakukannya?\""},"2957":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ قَالَ قُلْتُ لِأُبَيٍّ إِنَّ عَبْدَ اللَّهِ يَقُولُ فِي الْمُعَوِّذَتَيْنِ فَقَالَ سَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُمَا فَقَالَ قِيلَ لِي فَقُلْتُ فَأَنَا أَقُولُ كَمَا قَالَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ زِرٍّ قَالَ سَأَلْتُ أُبَيَّ بْنَ كَعْبٍ عَنْ الْمُعَوِّذَتَيْنِ فَقَالَ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُمَا فَقَالَ قِيلَ لِي فَقُلْتُ لَكُمْ فَقُولُوا قَالَ أُبَيٌّ فَقَالَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَحْنُ نَقُولُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ زِرٍّ قَالَ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُعَوِّذَتَيْنِ فَقَالَ قِيلَ لِي فَقُلْتُ قَالَ أُبَيٌّ فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَحْنُ نَقُولُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ أَبِي رَزِينٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ أُبَيِّ بْنِ كَعْبٍ بِمِثْلِهِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ زِرٍّ قَالَ سَأَلْتُ أُبَيًّا عَنْ الْمُعَوِّذَتَيْنِ فَقَالَ إِنِّي سَأَلْتُ عَنْهُمَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقِيلَ لِي فَقُلْتُ فَأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَحْنُ نَقُولُ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ زِرِّ بْنِ حُبَيْشٍ قَالَقُلْتُ لِأُبَيِّ بْنِ كَعْبٍ إِنَّ ابْنَ مَسْعُودٍ كَانَ لَا يَكْتُبُ الْمُعَوِّذَتَيْنِ فِي مُصْحَفِهِ فَقَالَ أَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَنِي أَنَّ جِبْرِيلَ عَلَيْهِ السَّلَام قَالَ لَهُ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ فَقُلْتُهَا فَقَالَ قُلْ أَعُوذُ بِرَبِّ النَّاسِ فَقُلْتُهَا فَنَحْنُ نَقُولُ مَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ أُبَيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Ayyasy] dari [Ashim] dari [Zir] dia berkata, Aku berkata kepada [Ubay], bahwa Abdullah berkomentar tentang surat Al Mu'awwidzatain, maka dia menjawab, \"Kami telah menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam tentang keduanya, kemudian beliau membacakannya kepadaku dan aku membacanya, saya mengucapkan sebagaimana yang diucapkan oleh beliau.\" Telah menceritakan kepada kami [Waki'] dia berkata, telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Zir] dia berkata, \"Aku bertanya kepada [Ubay bin Ka'ab] tentang surat Al Mu'awwidzatain, kemudian dia berkata, 'Aku telah menanyakannya kepada Nabi shallallahu 'alaihi wasallam tentang keduanya, maka beliau mengucapkannya kepadaku dan aku mengucapkannya kepada kalian, maka ucapkanlah sebagaimana yang aku ucapkan.\" Ubay berkata, \"kemudian Nabi mengucapkannya kepada kami dan kami mengucapkannya juga.\" Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dia berkata, telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Zir] dia berkata, telah bercerita kepadaku [Ubay bin Ka'b] dia berkata, \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang surat Al Mu'awwidzatain, kemudian beliau mengucapkannya kepadaku dan akupun mengucapkannya.\" Ubay berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam mengucapkan kepada kami dan kamipun mengikutinya.\" Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Zubair bin 'Adi] dari [Abu Razin] dari [Zir bin Hubaisy] dari [Ubay bin Ka'b] dengan hadits yang sama. Telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata, telah menceritakan kepada kami [Syu'bah] dari ['Ashim bin Bahdalah] dari [Zir] dia berkata, \"Aku bertanya kepada [Ubay] tentang surat Al Mu'awwidzatain kemudian dia berkata, \"Sesungguhnya aku telah menanyakan tentang keduanya kepada Rasulullah shallallahu 'alaihi wasallam.\" Ubay berkata, \"Maka dibacakanlah kepadaku dan akupun membacanya kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan kami membacanya dan kamipun membacanya.\" Telah menceritakan kepada kami [Affan] dia berkata, telah menceritakan kepada kami [Hammad bin Salamah] dia berkata, telah mengabarkan kepada kami ['Ashim bin Bahdalah] dari [Zir bin Hubaisy] dia berkata, \"Aku berkata kepada [Ubay bin Ka'b], \"Ibnu Mas'ud tidak menulis surat Al Mu'awwidzatain dalam Mushafnya?\" Kemudian dia menjawab, \"Aku bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam telah menceritakan kepadaku, bahwa Malaikat Jibril telah membacakan kepada beliau: 'QUL A'UUDZU BIRABBIL FALAQ (Katakanlah: \"Aku berlindung kepada Tuhan yang menguasai subuh) ' (Qs. Al Falaq: 1). Maka aku pun membacanya, kemudian Jibril membaca: 'QUL A'UUDZU BIRABBIN NAAS (Katakanlah: \"Aku berlidung kepada Tuhan (yang memelihara dan menguasai) manusia) ' (Qs. An Naas: 1), maka aku pun membacanya.\" Dan kami membaca apa yang telah dibaca oleh Nabi shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami [Affan] dia berkata, telah menceritakan kepada kami [Abu Awanah] dari [Ashim] dari [Zir] dari [Ubay] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang semakna.\""},"2958":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْحُسَيْنِ بْنِ أَشْكَابٍ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عُبَيْدَةَ بْنِ مَعْنٍ حَدَّثَنَا أَبِي عَنِ الْأَعْمَشِ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ كَانَ عَبْدُ اللَّهِ يَحُكُّ الْمُعَوِّذَتَيْنِ مِنْ مَصَاحِفِهِ وَيَقُولُ إِنَّهُمَا لَيْسَتَا مِنْ كِتَابِ اللَّهِ تَبَارَكَ وَتَعَالَى قَالَ الْأَعْمَشُ وَحَدَّثَنَا عَاصِمٌ عَنْ زِرٍّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَسَأَلْنَا عَنْهُمَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقِيلَ لِي فَقُلْتُ","id":"Telah menceritakan kepada kami [Muhammad bin Husain bin Asykab] telah menceritakan kepada kami [Muhammad bin Abu Ubaidah bin Ma'n] telah menceritakan kepada kami [Ayahku] dari [Al A'masy] dari [Abu Ishaq] dari [Abdurrahman bin Yazid] berkata, \" [Abdullah] (Ibnu Mas'ud) menghapus Mu'awidzatain dari dalam mushafnya, ia mengatakan baha keduanya bukan dari kitabullah Tabaaraka Wa Ta'ala.\" [Al A'masy] berkata, telah menceritakan kepada kami [Ashim] dari [Zir] dari [Ubay bin Ka'b] berkata, \"Kami telah menanyakannya pada Rasulullah shallallahu 'alaihi wasallam, beliau lalu membacakannya, maka aku pun mengikutinya.\""},"2959":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدةَ وَعَاصِمٍ عَنْ زِرٍّ قَالَقُلْتُ لِأُبَيٍّ إِنَّ أَخَاكَ يَحُكُّهُمَا مِنْ الْمُصْحَفِ فَلَمْ يُنْكِرْ قِيلَ لِسُفْيَانَ ابْنِ مَسْعُودٍ قَالَ نَعَمْ وَلَيْسَا فِي مُصْحَفِ ابْنِ مَسْعُودٍ كَانَ يَرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَوِّذُ بِهِمَا الْحَسَنَ وَالْحُسَيْنَ وَلَمْ يَسْمَعْهُ يَقْرَؤُهُمَا فِي شَيْءٍ مِنْ صَلَاتِهِ فَظَنَّ أَنَّهُمَا عُوذَتَانِ وَأَصَرَّ عَلَى ظَنِّهِ وَتَحَقَّقَ الْبَاقُونَ كَوْنَهُمَا مِنْ الْقُرْآنِ فَأَوْدَعُوهُمَا إِيَّاهُ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdah] dan [Ashim] dari [Zir] berkata, Aku berkata kepada Ubay, 'Sungguh saudaramu menghapus keduanya (mu'awidzatain) dari dalam mushafnya, ' namun ia tidak mengingkarinya.\" -Disebutkan kepada Sufyan; apakah ia Ibnu Mas'ud- ia menjawab, \"Ya. Itu tidak ada dalam mushaf Ibnu Mas'ud. Ia melihat Rasulullah shallallahu 'alaihi wasallam memohon perlindungan untuk Hasan dan Husian dengan surat tersebut, dan tidak pernah mendengar Rasulullah shallallahu 'alaihi wasallam membacanya saat shalat. Sehingga ia beranggapan bahwa itu hanya untuk perlindungan, dan keyakinan itu tetap ia pegang, sementara yang lain menetapkan bahwa keduanya adalah bagian dari Al-Qur'an.\""},"2960":{"ar":"حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الْأَجْلَحِ عَنْ الشَّعْبِيِّ عَنْ زِرِّ بْنِ حُبَيْشٍ قَالَسَمِعْتُ أُبَيَّ بْنَ كَعْبٍ يَقُولُ لَيْلَةُ سَبْعٍ وَعِشْرِينَ هِيَ الَّتِي أَخْبَرَنَا بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الشَّمْسَ تَطْلُعُ بَيْضَاءَ تَرَقْرَقُو حَدَّثَنَاه عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ إِدْرِيسَ بِإِسْنَادِهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ وَزَادَ فِيهِ لَيْسَ لَهَا شُعَاعٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari [Ajlah] dari [Asy Sya'bi] dari [Zir bin Hubaisy] dari [Ubay bin Ka'b] dia berkata, \"Malam lailatul qadar adalah malam ke dua puluh tujuh dalam bulan Ramadan, Rasulullah shallallahu 'alaihi wasallam telah mengabarkan kepada kami bahwa di antara tanda-tandanya adalah terbitnya matahari dengan sinar berwarna putih bersih.\" Telah menceritakannya kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Idris] dengan sanadnya dari Nabi shallallahu 'alaihi wasallam, seperti hadits tersebut. Namun ia menambahkan, \"Matahari terbit tanpa terik panas.\""},"2961":{"ar":"حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُهُ مِنْ عَبْدَةَ وَعَاصِمٍ عَنْ زِرٍّ قَالَسَأَلْتُ أُبَيًّا قُلْتُ أَبَا الْمُنْذِرِ إِنَّ أَخَاكَ ابْنَ مَسْعُودٍ يَقُولُ مَنْ يَقُمْ الْحَوْلَ يُصِبْ لَيْلَةَ الْقَدْرِ فَقَالَ يَرْحَمُهُ اللَّهُ لَقَدْ عَلِمَ أَنَّهَا فِي شَهْرِ رَمَضَانَ وَأَنَّهَا لَيْلَةُ سَبْعٍ وَعِشْرِينَ قَالَ وَحَلَفَ قُلْتُ وَكَيْفَ تَعْلَمُونَ ذَلِكَ قَالَ بِالْعَلَامَةِ أَوْ بِالْآيَةِ الَّتِي أُخْبِرْنَا بِهَا أَنَّ الشَّمْسَ تَطْلُعُ ذَلِكَ الْيَوْمَ لَا شُعَاعَ لَهَا","id":"Telah menceritakan kepada kami [Sufyan] ia berkata, Aku mendengarnya dari [Abdah] dan [Ashim] dari [Zir] ia berkata, Aku berkata kepada [Ubay], \"Wahai Abu Mundzir, sungguhnya Ibnu Mas'ud, saudaramu, mengatakan, 'Barangsiapa melaksanakan shalat malam setahun, maka ia akan mendapatkan lailatul qadar.' Ubay lalu menjawab, \"Semoga Allah merahmatinya, padahal ia tahu bahwa itu terjadi di bulan Ramadan, pada malam kedua puluh tujuh.\" Ubay lalu bersumpah, maka akupun bertanya, \"Bagaimana kalian bisa mengetahuinya?\" Ia menjawab, \"Dengan tanda-tanda yang telag dikabarkan kepada kami, bahwa di antara tandanya adalah, bahwa pada hari itu matahari akan terbit tanpa terik panas.\""},"2962":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَبْدَةَ بْنَ أَبِي لُبَابَةَ يُحَدِّثُ عَنْ زِرِّ بْنِ حُبَيْشٍ قَالَ قَالَ أُبَيٌّلَيْلَةُ الْقَدْرِ وَاللَّهِ إِنِّي لَأَعْلَمُهَا قَالَ شُعْبَةُ وَأَكْثَرُ عِلْمِي هِيَ اللَّيْلَةُ الَّتِي أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِيَامِهَا هِيَ لَيْلَةُ سَبْعٍ وَعِشْرِينَ وَإِنَّمَا شَكَّ شُعْبَةُ فِي هَذَا الْحَرْفِ هِيَ اللَّيْلَةُ الَّتِي أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ وَحَدَّثَنِي صَاحِبٌ لِي بِهَا عَنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] ia berkata, Aku mendengar [Abdah bin Abu Lubabah] menceritakan dari [Zir bin Hubaisy] ia mengatakan, [Ubay] berkata, \"Demi Allah, sungguh aku mengetahui perihal lailatul qadar -Syu'bah menyebutkan-, sedalam pengetahuanku bahwa malam itu akan terjadi pada malam yang Rasulullah shallallahu 'alaihi wasallam menyuruh kami memperbanyak shalat, malam itu adalah malam kedua puluh tujuh.\" Hanya saja Syu'bah merasa pada kalimat 'yaitu malam yang Rasulullah shallallahu 'alaihi wasallam menyuruh kami'. Ia (syu'bah) Berkata; temanku menceritakan hadits tersebut kepadaku darinya (Ubay).\""},"2963":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سُفْيَانُ بْنُ سَعِيدٍ عَنْ عَاصِمٍ عَنْ زِرٍّ قَالَقَالَ لِي أُبَيٌّ إِنَّهَا لَيْلَةُ سَبْعٍ وَعِشْرِينَ وَإِنَّهَا لَهِيَ هِيَ مَا يُسْتَثْنَى بِالْآيَةِ الَّتِي حَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَسَبْنَا وَعَدَدْنَا فَإِنَّهَا لَهِيَ هِيَ مَا يُسْتَثْنَى","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Sufyan bin Sa'id] dari [Ashim] dari [Zir] berkata, [Ubay] berkata kepadaku bahwa malam lailatul qadar itu ada di malam ke dua puluh tujuh, yaitu malam yang dikecualikan dengan tanda-tanda sebagaimana Rasulullah shallallahu 'alaihi wasallam telah menceritakan kepada kami. Maka kami menghitung bahwa malam itu adalah apa yang telah dikecualikan.\""},"2964":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ وَخَلَفُ بْنُ هِشَامٍ الْبَزَّارُ وَعُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ قَالُوا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا عَاصِمٌ عَنْ زِرٍّ قَالَقُلْتُ لِأُبَيِّ بْنِ كَعْبٍ أَبَا الْمُنْذِرِ أَخْبِرْنِي عَنْ لَيْلَةِ الْقَدْرِ فَإِنَّ صَاحِبَنَا يَعْنِي ابْنَ مَسْعُودٍ كَانَ إِذَا سُئِلَ عَنْهَا قَالَ مَنْ يَقُمْ الْحَوْلَ يُصِبْهَا فَقَالَ يَرْحَمُ اللَّهُ أَبَا عَبْدِ الرَّحْمَنِ أَمَا وَاللَّهِ لَقَدْ عَلِمَ أَنَّهَا فِي رَمَضَانَ وَلَكِنْ أَحَبَّ أَنْ لَا يَتَّكِلُوا وَإِنَّهَا لَيْلَةُ سَبْعٍ وَعِشْرِينَ لَمْ يَسْتَثْنِ قُلْتُ أَبَا الْمُنْذِرِ أَنَّى عَلِمْتَ ذَلِكَ قَالَ بِالْآيَةِ الَّتِي قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُبْحَةَ لَيْلَةِ الْقَدْرِ تَطْلُعُ الشَّمْسُ لَا شُعَاعَ لَهَا كَأَنَّهَا طَسْتٌ حَتَّى تَرْتَفِعَ وَهَذَا لَفْظُ حَدِيثِ الْمُقَدَّمِيِّحَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا عَاصِمٌ عَنْ زِرٍّ قَالَ قُلْتُ لِأُبَيِّ بْنِ كَعْبٍ أَبَا الْمُنْذِرِ أَخْبِرْنِي عَنْ لَيْلَةِ الْقَدْرِ فَذَكَرَ الْحَدِيثَ قَالَ فَقُلْتُ يَا أَبَا الْمُنْذِرِ أَنَّى عَلِمْتَ ذَلِكَ قَالَ بِالْآيَةِ الَّتِي أَخْبَرَنَا رَسُولُ اللَّهِ صَ��َّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] [Khalaf bin Hisyam Al Bazzar] dan [Ubaidullah bin Umar Al Qawariri] semuanya berkata, telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ashim] dari [Zir] berkata, Aku bertanya kepada [Ubay bin Ka'b], \"Wahai Abu Mundzir, kabarkan kepadaku tentang lailatul qadar, karena sahabatmu -yaitu Ibnu Mas'ud- apabila ditanya tentang malam lailatul qadar ia menjawab, \"Barangsiapa melakukan shalat malam setahun niscaya ia baru akan mendapatkannya'.\" Ubay menjawab, \"Semoga Allah merahmati Abu Abdurrahman, sebenarnya ia tahu bahwa malam itu terjadi di bulan Ramadan, tetapi ia suka jika jika manusia tidak membatasi diri (beramal pada malam itu). Sungguh, ia ada pada malam kedua puluh tujuh tanpa ada pengecualian.\" Aku bertanya lagi, \"Wahai Abu Mundzir, darimana engkau mengetahuinya?\" Ubay menjawab, \"Dengan tanda-tandanya yang Rasulullah shallallahu 'alaihi wasallam telah menceritakan kepada kami, bahwa pada pagi dari malam lailatul qadar matahari akan terbit tanpa cahaya yang terik hingga ia meninggi.\" Dan ini adalah lafadz hadits dari Al Muqaddami. Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ashim] dari [Zir] ia berkata, Aku bertanya pada [Ubay bin Ka'b], \"Wahai Abu Mundzir, kabarkan kepadaku tentang lailatul qadar…lalu ia sebutkan hadits tersebut.\" Zir berkata, \"Aku lalu bertanya, \"Wahai Abu Mundzir, dari mana engkau tahu?\" Ubay menjawab, \"Dengan tanda-tanda yang telah Rasulullah shallallahu 'alaihi wasallam kabarkan kepada kami.\""},"2965":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي الْعَبَّاسُ بْنُ الْوَلِيدِ النَّرْسِيُّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ شُعَيْبٍ عَنْ عَاصِمٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ عَبْدِ اللَّهِ أَنَّهُ قَالَ فِي لَيْلَةِ الْقَدْرِ مَنْ يَقُمْ الْحَوْلَ يُصِبْهَافَانْطَلَقْتُ حَتَّى قَدِمْتُ عَلَى عُثْمَانَ بْنِ عَفَّانَ وَأَرَدْتُ لُقِيَّ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمُهَاجِرِينَ وَالْأَنْصَارِ قَالَ عَاصِمٌ فَحَدَّثَنِي أَنَّهُ لَزِمَ أُبَيَّ بْنَ كَعْبٍ وَعَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ فَزَعَمَ أَنَّهُمَا كَانَا يَقُومَانِ حَتَّى تَغْرُبَ الشَّمْسُ فَيَرْكَعَانِ رَكْعَتَيْنِ قَبْلَ الْمَغْرِبِ قَالَ فَقُلْتُ لِأُبَيٍّ وَكَانَتْ فِيهِ شَرَاسَةٌ اخْفِضْ لَنَا جَنَاحَكَ رَحِمَكَ اللَّهُ فَإِنِّي إِنَّمَا أَتَمَتَّعُ مِنْكَ تَمَتُّعًا فَقَالَ تُرِيدُ أَنْ لَا تَدَعَ آيَةً فِي الْقُرْآنِ إِلَّا سَأَلْتَنِي عَنْهَا قَالَ وَكَانَ لِي صَاحِبَ صِدْقٍ فَقُلْتُ يَا أَبَا الْمُنْذِرِ أَخْبِرْنِي عَنْ لَيْلَةِ الْقَدْرِ فَإِنَّ ابْنَ مَسْعُودٍ يَقُولُ مَنْ يَقُمْ الْحَوْلَ يُصِبْهَا فَقَالَ وَاللَّهِ لَقَدْ عَلِمَ عَبْدُ اللَّهِ أَنَّهَا فِي رَمَضَانَ وَلَكِنَّهُ عَمَّى عَلَى النَّاسِ لِكَيْلَا يَتَّكِلُوا وَاللَّهِ الَّذِي أَنْزَلَ الْكِتَابَ عَلَى مُحَمَّدٍ إِنَّهَا لَفِي رَمَضَانَ وَإِنَّهَا لَيْلَةُ سَبْعٍ وَعِشْرِينَ فَقُلْتُ يَا أَبَا الْمُنْذِرِ أَنَّى عَلِمْتَ ذَلِكَ قَالَ بِالْآيَةِ الَّتِي أَنْبَأَنَا بِهَا مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَدَدْنَا وَحَفِظْنَا فَوَاللَّهِ إِنَّهَا لَهِيَ مَا يُسْتَثْنَى قَالَ فَقُلْتُ وَمَا الْآيَةُ فَقَالَ إِنَّهَا تَطْلُعُ حِينَ تَطْلُعُ لَيْسَ لَهَا شُعَاعٌ حَتَّى تَرْتَفِعَوَكَانَ عَاصِمٌ لَيْلَتَئِذٍ مِنْ السَّحَرِ لَا يَطْعَمُ طَعَامًا حَتَّى إِذَا صَلَّى الْفَجْرَ صَعِدَ عَلَى الصَّوْمَعَةِ فَنَظَرَ إِلَى الشَّمْسِ حِينَ تَطْلُعُ لَا شُعَاعَ لَهَا حَتَّى تَبْيَضَّ وَتَرْتَفِعَ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Abbas bin Walid An Narsi] ia berkata; telah menceritakan kepada kami [Hammad bin Syu'aib] dari [Ashim] dari [Zir bin Hubaisy] dari Abdullah bahwa ia mengatakan tentang lailataul qadar, \"Barangsiapa melaksanakan shalat malam setahun maka ia akan mendapatkannya.\" Maka aku bergegas pergi ke tempat Utsman bin Affan, aku berharap bertemu beberapa sahabat Rasulullah shallallahu 'alaihi wasallam baik dari kalangan Muhajirin maupun Anshar.\" Ashim berkata, \" [Ubay bin Ka'b] dan Abdurrahman bin Auf melazimkannya untuk melaksanakan shalat hingga terbenam matahari, lalu shalat dua kali sebelum Maghrib.\" Ashim berkata, \"Aku bertanya pada Ubai -Dia adalah seorang yang berperangai kasar-, \"Berlaku sopanlah semoga Allah merahmatimu, aku hanya mengharapkan satu harapan padamu.\" Lantas Ubai berkata, \"Agar kamu tidak melewatkankan satupun ayat dalam Al Qur`an kecuali engkau menanyakannya kepadaku?\" Ashim berkata, \"Dan aku memiliki teman yang jujur, aku lalu berkata, 'Wahai Abu Mundzir, jelaskan lailatul qadar kepadaku! karena Ibnu Mas'ud pernah menyatakan siapa saja yang mendirikan shalat setahun niscaya ia mendapatkannya'.\" Ubai pun menjawab, 'Demi Allah, sungguh Abdullah (Ibnu Mas'ud) Telah mengetahui bila lailatul qadar terjadi di bulan Ramadan, mungkin ia sembunyikan itu agar manusia tidak terlalu menggantungkan pada hal itu. Demi Allah yang telah menurunkan Al Qur`an pada Muhammad, Lailatul qadar itu terjadi di bulan Ramadan, yaitu di malam ke dua puluh tujuh.\" Aku (Ashim) bertanya, 'Wahai Abu mundzir, dari mana kamu tahu itu?\" Ia menjawab, \"Rasulullah Muhammad shallallahu 'alaihi wasallam telah memberitakannya pada kami, kami hitung dan kami hafal itu. Demi Allah, sungguh ia ada di malam-malam ganjil.\" Aku bertanya, \"Apa tanda-tandanya?\" Dia menjawab, \"Ia terjadi ketika matahari terbit tanpa ada benang sinarnya.\" Maka di malam sahurnya itu Ashim tidak makan, hingga ia selesai shalat subuh, ia naik di tempat yang tinggi dan memperhatikan matahari di kala terbitnya tanpa menyisakan benang sinarnya hingga memutih dan merangkak menaiki langit (siang).\""},"2966":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَجَّاجُ بْنُ أَرْطَاةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ أُبَيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَبِعَ جَنَازَةً حَتَّى يُصَلَّى عَلَيْهَا وَيُفْرَغَ مِنْهَا فَلَهُ قِيرَاطَانِ وَمَنْ تَبِعَهَا حَتَّى يُصَلَّى عَلَيْهَا فَلَهُ قِيرَاطٌ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَهُوَ أَثْقَلُ فِي مِيزَانِهِ مِنْ أُحُدٍ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengkabarkan kepada kami [Hajjaj bin Arthah] dari [Adi bin Tsabit] dari [Zir bin Hubaisy] dari [Ubay] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa mengiringi Jenazah hingga di shalatkan dan selesai dari pemakamannya, maka ia akan mendapatkan pahala dua Qirath. Dan barangsiapa mengiringi Jenazah hingga dishalatkan maka baginya pahala satu Qirath, demi Dzat yang jiwa Muhammad berada di tangannya (satu qirath) itu adalah lebih berat timbangannya ketimbang gunung uhud.\""},"2967":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ أُبَيٍّ قَالَكَانَ ابْنُ عَمٍّ لِي شَاسِعَ الدَّارِ فَقُلْتُ لَوْ أَنَّكَ اتَّخَذْتَ حِمَارًا أَوْ شَيْئًا فَقَالَ مَا يَسُرُّنِي أَنَّ بَيْتِي مُطَنَّبٌ بِبَيْتِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَمَا سَمِعْتُ عَنْهُ كَلِمَةً أَكْرَهَ إِلَيَّ مِنْهَا قَالَ فَإِذَا هُوَ يَذْكُرُ الْخُطَا إِلَى الْمَسْجِدِ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ لَهُ بِكُلِّ خُطْوَةٍ دَرَجَةًحَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَبِي عُثْمَانَ حَدَّثَنِي أُبَيُّ بْنُ كَعْبٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّ لَكَ مَا احْتَسَبْتَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Ashim] dari [Abu Utsman] dari [Ubay] dia berkata, \"Rumah tempat tinggal anak lelaki pamanku sangat jauh maka aku katakana, 'Seandainya kamu mengendarai keledai atau sesuatu.' Lalu ia menjawab, \"Bukan suatu kebanggaan bagiku jika rumahku dekat dengan rumah Muhammad shallallahu 'alaihi wasallam.\" Ubay berkata, \"Maka tidak ada perkataan yang paling aku benci keluar dari mulutnya kecuali perkataan tersebut.\" Perawi berkata, \"Ketika saudaranya menyebut-nyebut tentang (keutamaan) melangkahkan keki ke masjid, Ubay bertanya kepada Nabi shallallahu 'alaihi wasallam. Beliau pun menjawab: \"Setiap langkah kaki yang ia langkahkan, maka derajatnya akan naik satu tingkat.\" Telah menceritakan kepada kami [Ali bin Ishaq] dia berkata, telah menceritakan kepada kami [Abdullah bin Al Mubarak] dia berkata, telah memberitakan kepada kami ['Ashim Al Ahwal] dari [Abu Utsman] dia berkata, telah bercerita kepadaku [Ubay bin Ka'b] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Bagimu adalah apa yang kamu usahakan.\""},"2968":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَجُلٌ بِالْمَدِينَةِ لَا أَعْلَمُ رَجُلًا كَانَ أَبْعَدَ مِنْهُ مَنْزِلًا أَوْ قَالَ دَارًا مِنْ الْمَسْجِدِ مِنْهُ فَقِيلَ لَهُ لَوْ اشْتَرَيْتَ حِمَارًا فَرَكِبْتَهُ فِي الرَّمْضَاءِ وَالظُّلُمَاتِ فَقَالَ مَا يَسُرُّنِي أَنَّ دَارِي أَوْ قَالَ مَنْزِلِي إِلَى جَنْبِ الْمَسْجِدِ فَنُمِيَ الْحَدِيثُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا أَرَدْتَ بِقَوْلِكَ مَا يَسُرُّنِي أَنَّ مَنْزِلِي أَوْ قَالَ دَارِي إِلَى جَنْبِ الْمَسْجِدِ قَالَ أَرَدْتُ أَنْ يُكْتَبَ إِقْبَالِي إِذَا أَقْبَلْتُ إِلَى الْمَسْجِدِ وَرُجُوعِي إِذَا رَجَعْتُ إِلَى أَهْلِي قَالَ أَعْطَاكَ اللَّهُ تَعَالَى ذَلِكَ كُلَّهُ أَوْ أَنْطَاكَ اللَّهُ مَا احْتَسَبْتَ أَجْمَعَ أَوْ أَنْطَاكَ اللَّهُ تَعَالَى ذَلِكَ كُلَّهُ مَا احْتَسَبْتَ أَجْمَعَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [At Taimi] dari [Abu Utsman] dari [Ubay bin Ka'b] ia berkata, \"Di Madinah ada seorang laki-laki laki-laki yang aku tidak tahu orang yang rumahnya paling jauh dari masjid selain rumahnya. Lalu dikatakan padanya, 'Sekiranya engkau membeli seekor keledai sehingga engkau bisa kendarai di saat gurun pasir terasa panas dan malam menjadi gelap.' Lalu ia menjawab, \"Bukan suatu kebanggaan jika rumahku dekat dengan masjid.\" lalu disampaikanlah perkataan itu kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Apa yang kamu inginkan dengan ucapanmu 'Bukan suatu kebanggaan jika rumahku dekat dengan masjid'?\" orang itu menjawab, \"Aku ingin langkahku bernilai pahala apabila aku berangkat ke masjid dan jika pulang menuju keluargaku.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah memberikan semuanya padamu, atau semoga Allah memberikan semua yang engkau harapkan.\""},"2969":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ قَالَ سَمِعْتُ أَبَا عُثْمَانَ يُحَدِّثُ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَجُلٌ يَأْتِي الصَّلَاةَ فَقِيلَ لَهُ لَوْ اتَّخَذْتَ حِمَارًا يَقِيكَ الرَّمْضَاءَ وَالشَّوْكَ وَالْوَقْعَ قَالَ شُعْبَةُ وَذَكَرَ رَابِعَةً قَالَ مَحْلُوفَةً مَا أُحِبُّ أَنَّ طُنُبِي بِطُنُبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَكَ مَا نَوَيْتَ أَوْ قَالَ لَكَ أَجْرُ مَا نَوَيْتَ شُعْبَةُ يَقُولُ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Ashim] berkata, Aku mendengar [Abu Utsman] menceritakan dari [Ubay bin Ka'b] ia berkata, \"Seorang laki-laki datang untuk melaksanakan shalat, lalu dikatakan padanya, \"Sekiranya engkau mengendarai keledai tentu itu bias menjagamu dari terik panas, duri dan tergelincir.\" Syu'bah berkata, \"Pada kali yang keempat ia mengucapkan suatu sumpah, \"Aku tidak suka jika rumahku dekat dengan rumah Rasulullah shallallahu 'alaihi wasallam.\" Hal itu kemudian disebutkan kepada Nabi shallallahu 'alaihi wasallam, beliau pun bersabda: \"Bagimu apa yang engkau niatkan, atau beliau bersabda: \"Bagimu pahala yang telah engkau niatkan.' Demikianlah yang disebutkan oleh Syu'bah."},"2970":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذِ بْنِ الْعَنْبَرِيِّ حَدَّثَنَا الْمُعْتَمِرُ قَالَ قَالَ أَبِي رَحِمَهُ اللَّهُ حَدَّثَنَا أَبُو عُثْمَانَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَجُلٌ مَا أَعْلَمُ مِنْ النَّاسِ مِنْ إِنْسَانٍ مِنْ أَهْلِ الْمَدِينَةِ مِمَّنْ يُصَلِّي الْقِبْلَةَ أَبْعَدَ بَيْتًا مِنْ الْمَسْجِدِ مِنْهُ قَالَ فَكَانَ يَحْضُرُ الصَّلَوَاتِ كُلَّهُنَّ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ لَوْ اشْتَرَيْتَ حِمَارًا تَرْكَبُهُ فِي الرَّمْضَاءِ وَالظَّلْمَاءِ قَالَ وَاللَّهِ مَا أُحِبُّ أَنَّ بَيْتِي يَلْزَقُ بِمَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَخْبَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ يَا نَبِيَّ اللَّهِ لِكَيْمَا يُكْتَبَ أَثَرِي وَرُجُوعِي إِلَى أَهْلِي وَإِقْبَالِي إِلَيْهِ قَالَ أَنْطَاكَ اللَّهُ ذَلِكَ كُلَّهُ أَوْ أَعْطَاكَ مَا احْتَسَبْتَ أَجْمَعَ أَوْ كَمَا قَالَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz bin 'Anbari] telah menceritakan kepada kami [Mu'tamir] ia berkata, [Ayahku] -semoga Allah merahmatinya- berkata, telah menceritakan kepada kami [Abu Utsman] dari [Ubay bin Ka'b] ia berkata, \"Tidak seorang laki-laki pun dari penduduk Madinah yang mendirikan shalat menghadap kiblat yang rumahnya paling jauh dari masjid kecuali dia.\" Ubay melanjutkan, \"Ia selalu menghadiri shalat lima waktu bersama Nabi shallallahu 'alaihi wasallam, maka aku katakan kepadanya, 'Sekiranya engkau membeli seekor keledai sehingga engkau bisa mengendarainya di saat panas dan malam yang gelap.' Laki-laki itu menjawab, \"Demi Allah, aku tidak ingin rumahku berdekatan dengan masjid Rasulullah shallallahu 'alaihi wasallam.\" Ubay melanjutkan kisahnya, \"Maka itu aku kabarkan kepada Rasulullah shallallahu 'alaihi wasallam hingga beliau menanyai laki-laki tersebut, maka laki-laki itu pun menjawab, \"Wahai Nabi Allah, semoga kepulanganku kepada keluargaku dan kepergianku menuju masjid dicatat oleh Allah.\" Beliau menjawab: \"Semoga Allah memberikan itu semua kepadamu, atau beliau mengatakan, \"Apa yang engkau harapkan, atau sebagaimana yang beliau ucapkan.\""},"2971":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي عُثْمَانَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَجُلٌ مِنْ الْأَنْصَارِ بَيْتُهُ أَقْصَى بَيْتٍ فِي الْمَدِينَةِ فَكَانَ لَا تَكَادُ تُخْطِئُهُ الصَّلَاةُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَتَوَجَّعْتُ لَهُ فَقُلْتُ يَا فُلَانُ لَوْ أَنَّكَ اشْتَرَيْتَ حِمَارًا يَقِيكَ مِنْ حَرِّ الرَّمْضَاءِ وَيَقِيكَ مِنْ هَوَامِّ الْأَرْضِ قَالَ وَاللَّهِ مَا أُحِبُّ أَنَّ بَيْتِي بِطُنُبِ بَيْتِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَحَمَلْتُ حِمْلًا حَتَّى أَتَيْتُ بِهِ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَدَعَاهُ فَقَالَ مِثْلَ ذَلِكَ وَذَكَرَ أَنَّهُ يَرْجُو فِي أَثَرِهِ الْأَجْرَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لَكَ مَا احْتَسَبْتَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] telah menceritakan kepada kami [Abbad bin Abbad] telah menceritakan kepada kami [Ashim] dari [Abu Utsman] dari [Ubay bin Ka'b] ia berkata, \"Ada seorang Anshar yang rumahnya di penghujung kota Madinah, akan tetapi ia tidak pernah tertinggal untuk shalat berjamaah bersama Rasulullah shallallahu 'alaihi wasallam. Aku lalu memberikan masukan padanya, aku katakana, 'Wahai fulan, jikalau engkau membeli seekor himar tentu dapat menjagamu dari terik matahari dan dari duri di bumi.' Ia menjawab, 'Demi Allah, aku tidak ingin rumahku berdekatan dengan masjid Rasulullah shallallahu 'alaihi wasallam.' Lalu aku bawa ia menuju Rasulullah shallallahu 'alaihi wasallam dan aku kabarkan kepada beliau, beliau bertanya dan ia beralasan untuk mendapatkan banyak pahala.' Beliau bersabda: \"Engkau akan mendapatkan apa yang engkau harapkan.\""},"2972":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ الْعَبَّاسِ الْبَاهِلِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ أَبِي عُثْمَانَ عَنْ أُبَيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا اعْتَزَى فَأَعَضَّهُ أُبَيٌّ بِهَنِ أَبِيهِ فَقَالُوا مَا كُنْتَ فَحَّاشًا قَالَ إِنَّا أُمِرْنَا بِذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Amru bin Abbas AlBahili] telah menceritakan kepada kami [Sufyan] dari [Ashim] dari [Abu Utsman] dari [Ubay] radliallahu 'anhu, bahwa seorang lelaki berbangga dengan nasabnya maka Ubay mengingatkannya dengan kekurangan yang ada pada bapaknya. Mereka pun mengatakan, \"Kamu (Ubay) bukanlah orang yang jalang.\" Kemudian Ubay berkata, \"Kami diperintahkan untuk melakukan demikian.\""},"2973":{"ar":"حَدَّثَنَا أَبُو سَعْدٍ مُحَمَّدُ بْنُ مُيَسَّرٍ الصَّاغَانِيُّ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ الْمُشْرِكِينَ قَالُوا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُحَمَّدُ انْسُبْ لَنَا رَبَّكَ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ قُلْ هُوَ اللَّهُ أَحَدٌ اللَّهُ الصَّمَدُ لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ }","id":"Telah menceritakan kepada kami [Abu Sa'id Muhammad bin Miassar Ash Sha ghani] telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Rabi' bin Anas] dari [Abu Aliyah] dari [Ubay bin Ka'b], bahwa orang-orang musyrik berkata kepada Nabi shallallahu 'alaihi wasallam, \"Wahai Muhammad, sebutkan nasab Rabbmu kepada kami.\" Maka Allah Tabaaraka Wa Ta'ala menurunkan firman-Nya: '(Katakanlah \"Dialah Allah yang maha Esa, Allah adalah Robb yang bergantung kepadaNya segala sesuatu, Dia tiada beranak dan tidak pula diperanakkan, dan tidak ada seorangpun yang setara dengan Dia) ' (Qs. Al Ikhlas: 1-4)."},"2974":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ سُفْيَانَ عَنْ أَبِي سَلَمَةَ عَنِ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشِّرْ هَذِهِ الْأُمَّةَ بِالسَّنَاءِ وَالرِّفْعَةِ وَالدِّينِ وَالنَّصْرِ وَالتَّمْكِينِ فِي الْأَرْضِ وَهُوَ يَشُكُّ فِي السَّادِسَةِ قَالَ فَمَنْ عَمِلَ مِنْهُمْ عَمَلَ الْآخِرَةِ لِلدُّنْيَا لَمْ يَكُنْ لَهُ فِي الْآخِرَةِ نَصِيبٌقَالَ عَبْد اللَّهِ قَالَ أَبِي أَبُو سَلَمَةَ هَذَا الْمُغِيرَةُ بْنُ مُسْلِمٍ أَخُو عَبْدِ الْعَزِيزِ بْنِ مُسْلِمٍ الْقَسْمَلِيِّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي سَلَمَةَ الْخُرَاسَانِيِّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Sufyan] dari [Abu Salamah] dari [Rabi' bin Anas] dari [Abu Aliyah] dari [Ubay bin Ka'b] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah kabar gembira kepada umat ini dengan para wanita, kemulyaan, agama, pertologan dan kekuasaan di muka bumi.\" Dan beliau ragu-ragu yang ke enam, beliau lalu melanjutkan: \"Barangsiapa di antara mereka mengerjakan aml akhirat untuk keduniaan, maka di Akhirat dia tidak akan mendapatkan bagian.\" Abdullah berkata; Bapakku berkata; Abu Salamah adalah Al Mughirah bin Muslim, saudara laki laki Abdul Aziz bin Muslim Al Qasmali.\" Telah menceritakan kepada kami [Muhammad bin Abu Bakar Al Muqaddami] dia berkata, telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dia berkata, telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Abu Salamah Al Khurasani] dari [Rabi' bin Anas] dari [Abu 'Aliyah] dari [Ubay bin Ka'b] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang semisalnya.\""},"2975":{"ar":"حَدَّثَنَا عَبْد اللَّهِ بْن أَحْمَد قَالَ و حَدَّثَنِي أَبُو الشَّعْثَاءِ عَلِيُّ بْنُ الْحَسَنِ الْوَاسِطِيُّ حَدَّثَنَا يَحْيَى بْنُ يَمَانٍ عَنْ سُفْيَانَ عَنْ مُغِيرَةَ السَّرَّاجِ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشِّرْ هَذِهِ الْأُمَّةَ بِالسَّنَاءِ وَالرِّفْعَةِ وَالنَّصْرِ وَالتَّمْكِينِ فِي الْأَرْضِ فَمَنْ عَمِلَ عَمَلَ الْآخِرَةِ لِلدُّنْيَا لَمْ يَكُنْ لَهُ فِي الْآخِرَةِ نَصِيبٌ وَهَذَا لَفْظُ الْمُقَدَّمِيِّ","id":"Telah menceritakan kepada kami Abdullah bin Ahmad ia berkata, telah menceritakan kepadaku [Abu Sya'tsa` Ali bin Hasan Al Wasithi] telah menceritakan kepada kami [Yahya bin Yaman] dari [Sufyan] dari [Mughirah As Saraj] dari [Rabi' bin Anas] dari [Abu 'Aliyah] dari [Ubay bin Ka'b] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah kabar gembira kepada umat ini dengan para wanita, kemuliaan, agama, pertologan dan kekuasaan di muka bumi. Barangsiapa di antara mereka melakukan amal akhirat untuk keduniaan, maka di Akhirat dia tidak akan mendapatkan bagian.\" Ini adalah lafadz Al Muqaddami."},"2976":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ و حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي عَبْدُ الْوَاحِدِ بْنُ غِيَاثٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُسْلِمٍ عَنْ الرَّبِيعِ بْنِ أَنَسٍ فِي حَدِيثِهِ حَدَّثَنَا الرَّبِيعُ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَشِّرْ هَذِهِ الْأُمَّةَ بِالسَّنَاءِ وَالنَّصْرِ وَالتَّمْكِينِ فَمَنْ عَمِلَ مِنْهُمْ عَمَلَ الْآخِرَةِ لِلدُّنْيَا لَمْ يَكُنْ لَهُ فِي الْآخِرَةِ نَصِيبٌ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Abdul Aziz bin Muslim], dan telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Abdul Wahid bin Ghayyats] telah menceritakan kepada kami [Abdul Aziz bin Muslim] dari [Rabi' bin Anas] -dalam haditsnya; telah menceritakan kepada kami Rabi'- dari [Abu 'Aliyah] dari [Ubay bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah kabar gembira kepada umat ini dengan para wanita, kemuliaan, agama, pertologan dan kekuasaan di muka bumi. Barangsiapa di antara mereka melakukan amalan Akhirat untuk dunia, maka di Akhirat dia tidak akan mendapatkan bagian.\""},"2977":{"ar":"حَدَّثَنِي أَبُو يَحْيَى مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ الْبَزَّازُ حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشِّرْ هَذِهِ الْأُمَّةَ بِالسَّنَاءِ وَالتَّمْكِينِ فِي الْبِلَادِ وَالنَّصْرِ وَالرِّفْعَةِ فِي الدِّينِ وَمَنْ عَمِلَ مِنْهُمْ بِعَمَلِ الْآخِرَةِ لِلدُّنْيَا فَلَيْسَ لَهُ فِي الْآخِرَةِ نَصِيبٌ","id":"Telah menceritakan kepadaku [Abu Yahya Muhammad bin Abdurrahim Al Bazzaz] telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Abu 'Aliyah] dari [Ubay bin Ka'b] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berilah kabar gembira kepada umat ini dengan para wanita, kemuliaan, agama, pertologan dan kekuasaan di muka bumi. Barangsiapa di antara mereka mengerjakan amal akhirat untuk keduniaan, maka di Akhirat dia tidak akan mendapatkan bagian.\""},"2978":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا رَوْحُ بْنُ عَبْدِ الْمُؤْمِنِ الْمُقْرِئُ حَدَّثَنَا عُمَرُ بْنُ شَقِيقٍ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَانْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ فَقَرَأَ بِسُورَةٍ مِنْ الطُّوَلِ ثُمَّ رَكَعَ خَمْسَ رَكَعَاتٍ وَسَجْدَتَيْنِ ثُمَّ قَامَ الثَّانِيَةَ فَقَرَأَ بِسُورَةٍ مِنْ الطُّوَلِ ثُمَّ رَكَعَ خَمْسَ رَكَعَاتٍ وَسَجَدَ سَجْدَتَيْنِ ثُمَّ جَلَسَ كَمَا هُوَ مُسْتَقْبِلَ الْقِبْلَةِ يَدْعُو حَتَّى انْجَلَى كُسُوفُهَا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Rauh bin Abdul Mu`min Al Muqri`] telah menceritakan kepada kami [Umar bin Syaqiq] telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Rabi' bin Anas] dari [Abu Aliyah] dari [Ubay bin Ka'b] dia berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari, kemudian Rasulullah shallallahu 'alaihi wasallam bersama para sahabat melaksanakan shalat dan membaca surat-surat panjang, beliau lalu rukuk lima kali rakaat dan sujud dua kali. Kemudian beliau bangkit pada rakaat kedua membaca surat-surat panjang, kemudian rukuk lima kali dan sujud dua kali, kemudian beliau duduk dengan menghadap kiblat berdoa sampai hilang gerhananya.\""},"2979":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو جَعْفَرٍ عَنْ الرَّبِيعِ عَنْ أَبِي الْعَالِيَةِعَنْ أُبَيِّ بْنِ كَعْبٍ فِي قَوْلِهِ تَبَارَكَ وَتَعَالَى{ هُوَ الْقَادِرُ عَلَى أَنْ يَبْعَثَ عَلَيْكُمْ عَذَابًا مِنْ فَوْقِكُمْ }الْآيَةَ قَالَ هُنَّ أَرْبَعٌ وَكُلُّهُنَّ عَذَابٌ وَكُلُّهُنَّ وَاقِعٌ لَا مَحَالَةَ فَمَضَتْ اثْنَتَانِ بَعْدَ وَفَاةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخَمْسٍ وَعِشْرِينَ سَنَةً فَأُلْبِسُوا شِيَعًا وَذَاقَ بَعْضُهُمْ بَأْسَ بَعْضٍ وَثِنْتَانِ وَاقِعَتَانِ لَا مَحَالَةَ الْخَسْفُ وَالرَّجْمُحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا رَوْحُ بْنُ عَبْدِ الْمُؤْمِنِ حَدَّثَنَا عُمَرُ بْنُ شَقِيقٍ حَدَّثَنَا أَبُو جَعْفَرٍ الرَّازِيُّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ فِي قَوْلِهِ{ قُلْ هُوَ الْقَادِرُ }فَذَكَرَ نَحْوَهُ وَقَالَ فِي حَدِيثِهِ الْخَسْفُ وَالْقَذْفُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Abu Ja'far] dari [Rabi'] dari [Abu Aliyah] dari [Ubay bin Ka'b] berkenaan dengan firman Allah Ta'ala: '(Katakanlah: \"Dialah yang berkuasa untuk mengirimkan azab kepadamu, dari atas kamu) ' (Qs. Al An'am: 65). Ubay berkata, \"Semuanya ada empat, semuanya adalah siksa dan mau tidak mau semuanya pasti terjadi, yang dua sudah terjadi dua puluh lima tahun setelah Nabi shallallahu 'alaihi wasallam wafat, mereka diliputi dengan perpecahan, satu sama lain saling menyerang, dan yang dua lagi pasti terjadi; yaitu Al Khasaf (tenggelam ke dalam bumi) dan rajam.\" Telah menceritakan kepada kami Abdullah dia berkata, telah menceritakan kepada kami [Rauh bin Abdul Mu`min] dia berkata, telah menceritakan kepada kami [Umar bin Syaqiq] dia berkata, telah menceritakan kepada kami [Abu Ja'far Ar Razi] dari [Rabi' bin Anas] dari [Abu 'Aliyah] dari [Ubay bin Kab] tentang firman Allah: QUL HUWAL QAADIRU (Katakanlah: \"Dialah yang berkuasa..) ' (Qs. Al An'am: 65), lalu ia menyebutkan sebagaimana hadits tersebut. Dan dalam hadits ia menyebutkan Al Khasaf dan Qadzaf (tenggelam ke dalam bumi dan menuduh berbuat zina).\""},"2980":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا أَبُو صَالِحٍ هَدِيَّةُ بْنُ عَبْدِ الْوَهَّابِ الْمَرْوَزِيُّ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى حَدَّثَنَا عِيسَى بْنُ عُبَيْدٍ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ قُتِلَ مِنْ الْأَنْصَارِ أَرْبَعَةٌ وَسِتُّونَ رَجُلًا وَمِنْ الْمُهَاجِرِينَ سِتَّةٌ فَقَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَئِنْ كَانَ لَنَا يَوْمٌ مِثْلُ هَذَا مِنْ الْمُشْرِكِينَ لَنُرْبِيَنَّ عَلَيْهِمْ فَلَمَّا كَانَ يَوْمُ الْفَتْحِ قَالَ رَجُلٌ لَا يُعْرَفُ لَا قُرَيْشَ بَعْدَ الْيَوْمِ فَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمِنَ الْأَسْوَدُ وَالْأَبْيَضُ إِلَّا فُلَانًا وَفُلَانًا نَاسًا سَمَّاهُمْ فَأَنْزَلَ اللَّهُ تَبَارَكَ وَتَعَالَى{ وَإِنْ عَاقَبْتُمْ فَعَاقِبُوا بِمِثْلِ مَا عُوقِبْتُمْ بِهِ وَلَئِنْ صَبَرْتُمْ لَهُوَ خَيْرٌ لِلصَّابِرِينَ }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَصْبِرُ وَلَا نُعَاقِبُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Abu Shalih Hadiyyah bin Abdul Wahab Al Marwazi] telah menceritakan kepada kami [Fadlal bin Musa] telah menceritakan kepada kami [Isa bin Ubaid] dari [Rabi' bin Anas] dari [Abu Aliyah] dari [Ubay bin Ka'b] dia berkata, \"Ketika perang Uhud kaum Anshar yang terbunuh berjumlah enam puluh empat orang, dan dari kaum Muhajirin berjumlah enam orang. Maka para sahabat Rasulullah shallallahu 'alaihi wasallam berkata: \"Jika kita mendapatkan seperti hari ini dengan orang-orang musyrik pasti kita akan jatuhkan korban dari mereka lebih banyak.\" Maka ketika hari penaklukan kota Makkah berkatalah seseorang yang tak dikenal, \"Tidak ada orang Quraisy setelah hari ini.\" Maka berkatalah penyeru Rasulullah shallallahu 'alaihi wasallam: \"Orang yang berkulit putih dan berkulit hitam akan mendapatkan keamaan, kecuali fulan dan fulan.\" Yakni beberapa orang yang mereka sebutkan namanya. Kemudian Allah Tabaaraka Wa Ta'ala menurunkan firman-Nya: '(Dan jika kamu memberikan balasan, Maka balaslah dengan balasan yang sama dengan siksaan yang ditimpakan kepadamu, akan tetapi jika kamu bersabar, Sesungguhnya Itulah yang lebih baik bagi orang-orang yang sabar) ' (Qs. An Nahl: 126). Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita bersabar dan jangan membalas.\""},"2981":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ الْجَرْمِيُّ قَدِمَ مِنْ الْكُوفَةِ حَدَّثَنَا أَبُو نُمَيْلَةَ حَدَّثَنَا عِيسَى بْنُ عُبَيْدٍ الْكِنْدِيُّ عَنْ الرَّبِيعِ بْنِ أَنَسٍ حَدَّثَنِي أَبُو الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّهُ أُصِيبَ يَوْمَ أُحُدٍ مِنْ الْأَنْصَارِ أَرْبَعَةٌ وَسِتُّونَ وَأُصِيبَ مِنْ الْمُهَاجِرِينِ سِتَّةٌ وَحَمْزَةُ فَمَثَّلُوا بِقَتْلَاهُمْ فَقَالَتْ الْأَنْصَارُ لَئِنْ أَصَبْنَا مِنْهُمْ يَوْمًا مِنْ الدَّهْرِ لَنُرْبِيَنَّ عَلَيْهِمْ فَلَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ نَادَى رَجُلٌ مِنْ الْقَوْمِ لَا يُعْرَفُ لَا قُرَيْشَ بَعْدَ الْيَوْمِ فَأَنْزَلَ اللَّهُ تَعَالَى عَلَى نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَإِنْ عَاقَبْتُمْ فَعَاقِبُوا بِمِثْلِ مَا عُوقِبْتُمْ بِهِ }الْآيَةَ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُفُّوا عَنْ الْقَوْمِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Sa'id bin Muhammad Al Jarmi] datang dari Kufah, telah menceritakan kepada kami [Abu Numailah] telah menceritakan kepada kami [Isa bin Ubaid Al Kindi] dari [Rabi' bin Anas] telah menceritakan kepadaku [Abu Aliyah] dari [Ubay bin Ka'b], bahwa dalam perang Uhud sebanyak enam puluh empat orang-orang Anshar dan enam orang Muhajirin syahid terbunuh. Dan Hamzah sendiri terbunuh dengan mutilasi. Orang-orang Anshar berkata: \"Jika pada suatu saat kita mendapatkan kesempatan membalas orang-orang musyrik sebagaimana yang mereka lakukan hari ini, niscaya kita akan jatuhkan korban dari mereka lebih banyak.\" Maka ketika hari penaklukan kota Makkah berkatalah seseorang yang tak dikenal, \"Tidak ada orang Quraisy setelah hari ini!\" Kemudian Allah Tabaaraka Wa Ta'ala menurunkan firman-Nya: '(Dan jika kamu memberikan balasan, Maka balaslah dengan balasan yang sama dengan siksaan yang ditimpakan kepadamu…) ' (Qs. An Nahl: 126). Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tahanlah dari membunuh mereka.\""},"2982":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ يَعْقُوبَ الزُّبَالِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ الرَّبِيعِ بْنِ أَنَسٍ عَنْ رُفَيْعٍ أَبِي الْعَالِيَةِ عَنْ أُبَيِّ بْنِ كَعْبٍفِي قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ وَإِذْ أَخَذَ رَبُّكَ مِنْ بَنِي آدَمَ مِنْ ظُهُورِهِمْ ذُرِّيَّاتِهِمْ وَأَشْهَدَهُمْ عَلَى أَنْفُسِهِمْ }الْآيَةَ قَالَ جَمَعَهُمْ فَجَعَلَهُمْ أَرْوَاحًا ثُمَّ صَوَّرَهُمْ فَاسْتَنْطَقَهُمْ فَتَكَلَّمُوا ثُمَّ أَخَذَ عَلَيْهِمْ الْعَهْدَ وَالْمِيثَاقَ وَأَشْهَدَهُمْ عَلَى أَنْفُسِهِمْ أَلَسْتُ بِرَبِّكُمْ قَالَ فَإِنِّي أُشْهِدُ عَلَيْكُمْ السَّمَوَاتِ السَّبْعَ وَالْأَرَضِينَ السَّبْعَ وَأُشْهِدُ عَلَيْكُمْ أَبَاكُمْ آدَمَ عَلَيْهِ السَّلَام أَنْ تَقُولُوا يَوْمَ الْقِيَامَةِ لَمْ نَعْلَمْ بِهَذَا اعْلَمُوا أَنَّهُ لَا إِلَهَ غَيْرِي وَلَا رَبَّ غَيْرِي فَلَا تُشْرِكُوا بِي شَيْئًا وَإِنِّي سَأُرْسِلُ إِلَيْكُمْ رُسُلِي يُذَكِّرُونَكُمْ عَهْدِي وَمِيثَاقِي وَأُنْزِلُ عَلَيْكُمْ كُتُبِي قَالُوا شَهِدْنَا بِأَنَّكَ رَبُّنَا وَإِلَهُنَا لَا رَبَّ لَنَا غَيْرُكَ فَأَقَرُّوا بِذَلِكَ وَرَفَعَ عَلَيْهِمْ آدَمَ يَنْظُرُ إِلَيْهِمْ فَرَأَى الْغَنِيَّ وَالْفَقِيرَ وَحَسَنَ الصُّورَةِ وَدُونَ ذَلِكَ فَقَالَ رَبِّ لَوْلَا سَوَّيْتَ بَيْنَ عِبَادِكَ قَالَ إِنِّي أَحْبَبْتُ أَنْ أُشْكَرَ وَرَأَى الْأَنْبِيَاءَ فِيهِمْ مِثْلُ السُّرُجِ عَلَيْهِمْ النُّورُ خُصُّوا بِمِيثَاقٍ آخَرَ فِي الرِّسَالَةِ وَالنُّبُوَّةِ وَهُوَ قَوْلُهُ تَعَالَى{ وَإِذْ أَخَذْنَا مِنْ النَّبِيِّينَ مِيثَاقَهُمْ إِلَى قَوْلِهِ عِيسَى ابْنِ مَرْيَمَ }كَانَ فِي تِلْكَ الْأَرْوَاحِ فَأَرْسَلَهُ إِلَى مَرْيَمَ فَحَدَّثَ عَنْ أُبَيٍّ أَنَّهُ دَخَلَ مِنْ فِيهَا","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Ya'qub Az Zubali] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] berkata, Aku mendengar [Ayahku] menceritakan dari [Rabi' bin Anas] dari [Rufai' Abu Aliyah] dari [Ubay bin Ka'b] tentang firman Allah Azza Wa Jalla: '(Dan ingatlah, ketika Tuhanmu mengeluarkan keturunan anak-anak Adam dari sulbi mereka dan Allah mengambil kesaksian terhadap jiwa mereka) ' (Qs. Al A'raaf: 172). Ubay berkata, \"Allah kumpulkan dan menjadikan bagi mereka ruh, kemudian membentuk rupa dan menjadikan mereka dapat berbicara sehingga mereka berbicara. Allah lalu mengambil sumpah dan janji kepada mereka dan mempersaksikan kepada diri mereka sendiri 'bukankah aku ini Rabb kalian? ', kemudian Allah berfirman: 'Sesungguhnya aku mempersaksikan kepada kalian dengan tujuh langit dan tujuh bumi dan aku persaksikan kepada kalian dengan bapak kalian Adam 'Alaihis Salam, agar supaya kalian tidak mengatakan pada hari kiyamat 'kami tidak mengetahui sumpah ini'. Ketahuilah oleh kalian bahwa tidak ada tuhan selain-Ku dan tidak ada Rabb selain-Ku, maka janganlah kalian mensekutukan Aku dengan sesuatu yang lain. Sesungguhnya Aku akan mengutus seorang para rasul-Ku kepada kalian yang akan mengingatkan kalian akan sumpah dan janji-Ku, dan aku akan menurunkan Kitab-Ku kepada kalian.\" Mereka menjawab, \"Kami bersaksi bahwa Engkau adalah Rabb dan tuhan kami, tidak ada Rabb bagi kami kecuali Engkau. Maka mereka pun menyatakannya dan diangkatlah Adam sebagai saksi bagi mereka sehingga dia dapat melihat orang yang kaya dan yang miskin, yang bagus rupanya dan yang jelek. Kemudian Adam berkata, \"Wahai Rabb mengapa tidak Engkau samakan di antara hamba hamba-Mu? ' Allah menjawab: \"Sesungguhnya Aku suka untuk disyukuri.\" Adam lalu melihat para Nabi di antara mereka, di antara mereka ada yang seperti pelita, mereka dinaungi oleh cahaya, sebab mereka mempunyai perjanjian sendiri terhadap risalah dan kenabian mereka. Maka inilah yang disinggung oleh firman Allah: '(Dan Ingatlah, ketika kami mengambil perjanjian dari nabi-nabi) ' (Qs. Al Ahzab: 7) sampai pada firman-Nya: '(Isa putra Maryam) ' (Qs. Al Ahzab: 7). Isa pada saat itu masih bersama-sama dengan ruh-ruh para Nabi tersebut, lalu Allah mengirimkannya kepada Maryam.\" Beliau menceritakan yang diriwayatkan Ubay, bahwa isa masuk dari mulut Maryam.\""},"2983":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَوْفٌ عَنِ الْحَسَنِ عَنْ عُتَيِّ بْنِ ضَمْرَةَ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَجُلًا اعْتَزَى بِعَزَاءِ الْجَاهِلِيَّةِ فَأَعَضَّهُ وَلَمْ يُكَنِّهِ فَنَظَرَ الْقَوْمُ إِلَيْهِ فَقَالَ لِلْقَوْمِ إِنِّي قَدْ أَرَى الَّذِي فِي أَنْفُسِكُمْ إِنِّي لَمْ أَسْتَطِعْ إِلَّا أَنْ أَقُولَ هَذَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَنَا إِذَا سَمِعْتُمْ مَنْ يَعْتَزِي بِعَزَاءِ الْجَاهِلِيَّةِ فَأَعِضُّوهُ وَلَا تَكْنُوا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Auf] dari [Hasan] dari [Utayi bin Dlamrah] dari [Ubay bin Ka'b], bahwa ada seorang laki-laki membanggakan nasabnya seperti perbuatan orang-orang Jahiliyah, namun ia menahan dan tidak menyatakannya secara fulgar. Orang-orang pun memandang ke arahnya, maka laki-laki itu pun berkata, \"Sesungguhnya aku bisa memahami apa yang ada pada kalian, dan tiada yang bisa saya lakukan kecuali ini, karena Rasulullah shallallahu 'alaihi wasallam menyuruh kami: \"Jika kalian mendengar seseorang membanggakan nasabnya seperti orang jahiliyah, maka tahanlah dan jangan kalian tampakkan dengan fulgar.\""},"2984":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عَوْفٌ عَنْ الْحَسَنِ عَنْ عُتَيٍّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَرَأَيْتُ رَجُلًا تَعَزَّى عِنْدَ أُبَيٍّ بِعَزَاءِ الْجَاهِلِيَّةِ افْتَخَرَ بِأَبِيهِ فَأَعَضَّهُ بِأَبِيهِ وَلَمْ يُكَنِّهِ ثُمَّ قَالَ لَهُمْ أَمَا إِنِّي قَدْ أَ��َى الَّذِي فِي أَنْفُسِكُمْ إِنِّي لَا أَسْتَطِيعُ إِلَّا ذَلِكَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَعَزَّى بِعَزَاءِ الْجَاهِلِيَّةِ فَأَعِضُّوهُ وَلَا تَكْنُواحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عَوْفٍ عَنْ الْحَسَنِ عَنْ عُتَيٍّ عَنْ أُبَيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ حَدَّثَنَا إِسْمَاعِيلُ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ عُتَيٍّ أَنَّ رَجُلًا تَعَزَّى بِعَزَاءِ الْجَاهِلِيَّةِ فَذَكَرَ الْحَدِيثَ قَالَ أُبَيٌّ كُنَّا نُؤْمَرُ إِذَا الرَّجُلُ تَعَزَّى بِعَزَاءِ الْجَاهِلِيَّةِ فَأَعِضُّوهُ بِهَنِ أَبِيهِ وَلَا تَكْنُوا حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ عَنْ عُتَيٍّ قَالَ قَالَ أُبَيٌّ كُنَّا نُؤْمَرُ إِذَا اعْتَزَى رَجُلٌ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Auf] dari [Hasan] dari [Utay] dari [Ubay bin Ka'b] berkata, \"Pernah kulihat seseorang telanjur membanggakan diri dengan kebanggaan jahiliyah pada Ubbay bin Ka'b. Ia membangga-banggakan ayahnya. Hanya sesaat kemudian ia menggigit (menahan, menyembunyikan) kebanggaan itu dan tidak menyatakannya secara vulgar (terang-terangan). Laki-laki itu (menyatakan keinsafannya) seraya berkata kepada mereka 'Ketahuilah, saya sebenarnya juga sependapat dengan kalian, saya tak bisa apa-apa, hanya telah kudengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang membangga-banggakan diri dengan kebanggaan jahiliyah, tolong gigitlah (tahanlah) dan jangan (diterus-teruskan hingga) dinyatakan secara vulgar (terang-terangan).\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Isa bin Yunus] dari [Auf] dari [Hasan] dari [Utay] dari [Ubay] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" Telah menceritakan kepada kami [Isma'il] dari [Yunus] dari [Hasan] dari [Utay], bahwa seseorang yang membanggakan nasabnya seperti perbuatan orang-orang Jahiliyah…lalu ia menyebutkan sebagaimana dalam hadits tersebut.\" [Ubay] berkata, \"Jika ada seorang laki-laki membangga-banggakan nasabnya secara jahiliyah maka kami diperintahkan untuk menahan (dari membangga-banggakan) dengan menjelekkan bapaknya tanpa dengan cara yang vulgar.\" Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Ubaidullah bin Umar bin Maisarah]. Telah menceritakan kepada kami [Yazid bin Zura'i] telah menceritakan kepada kami [Yunus] dari [Hasan] dari [Utay] berkata, [Ubay] berkata, \"Kami diperintah jika seseorang yang membanggakan keturunannya…lalu ia menyebutkan hadits tersebut.\""},"2985":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى أَبُو مُوسَى الْعَنَزِيُّ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا خَارِجَةُ بْنُ مُصْعَبٍ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ عُتَيٍّ عَنْ أُبَيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْوُضُوءِ شَيْطَانٌ يُقَالُ لَهُ الْوَلَهَانُ فَاتَّقُوهُ أَوْ قَالَ فَاحْذَرُوهُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepadaku [Muhammad bin Mutsanna Abu Musa Al 'Anazi] telah menceritakan kepada kami [Abu Dawud] telah menceritakan kepada kami [Kharijah bin Mus'ab] dari [Yunus bin Ubaid] dari [Hasan] dari [Utai] dari [Ubay] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada tiap wudlu itu ada setan yang di namakan dengan Al Walahan, maka berhati-hatilah kalian, atau beliau mengatakan: \"Maka waspadalah kalian darinya.\""},"2986":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَبُو يَحْيَى الْبَزَّازُ حَدَّثَنَا أَبُو حُذَيْفَةَ مُوسَى بْنُ مَسْعُودٍ حَدَّثَنَا سُفْيَانُ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ عُتَيٍّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مَطْعَمَ ابْنِ آدَمَ جُعِلَ مَثَلًا لِلدُّنْيَا وَإِنْ قَزَّحَهُ وَمَلَّحَهُ فَانْظُرُوا إِلَى مَا يَصِيرُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Abdurrahim Abu Yahya Al Bazaz] telah menceritakan kepada kami [Abu Khudzaifah Musa bin Mas'ud] telah menceritakan kepada kami [Sufyan] dari [Yunus bin Ubaid] dari [Al Hasan] dari [Utay] dari [Ubay bin Ka'b] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesugguhnya makanan anak Adam itu dijadikan permisalan untuk kehidupan dunia, dan jika dia dibumbui dan di beri garam maka lihatlah apa jadinya.\""},"2987":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ الْحَسَنِ عَنْ عُتَيٍّ قَالَرَأَيْتُ شَيْخًا بِالْمَدِينَةِ يَتَكَلَّمُ فَسَأَلْتُ عَنْهُ فَقَالُوا هَذَا أُبَيُّ بْنُ كَعْبٍ فَقَالَ إِنَّ آدَمَ عَلَيْهِ السَّلَام لَمَّا حَضَرَهُ الْمَوْتُ قَالَ لِبَنِيهِ أَيْ بَنِيَّ إِنِّي أَشْتَهِي مِنْ ثِمَارِ الْجَنَّةِ فَذَهَبُوا يَطْلُبُونَ لَهُ فَاسْتَقْبَلَتْهُمْ الْمَلَائِكَةُ وَمَعَهُمْ أَكْفَانُهُ وَحَنُوطُهُ وَمَعَهُمْ الْفُؤُوسُ وَالْمَسَاحِي وَالْمَكَاتِلُ فَقَالُوا لَهُمْ يَا بَنِي آدَمَ مَا تُرِيدُونَ وَمَا تَطْلُبُونَ أَوْ مَا تُرِيدُونَ وَأَيْنَ تَذْهَبُونَ قَالُوا أَبُونَا مَرِيضٌ فَاشْتَهَى مِنْ ثِمَارِ الْجَنَّةِ قَالُوا لَهُمْ ارْجِعُوا فَقَدْ قُضِيَ قَضَاءُ أَبِيكُمْ فَجَاءُوا فَلَمَّا رَأَتْهُمْ حَوَّاءُ عَرَفَتْهُمْ فَلَاذَتْ بِآدَمَ فَقَالَ إِلَيْكِ إِلَيْكِ عَنِّي فَإِنِّي إِنَّمَا أُوتِيتُ مِنْ قِبَلِكِ خَلِّي بَيْنِي وَبَيْنَ مَلَائِكَةِ رَبِّي تَبَارَكَ وَتَعَالَى فَقَبَضُوهُ وَغَسَّلُوهُ وَكَفَّنُوهُ وَحَنَّطُوهُ وَحَفَرُوا لَهُ وَأَلْحَدُوا لَهُ وَصَلَّوْا عَلَيْهِ ثُمَّ دَخَلُوا قَبْرَهُ فَوَضَعُوهُ فِي قَبْرِهِ وَوَضَعُوا عَلَيْهِ اللَّبِنَ ثُمَّ خَرَجُوا مِنْ الْقَبْرِ ثُمَّ حَثَوْا عَلَيْهِ التُّرَابَ ثُمَّ قَالُوا يَا بَنِي آدَمَ هَذِهِ سُنَّتُكُمْ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Hudbah binKhalid] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Hasan] dari [Utai] dia berkata, \"Aku pernah melihat seorang lelaki tua di Madinah sedang berbicara, maka aku bertanya kepada orang-orang tentang siapa dia. Mereka lantas menjawab, \"Ini adalah [Ubay bin Ka'b].\" Lalu ia berkata, \"Sesungguhnya Adam 'Alaihis Salam ketika ajalnya tiba, dia berkata kepada anak-anakya, \"Wahai anakku, sesungguhnya aku menginginkan buah dari Surga.\" Mereka kemudian pergi memintakan buah untuk Adam, lalu para Malaikat menyambut mereka dengan membawa kain kafannya (Adam) dan keranda, sementara mereka (anak-anak Adam) membawa kapak, sekop dan keranjang buah. Para Malaikat lantas bertanya kepada mereka, \"Wahai Bani Adam apa yang kalian inginkan dan kalian minta?, Atau dalam riwayat lain, \"Apa yang kalian inginkan dan hendak ke mana kalian pergi?\" Mereka menjawab, \"Bapak kami sakit dan menginginkan buah Surga.\" Para Malaikat menjawab, \"Kembalilah! Sungguh telah ditetapkan keputusan untuk bapak kalian (kematian).\" Mereka pun kembali. Ketika Hawa' melihat para malaikat dan ia tahu siapa mereka, maka ia kembali kepada Adam untuk menjaganya. Kemudian Adam berkata kepada Hawa`, \"Menyingkirlah kamu dariku, hanyasannya aku telah diberi dari sisimu, maka biarkan yang berada di antara aku dan para Malaikat adalah Rabbku Tabaaraka Wa Ta'ala. Maka para Malaikat pun mencabut nyawanya, memandikan, mengkafani, membuatkannya lubang dan lahat untuknya, serta menshalatinya. Kemudian mereka masuk ke dalam makamnya dan meletakkan Adam ke dalam kuburnya, mereka letakkan batu bata di atasnya kemudian mereka keluar dari dalam makamnya. Setelah itu mereka menimbunnya dengan tanah seraya berkata, \"Wahai anak Adam ini adalah sunnah kalian.\""},"2988":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ جَعَلْتُ صَلَاتِي كُلَّهَا عَلَيْكَ قَالَ إِذَنْ يَكْفِيَكَ اللَّهُ تَبَارَكَ وَتَعَالَى مَا أَهَمَّكَ مِنْ دُنْيَاكَ وَآخِرَتِكَ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Muhammad bin Aqil] dari [At Thufail bin Ubay bin Ka'b] dari [Bapaknya] dia berkata, \"Ada seorang lelaki berkata, \"Wahai Rasulullah, bagaimana pendapatmu jika shalawatku semuanya aku tujukan untukmu?\" Beliau menjawab: \"Berarti Allah Tabaraka Wa Ta'ala akan mencukupkan apa yang menjadi keinginanmu baik masalah duniamu maupun masalah akhiratmu.\""},"2989":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَأَبُو عَامِرٍ قَالَا حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلِي فِي النَّبِيِّينَ كَمَثَلِ رَجُلٍ بَنَى دَارًا فَأَحْسَنَهَا وَأَكْمَلَهَا وَتَرَكَ فِيهَا مَوْضِعَ لَبِنَةٍ لَمْ يَضَعْهَا فَجَعَلَ النَّاسُ يَطُوفُونَ بِالْبُنْيَانِ وَيَعْجَبُونَ مِنْهُ وَيَقُولُونَ لَوْ تَمَّ مَوْضِعُ هَذِهِ اللَّبِنَةِ فَأَنَا فِي النَّبِيِّينَ مَوْضِعُ تِلْكَ اللَّبِنَةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Abu Amir] keduanya berkata, telah menceritakan kepada kami [Zuhair bin Muhammad] dari [Abdullah bin Muhammad bin Aqil] dari [At Thufail bin Ubay bin Ka'b] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaanku dari para Nabi adalah seperti seorang lelaki yang membangun rumah, dia memperindahnya dan melengkapinya, namun dia meningglkan satu tempat sebesar batu bata dan dia tidak meletakkannya, maka orang-orang berkeliling mengitari bangunan dengan terkagum kagum sambil mengatakan, 'seandainya tempat batu bata ini sempurna', maka saya dari para Nabi itu seperti tempat batu bata itu.\""},"2990":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا زُهَيْرٌ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ يَوْمُ الْقِيَامَةِ كُنْتُ إِمَامَ النَّبِيِّينَ وَخَطِيبَهُمْ وَصَاحِبَ شَفَاعَتِهِمْ غَيْرَ فَخْرٍ","id":"Telah menceritakan kepada kami [Abu Amir] telah menceritakan kepada kami [Zuhair binMuhammad] dari [Abdullah bin Muhammad] dari [At Thufail bin Ubay bin Ka'b] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada hari kiamat nanti aku akan menjadi pemimpin para Nabi, khatib mereka, dan pemberi syafa'at mereka. Dan ini bukanlah (bentuk) kesombongan.\""},"2991":{"ar":"قَالَوَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْلَا الْهِجْرَةُ لَكُنْتُ امْرَأً مِنْ الْأَنْصَارِ وَلَوْ سَلَكَ النَّاسُ وَادِيًا أَوْ شِعْبًا لَكُنْتُ مَعَ الْأَنْصَارِحَدَّثَنَا زَكَرِيَّا حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ الْقِيَامَةِ كُنْتُ إِمَامَ النَّبِيِّينَ فَذَكَرَ مَعْنَاهُ","id":"Masih melalui jalur periwayatan yang sama seperti hadits sebelumnya dari [Ubay bin Ka'ab]; Ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalaulah bukan karena Hijrah, tentulah aku termasuk orang-orang Anshar, bila satu kaum berjalan di satu lembah dan kaum Anshar di lembah yang lain, maka aku bersama orang-orang Anshar.\" Telah menceritakan kepada kami Ubaidullah bin Amru dari Abdullah bin Muhammad bin Aqil dari Thufail bin Ubay bin Ka'b dari Ayahnya dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada Hari Kiamat nanti aku adalah pemimpin para Nabi menyebutkan…lalu ia menyebutkan makna hadits tersebut.\""},"2992":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرُبُ إِلَى جِذْعٍ إِذْ كَانَ الْمَسْجِدُ عَرِيشًا وَكَانَ يَخْطُبُ إِلَى ذَلِكَ الْجِذْعِ فَقَالَ رَجُلٌ مِنْ أَصْحَابِهِ يَا رَسُولَ اللَّهِ هَلْ لَكَ أَنْ تَجْعَلَ لَكَ شَيْئًا تَقُومُ عَلَيْهِ يَوْمَ الْجُمُعَةِ حَتَّى يَرَاكَ النَّاسُ وَتُسْمِعَهُمْ خُطْبَتَكَ قَالَ نَعَمْ فَصُنِعَ لَهُ ثَلَاثُ دَرَجَاتٍ اللَّاتِي عَلَى الْمِنْبَرِ فَلَمَّا صُنِعَ الْمِنْبَرُ وَوُضِعَ فِي مَوْضِعِهِ الَّذِي وَضَعَهُ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَرَادَ أَنْ يَأْتِيَ الْمِنْبَرَ مَرَّ عَلَيْهِ فَلَمَّا جَاوَزَهُ خَارَ الْجِذْعُ حَتَّى تَصَدَّعَ وَانْشَقَّ فَرَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَهُ بِيَدِهِ حَتَّى سَكَنَ ثُمَّ رَجَعَ إِلَى الْمِنْبَرِ وَكَانَ إِذَا صَلَّى صَلَّى إِلَيْهِ فَلَمَّا هُدِمَ الْمَسْجِدُ وَغُيِّرَ أَخَذَ ذَاكَ الْجِذْعَ أُبَيُّ بْنُ كَعْبٍ فَكَانَ عِنْدَهُ حَتَّى بَلِيَ وَأَكَلَتْهُ الْأَرَضَةُ وَعَادَ رُفَاتًا","id":"Telah menceritakan kepada kami [Zakaria bin Adi] telah mengabarkan kepada kami [Ubaidullah bin Amru] dari [Abdullah bin Muhammad bin Aqil] dari [Ath Thufail bin Ubay bin Ka'b] dari [Bapaknya] dia berkata, \"Ketika masjid sudah beratap Rasulullah mendekat ke sebuah batang pohon kurma, dan apabila berkhutbah beliau bersandar kepadanya, maka berkatalah salah seorang dari sahabat, \"Wahai Rasulullah, apakah perlu dibuatkan sesuatu untuk tempat engkau berdiri saat khutbah di hari Jum'at, sehingga orang-orang dapat melihatmu dan mendengarkan khutbahmu?\" Nabi menjawab: \"Ya.\" Maka dibuatkanlah tempat dengan tiga tangga menuju mimbar, setelah selesai dibuat diletakkanlah ia di tempat yang disetujui oleh Rasulullah shallallahu 'alaihi wasallam, namun ketika beliau hendak naik mimbar dan melewati batang pohon kurma, dia (batang kurma) itu menangis sehingga terbelah dan pecah, maka Rasulullah shallallahu 'alaihi wasallam kembali dan mengusapnya dengan tangan hingga batang kurma itu kembali tenang, kemudian beliau kembali ke mimbar. Jika melaksanakan shalat maka beliau menghadap ke arah batang kurma itu, maka ketika masjid dihancurkan dan direnovasi, Ubay bin Ka'b mengambil batang pohon kurma itu. Maka batang kurma itu berada di sisi Ubay hingga rapuh dan dimakan oleh rayap dan hancur.\""},"2993":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَيْنَا نَحْنُ صُفُوفًا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الظُّهْرِ أَوْ الْعَصْرِ إِذْ رَأَيْنَاهُ يَتَنَاوَلُ شَيْئًا بَيْنَ يَدَيْهِ وَهُوَ فِي الصَّلَاةِ لِيَأْخُذَهُ ثُمَّ تَنَاوَلَهُ لِيَأْخُذَهُ ثُمَّ حِيلَ بَيْنَهُ وَبَيْنَهُ ثُمَّ تَأَخَّرَ وَتَأَخَّرْنَا ثُمَّ تَأَخَّرَ الثَّانِيَةَ وَتَأَخَّرْنَا فَلَمَّا سَلَّمَ قَالَ أُبَيُّ بْنُ كَعْبٍ رَضِيَ اللَّهُ عَنْهُ يَا رَسُولَ اللَّهِ رَأَيْنَاكَ الْيَوْمَ تَصْنَعُ فِي صَلَاتِكَ شَيْئًا لَمْ تَكُنْ تَصْنَعُهُ قَالَ إِنَّهُ عُرِضَتْ عَلَيَّ الْجَنَّةُ بِمَا فِيهَا مِنْ الزَّهْرَةِ فَتَنَاوَلْتُ قِطْفًا مِنْ عِنَبِهَا لِآتِيَكُمْ بِهِ وَلَوْ أَخَذْتُهُ لَأَكَلَ مِنْهُ مَنْ بَيْنَ السَّمَاءِ وَالْأَرْضِ وَلَا يَتَنَقَّصُونَهُ فَحِيلَ بَيْنِي وَبَيْنَهُ وَعُرِضَتْ عَلَيَّ النَّارُ فَلَمَّا وَجَدْتُ حَرَّ شُعَاعِهَا تَأَخَّرْتُ وَأَكْثَرُ مَنْ رَأَيْتُ فِيهَا النِّسَاءُ اللَّاتِي إِنْ اؤْتُمِنَّ أَفْشَيْنَ وَإِنْ سَأَلْنَ أَحْفَيْنَ قَالَ أَبِي قَالَ زَكَرِيَّا بْنُ عَدِيٍّ أَلْحَفْنَ وَإِنْ أُعْطِينَ لَمْ يَشْكُرْنَ وَرَأَيْتُ فِيهَا لُحَيَّ بْنَ عَمْرٍو يَجُرُّ قُصْبَهُ وَأَشْبَهُ مَنْ رَأَيْتُ بِهِ مَعْبَدُ بْنُ أَكْثَمَ قَالَ مَعْبَدٌ أَيْ رَسُولَ اللَّهِ يُخْشَى عَلَيَّ مِنْ شَبَهِهِ فَإِنَّهُ وَالِدٌ قَالَ لَا أَنْتَ مُؤْمِنٌ وَهُوَ كَافِرٌ وَهُوَ أَوَّلُ مَنْ جَمَعَ الْعَرَبَ عَلَى الْأَصْنَامِحَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عَمْرٍو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ عَنِ الطُّفَيْلِ بْنِ أُبَيٍّ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdul Malik] telah menceritakan kepada kami [Ubaidullah bin Amru] dari [Abdullah bin Muhammad bin Aqil] dari [Jabir bin Abdullah] dia berkata, \"Ketika kami berbaris untuk shalat zhuhur atau ashar di belakang Rasulullah shallallahu 'alaihi wasallam, kami melihat beliau meraih sesuatu di hadapannya untuk beliau ambil padahal sedang dalam shalat, kemudian beliau meraihnya lagi untuk beliau ambil namun kemudian terhalang sesuatu, lalu beliau mundur ke belakang dan kami pun mundur ke belakang, kemudian beliau mundur untuk yang kedua kalinya dan kamipun mundur. Setelah salam Ubay? radliallahu 'anhu bertanya, \"Wahai Rasulullah, hari ini kami melihat engkau melakukan sesuatu dalam shalat yang sebelumnya tidak pernah engkau lakukan?\" Beliau menjawab: \"Sesungguhnya telah ditampakkan kepadaku Surga beserta isinya berupa bunga bunga, kemudian aku memetik setangkai dari pohon anggur untuk aku berikan kepada kalian yang seandainya aku dapat mengambilnya pasti akan dapat dimakan oleh siapa saja yang ada di antara langit dan bumi dan tidak akan berkurang. Namun aku terhalang darinya, kemudian ditampakkan kepadaku Neraka dan ketika aku mendapatkan panas sinarnya aku mundur ke belakang, dan kebanyakan orang yang aku lihat di dalamnya adalah para wanita yang jika di percaya (tentang rahasia) mereka justru menyebarkannya, dan jika bertanya mereka memaksa dengan bersikeras.\" Bapakku berkata, \" [Zakaria bin Adi] menyebutkan dalam riwayat yang lain: \"Memaksa sedang jika diberi mereka tidak bersyukur. Aku (Rasulullah) juga melihat Luhai bin Amru menjulurkan lambungnya, dan orang yang paling mirip dengan dia dari yang pernah aku lihat adalah Ma'bad bin Aktsam.\" Ma'bad pun berkata, \"Wahai Rasulullah, aku takut menyerupainya sebab ia adalah seorang bapak.\" Nabi menjawab: \"Tidak, karena kamu adalah seorang yang mukmin sedangkan dia adalah kafir dan dia adalah orang yang pertama kali mengumpulkan orang-orang arab untuk menyembah patung.\" Telah menceritakan kepada kami [Ahmad bin Abdul Malik] dia berkata, telah menceritakan kepada kami [Ubaidullah bin Amru] dia berkata, telah menceritakan kepada kami [Abdullah bin Muhammad] dari [Thufail bin Ubay] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam dengan hadits yang serupa.\""},"2994":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي الرَّبِيعِ السَّمَّانُ أَخْبَرَنِي سَعِيدُ بْنُ سَلَمَةَ بْنِ أَبِي الْحُسَامِ الْمَدِينِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَقِيلِ بْنِ أَبِي طَالِبٍ عَنِ الطُّفَيْلِ بْنِ أُبَيٍّ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَى جِذْعٍ إِذْ كَانَ الْمَسْجِدُ عَرِيشًا وَكَانَ يَخْطُبُ النَّاسَ إِلَى جَانِبِ ذَلِكَ الْجِذْعِ فَقَالَ رَجُلٌ مِنْ أَصْحَابِهِ يَا رَسُولَ اللَّهِ هَلْ لَكَ أَنْ أَجْعَلَ لَكَ مِنْبَرًا تَقُومُ عَلَيْهِ يَوْمَ الْجُمُعَةِ حَتَّى يَرَى النَّاسُ خُطْبَتَكَ قَالَ نَعَمْ فَصَنَعَ لَهُ ثَلَاثَ دَرَجَاتٍ هِيَ الَّتِي عَلَى الْمِنْبَرِ فَلَمَّا قُضِيَ الْمِنْبَرُ وَوُضِعَ فِي مَوْضِعِهِ الَّذِي وَضَعَهُ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقُومَ عَلَى ذَلِكَ الْمِنْبَرِ فَمَرَّ إِلَيْهِ فَلَمَّا أَنْ جَاوَزَ الْجِذْعَ الَّذِي كَانَ يَخْطُبُ إِلَيْهِ وَيَقُومُ إِلَيْهِ خَارَ إِلَيْهِ ذَلِكَ الْجِذْعُ حَتَّى تَصَدَّعَ وَانْشَقَّ فَنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا سَمِعَ صَوْتَ الْجِذْعِ فَمَسَحَهُ بِيَدِهِ ثُمَّ رَجَعَ إِلَى الْمِنْبَرِ وَكَانَ إِذَا صَلَّى مَعَ ذَلِكَ مَالَ إِلَى الْجِذْعِيَقُولُ الطُّفَيْلُ فَلَمَّا هُدِمَ الْمَسْجِدُ وَغُيِّرَ أَخَذَ أَبُوهُ أُبَيُّ بْنُ كَعْبٍ ذَلِكَ الْجِذْعَ فَكَانَ عِنْدَهُ فِي بَيْتِهِ حَتَّى بَلِيَ وَأَكَلَتْهُ الْأَرَضُ وَعَادَ رُفَاتًا","id":"Telah menceritakan kepada kami [Sa'id bin Abu Rabi' As Saman] telah mengkabarkan kepadaku [Sa'id bin Salamah bin Abu Husam Al Madini] telah menceritakan kepada kami [Abdullah bin Muhammad bin Aqil bin Abu Thalib] dari [Ath Thufail bin Ubay bin Ka'b] dari [Bapaknya] dia berkata, \"Rasulullah melaksanakan shalat menghadap pada sebuah batang pohon kurma ketika masjid telah mempunyai atap, dan beliau biasa berkhutbah di sisi batang kurma tersebut. Maka seorang sahabatnya berkata, \"Wahai Rasulullah, apakah perlu dibuatkan sesuatu untuk tempat engkau berdiri saat khutbah hari Jum'at, sehingga orang-orang dapat melihatmu dan mendengarkan khutbahmu?\" Nabi menjawab: \"Ya.\" Maka dibuatkanlah dengan tiga tangga menuju mimbar, setelah selesai dibuat diletakkanlah ia di tempat yang disetujui oleh Rasulullah shallallahu 'alaihi wasallam, Rasulullah shallallahu 'alaihi wasallam pun berkeinginan untuk naik ke atasnya. Namun ketika beliau hendak naik mimbar dan melewati batang pohon kurma itu, dia (batang kurma) menangis sehingga terbelah dan pecah. Ketika Rasulullah shallallahu 'alaihi wasallam mendengar suara jeritan batang kurma itu beliau turun dari mimbar dan mengusapnya dengan tangan lalu kembali lagi ke atas mimbar. Dan jika shalat beliau selalu condong ke arah batang kurma tersebut.\" Ath Thufail berkata, \"Ketika masjid dihancurkan dan direnovasi, batang kurma itu diambil oleh bapaknya, Ubay bin Ka'b. Lalu batang itu ia simpan di dalam rumahnya hingga lapuk dan dimakan oleh rayap dan hancur.\""},"2995":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْحَارِثِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ الْقِيَامَةِ كُنْتُ إِمَامَ النَّبِيِّينَ وَخَطِيبَهُمْ وَصَاحِبَ شَفَاعَتِهِمْ غَيْرَ فَخْرٍ","id":"Telah menceritakan kepada kami [Hasyim bin Harits] telah menceritakan kepada kami [Ubaidullah bin Amru] dari [Abdullah bin Muhammad bin Aqil] dari [Ath Thufail bin Ubay bin Ka'b] dari [Bapaknya] dia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat aku adalah pemimpin para Nabi, khatib mereka, dan pemberi syafa'at mereka. Dan ini bukanlah (bentuk) kesombongan.\""},"2996":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا الْحَسَنُ بْنُ قَزَعَةَ أَبُو عَلِيٍّ الْبَصْرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ حَبِيبٍ حَدَّثَنَا شُعْبَةُ عَنْ ثُوَيْرٍ عَنْ أَبِيهِ عَنْ الطُّفَيْلِ عَنْ أَبِيهِ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ{ وَأَلْزَمَهُمْ كَلِمَةَ التَّقْوَى }قَالَ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Al Hasan bin Qaza'ah Abu Ali Al Bashri] telah menceritakan kepada kami [Sufyan bin Habib] telah menceritakan kepada kami [Syu'bah] dari [Tsuwair] dari [Ayahnya] dari [Thufail] dari [Bapaknya], bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda dan mengharuskan mereka mengucap kalimat takwa, beliau bersabda \"Laa Ilaaha Illallaah (Tidak ada tuhan yang berhak untuk disembah selain Allah).\""},"2997":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ عَنْ الطُّفَيْلِ بْنِ أُبَيِّ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ الْقِيَامَةِ كُنْتُ إِمَامَ النَّبِيِّينَ وَخَطِيبَهُمْ وَصَاحِبَ شَفَاعَتِهِمْ وَلَا فَخْرَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Muhammad bin Abdullah bin Zubair] telah menceritakan kepada kami [Syarik] dari [Abdullah bin Muhammad bin 'Aqil] dari [Thufail bin Ubai bin Ka'b] dari [Ayahnya] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat nanti aku adalah pemimpin para Nabi, khatib mereka pemberi syafaat mereka, dan ini bukahlah suatu kesombongan.\""},"2998":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَبُو يَحْيَى الْبَزَّازُ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُعَاذُ بْنُ مُحَمَّدِ بْنِ مُعَاذِ بْنِ أُبَيِّ بْنِ كَعْبٍ حَدَّثَنِي أَبِي مُحَمَّدُ بْنُ مُعَاذٍ عَنْ مُعَاذٍ عَنْ مُحَمَّدٍ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ أَبَا هُرَيْرَةَ كَانَ جَرِيًّا عَلَى أَنْ يَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَشْيَاءَ لَا يَسْأَلُهُ عَنْهَا غَيْرُهُ فَقَالَ يَا رَسُولَ اللَّهِ مَا أَوَّلُ مَا رَأَيْتَ فِي أَمْرِ النُّبُوَّةِ فَاسْتَوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا وَقَالَ لَقَدْ سَأَلْتَ أَبَا هُرَيْرَةَ إِنِّي لَفِي صَحْرَاءَ ابْنُ عَشْرِ سِنِينَ وَأَشْهُرٍ وَإِذَا بِكَلَامٍ فَوْقَ رَأْسِي وَإِذَا رَجُلٌ يَقُولُ لِرَجُلٍ أَهُوَ هُوَ قَالَ نَعَمْ فَاسْتَقْبَلَانِي بِوُجُوهٍ لَمْ أَرَهَا لِخَلْقٍ قَطُّ وَأَرْوَاحٍ لَمْ أَجِدْهَا مِنْ خَلْقٍ قَطُّ وَثِيَابٍ لَمْ أَرَهَا عَلَى أَحَدٍ قَطُّ فَأَقْبَلَا إِلَيَّ يَمْشِيَانِ حَتَّى أَخَذَ كُلُّ وَاحِدٍ مِنْهُمَا بِعَضُدِي لَا أَجِدُ لِأَحَدِهِمَا مَسًّا فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ أَضْجِعْهُ فَأَضْجَعَانِي بِلَا قَصْرٍ وَلَا هَصْرٍ وَقَالَ أَحَدُهُمَا لِصَاحِبِهِ افْلِقْ صَدْرَهُ فَهَوَى أَحَدُهُمَا إِلَى صَدْرِي فَفَلَقَهَا فِيمَا أَرَى بِلَا دَمٍ وَلَا وَجَعٍ فَقَالَ لَهُ أَخْرِجْ الْغِلَّ وَالْحَسَدَ فَأَخْرَجَ شَيْئًا كَهَيْئَةِ الْعَلَقَةِ ثُمَّ نَبَذَهَا فَطَرَحَهَا فَقَالَ لَهُ أَدْخِلْ الرَّأْفَةَ وَالرَّحْمَةَ فَإِذَا مِثْلُ الَّذِي أَخْرَجَ يُشْبِهُ الْفِضَّةَ ثُمَّ هَزَّ إِبْهَامَ رِجْلِي الْيُمْنَى فَقَالَ اغْدُ وَاسْلَمْ فَرَجَعْتُ بِهَا أَغْدُو رِقَّةً عَلَى الصَّغِيرِ وَرَحْمَةً لِلْكَبِيرِ","id":"Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Muhammad bin Abdurrahim Abu Yahya Al Bazzaz] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Mu'adz bin Muhammad bin Mu'adz bin Ubai bin Ka'b] telah menceritakan kepadaku ayahku [Muhammad bin Mu'adz] dari [Mu'adz] dari [Muhammad] dari [Ubay bin Ka'b] bahwa Abu Hurairah adalah orang yang paling berani bertanya kepada Rasulullah tentang sesuatu yang tidak ditanyakan oleh orang lain, dia bertanya, \"Wahai Rasulullah, apa yang pertama kali engkau lihat dalam perkara kenabian?\" kemudian Rasulullah shallallahu 'alaihi wasallam membenarkan posisi duduknya dan bersabda: \"Sungguh kamu telah bertanya wahai Abu Hurairah, ketika aku berada di sebuah padang pasir dan umurku masih sepuluh tahun lebih beberapa bulan, tiba-tiba ada suara orang berbicara di atas kepalaku dan ternyata seorang lelaki sedang bertanya kepada lelaki lain, 'Apakah benar dia orangnya? ' Yang lain menjawab, 'Ya', kemudian wajah keduanya menghadap ke arahku yang aku tidak pernah melihat makhluk sepertinya sama sekali, tidak pernah aku melihat ruh sepertinya sama sekali, dan pakaian yang tidak pernah aku melihatnya sama sekali, kemudian keduanya berjalan ke arahku sampai akhirnya masing-masing dari keduanya memegang lenganku dan aku tidak merasakan sama sekali. Salah satu dari keduanya berkata kepada temannya, 'Baringkan dia, ' dan keduanya membaringkanku dengan cepat dan baik, kemudian salah satunya memerintahkan kepada temannya, 'Belahlah dadanya! ' Maka salah satu dari keduanya merunduk ke dadaku dan membelahnya, menurut penglihatanku tanpa ada darah yang keluar dan tanpa ada rasa sakit, maka salah satunya berkata, 'Keluarkan sifat dengki dan hasad, ' kemudian dia mengeluarkan sesuatu seperti gumpalan darah dan membuangnya. Sementara yang satunya berkata, \"Masukkan gantinya dengan sifat lemah lembut dan kasih sayang!\" Dan ternyata bentuknya menyerupai sesuatu yang dikeluarkan namun mirip degan perak, kemudian dia menggerakkan ibu jari kaki kananku sambil berkata, 'Pergilah dan selamatlah! ' Maka aku kembali dengan membawa sifat lemah lembut kepada yang kecil dan kasih sayang kepada yang besar.\""},"2999":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ و حَدَّثَنَا عَبْد اللَّهِ قَالَ و حَدَّثَنَا الصَّلْتُ بْنُ مَسْعُودٍ الْجَحْدَرِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ حَدَّثَنِي أَبِي عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَوَقَفْتُ أَنَا وَأُبَيُّ بْنُ كَعْبٍ فِي ظِلِّ أُجُمِ حَسَّانَ فَقَالَ لِي أُبَيٌّ أَلَا تَرَى النَّاسَ مُخْتَلِفَةً أَعْنَاقُهُمْ فِي طَلَبِ الدُّنْيَا قَالَ قُلْتُ بَلَى قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُوشِكُ الْفُرَاتُ أَنْ يَحْسِرَ عَنْ جَبَلٍ مِنْ ذَهَبٍ فَإِذَا سَمِعَ بِهِ النَّاسُ سَارُوا إِلَيْهِ فَيَقُولُ مَنْ عِنْدَهُ وَاللَّهِ لَئِنْ تَرَكْنَا النَّاسَ يَأْخُذُونَ فِيهِ لَيَذْهَبَنَّ فَيَقْتَتِلُ النَّاسُ حَتَّى يُقْتَلَ مِنْ كُلِّ مِائَةٍ تِسْعَةٌ وَتِسْعُونَ وَهَذَا لَفْظُ حَدِيثِ أُبَيٍّ عَنْ عَفَّانَ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Khalid bin Al Harits] dan telah menceritakan kepada kami Abdullah ia berkata, telah menceritakan kepada kami [Shalt bin Mas'ud Al Jahdari] telah menceritakan kepada kami [Khalid bin Harits], telah menceritakan kepada kami [Abdul Hamid bin Ja'far] telah menceritakan kepadaku [Ayahku] dari [Sulaiman bin Yasar] dari [Abdullah bin Al Harits] dia berkata, \"Aku dan [Ubai bin Ka'b] berdiri di bawah lindungan tembok milik Hassan, kemudian Ubai berkata kepadaku, 'Tidakkah kamu melihat orang-orang memiliki bermacam cara dalam mengejar dunia?\" Abdullah bin Al Harits berkata, \"Aku menjawab, \"Ya, \" Ubai berkata, \"Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hampir hampir sungai Furath mengeluarkan gunung emas yang apabila manusia mendengarnya pasti akan bergegas mendatanginya.\" Kemudian seseorang yang ada di sisi beliau berkata, \"Demi Allah, seandainya manusia kita biarkan mengambilnya pasti dia akan habis dan manusia akan saling bunuh, sehingga akan terbunuh sembilan puluh sembilan dari tiap seratus orang.\" Dan ini lafadz hadits Ubai dari 'Affan.\""},"3000":{"ar":"حَدَّثَنَا شُجَاعُ بْنُ مَخْلَدٍ وَأَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ حُمْرَانَ الْحُمْرَانِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ أَخْبَرَنِي أَبِي عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَوَقَفْتُ أَنَا وَأُبَيُّ بْنُ كَعْبٍ فِي ظِلِّ أُجُمِ حَسَّانَ فَقَالَ لِي أُبَيٌّ أَلَا تَرَى النَّاسَ مُخْتَلِفَةً أَعْنَاقُهُمْ فِي طَلَبِ الدُّنْيَا قُلْتُ بَلَى قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُوشِكُ الْفُرَاتُ أَنْ يَحْسِرَ عَنْ جَبَلٍ مِنْ ذَهَبٍ فَإِذَا سَمِعَ بِهِ النَّاسُ سَارُوا إِلَيْهِ فَيَقُولُ مَنْ عِنْدَهُ وَاللَّهِ لَئِنْ تَرَكْنَا النَّاسَ يَأْخُذُونَ فِيهِ لَيَذْهَبَنَّ فَيَقْتَتِلُ النَّاسُ حَتَّى يُقْتَلَ مِنْ كُلِّ مِائَةٍ تِسْعَةٌ وَتِسْعُونَوَهَذَا لَفْظُ حَدِيثِ أَبِي عَنْ عَفَّانَ حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا شُجَاعُ بْنُ مَخْلَدٍ وَأَبُو خَيْثَمَةَ زُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ حُمْرَانَ الْحُمْرَانِيُّ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ أَخْبَرَنِي أَبِي جَعْفَرُ بْنُ عَبْدِ اللَّهِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُوشِكُ الْفُرَاتُ أَنْ يَحْسِرَ عَنْ جَبَلٍ مِنْ ذَهَبٍ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Syuja' bin Makhlad] dan [Abu Khaitsamah Zuhair bin harb] keduanya berkata, telah menceritakan kepada kami [Abdullah bin Humran Al Humrani] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] telah menceritakan kepadaku [Ayahku] dari [Sulaiman bin Yasar] dari [Abdullah bin Harits] berkata, \"Aku dan [Ubay bin Ka'b] berdiri di bawah lidungan tembok milik Hassan, kemudian Ubai berkata kepadaku, \"Tidakkah kamu melihat orang-orang memiliki bermacam cara dalam mengejar dunia?\" Abdullah bin Al Harits berkata, \"Aku menjawab, \"Ya, \" Ubai berkata, \"Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hampir-hampir sungai Furath mengeluarkan gunung emas yang apabila manusia mendengarnya pasti akan bergegas mendatanginya.\" Kemudian seseorang yang ada di sisi beliau berkata, \"Demi Allah, seandainya manusia kita biarkan mengambilnya pasti dia akan habis dan manusia akan saling bunuh, sehingga akan terbunuh sembilan puluh sembilan dari tiap seratus orang.\" -Dan ini adalah lafadz hadits Ubai dari ['Affan] -. Telah menceritakan kepada kami Abdullah telah menceritakan kepada kami [Syuja' bin Makhlad] dan [Abu Khaitsamah Zuhair bin Harb] keduanya berkata, telah menceritakan kepada kami [Abdullah bin Humran Al Humrani] telah menceritakan kepada kami [Abdul Hamid bin Ja'far] telah menceritakan kepadaku [Ayahku Ja'far bin Abdullah] dari [Sulaiman bin Yasar] dari [Abdullah bin Harits bin Naufal] dari [Ubay bin Ka'b] berkata, \"Aku mendengar Rasulullah bersabda: \"Hampir-hampir sungai Furath mengeluarkan gunung emas… lalu ia menyebutkan hadits tersebut.\""}};
